***** Object:  StoredProcedure [dbo].[mstp_Adviser]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[mstp_Adviser] -- WITH RECOMPILE,ENCRYPTION
 /* Param List */  
AS  
  
/******************************************************************************  
  
Copyright (C) Moore Stephens Consulting Limited 2005  
  
Summary : %Summary%  
Author : Matt Kennedy  
Created : %DateCreated%    
       
<doc>  
 <summary>%Summary%</summary>  
 <param name='%Param1Name%'>%Param1Summary%</param>  
 <returns>%Returns%</returns>  
 <author>Matt Kennedy</author>  
 <revision>  
  Date  Author  Description  
  25/09/2008 A Groves Replaced getdate() with ProcessDate to enable proc  
        to run before midnight.  
 </revision>  
</doc>  
  
*******************************************************************************/  
  
  
-- PROCEDURE BODY GOES HERE  
  
BEGIN  
  
declare @DefaultCompanyCode                      varchar(50)  
declare @DefaultCompanyName                      varchar(50)  
declare @DefaultAreaSalesManagerName             varchar(50)  
declare @DefaultAreaSalesManagerCode             varchar(50)  
declare @DefaultAreaName                         varchar(50)  
declare @DefaultAreaCode                         varchar(50)  
declare @DefaultRegionalSalesManagerName         varchar(50)  
declare @DefaultRegionalSalesManagerCode         varchar(50)  
declare @DefaultSalesQualityManagerName          varchar(50)  
declare @DefaultSalesQualityManagerCode          varchar(50)  
declare @DefaultFranchiseName                    varchar(50)  
declare @DefaultFranchiseCode                    varchar(50)  
declare @DefaultFranchiseSizeID                  int  
declare @DefaultFranchiseSegmentID               int  
declare @DefaultPracticePrincipalName            varchar(50)  
declare @DefaultPracticePrincipalCode            varchar(50)  
declare @DefaultPracticeSupervisorName           varchar(50)  
declare @DefaultPracticeSupervisorCode           varchar(50)  
declare @DefaultPracticeAdministratorName        varchar(50)  
declare @DefaultPracticeAdministratorCode        varchar(50)  
declare @DefaultAdviserID                        int  
declare @DefaultAdviserName                      varchar(50)  
declare @DefaultAgentCode                        varchar(50)  
declare @ProcessDate        datetime -- AG 25/09/2008  
  
set @DefaultCompanyCode                         = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'CompanyCode')  
set @DefaultCompanyName                         = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'CompanyName')  
set @DefaultAreaSalesManagerName                = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AreaSalesManagerName')  
set @DefaultAreaSalesManagerCode                = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AreaSalesManagerCode')  
set @DefaultAreaName                            = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AreaName')  
set @DefaultAreaCode                            = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AreaCode')  
set @DefaultRegionalSalesManagerName            = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'RegionalSalesManagerName')  
set @DefaultRegionalSalesManagerCode            = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'RegionalSalesManagerCode')  
set @DefaultSalesQualityManagerName             = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'SalesQualityManagerName')  
set @DefaultSalesQualityManagerCode             = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'SalesQualityManagerCode')  
set @DefaultFranchiseName                       = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'FranchiseName')  
set @DefaultFranchiseCode                       = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'FranchiseCode')  
set @DefaultFranchiseSizeID                     = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'FranchiseSizeID')  
set @DefaultFranchiseSegmentID                  = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'FranchiseSegmentID')  
set @DefaultPracticePrincipalName               = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'PracticePrincipalName')  
set @DefaultPracticePrincipalCode               = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'PracticePrincipalCode')  
set @DefaultPracticeSupervisorName              = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'PracticeSupervisorName')  
set @DefaultPracticeSupervisorCode              = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'PracticeSupervisorCode')  
set @DefaultPracticeAdministratorName           = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'PracticeAdministratorName')  
set @DefaultPracticeAdministratorCode           = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'PracticeAdministratorCode')  
set @DefaultAdviserID                           = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'AdviserID')  
set @DefaultAdviserName                         = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AdviserName')  
set @DefaultAgentCode                           = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AgentCode')  
set @ProcessDate        = (select ProcessDate from mst_ImportControl where Type = 'Openwork' and Module = 'Swift') -- AG 25/09/2008  
  
select distinct Code  
into #SalesHierarchyCategories  
from msdt_DropLists  
where CodeType = 'WH-SalesHierarchyCategory'  
--'DIRNS', 'DIRSL', 'IAR', 'MBRNS', 'MBRSL', 'PRINNS', 'PRINSL', 'PTNRNS', 'PTNRSL',  
--'MEMSL', 'PARSL', 'PFA', 'PRISL', 'PRAC', 'SOLE', 'PTNRSHP', 'LTDCO', 'LLP',   
--'DIRRI', 'PRINRI', 'MBRRI', 'RI', 'PTNRRI'  
  
  
select distinct Code  
into #BusinessTypeCategories  
from msdt_DropLists  
where CodeType = 'WH-BusinessTypeCategory'  
--'PRAC', 'SOLE', 'PTNRSHP', 'LTDCO', 'LLP'  
  
  
select  cast(@DefaultCompanyName as varchar(255))             as [Exec],   
 cast(@DefaultAreaSalesManagerName as varchar(255))        as AreaSalesManager,   
 cast(@DefaultAreaSalesManagerCode as varchar(255))        as AreaSalesManagerCode,   
 cast(@DefaultAreaName as varchar(255))                    as AreaName,   
 isnull(LocationCode, @DefaultAreaCode)                    as AreaCode,   
 cast(@DefaultRegionalSalesManagerName as varchar(255))    as RegionalSalesManager,   
 cast(@DefaultRegionalSalesManagerCode as varchar(255))    as RegionalSalesManagerCode,   
 cast(@DefaultSalesQualityManagerName as varchar(255))     as SalesQualityManager,   
 isnull(SaleSupervisorCode, @DefaultSalesQualityManagerCode)  as SalesQualityManagerCode,   
 cast(@DefaultFranchiseName as varchar(255))               as Franchise,   
 case when AgentCategory in (select distinct Code from #BusinessTypeCategories)   
  then Code else  
  Coalesce(nullif(FranchiseCode, @DefaultFranchiseCode),  
  nullif(OfficeCode, @DefaultFranchiseCode),   
  nullif(DirectlyAuthorisedCode, @DefaultFranchiseCode),  
  nullif(StrategicAllianceCode, @DefaultFranchiseCode),   
  nullif(AccessAgentCode, @DefaultFranchiseCode),   
  @DefaultFranchiseCode) end                            as FranchiseCode,   
 FranchiseSize,  
 @DefaultFranchiseSizeID                                   as FranchiseSizeID,   
 @DefaultFranchiseSegmentID                                as FranchiseSegmentID,   
 cast(@DefaultPracticePrincipalName as varchar(255))       as PracticePrincipalName,  
 cast(@DefaultPracticePrincipalCode as varchar(255))       as PracticePrincipalCode,     
 cast(@DefaultPracticeSupervisorName as varchar(255))      as PracticeSupervisorName,  
 cast(@DefaultPracticeSupervisorCode as varchar(255))      as PracticeSupervisorCode,     
 cast(@DefaultPracticeAdministratorName as varchar(255))   as PracticeAdministratorName,  
 cast(@DefaultPracticeAdministratorCode as varchar(255))   as PracticeAdministratorCode,    
 case when AgentCategory in (select distinct Code from #BusinessTypeCategories)   
  then rtrim(MIName) + ' (Franchise)'   
  else MIName end                                       as AdviserName,   
 code                                                      as AgentCode,  
 null                                                      as TransactionDate,  
 null                                                      as DomainName,  
 @ProcessDate                                              as ChangeDate, -- AG 25/09/2008  
 1                                                         as IsCurrent  
  
into #SubRegionLevelAgents  
from mstt_Agents  
where agentcategory in (select distinct Code from #SalesHierarchyCategories)  
  
  
  
select  isnull(CompanyCode, @DefaultCompanyName)             as [Exec],   
 cast(@DefaultAreaSalesManagerName as varchar(255))       as AreaSalesManager,   
 isnull(Manager4Code, @DefaultAreaSalesManagerCode)       as AreaSalesManagerCode,   
 cast(@DefaultAreaName as varchar(255))                   as AreaName,   
 isnull(LocationCode, @DefaultAreaCode)                   as AreaCode,   
 cast(@DefaultRegionalSalesManagerName as varchar(255))   as RegionalSalesManager,   
 isnull(Manager2Code, @DefaultRegionalSalesManagerCode)   as RegionalSalesManagerCode,   
 cast(@DefaultSalesQualityManagerName as varchar(255))    as SalesQualityManager,   
 isnull(Manager1Code, @DefaultSalesQualityManagerCode)    as SalesQualityManagerCode,   
 cast(@DefaultFranchiseName as varchar(255))              as Franchise,   
 isnull(Code, @DefaultFranchiseCode)                      as FranchiseCode,   
 FranchiseSize,  
 @DefaultFranchiseSizeID                                  as FranchiseSizeID,   
 @DefaultFranchiseSegmentID                               as FranchiseSegmentID,   
 cast(@DefaultPracticePrincipalName as varchar(255))      as PracticePrincipalName,  
 cast(@DefaultPracticePrincipalCode as varchar(255))      as PracticePrincipalCode,     
 cast(@DefaultPracticeSupervisorName as varchar(255))     as PracticeSupervisorName,  
 cast(@DefaultPracticeSupervisorCode as varchar(255))     as PracticeSupervisorCode,     
 cast(@DefaultPracticeAdministratorName as varchar(255))  as PracticeAdministratorName,  
 cast(@DefaultPracticeAdministratorCode as varchar(255))  as PracticeAdministratorCode,    
 MIName                                                   as AdviserName,   
 code                                                     as AgentCode,  
 null                                                     as TransactionDate,  
 null                                                     as DomainName,  
 @ProcessDate                                             as ChangeDate, -- AG 25/09/2008  
 1                                                        as IsCurrent  
  
into #SQMLevelAgents  
from mstt_Agents  
where agentcategory in ('SQMSL', 'SQMNS')  
  
  
  
select  isnull(CompanyCode, @DefaultCompanyName)             as [Exec],   
 cast(@DefaultAreaSalesManagerName as varchar(255))       as AreaSalesManager,   
 isnull(Manager4Code, @DefaultAreaSalesManagerCode)       as AreaSalesManagerCode,   
 cast(@DefaultAreaName as varchar(255))                   as AreaName,   
 isnull(LocationCode, @DefaultAreaCode)                   as AreaCode,   
 cast(@DefaultRegionalSalesManagerName as varchar(255))   as RegionalSalesManager,   
 isnull(Code, @DefaultRegionalSalesManagerCode)           as RegionalSalesManagerCode,   
 cast(@DefaultSalesQualityManagerName as varchar(255))    as SalesQualityManager,   
 isnull(Manager1Code, @DefaultSalesQualityManagerCode)    as SalesQualityManagerCode,   
 cast(@DefaultFranchiseName as varchar(255))              as Franchise,   
 isnull(Code, @DefaultFranchiseCode)                      as FranchiseCode,   
 FranchiseSize,  
 @DefaultFranchiseSizeID                                  as FranchiseSizeID,   
 @DefaultFranchiseSegmentID                   as FranchiseSegmentID,   
 cast(@DefaultPracticePrincipalName as varchar(255))      as PracticePrincipalName,  
 cast(@DefaultPracticePrincipalCode as varchar(255))      as PracticePrincipalCode,     
 cast(@DefaultPracticeSupervisorName as varchar(255))     as PracticeSupervisorName,  
 cast(@DefaultPracticeSupervisorCode as varchar(255))     as PracticeSupervisorCode,     
 cast(@DefaultPracticeAdministratorName as varchar(255))  as PracticeAdministratorName,  
 cast(@DefaultPracticeAdministratorCode as varchar(255))  as PracticeAdministratorCode,    
 MIName                                                   as AdviserName,   
 code                                                     as AgentCode,  
 null                                                     as TransactionDate,  
 null                                                     as DomainName,  
 @ProcessDate                                             as ChangeDate, -- AG 25/09/2008  
 1                                                        as IsCurrent  
  
into #RSMLevelAgents  
from mstt_Agents  
where agentcategory in ('RSMSL', 'RSMNS', 'SRSMSL')  
  
  
  
  
--Consolidate these records  
select q.*, ' ' as IsNew, -2 as RelatesTo  
into #AllSellers  
from   
(  
select * from #RSMLevelAgents  
union all  
select * from #SQMLevelAgents  
union all  
select * from #SubRegionLevelAgents  
) q  
  
  
drop table #RSMLevelAgents  
drop table #SQMLevelAgents  
drop table #SubRegionLevelAgents  
  
  
--re-do the 'hierarchy' as the data is unreliable in S_AGENTS!!   
--get the Region Manager for the Franchise  
update t  
set RegionalSalesManagerCode = isnull(Manager2Code, @DefaultRegionalSalesManagerCode) --RegionalSalesManagerCode)   
from #AllSellers t  
 inner join mstt_Agents a  
  on t.FranchiseCode = a.Code  
--We do NOT want to re-set the RSM Code, if the agent itself is above Franchise Level. See below.   
where not exists (select 'x' from mstt_agents ag  
   where t.AgentCode = ag.Code  
   and AgentCategory in ('SQMSL', 'SQMNS', 'RSMSL', 'RSMNS', 'SRSMSL'))  
  
--Get the AreaManager for the RegionManager  
update t  
set AreaSalesManagerCode = isnull(Manager4Code, @DefaultAreaSalesManagerCode) --AreaSalesManagerCode)   
from #AllSellers t  
 inner join mstt_Agents a  
  on t.RegionalSalesManagerCode = a.Code  
  
--get the 'Exec' for the AreaManager  
update t  
set [Exec] = isnull(CompanyCode, [Exec]) --@DefaultCompanyName)  
from #AllSellers t  
 inner join mstt_Agents a  
  on t.AreaSalesManagerCode = a.Code  
  
  
--get the LocationCode (ie AreaCode) for each person, based on the location of the Area Manager  
update t  
set AreaCode = isnull(LocationCode, @DefaultAreaCode)  
from #AllSellers t  
 inner join mstt_Agents a  
  on t.AreaSalesManagerCode = a.Code  
  
  
--Now get all the descriptions  
update t  
set AreaSalesManager = a.MIName  
from #AllSellers t  
 inner join mstt_Agents a  
  on t.AreaSalesManagerCode = a.Code  
  
  
update t  
set AreaName = a.[Description]  
from #AllSellers t  
 inner join msit_CodeLocations a  
  on t.AreaCode = a.Code  
   
  
update t  
set RegionalSalesManager = a.MIName  
from #AllSellers t  
 inner join mstt_Agents a  
  on t.RegionalSalesManagerCode = a.Code  
   
  
update t  
set SalesQualityManager = a.MIName  
from #AllSellers t  
 inner join mstt_Agents a  
  on t.SalesQualityManagerCode = a.Code  
  
  
update t  
set Franchise = a.MIName  
from #AllSellers t  
 inner join mstt_Agents a  
  on t.FranchiseCode = a.Code  
   
  
--resolve the surrogate keys  
update t  
set FranchiseSizeID = f.FranchiseSizeID   
from #AllSellers t  
 inner join mstt_Agents a  
  on t.AgentCode = a.Code  
 inner join mstt_Agents fa  
  on coalesce(a.FranchiseCode,   
    a.DirectlyAuthorisedCode,  
    a.OfficeCode,  
    a.AccessAgentCode,  
    a.StrategicAllianceCode) = fa.Code  
  inner join msdt_FranchiseSize f  
   on fa.FranchiseSize = f.FranchiseSize  
     
     
--resolve the FranchiseSizeId for Franchise Agents  
update t  
set FranchiseSizeID = f.FranchiseSizeID   
from #AllSellers t  
 inner join mstt_Agents a  
  on t.AgentCode = a.Code  
  inner join msdt_FranchiseSize f  
   on a.FranchiseSize = f.FranchiseSize     
where a.AgentCategory in (select distinct Code from #BusinessTypeCategories)        
  
  
--Clear down the Adviser Table  
truncate table msdt_Adviser  
  
  
--decide whether this is a new Adviser, and as such needs to be inserted.  
Update t  
set IsNew = 'Y'  
from #AllSellers t  
where not exists (select 'x'   
  from msdt_Adviser a  
  where t.AgentCode = a.AgentCode)  
  
--insert any new advisers  
insert into msdt_Adviser  
(  
 [Exec],   
 AreaSalesManager,   
 AreaSalesManagerCode,   
 AreaSalesQualityManager,   
 AreaSalesQualityManagerCode,   
 AreaName,   
 AreaCode,   
 RegionalSalesManager,   
 RegionalSalesManagerCode,   
 RegionName,   
 RegionCode,   
 SalesQualityManager,   
 SalesQualityManagerCode,   
 Franchise,   
 FranchiseCode,  
 FranchiseSizeID,   
 FranchiseSegmentID,   
 PracticePrincipal,   
 PracticePrincipalCode,   
 PracticeSupervisor,   
 PracticeSupervisorCode,   
 PracticeAdministrator,   
 PracticeAdministratorCode,   
 Adviser,   
 AgentCode,   
 TransactionDate,   
 DomainName,   
 ChangeDate,   
 IsCurrent  
)  
select   
 [Exec],   
 AreaSalesManager,   
 AreaSalesManagerCode,   
 null as AreaSalesQualityManager,   
 null as AreaSalesQualityManagerCode,   
 AreaName,   
 AreaCode,   
 RegionalSalesManager,   
 RegionalSalesManagerCode,   
 null as RegionName,  
 null as RegionCode,  
 SalesQualityManager,   
 SalesQualityManagerCode,   
 Franchise,   
 FranchiseCode,   
 FranchiseSizeID,   
 FranchiseSegmentID,   
 PracticePrincipalName,   
 PracticePrincipalCode,   
 PracticeSupervisorName,   
 PracticeSupervisorCode,   
 PracticeAdministratorName,   
 PracticeAdministratorCode,   
 AdviserName,   
 AgentCode,   
 TransactionDate,   
 DomainName,   
 ChangeDate,   
 IsCurrent  
from   
 #AllSellers  
where   
 IsNew = 'Y'  
  
 --JNG  
 ORDER BY  
  [Exec],   
  AreaSalesManager,   
  AreaSalesManagerCode,   
  AreaName,   
  AreaCode,   
  RegionalSalesManager,   
  RegionalSalesManagerCode,   
  SalesQualityManager,   
  SalesQualityManagerCode,   
  Franchise,   
  FranchiseCode,   
  FranchiseSizeID,   
  FranchiseSegmentID,   
  PracticePrincipalName,   
  PracticePrincipalCode,   
  PracticeSupervisorName,   
  PracticeSupervisorCode,   
  PracticeAdministratorName,   
  PracticeAdministratorCode,   
  AdviserName,   
  AgentCode,   
  TransactionDate,   
  DomainName,   
  ChangeDate,   
  IsCurrent  
 --JNG   
  
--decide whether this record has changed enough to generate a new record (Type 2 change)  
update t  
set RelatesTo = a.AdviserID  
from #AllSellers t  
 inner join msdt_Adviser a  
  on t.AgentCode = a.AgentCode  
where a.IsCurrent = 1  
and   
(  
 t.[EXEC] <> a.[EXEC]  
 or t.AreaSalesManagerCode <> a.AreaSalesManagerCode  
 or t.AreaCode <> a.AreaCode  
 or t.RegionalSalesManagerCode <> a.RegionalSalesManagerCode  
 or t.SalesQualityManagerCode <> a.SalesQualityManagerCode  
 or t.FranchiseCode <> a.FranchiseCode  
 or t.PracticePrincipalCode <> a.PracticePrincipalCode  
 or t.PracticeSupervisorCode <> a.PracticeSupervisorCode  
 or t.PracticeAdministratorCode <> a.PracticeAdministratorCode  
)  
    
--insert the 'changes'  
  
insert into msdt_Adviser   
 (  
 [Exec],   
 AreaSalesManager,   
 AreaSalesManagerCode,   
  AreaSalesQualityManager,   
  AreaSalesQualityManagerCode,   
 AreaName,   
 AreaCode,   
 RegionalSalesManager,   
 RegionalSalesManagerCode,   
  RegionName,   
  RegionCode,   
 SalesQualityManager,   
 SalesQualityManagerCode,   
 Franchise,   
 FranchiseCode,   
 FranchiseSizeID,   
 FranchiseSegmentID,   
 PracticePrincipal,   
 PracticePrincipalCode,   
 PracticeSupervisor,   
 PracticeSupervisorCode,   
 PracticeAdministrator,   
 PracticeAdministratorCode,   
 Adviser,   
 AgentCode,   
 TransactionDate,   
 DomainName,   
 ChangeDate,   
 IsCurrent  
 )  
  
select   
 [Exec],   
 AreaSalesManager,   
 AreaSalesManagerCode,   
 null as AreaSalesQualityManager,   
 null as AreaSalesQualityManagerCode,   
 AreaName,   
 AreaCode,   
 RegionalSalesManager,   
 RegionalSalesManagerCode,   
 null as RegionName,  
 null as RegionCode,  
 SalesQualityManager,   
 SalesQualityManagerCode,   
 Franchise,   
 FranchiseCode,   
 FranchiseSizeID,   
 FranchiseSegmentID,   
 PracticePrincipalName,   
 PracticePrincipalCode,   
 PracticeSupervisorName,   
 PracticeSupervisorCode,   
 PracticeAdministratorName,   
 PracticeAdministratorCode,   
 AdviserName,   
 AgentCode,   
 TransactionDate,   
 DomainName,   
 ChangeDate,   
 IsCurrent  
   
from #AllSellers a  
where RelatesTo <> -2  
  
  
  
--remove the IsCurrent = 1 from the recently 'updated' records.  
update a  
set IsCurrent = 0  
from msdt_Adviser a  
 inner join #AllSellers t  
  on a.AdviserID = t.RelatesTo  
  
drop table #AllSellers  
  
  
--Load the Dummy Advisers...  
  
truncate table msdt_AdviserDummies  
  
--Create the Exec level Dummy  
insert into msdt_AdviserDummies   
 ([Exec],   
 AreaSalesManager,   
 AreaSalesManagerCode,  
 AreaName,   
 AreaCode,   
 RegionalSalesManager,   
 RegionalSalesManagerCode,  
 Franchise,   
 FranchiseCode,  
 FranchiseSizeId,  
 PracticePrincipal,   
 PracticePrincipalCode,  
 PracticeSupervisor,   
 PracticeSupervisorCode,  
 PracticeAdministrator,   
 PracticeAdministratorCode,  
 Adviser,   
 AgentCode,   
 TransactionDate,   
 DomainName,   
 ChangeDate,   
 IsCurrent)  
select distinct   
 'All Adviser',   
 'All Adviser',   
 'EXEC_DUMMY_CODE',  
 @DefaultAreaName as AreaName,   
 @DefaultAreaCode as AreaCode,  
 'All Adviser',   
 'EXEC_DUMMY_CODE',  
 'All Adviser'   as Franchise,   
 'EXEC_DUMMY_CODE' as FranchiseCode,  
 -99   as FranchiseSizeId,  
 'All Adviser'  as PracticePrincipal,   
 'EXEC_DUMMY_CODE' as PracticePrincipalCode,  
 'All Adviser'  as PracticeSupervisor,   
 'EXEC_DUMMY_CODE' as PracticeSupervisorCode,  
 'All Adviser'  as PracticeAdministrator,   
 'EXEC_DUMMY_CODE' as PracticeAdministratorCode,  
 'All Adviser'  as Adviser,   
 'EXEC_DUMMY_CODE' as AgentCode,   
 null    as TransactionDate,   
 null    as DomainName,   
 null    as ChangeDate,   
 1    as IsCurrent  
from msdt_Adviser a  
where not exists (select 'x' from msdt_adviserdummies a2   
  where 'EXEC_DUMMY_CODE' = a2.AgentCode)  
  
  
  
--Create the AreaSalesManager Dummies  
insert into msdt_AdviserDummies    
 ([Exec],   
 AreaSalesManager,   
 AreaSalesManagerCode,  
 AreaName,   
 AreaCode,   
 RegionalSalesManager,   
 RegionalSalesManagerCode,  
 Franchise,   
 FranchiseCode,  
 FranchiseSizeId,  
 PracticePrincipal,   
 PracticePrincipalCode,  
 PracticeSupervisor,   
 PracticeSupervisorCode,  
 PracticeAdministrator,   
 PracticeAdministratorCode,  
 Adviser,   
 AgentCode,   
 TransactionDate,   
 DomainName,   
 ChangeDate,   
 IsCurrent)  
select distinct   
 [Exec],   
 AreaSalesManager,   
 AreaSalesManagerCode,  
 AreaName,   
 AreaCode,   
 AreaSalesManager  as RegionalSalesManager,   
 AreaSalesManagerCode as RegionalSalesManagerCode,  
 AreaSalesManager  as Franchise,   
 AreaSalesManagerCode as FranchiseCode,  
 -99   as FranchiseSizeId,  
 AreaSalesManager as PracticePrincipal,   
 AreaSalesManagerCode as PracticePrincipalCode,  
 AreaSalesManager as PracticeSupervisor,   
 AreaSalesManagerCode as PracticeSupervisorCode,  
 AreaSalesManager as PracticeAdministrator,   
 AreaSalesManagerCode as PracticeAdministratorCode,  
 AreaSalesManager as Adviser,   
 Upper(AreaSalesManagerCode)+ '_ASM_DUMMY_CODE' as AgentCode,   
 null    as TransactionDate,   
 null    as DomainName,   
 null    as ChangeDate,   
 1    as IsCurrent  
from msdt_Adviser a  
where not exists (select 'x' from msdt_adviserdummies a2   
  where Upper(a.AreaSalesManagerCode)+ '_ASM_DUMMY_CODE' = a2.AgentCode)  
  
  
--Create the RegionalSalesManager Dummies  
insert into msdt_AdviserDummies   
 ([Exec],   
 AreaSalesManager,   
 AreaSalesManagerCode,  
 AreaName,   
 AreaCode,   
 RegionalSalesManager,   
 RegionalSalesManagerCode,  
 Franchise,   
 FranchiseCode,  
 FranchiseSizeId,  
 PracticePrincipal,   
 PracticePrincipalCode,  
 PracticeSupervisor,   
 PracticeSupervisorCode,  
 PracticeAdministrator,   
 PracticeAdministratorCode,  
 Adviser,   
 AgentCode,   
 TransactionDate,   
 DomainName,   
 ChangeDate,   
 IsCurrent)  
select distinct   
 [Exec],   
 AreaSalesManager,   
 AreaSalesManagerCode,  
 AreaName,   
 AreaCode,   
 RegionalSalesManager,   
 RegionalSalesManagerCode,  
 RegionalSalesManager   as Franchise,   
 RegionalSalesManagerCode as FranchiseCode,  
 -99    as FranchiseSizeId,  
 RegionalSalesManager  as PracticePrincipal,   
 RegionalSalesManagerCode as PracticePrincipalCode,  
 RegionalSalesManager  as PracticeSupervisor,   
 RegionalSalesManagerCode as PracticeSupervisorCode,  
 RegionalSalesManager  as PracticeAdministrator,   
 RegionalSalesManagerCode as PracticeAdministratorCode,  
 RegionalSalesManager  as Adviser,   
 Upper(RegionalSalesManagerCode)+ '_RSM_DUMMY_CODE' as AgentCode,   
 null    as TransactionDate,   
 null    as DomainName,   
 null    as ChangeDate,   
 1    as IsCurrent  
from msdt_Adviser a  
where not exists (select 'x' from msdt_adviserdummies a2   
  where Upper(a.RegionalSalesManagerCode)+ '_RSM_DUMMY_CODE' = a2.AgentCode)  
    
    
--Create the Franchise Dummies  
insert into msdt_AdviserDummies   
 ([Exec],   
 AreaSalesManager,   
 AreaSalesManagerCode,  
 AreaName,   
 AreaCode,   
 RegionalSalesManager,   
 RegionalSalesManagerCode,  
 Franchise,   
 FranchiseCode,  
 FranchiseSizeId,  
 PracticePrincipal,   
 PracticePrincipalCode,  
 PracticeSupervisor,   
 PracticeSupervisorCode,  
 PracticeAdministrator,   
 PracticeAdministratorCode,  
 Adviser,   
 AgentCode,   
 TransactionDate,   
 DomainName,   
 ChangeDate,   
 IsCurrent)  
select distinct   
 [Exec],   
 AreaSalesManager,   
 AreaSalesManagerCode,  
 AreaName,   
 AreaCode,   
 RegionalSalesManager,   
 RegionalSalesManagerCode,  
 Franchise   as Franchise,   
 FranchiseCode  as FranchiseCode,  
 FranchiseSizeId  as FranchiseSizeId,  
 Franchise  as PracticePrincipal,   
 FranchiseCode  as PracticePrincipalCode,  
 Franchise  as PracticeSupervisor,   
 FranchiseCode  as PracticeSupervisorCode,  
 Franchise  as PracticeAdministrator,   
 FranchiseCode  as PracticeAdministratorCode,  
 Franchise  as Adviser,   
 Upper(FranchiseCode)+ '_FRANCHISE_DUMMY_CODE' as AgentCode,   
 null    as TransactionDate,   
 null    as DomainName,   
 null    as ChangeDate,   
 1    as IsCurrent  
from msdt_Adviser a  
where a.IsCurrent = 1  
and not exists (select 'x' from msdt_adviserdummies a2   
  where Upper(a.FranchiseCode)+ '_FRANCHISE_DUMMY_CODE' = a2.AgentCode)    
  
  
if not exists (select * from msdt_Adviser where adviserID = -99)  
 begin  
  set identity_insert msdt_Adviser on  
    
  insert into msdt_Adviser   
   (AdviserID,   
   [Exec],   
   AreaSalesManager,   
   AreaSalesManagerCode,   
   AreaSalesQualityManager,   
   AreaSalesQualityManagerCode,   
   AreaName,   
   AreaCode,   
   RegionalSalesManager,   
   RegionalSalesManagerCode,   
   RegionName,   
   RegionCode,   
   SalesQualityManager,   
   SalesQualityManagerCode,   
   Franchise,   
   FranchiseCode,   
   FranchiseSizeID,   
   FranchiseSegmentID,   
   PracticePrincipal,   
   PracticePrincipalCode,   
   PracticeSupervisor,   
   PracticeSupervisorCode,   
   PracticeAdministrator,   
   PracticeAdministratorCode,   
   Adviser,   
   AgentCode,   
   TransactionDate,   
   DomainName,   
   ChangeDate,   
   IsCurrent)  
  select   
   @DefaultAdviserID,   
   @DefaultCompanyName,   
   @DefaultAreaSalesManagerName,   
   @DefaultAreaSalesManagerCode,   
   @DefaultAreaSalesManagerName,   
   @DefaultAreaSalesManagerCode,   
   @DefaultAreaName,   
   @DefaultAreaCode,   
   @DefaultRegionalSalesManagerName,   
   @DefaultRegionalSalesManagerCode,   
   @DefaultAreaName,   
   @DefaultAreaCode,   
   @DefaultSalesQualityManagerName,   
   @DefaultSalesQualityManagerCode,   
   @DefaultFranchiseName,   
   @DefaultFranchiseCode,   
   @DefaultFranchiseSizeID,   
   @DefaultFranchiseSegmentID,   
   @DefaultPracticePrincipalName,   
   @DefaultPracticePrincipalCode,   
   @DefaultPracticeSupervisorName,   
   @DefaultPracticeSupervisorCode,   
   @DefaultPracticeAdministratorName,   
   @DefaultPracticeAdministratorCode,   
   @DefaultAdviserName,   
   @DefaultAgentCode,   
   null,   
   null,   
   null,   
   1  
   
  set identity_insert msdt_Adviser off  
   
 end  
  
END  
  
  
  


GO
/****** Object:  StoredProcedure [dbo].[mstp_AdviserDummiesFromInactiveOWFranchises]    Script Date: 7/3/2026 3:44:25 PM ******/
