create procedure [dbo].[mstp_AdviserDummiesFromInactiveOWFranchises] as

begin

declare @DefaultCompanyCode       varchar(50)
declare @DefaultCompanyName       varchar(50)
declare @DefaultAreaSalesManagerName      varchar(50)
declare @DefaultAreaSalesManagerCode      varchar(50)
declare @DefaultAreaName        varchar(50)
declare @DefaultAreaCode        varchar(50)
declare @DefaultRegionalSalesManagerName    varchar(50)
declare @DefaultRegionalSalesManagerCode    varchar(50)
declare @DefaultSalesQualityManagerName   varchar(50)
declare @DefaultSalesQualityManagerCode   varchar(50)
declare @DefaultFranchiseName       varchar(50)
declare @DefaultFranchiseCode       varchar(50)
declare @DefaultFranchiseSizeID     int
declare @DefaultFranchiseSegmentID      int
declare @DefaultPracticePrincipalName     varchar(50)
declare @DefaultPracticePrincipalCode     varchar(50)
declare @DefaultPracticeSupervisorName    varchar(50)
declare @DefaultPracticeSupervisorCode    varchar(50)
declare @DefaultPracticeAdministratorName   varchar(50)
declare @DefaultPracticeAdministratorCode   varchar(50)
declare @DefaultAdviserID       int
declare @DefaultAdviserName       varchar(50)
declare @DefaultAgentCode       varchar(50)

set @DefaultCompanyCode     = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'CompanyCode')
set @DefaultCompanyName     = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'CompanyName')
set @DefaultAreaSalesManagerName  = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AreaSalesManagerName')
set @DefaultAreaSalesManagerCode  = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AreaSalesManagerCode')
set @DefaultAreaName      = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AreaName')
set @DefaultAreaCode      = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AreaCode')
set @DefaultRegionalSalesManagerName  = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'RegionalSalesManagerName')
set @DefaultRegionalSalesManagerCode  = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'RegionalSalesManagerCode')
set @DefaultSalesQualityManagerName   = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'SalesQualityManagerName')
set @DefaultSalesQualityManagerCode   = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'SalesQualityManagerCode')
set @DefaultFranchiseName     = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'FranchiseName')
set @DefaultFranchiseCode     = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'FranchiseCode')
set @DefaultFranchiseSizeID     = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'FranchiseSizeID')
set @DefaultFranchiseSegmentID    = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'FranchiseSegmentID')
set @DefaultPracticePrincipalName   = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'PracticePrincipalName')
set @DefaultPracticePrincipalCode   = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'PracticePrincipalCode')
set @DefaultPracticeSupervisorName  = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'PracticeSupervisorName')
set @DefaultPracticeSupervisorCode  = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'PracticeSupervisorCode')
set @DefaultPracticeAdministratorName   = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'PracticeAdministratorName')
set @DefaultPracticeAdministratorCode   = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'PracticeAdministratorCode')
set @DefaultAdviserID       = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'AdviserID')
set @DefaultAdviserName     = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AdviserName')
set @DefaultAgentCode       = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AgentCode')


delete from msdt_AdviserDummies
where FranchiseCode like 'INACTIVE_%'


select 
[Exec],
AreaSalesManager, 
AreaSalesManagerCode, 
AreaSalesQualityManager, 
AreaSalesQualityManagerCode, 
AreaName, 
AreaCode, 
RegionalSalesManager, 
RegionalSalesManagerCode, 
RegionName, RegionCode, 
SalesQualityManager, 
SalesQualityManagerCode, 
Franchise, 
FranchiseCode, 
FranchiseSizeID, 
FranchiseSegmentID, 
PracticePrincipal, 
PracticePrincipalCode, 
PracticeSupervisor, 
PracticeSupervisorCode, 
PracticeAdministrator, 
PracticeAdministratorCode, 
Adviser, 
AgentCode, 
TransactionDate, 
DomainName, 
ChangeDate, 
IsCurrent
into #InactiveDummies
from msdt_AdviserDummies
where 1=2


insert into #InactiveDummies
(
[Exec],
AreaSalesManager, 
AreaSalesManagerCode, 
AreaSalesQualityManager, 
AreaSalesQualityManagerCode, 
AreaName, 
AreaCode, 
RegionalSalesManager, 
RegionalSalesManagerCode, 
RegionName, 
RegionCode, 
SalesQualityManager, 
SalesQualityManagerCode, 
Franchise, 
FranchiseCode, 
FranchiseSizeID, 
FranchiseSegmentID, 
PracticePrincipal, 
PracticePrincipalCode, 
PracticeSupervisor, 
PracticeSupervisorCode, 
PracticeAdministrator, 
PracticeAdministratorCode, 
Adviser, 
AgentCode, 
TransactionDate, 
DomainName, 
ChangeDate, 
IsCurrent
)
select 
@DefaultCompanyName     as [Exec],
@DefaultAreaSalesManagerName    as AreaSalesManager, 
@DefaultAreaSalesManagerCode    as AreaSalesManagerCode, 
@DefaultAreaSalesManagerName    as AreaSalesQualityManager, 
@DefaultAreaSalesManagerCode    as AreaSalesQualityManagerCode, 
@DefaultAreaName      as AreaName, 
@DefaultAreaCode      as AreaCode, 
@DefaultRegionalSalesManagerName  as RegionalSalesManager, 
isnull(RSM_SWIFT_ID, @DefaultRegionalSalesManagerCode) as RegionalSalesManagerCode, 
@DefaultAreaName      as RegionName, 
@DefaultAreaCode      as RegionCode, 
@DefaultSalesQualityManagerName   as SalesQualityManager, 
@DefaultSalesQualityManagerCode   as SalesQualityManagerCode, 
Fullname        as Franchise, 
'INACTIVE_'+Agent_ID      as FranchiseCode, 
@DefaultFranchiseSizeID     as FranchiseSizeID, 
@DefaultFranchiseSegmentID    as FranchiseSegmentID, 
@DefaultPracticePrincipalName   as PracticePrincipal, 
@DefaultPracticePrincipalCode   as PracticePrincipalCode, 
@DefaultPracticeSupervisorName    as PracticeSupervisor, 
@DefaultPracticeSupervisorCode    as PracticeSupervisorCode, 
@DefaultPracticeAdministratorName as PracticeAdministrator, 
@DefaultPracticeAdministratorCode as PracticeAdministratorCode, 
Fullname+' (Inactive)'      as Adviser, 
'INACTIVE_'+Agent_ID      as AgentCode, 
null          as TransactionDate, 
null          as DomainName, 
null          as ChangeDate, 
1         as IsCurrent
from msit_InactiveOWFranch


--re-do the 'hierarchy' as the data is unreliable in S_AGENTS!! 


--Get the AreaManager for the RegionManager
update t
set AreaSalesManagerCode = isnull(Manager4Code, @DefaultAreaSalesManagerCode)
from #InactiveDummies t
  inner join mstt_Agents a
    on t.RegionalSalesManagerCode = a.Code

--get the 'Exec' for the AreaManager
update t
set [Exec] = isnull(CompanyCode, @DefaultCompanyName)
from #InactiveDummies t
  inner join mstt_Agents a
    on t.AreaSalesManagerCode = a.Code


--get the LocationCode (ie AreaCode) for each person, based on the location of the Area Manager
update t
set AreaCode = isnull(LocationCode, @DefaultAreaCode)
from #InactiveDummies t
  inner join mstt_Agents a
    on t.AreaSalesManagerCode = a.Code


--Now get all the descriptions
update t
set AreaSalesManager = a.MIName
from #InactiveDummies t
  inner join mstt_Agents a
    on t.AreaSalesManagerCode = a.Code


update t
set AreaName = a.[Description]
from #InactiveDummies t
  inner join msit_CodeLocations a
    on t.AreaCode = a.Code
 

update t
set RegionalSalesManager = a.MIName
from #InactiveDummies t
  inner join mstt_Agents a
    on t.RegionalSalesManagerCode = a.Code
 

update t
set SalesQualityManager = a.MIName
from #InactiveDummies t
  inner join mstt_Agents a
    on t.SalesQualityManagerCode = a.Code


insert into msdt_AdviserDummies
(
  [Exec], 
  AreaSalesManager, 
  AreaSalesManagerCode, 
  AreaSalesQualityManager, 
  AreaSalesQualityManagerCode, 
  AreaName, 
  AreaCode, 
  RegionalSalesManager, 
  RegionalSalesManagerCode, 
  RegionName, 
  RegionCode, 
  SalesQualityManager, 
  SalesQualityManagerCode, 
  Franchise, 
  FranchiseCode, 
  FranchiseSizeID, 
  FranchiseSegmentID, 
  PracticePrincipal, 
  PracticePrincipalCode, 
  PracticeSupervisor, 
  PracticeSupervisorCode, 
  PracticeAdministrator, 
  PracticeAdministratorCode, 
  Adviser, 
  AgentCode, 
  TransactionDate, 
  DomainName, 
  ChangeDate, 
  IsCurrent
)
select 
  [Exec], 
  AreaSalesManager, 
  AreaSalesManagerCode, 
  AreaSalesQualityManager, 
  AreaSalesQualityManagerCode, 
  AreaName, 
  AreaCode, 
  RegionalSalesManager, 
  RegionalSalesManagerCode, 
  RegionName, 
  RegionCode, 
  SalesQualityManager, 
  SalesQualityManagerCode, 
  Franchise, 
  FranchiseCode, 
  FranchiseSizeID, 
  FranchiseSegmentID, 
  PracticePrincipal, 
  PracticePrincipalCode, 
  PracticeSupervisor, 
  PracticeSupervisorCode, 
  PracticeAdministrator, 
  PracticeAdministratorCode, 
  Adviser, 
  AgentCode, 
  TransactionDate, 
  DomainName, 
  ChangeDate, 
  IsCurrent
from #InactiveDummies



drop table #InactiveDummies



end


