  null      as DomainName, 
  null      as ChangeDate, 
  1       as IsCurrent,
  ' '     as IsNew,
  -2      as RelatesTo
into #AdviserDummiesHistory
from msdt_AdviserHistory a

union all 

--Create the AreaSalesManager Dummies
select distinct 
  [Exec], 
  AreaSalesManager, 
  AreaSalesManagerCode,
--  AreaSalesQualityManager, 
--  AreaSalesQualityManagerCode,
  AreaName, 
  AreaCode, 
  AreaSalesManager  as RegionalSalesManager, 
  AreaSalesManagerCode  as RegionalSalesManagerCode,
--  AreaSalesQualityManager as SalesQualityManager, 
--  AreaSalesQualityManagerCode as SalesQualityManagerCode,
  AreaSalesManager  as Franchise, 
