  null      as DomainName, 
  null      as ChangeDate, 
  1       as IsCurrent,
  ' '     as IsNew,
  -2      as RelatesTo
from msdt_AdviserHistory a
where IsCurrent = 1
    
union all
    
--Create the Franchise Dummies
select distinct 
  [Exec], 
  AreaSalesManager, 
  AreaSalesManagerCode,
--  AreaSalesQualityManager, 
--  AreaSalesQualityManagerCode,
  AreaName, 
  AreaCode, 
  RegionalSalesManager, 
  RegionalSalesManagerCode,
--  AreaSalesQualityManager as SalesQualityManager, 
--  AreaSalesQualityManagerCode as SalesQualityManagerCode,
  Franchise     as Franchise, 
  FranchiseCode   as FranchiseCode,
  FranchiseSizeId   as FranchiseSizeId,
  Franchise   as PracticePrincipal, 
  FranchiseCode   as PracticePrincipalCode,
  Franchise   as PracticeSupervisor, 
  FranchiseCode   as PracticeSupervisorCode,
  Franchise   as PracticeAdministrator, 
  FranchiseCode   as PracticeAdministratorCode,
  Franchise   as Adviser, 
  Upper(FranchiseCode)+ '_FRANCHISE_DUMMY_CODE' as AgentCode, 
  null      as TransactionDate, 
  null      as DomainName, 
  null      as ChangeDate, 
  1       as IsCurrent,
  ' '     as IsNew,
  -2      as RelatesTo
from msdt_AdviserHistory a
where IsCurrent = 1

--decide whether this is a new Dummy Adviser, and as such needs to be inserted.
Update t
set IsNew = 'Y'
from #AdviserDummiesHistory t
where not exists (select 'x' 
    from msdt_AdviserDummiesHistory a
    where t.AgentCode = a.AgentCode)

--insert any new advisers
insert into msdt_AdviserDummiesHistory
(
  [Exec], 
  AreaSalesManager, 
  AreaSalesManagerCode, 
  AreaSalesQualityManager, 
  AreaSalesQualityManagerCode, 
  AreaName, 
  AreaCode, 
  RegionalSalesManager, 
  RegionalSalesManagerCode, 
  RegionName, 
  RegionCode, 
  SalesQualityManager, 
