  FranchiseSizeID, 
  FranchiseSegmentID, 
  PracticePrincipal, 
  PracticePrincipalCode, 
  PracticeSupervisor, 
  PracticeSupervisorCode, 
  PracticeAdministrator, 
  PracticeAdministratorCode, 
  Adviser, 
  AgentCode, 
  TransactionDate, 
  DomainName, 
  ChangeDate, 
  IsCurrent
)
select 
  [Exec], 
  AreaSalesManager, 
  AreaSalesManagerCode, 
  null as AreaSalesQualityManager, 
  null as AreaSalesQualityManagerCode, 
  AreaName, 
  AreaCode, 
  RegionalSalesManager, 
  RegionalSalesManagerCode, 
  null as RegionName,
  null as RegionCode,
  null as SalesQualityManager, 
  null as SalesQualityManagerCode, 
  Franchise, 
  FranchiseCode, 
  FranchiseSizeID, 
  null as FranchiseSegmentID, 
  null as PracticePrincipalName, 
  PracticePrincipalCode, 
  null as PracticeSupervisorName, 
  PracticeSupervisorCode, 
  null as PracticeAdministratorName, 
  PracticeAdministratorCode, 
  Adviser, 
  AgentCode, 
  TransactionDate, 
  DomainName, 
  ChangeDate, 
  IsCurrent
from 
  #AdviserDummiesHistory
where 
  IsNew = 'Y'

--decide whether this record has changed enough to generate a new record (Type 2 change)
update t
set RelatesTo = a.AdviserID
from #AdviserDummiesHistory t
  inner join msdt_AdviserDummiesHistory a
    on t.AgentCode = a.AgentCode
where a.IsCurrent = 1
and 
(
  t.[EXEC] <> a.[EXEC]
  or t.AreaSalesManagerCode <> a.AreaSalesManagerCode
  or t.AreaCode <> a.AreaCode
  or t.RegionalSalesManagerCode <> a.RegionalSalesManagerCode
  --or t.SalesQualityManagerCode <> a.SalesQualityManagerCode
  or t.FranchiseCode <> a.FranchiseCode
  or t.PracticePrincipalCode <> a.PracticePrincipalCode
  or t.PracticeSupervisorCode <> a.PracticeSupervisorCode
  or t.PracticeAdministratorCode <> a.PracticeAdministratorCode
)
    
--insert the 'changes'
insert into msdt_AdviserDummiesHistory
  (
  [Exec], 
  AreaSalesManager, 
  AreaSalesManagerCode, 
  AreaSalesQualityManager, 
  AreaSalesQualityManagerCode, 
  AreaName, 
  AreaCode, 
  RegionalSalesManager, 
  RegionalSalesManagerCode, 
  RegionName, 
  RegionCode, 
  SalesQualityManager, 
  SalesQualityManagerCode, 
  Franchise, 
  FranchiseCode, 
  FranchiseSizeID, 
  FranchiseSegmentID, 
  PracticePrincipal, 
  PracticePrincipalCode, 
  PracticeSupervisor, 
  PracticeSupervisorCode, 
  PracticeAdministrator, 
  PracticeAdministratorCode, 
  Adviser, 
  AgentCode, 
  TransactionDate, 
  DomainName, 
  ChangeDate, 
  IsCurrent
  )

select 
  [Exec], 
  AreaSalesManager, 
  AreaSalesManagerCode, 
  null as AreaSalesQualityManager, 
  null as AreaSalesQualityManagerCode, 
  AreaName, 
  AreaCode, 
  RegionalSalesManager, 
  RegionalSalesManagerCode, 
  null as RegionName,
  null as RegionCode,
  null as SalesQualityManager, 
  null as SalesQualityManagerCode, 
  Franchise, 
  FranchiseCode, 
  FranchiseSizeID, 
  null as FranchiseSegmentID, 
  null as PracticePrincipalName, 
  PracticePrincipalCode, 
  null as PracticeSupervisorName, 
  PracticeSupervisorCode, 
  null as PracticeAdministratorName, 
  PracticeAdministratorCode, 
  Adviser, 
  AgentCode, 
  TransactionDate, 
  DomainName, 
  ChangeDate, 
  IsCurrent
  
from #AdviserDummiesHistory a
where RelatesTo <> -2



--remove the IsCurrent = 1 from the recently 'updated' records.
update a
set IsCurrent = 0
from msdt_AdviserDummiesHistory a
  inner join #AdviserDummiesHistory t
    on a.AdviserID = t.RelatesTo


--MK: (TPR 2512) Ensure that if a name has changed, then it is updated in the History Records
update a
set Adviser = new.Adviser
from msdt_AdviserDummiesHistory a
  inner join #AdviserDummiesHistory new
    on a.AgentCode = new.AgentCode
    
select distinct FranchiseCode, Franchise
into #DummyFranchises
from #AdviserDummiesHistory
order by 1
    
update a
set Franchise = new.Franchise
from msdt_AdviserDummiesHistory a
  inner join #DummyFranchises new
    on a.FranchiseCode = new.FranchiseCode
    
select distinct RegionalSalesManagerCode, RegionalSalesManager
into #DummyRSMs
from #AdviserDummiesHistory
order by 1
    
update a
set RegionalSalesManager = new.RegionalSalesManager
from msdt_AdviserDummiesHistory a
  inner join #DummyRSMs new
    on a.RegionalSalesManagerCode = new.RegionalSalesManagerCode
    
select distinct AreaSalesManagerCode, AreaSalesManager
into #DummyASMs
from #AdviserDummiesHistory
order by 1    
    
update a
set AreaSalesManager = new.AreaSalesManager
from msdt_AdviserDummiesHistory a
  inner join #DummyASMs new
    on a.AreaSalesManagerCode = new.AreaSalesManagerCode                


drop table #AdviserDummiesHistory
drop table #DummyFranchises
drop table #DummyRSMs
drop table #DummyASMs



if not exists (select * from msdt_AdviserHistory where adviserID = -99)
  begin
    set identity_insert msdt_AdviserHistory on
    
    insert into msdt_AdviserHistory 
      (AdviserID, 
      [Exec], 
      AreaSalesManager, 
      AreaSalesManagerCode, 
      AreaSalesQualityManager, 
      AreaSalesQualityManagerCode, 
      AreaName, 
      AreaCode, 
      RegionalSalesManager, 
      RegionalSalesManagerCode, 
      RegionName, 
      RegionCode, 
      SalesQualityManager, 
      SalesQualityManagerCode, 
      Franchise, 
      FranchiseCode, 
      FranchiseSizeID, 
      FranchiseSegmentID, 
      PracticePrincipal, 
      PracticePrincipalCode, 
      PracticeSupervisor, 
      PracticeSupervisorCode, 
      PracticeAdministrator, 
      PracticeAdministratorCode, 
      Adviser, 
      AgentCode, 
      TransactionDate, 
      DomainName, 
      ChangeDate, 
      IsCurrent)
    select 
      @DefaultAdviserID, 
      @DefaultCompanyName, 
      @DefaultAreaSalesManagerName, 
      @DefaultAreaSalesManagerCode, 
      @DefaultAreaSalesManagerName, 
      @DefaultAreaSalesManagerCode, 
      @DefaultAreaName, 
      @DefaultAreaCode, 
      @DefaultRegionalSalesManagerName, 
      @DefaultRegionalSalesManagerCode, 
      @DefaultAreaName, 
      @DefaultAreaCode, 
      @DefaultSalesQualityManagerName, 
      @DefaultSalesQualityManagerCode, 
      @DefaultFranchiseName, 
      @DefaultFranchiseCode, 
      @DefaultFranchiseSizeID, 
      @DefaultFranchiseSegmentID, 
      @DefaultPracticePrincipalName, 
      @DefaultPracticePrincipalCode, 
      @DefaultPracticeSupervisorName, 
      @DefaultPracticeSupervisorCode, 
      @DefaultPracticeAdministratorName, 
      @DefaultPracticeAdministratorCode, 
      @DefaultAdviserName, 
      @DefaultAgentCode, 
      null, 
      null, 
      null, 
      1
  
    set identity_insert msdt_AdviserHistory off
  
  end

END


