CREATE PROCEDURE [dbo].[mstp_AgentAgencyNumbers] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
*******************************************************************************/
-- PROCEDURE BODY GOES HERE
begin
truncate table mstt_AgentAgencyNumbers
insert into mstt_AgentAgencyNumbers
select 
  cana.ID,
  cana.AgentCode,
  cana.AgencyNumberID,
  can.AgencyNo,
  can.CompanyCode as ProductProviderCode,
  pp.ProductProviderName,
  can.Division,
  can.Prefix,
  can.LongCode,
  can.Suffix
from msit_CodeAgencyNumberAgents cana
  inner join msit_CodeAgencyNumbers can
    on cana.AgencyNumberID = can.id
  left outer join mstt_ProductProviders pp
    on can.CompanyCode = pp.ProductProviderCode
end

