CREATE PROCEDURE [dbo].[mstp_AgentCluster] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
*******************************************************************************/
-- PROCEDURE BODY GOES HERE
BEGIN
truncate table mstt_AgentCluster
insert into mstt_AgentCluster
select
  ac.ID,
  ac.AgentID,
  a.Code as AgentCode,
  ac.CodeClusterID,
  cc.Code as ClusterCode,
  cc.Description as ClusterDescription,
  cc.CodeClusterSectorID,
  ccs.Code as ClusterSectorCode,
  ccs.Description as ClusterSectorDescription,
  ccs.CodeComplianceCategoryID,
  ccc.Code as ComplianceCategoryCode,
  ccc.Description as ComplianceCategoryDescn,
  ac.StartDate,
  ac.EndDate
from
  msit_AgentCluster ac
    inner join mstt_Agents a
      on ac.AgentId = a.Id
    inner join msit_CodeCluster cc
      on ac.CodeClusterId = cc.Id
    inner join msit_CodeClusterSector ccs
      on cc.CodeClusterSectorId = ccs.Id
    inner join msit_CodeComplianceCategory ccc
      on ccs.CodeComplianceCategoryID = ccc.Id
END

