  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
*******************************************************************************/
-- PROCEDURE BODY GOES HERE
BEGIN
truncate table mstt_AgentCompetence
insert into mstt_AgentCompetence
select 
  ac.ID,
  ac.AgentID,
  a.Code as AgentCode,
  ac.CodeEntryStatusID,
  ces.Code as EntryStatusCode,
  ces.Description as EntryStatusCodeDescription,
  ac.CodeComplianceCategoryID,
  ccc.Code as ComplianceCategoryCode,
  ccc.Description as ComplianceCategoryDescn,
  ac.CodeAgentControlFunctionID,
  cacf.Code as AgentControlFunctionCode,
  cacf.Description as AgentControlFunctionDescn,
  cacf.DisplayAsCAS,
  ac.DateAppointed,
  ac.AchievedDate,
  ac.EndDate,
  ac.PercentageMon,
  ac.Notes
from
  msit_AgentCompetence ac
    inner join mstt_Agents a
      on ac.AgentId = a.Id
    inner join msit_CodeEntryStatus ces
      on ac.CodeEntryStatusID = ces.Id
    inner join msit_CodeComplianceCategory ccc
      on ac.CodeComplianceCategoryID = ccc.id
    inner join msit_CodeAgentControlFunction cacf
      on ac.CodeAgentControlFunctionID = cacf.id
END

