/****** Object:  StoredProcedure [dbo].[mstp_AgentPayments]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	mstp_AgentPayments
  				(Rewritten version of the original proc by Matt Kennedy of Moore Stephens (circa 2006/2007)
	  Author:	A Groves
Date created:	20/12/2017

  Change Ref:	SR497067/CH20028	
											
 Description:   This proc populates the mstt_AgentPayments table. The old version of the proc
				truncated the table, INSERTed into it and followed up with 3 UPDATEs. This new 
				version uses the MERGE statement to achieve a performance improvement as the old
				proc was taking 24.5 minutes.
 
				It is called as follows:

				exec mstp_AgentPayments
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------	
05/12/2007	Karen King	Add column AGT_TYPE.
05/01/2018	A Groves	Added CommissionMonth to UPDATE check and use ISNULL on it to set the
						default value to 01/01/1900 to give the same results as the old process.
************************************************************************************************/

CREATE PROCEDURE [dbo].[mstp_AgentPayments] 

as

set nocount on

SET XACT_ABORT ON	-- Needed if XACT_STATE() function is used.

declare @PhaseStart						varchar(50),
		@PhaseEnd						varchar(50),
		@PhaseLog						varchar(50),
		@PhaseError						varchar(50),
		@Process						varchar(100),
		@ProcessMessage					varchar(100),
		@Path							varchar(255),
		@DataFileName					varchar(255),
		@sql							varchar(8000),
		@RowCount						int,
		@FileID							datetime,
		@ErrNum							int,
		@ErrSev							int,
		@ErrLine						int,
		@ErrState						int,
		@ErrMsg							nvarchar(4000),
		@ErrMsgBrief					nvarchar(100), 
		@DefaultAgentPaymentType		int,
		@DefaultAgentPaymentTypeDesc	nvarchar(255),
		@Client							varchar(50),
		@Module							varchar(50)
  
/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @Client			= 'Openwork'
set @Module			= 'Swift'
set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @PhaseLog		= 'LOG'
set @PhaseError		= 'ERROR'
set @Process		= object_name(@@procid)

set @DefaultAgentPaymentType		= (select convert(int,DefaultValue) from mstt_DefaultCodeValues where CodeColumn = 'AgentPaymentType')
set @DefaultAgentPaymentTypeDesc	= (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AgentPaymentTypeDescription')    

/****************************************************************************

	Log start																
																		
****************************************************************************/

--Keep outside the transaction, otherwise it will block other stored procedures
exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
			
	/****************************************************************************

		Merge mstt_AgentPayments with sa_swift_S_AGMPAY
																			
	****************************************************************************/

	merge	dbo.mstt_AgentPayments as target
	using	(select agmpay.*, isnull(p.CommissionMonth,'') as CommissionMonth, dl.Description	--AG 05/01/2018
			 from	dbo.sa_swift_S_AGMPAY agmpay
					left join mstt_PaymentsPending p on p.ID = agmpay.AGMID 
					left join msdt_DropLists dl
								on  dl.CodeType = 'AgentPaymentType'  
								and dl.Code = convert(varchar(50),agmpay.PaymentType)) as source	
	on		target.ID = source.ID 
	when	matched 
			and	(target.AGMID <> source.AGMID
			or	 target.AMOUNT <> source.AMOUNT
			or	 target.AGENT_CODE <> source.AGENT_CODE
			or	 target.Exported <> source.Exported
			or	 isnull(target.Export_Date,'') <> isnull(source.Export_Date,'')
			or	 isnull(target.LAST_DUE,'') <> isnull(source.LAST_DUE,'')
			or	 target.PaymentType <> source.PaymentType
			or	 isnull(target.TransactionID,-1) <> isnull(source.TransactionID,-1)
			or	 isnull(target.SubjectToVAT,255) <> isnull(source.SubjectToVAT,255)
			or	 target.VATAmount <> source.VATAmount
			or	 target.NetAmount <> source.NetAmount
			or	 isnull(target.InvoiceNumber,'') <> isnull(source.InvoiceNumber,'')
			or	 isnull(target.ExportingUserID,-1) <> isnull(source.ExportingUserID,-1)			
			or	 target.PayNow <> source.PayNow
			or	 target.PaymentDate <> source.PaymentDate
			or	 isnull(target.CommissionMonth,'') <> isnull(source.CommissionMonth,'')		--AG 05/01/2018
			or	 target.AGT_TYPE <> source.AGT_TYPE)
	then	update 
				set target.AGMID = source.AGMID,
					target.AMOUNT = source.AMOUNT,
					target.AGENT_CODE = source.AGENT_CODE,
					target.Exported = source.Exported,
					target.Export_Date = source.Export_Date,
					target.LAST_DUE = source.LAST_DUE,
					target.PaymentType = source.PaymentType,
					target.PaymentTypeDesc = case when source.PaymentType = @DefaultAgentPaymentType
												then @DefaultAgentPaymentTypeDesc
												else source.Description
											 end,
					target.TransactionID = source.TransactionID,
					target.SubjectToVAT = source.SubjectToVAT,
					target.VATAmount = source.VATAmount,
					target.NetAmount = source.NetAmount,
					target.InvoiceNumber = source.InvoiceNumber,
					target.ExportingUserID = source.ExportingUserID,
					target.PayNow = source.PayNow,
					target.PaymentDate = source.PaymentDate,
					target.CommissionMonth = source.CommissionMonth,
					target.AGT_TYPE = source.AGT_TYPE
	when	not matched by target
	then	insert
			(
				ID,
				AGMID,
				AMOUNT,
				AGENT_CODE,
				Exported,
				Export_Date,
				LAST_DUE,
				PaymentType,
				PaymentTypeDesc,
				TransactionID,
				SubjectToVAT,
				VATAmount,
				NetAmount,
				InvoiceNumber,
				ExportingUserID,
				PayNow,
				PaymentDate,
				CommissionMonth,
				AGT_TYPE
			)		
			values
			(
				source.ID,
				source.AGMID,
				source.AMOUNT,
				source.AGENT_CODE,
				source.Exported,
				source.Export_Date,
				source.LAST_DUE,
				source.PaymentType,
				case when source.PaymentType = @DefaultAgentPaymentType
					then @DefaultAgentPaymentTypeDesc
					else source.Description
				end,
				source.TransactionID,
				source.SubjectToVAT,
				source.VATAmount,
				source.NetAmount,
				source.InvoiceNumber,
				source.ExportingUserID,
				source.PayNow,
				source.PaymentDate,
				source.CommissionMonth,
				source.AGT_TYPE
			)
	when	not matched by source
	then	delete;
	
	set @RowCount = @@rowcount

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION      

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	--Keep outside the transaction, otherwise it will block other stored procedures
	set @Process = @Process + '. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE(), @ErrState = XACT_STATE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10))
	
	-- Test XACT_STATE for 0, 1, or -1.
    -- If 1, the transaction is committable.
    -- If -1, the transaction is uncommittable and should be rolled back.
    -- If 0, there is no transaction and a commit or rollback operation would generate an error.

	if @ErrState = -1			-- Transaction is uncommitable
		rollback transaction

	if @ErrState = 1			
		commit transaction

	-- Error message line 1
	set @ErrMsgBrief = left(@ErrMsg,100)
	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	
	-- Error message line 2 - if any text exists
	set @ErrMsgBrief = substring(@ErrMsg,101,100)
	if len(@ErrMsgBrief) > 0
		exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @ErrSev , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
