  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>Matt Kennedy</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

*******************************************************************************/

/*

  Karen King 5 Dec 2007 - Add column AGT_TYPE

*/



-- PROCEDURE BODY GOES HERE
begin


Truncate table mstt_AgentPayments

declare 
  @DefaultAgentPaymentType        int,
  @DefaultAgentPaymentTypeDesc      nvarchar(255)

set @DefaultAgentPaymentType    = (select convert(int,DefaultValue) from mstt_DefaultCodeValues where CodeColumn = 'AgentPaymentType')
set @DefaultAgentPaymentTypeDesc  = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AgentPaymentTypeDescription')    



insert into mstt_AgentPayments

select
  [ID],
  AGMID,
  AMOUNT,
  AGENT_CODE,
  Exported,
  Export_Date,
  LAST_DUE,
  isnull(convert(int,PaymentType),@DefaultAgentPaymentType),
  Null, -- AgentPaymentTypeDescription
  TransactionID,
  SubjectToVAT,
  VATAmount,
  NetAmount,
  InvoiceNumber,
  ExportingUserID,
  PayNow,
  PaymentDate,
  '', --CommissionMonth
  AGT_TYPE
from
msit_S_AGMPAY

Update
 mstt_AgentPayments
Set
 PaymentTypeDesc = dl.Description
from 
 mstt_AgentPayments A, 
 msdt_DropLists dl
where
 dl.CodeType = 'AgentPaymentType'  and
 convert(varchar(50),A.PaymentType)  = dl.Code
 
Update
 mstt_AgentPayments
Set
 PaymentTypeDesc = @DefaultAgentPaymentTypeDesc
where
 PaymentType =  @DefaultAgentPaymentType

Update mstt_AgentPayments
Set CommissionMonth = p.CommissionMonth
from mstt_AgentPayments a 
  inner join mstt_PaymentsPending p
on a.AGMID = p.ID
 

end



GO
