create procedure [dbo].[mstp_AgentProductAggregation_ASD] as 

begin

declare @KPILevel varchar(20)
set @KPILevel = 'ASD'

declare @MaxHierarchyEndDate datetime
set @MaxHierarchyEndDate =(select max(ReportMonth) 
        from mstt_AgentQualityAggregation
        where KPILevel = 'ADVISERKPI')


select 
  @KPILevel as KPILevel,
  a.AgentType,
  a.Code as AgentCode,
  p.ProductCode,
  p.ProductProviderCode,
  count(distinct p.Pol_Num) as IssuedPolicyQty,
  cast(0.00 as float) as SubmittedPolicyQty
into #Issued
from mstt_Policies p
  inner join mstt_AgentQualityHierarchy aqh 
    on p.SalesQualityAdviserLevelCode = aqh.AgentCode 
  inner join mstt_Agents a
    on aqh.SalesQualityASDLevelCode = a.Code 
  inner join mstt_Agents a_Seller 
    on aqh.AgentCode = a_Seller.Code
  inner join mstt_Commissions c
    on p.Pol_Num = c.PolicyId
  inner join mstt_Expectation e
    on c.TransactionId = e.TransactionId
where c.TransactionDate between dateadd(yy, -1, getdate()) and getdate()
and @MaxHierarchyEndDate between aqh.AgentHierarchyStartDate and aqh.AgentHierarchyEndDate
and aqh.SalesQualityASDLevelCode is not null
and (a_Seller.AgentType in ('4','43','51') or a_Seller.AgentType in ('52','53'))
and a_Seller.DirectlyAuthorisedCode is null
group by  
  a.AgentType,
  a.Code,
  p.ProductCode,
  p.ProductProviderCode
order by a.Code, IssuedPolicyQty desc, p.ProductCode

select 
  @KPILevel as KPILevel,
  a.AgentType,
  a.Code as AgentCode,
  p.ProductCode,
  p.ProductProviderCode,
  cast(0.00 as float) as IssuedPolicyQty,
  count(distinct p.Pol_Num) as SubmittedPolicyQty
into #Submitted_Mortgage
from mstt_Policies p
  inner join mstt_AgentQualityHierarchy aqh 
    on p.SalesQualityAdviserLevelCode = aqh.AgentCode 
  inner join mstt_Agents a
    on aqh.SalesQualityASDLevelCode = a.Code 
  inner join mstt_Agents a_Seller 
    on aqh.AgentCode = a_Seller.Code    
where p.Start_Date between dateadd(yy, -1, getdate()) and getdate()
and p.SalesProcess is not null
and p.ProductGroupCode = 3
and @MaxHierarchyEndDate between aqh.AgentHierarchyStartDate and aqh.AgentHierarchyEndDate
and aqh.SalesQualityASDLevelCode is not null
and (a_Seller.AgentType in ('4','43','51') or a_Seller.AgentType in ('52','53'))
and a_Seller.DirectlyAuthorisedCode is null
group by  
  a.AgentType,
  a.Code,
  p.ProductCode,
  p.ProductProviderCode
order by a.Code, IssuedPolicyQty desc, p.ProductCode

select 
  @KPILevel as KPILevel,
  a.AgentType,
  a.Code as AgentCode,
  p.ProductCode,
  p.ProductProviderCode,
  cast(0.00 as float) as IssuedPolicyQty,
  count(distinct p.Pol_Num) as SubmittedPolicyQty
into #Submitted_NonMortgage
from mstt_Policies p
  inner join mstt_AgentQualityHierarchy aqh 
    on p.SalesQualityAdviserLevelCode = aqh.AgentCode 
  inner join mstt_Agents a
    on aqh.SalesQualityASDLevelCode = a.Code 
  inner join mstt_Agents a_Seller 
    on aqh.AgentCode = a_Seller.Code    
  inner join mstt_PolicyTransactions pt
    on p.Pol_Num = pt.PolicyId
where p.Prop_Date between dateadd(yy, -1, getdate()) and getdate()
and pt.TransType = 39
and p.ProductGroupCode <> 3
and @MaxHierarchyEndDate between aqh.AgentHierarchyStartDate and aqh.AgentHierarchyEndDate
and aqh.SalesQualityASDLevelCode is not null
and (a_Seller.AgentType in ('4','43','51') or a_Seller.AgentType in ('52','53'))
and a_Seller.DirectlyAuthorisedCode is null
group by  
  a.AgentType,
  a.Code,
  p.ProductCode,
  p.ProductProviderCode
order by a.Code, IssuedPolicyQty desc, p.ProductCode


delete from mstt_AgentProductAggregation
where KPILevel = @KPILevel

insert into mstt_AgentProductAggregation
select KPILevel,
  AgentType,
  AgentCode,
  ProductCode,
  ProductProviderCode,
  sum(IssuedPolicyQty),
  sum(SubmittedPolicyQty)
from
(select * from #Issued
union all
select * from #Submitted_Mortgage
union all
select * from #Submitted_NonMortgage) SubQuery
group by KPILevel,
  AgentType,
  AgentCode,
  ProductCode,
  ProductProviderCode

drop table #Issued
drop table #Submitted_Mortgage
drop table #Submitted_NonMortgage


end  

