set ComplaintQty = sub.Amount
from #Values v
  inner join 
  (select c.AgentCode, 
    aqh.SalesQualityPSLevelCode,
    aqh.SalesQualitySQMLevelCode,
    aqh.SalesQualityRSMLevelCode,
    aqh.SalesQualityASDLevelCode,
    c.ComplianceCategoryCode, 
    count(distinct c.CaseId) as Amount
  from mstt_Complaint c
    inner join mstt_AgentQualityHierarchy aqh
      on c.AgentCode = aqh.AgentCode
      and c.AgentInformedDate between aqh.AgentHierarchyStartDate and aqh.AgentHierarchyEndDate
  where c.AgentInformedDate between @FirstDayOfReportMonth and @LastDayOfReportMonth
  group by c.AgentCode, 
    aqh.SalesQualityPSLevelCode,
    aqh.SalesQualitySQMLevelCode,
    aqh.SalesQualityRSMLevelCode,
    aqh.SalesQualityASDLevelCode,
    c.ComplianceCategoryCode) sub
    on v.AgentCode = sub.AgentCode
