create procedure [dbo].[mstp_AgentQualityAggregation_BaseValues_Rolling6] 
      @FirstDayOfReportMonth datetime 
as 

/*  PR 13 Sept

  Changes for OriginatingSource
*/

begin

declare @LastDayOfReportMonth datetime
set @LastDayOfReportMonth  = dateAdd(mm, 1, @FirstDayOfReportMonth) - 1

declare @FirstDayOfRolling6Months datetime
set @FirstDayOfRolling6Months = dateAdd(mm, -5, @FirstDayOfReportMonth)

declare @DQ varchar(10)
declare @CQ varchar(10)
declare @SA varchar(10)

set @DQ = (select ID from msit_CodeNBCCFailureReason where Code = 'DQ')
set @CQ = (select ID from msit_CodeNBCCFailureReason where Code = 'CQ')
set @SA = (select ID from msit_CodeNBCCFailureReason where Code = 'SA')

--create temp table of ComplianceCategoryCodes
select 'MCOB' as ComplianceCategoryCode
into #Compliance
union 
select 'COB' as ComplianceCategoryCode
union 
select 'ICOB-GI' as ComplianceCategoryCode
union 
select 'ICOB-PP' as ComplianceCategoryCode


--create Temp Table to hold relevant agents
select 
  aqh.AgentCode,
  a.AgentType,
  aqh.SalesQualityASDLevelCode, 
  aqh.SalesQualityRSMLevelCode, 
  aqh.SalesQualitySQMLevelCode, 
  aqh.SalesQualityPSLevelCode,
  aqh.PracticeCode
into #Agents
from mstt_AgentQualityHierarchy aqh
  inner join mstt_Agents a
    on aqh.AgentCode = a.Code
where @FirstDayOfReportMonth between 
    --First Day of the Month of the Start Date
    DATEADD(mm, DATEDIFF(mm,0,AgentHierarchyStartDate), 0) and 
    --First Day of the Month of the End Date
    DATEADD(mm, DATEDIFF(mm,0,AgentHierarchyEndDate), 0)
    --(This should give us all the combinations for the month, 
    --in case there are multiples)
and aqh.SalesQualitySQMLevelCode is not null
union
--Get AgentHierarchy from CaseCheck for the relevant Months
select cc.AgentCode,
  a.AgentType,
  cc.SalesQualityASDLevelCode, 
  cc.SalesQualityRSMLevelCode, 
  cc.SalesQualitySQMLevelCode, 
  cc.SalesQualityPSLevelCode,
  cc.PracticeCode
from mstt_CaseCheck cc  
  inner join mstt_Agents a
    on cc.AgentCode = a.Code
where cc.CaseCheckValidatedDate between @FirstDayOfRolling6Months and @LastDayOfReportMonth
union
--Get AgentHierarchy from Non-Mortgage Policies for the relevant Months
select p.SalesQualityAdviserLevelCode as AgentCode, 
  a.AgentType,
  p.SalesQualityASDLevelCode,
  p.SalesQualityRSMLevelCode,
  p.SalesQualitySQMLevelCode,
  p.SalesQualityPSLevelCode,
  p.PracticeCode
from mstt_Policies p
  inner join mstt_Agents a
    on p.SalesQualityAdviserLevelCode = a.Code
where p.ProductGroupCode <> 3
  and p.PROP_DATE between @FirstDayOfRolling6Months and @LastDayOfReportMonth
  and p.Prop_Date >= '01 Oct 2006'
union
--Get AgentHierarchy from Mortgage Policies for the relevant Months
select p.SalesQualityAdviserLevelCode as AgentCode, 
  a.AgentType,
  p.SalesQualityASDLevelCode,
  p.SalesQualityRSMLevelCode,
  p.SalesQualitySQMLevelCode,
  p.SalesQualityPSLevelCode,
  p.PracticeCode
from mstt_Policies p
  inner join mstt_Agents a
    on p.SalesQualityAdviserLevelCode = a.Code
where p.ProductGroupCode = 3
and ((isnull(p.OriginatingSource,0) = 3 
  and p.PROP_DATE between @FirstDayOfRolling6Months and @LastDayOfReportMonth
  and p.PROP_DATE >= '01 Oct 2006')
or  (isnull(p.OriginatingSource,0) <> 3
  and p.CreateDate between @FirstDayOfRolling6Months and @LastDayOfReportMonth
  and p.CreateDate >= '01 Oct 2006'))
and p.SalesProcess is not null
    

--create temp table to hold relevant products
select distinct Code
into #RelevantProducts
from msit_CodeBIProducts
where isnull([Sales Quality Product Ind], 'N') = 'Y'


--Create Temp Table to hold values
select 
'KPI' as HierarchyTypeCode, 
'BASEVALUES' as KPILevel,
ag.AgentType, 
ag.AgentCode, 
ag.SalesQualityPSLevelCode, 
ag.SalesQualitySQMLevelCode, 
ag.SalesQualityRSMLevelCode, 
ag.SalesQualityASDLevelCode, 
cast('' as varchar(7)) as SalesQualityCorpLevelCode, 
ag.PracticeCode, 
@FirstDayOfReportMonth as ReportMonth, 
6 as SummaryPeriod, 
c.ComplianceCategoryCode, 
0 as SubmittedRiskProposalQty, 
0 as SubmittedRandomProposalQty, 
0 as SubmittedOtherProposalQty, 
0 as DisclosedReplacementQty, 
0 as UnDisclosedReplacementQty, 
0 as InitialRiskAssessedQty, 
0 as InitialRiskCompletionQty, 
0 as InitialRiskSuitableAdviceQty, 
0 as InitialRandomAssessedQty, 
0 as InitialRandomCompletionQty, 
0 as InitialRandomSuitableAdviceQty, 
0 as InitialOtherAssessedQty, 
0 as InitialOtherCompletionQty, 
0 as InitialOtherSuitableAdviceQty, 
0 as FinalRiskAssessedQty, 
0 as FinalRiskRejectQty, 
0 as FinalRandomAssessedQty, 
0 as FinalRandomRejectQty, 
0 as FinalOtherAssessedQty, 
0 as FinalOtherRejectQty, 
0 as ComplaintQty, 
cast(0 as Float) as RejectKPIPercent,
cast(0 as Float) as ReplacementKPIPercent,
cast(0 as Float) as SAKPIPercent,
cast(0 as Float) as CQKPIPercent
into 
  #Values
from 
  #Agents ag
    cross join #Compliance c

--SubmittedRiskProposalQty, Non-Mortgage
update v
set SubmittedRiskProposalQty = sub.Amount
from #Values v
  inner join 
    (select p.SalesQualityAdviserLevelCode as AgentCode, 
      p.SalesQualityPSLevelCode,
      p.SalesQualitySQMLevelCode,
      p.SalesQualityRSMLevelCode,
      p.SalesQualityASDLevelCode,
      p.Regulation as ComplianceCategoryCode, count(distinct p.Pol_Num) as Amount
    from mstt_Policies p
      inner join #RelevantProducts rp
        on p.ProductCode = rp.Code
      inner join mstt_PolicyTransactions pt
        on p.ProposalTransactionNumber = pt.Id
    where p.NBCCReferralReasonCode = 'RISK'
      and p.ProductGroupCode <> 3
      and p.PROP_DATE between @FirstDayOfRolling6Months and @LastDayOfReportMonth
      and p.Prop_Date >= '01 Oct 2006'
      and pt.AdminMethod not in ('E','X','G','O')
      and pt.TransType = 39
    group by p.SalesQualityAdviserLevelCode,
      p.SalesQualityPSLevelCode,
      p.SalesQualitySQMLevelCode,
      p.SalesQualityRSMLevelCode,
      p.SalesQualityASDLevelCode,
      p.Regulation) sub
    on v.AgentCode = sub.AgentCode
    and isnull(v.SalesQualityPSLevelCode,'X') = isnull(sub.SalesQualityPSLevelCode,'X')
    and isnull(v.SalesQualitySQMLevelCode,'X') = isnull(sub.SalesQualitySQMLevelCode,'X')
    and isnull(v.SalesQualityRSMLevelCode,'X') = isnull(sub.SalesQualityRSMLevelCode,'X')
    and isnull(v.SalesQualityASDLevelCode,'X') = isnull(sub.SalesQualityASDLevelCode,'X')
    and v.ComplianceCategoryCode = sub.ComplianceCategoryCode


--SubmittedRiskProposalQty, Mortgage
update v
set SubmittedRiskProposalQty = sub.Amount
from #Values v
  inner join 
    (select p.SalesQualityAdviserLevelCode as AgentCode, 
      p.SalesQualityPSLevelCode,
      p.SalesQualitySQMLevelCode,
      p.SalesQualityRSMLevelCode,
      p.SalesQualityASDLevelCode,
      p.Regulation as ComplianceCategoryCode, count(distinct p.Pol_Num) as Amount
    from mstt_Policies p
      inner join #RelevantProducts rp
        on p.ProductCode = rp.Code
    where p.NBCCReferralReasonCode = 'RISK' 
      and p.ProductGroupCode = 3
      and ((isnull(p.OriginatingSource,0) = 3 
        and p.PROP_DATE between @FirstDayOfRolling6Months and @LastDayOfReportMonth
        and p.PROP_DATE >= '01 Oct 2006')
      or  (isnull(p.OriginatingSource,0) <> 3
        and p.CreateDate between @FirstDayOfRolling6Months and @LastDayOfReportMonth
        and p.CreateDate >= '01 Oct 2006'))
      and p.SalesProcess is not null
    group by p.SalesQualityAdviserLevelCode,
      p.SalesQualityPSLevelCode,
      p.SalesQualitySQMLevelCode,
      p.SalesQualityRSMLevelCode,
      p.SalesQualityASDLevelCode,
      p.Regulation) sub
    on v.AgentCode = sub.AgentCode
    and isnull(v.SalesQualityPSLevelCode,'X') = isnull(sub.SalesQualityPSLevelCode,'X')
    and isnull(v.SalesQualitySQMLevelCode,'X') = isnull(sub.SalesQualitySQMLevelCode,'X')
    and isnull(v.SalesQualityRSMLevelCode,'X') = isnull(sub.SalesQualityRSMLevelCode,'X')
    and isnull(v.SalesQualityASDLevelCode,'X') = isnull(sub.SalesQualityASDLevelCode,'X')
    and v.ComplianceCategoryCode = sub.ComplianceCategoryCode

