from #Values v
  inner join 
    (select p.SalesQualityAdviserLevelCode as AgentCode, 
      p.SalesQualityPSLevelCode,
      p.SalesQualitySQMLevelCode,
      p.SalesQualityRSMLevelCode,
      p.SalesQualityASDLevelCode,
      p.Regulation as ComplianceCategoryCode, count(distinct cc.Policy_Id) as Amount
    from mstt_CaseCheck cc 
    inner join mstt_Policies p
      on cc.Policy_Id = p.Pol_Num
    inner join #RelevantProducts rp
      on p.ProductCode = rp.Code
    where cc.CaseCheckValidatedDate between @FirstDayOfRolling6Months and @LastDayOfReportMonth
      and cc.CaseCheckValidatedDate >= '01 Oct 2006'
      and cc.NBCCReferralReasonCode = 'RISK'
      and cc.NBCCInitialFailureReasonCode in (@CQ)
      and cc.CompletedState in (0,1)
      and cc.NBCCStatus is not null
      and cc.TrackGroupId = cc.RelevantTrackGroupId
    group by p.SalesQualityAdviserLevelCode,
      p.SalesQualityPSLevelCode,
      p.SalesQualitySQMLevelCode,
      p.SalesQualityRSMLevelCode,
      p.SalesQualityASDLevelCode,
      p.Regulation) sub
    on v.AgentCode = sub.AgentCode
    and isnull(v.SalesQualityPSLevelCode,'X') = isnull(sub.SalesQualityPSLevelCode,'X')
    and isnull(v.SalesQualitySQMLevelCode,'X') = isnull(sub.SalesQualitySQMLevelCode,'X')
    and isnull(v.SalesQualityRSMLevelCode,'X') = isnull(sub.SalesQualityRSMLevelCode,'X')
