create procedure [dbo].[mstp_AgentQualityAggregation_SQMSummary_SingleMonth]
      @FirstDayOfReportMonth datetime 
as 

begin

declare @LastDayOfReportMonth datetime
set @LastDayOfReportMonth  = dateAdd(mm, 1, @FirstDayOfReportMonth) - 1

declare @HierarchyTypeCode varchar(10)
declare @KPILevel varchar(20)
declare @SummaryPeriod int

set @HierarchyTypeCode = 'KPI'
set @KPILevel = 'SQMSummary'
set @SummaryPeriod = 1 

truncate table mstt_Work_AgentQualityAggregation


delete from mstt_AgentQualityAggregation
where HierarchyTypeCode = @HierarchyTypeCode
and KPILevel = @KPILevel
and SummaryPeriod = @SummaryPeriod
and ReportMonth = @FirstDayOfReportMonth

insert into mstt_Work_AgentQualityAggregation
select 
  @HierarchyTypeCode, 
  @KPILevel,
  AgentType as AgentType, 
  AgentCode as AgentCode, 
  null as SalesQualityPSLevelCode, 
  SalesQualitySQMLevelCode as SalesQualitySQMLevelCode, 
  null as SalesQualityRSMLevelCode, 
  null as SalesQualityASDLevelCode, 
  null as SalesQualityCorpLevelCode, 
  null as PracticeCode, 
  ReportMonth, 
  @SummaryPeriod, 
  ComplianceCategoryCode, 
  sum(SubmittedRiskProposalQty)   as SubmittedRiskProposalQty, 
  sum(SubmittedRandomProposalQty)   as SubmittedRandomProposalQty, 
  sum(SubmittedOtherProposalQty)    as SubmittedOtherProposalQty, 
  sum(DisclosedReplacementQty)    as DisclosedReplacementQty, 
  sum(UnDisclosedReplacementQty)    as UnDisclosedReplacementQty, 
  sum(InitialRiskAssessedQty)   as InitialRiskAssessedQty, 
  sum(InitialRiskCompletionQty)   as InitialRiskCompletionQty, 
  sum(InitialRiskSuitableAdviceQty) as InitialRiskSuitableAdviceQty, 
  sum(InitialRandomAssessedQty)   as InitialRandomAssessedQty, 
  sum(InitialRandomCompletionQty)   as InitialRandomCompletionQty, 
  sum(InitialRandomSuitableAdviceQty) as InitialRandomSuitableAdviceQty, 
  sum(InitialOtherAssessedQty)    as InitialOtherAssessedQty, 
  sum(InitialOtherCompletionQty)    as InitialOtherCompletionQty, 
  sum(InitialOtherSuitableAdviceQty)  as InitialOtherSuitableAdviceQty, 
  sum(FinalRiskAssessedQty)   as FinalRiskAssessedQty, 
  sum(FinalRiskRejectQty)     as FinalRiskRejectQty, 
  sum(FinalRandomAssessedQty)   as FinalRandomAssessedQty, 
  sum(FinalRandomRejectQty)   as FinalRandomRejectQty, 
  sum(FinalOtherAssessedQty)    as FinalOtherAssessedQty, 
  sum(FinalOtherRejectQty)    as FinalOtherRejectQty, 
  sum(ComplaintQty)     as ComplaintQty, 
  null as RejectKPIPercent, 
  null as ReplacementKPIPercent, 
  null as SAKPIPercent, 
  null as CQKPIPercent
from mstt_AgentQualityAggregation a
where ReportMonth = @FirstDayOfReportMonth
and SummaryPeriod = 1
and KPILevel = 'BASEVALUES'
and SalesQualityPSLevelCode is null
group by 
  AgentType, 
  AgentCode,
  SalesQualitySQMLevelCode,
  SalesQualityCorpLevelCode, 
  ReportMonth, 
  ComplianceCategoryCode
order by 3, ReportMonth


exec mstp_KPICalc_Adviser



insert into mstt_AgentQualityAggregation
select HierarchyTypeCode, KPILevel, AgentType, AgentCode, 
  SalesQualityPSLevelCode, SalesQualitySQMLevelCode, SalesQualityRSMLevelCode, SalesQualityASDLevelCode, 
  SalesQualityCorpLevelCode, PracticeCode, 
  ReportMonth, SummaryPeriod, ComplianceCategoryCode, 
  SubmittedRiskProposalQty, SubmittedRandomProposalQty, SubmittedOtherProposalQty, 
  DisclosedReplacementQty, UnDisclosedReplacementQty, 
  InitialRiskAssessedQty, InitialRiskCompletionQty, InitialRiskSuitableAdviceQty, 
  InitialRandomAssessedQty, InitialRandomCompletionQty, InitialRandomSuitableAdviceQty, 
  InitialOtherAssessedQty, InitialOtherCompletionQty, InitialOtherSuitableAdviceQty, 
  FinalRiskAssessedQty, FinalRiskRejectQty, FinalRandomAssessedQty, FinalRandomRejectQty, 
  FinalOtherAssessedQty, FinalOtherRejectQty, ComplaintQty, 
  RejectKPIPercent, ReplacementKPIPercent, SAKPIPercent, CQKPIPercent
from mstt_Work_AgentQualityAggregation

truncate table mstt_Work_AgentQualityAggregation

end

