/****** Object:  StoredProcedure [dbo].[mstp_AgentQualityCases]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


create procedure [dbo].[mstp_AgentQualityCases] as 

-- Amended :  BT  - 22/08/2006 - Add new column CaseCheckFinalAssessment
-- Amended :  BT  - 23/08/2006 - Modify rule for CaseCheckFinalAssessment so that only set to Pass if FinalAssessmentDate has a value
-- Amended :  BT  - 20/10/2006 - Display Suitable Advice failures as Advice instead of Suitable (CR176)
-- Amended :  BT  - 20/10/2006 - Display Suitable Advice failures as Advice instead of Suitable (CR176)
-- Amended :  PR  - 13/09/2007 - Changes for SR8 - amend code around OriginatingSource

begin

truncate table mstt_AgentQualityCases

insert into mstt_AgentQualityCases
SELECT a.[CODE] AS [SellerAgentCode]
      ,RTRIM(a.[DESCN]) AS [SellerName]
      ,c.[CLIENT_NUM] AS [ClientNum]
      --Concatenate the title, firstname and name for Personal client types
      ,RTRIM(CASE WHEN c.[CLIENT_TYP] IN (1,4) THEN 
                       CASE WHEN c.[TITLE] IS NULL THEN '' ELSE c.[TITLE] + ' ' END 
                       + CASE WHEN c.[FIRSTNAMES] IS NULL THEN '' ELSE c.[FIRSTNAMES] + ' ' END 
                       + c.[NAME]
                  ELSE c.[NAME] END) AS [ClientName]
      ,p.[CONT_NUM] AS [ContractNum]
      ,p.[PolicyRef] AS [PolicyRef]
      --Use the start date for Mortgage, otherwise use the prop date
      --Commenting out under Change Item 138
      --,CASE WHEN cc.[ComplianceCategoryCode] = 'MCOB' THEN p.[START_DATE] 
      --      ELSE p.[PROP_DATE] END AS [DateOfSale]
      --Use Prop Date for Mortgages from ETI, CreateDate for Mortgages not from ETI, Prop Date for Non Mortgages
      ,CASE WHEN cc.[ComplianceCategoryCode] = 'MCOB' and isnull(p.OriginatingSource,0) = 3 THEN p.[PROP_DATE] 
            WHEN cc.[ComplianceCategoryCode] = 'MCOB' and isnull(p.OriginatingSource,0) <> 3 THEN p.[CreateDate]
            ELSE p.[PROP_DATE] END AS [DateOfSale]
      ,p.[ProductCode]
      ,p.[Replacement]
      ,CASE WHEN p.[Replacement] = 0 THEN 'No' 
            WHEN p.[Replacement] IN (1,2,3) THEN 'Yes' 
            END AS [IsAReplacement]
      ,CASE WHEN p.[Replacement] = 0 THEN '' 
            WHEN p.[Replacement] = 1 THEN 'A' 
            WHEN p.[Replacement] = 2 THEN 'B' 
            WHEN p.[Replacement] = 3 THEN 'C' 
            END AS [ReplacementType] --TODO: Put replacement type codes in msit_MIWarehouseCodesAndDescriptions
      ,cc.[TrackGroupId]
      ,cofb.[ComplianceCategoryCode]
      ,cofb.[CategoryOfBusiness]
      ,cofb.[CategoryOfBusinessSequence]
      ,cc.[NBCCStatus] AS [CaseCheckStatus]
      ,cc.[NBCCReferralReasonCode] AS [CaseCheckReferralReasonCode]
      ,ISNULL(cc.[NBCCReferralReasonDesc],'') AS [CaseCheckReferralReasonDesc]
      ,CAST(MONTH(cc.[CaseCheckValidatedDate]) as nvarchar(50)) + '/' + CAST(YEAR(cc.[CaseCheckValidatedDate]) as nvarchar(50)) AS [CaseCheckInitialAssessmentMonthYear]
      ,cc.[CaseCheckValidatedDate] AS [CaseCheckInitialAssessmentDate]
      ,cc.[NBCCInitialFailureReasonCode] AS [CaseCheckInitialFailureReasonCode]
      ,cc.[NBCCInitialFailureReasonDesc] AS [CaseCheckInitialFailureReasonDesc]
      ,cc.[FinalCheckValidatedDate] AS [CaseCheckFinalAssessmentDate]
      ,cc.[NBCCFinalFailureReasonCode] AS [CaseCheckFinalFailureReasonCode]
      ,cc.[NBCCFinalFailureReasonDesc] AS [CaseCheckFinalFailureReasonDesc]
      --If status is 'Pass' or 'Pass with comments' or the failure reason was a documentation query then set to pass, otherwise set to failure reason
      ,CASE WHEN cc.[NBCCStatus] like 'Pass%' THEN 'Pass'
            WHEN cc.[NBCCStatus] = 'Fail' AND cc.[NBCCInitialFailureReasonCode] = 1 THEN 'Advice'
            WHEN cc.[NBCCStatus] = 'Fail' AND cc.[NBCCInitialFailureReasonCode] = 2 THEN 'Completion'
            WHEN cc.[NBCCStatus] = 'Fail' AND cc.[NBCCInitialFailureReasonCode] = 3 THEN 'Pass'
            ELSE NULL END AS [CaseCheckInitialAssessment]
      ,CASE WHEN cc.[NBCCStatus] like 'Pass%' AND [FinalCheckValidatedDate] IS NOT NULL THEN 'Pass'
            WHEN cc.[NBCCStatus] = 'Fail' AND cc.[NBCCFinalFailureReasonCode] = 1 THEN 'Advice'
            WHEN cc.[NBCCStatus] = 'Fail' AND cc.[NBCCFinalFailureReasonCode] = 2 THEN 'Completion'
            WHEN cc.[NBCCStatus] = 'Fail' AND cc.[NBCCFinalFailureReasonCode] = 3 THEN 'Pass'
            ELSE NULL END AS [CaseCheckFinalAssessment]
      ,ccq.[QuestionText]
      ,ccq.[StandardWording] AS [QuestionStandardWording]
      ,ccq.[CodeNBCCFailureReasonCode] AS [QuestionFailureReasonCode]
      ,ccq.[CodeNBCCFailureReasonDesc] AS [QuestionFailureReasonDesc]
      ,asd.[CODE] AS [ASDAgentCode]
      ,RTRIM(asd.[DESCN]) AS [ASDName]
      ,rsm.[CODE] AS [RSMAgentCode]
      ,RTRIM(rsm.[DESCN]) AS [RSMName]
      ,sqm.[CODE] AS [SQMAgentCode]
      ,RTRIM(sqm.[DESCN]) AS [SQMName]
      ,ps.[CODE] AS [PSAgentCode]
      ,RTRIM(ps.[DESCN]) AS [PSName]
FROM  [mstt_CaseCheck] cc 
      LEFT OUTER JOIN [mstt_CodeBIProducts] bip ON cc.[ProductCode] = bip.[ProductCode]
      INNER JOIN [msv_CategoryOfBusiness] cofb ON cc.[ComplianceCategoryCode] = cofb.[ComplianceCategoryCode]
      INNER JOIN [mstt_Policies] p ON cc.[Policy_Id] = p.[POL_NUM]
      INNER JOIN [mstt_Clients] c ON cc.[ClientId] = c.[CLIENT_NUM]
      INNER JOIN [mstt_Agents] a on cc.[AgentCode] = a.[CODE]
      LEFT JOIN [mstt_CaseComplianceQuestion] ccq ON cc.[TrackGroupId] = ccq.[TrackGroupId] 
           AND ccq.[Compliant] = 0 
           AND [CodeNBCCFailureReasonCode] IN ('CQ','SA')
      LEFT JOIN [mstt_Agents] asd on cc.[SalesQualityASDLevelCode] = asd.[CODE]
      LEFT JOIN [mstt_Agents] rsm on cc.[SalesQualityRSMLevelCode] = rsm.[CODE]
      LEFT JOIN [mstt_Agents] sqm on cc.[SalesQualitySQMLevelCode] = sqm.[CODE]
      LEFT JOIN [mstt_Agents] ps on cc.[SalesQualityPSLevelCode] = ps.[CODE]
WHERE
      cc.[TrackGroupId] = cc.[RelevantTrackGroupId] --Only include relevant case checks
      and isnull(bip.[SalesQualityProductInd],'N') <> 'N'


end




GO
/****** Object:  StoredProcedure [dbo].[mstp_AgentQualityHierarchy_Daily]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER OFF
GO
/***************************************************************************************************

Author: Unknown
Date: Unknown

Amendment History
=================
Author    Date    Description
A Groves  20/10/2008  Added ProcessLog entries for each SQL statement to assess time taken.

****************************************************************************************************/
CREATE procedure [dbo].[mstp_AgentQualityHierarchy_Daily] 
      @StartDate datetime 
    
      as

begin

exec msp_ProcessLog 'AQH', '01) Proc Start', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'

--Get QualityHierarchy from AgentsHierarchyHistory
--declare @StartDate datetime
declare @EndDate datetime,
    @Msg   varchar(100),
    @Debug   varchar(1)

set @debug = 'N'

--set @StartDate = '01 Jun 2006'
set @EndDate = dateAdd(mm, 1, @StartDate) - 1

if @debug = 'Y'
begin
  select @Msg = 'a) Debug: @StartDate = ' + convert(varchar(30),@StartDate,113) 
  exec msp_ProcessLog 'AQH', @Msg, null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'
  select @Msg = 'b) Debug: @EndDate = ' + convert(varchar(30),@EndDate,113) 
  exec msp_ProcessLog 'AQH', @Msg, null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'
end

declare @NumRows int
set @NumRows = (select count(*) from mstt_AgentQualityHierarchy)

--Create a 'valid' AgentsHistory to join to in later queries
select code, 
CONVERT (datetime, CONVERT (int, CONVERT (float, CONVERT (datetime, ValidFromDate)) * 10) / 10) as ValidFromDate, 
max(CONVERT (datetime, CONVERT (int, CONVERT (float, CONVERT (datetime, ValidToDate)) * 10) / 10)) as ValidToDate
into #NoDuplicateStartDates
from mstt_AgentsHistory
group by code, ValidFromDate
order by 1,2,3

exec msp_ProcessLog 'AQH', '02) Populate #NoDuplicateStartDates', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'

select ah.Code, 
CONVERT (datetime, CONVERT (int, CONVERT (float, CONVERT (datetime, ah.ValidFromDate)) * 10) / 10) as ValidFromDate, 
CONVERT (datetime, CONVERT (int, CONVERT (float, CONVERT (datetime, ah.ValidToDate)) * 10) / 10) as ValidToDate, 
ah.AgentType, ah.DirectlyAuthorisedCode, ah.CompetentStatus, ah.GivesAdvice, ah.AgentCategory
into #Table1
from mstt_AgentsHistory ah
  inner join #NoDuplicateStartDates n
    on ah.Code = n.Code
    and CONVERT (datetime, CONVERT (int, CONVERT (float, CONVERT (datetime, ah.ValidFromDate)) * 10) / 10) = n.ValidFromDate
    and CONVERT (datetime, CONVERT (int, CONVERT (float, CONVERT (datetime, ah.ValidToDate)) * 10) / 10) = n.ValidToDate
order by 1,2,3

exec msp_ProcessLog 'AQH', '03) Populate #Table1', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'

select This.Code, This.ValidFromDate, min(isnull(next.ValidFromDate, '1 Jan 9999'))-1 as ValidToDate,
This.AgentType, This.DirectlyAuthorisedCode, This.CompetentStatus, This.GivesAdvice, This.AgentCategory
into #ValidAgentsHistory
from #Table1 this
  left join #Table1 next
    on this.Code = next.Code
    and this.ValidFromDate < next.ValidFromDate
group by This.Code, This.ValidFromDate, This.AgentType, This.DirectlyAuthorisedCode, This.CompetentStatus, This.GivesAdvice, This.AgentCategory
order by 1,2,3

exec msp_ProcessLog 'AQH', '04) Populate #ValidAgentsHistory', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'

--Delete any records that have been created in our month
--get the latest rows for each agent, and set iscurrent and nullify end date
select AgentCode, max(AgentHierarchyEndDate) as EndDate
into #ClosedAgents
from mstt_AgentQualityHierarchy
group by AgentCode
having max(AgentHierarchyEndDate) <> '31 Dec 9999'

exec msp_ProcessLog 'AQH', '05) Populate #ClosedAgents', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'

delete from mstt_AgentQualityHierarchy
where AgentHierarchyStartDate >= @StartDate

exec msp_ProcessLog 'AQH', '06) Delete from mstt_AgentQualityHierarchy', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'

select AgentCode, max(AgentHierarchyStartDate) as StartDate
into #MaxRows
from mstt_AgentQualityHierarchy
where AgentCode not in (select distinct AgentCode from #ClosedAgents)
group by AgentCode

exec msp_ProcessLog 'AQH', '07) Populate #MaxRows', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'

update a
set AgentHierarchyEndDate = '31 Dec 9999',
  IsCurrent = 1
from mstt_AgentQualityHierarchy a
  inner join #MaxRows mr
    on a.AgentCode = mr.AgentCode
    and a.AgentHierarchyStartDate = mr.StartDate

exec msp_ProcessLog 'AQH', '08) Update AgentHierarchyEndDate', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'

--Now we have a clean start position, we can start building the 
--hierarchy for the current month.

--Start to build up the hierarchy using msit_AgentHierarchyHistory
select Code as AgentCode, 
  AgentType,
  coalesce(Firm, 
    OfficeCode, 
    DirectlyAuthorisedCode, 
    StrategicAllianceCode, 
    AccessAgentCode, 
    FranchiseCode) as PracticeCode,
  @StartDate as AgentHierarchyStartDate, 
  @EndDate as AgentHierarchyEndDate, 
  SaleSupervisorCode as SupervisorCode,
  AgentType as SupervisorAgentType,
  Manager4Code as SalesQualityASDLevelCode,
  Manager2Code as SalesQualityRSMLevelCode,
  SaleSupervisorCode as SalesQualitySQMLevelCode,
  SaleSupervisorCode as SalesQualityPSLevelCode,
  ' ' as IsNew,
  -2 as RelatesTo,
  1 as IsCurrent
into #Agents
from mstt_AgentsHistory
where 1=0

CREATE INDEX Agents_AgentCode ON #Agents (AgentCode)

exec msp_ProcessLog 'AQH', '09) Create #Agents', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'

select AgentCode,
  DetailAgentCode
into #PS_SQMLink
from msit_AgentHierarchyHistory
where 1=0

CREATE INDEX PS_SQMLink_AgentCode ON #PS_SQMLink (AgentCode)

exec msp_ProcessLog 'AQH', '10) Create #PS_SQMLink', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'

select AgentCode,
  DetailAgentCode
into #SQM_RSMLink
from msit_AgentHierarchyHistory
where 1=0

CREATE INDEX SQM_RSMLink_AgentCode ON #SQM_RSMLink (AgentCode)

exec msp_ProcessLog 'AQH', '11) Create #SQM_RSMLink', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'

select AgentCode,
  DetailAgentCode
into #RSM_ASDLink
from msit_AgentHierarchyHistory
where 1=0

CREATE INDEX RSM_ASDLink_AgentCode ON #RSM_ASDLink (AgentCode)

exec msp_ProcessLog 'AQH', '12) Create #RSM_ASDLink', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'

select AgentCode, 
  DefaultValue, 
  StartDate, 
  EndDate, 
  Status, 
  DetailAgentCode, 
  ParticipantType
into #AgentHierarchyHistory 
from msit_AgentHierarchyHistory
where 1=0

CREATE INDEX AgentHierarchyHistory_AgentCode ON #AgentHierarchyHistory (AgentCode)

exec msp_ProcessLog 'AQH', '13) Create #AgentHierarchyHistory', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'

select distinct Code 
into #NonSelectedAgents
from mstt_AgentsHistory
where 1=0

exec msp_ProcessLog 'AQH', '14) Create #NonSelectedAgents', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'

insert into #AgentHierarchyHistory  
select ahh4.AgentCode, 
  ahh4.DefaultValue, 
  ahh4.StartDate, 
  ahh4.EndDate, 
  ahh4.Status, 
  ahh4.DetailAgentCode, 
  ahh4.ParticipantType 
from msit_AgentHierarchyHistory ahh4
  inner join 
    (--Get the max Id if there are multiple entries for a 
    --StartDate/EndDate/ParticipantType combo
    select max(ahh2.Id) as Id, 
      ahh2.AgentCode, 
      ahh2.ParticipantType, 
      ahh2.StartDate, 
      ahh2.EndDate 
    from msit_AgentHierarchyHistory ahh2
      inner join (--Get the latest end date for each start date
          select ahh.AgentCode, 
            ahh.ParticipantType, 
            ahh.StartDate, 
            max(isnull(ahh.EndDate, '31 Dec 9999')) as EndDate
          from msit_agenthierarchyhistory ahh
          group by ahh.AgentCode, ahh.ParticipantType, ahh.StartDate ) ahh1
        on ahh2.AgentCode = ahh1.AgentCode
        and ahh2.ParticipantType = ahh1.ParticipantType
        and ahh2.StartDate = ahh1.StartDate
        and isnull(ahh2.EndDate, '31 Dec 9999') = ahh1.EndDate
    group by ahh2.AgentCode, 
      ahh2.ParticipantType, 
      ahh2.StartDate, 
      ahh2.EndDate ) ahh3
    on ahh4.id = ahh3.Id
where ahh4.ParticipantType in (7,11,12)   
and isnull(ahh4.EndDate, '31 dec 2999') >= '01 Feb 2006'
and ahh4.StartDate <> isnull(ahh4.EndDate, '31 dec 2999')
order by 1

exec msp_ProcessLog 'AQH', '15) Populate #AgentHierarchyHistory', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'


while @StartDate <= @EndDate

begin 

if @debug = 'Y'
begin
  exec msp_ProcessLog 'AQH', 'c) Debug: Insert into #Agents 1', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'
end


insert into #Agents
select distinct Seller.AgentCode as SellerCode,
  SellerAgent.AgentType as SellerType, 
  null as PracticeCode,
  case when @NumRows = 0 then '01 Jan 1900' else @StartDate end,
  '31 Dec 9999',
  Seller.DetailAgentCode as SupervisorCode,
  SupervisorAgent.AgentType as SupervisorType,
  null,
  null,
  null,
  null,
  ' ',
  -2,
  1
from #AgentHierarchyHistory Seller
  inner join #ValidAgentsHistory SellerAgent
    on Seller.AgentCode = SellerAgent.Code
  inner join #ValidAgentsHistory SupervisorAgent
    on Seller.DetailAgentCode = SupervisorAgent.Code
where (SellerAgent.AgentType in ('4','43','51') or SellerAgent.AgentType in ('52','53'))
and SellerAgent.GivesAdvice = 'Y'
and SellerAgent.DirectlyAuthorisedCode is null
and SellerAgent.CompetentStatus in (1,3) -- Active or Deceased
and Seller.ParticipantType = case when SellerAgent.AgentType in ('4','43','51') then 12 else 11 end 
and @StartDate between Seller.StartDate and isnull(Seller.EndDate, '31 Dec 9999')
and @StartDate between SellerAgent.ValidFromDate and SellerAgent.ValidToDate
and @StartDate between SupervisorAgent.ValidFromDate and SupervisorAgent.ValidToDate
order by 4,3,1


if @debug = 'Y'
begin
  exec msp_ProcessLog 'AQH', 'd) Debug: Insert into #Agents 2', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'
end

--Catch Agents who have changed agent type, ie Managers who used to be sellers, but AgentsHistory
--has not reflected that yet.


insert into #Agents
select distinct Seller.AgentCode as SellerCode,
  SellerAgent.AgentType as SellerType, 
  null as PracticeCode,
  case when @NumRows = 0 then '01 Jan 1900' else @StartDate end,
  '31 Dec 9999',
  Seller.DetailAgentCode as SupervisorCode,
  SupervisorAgent.AgentType as SupervisorType,
  null,
  null,
  null,
  null,
  ' ',
  -2,
  1
from #AgentHierarchyHistory Seller
  inner join #ValidAgentsHistory SellerAgent
    on Seller.AgentCode = SellerAgent.Code
  inner join #ValidAgentsHistory SupervisorAgent
    on Seller.DetailAgentCode = SupervisorAgent.Code
where (SellerAgent.AgentType in ('4','43','51') or SellerAgent.AgentType in ('52','53'))
and SellerAgent.GivesAdvice = 'Y'
and SellerAgent.DirectlyAuthorisedCode is null
and SellerAgent.CompetentStatus in (1,3) -- Active or Deceased
and Seller.ParticipantType = case when SellerAgent.AgentType in ('52','53') then 12 else 11 end 
and @StartDate between Seller.StartDate and isnull(Seller.EndDate, '31 Dec 9999')
and @StartDate between SellerAgent.ValidFromDate and SellerAgent.ValidToDate
and @StartDate between SupervisorAgent.ValidFromDate and SupervisorAgent.ValidToDate
--Ensure we haven't already picked this agent
and Seller.AgentCode not in (select Distinct AgentCode from #Agents)
order by 4,3,1


if @debug = 'Y'
begin
  exec msp_ProcessLog 'AQH', 'e) Debug: Update #Agents 1', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'
end

--Get the Practice for Sellers
update a
set PracticeCode = ahh.DetailAgentCode
from #Agents a
  inner join #AgentHierarchyHistory ahh
    on a.AgentCode = ahh.AgentCode
where ahh.ParticipantType = 7
and cast(@StartDate as datetime) between ahh.StartDate and isnull(ahh.EndDate, '31 Dec 9999')


if @debug = 'Y'
begin
  exec msp_ProcessLog 'AQH', 'f) Debug: Update #Agents 2', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'
end

--Agent <> Manager, and Supervisor <> Manager 
--then set SalesQualityPSLevelCode to SupervisorCode
update a
set SalesQualityPSLevelCode = SupervisorCode
from #Agents a
where a.AgentType not in ('52','53','54','55')
and a.SupervisorAgentType not in ('52','53','54','55')


if @debug = 'Y'
begin
  exec msp_ProcessLog 'AQH', 'g) Debug: Update #Agents 3', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'
end

--Agent <> Manager, and Supervisor = Manager 
--then set SalesQualitySQMLevelCode to SupervisorCode
update a
set SalesQualitySQMLevelCode = SupervisorCode
from #Agents a
where a.SupervisorAgentType in ('52','53','54','55')
and a.AgentType not in ('52','53','54','55')


if @debug = 'Y'
begin
  exec msp_ProcessLog 'AQH', 'h) Debug: Update #Agents 4', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'
end

--Agent = Manager, then set SalesQualitySQMLevelCode to SupervisorCode
update a
set SalesQualitySQMLevelCode = SupervisorCode
from #Agents a
where a.AgentType in ('52','53','54','55')


if @debug = 'Y'
begin
  exec msp_ProcessLog 'AQH', 'i) Debug: Insert into #PS_SQMLink', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'
end

--Get the SQM for any PSs as at the target date
insert into #PS_SQMLink
select distinct ps.AgentCode,
  ps.DetailAgentCode
from #AgentHierarchyHistory ps
  inner join #Agents a
    on ps.AgentCode = a.SalesQualityPSLevelCode
where @StartDate between ps.StartDate and isnull(ps.EndDate, '31 Dec 9999')
and ps.ParticipantType = 12


if @debug = 'Y'
begin
  exec msp_ProcessLog 'AQH', 'j) Debug: Update #Agents 5', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'
end


update a
set SalesQualitySQMLevelCode = ps.DetailAgentCode
from #Agents a
  inner join #PS_SQMLink ps
    on a.SalesQualityPSLevelCode = ps.AgentCode


if @debug = 'Y'
begin
  exec msp_ProcessLog 'AQH', 'k) Debug: Insert into #SQM_RSMLink', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'
end


--Get the RSM for the SQM as at the Target Date, where the SQM is not an ASQM
insert into #SQM_RSMLink
select distinct sqm.AgentCode,
  sqm.DetailAgentCode
from #AgentHierarchyHistory sqm
  inner join #Agents a
    on sqm.AgentCode = a.SalesQualitySQMLevelCode
  inner join #ValidAgentsHistory SQMAgent
    on sqm.AgentCode = SQMAgent.Code
where @StartDate between sqm.StartDate and isnull(sqm.EndDate, '31 Dec 9999')
and @StartDate between SQMAgent.ValidFromDate and SQMAgent.ValidToDate
and sqm.ParticipantType = 12
and SQMAgent.AgentCategory <> 'ASQMNS'


if @debug = 'Y'
begin
  exec msp_ProcessLog 'AQH', 'l) Debug: Update #Agents 6', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'
end


update a
set SalesQualityRSMLevelCode = sqm.DetailAgentCode
from #Agents a
  inner join #SQM_RSMLink sqm
    on a.SalesQualitySQMLevelCode = sqm.AgentCode


if @debug = 'Y'
begin
  exec msp_ProcessLog 'AQH', 'm) Debug: Insert into #RSM_ASDLink', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'
end


--Get the ASD for the RSM as at the Target Date
insert into #RSM_ASDLink
select distinct rsm.AgentCode,
  rsm.DetailAgentCode
from #AgentHierarchyHistory rsm
  inner join #Agents a
    on rsm.AgentCode = a.SalesQualityRSMLevelCode
where @StartDate between rsm.StartDate and isnull(rsm.EndDate, '31 Dec 9999')
and rsm.ParticipantType = 12



if @debug = 'Y'
begin
  exec msp_ProcessLog 'AQH', 'n) Debug: Update #Agents 7', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'
end


update a
set SalesQualityASDLevelCode = rsm.DetailAgentCode
from #Agents a
  inner join #RSM_ASDLink rsm
    on a.SalesQualityRSMLevelCode = rsm.AgentCode


--Now that we have a picture of the hierarchy as at the specified date
--we need to see if that is different to what we have stored as the 'current'
--record for the agent in mstt_AgentQualityHierarchy.
--If it is different, we update the end date of the old record,
--and remove the ActiveFlag (if required)

if @debug = 'Y'
begin
  exec msp_ProcessLog 'AQH', 'o) Debug: Update #Agents 8', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'
end


--decide whether this is a new Seller, and as such needs to be inserted.
Update a
set IsNew = 'Y'
from #Agents a
where not exists (select 'x' 
    from mstt_AgentQualityHierarchy aqh
    where a.AgentCode = aqh.AgentCode)

if @debug = 'Y'
begin
  exec msp_ProcessLog 'AQH', 'p) Debug: Insert into mstt_AgentQualityHierarchy (new)', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'
end


--Insert the new sellers
insert into mstt_AgentQualityHierarchy
(AgentCode, AgentHierarchyStartDate, AgentHierarchyEndDate, 
SalesQualityASDLevelCode, SalesQualityRSMLevelCode, 
SalesQualitySQMLevelCode, SalesQualityPSLevelCode, PracticeCode, IsCurrent)
select AgentCode, AgentHierarchyStartDate, AgentHierarchyEndDate, 
SalesQualityASDLevelCode, SalesQualityRSMLevelCode, 
SalesQualitySQMLevelCode, SalesQualityPSLevelCode, PracticeCode, IsCurrent
from #Agents
where IsNew = 'Y'


if @debug = 'Y'
begin
  exec msp_ProcessLog 'AQH', 'q) Debug: Update #Agents 9', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'
end


--decide whether this record has changed enough to generate a new record (Type 2 change)
update a
set RelatesTo = aqh.AgentHierarchyId
from #Agents a
  inner join mstt_AgentQualityHierarchy aqh
    on a.AgentCode = aqh.AgentCode
where aqh.IsCurrent = 1
and 
(
  isnull(aqh.SalesQualityASDLevelCode,'x') <> isnull(a.SalesQualityASDLevelCode,'x')
  or isnull(aqh.SalesQualityRSMLevelCode,'x') <> isnull(a.SalesQualityRSMLevelCode,'x')
  or isnull(aqh.SalesQualitySQMLevelCode,'x') <> isnull(a.SalesQualitySQMLevelCode,'x')
  or isnull(aqh.SalesQualityPSLevelCode,'x') <> isnull(a.SalesQualityPSLevelCode,'x')
  or isnull(aqh.PracticeCode,'x') <> isnull(a.PracticeCode,'x')
)


--decide whether this record represents a returning seller - in which case 
--there won't be a record with IsCurrent = 1
--Note that this may return a random (not necessarily the latest) AgentHierarchyID, 
--but as long as it doesn't return -2, that will be enough to get this #Agents row
--inserted into the Hierarchy table.

truncate table #ClosedAgents

if @debug = 'Y'
begin
  exec msp_ProcessLog 'AQH', 'r) Debug: Insert into #ClosedAgents', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'
end


insert into #ClosedAgents
select AgentCode, max(AgentHierarchyEndDate) as EndDate
from mstt_AgentQualityHierarchy
group by AgentCode
having max(AgentHierarchyEndDate) <> '31 Dec 9999'


if @debug = 'Y'
begin
  exec msp_ProcessLog 'AQH', 's) Debug: Update #Agents 10', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'
end


update a
set RelatesTo = aqh.AgentHierarchyId
from #Agents a
  inner join mstt_AgentQualityHierarchy aqh
    on a.AgentCode = aqh.AgentCode
  inner join #ClosedAgents ca
    on a.AgentCode = ca.AgentCode


if @debug = 'Y'
begin
  exec msp_ProcessLog 'AQH', 't) Debug: Insert into mstt_AgentQualityHierarchy (changes)', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'
end

--insert the 'changes'
insert into mstt_AgentQualityHierarchy
(AgentCode, AgentHierarchyStartDate, AgentHierarchyEndDate, 
SalesQualityASDLevelCode, SalesQualityRSMLevelCode, 
SalesQualitySQMLevelCode, SalesQualityPSLevelCode, PracticeCode, IsCurrent)
select AgentCode, AgentHierarchyStartDate, AgentHierarchyEndDate, 
SalesQualityASDLevelCode, SalesQualityRSMLevelCode, 
SalesQualitySQMLevelCode, SalesQualityPSLevelCode, PracticeCode, IsCurrent
from #Agents
where RelatesTo <> -2


if @debug = 'Y'
begin
  exec msp_ProcessLog 'AQH', 'u) Debug: Update mstt_AgentQualityHierarchy 1', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'
end

--remove the IsCurrent = 1 from the recently 'updated' records, 
--and set the End Date to 1 day before 'StartDate' of new record.
--We do NOT want to reset the EndDate for the 'old' record for a returning agent.
update aqh
set IsCurrent = 0,
  AgentHierarchyEndDate = @StartDate - 1
from mstt_AgentQualityHierarchy aqh
  inner join #Agents a
    on aqh.AgentHierarchyId = a.RelatesTo
where not exists (select 'x' from #ClosedAgents ca
      where a.AgentCode = ca.AgentCode)
  
    
--Now, we need to set the end date for the 'Current' record for agents who 
--have left/been cancelled/became directly autorised/became a non-seller.
--We can do this by getting ALL the agents who did NOT get selected earlier, then 
--matching them up against mstt_AgentQualityHierarchy 'Current' record and set the 
--end date on that record.

if @debug = 'Y'
begin
  exec msp_ProcessLog 'AQH', 'v) Debug: Insert into #NonSelectedAgents', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'
end

insert into #NonSelectedAgents
select distinct Code 
from #ValidAgentsHistory
where Code not in (select distinct AgentCode from #Agents)


if @debug = 'Y'
begin
  exec msp_ProcessLog 'AQH', 'w) Debug: Update mstt_AgentQualityHierarchy 2', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'
end


update aqh
set IsCurrent = 0,
  AgentHierarchyEndDate = @StartDate - 1
from mstt_AgentQualityHierarchy aqh
  inner join #NonSelectedAgents a
    on aqh.AgentCode = a.Code
where aqh.IsCurrent = 1   


if @debug = 'Y'
begin
  exec msp_ProcessLog 'AQH', 'x) Debug: Truncate Temporary Tables', null, 'mstp_AgentQualityHierarchy_Daily', 'Openwork'
end

truncate table #Agents
truncate table #PS_SQMLink
truncate table #SQM_RSMLink
truncate table #RSM_ASDLink
truncate table #NonSelectedAgents

set @NumRows = 1

exec msp_ProcessLog 'AQH', @StartDate, null, 'AQH', 'Openwork'

set @StartDate = @StartDate + 1

end


drop table #Agents
drop table #PS_SQMLink
drop table #SQM_RSMLink
drop table #RSM_ASDLink
drop table #AgentHierarchyHistory
drop table #NonSelectedAgents
drop table #Table1
drop table #NoDuplicateStartDates
drop table #ValidAgentsHistory
drop table #MaxRows
drop table #ClosedAgents

end


GO
