CREATE PROCEDURE [dbo].[mstp_Agents_Backup_17052023_SL] -- WITH RECOMPILE,ENCRYPTION
	/* Param List */
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary	: %Summary%
Author	: %Author%
Created	: %DateCreated%  
					
<doc>
	<summary>%Summary%</summary>
	<param name='%Param1Name%'>%Param1Summary%</param>
	<returns>%Returns%</returns>
	<author>%Author</author>
	<revision>
		<dateCreated></dateCreated>
		<author>/<author>
		<summary></summary>
	</revision>
</doc>

*******************************************************************************/

-- PROCEDURE BODY GOES HERE

begin

--Clear the target table first
Truncate Table mstt_Agents


--Get the data from the Import Table
insert into mstt_Agents
select
	CODE, 
	AgentType, 
	AgentTypeDescription, 
	DESCN, 
	ADDRESSEE, 
	ADDRESS1, 
	ADDRESS2, 
	ADDRESS3, 
	ADDRESS4, 
	ADDRESS5, 
	POSTCODE, 
	COUNTRY, 
	TELEPHONE, 
	FAX_NUMBER, 
	SALUTATION, 
	NOTES, 
	EMAIL, 
	Website, 
	LicenceNumber, 
	PortalLogon, 
	CurrentSamplingRate, 
	CurrentSamplingDate, 
	PreviousSamplingRate, 
	PreviousSamplingDate, 
	SamplingCounter, 
	VATAgent, 
	VATRegistered, 
	VATRegNumber, 
	SignificantInfluenceCode, 
	CustomerFunctionCode, 
	TradingName, 
	NoticePeriod, 
	AGENTID, 
	STATUS, 
	EFFDATE, 
	OfficeCode, 
	ActiveStatus, 
	AgentCategory, 
	AgentCategoryDescription, 
	GivesAdvice,
	Recruiter,
	RegionCode, 
	PracticeCode, 
	UnitCode, 
	ClawbackReservePayments, 
	ClawbackReserveRate, 
	ClawbackInterestPayments, 
	ClawbackLastBalance, 
	ClawbackLastPaymentDate, 
	DateStarted, 
	OscarDateStarted,
	OscarAgentId,      --CR 26 Oscar Agent Data: Rename column
	OscarAgentPrefix,  --CR 26 Oscar Agent Data: added column 
	OscarAgentSerial,  --CR 26 Oscar Agent Data: added column 
	OscarAgentSuffix,  --CR 26 Oscar Agent Data: added column 	
	DateLeaving, 
	FPC1Passed, 
	FPC2Passed, 
	FPC3Passed, 
	CompetentStatus, 
	CompetentStatusDescription, 
	PortfolioCode, 
	BankCode, 
	ConsultantCode, 
	BackUpConsultantCode, 
	IntroducerCode, 
	SourceCode, 
	BranchCode, 
	AreaCode, 
	DivisionCode, 
	OrganisationCode, 
	LevelOfSupervision, 
	PercentageOfBusinessChecked, 
	OverridePercentage, 
	OrphanedClientAdministrator, 
	Name, 
	Title, 
	FirstNames, 
	Initials, 
	Suffix, 
	PreferredName, 
	Corporate, 
	ClawbackReserve, 
	RecruiterCode, 
	LocationCode, 
	DirectlyAuthorisedCode, 
	EmploymentType, 
	StrategicAllianceCode, 
	AccessAgentCode, 
	CompanyCode, 
	PFACompanyCode, 
	SpecialDeal, 
	ReasonForLeaving, 
	BreachNotification, 
	BreachNotificationCode, 
	BreachNotificationEndDate, 
	AccessAgent, 
	FranchiseCode, 
	PracticeTypeCode, 
	AgentTypeGrouping, 
	AgentTypeGroupingDescription, 
	AgentTypeB30, 
	Manager1Code, 
	Manager2Code, 
	PaymentFrequency, 
	PaymentThreshold, 
	LastModifiedDate, 
	ID, 
	CanSupervise, 
	Manager3Code, 
	Manager4Code, 
	SupervisorTypeCode, 
	SaleSupervisorCode, 
	SpanSupervisorCode, 
	RecruitedByCode, 
	FranchiseSize,
	CDIStatusDate,				--CR 66
	Firm,					--CR 66
	CompetitionName,			--CR 66
	MCVDate,				--CR 66
	InterestCharged,			--CR 66
	DeclarationOfAssociation,		--CR 66
	DeclarationOfAssociationEffectiveDate,	--CR 66
	MCVIndicator,				--CR 66
	MCVStatusDate,				--CR 66
	ContactTitle,				--CR 66
	ContactForename,			--CR 66
	ContactSurname,				--CR 66
	ThirdPartyClass,			--CR 66
	PreservedUpliftRate,			--CR 66
	null as MIName,				--CR 60
	null as AgentSpecialistDesc		--Quality


from
 mstt_AgentsHistory
where
 Active = 1
 
 
update mstt_Agents
set MIName = coalesce(nullif(ltrim(rtrim(TradingName)),''), ltrim(rtrim(DESCN))) 
		+ case	when CompetentStatus in (2,3,4,6) then ' (Inactive)'
			when CompetentStatus = 5 then ' (Pre-App)'
			else '' end


--Set the AgentSpecialistDesc field
select 
	AgentCode, 
	CodeClusterSectorId as SectorCode1,
	CodeClusterSectorId as SectorCode2,
	CodeClusterSectorId as SectorCode3,
	cast(' ' as varchar(255)) as Description
into #Specialist
from mstt_AgentSector
where 1=0

declare AllAgents cursor for
select distinct AgentCode
from mstt_AgentSector
order by 1

declare @AgentCode varchar(20)

declare @SectorID1 int
declare @SectorID2 int
declare @SectorID3 int

open AllAgents
fetch next from AllAgents into @AgentCode

while @@Fetch_Status = 0

	begin

		set @SectorID1 = null
		set @SectorID2 = null
		set @SectorID3 = null

		declare @i int
		set @i = 1

		declare Sectors cursor for
		select distinct ags.CodeClusterSectorId
		from mstt_AgentSector ags
			inner join (select AgentCode, min(Priority) as Priority
						from mstt_AgentSector
						where AgentCode = @AgentCode
						group by AgentCode) as p
				on ags.AgentCode = p.AgentCode
				and ags.Priority = p.Priority
		order by 1

		declare @SectorId int

		open Sectors
		fetch next from Sectors into @SectorId

		while @@Fetch_Status = 0

			begin

				if @i = 1 set @SectorId1 = @SectorId
				if @i = 2 set @SectorId2 = @SectorId
				if @i = 3 set @SectorId3 = @SectorId

				set @i = @i + 1

				fetch next from Sectors into @SectorId

			end

		insert into #Specialist
		select @AgentCode, @SectorId1, @SectorId2, @SectorId3, null

		close Sectors
		deallocate Sectors

		fetch next from AllAgents into @AgentCode

	end

close AllAgents
deallocate AllAgents


update s
set Description = m.CodeSpecialistDescription
from #Specialist s
	inner join msit_AgentSpecialist m
		on isnull(s.SectorCode1,-99) = isnull(m.SectorCode1,-99)
		and isnull(s.SectorCode2,-99) = isnull(m.SectorCode2,-99)
		and isnull(s.SectorCode3,-99) = isnull(m.SectorCode3,-99) 

--select * from #Specialist

update a
set AgentSpecialistDesc = s.Description
from mstt_Agents a
	inner join #Specialist s
		on a.Code = s.AgentCode

drop table #Specialist			
 
end


GO
