CREATE PROCEDURE [dbo].[mstp_AgentSector] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
*******************************************************************************/
-- PROCEDURE BODY GOES HERE
BEGIN
truncate table mstt_AgentSector
insert into mstt_AgentSector
select
ags.ID,
ags.AgentID,
a.Code as AgentCode,
ags.CodeClusterSectorID,
ccs.Code as ClusterSectorCode,
ccs.Description as ClusterSectorDescription,
ccs.Priority ,
ccs.CodeComplianceCategoryID,
ccc.Code as ComplianceCategoryCode,
ccc.Description as ComplianceCategoryDescn,
ags.StartDate,
ags.EndDate,
ags.DateCreated,
ags.Notes
from 
  msit_AgentSector ags
    inner join mstt_Agents a
      on ags.AgentId = a.Id   
    inner join msit_CodeClusterSector ccs
      on ags.CodeClusterSectorId = ccs.Id
    inner join msit_CodeComplianceCategory ccc
      on ccs.CodeComplianceCategoryID = ccc.Id
END

GO
