CREATE PROCEDURE [dbo].[mstp_AgentsFact] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
AMENDMENTS
==========
03/08/2009  Mike Cawood   Use current msdt_Adviser row to avoid many-to-one relationship.         

*******************************************************************************/
/** AGENTS CUBE TO BE RELOADED DAILY **/
truncate table msft_Agents
declare 
  @DefaultSwiftAgentCode        nvarchar(255),
  @DefaultSwiftFranchiseCode      nvarchar(255)
set @DefaultSwiftAgentCode     = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AgentCode')   
set @DefaultSwiftFranchiseCode = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'FranchiseAgentCode')    
--Transitional FranchiseSeller Info
select 
 SwiftAgentCode as AgentCode,
 SwiftFranchiseCode as FranchiseAgentCode,
 -99 as AdviserId,
 Oscar_Appointed as DateAppointed,
 -99 as DateAppointedId,
 -99 as SegmentId,
 Oscar_Status as OscarStatus,
 --Mapping OscarStatus to derive Swift Status i.e CompetentStatus in S_Agents or mstt_agentshistory
 case 
  when Oscar_Status = '0' then '0'
  when Oscar_Status = '10' then '1'
  when Oscar_Status in ('20', '30') then '2'
  when Oscar_Status = '01' then '5'
  else '-99'
 end as AgentStatus,
 -99 as AgentStatusId,
 -99 as SizeId,
 -99 as SourceId,
 'Actual' as Comparison,
 -99 as ComparisonId,
 -99 as PreAppointedDateId,
 case 
  when Oscar_Status in ('20', '30') then Oscar_Status_Date 
  else Null
 end as TerminatedDate,
 -99 as TerminatedDateId,
  4 as AgentType,  --default to AgentTyype for Sellers
 -99 as AgentTypeId,
  1 as AgentCount,
  FranchiseOrSeller
into
 #FranchiseSellerTransition
from 
 mstt_TransitionCapacity_SellersFranchise
where 
 SwiftAgentCode <> @DefaultSwiftAgentCode and    --need to ask what to do with the other transitional advisers who are not in SWIFT
 FranchiseOrSeller = 'S'
/***
--Need to check Transition Adviser has record in Adviser table
--If not add one, to generate an AdviserID
***/
declare @DefaultCompanyName       varchar(50)
declare @DefaultAreaSalesManagerName      varchar(50)
declare @DefaultAreaSalesManagerCode      varchar(50)
declare @DefaultAreaName        varchar(50)
declare @DefaultAreaCode        varchar(50)
declare @DefaultRegionalSalesManagerName    varchar(50)
declare @DefaultRegionalSalesManagerCode    varchar(50)
declare @DefaultFranchiseName       varchar(50)
declare @DefaultFranchiseCode       varchar(50)
declare @DefaultFranchiseSizeID     int
declare @DefaultFranchiseSegmentID      int
declare @DefaultPracticePrincipalName     varchar(50)
declare @DefaultPracticePrincipalCode     varchar(50)
declare @DefaultPracticeSupervisorName    varchar(50)
declare @DefaultPracticeSupervisorCode    varchar(50)
declare @DefaultPracticeAdministratorName   varchar(50)
declare @DefaultPracticeAdministratorCode   varchar(50)
declare @DefaultAdviserName       varchar(50)
declare @DefaultAgentCode       varchar(50)
declare @DefaultFranchiseAgentCode    varchar(50)
declare @DefaultManager2Code      varchar(50)
declare @DefaultManager4Code      varchar(50)
declare @DefaultRegionName      varchar(50)
set @DefaultCompanyName     = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'CompanyName')
set @DefaultAreaSalesManagerName  = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AreaSalesManagerName')
set @DefaultAreaSalesManagerCode  = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AreaSalesManagerCode')
set @DefaultAreaName      = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AreaName')
set @DefaultAreaCode      = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AreaCode')
set @DefaultRegionalSalesManagerName  = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'RegionalSalesManagerName')
set @DefaultRegionalSalesManagerCode  = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'RegionalSalesManagerCode')
set @DefaultFranchiseName     = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'FranchiseName')
set @DefaultFranchiseCode     = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'FranchiseCode')
set @DefaultFranchiseSizeID     = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'FranchiseSizeID')
set @DefaultFranchiseSegmentID    = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'FranchiseSegmentID')
set @DefaultPracticePrincipalName   = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'PracticePrincipalName')
set @DefaultPracticePrincipalCode   = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'PracticePrincipalCode')
set @DefaultPracticeSupervisorName  = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'PracticeSupervisorName')
set @DefaultPracticeSupervisorCode  = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'PracticeSupervisorCode')
set @DefaultPracticeAdministratorName   = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'PracticeAdministratorName')
set @DefaultPracticeAdministratorCode   = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'PracticeAdministratorCode')
set @DefaultAdviserName     = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AdviserName')
set @DefaultAgentCode       = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AgentCode')
set @DefaultFranchiseAgentCode    = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'FranchiseAgentCode')
set @DefaultManager2Code    = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'Manager2Code')
set @DefaultManager4Code    = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'Manager4Code')
set @DefaultRegionName      = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'RegionName')
select
  distinct 
  isnull(AgentCode, @DefaultAgentCode)      as AgentCode, 
  ' ' as IsNew
into #TransitionSellersHierarchy
from 
 #FranchiseSellerTransition--#FranchiseSellerTransition
where
 FranchiseOrSeller = 'S'
select
  distinct 
  isnull(FranchiseAgentCode, @DefaultFranchiseAgentCode)    as FranchiseAgentCode, 
  ' ' as IsNew
into #TransitionFranchiseHierarchy
from 
 #FranchiseSellerTransition--#FranchiseSellerTransition
where
 FranchiseOrSeller = 'F'
--Check to see if this is a 'new' hierarchy - ie one that is NOT in msdt_Adviser.
--need to check for the complete hierarchy of Agent
update t
set IsNew = 'Y'
from #TransitionSellersHierarchy t
where not exists (select null from msdt_Adviser a
       where t.AgentCode = a.AgentCode 
      )
--need to check for the complete hierarchy of Franchise
update t
set IsNew = 'Y'
from #TransitionFranchiseHierarchy t
where not exists (select null from msdt_Adviser a
    where t.FranchiseAgentCode = a.FranchiseCode)
--select * from #TransitionSellersHierarchy
--Get the 'new' records into a temp table with the structure of the msdt_Adviser table
insert into msdt_adviser
  ([Exec], AreaSalesManager, AreaSalesManagerCode, AreaSalesQualityManager, AreaSalesQualityManagerCode, 
  AreaName, AreaCode, RegionalSalesManager, RegionalSalesManagerCode, 
  RegionName, RegionCode, SalesQualityManager, SalesQualityManagerCode, 
  Franchise, FranchiseCode, FranchiseSizeID, FranchiseSegmentID, 
  PracticePrincipal, PracticePrincipalCode, PracticeSupervisor, PracticeSupervisorCode, 
  PracticeAdministrator, PracticeAdministratorCode, Adviser, AgentCode, 
  TransactionDate, DomainName, ChangeDate, IsCurrent)
select  
  cast(@DefaultCompanyName as varchar(255))     as [Exec], 
  cast(@DefaultAreaSalesManagerName as varchar(255))  as AreaSalesManager, 
  @DefaultManager4Code          as AreaSalesManagerCode, 
  Null,
  Null,
  cast(@DefaultAreaName as varchar(255))      as AreaName, 
  cast(' ' as varchar(255))         as AreaCode, 
  cast(@DefaultRegionalSalesManagerName as varchar(255))  as RegionalSalesManager, 
  @DefaultManager2Code          as RegionalSalesManagerCode, 
  cast(@DefaultRegionName as varchar(255))    as RegionName, 
  cast(' ' as varchar(255))         as RegionCode, 
  Null,
  Null,
  cast(@DefaultFranchiseName as varchar(255))     as Franchise, 
  @DefaultFranchiseAgentCode        as FranchiseCode, 
  @DefaultFranchiseSizeID         as FranchiseSizeID, 
  @DefaultFranchiseSegmentID        as FranchiseSegmentID, 
  cast(@DefaultPracticePrincipalName as varchar(255))   as PracticePrincipal, 
  cast(@DefaultPracticePrincipalCode as varchar(255))   as PracticePrincipalCode, 
  cast(@DefaultPracticeSupervisorName as varchar(255))  as PracticeSupervisor, 
  cast(@DefaultPracticeSupervisorCode as varchar(255))  as PracticeSupervisorCode, 
  cast(@DefaultPracticeAdministratorName as varchar(255)) as PracticeAdministrator, 
  cast(@DefaultPracticeAdministratorCode as varchar(255)) as PracticeAdministratorCode, 
  cast(@DefaultAdviserName as varchar(255))     as Adviser, 
  cast(AgentCode   as varchar(10))        as AgentCode, 
  null              as TransactionDate, 
  null              as DomainName, 
  null              as ChangeDate, 
  0               as IsCurrent
from 
  #TransitionSellersHierarchy 
where
  IsNew = 'Y'
union all
select 
  cast(@DefaultCompanyName as varchar(255))     as [Exec], 
  cast(@DefaultAreaSalesManagerName as varchar(255))  as AreaSalesManager, 
  @DefaultManager4Code          as AreaSalesManagerCode, 
  Null,
  Null,
  cast(@DefaultAreaName as varchar(255))      as AreaName, 
  cast(' ' as varchar(255))         as AreaCode, 
  cast(@DefaultRegionalSalesManagerName as varchar(255))  as RegionalSalesManager, 
  @DefaultManager2Code          as RegionalSalesManagerCode, 
  cast(@DefaultRegionName as varchar(255))    as RegionName, 
  cast(' ' as varchar(255))         as RegionCode, 
  Null,
  Null,
  cast(@DefaultFranchiseName as varchar(255))     as Franchise, 
  FranchiseAgentCode          as FranchiseCode, 
  @DefaultFranchiseSizeID         as FranchiseSizeID, 
  @DefaultFranchiseSegmentID        as FranchiseSegmentID, 
  cast(@DefaultPracticePrincipalName as varchar(255))   as PracticePrincipal, 
  cast(@DefaultPracticePrincipalCode as varchar(255))   as PracticePrincipalCode, 
  cast(@DefaultPracticeSupervisorName as varchar(255))  as PracticeSupervisor, 
  cast(@DefaultPracticeSupervisorCode as varchar(255))  as PracticeSupervisorCode, 
  cast(@DefaultPracticeAdministratorName as varchar(255)) as PracticeAdministrator, 
  cast(@DefaultPracticeAdministratorCode as varchar(255)) as PracticeAdministratorCode, 
  cast(@DefaultAdviserName as varchar(255))     as Adviser, 
  @DefaultAgentCode           as AgentCode, 
  null              as TransactionDate, 
  null              as DomainName, 
  null              as ChangeDate, 
  0               as IsCurrent
from 
  #TransitionFranchiseHierarchy 
where
  IsNew = 'Y'
--select *  from #TransitionSellersHierarchy
--select * from TransitionSellersHierarchy_SLAM
--Update the Surrogate IDS
--DateAppointedId
update #FranchiseSellerTransition
set 
 DateAppointedId = C.DateId
from
 #FranchiseSellerTransition A,
 msdt_Calendartime C,
 mst_DateTimeControl D
where
 D.EntryType   = 'DateAppointed' and
 D.EntryTypeID = C.EntryTypeId   and
 C.Datetime    = A.DateAppointed
--TerminatedDateId
update #FranchiseSellerTransition
set 
 TerminatedDateId = C.DateId
from
 #FranchiseSellerTransition A,
 msdt_Calendartime C,
 mst_DateTimeControl D
where
 D.EntryType   = 'TerminatedDate' and
 D.EntryTypeID = C.EntryTypeId   and
 C.Datetime    = A.DateAppointed
--AgentStatusId
update #FranchiseSellerTransition
set 
 AgentStatusId =  A1.AgentStatusId
from
 #FranchiseSellerTransition A,
 msdt_AgentStatus A1
where
 A.AgentStatus = A1.AgentStatus
--AdviserId
update #FranchiseSellerTransition
set AdviserID = a.AdviserID
from 
 #FranchiseSellerTransition t,
 msdt_Adviser a
where
 t.FranchiseOrSeller = 'S'  and
 t.AgentCode = a.AgentCode  and     --MPC: 03/08/2009
 a.IsCurrent = 1            --MPC: 03/08/2009
update #FranchiseSellerTransition
set AdviserID = a.AdviserID
from 
 #FranchiseSellerTransition t,
 msdt_Adviser a
where
 t.FranchiseOrSeller = 'F'    and
 t.AgentCode = a.FranchiseCode  and   --MPC: 03/08/2009
 a.IsCurrent = 1            --MPC: 03/08/2009
--ComparisonId
update #FranchiseSellerTransition
set
 ComparisonId = C.ComparisonId
from 
 #FranchiseSellerTransition A,
 msdt_comparison     C
where
 A.Comparison = C.Comparison
--AgentTypeId
update #FranchiseSellerTransition
set
 AgentTypeId = T.AgenTTypeId
from
  #FranchiseSellerTransition A,
  msdt_AgentType           T
where
 A.AgentType = T.AgentType 
/***  add rows to FACT table ***/
--SELLERS
insert into msft_Agents 
  (
  AdviserId,
  AgentCode,
  DateAppointedId,
  SegmentId,
  AgentStatusId,
  SizeId,
  SourceId,
  ComparisonId,
  PreAppointedDateId,
  TerminatedDateId,
  AgentTypeId,
  ReasonForLeavingId,
  AgentCount,
  DataSource
  )
select
  AdviserId,
  AgentCode,
  DateAppointedId,
  SegmentId,
  AgentStatusId,
  SizeId,
  SourceId,
  ComparisonId,
  PreAppointedDateId,
  TerminatedDateId,
  AgentTypeId,
  -99 as ReasonForLeavingId,
  AgentCount,
  'T'
from #FranchiseSellerTransition
/*********************  FROM SWIFT ************************************************************/
select 
 Code as AgentCode,
 -99 as AdviserId,
 -99 as SegmentId,
 FranchiseSize,
 -99 as SizeId,
 -99 as SourceId,
 'Actual' as Comparison,
 -99 as ComparisonId,
 CompetentStatus,
 -99 as AgentStatusId, -- aka competentStatus
 DateStarted,
 case 
  when CompetentStatus = 1 then DateStarted else NULL
 end as DateAppointed,
 -99 as DateAppointedId,
 case 
  when CompetentStatus = 5 then DateStarted else NULL
 end as PreAppointedDate,
 -99 as PreAppointedDateId,
 DateLeaving as TerminatedDate,
 -99 as TerminatedDateId,
 AgentType,
 -99 as AgentTypeId,
 -99 as ReasonForLeavingId,
  1 as AgentCount
into 
 #AgentsStagingSwift
from 
 mstt_Agentshistory
where
 active = 1 and agentcategory in ('DIRSL', 'MEMSL', 'PARSL', 'PFA', 'PRISL','RSM','SRSM','SQM') and --FOR SELLERS ONLY!!!!
 not exists (select null from  mstt_TransitionCapacity_SellersFranchise T
    where T.SwiftAgentCode = mstt_Agentshistory.Code)
/** Update IDs **/
--Update the Surrogate IDS
--ADviserId
--SegmentId
--SizeId    ,ok
--SourceId
--ComparisonId    ,ok
--AgentStatusID   ,ok
--DateAppointedId ,ok
--PreAppointedId  ,ok
--TerminatedDateId  ,ok
--AgentTypeID   ,ok
--ADviserId
update t
set AdviserID = a.AdviserID
from #AgentsStagingSwift t
  inner join msdt_Adviser a
  on t.AgentCode = a.AgentCode
--SizeId
update #AgentsStagingSwift
set 
 SizeId = F.FranchiseSizeId
from
 #AgentsStagingSwift A,
 msdt_FranchiseSize  F
where
 A.FranchiseSize = F.FranchiseSize
--ComparisonId
update #AgentsStagingSwift
set
 ComparisonId = C.ComparisonId
from 
 #AgentsStagingSwift A,
 msdt_comparison     C
where
 A.Comparison = C.Comparison
--AgentStatusID
update #AgentsStagingSwift
set
 AgentStatusId = S.AgentStatusId
from 
 #AgentsStagingSwift A,
 msdt_AgentStatus    S
where
 A.CompetentStatus = S.AgentStatus
--DateAppointedId
update #AgentsStagingSwift
set 
 DateAppointedId = C.DateId
from
 #AgentsStagingSwift A,
 msdt_Calendartime C,
 mst_DateTimeControl D
where
 D.EntryType   = 'DateAppointed' and
 D.EntryTypeID = C.EntryTypeId   and
 C.Datetime    = A.DateAppointed
--PreAppointedId
update #AgentsStagingSwift
set 
 PreAppointedDateID = C.DateId
from
 #AgentsStagingSwift A,
 msdt_Calendartime C,
 mst_DateTimeControl D
where
 D.EntryType   = 'PreAppointedDate' and
 D.EntryTypeID = C.EntryTypeId   and
 C.Datetime    = A.PreAppointedDate
--TerminatedDateId
update #AgentsStagingSwift
set 
 TerminatedDateId = C.DateId
from
 #AgentsStagingSwift A,
 msdt_Calendartime C,
 mst_DateTimeControl D
where
 D.EntryType   = 'TerminatedDate' and
 D.EntryTypeID = C.EntryTypeId   and
 C.Datetime    = A.TerminatedDate
--AgentTypeID
update #AgentsStagingSwift
set
 AgentTypeId = T.AgentTypeId
from 
 #AgentsStagingSwift A,
 msdt_AgentType      T
where
 A.AgentType = T.AgentType
 --ReasonForLeavingId
 update #AgentsStagingSwift
set
 ReasonForLeavingId = RL.ReasonForLeavingId
from 
 #AgentsStagingSwift  A,
 mstt_Agents    AG,
 msdt_ReasonForLeaving  RL
where
 A.AgentCode = AG.Code
 and ag.ReasonForLeaving = RL.ReasonForLeavingCode
--add rows to FACT table
insert into msft_Agents 
  (
  AdviserId,
  AgentCode,
  DateAppointedId,
  SegmentId,
  AgentStatusId,
  SizeId,
  SourceId,
  ComparisonId,
  PreAppointedDateId,
  TerminatedDateId,
  AgentTypeId,
  ReasonForLeavingId,
  AgentCount,
  DataSource
  )
select
  AdviserId,
  AgentCode,
  DateAppointedId,
  SegmentId,
  AgentStatusId,
  SizeId,
  SourceId,
  ComparisonId,
  PreAppointedDateId,
  TerminatedDateId,
  AgentTypeId,
  ReasonForLeavingId,
  AgentCount,
  'S'
from #AgentsStagingSwift
drop table #FranchiseSellerTransition
drop table #TransitionSellersHierarchy
drop table #TransitionFranchiseHierarchy
drop table #AgentsStagingSwift
update msft_Agents
set ReasonForLeavingId = -99
where ReasonForLeavingId is null


GO
