CREATE PROCEDURE [dbo].[mstp_AgentsHierarchyHistory] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
*******************************************************************************/
truncate table mstt_AgentsHierarchyHistory
insert into mstt_AgentsHierarchyHistory
  (
   AgentCode,
   DefaultValue,
   StartDate,
   EndDate,
   Status,
   DetailAgentCode,
   ParticipantType
  )
select
 AgentCode,
 DefaultValue,
 StartDate,
 EndDate,
 Status,
 DetailAgentCode,
 ParticipantType
from
 msit_AgentHierarchyHistory

