/****** Object:  StoredProcedure [dbo].[mstp_AgentsHistory]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[mstp_AgentsHistory] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS
/******************************************************************************

CHANGE LOG
==========          
Amended : Oct 2007 PR changes for new Ecodes table

Amended : Jan 2008 MC - update OscarDateStarted from Transition

Amended : 31/05/2008 MPC - fix to exclude entries with missing CODE

Amended : 25/09/2008 A Groves - Replaced getdate() with ProcessDate to enable proc
                to run before midnight.

Amended : 21/10/2008 A Groves - Spurious rows being created on mstt_AgentsHistory.
                This is causing mstp_AgentQualityHierarchy_Daily to
                run very slowly.  This proc completely restructured 
                but using the same logic steps and UNION mechanism
                to identify changed records as before.
                Also, "LastModifiedDate" excluded from changed
                values check because if this is the only changed
                column, then it doesn't count as a row change.

Amended : 29/10/2008 A Groves - This cursor-based program is quite slow therefore
                a restriction has been added only to process
                rows that have changed in the last 8 days based
                on "LastModifiedDate".  8 days is used in case of 
                successive batch failures so we can be sure the
                Agent change has been swept up.  If "LastModifiedDate"
                is set, but no column differences are identified,
                then no history row is written anyway.

Amended : 13/03/2009 A Groves - Amended to ensure change of PortalLogon is reflected
                in mstt_AgentsHistory.

Amended : 26/06/2009 A Groves - Amended to return only 1 row when looking up
                owhot_OscarSwiftAgentXRef to populate Oscar codes.
                This enhancement required to reconcile MI1 to MI3.

Amended : 03/08/2009 M Cawood - Amended to ensure AgentCategory assigned from 
                msit_CodeAgentTypeCategories exists on 
                msit_CodeAgentCategories.

Amended : 18/05/2010 A Groves - Add businesses to cursor if any of its sellers
                are being updated to ensure FranchiseSize on the
                business record is correctly updated.  This is 
                needed to ensure that the business is placed in
                the correct league i.e. SOLE, SMALL or LARGE.  
                Note: The first time this revised proc runs, it
                should process all businesses irrespective of
                their LastModifiedDate as many businesses need
                correcting.

Amended : 17/06/2010 A Groves - The above FranchiseSize fix introduced a bug that
                stopped business records being updated.  This is
                now fixed. 

Amended : 26 August K Zywcyk
          The following code fixes are applied:
          1) Valid To dates will now show a datetime element set to 3ms prior to
             the end of the date shown (i.e. 23:59:59.997).
          2) Where no AgentCategory code defined on S_AGENTS row uses the MAX code
             defined on SWIFT CodeAgentTypeCategories table for the row's AGT_TYPE.
          3) Fixes error that prevented OSCARDateStarted being updated if NULL from
             TransitionSeller and TransitionFranchise source tables.          

*******************************************************************************/

set nocount on

-- AG 19/05/2009 Temp Fix to identify this business in MI Front Ends (OA, BI, HeadOffice)
--update mstt_AgentsHistory
--    set Tradingname = '003MIDB: ' + TradingName,
--      Descn = '003MIDB: ' + Descn
--where code = '1004124'
--and active = 1
--and left(Descn,8) <> '003MIDB:'

declare 
  @DefaultValidFromDate       datetime,
  @DefaultValidToDate         datetime,
  @DefaultAgentTypeDescription    nvarchar(255),
  @DefaultAgentCategoryDescription  nvarchar(255),
  @DefaultCompetentStatusDescription  nvarchar(255),
  @DefaultGivesAdvice         nvarchar(1),
  @DefaultRecruiter         nvarchar(1),
  @ProcessDate            datetime, -- AG 25/09/2008
  @AgentCode              varchar(7),
  @AgentType              int,
  @BusinessAgentType          int,
  @FranchiseSize            int,
  @RecordStatusCheck          int,
  @NewHistoryRowCount         int,
  @ProcessMessage           nvarchar(100)

declare @ValidFromDate   datetime;    --KZ: 26/08/2010
declare @PrevValidToDate datetime;    --KZ: 26/08/2010


set @DefaultValidFromDate       = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'ValidFromDate')
set @DefaultValidToDate         = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'ValidToDate')
set @DefaultAgentTypeDescription    = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AgentTypeDescription')
set @DefaultAgentCategoryDescription  = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AgentCategoryDescription')
set @DefaultCompetentStatusDescription  = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'CompetentStatusDescription')
set @DefaultGivesAdvice         = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'GivesAdvice')
set @DefaultRecruiter         = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'Recruiter')
set @ProcessDate            = (select ProcessDate from mst_ImportControl where Type = 'Openwork' and Module = 'Swift') -- AG 25/09/2008
set @NewHistoryRowCount         = 0 

set @ProcessDate     = dateadd(day, datediff(day, 0, isnull(@ProcessDate, getdate())), 0);  --KZ: 26/08/2010
set @ValidFromDate   = dateadd(day, -1, @ProcessDate);                                      --KZ: 26/08/2010
set @PrevValidToDate = dateadd(millisecond, -3, @ValidFromDate);                            --KZ: 26/08/2010

IF OBJECT_ID('tempdb..#msit_AgentsHistory') IS NOT NULL
  drop table #msit_AgentsHistory


-- Create a temporary table to receive the msit_S_Agents data
-- Collation specification required otherwise collation conflict occurs
create table #msit_AgentsHistory
(
  CODE                  varchar(7) collate database_default,
  ValidFromDate             datetime,
  ValidToDate               datetime,
  Active                  int,
  AgentType               tinyint,
  AgentTypeDescription          varchar(50) collate database_default,
  DESCN                 varchar(255) collate database_default,
  ADDRESSEE               varchar(35) collate database_default,
  ADDRESS1                varchar(35) collate database_default,
  ADDRESS2                varchar(35) collate database_default,
  ADDRESS3                varchar(35) collate database_default,
  ADDRESS4                varchar(35) collate database_default,
  ADDRESS5                varchar(35) collate database_default,
  POSTCODE                varchar(10) collate database_default,
  COUNTRY                 varchar(35) collate database_default,
  TELEPHONE               varchar(30) collate database_default,
  FAX_NUMBER                varchar(20) collate database_default,
  SALUTATION                varchar(35) collate database_default,
  NOTES                 varchar(16) collate database_default,
  EMAIL                 varchar(50) collate database_default,
  Website                 varchar(200) collate database_default,
  LicenceNumber             varchar(50) collate database_default,
  PortalLogon               varchar(20) collate database_default,
  CurrentSamplingRate           int,
  CurrentSamplingDate           datetime,
  PreviousSamplingRate          int,
  PreviousSamplingDate          datetime,
  SamplingCounter             int,
  VATAgent                int,
  VATRegistered             int,
  VATRegNumber              varchar(9) collate database_default,
  SignificantInfluenceCode        varchar(10) collate database_default,
  CustomerFunctionCode          varchar(10) collate database_default,
  TradingName               varchar(255) collate database_default,
  NoticePeriod              int,
  AGENTID                 varchar(9) collate database_default,
  STATUS                  varchar(10) collate database_default,
  EFFDATE                 datetime,
  OfficeCode                varchar(7) collate database_default,
  ActiveStatus              tinyint,
  AgentCategory             varchar(8) collate database_default,
  AgentCategoryDescription        varchar(50) collate database_default,
  GivesAdvice               varchar(1) collate database_default,
  Recruiter               varchar(1) collate database_default,
  RegionCode                varchar(7) collate database_default,
  PracticeCode              varchar(7) collate database_default,
  UnitCode                varchar(7) collate database_default,
  ClawbackReservePayments         int,
  ClawbackReserveRate           float,
  ClawbackInterestPayments        int,
  ClawbackLastBalance           float,
  ClawbackLastPaymentDate         datetime,
  DateStarted               datetime,
  OscarDateStarted            datetime,
  OscarAgentId              varchar(255) collate database_default,
  OscarAgentPrefix            varchar(255) collate database_default,
  OscarAgentSerial            varchar(255) collate database_default,
  OscarAgentSuffix            varchar(255) collate database_default,
  DateLeaving               datetime,
  FPC1Passed                datetime,
  FPC2Passed                datetime,
  FPC3Passed                datetime,
  CompetentStatus             tinyint,
  CompetentStatusDescription        varchar(20) collate database_default,
  PortfolioCode             varchar(7) collate database_default,
  BankCode                varchar(7) collate database_default,
  ConsultantCode              varchar(7) collate database_default,
  BackUpConsultantCode          varchar(7) collate database_default,
  IntroducerCode              varchar(7) collate database_default,
  SourceCode                varchar(7) collate database_default,
  BranchCode                varchar(7) collate database_default,
  AreaCode                varchar(7) collate database_default,
  DivisionCode              varchar(7) collate database_default,
  OrganisationCode            varchar(7) collate database_default,
  LevelOfSupervision            int,
  PercentageOfBusinessChecked       int,
  OverridePercentage            int,
  OrphanedClientAdministrator       tinyint,
  Name                  varchar(60) collate database_default,
  Title                 varchar(35) collate database_default,
  FirstNames                varchar(60) collate database_default,
  Initials                varchar(35) collate database_default,
  Suffix                  varchar(60) collate database_default,
  PreferredName             varchar(60) collate database_default,
  Corporate               tinyint,
  ClawbackReserve             float,
  RecruiterCode             varchar(10) collate database_default,
  LocationCode              varchar(10) collate database_default,
  DirectlyAuthorisedCode          varchar(7) collate database_default,
  EmploymentType              tinyint,
  StrategicAllianceCode         varchar(7) collate database_default,
  AccessAgentCode             varchar(7) collate database_default,
  CompanyCode               varchar(10) collate database_default,
  PFACompanyCode              varchar(7) collate database_default,
  SpecialDeal               int,
  ReasonForLeaving            varchar(8) collate database_default,
  BreachNotification            tinyint,
  BreachNotificationCode          varchar(8) collate database_default,
  BreachNotificationEndDate       datetime,
  AccessAgent               varchar(7) collate database_default,
  FranchiseCode             varchar(7) collate database_default,
  PracticeTypeCode            varchar(8) collate database_default,
  AgentTypeGrouping           int,
  AgentTypeGroupingDescription      varchar(50) collate database_default,
  AgentTypeB30              int,
  Manager1Code              varchar(7) collate database_default,
  Manager2Code              varchar(7) collate database_default,
  PaymentFrequency            int,
  PaymentThreshold            float,
  LastModifiedDate            datetime,
  ID                    int,
  CanSupervise              tinyint,
  Manager3Code              varchar(7) collate database_default,
  Manager4Code              varchar(7) collate database_default,
  SupervisorTypeCode            varchar(10) collate database_default,
  SaleSupervisorCode            varchar(7) collate database_default,
  SpanSupervisorCode            varchar(7) collate database_default,
  RecruitedByCode             varchar(7) collate database_default,
  FranchiseSize             int,
  CDIStatusDate             datetime,
  Firm                  varchar(7) collate database_default,
  CompetitionName             varchar(60) collate database_default,
  MCVDate                 datetime,
  InterestCharged             int,
  DeclarationOfAssociation        int,
  DeclarationOfAssociationEffectiveDate datetime,
  MCVIndicator              int,
  MCVStatusDate             datetime,
  ContactTitle              varchar(35) collate database_default,
  ContactForename             varchar(60) collate database_default,
  ContactSurname              varchar(60) collate database_default,
  ThirdPartyClass             int,
  PreservedUpliftRate           float
)


-- We are going to process one agent record at a time with lots of steps hence the cursor.
-- BusinessAgentTypes need to be processed last because, for them, we need to calculate
-- FranchiseSize and for that, all the non-business records need to be created first so
-- they can be counted.

-- AG 13/03/2009 Start

declare AgentCheck cursor 
fast_forward
for select  Code as AgentCode, 
      case Agt_type
        when 2 then 2
        when 46 then 2
        when 47 then 2
        when 49 then 2
        else 1
      end as BusinessAgentType, -- Process all agent types i.e. businesses and people. AG 17/06/2010.
      Agt_type as AgentType
  from  msit_S_Agents Ag
  where len(Code) > 0     --MPC: 31/05/2008
  and   (LastModifiedDate >= (@ProcessDate - 8) -- Changed in the last eight days or....
  or    Code in (select   AH.Code       -- Their PortalLogin has changed at any time
            from  mstt_AgentsHistory AH
                inner join msit_IntUsers IU on IU.AssociatedAgent = AH.Code
            where isnull(AH.PortalLogon,'') <> isnull(IU.Name,'')
            and   IU.ID < 99000 -- Above 99000 are the mitest logons
            and   AH.Active = 1))
  union -- Include all businesses for modified sellers to ensure Franchise Size is updated for the leagues AG 18/05/2010.
  select  Ag.Code as AgentCode,
      2 as BusinessAgentType,
      Ag.Agt_type as AgentType
  from  msit_S_Agents Ag
  where Ag.Agt_Type in (2,46,47,49)
  and   Ag.code in (select  sellers.firm 
             from msit_S_Agents sellers
             where  sellers.Agt_Type not in (2,46,47,49) 
             and  sellers.LastModifiedDate >= (@ProcessDate - 8))
  order by 2, 1 
  for   read only

-- AG 13/03/2009 End

open AgentCheck


fetch AgentCheck
into  @AgentCode, @BusinessAgentType, @AgentType


while (@@fetch_status = 0)
begin


  -- Obtain the msit_S_Agents data which will be compared against mstt_AgentsHistory for any differences
    insert  #msit_AgentsHistory
  (
    CODE, 
        ValidFromDate, 
    ValidToDate, 
    Active, 
    AgentType, 
    AgentTypeDescription, 
    DESCN, 
    ADDRESSEE, 
    ADDRESS1, 
    ADDRESS2, 
    ADDRESS3, 
    ADDRESS4, 
    ADDRESS5, 
    POSTCODE, 
    COUNTRY, 
    TELEPHONE, 
    FAX_NUMBER, 
    SALUTATION, 
    NOTES, 
    EMAIL, 
    Website, 
    LicenceNumber, 
    PortalLogon, 
    CurrentSamplingRate, 
    CurrentSamplingDate, 
    PreviousSamplingRate, 
    PreviousSamplingDate, 
    SamplingCounter, 
    VATAgent, 
    VATRegistered, 
    VATRegNumber, 
    SignificantInfluenceCode, 
    CustomerFunctionCode, 
    TradingName, 
    NoticePeriod, 
    AGENTID, 
    STATUS, 
    EFFDATE, 
    OfficeCode, 
    ActiveStatus, 
    AgentCategory, 
    AgentCategoryDescription, 
    GivesAdvice, 
    Recruiter, 
    RegionCode, 
    PracticeCode, 
    UnitCode, 
    ClawbackReservePayments, 
    ClawbackReserveRate, 
    ClawbackInterestPayments, 
    ClawbackLastBalance, 
    ClawbackLastPaymentDate, 
    DateStarted, 
    OscarDateStarted, 
    OscarAgentId, 
    OscarAgentPrefix, 
    OscarAgentSerial, 
    OscarAgentSuffix, 
    DateLeaving, 
    FPC1Passed, 
    FPC2Passed, 
    FPC3Passed, 
    CompetentStatus, 
    CompetentStatusDescription, 
    PortfolioCode, 
    BankCode, 
    ConsultantCode, 
    BackUpConsultantCode, 
    IntroducerCode, 
    SourceCode, 
    BranchCode, 
    AreaCode, 
    DivisionCode, 
    OrganisationCode, 
    LevelOfSupervision, 
    PercentageOfBusinessChecked, 
    OverridePercentage, 
    OrphanedClientAdministrator, 
    Name, 
    Title, 
    FirstNames, 
    Initials, 
    Suffix, 
    PreferredName, 
    Corporate, 
    ClawbackReserve, 
    RecruiterCode, 
    LocationCode, 
    DirectlyAuthorisedCode, 
    EmploymentType, 
    StrategicAllianceCode, 
    AccessAgentCode, 
    CompanyCode, 
    PFACompanyCode, 
    SpecialDeal, 
    ReasonForLeaving, 
    BreachNotification, 
    BreachNotificationCode, 
    BreachNotificationEndDate, 
    AccessAgent, 
    FranchiseCode, 
    PracticeTypeCode, 
    AgentTypeGrouping, 
    AgentTypeGroupingDescription, 
    AgentTypeB30, 
    Manager1Code, 
    Manager2Code, 
    PaymentFrequency, 
    PaymentThreshold, 
    LastModifiedDate, 
    ID, 
    CanSupervise, 
    Manager3Code, 
    Manager4Code, 
    SupervisorTypeCode, 
    SaleSupervisorCode, 
    SpanSupervisorCode, 
    RecruitedByCode, 
    FranchiseSize, -- next is the ID Column, which we skip
    CDIStatusDate, 
    Firm, 
    CompetitionName, 
    MCVDate, 
    InterestCharged, 
    DeclarationOfAssociation, 
    DeclarationOfAssociationEffectiveDate, 
    MCVIndicator, 
    MCVStatusDate, 
    ContactTitle, 
    ContactForename, 
    ContactSurname, 
    ThirdPartyClass, 
    PreservedUpliftRate --132
  )
    select
     CODE,
     LastModifiedDate,    --ValidFromDate
     @DefaultValidToDate, --ValidToDate
     1,           --Active --Set to true when new record, and set previous one to be false
     Agt_type,        --AgentType
     null,          --AgentTypeDescription (column not on msit_S_Agents)
     DESCN,
     ADDRESSEE, 
     ADDRESS1, 
     ADDRESS2, 
     ADDRESS3, 
     Town, 
     County, 
     POSTCODE, 
     COUNTRY, 
     TELEPHONE, 
     FAX_NUMBER, 
     SALUTATION, 
     NOTES, 
     EMAIL, 
     Website, 
     LicenceNumber, 
     null,          --PortalLogon (column not on msit_S_Agents)
     CurrentSamplingRate, 
     CurrentSamplingDate, 
     PreviousSamplingRate, 
     PreviousSamplingDate, 
     SamplingCounter, 
     VATAgent, 
     VATRegistered, 
     VATRegNumber, 
     SignificantInfluenceCode, 
     CustomerFunctionCode, 
     TradingName, 
     NoticePeriod, 
     AGENTID,
     STATUS,
     EFFDATE,
     OfficeCode,
     ActiveStatus,
     AgentCategory,
     null,          --AgentCategoryDescription  (column not on msit_S_Agents)
     @DefaultGivesAdvice, --GivesAdvice
     @DefaultRecruiter,   --Recruiter
     RegionCode,
     PracticeCode,
     UnitCode,
     ClawbackReservePayments,
     ClawbackReserveRate,
     ClawbackInterestPayments,
     ClawbackLastBalance,
     ClawbackLastPaymentDate,
     DateStarted,
     null,          --OscarDateStarted                      (column not on msit_S_Agents)
     null,          --OscarAgentId      --CR 26 Oscar Agent Data: Rename column (column not on msit_S_Agents)
     null,          --OscarAgentPrefix  --CR 26 Oscar Agent Data: added column  (column not on msit_S_Agents)
     null,          --OscarAgentSerial  --CR 26 Oscar Agent Data: added column  (column not on msit_S_Agents)
     null,          --OscarAgentSuffix  --CR 26 Oscar Agent Data: added column  (column not on msit_S_Agents)
     DateLeaving,
     FPC1Passed,
     FPC2Passed,
     FPC3Passed,
     CompetentStatus,
     null,          --CompetentStatusDescription  (column not on msit_S_Agents)
     PortfolioCode,
     BankCode,
     ConsultantCode,
     BackUpConsultantCode,
     IntroducerCode,
     SourceCode,
     BranchCode,
     AreaCode,
     DivisionCode,
     OrganisationCode,
     LevelOfSupervision,
     PercentageOfBusinessChecked,
     OverridePercentage,
     OrphanedClientAdministrator,
     Name,
     Title,
     FirstNames,
     Initials,
     Suffix,
     PreferredName,
     Corporate,
     ClawbackReserve,
     RecruiterCode,
     LocationCode,
     DirectlyAuthorisedCode,
     EmploymentType,
     StrategicAllianceCode,
     AccessAgentCode,
     CompanyCode,
     PFACompanyCode,
     SpecialDeal,
     ReasonForLeaving,
     BreachNotification,
     BreachNotificationCode,
     BreachNotificationEndDate,
     AccessAgent,
     OfficeCode,        --FranchiseCode,
     PracticeTypeCode,
     AgentTypeB30, 
     null,            --AgentTypeGroupingDescription (column not on msit_S_Agents)
     AgentTypeB30,
     Manager1Code,
     Manager2Code,
     PaymentFrequency,
     PaymentThreshold,
     LastModifiedDate,
     ID,
     CanSupervise,
     Manager3Code,
     Manager4Code,
     SupervisorTypeCode,
     SaleSupervisorCode,
     SpanSupervisorCode,
     RecruitedByCode,
     null,            --FranchiseSize (column not on msit_S_Agents)
     CDIStatusDate,               --CR 66
     Firm,                    --CR 66
     CompetitionName,           --CR 66
     MCVDate,                   --CR 66
     InterestCharged,           --CR 66
     DeclarationOfAssociation,        --CR 66
     DeclarationOfAssociationEffectiveDate, --CR 66
     MCVIndicator,                --CR 66
     MCVStatusDate,               --CR 66
     ContactTitle,                --CR 66
     ContactForename,           --CR 66
     ContactSurname,              --CR 66
     ThirdPartyClass,           --CR 66
     PreservedUpliftRate          --CR 66
    from
     msit_S_Agents 
    where
     Code = @AgentCode


  -- AG 19/05/2009 Temp Fix to identify this business in MI Front Ends (OA, BI, HeadOffice)
  --if @AgentCode = '1004124'
  --begin
  --  update #msit_AgentsHistory
  --    set Tradingname = '003MIDB: ' + TradingName,
  --      Descn = '003MIDB: ' + Descn
  --  where code = '1004124'
  --  and left(Descn,8) <> '003MIDB:'
  --end

  --Update PortalLogon
  update  #msit_AgentsHistory
      set PortalLogon = i.[Name]
  from  #msit_AgentsHistory A,
      msit_IntUsers i
  where A.Code = i.AssociatedAgent
  and   i.ID in (select max(ID)     -- AG 13/03/2009 
           from msit_IntUsers 
           where  AssociatedAgent = @AgentCode
           and  ID < 99000)   -- Above 99000 are the mitest logons

  --AgentCategory.  Will determine 'GivesAdvice' and 'Recruiter'.
  /*  CODE REMOVED-START     --KZ: 26/08/2010 
  update  #msit_AgentsHistory
      set AgentCategory = C.AgentCategoryCode
    from  #msit_AgentsHistory A         --MPC: 03/08/2009
  inner join  msit_CodeAgentTypeCategories C    --MPC: 03/08/2009
    on A.AgentType = C.AgentType        --MPC: 03/08/2009
  inner join  msit_CodeAgentCategories B      --MPC: 03/08/2009
    on B.Code = C.AgentCategoryCode       --MPC: 03/08/2009
    where A.AgentCategory is null
    --and   A.AgentType = C.AgentType     --MPC: 03/08/2009
      CODE REMOVED - END    --KZ: 26/08/2010      */

  -->Replaced by START:   --KZ: 26/08/2010
  update t
  set AgentCategory = x.AgentCategory
  from #msit_AgentsHistory t
       inner join (select CODE          = a.CODE,
                          AgentCategory = max(c.AgentCategoryCode)
                   from #msit_AgentsHistory a
                        inner join  dbo.msit_CodeAgentTypeCategories c on a.AgentType = c.AgentType
                        inner join  dbo.msit_CodeAgentCategories b on b.Code = c.AgentCategoryCode
                   where a.AgentCategory is null
                   group by a.CODE) as x on t.CODE = x.CODE
  where t.AgentCategory is null;
  --<Replaced By END      --KZ: 26/08/2010
    
    --GivesAdvice, Recruiter
    update  #msit_AgentsHistory
      set GivesAdvice = case  when cac.GivesAdvice = 1 then 'Y' else 'N' end,
        Recruiter   = case  when cac.Recruiter   = 1 then 'Y' else 'N' end
    from  #msit_AgentsHistory      A, 
      msit_CodeAgentCategories  cac
    where A.AgentCategory = cac.Code

    
    --AgentTypeDescription
    update  #msit_AgentsHistory
      set AgentTypeDescription = dl.Description
    from  #msit_AgentsHistory A, 
      msdt_DropLists dl
    where dl.CodeType = 'AgentType'
    and   convert(varchar(50),A.AgentType) = dl.Code


  --No AgentTypeDescription so use default value
    update  #msit_AgentsHistory 
      set AgentTypeDescription = @DefaultAgentTypeDescription 
    where isnull(AgentTypeDescription,'') = ''


    --AgentTypeGroupingDescription
    update  #msit_AgentsHistory
    set AgentTypeGroupingDescription = dl.Description
    from  #msit_AgentsHistory A, 
      msdt_DropLists dl
    where dl.CodeType = 'AgentGrouping'  
  and   convert(varchar(50),A.AgentTypeGrouping) = dl.Code


    --AgentCategoryDescription
    update  #msit_AgentsHistory
    set AgentCategoryDescription = cac.Description
    from  #msit_AgentsHistory A,
      msit_CodeAgentCategories cac
    where A.AgentCategory = cac.Code


  --No AgentCategoryDescription so use default value
    update #msit_AgentsHistory 
    set AgentCategoryDescription = @DefaultAgentCategoryDescription 
    where isnull(AgentCategoryDescription,'') = ''


    --CompetentStatusDescription
    update  #msit_AgentsHistory
    set CompetentStatusDescription = dl.Description
    from  #msit_AgentsHistory A, 
      msdt_DropLists dl
    where dl.CodeType = 'CompetentStatus'         -- AG 21/10/2008
    and   convert(varchar(50),A.CompetentStatus) = dl.Code
  

    --No CompetentStatusDescription so use default value
    update #msit_AgentsHistory 
    set CompetentStatusDescription = @DefaultCompetentStatusDescription 
    where isnull(CompetentStatusDescription,'') = ''


  --Calculate FranchiseSize
  if @BusinessAgentType = 2 
    exec owp_GetFranchiseSize @AgentCode, @AgentType, @FranchiseSize output
  else
    select @FranchiseSize = null


  --Update FranchiseSize
    update  #msit_AgentsHistory 
      set FranchiseSize = @FranchiseSize 
    

    --CR 26 Oscar Agent Data:
    --OscarAgentId, OscarDateStarted, OscarAgentPrefix, OscarAgentSerial, OscarAgentSuffix
    -- PR Oct 2007 use new Oscar Ecode table
  --   update 
  --    #msit_AgentsHistory
  --   set 
  --    OscarAgentId     = O.OscarAgentId,
  --    OscarDateStarted = convert(datetime,O.OscarDateStarted),
  --    OscarAgentPrefix = O.OscarAgentPrefix,
  --    OscarAgentSerial = O.OscarAgentSerial,
  --    OscarAgentSuffix = O.OscarAgentSuffix
  --   from 
  --    msit_OscarSwiftAgents O,
  --    #msit_AgentsHistory A
  --   where
  --    O.SwiftAgentId = A.Code


  update #msit_AgentsHistory
      set OscarDateStarted = x.StartDate,
        OscarAgentID   = x.OSCAR_ID,
          OscarAgentPrefix = x.OSCAR_Prefix,
          OscarAgentSerial = x.OSCAR_Serial,
          OscarAgentSuffix = x.OSCAR_Suffix
  from  #msit_AgentsHistory ah
      inner join Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref x on ah.Code = x.AgentCode
  where x.NoEcode is Null 
  and   x.AgentLevel = 'B' 
  and   x.id = (select min(xref.id) from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref xref -- min(id) matches MIDB001
          where xref.AgentLevel = 'B'
          and xref.AgentCode = ah.code 
          and ah.ValidFromDate between xref.StartDate and isnull(xref.EndDate,@DefaultValidToDate)) -- AG 26/06/2009
  and   ah.ValidFromDate between x.StartDate and isnull(x.EndDate,@DefaultValidToDate)            -- AG 26/06/2009
  and   ah.AgentType in (2, 46, 47, 49) 
  and   ah.CompetentStatus in (1,2) 
  and   ah.Active = 1
  


  update #msit_AgentsHistory
      set OscarDateStarted = x.StartDate,
        OscarAgentID   = x.OSCAR_ID,
        OscarAgentPrefix = x.OSCAR_Prefix,
        OscarAgentSerial = x.OSCAR_Serial,
        OscarAgentSuffix = x.OSCAR_Suffix
  from  #msit_AgentsHistory ah
      inner join Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref x on ah.Code = x.AgentCode
  where x.NoEcode is Null 
  and   x.AgentLevel= 'M' 
  and   x.id = (select min(xref.id) from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref xref -- min(id) matches MIDB001
          where xref.AgentLevel= 'M' 
          and xref.AgentCode = ah.code 
          and ah.ValidFromDate between xref.StartDate and isnull(xref.EndDate,@DefaultValidToDate)) -- AG 26/06/2009
  and   ah.ValidFromDate between x.StartDate and isnull(x.EndDate,@DefaultValidToDate)            -- AG 26/06/2009
  and   ah.AgentType in (52, 53, 54, 55 ) 
  and   ah.CompetentStatus in (1,2,3) 
  and   ah.GivesAdvice = 'Y' 


  update #msit_AgentsHistory 
        set OscarDateStarted = x.StartDate,
        OscarAgentID     = x.OSCAR_ID,
        OscarAgentPrefix = x.OSCAR_Prefix,
        OscarAgentSerial = x.OSCAR_Serial,
        OscarAgentSuffix = x.OSCAR_Suffix
  from  #msit_AgentsHistory ah
      inner join Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref x on ah.Code = x.AgentCode
  where x.NoEcode is Null 
  and   x.AgentLevel= 'S' 
  and   x.id = (select min(xref.id) from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref xref -- min(id) matches MIDB001
          where xref.AgentLevel= 'S' 
          and xref.AgentCode = ah.code 
          and ah.ValidFromDate between xref.StartDate and isnull(xref.EndDate,@DefaultValidToDate)) -- AG 26/06/2009
  and   ah.ValidFromDate between x.StartDate and isnull(x.EndDate,@DefaultValidToDate)            -- AG 26/06/2009
  and   ah.AgentType in ( 3, 4, 5, 43, 45, 51  ) 
  and   ah.CompetentStatus in (1,2,3) 
  and   ah.GivesAdvice = 'Y' 
  and   ah.Active = 1

    -- PR Oct 2007 END new Oscar Ecode table


  ---------------- MC: Jan 2008 Start -------------------------------------------------------------
  -----------------AG: Restructured 23/10/208------------------------------------------------------


  -- Now update OscarDateStarted from Transition Seller data
  update  #msit_AgentsHistory 
        set OscarDateStarted = derived_table.AppointedDate
  from  #msit_AgentsHistory ah
  inner join 
  (
    select  Code as AgentCode,
        min(tc.Appointed) as AppointedDate
    from  #msit_AgentsHistory ag
        inner join head_office_systems.dbo.owhot_OscarSwiftAgentXRef os on os.agentcode = ag.code
        inner join mstt_TransitionCapacity_SellersHistory tc on tc.Agent_Id = os.Oscar_Id
    group by Code
  )
  as derived_table on ah.Code = derived_table.AgentCode 
  ----KZ: 26/08/2010> where derived_table.AppointedDate < ah.OscarDateStarted <--
  ----KZ: 26/08/2010> Replaced by:
  where derived_table.AppointedDate < coalesce(ah.OscarDateStarted, '20790606') --'20790606' is max for smalldatetime


  --Now apply Appointed Date from Transition Franchise if earlier
  update  #msit_AgentsHistory 
        set OscarDateStarted = derived_table.AppointedDate
  from  #msit_AgentsHistory ah
  inner join 
  (
    select  Code as AgentCode,
        min(tc.Oscar_Appointed) as AppointedDate
    from  #msit_AgentsHistory ag
        inner join head_office_systems.dbo.owhot_OscarSwiftAgentXRef os on os.agentcode = ag.code
        inner join mstt_TransitionCapacity_SellersFranchise tc on tc.OscarCode = os.Oscar_ID
    group by Code
  )
  as derived_table on ah.Code = derived_table.AgentCode 
  ----KZ: 26/08/2010> where derived_table.AppointedDate < ah.OscarDateStarted 
  ----KZ: 26/08/2010> Replaced by:
  where derived_table.AppointedDate < coalesce(ah.OscarDateStarted, '20790606')


  -----------------AG: Restructured 23/10/208------------------------------------------------------
  ---------------- MC: Jan 2008 End --------------------------------------------------------------

    -- Active is set to "1" on both records, so this column will - correctly - never cause a changed row to be identified.

    set @RecordStatusCheck = null

    set @RecordStatusCheck = 
     (select count(*) from 
      (select
        CODE, Active, AgentType, AgentTypeDescription, DESCN, ADDRESSEE, ADDRESS1, ADDRESS2,
        ADDRESS3, ADDRESS4, ADDRESS5, POSTCODE, COUNTRY, TELEPHONE, FAX_NUMBER, SALUTATION, NOTES, EMAIL, Website, 
    LicenceNumber, PortalLogon, CurrentSamplingRate,  CurrentSamplingDate, PreviousSamplingRate, PreviousSamplingDate,
        SamplingCounter, VATAgent, VATRegistered, VATRegNumber, SignificantInfluenceCode, CustomerFunctionCode,
        TradingName, NoticePeriod, AGENTID, STATUS, EFFDATE, OfficeCode, ActiveStatus, AgentCategory, AgentCategoryDescription, 
    GivesAdvice, Recruiter, RegionCode, PracticeCode, UnitCode, ClawbackReservePayments,
        ClawbackReserveRate, ClawbackInterestPayments, ClawbackLastBalance, ClawbackLastPaymentDate, DateStarted,
        OscarDateStarted, OscarAgentId, OscarAgentPrefix, OscarAgentSerial, OscarAgentSuffix, DateLeaving,
        FPC1Passed, FPC2Passed, FPC3Passed, CompetentStatus, CompetentStatusDescription, PortfolioCode, BankCode,
        ConsultantCode, BackUpConsultantCode, IntroducerCode, SourceCode, BranchCode, AreaCode, DivisionCode,
        OrganisationCode, LevelOfSupervision, PercentageOfBusinessChecked, OverridePercentage, OrphanedClientAdministrator, 
    Name, Title, FirstNames, Initials, Suffix, PreferredName, Corporate,
        ClawbackReserve, RecruiterCode, LocationCode, DirectlyAuthorisedCode, EmploymentType, StrategicAllianceCode,
        AccessAgentCode, CompanyCode, PFACompanyCode, SpecialDeal, ReasonForLeaving,
        BreachNotification, BreachNotificationCode, BreachNotificationEndDate, AccessAgent, FranchiseCode,
        PracticeTypeCode, AgentTypeGrouping, AgentTypeGroupingDescription, AgentTypeB30, Manager1Code,
        Manager2Code, PaymentFrequency, PaymentThreshold, /*LastModifiedDate,*/ ID,
        CanSupervise, Manager3Code, Manager4Code, SupervisorTypeCode, SaleSupervisorCode, SpanSupervisorCode,
        RecruitedByCode, FranchiseSize, CDIStatusDate, Firm, CompetitionName, MCVDate, InterestCharged, 
    DeclarationOfAssociation, DeclarationOfAssociationEffectiveDate, MCVIndicator, MCVStatusDate,
        ContactTitle, ContactForename, ContactSurname, ThirdPartyClass, PreservedUpliftRate
       from   mstt_AgentsHistory
     where  Active = 1 
     and    Code = @AgentCode

  UNION 

       select 
        CODE, Active, AgentType, AgentTypeDescription, DESCN, ADDRESSEE, ADDRESS1, ADDRESS2,
        ADDRESS3, ADDRESS4, ADDRESS5, POSTCODE, COUNTRY, TELEPHONE, FAX_NUMBER, SALUTATION, NOTES, EMAIL, Website, 
    LicenceNumber, PortalLogon, CurrentSamplingRate,  CurrentSamplingDate, PreviousSamplingRate, PreviousSamplingDate,
        SamplingCounter, VATAgent, VATRegistered, VATRegNumber, SignificantInfluenceCode, CustomerFunctionCode,
        TradingName, NoticePeriod, AGENTID, STATUS, EFFDATE, OfficeCode, ActiveStatus, AgentCategory, AgentCategoryDescription, 
    GivesAdvice, Recruiter, RegionCode, PracticeCode, UnitCode, ClawbackReservePayments,
        ClawbackReserveRate, ClawbackInterestPayments, ClawbackLastBalance, ClawbackLastPaymentDate, DateStarted,
        OscarDateStarted, OscarAgentId, OscarAgentPrefix, OscarAgentSerial, OscarAgentSuffix, DateLeaving,
        FPC1Passed, FPC2Passed, FPC3Passed, CompetentStatus, CompetentStatusDescription, PortfolioCode, BankCode,
        ConsultantCode, BackUpConsultantCode, IntroducerCode, SourceCode, BranchCode, AreaCode, DivisionCode,
        OrganisationCode, LevelOfSupervision, PercentageOfBusinessChecked, OverridePercentage, OrphanedClientAdministrator, 
    Name, Title, FirstNames, Initials, Suffix, PreferredName, Corporate,
        ClawbackReserve, RecruiterCode, LocationCode, DirectlyAuthorisedCode, EmploymentType, StrategicAllianceCode,
        AccessAgentCode, CompanyCode, PFACompanyCode, SpecialDeal, ReasonForLeaving,
        BreachNotification, BreachNotificationCode, BreachNotificationEndDate, AccessAgent, FranchiseCode,
        PracticeTypeCode, AgentTypeGrouping, AgentTypeGroupingDescription, AgentTypeB30, Manager1Code,
        Manager2Code, PaymentFrequency, PaymentThreshold, /*LastModifiedDate,*/ ID,
        CanSupervise, Manager3Code, Manager4Code, SupervisorTypeCode, SaleSupervisorCode, SpanSupervisorCode,
        RecruitedByCode, FranchiseSize, CDIStatusDate, Firm, CompetitionName, MCVDate, InterestCharged, 
    DeclarationOfAssociation, DeclarationOfAssociationEffectiveDate, MCVIndicator, MCVStatusDate,
        ContactTitle, ContactForename, ContactSurname, ThirdPartyClass, PreservedUpliftRate
       from   #msit_AgentsHistory) as a)
                                  
  if @RecordStatusCheck = 2 -- record has changed
  begin
      
    --Make the current "Active" record "Inactive" in preparation for a new History record. 
    update mstt_AgentsHistory
      set Active    = 0,
        ValidToDate = @PrevValidToDate -->@ProcessDate - 2      --KZ: 26/08/2010
    where Active    = 1 
    and   Code    = @AgentCode    

  end
  
  -- Create a new history record if the record has changed from previous history or there's no history 

  if @RecordStatusCheck = 2 -- record has changed
  or  not exists (select null from mstt_AgentsHistory where Code = @AgentCode) -- no previous history
  begin

    --add record for latest position from #msit_AgentsHistory
    insert into mstt_AgentsHistory
      (
      CODE, 
      ValidFromDate, 
      ValidToDate, 
      Active, 
      AgentType, 
      AgentTypeDescription, 
      DESCN, 
      ADDRESSEE, 
      ADDRESS1, 
      ADDRESS2, 
      ADDRESS3, 
