      CustomerFunctionCode, 
      TradingName, 
      NoticePeriod, 
      AGENTID, 
      STATUS, 
      EFFDATE, 
      OfficeCode, 
      ActiveStatus, 
      AgentCategory, 
      AgentCategoryDescription, 
      GivesAdvice, 
      Recruiter, 
      RegionCode, 
      PracticeCode, 
      UnitCode, 
      ClawbackReservePayments, 
      ClawbackReserveRate, 
      ClawbackInterestPayments, 
      ClawbackLastBalance, 
      ClawbackLastPaymentDate, 
      DateStarted, 
      OscarDateStarted, 
      OscarAgentId, 
      OscarAgentPrefix, 
      OscarAgentSerial, 
      OscarAgentSuffix, 
      DateLeaving, 
      FPC1Passed, 
      FPC2Passed, 
      FPC3Passed, 
      CompetentStatus, 
      CompetentStatusDescription, 
      PortfolioCode, 
      BankCode, 
      ConsultantCode, 
      BackUpConsultantCode, 
      IntroducerCode, 
      SourceCode, 
      BranchCode, 
      AreaCode, 
      DivisionCode, 
      OrganisationCode, 
      LevelOfSupervision, 
      PercentageOfBusinessChecked, 
      OverridePercentage, 
      OrphanedClientAdministrator, 
