      Suffix, 
      PreferredName, 
      Corporate, 
      ClawbackReserve, 
      RecruiterCode, 
      LocationCode, 
      DirectlyAuthorisedCode, 
      EmploymentType, 
      StrategicAllianceCode, 
      AccessAgentCode, 
      CompanyCode, 
      PFACompanyCode, 
      SpecialDeal, 
      ReasonForLeaving, 
      BreachNotification, 
      BreachNotificationCode, 
      BreachNotificationEndDate, 
      AccessAgent, 
      FranchiseCode, 
      PracticeTypeCode, 
      AgentTypeGrouping, 
      AgentTypeGroupingDescription, 
      AgentTypeB30, 
      Manager1Code, 
      Manager2Code, 
      PaymentFrequency, 
      PaymentThreshold, 
      LastModifiedDate, 
      ID, 
      CanSupervise, 
      Manager3Code, 
      Manager4Code, 
      SupervisorTypeCode, 
      SaleSupervisorCode, 
      SpanSupervisorCode, 
      RecruitedByCode, 
      FranchiseSize, -- next is the ID Column, which we skip
      CDIStatusDate, 
      Firm, 
      CompetitionName, 
      MCVDate, 
      InterestCharged, 
      DeclarationOfAssociation, 
      DeclarationOfAssociationEffectiveDate, 
      MCVIndicator, 
      MCVStatusDate, 
      ContactTitle, 
      ContactForename, 
      ContactSurname, 
      ThirdPartyClass, 
      PreservedUpliftRate --132
      )
    select
      CODE,
      @ValidFromDate, -->@ProcessDate - 1,    --ValidFromDate   -- AG 25/09/2008    --KZ: 26/08/2010
      @DefaultValidToDate,  --ValidToDate
      1,            --Active --Set to true when new record, and set previous one to be false
      AgentType,        --AgentType
      AgentTypeDescription, -- AG 21/10/2008 back in
      DESCN,
      ADDRESSEE, 
      ADDRESS1, 
      ADDRESS2, 
      ADDRESS3, 
