      OscarAgentSerial,  --CR 26 Oscar Agent Data: added column -- AG 21/10/2008 back in
      OscarAgentSuffix,  --CR 26 Oscar Agent Data: added column   -- AG 21/10/2008 back in  
      DateLeaving,
