set @ProcessMessage = 'New History Rows = ' + convert(nvarchar(10), @NewHistoryRowCount)

exec msp_ProcessLog 'END', @ProcessMessage, null, 'mstp_AgentsHistory', 'Openwork'

close AgentCheck
