      )
    select
      CODE,
      @DefaultValidFromDate, --ValidFromDate
      @DefaultValidToDate,--LastMOdifiedDate, --ValidToDate
      1,--Active --Set to true when new record, and set previous one to be false
      Agt_type,--AgentType
      '',--AgentTypeDescription
