      OrganisationCode,
      LevelOfSupervision,
      PercentageOfBusinessChecked,
      OverridePercentage,
      OrphanedClientAdministrator,
      Name,
      Title,
      FirstNames,
      Initials,
      Suffix,
      PreferredName,
      Corporate,
      ClawbackReserve,
      RecruiterCode,
      LocationCode,
      DirectlyAuthorisedCode,
      EmploymentType,
      StrategicAllianceCode,
      AccessAgentCode,
      CompanyCode,
      PFACompanyCode,
