       msit_S_Agents
      
      
--Need to update PortalLogon
update 
 mstt_AgentsHistory
set 
 PortalLogon = i.[Name]
from 
 mstt_AgentsHistory A,
 msit_IntUsers i
where
 A.Code = i.AssociatedAgent

 
--Need to update AgentTypeDescription,AgentCategoryDescription, CompetentStatusDescription, GivesAdvice
--Recruiter, OscarDateStarted, OscarAgentCode

--Update any NULL AgentCategory 
update
 mstt_AgentsHistory
set
 AgentCategory = C.AgentCategoryCode
from
 mstt_AgentsHistory A ,
 msit_CodeAgentTypeCategories C
where 
 A.AgentCategory is null and
 A.AgentType = C.AgentType


--AgentTypeDescription
update 
 mstt_AgentsHistory
set 
 AgentTypeDescription = dl.Description
from 
 mstt_AgentsHistory A, 
 msdt_DropLists dl
where
 dl.CodeType = 'AgentType'  and
 convert(varchar(50),A.AgentType) = dl.Code

update 
 mstt_AgentsHistory 
set 
 AgentTypeDescription = @DefaultAgentTypeDescription 
where 
 AgentTypeDescription = ''


--AgentTypeGroupingDescription
update 
 mstt_AgentsHistory
set 
 AgentTypeGroupingDescription = dl.Description
from 
 mstt_AgentsHistory A, 
 msdt_DropLists dl
where
 dl.CodeType = 'AgentGrouping'  and
 convert(varchar(50),A.AgentTypeGrouping) = dl.Code


--AgentCategoryDescription
update 
 mstt_AgentsHistory
set 
 AgentCategoryDescription = cac.Description
from 
 mstt_AgentsHistory A,
 msit_CodeAgentCategories cac
where
 A.AgentCategory = cac.Code


update 
 mstt_AgentsHistory 
set 
 AgentCategoryDescription = @DefaultAgentCategoryDescription 
where 
 AgentCategoryDescription = ''



--CompetentStatusDescription
update 
 mstt_AgentsHistory
set 
 CompetentStatusDescription = dl.Description
from 
 mstt_AgentsHistory A, 
 msdt_DropLists dl
where
 dl.CodeType = ''  and
 convert(varchar(50),A.CompetentStatus) = dl.Code
 
 
 
--Hardcoded until values are put into the MI Warehouse Code&Descriptions Import
update 
 mstt_AgentsHistory
set 
 CompetentStatusDescription = case 
        when CompetentStatus = 0 then 'N/A'
        when CompetentStatus = 1 then 'Active'
        when CompetentStatus = 2 then 'Left'
        when CompetentStatus = 3 then 'Deceased'
        when CompetentStatus = 5 then 'Pre-Appointment'
        end

update 
 mstt_AgentsHistory 
set 
 CompetentStatusDescription = @DefaultCompetentStatusDescription 
where 
 CompetentStatusDescription = ''



--GivesAdvice, Recruiter
update 
 mstt_AgentsHistory
set 
 GivesAdvice = case when cac.GivesAdvice = 1 then 'Y' else 'N' end,
 Recruiter   = case when cac.Recruiter   = 1 then 'Y' else 'N' end
from 
 mstt_AgentsHistory      A, 
 msit_CodeAgentCategories  cac
where
 A.AgentCategory = cac.Code
 

--CR 26 Oscar Agent Data:
--OscarAgentId, OscarDateStarted, OscarAgentPrefix, OscarAgentSerial, OscarAgentSuffix
update 
 mstt_AgentsHistory
set 
 OscarAgentId     = O.OscarAgentId,
 OscarDateStarted = convert(datetime,O.OscarDateStarted),
 OscarAgentPrefix = O.OscarAgentPrefix,
 OscarAgentSerial = O.OscarAgentSerial,
 OscarAgentSuffix = O.OscarAgentSuffix
from 
 msit_OscarSwiftAgents O,
 mstt_AgentsHistory A
where
 O.SwiftAgentId = A.Code



--IF FIRST LOAD run this UPDATE for FRANCHISE SIZE !!!!!!!!!!!!!!!!!

--For Each current AgentType of 2 (Franchise) count the number of Agents that have 
--GivesAdvice = 'Y' that has this agent in the OfficeCode. 

--For Each current AgentType of 49 (Directly Authorised) count the number of Agents that have 
--GivesAdvice = 'Y' that has this agent in the DirectlyAuthorisedCode. 

--For Each current AgentType of 47 (StrategicAlliance) count the number of Agents that have 
--GivesAdvice = 'Y' that has this agent in the StrategicAllianceCode. 

--For Each current AgentType of 46 (AccessAgent) count the number of Agents that have 
--GivesAdvice = 'Y' that has this agent in the AccessAgentCode 

/*Update
 mstt_AgentsHistory
set
  FranchiseSize = (select count(*) 
    from mstt_AgentsHistory s 
    where 
      s.agenttype = 4 and --for Sellers
      s.active = 1    and 
      s.franchisecode = mstt_AgentsHistory.code)
from 
 mstt_AgentsHistory 
where
 mstt_AgentsHistory.agenttype = 2 and --for Franchise
 mstt_AgentsHistory.active =1  */
 
 
--Counts under Franchise 
Update
 mstt_AgentsHistory
set
  FranchiseSize = (select count(*) 
    from mstt_AgentsHistory s 
    where 
      s.GivesAdvice   = 'Y'  and 
      s.active    = 1    and 
      s.CompetentStatus = 1 and
      s.AgentType in (4, 43, 51) and
      s.franchisecode = mstt_AgentsHistory.code)
from 
 mstt_AgentsHistory 
where
 mstt_AgentsHistory.agenttype = 2 and --for Franchise
 mstt_AgentsHistory.active =1

--Counts under Directly Authorised 
Update
 mstt_AgentsHistory
set
  FranchiseSize = (select count(*) 
    from mstt_AgentsHistory s 
    where 
      s.GivesAdvice   = 'Y'  and 
      s.active    = 1    and 
      s.CompetentStatus = 1 and
      s.AgentType in (4, 43, 51) and
      s.DirectlyAuthorisedCode = mstt_AgentsHistory.code)
from 
 mstt_AgentsHistory 
where
 mstt_AgentsHistory.agenttype = 49 and --for Directly Authorised
 mstt_AgentsHistory.active =1

--Counts under StrategicAlliance
Update
 mstt_AgentsHistory
set
  FranchiseSize = (select count(*) 
    from mstt_AgentsHistory s 
    where 
      s.GivesAdvice   = 'Y'  and 
      s.active    = 1    and 
      s.CompetentStatus = 1 and
      s.AgentType in (4, 43, 51) and
      s.StrategicAllianceCode = mstt_AgentsHistory.code)
from 
 mstt_AgentsHistory 
where
 mstt_AgentsHistory.agenttype = 47 and --for StrategicAlliance
 mstt_AgentsHistory.active =1

--Counts under AccessAgent
Update
 mstt_AgentsHistory
set
  FranchiseSize = (select count(*) 
    from mstt_AgentsHistory s 
    where 
      s.GivesAdvice   = 'Y'  and 
      s.active    = 1    and 
      s.CompetentStatus = 1 and
      s.AgentType in (4, 43, 51) and
      s.AccessAgentCode = mstt_AgentsHistory.code)
from 
 mstt_AgentsHistory 
where
 mstt_AgentsHistory.agenttype = 46 and --for AccessAgent
 mstt_AgentsHistory.active    =1

 


--Update control table so this procedure is not run for subsequent loads
--This is done at the end of mcip_DataWarehouseBuild




end




