CREATE procedure [dbo].[mstp_AgentStandingOrders] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
*******************************************************************************/
begin
truncate table mstt_AgentStandingOrders
insert into mstt_AgentStandingOrders
  (ID, 
  AgentCode, 
  StandingOrderCode, 
  Description, 
  StartDate, 
  EndDate, 
  NextPaymentDue, 
  Frequency, 
  FrequencyDescription, 
  PaymentAmount, 
  TotalPaymentAmount, 
  AmountPaidToDate, 
  Suspend, 
  SuspendDescription, 
  SubjectToVAT, 
  CreatedBy, 
  CreatedDate)
select 
  ID,
  AgentCode,
  StandingOrderCode,
  Description,
  StartDate,
  EndDate,
  NextPaymentDue,
  Frequency,
  null as FrequencyDescription,
  PaymentAmount,
  TotalPaymentAmount,
  AmountPaidToDate,
  Suspend,
  null as SuspendDescription,
  SubjectToVAT,
  CreatedBy,
  CreatedDate
from msit_CommAgentStandingOrders
update a
set FrequencyDescription = dl.Description
from mstt_AgentStandingOrders a
  inner join msdt_DropLists dl
    on a.Frequency = dl.Code
where dl.CodeType = 'Frequency'
update a
set SuspendDescription = dl.Description
from mstt_AgentStandingOrders a
  inner join msdt_DropLists dl
    on a.Suspend = dl.Code
where dl.CodeType = 'SOSuspend'
end

