CREATE PROCEDURE [dbo].[mstp_AgentStatus] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
*******************************************************************************/
insert into msdt_AgentStatus
select 
 distinct AH.CompetentStatus, AH.CompetentStatusDescription
from 
 mstt_AgentsHistory AH
where
 not exists (select null from msdt_AgentStatus S
    where S.AgentStatus = AH.CompetentStatus)
if not exists (select * from msdt_AgentStatus where AgentStatusID = -99)
 begin
  SET IDENTITY_INSERT msdt_AgentStatus ON
  declare 
    @DefaultAgentStatusID     int,
    @DefaultAgentStatus       int,
    @DefaultAgentStatusDescription  nvarchar(255)
  set @DefaultAgentStatusID     = (select convert(int,DefaultValue) from mstt_DefaultCodeValues where CodeColumn = 'AgentStatusID')
  set @DefaultAgentStatus       = (select convert(int,DefaultValue) from mstt_DefaultCodeValues where CodeColumn = 'AgentStatus')
  set @DefaultAgentStatusDescription  = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AgentStatusDescription')
  insert into msdt_AgentStatus (AgentStatusID, AgentStatus, AgentStatusDescription) 
  values             (@DefaultAgentStatusID, @DefaultAgentStatus, @DefaultAgentStatusDescription)
  SET IDENTITY_INSERT msdt_AgentStatus OFF
 end 

