CREATE PROCEDURE [dbo].[mstp_AgentType] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
*******************************************************************************/
insert into msdt_AgentType
 select distinct
  AH.AgentCategory,
  AH.AgentCategoryDescription,
  AH.AgentType, 
  AH.AgentTypeDescription,
  AH.AgentTypeB30, --Business = 1, Individual = 2
  (select d.Description 
   from 
    msdt_DropLists d 
   where 
    d.CodeType = 'AgentGrouping' and 
    convert(varchar(50),AH.AgentTypeB30) = d.Code) as AgentGrouping
 from
  mstt_AgentsHistory AH
 where
  not exists (select null from msdt_AgentType A
    where A.AgentType = AH.AgentType)
declare 
  @DefaultAgentTypeID         int,
  @DefaultAgentCategory       nvarchar(255),
  @DefaultAgentCategoryDescription  nvarchar(255),
  @DefaultAgentType         int,
  @DefaultAgentTypeDescription    nvarchar(255),
  @DefaultAgentTypeB30        int,
  @DefaultAgentGrouping       nvarchar(255)
set @DefaultAgentTypeID        = (select convert(int,DefaultValue) from mstt_DefaultCodeValues where CodeColumn = 'AgentTypeID')
set @DefaultAgentCategory      = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AgentCategory')   
set @DefaultAgentCategoryDescription = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AgentCategoryDescription')     
set @DefaultAgentType        = (select convert(int,DefaultValue) from mstt_DefaultCodeValues where CodeColumn = 'AgentType')
set @DefaultAgentTypeDescription     = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AgentTypeDescription')
set @DefaultAgentTypeB30       = (select convert(int,DefaultValue) from mstt_DefaultCodeValues where CodeColumn = 'AgentTypeB30')    
set @DefaultAgentGrouping      = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AgentGrouping')   
--Add record for Unknown if there isn't one already
if not exists (select * from msdt_AgentType where AgentTypeID = @DefaultAgentTypeID)
 begin
  SET IDENTITY_INSERT msdt_AgentType ON
  insert into msdt_AgentType 
  (AgentTypeID,AgentCategory,AgentCategoryDescription,AgentType,AgentTypeDescription,AgentTypeB30,AgentGrouping)
  values 
  (@DefaultAgentTypeID, @DefaultAgentCategory,@DefaultAgentCategoryDescription,@DefaultAgentType,@DefaultAgentTypeDescription,@DefaultAgentTypeB30,@DefaultAgentGrouping)
  SET IDENTITY_INSERT msdt_AgentType OFF
 end 

