/****** Object:  StoredProcedure [dbo].[mstp_ApplyHierarchyTranslation]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[mstp_ApplyHierarchyTranslation] as
begin
declare 
@CODE       varchar(7), 
@AgentType      tinyint, 
@OfficeCode     varchar(7), 
@OrganisationCode   varchar(7), 
@DirectlyAuthorisedCode   varchar(7), 
@StrategicAllianceCode    varchar(7), 
@AccessAgentCode    varchar(7), 
@CompanyCode      varchar(10), 
@FranchiseCode      varchar(7), 
@AgentTypeGrouping    int, 
@Manager2Code     varchar(7), 
@Manager3Code     varchar(7), 
@Manager4Code     varchar(7)
declare 
@TranslationAgentCode   varchar(7),
@TranslationFranchiseCode varchar(7),
@TranslationManager2Code  varchar(7),
@TranslationManager4Code  varchar(7)
declare 
@NewOrganisationCode    varchar(7), 
@NewCompanyCode     varchar(10)
declare
@EarliestFromDate   datetime,
@LatestToDate     datetime
declare Agents cursor for 
select 
  CODE, 
  AgentType, 
  OfficeCode, 
  OrganisationCode, 
  DirectlyAuthorisedCode, 
  StrategicAllianceCode, 
  AccessAgentCode, 
  CompanyCode, 
  FranchiseCode, 
  AgentTypeGrouping, 
  Manager2Code,
  Manager3Code,
  Manager4Code
from mstt_Agents
order by Code
truncate table mstt_HierarchyTranslation
insert into mstt_HierarchyTranslation
select * from msit_HierarchyTranslation
--Get the Swift Code for the Seller, using the Oscar/Swift XREF (Individuals)
update ht
set Seller_Swift_Id = osa.SwiftAgentId
from mstt_HierarchyTranslation ht
  inner join msit_OscarSwiftAgents osa
    on ht.Seller_ID = osa.OscarAgentId
where osa.AgentType = 'I'
--Get the Swift Code for the Seller, using the Oscar/Swift XREF (Businesses)
update ht
set Seller_Swift_Id = osa.SwiftAgentId
from mstt_HierarchyTranslation ht
  inner join msit_OscarSwiftAgents osa
    on ht.Seller_ID = osa.OscarAgentId
where osa.AgentType = 'B'
and ht.Seller_Swift_id is null
/*
select * from mstt_HierarchyTranslation 
where Seller_Swift_id is null
and Franchise_Id = Seller_Id
select ht.* 
from mstt_HierarchyTranslation ht
  inner join mstt_TransitionCapacity_SellersFranchise tc
    on ht.Seller_ID = tc.OscarCode
where ht.Seller_Swift_Id is null
select ht.*
from mstt_HierarchyTranslation ht
  inner join msit_OscarSwiftAgents osa
    on ht.Seller_ID = osa.OscarAgentId
where osa.AgentType = 'B'
and Seller_Swift_id is null
*/
--Get the Swift Code for the Franchise, using the Oscar/Swift XREF
update ht
set Franchise_Swift_Id = osa.SwiftAgentId
from mstt_HierarchyTranslation ht
  inner join msit_OscarSwiftAgents osa
    on ht.Franchise_ID = osa.OscarAgentId
where osa.AgentType = 'B'
/*
select * from mstt_HierarchyTranslation 
where Franchise_Swift_Id is null
--and Franchise_Id = Seller_Id
*/
--Get the Swift Code for the RSM, using the Oscar/Swift XREF
update ht
set RSM_Swift_Id = osa.SwiftAgentId
from mstt_HierarchyTranslation ht
  inner join msit_OscarSwiftAgents osa
    on ht.RSM_ID = osa.OscarAgentId
where osa.AgentType = 'I'
--Get the Swift Code for the ASD, using the Oscar/Swift XREF
update ht
set ASD_Swift_Id = osa.SwiftAgentId
from mstt_HierarchyTranslation ht
  inner join msit_OscarSwiftAgents osa
    on ht.ASD_ID = osa.OscarAgentId
where osa.AgentType = 'I'
/*
select distinct Regional_Manager, RSM_ID
from mstt_hierarchyTranslation
where RSM_SWIFT_ID is null
select * from msit_OscarSwiftAgents
where OscarAgentId in ('0169029','0157213','0167179','0156063')
select distinct Area_Sales_Director, ASD_ID 
from mstt_hierarchyTranslation
where ASD_SWIFT_ID is null
*/
set @NewOrganisationCode = (select top 1 Code from mstt_Agents where AgentType = 19)
set @NewCompanyCode = (select top 1 Code from mstt_Agents where AgentType = 42)
set @EarliestFromDate = (select min(ValidFromDate) from mstt_AgentsHistory where ValidFromDate is not null)
set @LatestToDate = (select max(ValidToDate) from mstt_AgentsHistory where ValidToDate is not null)
open Agents
fetch next from Agents into
  @CODE, 
  @AgentType, 
  @OfficeCode, 
  @OrganisationCode, 
  @DirectlyAuthorisedCode, 
  @StrategicAllianceCode, 
  @AccessAgentCode, 
  @CompanyCode, 
  @FranchiseCode, 
  @AgentTypeGrouping, 
  @Manager2Code,
  @Manager3Code,
  @Manager4Code
while @@Fetch_Status = 0
  begin --Update Process
    if @AgentType in (2, 3, 4, 5, 43, 46, 47, 49, 50, 51, 52, 53, 55)
      begin -- Valid AgentTypes
        if @AgentTypeGrouping = 2 -- Individual
          begin -- Updates for Individuals
            declare SellerTranslationData cursor for
            select  top 1
              cast(Seller_SWIFT_ID as varchar(7))   as AgentCode, 
              cast(Franchise_SWIFT_ID as varchar(7))  as FranchiseCode,
              cast(RSM_SWIFT_ID as varchar(7))  as Manager2Code, 
              cast(ASD_SWIFT_ID as varchar(7))  as Manager4Code
            from  mstt_HierarchyTranslation
            where   Seller_SWIFT_ID = @Code
            open SellerTranslationData
            set @TranslationAgentCode = null
            set @TranslationFranchiseCode = null
            set @TranslationManager2Code = null
            set @TranslationManager4Code = null
            fetch next from SellerTranslationData into 
              @TranslationAgentCode,
              @TranslationFranchiseCode,
              @TranslationManager2Code,
              @TranslationManager4Code
            while @@Fetch_Status = 0
              begin --Updates to Agents, AgentsHistory and TASHH
                update mstt_Agents
                set   OfficeCode = case when coalesce(OfficeCode,
                          FranchiseCode,
                          DirectlyAuthorisedCode,
                          StrategicAllianceCode,
                          AccessAgentCode) is null then @TranslationFranchiseCode
                      else coalesce(OfficeCode,
                          FranchiseCode,
                          DirectlyAuthorisedCode,
                          StrategicAllianceCode,
                          AccessAgentCode) end,
                  Manager2Code    = case when Manager2Code is null or Manager2Code in ('10006','10007') then @TranslationManager2Code else Manager2Code end,
                  Manager4Code    = case when Manager4Code is null or Manager4Code in ('10006','10007') then @TranslationManager4Code else Manager4Code end,
                  CompanyCode     = case when CompanyCode is null then @NewCompanyCode else CompanyCode end,
                  OrganisationCode  = case when OrganisationCode is null then @NewOrganisationCode else OrganisationCode end
                where Code = @Code
                update mstt_AgentsHistory
                set   OfficeCode = case when coalesce(OfficeCode,
                          FranchiseCode,
                          DirectlyAuthorisedCode,
                          StrategicAllianceCode,
                          AccessAgentCode) is null then @TranslationFranchiseCode
                      else coalesce(OfficeCode,
                          FranchiseCode,
                          DirectlyAuthorisedCode,
                          StrategicAllianceCode,
                          AccessAgentCode) end,
                  Manager2Code    = case when Manager2Code is null or Manager2Code in ('10006','10007') then @TranslationManager2Code else Manager2Code end,
                  Manager4Code    = case when Manager4Code is null or Manager4Code in ('10006','10007') then @TranslationManager4Code else Manager4Code end,
                  CompanyCode     = case when CompanyCode is null then @NewCompanyCode else CompanyCode end,
                  OrganisationCode  = case when OrganisationCode is null then @NewOrganisationCode else OrganisationCode end
                where Code = @Code
                and getdate() between isnull(ValidFromDate, @EarliestFromDate) and isnull(ValidToDate, @LatestToDate)
                update mstt_TransAgentSplitHierarchyHistory
                set   FranchiseAgentCode  = case when FranchiseAgentCode is null then @TranslationFranchiseCode else FranchiseAgentCode end,
                  Manager2Code    = case when Manager2Code is null then @TranslationManager2Code else Manager2Code end
                where AgentCode = @Code
                fetch next from SellerTranslationData into 
                  @TranslationAgentCode,
                  @TranslationFranchiseCode,
                  @TranslationManager2Code,
                  @TranslationManager4Code
              end  --Updates to Agents, AgentsHistory and TASHH
              close SellerTranslationData
              deallocate SellerTranslationData
          end -- Updates for Individuals
        if @AgentTypeGrouping = 1 -- Business
          begin -- Updates for Businesses
            declare FranchiseTranslationData cursor for
            select  top 1
              cast(Franchise_SWIFT_ID as varchar(7))  as FranchiseCode,
              cast(RSM_SWIFT_ID as varchar(7))  as Manager2Code, 
              cast(ASD_SWIFT_ID as varchar(7))  as Manager4Code
            from  mstt_HierarchyTranslation
            where   Franchise_SWIFT_ID = @Code
            open FranchiseTranslationData
            set @TranslationAgentCode = null
            set @TranslationFranchiseCode = null
            set @TranslationManager2Code = null
            set @TranslationManager4Code = null
            fetch next from FranchiseTranslationData into 
              @TranslationFranchiseCode,
              @TranslationManager2Code,
              @TranslationManager4Code
            while @@Fetch_Status = 0
              begin --Updates to Agents, AgentsHistory and TASHH
                update mstt_Agents
                set   Manager2Code    = case when Manager2Code is null or Manager2Code in ('10006','10007') then @TranslationManager2Code else Manager2Code end,
                  Manager4Code    = case when Manager4Code is null or Manager4Code in ('10006','10007') then @TranslationManager4Code else Manager4Code end,
                  CompanyCode     = case when CompanyCode is null then @NewCompanyCode else CompanyCode end,
                  OrganisationCode  = case when OrganisationCode is null then @NewOrganisationCode else OrganisationCode end
                where Code = @Code
                update mstt_AgentsHistory
                set   Manager2Code    = case when Manager2Code is null or Manager2Code in ('10006','10007') then @TranslationManager2Code else Manager2Code end,
                  Manager4Code    = case when Manager4Code is null or Manager4Code in ('10006','10007') then @TranslationManager4Code else Manager4Code end,
                  CompanyCode     = case when CompanyCode is null then @NewCompanyCode else CompanyCode end,
                  OrganisationCode  = case when OrganisationCode is null then @NewOrganisationCode else OrganisationCode end
                where Code = @Code
                and getdate() between isnull(ValidFromDate, @EarliestFromDate) and isnull(ValidToDate, @LatestToDate)
                update mstt_TransAgentSplitHierarchyHistory
                set   FranchiseAgentCode  = case when FranchiseAgentCode is null then @TranslationFranchiseCode else FranchiseAgentCode end,
                  Manager2Code    = case when Manager2Code is null or Manager2Code in ('10006','10007') then @TranslationManager2Code else Manager2Code end
                where AgentCode = @Code
                fetch next from FranchiseTranslationData into 
                  @TranslationFranchiseCode,
                  @TranslationManager2Code,
                  @TranslationManager4Code
              end  --Updates to Agents, AgentsHistory and TASHH
              close FranchiseTranslationData
              deallocate FranchiseTranslationData
          end -- Updates for Businesses
        if @AgentType in (52, 53) -- RSMs
          begin -- Updates for RSMs
            declare RSMTranslationData cursor for
            select  top 1
              cast(RSM_SWIFT_ID as varchar(7)) as Manager2Code, 
              cast(ASD_SWIFT_ID as varchar(7)) as Manager4Code
            from  mstt_HierarchyTranslation
            where   RSM_SWIFT_ID = @Code
            open RSMTranslationData
            set @TranslationAgentCode = null
            set @TranslationFranchiseCode = null
            set @TranslationManager2Code = null
            set @TranslationManager4Code = null
            fetch next from RSMTranslationData into 
              @TranslationManager2Code,
              @TranslationManager4Code
            while @@Fetch_Status = 0
              begin --Updates to Agents and AgentsHistory
                update mstt_Agents
                set   Manager4Code    = case when Manager4Code is null or Manager4Code in ('10006','10007') then @TranslationManager4Code else Manager4Code end,
                  CompanyCode     = case when CompanyCode is null then @NewCompanyCode else CompanyCode end,
                  OrganisationCode  = case when OrganisationCode is null then @NewOrganisationCode else OrganisationCode end
                where Code = @Code
                update mstt_AgentsHistory
                set   Manager4Code    = case when Manager4Code is null or Manager4Code in ('10006','10007') then @TranslationManager4Code else Manager4Code end,
                  CompanyCode     = case when CompanyCode is null then @NewCompanyCode else CompanyCode end,
                  OrganisationCode  = case when OrganisationCode is null then @NewOrganisationCode else OrganisationCode end
                where Code = @Code
                and getdate() between isnull(ValidFromDate, @EarliestFromDate) and isnull(ValidToDate, @LatestToDate)
                fetch next from RSMTranslationData into 
                  @TranslationManager2Code,
                  @TranslationManager4Code
              end  --Updates to Agents and AgentsHistory
              close RSMTranslationData
              deallocate RSMTranslationData
          end -- Updates for RSMs
        if @AgentType = 55 -- ASDs
          begin -- Updates for ASDs
            update mstt_Agents
              set   CompanyCode     = case when CompanyCode is null then @NewCompanyCode else CompanyCode end,
              OrganisationCode  = case when OrganisationCode is null then @NewOrganisationCode else OrganisationCode end
            where Code = @Code
            update mstt_AgentsHistory
            set   CompanyCode     = case when CompanyCode is null then @NewCompanyCode else CompanyCode end,
              OrganisationCode  = case when OrganisationCode is null then @NewOrganisationCode else OrganisationCode end
            where Code = @Code
            and getdate() between isnull(ValidFromDate, @EarliestFromDate) and isnull(ValidToDate, @LatestToDate)
          end -- Updates for ASDs
      end -- Valid AgentTypes
    fetch next from Agents into
      @CODE, 
      @AgentType, 
      @OfficeCode, 
      @OrganisationCode, 
      @DirectlyAuthorisedCode, 
      @StrategicAllianceCode, 
      @AccessAgentCode, 
      @CompanyCode, 
      @FranchiseCode, 
      @AgentTypeGrouping, 
      @Manager2Code,
      @Manager3Code,
      @Manager4Code
  end  --Update Process
close Agents
deallocate Agents
end

GO
