CREATE  PROCEDURE [dbo].[mstp_CapacityTerminationCounts] --WITH RECOMPILE,ENCRYPTION
  @DeleteDate VARCHAR(10),  -- Defines date from which Capacity Data is deleted
  @StartDate VARCHAR(10)    -- Defines date from which Capacity Data is reloaded
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

-- Ticket 102 : Mike Cawood - 22 May 2007
-- Cater for duplicate ValidFromDate occurrences on mstt_AgentsHistory

*******************************************************************************/

-- PROCEDURE BODY GOES HERE

set nocount on

-- Validate @StartDate and @DeleteDate
IF ISDATE(@StartDate) = 0 or isdate(@deletedate) = 0
BEGIN
  SELECT 
     CASE WHEN ISDATE(@DeleteDate) = 0 THEN 'Invalid Delete Date - please enter as dd/mm/yyyy'
          WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date - please enter as dd/mm/yyyy'
        END AS [Error]
   RETURN 0
END

DECLARE @DD DATETIME
DECLARE @SD DATETIME

SET @DD = CAST(CONVERT(NVARCHAR, @DeleteDate, 112) AS DATETIME)
SET @SD = CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)

Declare @SoleTraderSizeId int
set @SoleTraderSizeId = (select min(FranchiseSizeId) from msdt_FranchiseSize where FranchiseSizeType = 'Sole Trader')

Declare @RunDate DateTime

Delete msft_CapacityTerminationCounts
where StatusDate >= @DD and Comparison = 'Actual'

Declare CalendarTimeCursor Cursor
for 
select distinct DateTime from msdt_CalendarTime
where DateTime >= @SD
and DateTime <= getdate()
order by DateTime

OPEN CalendarTimeCursor
   FETCH NEXT FROM CalendarTimeCursor INTO @RunDate

 WHILE @@FETCH_STATUS = 0
   BEGIN
  
  /********************* CAPACITY FROM SWIFT ****************************/  
  
  --Add Advisers/Franchiserecords at a monthly level. 

  --StatusDate is based on today's date, in order to maintain ongoing history.
  --As this is run daily must check if the FACT table already contains a record 
  --for the current month. If yes, do not add, if no add record.

  --A record is uniquely identified at the ReportType,Level,AgentCode,AdviserId level
  --There can be more than one record for an AgentCode with different AdviserIds. 

  --Target data is not deleted or reloaded by this procedure

  /**********************************************************************/  

  --Remove the records for the current month 

delete from msft_CapacityTerminationCounts
where DATEDIFF(mm,Statusdate,@RunDate) = 0
and ReportType = 'Capacity'
and Comparison = 'Actual'
  
  --Insert Agents into a Current Version of the Table as it is in the month being run

-- Ticket 102 : Mike Cawood - 22 May 2007
-- Cater for duplicate ValidFromDate occurrences on mstt_AgentsHistory

select Code,Max(ValidFromDate) as ValidFromDate
into #AgentsHistoryFromDate
from mstt_AgentsHistory 
where ValidFromDate <= @RunDate
Group By Code

select t1.Code,t1.ValidFromDate,Max(isnull(ah.validtodate,'1 jan 9999')) as ValidToDate
into #AgentsHistoryFromToDate
from mstt_AgentsHistory ah
inner join #AgentsHistoryFromDate t1 on t1.code = ah.code and t1.validfromdate = ah.validfromdate
Group By t1.Code,t1.ValidFromDate

select ah.Code,t1.ValidFromDate,t1.ValidToDate,ah.AgentType,ah.GivesAdvice,ah.Competentstatus,ah.datestarted,
ah.dateleaving,ah.Reasonforleaving,coalesce(ah.Firm,ah.officecode,ah.accessagentcode) as Firm
into #AgentsHistory 
from mstt_AgentsHistory ah 
inner join #AgentsHistoryFromToDate t1 on t1.code = ah.code and t1.validfromdate = ah.validfromdate
and t1.validtodate = ah.validtodate
where ah.competentstatus in (1,2,3) and ah.datestarted <= @RunDate
Order by ah.Code desc

  --Get The Adviser Id according to the structure as it was at run date

select Agentcode,max(ChangeDate) as MaxDate
into #AdviserChangesMax
from msdt_AdviserHistory
where ChangeDate <= @RunDate
group by agentcode

select Agentcode,min(ChangeDate) as MinDate
into #AdviserChangesMin
from msdt_AdviserHistory
where ChangeDate >= @RunDate
group by agentcode

 select distinct adh.agentcode,coalesce(t1.maxdate,t2.mindate) as
   ChangeDate
   into #AdviserChanges
   from msdt_AdviserHistory adh
   left outer join #adviserchangesmax t1 on t1.agentcode = adh.agentcode
   left outer join #adviserchangesmin t2 on t2.agentcode = adh.agentcode


select adh.AdviserID,t1.AgentCode,adh.FranchiseSizeID,t1.ChangeDate
into #Advisers
from msdt_AdviserHistory adh
inner join #AdviserChanges t1 on adh.agentcode = t1.agentcode and adh.changedate = t1.changedate
order by adh.AdviserID, t1.AgentCode, adh.FranchiseSizeID

  --ADVISERS - add active Advisers

insert into msft_CapacityTerminationCounts
select  
  'Capacity' as ReportType, 
  convert(datetime,convert(nvarchar(6), @RunDate,112) + '01') as StatusDate, 
  'Adviser' as [Level], 
  ag.Code as AgentCode, 
  ah.AdviserId, 
  case when agh.AgentType in ('52','53','54','55') then @SoleTraderSizeId else ah.FranchiseSizeId end,
  'Actual' as Comparison,
  -99 as ComparisonId,
  -99 as ReasonForLeavingID,
  1 as Val
from mstt_Agents ag
  inner join #AgentsHistory agh
    on ag.Code = agh.Code
  inner join #Advisers ah
    on ag.Code = ah.AgentCode
  left outer join mstt_Agents ag_Firm
    on agh.Firm = ag_Firm.Code
where 
  isnull(ag.MCVIndicator,0) <> 1 --used by FSD to denote sellers linked to MCV termination
  -- Treat Admin staff linked to a NASP as Sellers even if GivesAdvice flag not set to Y
  and (isnull(agh.GivesAdvice, 'N') = 'Y'
       or (isnull(agh.GivesAdvice, 'N') = 'N' and agh.AgentType = '5' and ag_Firm.AgentCategory like 'NASP%'))
  and ( --'Normal' sellers (they exist in a franchise)
    --We need to only show CORE sellers, that is, 
    --no one who is attached to a Directly Authorised Firm
    (agh.AgentType in ('3', '4', '5', '43', '45','51') and ag_Firm.AgentType in ('2', '46'))
    or 
    --Selling Managers who do not exist in a franchise
    agh.AgentType in ('52','53','54','55'))  
  -- Still Active or Active at RunDate
  and (agh.competentstatus = 1 or (agh.dateleaving > @RunDate and agh.competentstatus in (2,3)))
  order by agentcode

  -- FRANCHISES - add active Franchises

insert into msft_CapacityTerminationCounts
select 'Capacity'  as ReportType,
  convert(datetime,convert(nvarchar(6), @RunDate,112) + '01') as StatusDate, 
  'Franchise' as [Level],
  ag.Code, 
  adh.AdviserId,
  adh.FranchiseSizeId,
  'Actual' as Comparison,
  -99 as ComparisonId,
  -99 as ReasonForLeavingID,
  1 as Val
    
from mstt_Agents ag
  inner join #AgentsHistory agh
    on ag.Code = agh.Code
  inner join #Advisers adh
    on ag.Code = adh.AgentCode
where 
  --Only CORE Franchises are to be included, AND Managers who sell.
  agh.AgentType in ('2', '46')
  and (agh.competentstatus = 1 or (agh.dateleaving > @RunDate and agh.competentstatus in (2,3)))
order by ag.Code

  /********************* TERMINATIONS FROM SWIFT ************************/

  --As this is run daily must check if the FACT table already contains the same record 
  --If yes, do not add, if no add record.
  --A record is uniquely identified at the ReportType,Level,AgentCode,AdviserId level
  --Assume An Agent cannot be terminated more than once

  -- ADVISER TERMINATIONS

insert into msft_CapacityTerminationCounts
select 'Terminations' as ReportType, 
  agh.DateLeaving as StatusDate, 
  'Adviser' as [Level], 
  ag.Code as AgentCode, 
  ah.AdviserId, 
  case when agh.AgentType in ('52','53','54','55') then @SoleTraderSizeId else ah.FranchiseSizeId end,
  'Actual' as Comparison,
  -99 as ComparisonId,
  (select ReasonForLeavingId 
    from msdt_ReasonForLeaving rl 
    where agh.ReasonForLeaving = rl.ReasonForLeavingCode) as ReasonForLeavingId,
  1 as Val
     
from mstt_Agents ag
  inner join #AgentsHistory agh
    on ag.Code = agh.Code
  inner join #Advisers ah
    on ag.Code = ah.AgentCode
  left outer join mstt_Agents ag_Firm
    on ag.Firm = ag_Firm.Code
where  
  agh.CompetentStatus in ('2', '3')
  and isnull(ag.MCVIndicator,0) <> 1 --used by FSD to denote sellers linked to MCV termination
  and agh.ReasonForLeaving <> 'PFATFR'--these Terminations should be ignored as new UID created for seller
  -- Treat Admin staff linked to a NASP as Sellers even if GivesAdvice flag not set to Y
  and (isnull(agh.GivesAdvice, 'N') = 'Y'
       or (isnull(agh.GivesAdvice, 'N') = 'N' and agh.AgentType = '5' and ag_Firm.AgentCategory like 'NASP%'))
  and ( --'Normal' sellers (they exist in a franchise)
    --We need to only show CORE sellers, that is, 
    --no one who is attached to a Directly Authorised Firm
    (agh.AgentType in ('3', '4', '5', '43', '45','51') and ag_Firm.AgentType in ('2', '46'))
    or 
    --Selling Managers who do not exist in a franchise
    agh.AgentType in ('52','53','54','55')) 
  and (agh.dateleaving is null or agh.dateleaving <= @Rundate)
  --Exclude if they have previously been identified as a Terminated adviser. 
  and not exists (select null from 
       msft_CapacityTerminationCounts F
            where
       F.ReportType = 'Terminations'  and
       F.Level      = 'Adviser'       and
       F.AgentCode  = ag.Code         and
       F.Comparison = 'Actual'  )
  order by ag.code

  -- Terminated franchises

insert into msft_CapacityTerminationCounts
select 'Terminations' as ReportType,
  agh.DateLeaving as StatusDate, 
  'Franchise' as [Level],
  adh.AgentCode, 
  adh.AdviserId,
  adh.FranchiseSizeId,
  'Actual' as Comparison,
  -99 as ComparisonId,
  (select ReasonForLeavingId 
  from msdt_ReasonForLeaving rl 
  where agh.ReasonForLeaving = rl.ReasonForLeavingCode) as ReasonForLeavingId,    
  1 as Val
    
from mstt_Agents ag
  inner join #AgentsHistory agh
    on ag.Code = agh.Code
  inner join #Advisers adh
    on ag.Code = adh.AgentCode

where 
  agh.CompetentStatus in ('2', '3')
  --Only CORE Franchises are to be included, AND Managers who sell.
  and agh.AgentType in ('2', '46') 
  and (agh.dateleaving is null or agh.dateleaving <= @Rundate)
  --Exclude if they have previously been identified as a Terminated franchise.
  and not exists (select null from 
       msft_CapacityTerminationCounts F
            where
      F.ReportType = 'Terminations' and
      F.Level      = 'Franchise'  and
      F.Comparison = 'Actual'   and
      F.AgentCode  = adh.AgentCode  )
  order by ag.code

--New Code to remove old terminated figures for Agents that are now Active

Delete msft_CapacityTerminationCounts 
from msft_CapacityTerminationCounts Capacity
where ReportType = 'Terminations'
and Capacity.ReportType = 'Capacity' 
and StatusDate <= Capacity.StatusDate
and Level = Capacity.Level
and AgentCode = Capacity.AgentCode
and Comparison = 'Actual'
and Capacity.StatusDate = convert(datetime,convert(nvarchar(6), @RunDate,112) + '01')

-- Delete termination figures where Reason For Leaving has changed to 'PFATFR' 
-- Delete terminations where MCV Indicator has changed to 1 on Sellers and Managers.
-- Exclude Businesses as these use the MCVIndicator as part of MCV process.

Delete msft_CapacityTerminationCounts
from mstt_Agents ag
where AgentCode = ag.Code
and ((ag.MCVIndicator = 1 and ag.AgentType not in (2,46,49))  
or ag.ReasonforLeaving = 'PFATFR')

-- Set ComparisonID
update t
  set ComparisonID = c.ComparisonID
from msft_CapacityTerminationCounts t
  inner join msdt_Comparison c
    on t.Comparison = c.Comparison  

--- Populate msft_CapacityCountsByDay for this particular Run date

declare @MostRecentDateAdvisers datetime
set @MostRecentDateAdvisers = 
  (select max(StatusDate) 
  from msft_CapacityTerminationCounts
  where ReportType = 'Capacity'
  and Level = 'Adviser'
  and Comparison = 'Actual')

delete from msft_CapacityCountsByDay
where StatusDate = convert(datetime, (convert(varchar(20), @RunDate, 112)))
and ReportType = 'Capacity'
and Level = 'Adviser'
and Comparison = 'Actual'

insert into msft_CapacityCountsByDay
(
ReportType, StatusDate, Level, AgentCode, AdviserId, FranchiseSizeId, Comparison, ComparisonId, Val
)
select 
ReportType, convert(datetime, (convert(varchar(20), @RunDate, 112))), 
Level, AgentCode, AdviserId, FranchiseSizeId, Comparison, ComparisonId, Val
from msft_CapacityTerminationCounts
where statusDate = @MostRecentDateAdvisers
and ReportType = 'Capacity'
and Level = 'Adviser'
and Comparison = 'Actual'


declare @MostRecentDateFranchises datetime
set @MostRecentDateFranchises = 
  (select max(StatusDate) 
  from msft_CapacityTerminationCounts
  where ReportType = 'Capacity'
  and Level = 'Franchise'
  and Comparison = 'Actual')

delete from msft_CapacityCountsByDay
where StatusDate = convert(datetime, (convert(varchar(20), @RunDate, 112)))
and ReportType = 'Capacity'
and Level = 'Franchise'
and Comparison = 'Actual'

insert into msft_CapacityCountsByDay
(
ReportType, StatusDate, Level, AgentCode, AdviserId, FranchiseSizeId, Comparison, ComparisonId,  Val
)
select 
ReportType, convert(datetime, (convert(varchar(20), @RunDate, 112))), 
Level, AgentCode, AdviserId, FranchiseSizeId, Comparison, ComparisonId,  Val
from msft_CapacityTerminationCounts
where statusDate = @MostRecentDateFranchises
and ReportType = 'Capacity'
and Level = 'Franchise'
and Comparison = 'Actual'

drop table #agentshistoryfromdate   -- Ticket 102
drop table #agentshistoryfromtodate   -- Ticket 102
drop table #agentshistory
drop table #adviserchangesmax
drop table #adviserchangesmin
drop table #adviserchanges
drop table #advisers

FETCH NEXT FROM CalendarTimeCursor INTO @RunDate

END 
 
close  CalendarTimeCursor

deallocate CalendarTimeCursor


  select 'Capacity' as ReportType,
    convert(smalldatetime, convert(varchar(30), DateCode, 113), 113) as StatusDate,
    'Adviser' as Level,
    case when SwiftRSMAgentId is null and SwiftASMAgentId is null then 'EXEC_DUMMY_CODE'
      when SwiftRSMAgentId is null and SwiftASMAgentId is not null then SwiftASMAgentID+'_ASM_DUMMY_CODE'
      when SwiftRSMAgentId is not null and SwiftASMAgentId is not null then SwiftRSMAgentID+'_RSM_DUMMY_CODE'
    end as AgentCode,
    -99 as AdviserId,
    -99 as FranchiseSizeId,
    TargetRevision as Comparison,
    ComparisonId,
    -99 as ReasonForLeavingId,
    Advisers as Val
  
  into #CapacityTargets
  
  from mstt_TargetCompany
  where isnull(Advisers,0) <> 0
  
  union all
  
  select 'Capacity' as ReportType,
    convert(smalldatetime, convert(varchar(30), DateCode, 113), 113) as StatusDate,
    'Franchise' as Level,
    case when SwiftRSMAgentId is null and SwiftASMAgentId is null then 'EXEC_DUMMY_CODE'
      when SwiftRSMAgentId is null and SwiftASMAgentId is not null then SwiftASMAgentID+'_ASM_DUMMY_CODE'
      when SwiftRSMAgentId is not null and SwiftASMAgentId is not null then SwiftRSMAgentID+'_RSM_DUMMY_CODE'
    end as AgentCode,
    -99 as AdviserId,
    -99 as FranchiseSizeId,
    TargetRevision as Comparison,
    ComparisonId,
    -99 as ReasonForLeavingId,
    Franchises as Val
  
  from mstt_TargetCompany
  where isnull(Franchises,0) <> 0
  
  union all
  
  select 'Terminations' as ReportType,
    convert(smalldatetime, convert(varchar(30), DateCode, 113), 113) as StatusDate,
    'Adviser' as Level,
    case when SwiftRSMAgentId is null and SwiftASMAgentId is null then 'EXEC_DUMMY_CODE'
      when SwiftRSMAgentId is null and SwiftASMAgentId is not null then SwiftASMAgentID+'_ASM_DUMMY_CODE'
      when SwiftRSMAgentId is not null and SwiftASMAgentId is not null then SwiftRSMAgentID+'_RSM_DUMMY_CODE'
    end as AgentCode,
    -99 as AdviserId,
    -99 as FranchiseSizeId,
    TargetRevision as Comparison,
    ComparisonId,
    -99 as ReasonForLeavingId,
    SellerLeavers as Val
  
  from mstt_TargetCompany
  where isnull(SellerLeavers,0) <> 0
  
  union all
  
  select 'Terminations' as ReportType,
    convert(smalldatetime, convert(varchar(30), DateCode, 113), 113) as StatusDate,
    'Franchise' as Level,
    case when SwiftRSMAgentId is null and SwiftASMAgentId is null then 'EXEC_DUMMY_CODE'
      when SwiftRSMAgentId is null and SwiftASMAgentId is not null then SwiftASMAgentID+'_ASM_DUMMY_CODE'
      when SwiftRSMAgentId is not null and SwiftASMAgentId is not null then SwiftRSMAgentID+'_RSM_DUMMY_CODE'
    end as AgentCode,
    -99 as AdviserId,
    -99 as FranchiseSizeId,
    TargetRevision as Comparison,
    ComparisonId,
    -99 as ReasonForLeavingId,    
    FranchiseLeavers as Val
  
  from mstt_TargetCompany
  where isnull(FranchiseLeavers,0) <> 0
  
  
  update c
  set   AdviserId = ad.AdviserId,
    FranchiseSizeId = ad.FranchiseSizeId
  from #CapacityTargets c
    inner join msdt_AdviserDummiesHistory ad
      on c.AgentCode = ad.AgentCode
  
  
  delete from msft_CapacityTerminationCounts
  where exists (select 'x' from #CapacityTargets ct
      where msft_CapacityTerminationCounts.ReportType = ct.ReportType 
      and msft_CapacityTerminationCounts.StatusDate = ct.StatusDate
      and msft_CapacityTerminationCounts.Level = ct.Level
      and msft_CapacityTerminationCounts.AgentCode = ct.AgentCode 
      and msft_CapacityTerminationCounts.AdviserId  = ct.AdviserId
      and msft_CapacityTerminationCounts.FranchiseSizeId = ct.FranchiseSizeId 
      and msft_CapacityTerminationCounts.Comparison = ct.Comparison
      and msft_CapacityTerminationCounts.ComparisonId = ct.ComparisonId)
      
  
  insert into msft_CapacityTerminationCounts
  select ReportType, 
    StatusDate, 
    Level, 
    AgentCode, 
    AdviserId, 
    FranchiseSizeId, 
    Comparison, 
    ComparisonId,
    ReasonForLeavingId,
    Val
  from #CapacityTargets ct
  
  drop table #CapacityTargets

  update msft_CapacityTerminationCounts
  set ReasonForLeavingId = -99
  where ReasonForLeavingId is null


GO
