CREATE procedure [dbo].[mstp_CaseCheck] as 
  
begin  
  
  
/******************************************************************************  
  
Mike Cawood 25 Mar'08  
SQR Fix to use Agentcode from Track Group if present  
  
*******************************************************************************/  
  
  
truncate table mstt_CaseCheck  
  
insert into mstt_CaseCheck  
select tg.Id,  
 null as RelevantTrackGroupId,  
 tg.ClientId,  
 null as SalesQualityASDLevelCode, --mstt_Policy  
 null as SalesQualityRSMLevelCode, --mstt_Policy  
 null as SalesQualitySQMLevelCode, --mstt_Policy  
 null as SalesQualityPSLevelCode, --mstt_Policy  
 null as PracticeCode,   --mstt_Policy  
 case when tg.AgentCode is not null then tg.AgentCode else NULL end as AgentCode, --mstt_Policy  --MPC: 25/03/08  
 null as TrackGroupCode,   --msit_CodeTrackGroup  
 tg.NBCCHeaderId,  
 PolicyId,  
 null as ComplianceCategoryCode,  --mstt_Policy  
 null as ProductCode,   --mstt_Policy  
 null as ProposalTransactionNumber, --mstt_PolicyTransactions  
 tg.Description as TrackGroupDescn,   
 TrackType,   
 RequestedDate,   
 ClearedDate,   
 CompletedState,   
 null as CompletedStateDescn,  --msdt_DropLists  
 NBCCStatus,   
 case when NBCCTrainingIssues is not null then 'Y' else 'N' end as NBCCTrainingIssuesInd,   
 case when NBCCComments is not null then 'Y' else 'N' end as NBCCCommentsInd,   
 WorkFlowID,   
 TriggeredBy,   
 CaseAccepted as CaseAcceptedInd,   
 CaseAcceptedBy,   
 CaseCheckValidatedDate,   
 FinalCheckValidatedDate,   
 FinalCheckedBy,   
 NBCCFinalStatus,   
 DoubleCheckingRequired as DoubleCheckingRequiredInd,   
 DoubleCheckingOutcome,   
 DoubleCheckedBy,   
 AgentClassId,   
 NBCCFailureReason as NBCCInitialFailureReasonCode,   
 null as NBCCInitialFailureReasonDesc,  
 NBCCFinalFailureReason as NBCCFinalFailureReasonCode,   
 null as NBCCFinalFailureReasonDesc,  
 null as NBCCReferralReasonCode,  --mstt_CaseNBCCSelection  
 null as NBCCReferralReasonDesc,  
 NBCCChecked as NBCCCheckedInd  
from msit_TrackGroups tg  
where tg.TrackType = 2  
and tg.Description like 'Case Check For%'  
  
	--JNG  
	ORDER BY  
	tg.Id,
	tg.ClientId,
	case when tg.AgentCode is not null then tg.AgentCode else NULL end,
	tg.NBCCHeaderId,
	PolicyId,
	tg.Description,
	TrackType,   
	RequestedDate,
	ClearedDate,
	CompletedState,
	NBCCStatus,
	case when NBCCTrainingIssues is not null then 'Y' else 'N' end,
	case when NBCCComments is not null then 'Y' else 'N' end,
	WorkFlowID,
	TriggeredBy,
	CaseAccepted,
	CaseAcceptedBy,   
	CaseCheckValidatedDate,
	FinalCheckValidatedDate,
	FinalCheckedBy,
	NBCCFinalStatus,
	DoubleCheckingRequired,
	DoubleCheckingOutcome,
	DoubleCheckedBy,
	AgentClassId,
	NBCCFailureReason,
	NBCCFinalFailureReason, 
	NBCCChecked
	--JNG   
   
--Get TrackGroupCode  
update c  
set TrackGroupCode = ctg.Code  
from mstt_CaseCheck c  
 inner join msit_CodeTrackGroups ctg  
  on c.TrackGroupDescn = ctg.Description  
  
  
--Get Failure Reason descriptions  
update c  
set NBCCInitialFailureReasonDesc = cnfr.Description  
from mstt_CaseCheck c  
 inner join msit_CodeNBCCFailureReason cnfr  
  on c.NBCCInitialFailureReasonCode = cnfr.Id  
    
update c  
set NBCCFinalFailureReasonDesc = cnfr.Description  
from mstt_CaseCheck c  
 inner join msit_CodeNBCCFailureReason cnfr  
  on c.NBCCFinalFailureReasonCode = cnfr.Id  
  
--Update fields from Policies  
update c  
set SalesQualityASDLevelCode = p.SalesQualityASDLevelCode,  
 SalesQualityRSMLevelCode = p.SalesQualityRSMLevelCode,   
 SalesQualitySQMLevelCode = p.SalesQualitySQMLevelCode,   
 SalesQualityPSLevelCode = p.SalesQualityPSLevelCode,  
 PracticeCode = p.PracticeCode,  
 AgentCode = coalesce(c.AgentCode,p.SalesQualityAdviserLevelCode), --MPC: 25/03/08  
 ComplianceCategoryCode = p.Regulation,  
 ProductCode = p.ProductCode,  
 ProposalTransactionNumber = p.ProposalTransactionNumber  
from mstt_CaseCheck c  
 inner join mstt_Policies p  
  on c.Policy_Id = p.Pol_Num   
  
  
  
--update the NBCCReferralReasonCode, then description  
update c  
set NBCCReferralReasonCode = p.NBCCReferralReasonCode  
from mstt_CaseCheck c  
 inner join mstt_Policies p  
  on c.Policy_Id = p.Pol_Num  
  
update c  
set NBCCReferralReasonDesc = n.Description  
from mstt_CaseCheck c  
 inner join msit_CodeNBCCReferralReason n  
  on c.NBCCReferralReasonCode = n.Code  
    
  
--update RelevantTrackGroupId  
select policy_Id, max(TrackGroupId) as RelevantTrackGroupId  
into #MaxIds  
from mstt_CaseCheck  
where CompletedState in (0,1)  
and NBCCStatus is not null  
group by Policy_Id  
  
update c  
set RelevantTrackGroupId = m.RelevantTrackGroupId  
from mstt_CaseCheck c  
 inner join #MaxIds m   
  on c.Policy_id = m.Policy_id  
  
drop table #MaxIds  
  
--Get other description fields  
update c  
set CompletedStateDescn = dl.Description  
from mstt_CaseCheck c  
 inner join msdt_DropLists dl  
  on cast(c.CompletedState as varchar(50)) = dl.Code  
where dl.CodeType = 'CompletedState'    
  
/*  
  
select * from mstt_CaseCheck  
  
select * from msit_PolicyNBCCSelection  
  
select Policy_Id, count(*)  
from mstt_CaseCheck  
group by Policy_Id  
order by 2 desc  
  
select * from mstt_CaseCheck  
where Policy_Id = 35206  
  
*/  
  
/*  
  
exec mstp_Policies  
  
select * from msit_trackGroups tg  
--where policyId is not null  
inner join mstt_policies p  
 on tg.policyid = p.Pol_Num  
 and tg.AgentCode = p.ServicingAgentCode  
  
select top 500 * from mstt_Policies  
where prop_date is not null  
  
*/  
  
  
  
--Update fields from CaseNBCCSelection  
  
  
  
--Update fields from DropLists  
  
  
  
  
--select * from mstt_CaseCheck  
  
--select * from mstt_CaseNBCCSelection  
  
--select * from msit_CodeNBCCHeader  
  
  
end

GO
