  insert into msdt_CommissionBasis (CommissionBasisId, CommissionBasisCode,CommissionBasisDescription) 
  values           (-99, 'UNK', 'Unknown')
  SET IDENTITY_INSERT msdt_CommissionBasis OFF
 end 

