exec msp_ProcessLog 'COM', 'Populate #CommAgents', null, 'COM', 'Openwork'

select  ca.Agent_Code,
  ca.TranDateTruncated,
  Coalesce(ah.FranchiseCode, 
    ah.OfficeCode, 
    ah.DirectlyAuthorisedCode, 
    ah.StrategicAllianceCode, 
    ah.AccessAgentCode) FirmCode,
  ah.FranchiseSize,
  ah.Manager3Code,
