    ON [dbo].[mstt_Commissions]([AGENT_CODE]) 
  WITH (DATA_COMPRESSION=PAGE) ON [PRIMARY]

  CREATE INDEX [IX_mstt_Commissions_PolicyID] 
    ON [dbo].[mstt_Commissions]([PolicyID]) 
