  /* --SR9(3) :MPC 22/04/08
  CREATE INDEX [IX_mstt_Commissions_Multiple] 
    ON [dbo].[mstt_Commissions]([PolicyID], [AGENT_CODE], [CommissionType]) 
  WITH FILLFACTOR = 80 ON [PRIMARY]

  CREATE INDEX [IX_mstt_Commissions_Trial1] 
    ON [dbo].[mstt_Commissions]([TransactionID], [CommissionType], [GrossOrNet], [FixedAmount]) 
  WITH FILLFACTOR = 80 ON [PRIMARY]

  CREATE INDEX [IX_mstt_Commissions_Trial2] 
    ON [dbo].[mstt_Commissions]([TransactionID], [CommissionType], [FixedAmount]) 
  WITH FILLFACTOR = 80 ON [PRIMARY]

