/*********************************************************************************************************

-- Object  : procedure
-- Name    : mstp_Commissions.sql
-- Owner   : CTT
-- Created : 26/10/2005
--
-- Call as 
--  mstp_Commissions 'Openwork', 'Open Access','MOVE'
-- OR
--  mstp_Commissions 'Openwork', 'Open Access','FULL'
--

Copyright (C) Moore Stephens Consulting Limited 2005

Date    Amended By  Change Details
========  ==========  ==============
16/01/08  M Cawood  Ensure APE and Turnover are positive on Splits

13/02/08  A Groves  Performance Improvements:
          1) Moved a number of updates into the insert
          2) If AdminMethod is changed to 'A' then AdminMethodDescription is also changed.
          3) Indexes dropped before final INSERT into mstt_Commissions then re-created. 
             This will improve INSERT speed and re-calc index statistics.
          4) Added TransactionDateTrunc to #mstt_Commissions to enable index to be used 
             when updating Agent History.

        Bug fix: Join mstt_CommTranInitialDate on ID not TransactionID (TransactionMonth).

22/04/08  M Cawood  SR9 Changes to derivation of FIRM
          1) Only use Valid TASHH records to derive Firm
          2) If no Valid TASHH apply Firm from AgentHierarchy with default of mstt_Agents.Firm
          3) Performance improvements

18/09/09  M Cawood  SR10 Changes - new OBP OriginatingSource codes
          1) Set Description to SWIFT msit_CodeOriginatingSources.CODE

25/01/10  M Cawood  Performance Improvements

  1) Use parameters to call Process Log displaying row counts where relevant.
  2) Replace msit_S_AGTCOM by sa_swift_S_AGTCOM.
  3) Replace msit_transagentsplithierarchyhistory by mstt_transagentsplithierarchyhistory.
  4) Replace msit_AgentHierarchyHistory by sa_swift_AgentHierarchyHistory.
  5) Performance Improvements. New Run Control parameter @mode added with two settings:

    'FULL': This triggers the full refresh of the mstt_Commissions table using the
        primary keys held on the owt_TransformationMovements table. All existing rows 
        are deleted. The load table indexes are dropped and recreated after the insert.

    'MOVE': In this mode only those rows that are linked to daily movements of the Driver
        sa_swift_S_AGTCOM table are processed. The primary keys of these movements 
        are held on the owt_TransformationMovements table with DriverTableName of
        'sa_swift_S_AGTCOM'. All mstt_Commission rows with whose ID matches to a primary 
        key held on the movements table are deleted and then inserted from the new data 
        generated by the procedure. Indexes are not dropped/created in this mode.

30/03/2010  A Groves  Use flag owt_TransformationMovements.CommissionSplits to minimise the
            number of rows to process.

02/07/2010  M Cawood    Replace mstt_transagentsplithierarchyhistory by 
                        sa_swift_transagentsplithierarchyhistory.

*************************************************************************************************************/
CREATE PROCEDURE [dbo].[mstp_Commissions_20180105AG]
  @Client   varchar(50),            --MPC:25/01/2010
  @Module   varchar(50),            --MPC:25/01/2010
  @Mode   varchar(4)    --'FULL' or 'MOVE'  --MPC:25/01/2010

AS

--MPC:25/01/2010 New ProcessLog Start
declare   @PhaseStart     varchar(50),
      @PhaseEnd     varchar(50),
      @ProcName     varchar(100),
      @ProgressModule   varchar(50),
      @RowCount     int,
      @ProcessMessage   varchar(100)

set @ProcName   = object_name(@@procid) + ' - ' + @Mode
set @PhaseStart   = 'START'
set @PhaseEnd   = 'END'
set @ProgressModule = 'COM'

exec msp_ProcessLog @PhaseStart, @ProcName, null, @Module, @Client
--exec msp_ProcessLog 'COM', 'Start', null, 'COM', 'Openwork'

--MPC:25/01/2010 New ProcessLog End

--MPC:25/01/2010 New Movements Processing - START
/******************************************************************************************************************
    DERIVE MOVEMENTS
******************************************************************************************************************/
CREATE TABLE #AGTCOMChanges (ID int)
CREATE INDEX #X ON #AGTCOMCHANGES (ID)

CREATE TABLE #TASHHChanges (ID int)
CREATE INDEX #X ON #TASHHCHANGES (ID)

IF @Mode = 'FULL' --FULL Reload of Table
BEGIN

  Insert INTO #AGTCOMCHANGES
  Select Distinct ID 
  from sa_swift_S_AGTCOM 

  select @RowCount = @@rowcount
  set @ProcessMessage = @Mode + ' - Identify S_AGTCOM Movements : Count = ' + convert(varchar(10), @RowCount)   
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client

  Insert INTO #TASHHCHANGES
  Select Distinct ID 
  from sa_swift_TransAgentSplitHierarchyHistory     --MPC 02/07/2010

  select @RowCount = @@rowcount
  set @ProcessMessage =  @Mode + ' - Identify TASHH Movements : Count = ' + convert(varchar(10), @RowCount)   
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client

END --@Mode = 'FULL'

IF @Mode = 'MOVE' --Process Movements only
BEGIN

  Insert  INTO #AGTCOMCHANGES
  Select  DISTINCT PKID as ID
  FROM  owt_TransformationMovements
  Where DriverTableName = 'sa_swift_S_AGTCOM'
  and   CommissionSplits = 'Y'            -- AG 30/03/2010

  select @RowCount = @@rowcount
  set @ProcessMessage = @Mode + ' - Identify S_AGTCOM Movements : Count = ' + convert(varchar(10), @RowCount)   
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client

  Insert  INTO #TASHHCHANGES
  Select  DISTINCT PKID as ID
  FROM  owt_TransformationMovements
  Where DriverTableName = 'sa_swift_TransAgentSplitHierarchyHistory'    --MPC 02/07/2010
  and   CommissionSplits = 'Y'            -- AG 30/03/2010

  select @RowCount = @@rowcount
  set @ProcessMessage = @Mode + ' - Identify TASHH Movements : Count = ' + convert(varchar(10), @RowCount)    
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client

END   --@Mode = 'MOVE'
--MPC:25/01/2010 New Movements Processing - END

--START of SR9(1) :MPC 22/04/08
select TASHH.ID,
case 
when (franchiseagentcode is null and accessagentcode is null and directlyauthorisedagentcode is null) then 'E01'
when (franchiseagentcode is not null and accessagentcode is not null) then 'E02'
when (franchiseagentcode is not null and directlyauthorisedagentcode is not null) then 'E03'
when (accessagentcode is not null and directlyauthorisedagentcode is not null) then 'E04'
when (franchiseagentcode is not null and franchiseagentcode not in (select code from mstt_agents where agenttype = 2) ) then 'E05'
when (accessagentcode is not null and accessagentcode not in (select code from mstt_agents where agenttype = 46) ) then 'E06'
when (directlyauthorisedagentcode is not null and directlyauthorisedagentcode not in (select code from mstt_agents where agenttype = 49) ) then 'E07'
when (manager2code is null or manager2code not in (select code from mstt_agents where agenttype = 53) ) then 'E08'
when (organisationagentcode is null or organisationagentcode not in (select code from mstt_agents where agenttype = 19) ) then 'E09'
when (companyagentcode is null or companyagentcode not in (select code from mstt_agents where agenttype = 42) ) then 'E10'
end as ErrCode
into #InvalidTASHH
from sa_swift_transagentsplithierarchyhistory TASHH --MPC:25/01/2010
inner join #TASHHCHANGES X ON X.ID = TASHH.ID     --MPC:25/01/2010
where ACTIVE = 1 and ( 
   (franchiseagentcode is null and accessagentcode is null and directlyauthorisedagentcode is null)
or (franchiseagentcode is not null and accessagentcode is not null) 
or (franchiseagentcode is not null and directlyauthorisedagentcode is not null) 
or (accessagentcode is not null and directlyauthorisedagentcode is not null)
or (franchiseagentcode is not null and franchiseagentcode not in (select code from mstt_agents where agenttype = 2) )
or (accessagentcode is not null and accessagentcode not in (select code from mstt_agents where agenttype = 46) )
or (directlyauthorisedagentcode is not null and directlyauthorisedagentcode not in (select code from mstt_agents where agenttype = 49) )
or (manager2code is null or manager2code not in (select code from mstt_agents where agenttype = 53) )
or (organisationagentcode is null or organisationagentcode not in (select code from mstt_agents where agenttype = 19) )
or (companyagentcode is null or companyagentcode not in (select code from mstt_agents where agenttype = 42) )
)
order by TASHH.ID

select @RowCount = @@rowcount     --MPC:25/01/2010
set @ProcessMessage = @Mode + ' - Invalid TASHH : Count = ' + convert(varchar(10), @RowCount) --MPC:25/01/2010  
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client  --MPC:25/01/2010

create clustered index idx_ID on #InvalidTASHH(ID)

-- END of SR9(1)  :MPC 22/04/08

select *, TransactionDate as TransactionDateTrunc 
into #mstt_Commissions from mstt_Commissions 
WHERE 1=0

--Get the data from the Import Table
insert into #mstt_Commissions
  (
  AGENT_CODE, 
  AGENT_PERC, 
  ID, 
  CommissionType, 
  CommissionTypeDesc, 
  BasedOn, 
  BasedOnDesc,  
  FixedAmount, 
  PaymentBasis, 
  GrossOrNet, 
  PolicyID, 
  ProductCode, 
  CLIENT_NUM, 
  JOINT_NUM, 
  TransactionID, 
  TransactionDate,
  TransactionDateTrunc, 
  TransactionWrittenDate, 
  PolTranTransactionDate,
  PolTranTransactionWrittenDate,
  PolTranTransType, 
  ProposalDate,
  APE, 
  SplitMargin,
  CodeCommissionShapeID,
  AdminMethod,
  AdminMethodDescription,
  BusinessReason,
  BusinessReasonDescription,
  Frequency,
  CommType,
  OriginatingSource,
  OriginatingSourceDescription,
  FranchiseUpliftPercent, 
  BaseAmount, 
  UpliftAmount, 
  StrategicAllianceAgentCode, 
  AccessAgentCode, 
  FranchiseAgentCode, 
  CompanyAgentCode, 
  OrganisationAgentCode, 
  DirectlyAuthorisedAgentCode, 
  Manager1Code, 
  Manager2Code, 
  Manager3Code, 
  Manager4Code, 
  FranchiseSize, 
  PracticeTypeCode,
  ProductType,
  ReportingProductCode,
  ProductSubGroupCode,
  ProductGroupCode,
  ProductCategoryCode,
  ProductProviderCode,
  ReportingProductProviderCode,
  CommRepProductProviderCode,
  Firm,
  CommissionMonth,
  IssuedDate,
  TransactionMonth
  )
select 
  a.AGENT_CODE, 
  a.AGENT_PERC, 
  a.ID, 
  a.CommissionType, 
  (select dl.Description            --CommissionTypeDesc 
   from msdt_DropLists dl
   where  convert(varchar(50),a.CommissionType) = dl.Code 
   and  dl.CodeType = 'CommissionType'), 
  a.BasedOn, 
  (select dl.Description            --BasedOnDesc 
   from msdt_DropLists dl
   where  convert(varchar(50),a.BasedOn) = dl.Code  
   and  dl.CodeType = 'CommissionBasedOn'),
  a.FixedAmount, 
  a.PaymentBasis, 
  a.GrossOrNet, 
  pt.PolicyID as PolicyID,                    --From mstt_PolicyTransactions, linked via TransactionID 
  coalesce(pt.CommProductCode, p.ProductCode) as ProductCode, --From mstt_Policies, linked via PolicyID
  p.CLIENT_NUM as CLIENT_NUM,                 --From mstt_Policies, linked via PolicyID
  p.JOINT_NUM as JOINT_NUM,                   --From mstt_Policies, linked via PolicyID
  a.TransactionID, 
  CommTranInitDate.TransactionDate as TransactionDate, --From mstt_CommTranInitialDate: CR 58 
  dateadd(d, 0, datediff(d, 0, CommTranInitDate.TransactionDate)) as TransactionDateTrunc,
  case pt.TransType             --TransactionDateTrunc has time element set to zero
     when 39 then CommTranInitDate.TransactionDate
     else pt.WrittenDate          --SR9(3) :MPC 22/04/08
  end as TransactionWrittenDate,              --From mstt_CommTranInitialDate: CR 58
  pt.TransactionDate as PolTranTransactionDate, --From mstt_PolicyTransactions, linked via TransactionID - CR 58
  pt.TransactionWrittenDate as PolTranTransactionWrittenDate, --From mstt_PolicyTransactions, linked via TransactionID - CR 58
  pt.TransType as PolTranTransType,           --From mstt_PolicyTransactions, linked via TransactionID 
  pt.ProposalDate as ProposalDate,            --From mstt_PolicyTransactions, linked via TransactionID 
  abs(pt.APE * (a.AGENT_PERC / 100)) as APE,  --From mstt_PolicyTransactions, linked via TransactionID :MPC 16/01/08
  null as SplitMargin,                        --Derived below
  pt.CodeCommissionShapeID as CodeCommissionShapeID, --From mstt_PolicyTransactions, linked via TransactionID 
  coalesce(pt.AdminMethod, 'A') as AdminMethod, --From mstt_PolicyTransactions, linked via TransactionID
              --ID262 - Set null AdminMethod to 'A' so that it is included as New Business
  (select dl.Description      --AdminMethodDescription
   from msdt_DropLists dl
   where  coalesce(pt.AdminMethod, 'A') = dl.Code 
   and  dl.CodeType = 'AdminMethod'),     
--  MICodesAndDescs.Description as BusinessReason, --From msit_MIWarehouseCodesAndDescriptions
  (Select Description from msit_MIWarehouseCodesAndDescriptions 
  where ColumnName = 'WH-AdminMethod' and Code = coalesce(pt.AdminMethod, 'A')) as BusinessReason,  --SR9(3) :MPC 22/04/08
--  MICodesAndDescs.LongDescription as BusinessReasonDescription, --From msit_MIWarehouseCodesAndDescriptions
  (Select LongDescription from msit_MIWarehouseCodesAndDescriptions 
  where ColumnName = 'WH-AdminMethod' and Code = coalesce(pt.AdminMethod, 'A')) as BusinessReasonDescription, --SR9(3) :MPC 22/04/08
  pt.Frequency as Frequency,                  --From mstt_PolicyTransactions, linked via TransactionID 
  pt.CommType as CommType,                    --From mstt_PolicyTransactions, linked via TransactionID 
  p.OriginatingSource as OriginatingSource,   --From mstt_Policies, linked via PolicyID 
--  (select dl.Description            --OriginatingSourceDescription    --SR10(1) : MPC 18/09/09
--   from msdt_DropLists dl                           --SR10(1) : MPC 18/09/09
--   where  convert(varchar(50),p.OriginatingSource) = dl.Code            --SR10(1) : MPC 18/09/09
--   and  dl.CodeType = 'OriginatingSource'),                   --SR10(1) : MPC 18/09/09
  CASE                    --SR10(1) : MPC 18/09/09
    WHEN OS.ID is not NULL THEN OS.Code   --SR10(1) : MPC 18/09/09
    ELSE 'Unknown'              --SR10(1) : MPC 18/09/09
  END,  --OriginatingSourceDescription    --SR10(1) : MPC 18/09/09
  a.FranchiseUpliftPercent, 
  a.BaseAmount, 
  a.UpliftAmount,
  tashh.StrategicAllianceAgentCode as StrategicAllianceAgentCode, --From sa_swift_TransAgentSplitHierarchyHistory, join on AgentCode, TransactionID, CommissionType
  tashh.AccessAgentCode as AccessAgentCode,   --From sa_swift_TransAgentSplitHierarchyHistory, join on AgentCode, TransactionID, CommissionType
  tashh.FranchiseAgentCode as FranchiseAgentCode, --From sa_swift_TransAgentSplitHierarchyHistory, join on AgentCode, TransactionID, CommissionType
  tashh.CompanyAgentCode as CompanyAgentCode, --From sa_swift_TransAgentSplitHierarchyHistory, join on AgentCode, TransactionID, CommissionType
  null as OrganisationAgentCode,              --From sa_swift_TransAgentSplitHierarchyHistory, join on AgentCode, TransactionID, CommissionType
  tashh.DirectlyAuthorisedAgentCode as DirectlyAuthorisedAgentCode, --From sa_swift_TransAgentSplitHierarchyHistory, join on AgentCode, TransactionID, CommissionType
  tashh.Manager1Code as Manager1Code,         --From sa_swift_TransAgentSplitHierarchyHistory, join on AgentCode, TransactionID, CommissionType
  tashh.Manager2Code as Manager2Code,         --From sa_swift_TransAgentSplitHierarchyHistory, join on AgentCode, TransactionID, CommissionType
  ag.Manager3Code,    --SR9(3) :MPC 22/04/08   --From mstt_AgentsHistory, joining on AgentCode and TransactionDate between ValidFromDate and ValidToDate
  ag.Manager4Code,    --SR9(3) :MPC 22/04/08   --From mstt_AgentsHistory, joining on AgentCode and TransactionDate between ValidFromDate and ValidToDate
  ag.FranchiseSize,   --SR9(3) :MPC 22/04/08   --From mstt_AgentsHistory, joining on AgentCode and TransactionDate between ValidFromDate and ValidToDate
  ag.PracticeTypeCode,    --SR9(3) :MPC 22/04/08   --From mstt_AgentsHistory, joining on AgentCode and TransactionDate between ValidFromDate and ValidToDate
  ph.ProductType as ProductType,              --From mstt_ProductHierarchy, joining on ProductCode
  ph.ReportingProductCode as ReportingProductCode, --From mstt_ProductHierarchy, joining on ProductCode
  ph.ProductSubGroupCode as ProductSubGroupCode, --From mstt_ProductHierarchy, joining on ProductCode
  ph.ProductGroupCode as ProductGroupCode,    --From mstt_ProductHierarchy, joining on ProductCode
  ph.ProductCategoryCode as ProductCategoryCode, --From mstt_ProductHierarchy, joining on ProductCode
  ph.ProductProviderCode as ProductProviderCode, --From mstt_ProductHierarchy, joining on ProductCode
  ph.ReportingProductProviderCode as ReportingProductProviderCode, --From mstt_ProductHierarchy, joining on ProductCode
  ph.CommRepProductProviderCode as CommRepProductProviderCode, --From mstt_ProductHierarchy, joining on ProductCode
/*  
--START of SR9(2) :MPC 22/04/08
  (select Coalesce(tashh.FranchiseAgentCode,  --Firm 
           tashh.AccessAgentCode, 
           tashh.DirectlyAuthorisedAgentCode, 
           tashh.StrategicAllianceAgentCode)
   from   mstt_Agents agents
   where  Coalesce(tashh.FranchiseAgentCode, 
           tashh.AccessAgentCode, 
           tashh.DirectlyAuthorisedAgentCode, 
           tashh.StrategicAllianceAgentCode) = agents.Code
   and  agents.AgentType in (2,46,49)),
*/  
  CASE
  when ag.agenttype in (2,46,49,52,53,54,55) then a.agent_code
  when tashh.id is not null and t1.id is null 
  then Coalesce(tashh.FranchiseAgentCode, tashh.AccessAgentCode, tashh.DirectlyAuthorisedAgentCode, tashh.StrategicAllianceAgentCode)
  end as FIRM,
--END of SR9(2) :MPC 22/04/08
--  ptm.MinMonth, --CommissionMonth  ID19   --SR9(3) :MPC 22/04/08
  pt.CommissionMonth,       --SR9(3) :MPC 22/04/08
  pt.IssuedDate,          --SR9(3) :MPC 22/04/08
  pt.CommissionMonth as TransactionMonth    --SR9(3) :MPC 22/04/08
from sa_swift_S_AGTCOM a      --MPC:25/01/2010
  inner join #AGTCOMCHANGES X ON X.ID = A.ID    --MPC:25/01/2010
  left outer join mstt_PolicyTransactions pt on a.TransactionID = pt.ID
  left outer join mstt_CommTranInitialDate CommTranInitDate on a.ID = CommTranInitDate.ID
  left outer join mstt_agents ag on ag.code = a.agent_code  --SR9(2)
--  left outer join (select PolTrnMinCommMth.ID, min(PolTrnMinCommMth.CommissionMonth) MinMonth --SR9(3) :MPC 22/04/08
--        from   mstt_PolicyTransactions PolTrnMinCommMth         --SR9(3) :MPC 22/04/08
--        group  by PolTrnMinCommMth.ID) ptm on a.TransactionID = ptm.ID    --SR9(3) :MPC 22/04/08
  left outer join mstt_Policies p on pt.PolicyID = p.POL_NUM
  left outer join sa_swift_TransAgentSplitHierarchyHistory tashh    --MPC 02/07/2010
       on a.Agent_Code  = tashh.AgentCode
      and a.TransactionID   = tashh.TransactionID
      and a.CommissionType  = tashh.CommissionType
      and tashh.Active  = 1               
  left outer join #InvalidTASHH t1 on t1.ID = tashh.ID    --SR9(2)
  left outer join mstt_ProductHierarchy ph on coalesce(pt.CommProductCode, p.ProductCode) = ph.ProductCode
  left outer join msit_CodeOriginatingSources OS on OS.ID = p.OriginatingSource --SR10(1) : MPC 18/09/09
--  left outer join msit_MIWarehouseCodesAndDescriptions MICodesAndDescs    --SR9(3) :MPC 22/04/08
--       on MICodesAndDescs.ColumnName = 'WH-AdminMethod'     --SR9(3) :MPC 22/04/08
--      and MICodesAndDescs.Code = coalesce(pt.AdminMethod, 'A')  --SR9(3) :MPC 22/04/08

select @RowCount = @@rowcount     --MPC:25/01/2010
set @ProcessMessage = @Mode + ' - Select from sa_swift_S_AGTCOM : Count = ' + convert(varchar(10), @RowCount) --MPC:25/01/2010  
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client  --MPC:25/01/2010

