--Get the AgentsHistory Data
update c
set   Manager3Code     = ca2.Manager3Code,  
  Manager4Code     = ca2.Manager4Code,  
  FranchiseSize  = ca2.FranchiseSize,   -- Agent level  
  PracticeTypeCode = ca2.PracticeTypeCode
from #mstt_Commissions c
  inner join #CommAgents2 ca2 on c.Agent_Code = ca2.Agent_Code 
where c.TransactionDateTrunc = ca2.TranDateTruncated
      
exec msp_ProcessLog 'COM', 'update from agents history', null, 'COM', 'Openwork'      

--Get the AgentsHistory Data for Franchise Size, where the Seller is below franchise Level

update c
set FranchiseSize = fah.FranchiseSize   -- Franchise, Access or DA level
from  #mstt_Commissions c
    inner join mstt_AgentsHistory fah on c.Firm = fah.Code 
    and c.TransactionDateTrunc between fah.ValidFromDate and fah.ValidToDate
where isnull(fah.FranchiseSize,0) = 0
and   fah.AgentType in (2,46,49)      

exec msp_ProcessLog 'COM', 'update franchiseSize from fran level', null, 'COM', 'Openwork'      
      
drop table #CommAgents
drop table #CommAgents2

exec msp_ProcessLog 'COM', 'DROP #CommAgents tables', null, 'COM', 'Openwork' 
*/ --SR9(3) :MPC 22/04/08

--Set the SplitMargin
select isnull(TransactionID, -99) as TransactionId, sum(FixedAmount) as Margin
into #Margins
from #mstt_Commissions
where GrossOrNet = 'N'
and FixedAmount <> 0
and CommissionType = 1  --MPC:25/01/10
group by TransactionID

exec msp_ProcessLog @PhaseEnd, 'get #Margins', null, @ProgressModule, @Client

alter table #Margins add constraint PK_Margins PRIMARY KEY (TransactionID) 

exec msp_ProcessLog @PhaseEnd, 'pk on #margins', null, @ProgressModule, @Client

--SR9(3) Start  :MPC 22/04/08
update c
set SplitMargin = case when c.GrossOrNet = 'G' then isnull(m.Margin,0) * (c.Agent_Perc / 100) else 0.0 end, 
    SalesMargin = case when c.GrossOrNet = 'G' then isnull(m.Margin,0) * (c.Agent_Perc / 100) else 0.0 end, 
    DistributionAllowance = case when c.GrossOrNet = 'G' then isnull(FixedAmount,0) + (isnull(m.Margin,0) * (c.Agent_Perc / 100)) else 0.0 end, --SR9(3)
    Turnover = case                       
    when c.GrossOrNet = 'G' and isnull(p.APE_Flag,'N') <> 'Y' then abs( isnull(FixedAmount,0) + (isnull(m.Margin,0) * (c.Agent_Perc / 100)) )         
    when c.GrossOrNet = 'G' and isnull(p.APE_Flag,'N') = 'Y' then abs(c.APE)              
    else 0.0
    end,
    APE = case when c.GrossOrNet = 'G' and isnull(p.APE_Flag,'N') = 'Y' then abs(c.APE) else 0.0 end
from #mstt_Commissions c
left outer join #Margins m on c.TransactionID = m.TransactionID 
left outer join mstt_ProductHierarchy p on c.ProductCode = p.ProductCode
where CommissionType = 1  --MPC:27/01/10
--where c.GrossOrNet = 'G'
--SR9(3) End  :MPC 22/04/08

exec msp_ProcessLog @PhaseEnd, 'Update Measures', null, @ProgressModule, @Client  --SR9(3) :MPC 22/04/08

drop table #Margins

/* --SR9(3) :MPC 22/04/08
--Set the Distribution Allowance field and SalesMargin Field
update c
set DistributionAllowance = isnull(FixedAmount,0) + isnull(SplitMargin,0),
  SalesMargin = SplitMargin
from #mstt_Commissions c

exec msp_ProcessLog 'COM', 'update DistAllow', null, 'COM', 'Openwork'

--Set the Turnover field
update c
set Turnover = case 
    when p.APE_Flag <> 'Y' then abs(DistributionAllowance)  --Mortgages and GI :MPC 16/01/08
    when p.APE_Flag = 'Y' then abs(APE)     --Non-Mortgages and GI :MPC 16/01/08
    end
from #mstt_Commissions c inner join mstt_ProductHierarchy p on c.ProductCode = p.ProductCode

exec msp_ProcessLog 'COM', 'update turnover 1+2', null, 'COM', 'Openwork'

--'Clean up' several fields for 'Margin' (ie 'NET') records.
update c
set APE = 0,
  DistributionAllowance = 0,
  SalesMargin = 0,
  SplitMargin = 0,
  Turnover = 0
from #mstt_Commissions c
where c.GrossOrNet = 'N'

exec msp_ProcessLog 'COM', 'clean up', null, 'COM', 'Openwork'
*/ --SR9(3) :MPC 22/04/08


/* --SR9(3) :MPC 22/04/08
--IssuedDate ID19

Update c
  set IssuedDate = MTD.MinTransactionDate
from (Select TransactionID, min(TransactionDate) as MinTransactionDate
    from #mstt_Commissions
    Group by TransactionID) MTD
  inner join mstt_PolicyTransactions pt on MTD.TransactionID = pt.IssuedTranID
  inner join #mstt_Commissions c on c.TransactionID = MTD.TransactionID
  
exec msp_ProcessLog 'COM', 'update Issued Date', null, 'COM', 'Openwork'
*/ --SR9(3) :MPC 22/04/08


/************************************************************************************************
  PERFORM DATABASE UPDATES
************************************************************************************************/

--Full Refresh - Truncate Table, Drop Indexes, Insert then Create Undexes
IF @Mode = 'FULL' --MPC:25/01/2010
BEGIN       --MPC:25/01/2010

  --Clear the target table first
  Truncate Table mstt_Commissions

  DROP INDEX mstt_Commissions.IX_mstt_Commissions_Agent_Code 
  DROP INDEX mstt_Commissions.IX_mstt_Commissions_PolicyID 
  DROP INDEX mstt_Commissions.IX_mstt_Commissions_TransactionID
  --DROP INDEX mstt_Commissions.IX_mstt_Commissions_Multiple    --SR9(3) :MPC 22/04/08
  --DROP INDEX mstt_Commissions.IX_mstt_Commissions_Trial1    --SR9(3) :MPC 22/04/08
  --DROP INDEX mstt_Commissions.IX_mstt_Commissions_Trial2    --SR9(3) :MPC 22/04/08
  --DROP INDEX mstt_Commissions.IX_mstt_Commissions_written   --SR9(3) :MPC 22/04/08
  DROP INDEX mstt_Commissions.PKmstt_Commissions        -- Clustered must be dropped last

  exec msp_ProcessLog @PhaseEnd, 'Indexes DROPPED', null, @ProgressModule, @Client

END --  @Mode = 'FULL'      --MPC:25/01/2010

--Delete existing rows in Movements List then Insert new Movements
IF @Mode = 'MOVE'   --MPC:25/01/2010
BEGIN         --MPC:25/01/2010

  --DELETE Movements only
  DELETE FROM mstt_Commissions      --MPC:25/01/2010
  WHERE ID IN (Select ID From #AGTCOMChanges)   --MPC:25/01/2010

  select @RowCount = @@rowcount   --MPC:25/01/2010
  set @ProcessMessage = @Mode + ' - Delete Data : Count = ' + convert(varchar(10), @RowCount)   --MPC:25/01/2010
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client  --MPC:25/01/2010

END --@Mode = 'MOVE'    --MPC:25/01/2010

--INSERT Rows from #Table
INSERT into mstt_Commissions
(
  AGENT_CODE,
  AGENT_PERC,
  ID,
  CommissionType,
  CommissionTypeDesc,
  BasedOn,
  BasedOnDesc,
  FixedAmount,
  PaymentBasis,
  GrossOrNet,
  PolicyID,
  ProductCode,
  CLIENT_NUM,
  JOINT_NUM,
  TransactionID,
  TransactionDate,
  TransactionWrittenDate,
  PolTranTransactionDate,
  PolTranTransactionWrittenDate,
  PolTranTransType,
  ProposalDate,
  APE,
  Turnover,
  DistributionAllowance,
  SplitMargin,
  SalesMargin,
  CodeCommissionShapeID,
  AdminMethod,
  AdminMethodDescription,
  BusinessReason,
  BusinessReasonDescription,
  Frequency,
  CommType,
  OriginatingSource,
  OriginatingSourceDescription,
  FranchiseUpliftPercent,
  BaseAmount,
  UpliftAmount,
  StrategicAllianceAgentCode,
  AccessAgentCode,
  FranchiseAgentCode,
  CompanyAgentCode,
  OrganisationAgentCode,
  DirectlyAuthorisedAgentCode,
  Manager1Code,
  Manager2Code,
  Manager3Code,
  Manager4Code,
  FranchiseSize,
  PracticeTypeCode,
  ProductType,
  ReportingProductCode,
  ProductSubGroupCode,
  ProductGroupCode,
  ProductCategoryCode,
  ProductProviderCode,
  ReportingProductProviderCode,
  CommRepProductProviderCode,
  Firm,
  CommissionMonth,
  IssuedDate,
  TransactionMonth
)
SELECT  AGENT_CODE,
    AGENT_PERC,
    ID,
    CommissionType,
    CommissionTypeDesc,
    BasedOn,
    BasedOnDesc,
    FixedAmount,
    PaymentBasis,
    GrossOrNet,
    PolicyID,
    ProductCode,
    CLIENT_NUM,
    JOINT_NUM,
    TransactionID,
    TransactionDate,
    TransactionWrittenDate,
    PolTranTransactionDate,
    PolTranTransactionWrittenDate,
    PolTranTransType,
    ProposalDate,
    APE,
    Turnover,
    DistributionAllowance,
    SplitMargin,
    SalesMargin,
    CodeCommissionShapeID,
    AdminMethod,
    AdminMethodDescription,
    BusinessReason,
    BusinessReasonDescription,
    Frequency,
    CommType,
    OriginatingSource,
    OriginatingSourceDescription,
    FranchiseUpliftPercent,
    BaseAmount,
    UpliftAmount,
    StrategicAllianceAgentCode,
    AccessAgentCode,
    FranchiseAgentCode,
    CompanyAgentCode,
    OrganisationAgentCode,
    DirectlyAuthorisedAgentCode,
    Manager1Code,
    Manager2Code,
    Manager3Code,
    Manager4Code,
    FranchiseSize,
    PracticeTypeCode,
    ProductType,
    ReportingProductCode,
    ProductSubGroupCode,
    ProductGroupCode,
    ProductCategoryCode,
    ProductProviderCode,
    ReportingProductProviderCode,
    CommRepProductProviderCode,
    Firm,
    CommissionMonth,
    IssuedDate,
    TransactionMonth
from  #mstt_Commissions 

select @RowCount = @@rowcount       --MPC:25/01/2010
set @ProcessMessage = @Mode + ' - mstt_Commissions INSERTED : Count = ' + convert(varchar(10), @RowCount) --MPC:25/01/2010
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client    --MPC:25/01/2010

IF @Mode = 'FULL' --MPC:25/01/2010
BEGIN       --MPC:25/01/2010

  CREATE UNIQUE CLUSTERED INDEX [PKmstt_Commissions]      -- Clustered must be created first
    ON [dbo].[mstt_Commissions]([ID]) 
  WITH FILLFACTOR = 80 ON [PRIMARY]

  CREATE INDEX [IX_mstt_Commissions_Agent_Code] 
    ON [dbo].[mstt_Commissions]([AGENT_CODE]) 
  WITH FILLFACTOR = 80 ON [PRIMARY]

  CREATE INDEX [IX_mstt_Commissions_PolicyID] 
    ON [dbo].[mstt_Commissions]([PolicyID]) 
  WITH FILLFACTOR = 80 ON [PRIMARY]

  CREATE INDEX [IX_mstt_Commissions_TransactionID] 
    ON [dbo].[mstt_Commissions]([TransactionID]) 
  WITH FILLFACTOR = 80 ON [PRIMARY]

  /* --SR9(3) :MPC 22/04/08
  CREATE INDEX [IX_mstt_Commissions_Multiple] 
    ON [dbo].[mstt_Commissions]([PolicyID], [AGENT_CODE], [CommissionType]) 
  WITH FILLFACTOR = 80 ON [PRIMARY]

  CREATE INDEX [IX_mstt_Commissions_Trial1] 
    ON [dbo].[mstt_Commissions]([TransactionID], [CommissionType], [GrossOrNet], [FixedAmount]) 
  WITH FILLFACTOR = 80 ON [PRIMARY]

  CREATE INDEX [IX_mstt_Commissions_Trial2] 
    ON [dbo].[mstt_Commissions]([TransactionID], [CommissionType], [FixedAmount]) 
  WITH FILLFACTOR = 80 ON [PRIMARY]

  CREATE INDEX [IX_mstt_Commissions_written] 
    ON [dbo].[mstt_Commissions]([Firm], [CommissionType], [PolTranTransType], [AGENT_CODE], 
         [TransactionDate], [ProductCode], [Turnover]) ON [PRIMARY]
  */--SR9(3) :MPC 22/04/08

  exec msp_ProcessLog @PhaseEnd, 'Indexes CREATED', null, @ProgressModule, @Client

  --MPC:25/01/2010  DatabaseUPDATE Changes - START

END --  @Mode = 'FULL'    

--Update FranchiseSize changes and perform Update Statistics
IF @Mode = 'MOVE'   
BEGIN

  --Apply any Enterprise Franchise Size changes detected on mstt_Agentshistory (to whole table)
  UPDATE mstt_Commissions
  Set FranchiseSize = B.FranchiseSize
  FROM mstt_Commissions COM
  inner Join 
  (select C.Code,C.FranchiseSize
  from mstt_Agentshistory C
  inner join (Select Code,max(validfromdate) as LastRow from mstt_Agentshistory
        WHERE agenttype in (2,46,49) and validfromdate < DATEADD(day,DATEDIFF(day,0,getdate()),0)
        Group by CODE) A ON A.CODE = C.CODE
  inner join mstt_Agentshistory P ON A.CODE = P.CODE and A.LastRow = P.ValidFromDate
  where C.agenttype in (2,46,49) -- Businesses
  and C.validfromdate = DATEADD(day,DATEDIFF(day,0,getdate()),0)
  and C.FranchiseSize <> P.FranchiseSize) B ON B.CODE = COM.Agent_Code

  UPDATE STATISTICS mstt_Commissions

  set @ProcessMessage = @Mode + ' - Update Statistics'
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client

END --@Mode = 'MOVE'

--MPC:25/01/2010  DatabaseUPDATE Changes - END

/******************************************************************************************************************
    END of PROCESSING
******************************************************************************************************************/

--END
exec msp_ProcessLog @PhaseEnd, @ProcName, null, @Module, @Client    --MPC:25/01/2010





