CREATE PROCEDURE [dbo].[mstp_CommTranInitialDate] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

*******************************************************************************/


-- PROCEDURE BODY GOES HERE
begin

if (select count(*) from mstt_CommTranInitialDate) = 0 
--This suggests that the table has not been populated before, 
--which means we need to populate the table for old/existing transactions,
--using a 'best guess', and NOT getdate()-1, which we will be using
--in future.
--ID 19 changed the transaction date for new transactions to the min CreatedDateTime from msit_S_AGTCOM
  begin
    
    insert into mstt_CommTranInitialDate (ID, TransactionDate)
    select  ac.ID, 
      pt.CreateDateTime
    from msit_S_AGTCOM ac
      inner join msit_PolicyTransactions pt
        on ac.TransactionId = pt.ID

  end

else

  begin
    
    insert into mstt_CommTranInitialDate (ID, TransactionDate)
    select  ac.ID,
      min(ac.CreatedDateTime)
    from msit_S_AGTCOM ac
    where not exists (select 'x' from mstt_CommTranInitialDate citd
          where ac.ID = citd.ID)
    group by ac.ID

  end

end

