declare 
  @DefaultComparisonID int,
  @DefaultComparison   nvarchar(255)
set @DefaultComparisonID = (select convert(int,DefaultValue) from mstt_DefaultCodeValues where CodeColumn = 'ComparisonID')
set @DefaultComparison   = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'Comparison')
insert into msdt_Comparison (ComparisonID, Comparison) values (@DefaultComparisonID, @DefaultComparison)
SET IDENTITY_INSERT msdt_Comparison OFF
end
GRANT EXEC ON mstp_DefaultComparisonValues TO PUBLIC

