CREATE PROCEDURE [dbo].[mstp_Expectation]
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

Date      Amended By  Change Details
========  ==========  ==============
16/01/08  A Groves  Performance Improvements:
            1)  Dropped indexes prior to INSERT followed by INDEX CREATES
                which also updates stats to make following UPDATES faster.
            2)  Default IncomeRecognitionDate and CashReceivedDate populated
              by INSERT rather than separate UPDATE.  
            3)  IncomeRecognitionDate updated in 1 statement using a derived
              table rather than a temp table and 2 statements.
            4)  Added separate UPDATEs to initial INSERT where possible.
21/12/18  C Mellors  Performance Improvements:
            Complete redesign to incremental update
21/05/19  C Mellors  Moved initial hash generation into seperate SPs
*******************************************************************************/
BEGIN TRY
	DECLARE  @StartDate DATETIME
			,@EndDate DATETIME
			,@Now DATETIME = GETDATE()
			;

	SELECT	 @StartDate = MIN(PeriodStartDate)
			,@EndDate = MAX(PeriodEndDate)
	FROM	dbo.msit_CommissionStatementPeriods;

	CREATE TABLE #CommissionStatementPeriods
	(
	  [date]	DATETIME PRIMARY KEY, 
	  [month]	DATETIME		
	);

	CREATE TABLE #CommissionStatus
	(
	  [Status]	TINYINT PRIMARY KEY, 
	  [Description]	VARCHAR(50)		
	);

	CREATE TABLE #CommissionType
	(
	  [Type]	TINYINT PRIMARY KEY, 
	  [Description]	VARCHAR(50)		
	);

	EXEC dbo.msp_ProcessLog 'EXP', '00) Start Update mstt_Expectation', null, 'mstp_Expectation', 'Openwork';

	------------------------------------------------------------------------------------------------------------------
	/*
		1 - Generate New Hashes
	*/

	EXEC [Staging].[msit_CommissionStatementPeriods_Hash_Generation] @Mode = 'MOVE';
	EXEC [Staging].[msit_MIWarehouseCodesAndDescriptions_Hash_Generation] @Mode = 'MOVE';
	EXEC [Staging].[mstt_Policies_Hash_Generation] @Mode = 'MOVE';
	EXEC [Staging].[mstt_PolicyTransactions_Hash_Generation] @Mode = 'MOVE';
	EXEC [Staging].[mstt_ProductHierarchy_Hash_Generation] @Mode = 'MOVE';
	EXEC [Staging].[sa_swift_CodeUnallocatedReasons_Hash_Generation] @Mode = 'MOVE';
	EXEC [Staging].[sa_swift_EDIFACTCommissionStatementContents_Hash_Generation] @Mode = 'MOVE';
	EXEC [Staging].[sa_swift_EDIFACTCommissionStatementHeader_Hash_Generation] @Mode = 'MOVE';
	EXEC [Staging].[sa_swift_S_PACC_Hash_Generation] @Mode = 'MOVE';
	EXEC [Staging].[sa_swift_S_PACCSU_Hash_Generation] @Mode = 'MOVE';
	EXEC [Staging].[sa_swift_S_PACCUN_Hash_Generation] @Mode = 'MOVE';
	EXEC [Staging].[sa_swift_S_STMTCT_Hash_Generation] @Mode = 'MOVE';

	EXEC [dbo].[msp_ProcessLog] 'EXP', '01) End Generate New Hashes', null, 'mstp_Expectation', 'Openwork';

	------------------------------------------------------------------------------------------------------------------
	/*
		2 - Identify expectation movements
	*/

	-- Create Commission Statement Periods Lookup
	TRUNCATE TABLE #CommissionStatementPeriods;

	WITH theDates AS
	(
		SELECT	@StartDate AS theDate
		UNION ALL
		SELECT	DATEADD(DAY, 1, theDate)
		FROM	theDates
		WHERE	DATEADD(DAY, 1, theDate) <= @EndDate
	)
	INSERT #CommissionStatementPeriods([date],[month]) 
		SELECT	 theDate
				,csp.Month
		FROM	theDates
		JOIN	dbo.msit_CommissionStatementPeriods csp ON theDate BETWEEN csp.PeriodStartDate AND csp.PeriodEndDate
		WHERE	EXISTS	(
						SELECT	*
						FROM	Staging.msit_CommissionStatementPeriods_Hash_Movement m
						WHERE	m.Month = csp.Month
						)
		OPTION (MAXRECURSION 0);

	-- Create Commission Status Lookup
	TRUNCATE TABLE #CommissionStatus;

	INSERT #CommissionStatus([Status],[Description]) 
		SELECT	 CONVERT(TINYINT, cs.Code)
				,CONVERT(VARCHAR(50), COALESCE(cs.ShortDescription, cs.LongDescription, cs.Description))
		FROM	dbo.msit_MIWarehouseCodesAndDescriptions cs
		WHERE	cs.ColumnName = 'CommissionStatus'
		AND		EXISTS	(
						SELECT	*
						FROM	Staging.msit_MIWarehouseCodesAndDescriptions_Hash_Movement m
						WHERE	m.ColumnName = cs.ColumnName 
						AND		m.Code = cs.Code
						);

	-- Create Commission Type Lookup
	TRUNCATE TABLE #CommissionType;

	INSERT #CommissionType([Type],[Description]) 
		SELECT	 CONVERT(TINYINT, ct.Code)
				,CONVERT(VARCHAR(50), COALESCE(ct.ShortDescription, ct.LongDescription, ct.Description))
		FROM	dbo.msit_MIWarehouseCodesAndDescriptions ct
		WHERE	ct.ColumnName = 'CommissionType'
		AND		EXISTS	(
						SELECT	*
						FROM	Staging.msit_MIWarehouseCodesAndDescriptions_Hash_Movement m
						WHERE	m.ColumnName = ct.ColumnName 
						AND		m.Code = ct.Code
						);

	-- Identify Changes
	INSERT [Staging].[mstt_Expectation_Movement] ([ID])
		SELECT	ID
		FROM	Staging.sa_swift_S_PACC_Hash_Movement
		UNION
		SELECT	spacc.ID
		FROM	dbo.sa_swift_S_PACC spacc
		WHERE	EXISTS	(
						SELECT	*
						FROM	Staging.mstt_PolicyTransactions_Hash_Movement m
						WHERE	m.ID = spacc.TransactionID
						)
		UNION
		SELECT	spacc.ID
		FROM	dbo.sa_swift_S_PACC spacc
		JOIN	dbo.mstt_PolicyTransactions pt ON pt.ID = spacc.TransactionID
		WHERE	EXISTS	(
						SELECT	*
						FROM	Staging.mstt_Policies_Hash_Movement m
						WHERE	m.POL_NUM = pt.PolicyID
						)
		UNION
		SELECT	spacc.ID
		FROM	dbo.sa_swift_S_PACC spacc
		JOIN	dbo.mstt_PolicyTransactions pt ON pt.ID = spacc.TransactionID
		JOIN	dbo.mstt_Policies p on p.POL_NUM = pt.PolicyID
		WHERE	EXISTS	(
						SELECT	*
						FROM	Staging.mstt_ProductHierarchy_Hash_Movement m
						WHERE	m.ProductCode = ISNULL(pt.CommProductCode, p.ProductCode)
						)
		UNION
		SELECT	ID
		FROM	Staging.sa_swift_EDIFACTCommissionStatementHeader_Hash_Movement
		UNION
		SELECT	PACC_ID
		FROM	Staging.sa_swift_S_PACCUN_Hash_Movement
		UNION
		SELECT	SUSP_ID
		FROM	dbo.sa_swift_S_PACCSU paccsu
		WHERE	EXISTS	(
						SELECT	*
						FROM	Staging.sa_swift_S_PACCSU_Hash_Movement m
						WHERE	m.ID = paccsu.ID
						)
		UNION
		SELECT	spacc.ID
		FROM	dbo.sa_swift_S_PACC spacc
		WHERE	EXISTS	(
						SELECT	*
						FROM	Staging.sa_swift_CodeUnallocatedReasons_Hash_Movement m
						WHERE	m.Code = spacc.UnallocatedReasonCode
						)
		UNION
		SELECT	spacc.ID
		FROM	dbo.sa_swift_S_PACC spacc
		WHERE	EXISTS	(
						SELECT	*
						FROM	Staging.sa_swift_S_STMTCT_Hash_Movement m
						WHERE	m.STATEMENT = spacc.STATEMENT
						)
		UNION
		SELECT	spacc.ID
		FROM	dbo.sa_swift_S_PACC spacc
		JOIN	dbo.sa_swift_EDIFACTCommissionStatementContents efc on efc.PACC_ID = spacc.ID
		WHERE	EXISTS	(
						SELECT	*
						FROM	Staging.sa_swift_EDIFACTCommissionStatementContents_Hash_Movement m
						WHERE	m.ID = efc.ID
						)
		UNION
		SELECT	spacc.ID
		FROM	dbo.sa_swift_S_PACC spacc
		WHERE EXISTS	(
						SELECT *
						FROM #CommissionStatementPeriods c
						WHERE c.date = spacc.DATE_DUE
						)
		UNION
		SELECT	spacc.ID
		FROM	dbo.sa_swift_S_PACC spacc
		WHERE EXISTS	(
						SELECT *
						FROM #CommissionStatementPeriods c
						WHERE c.date = spacc.DATE_RECV
						)
		UNION
		SELECT	spacc.ID
		FROM	dbo.sa_swift_S_PACC spacc
		WHERE EXISTS	(
						SELECT *
						FROM #CommissionStatus c
						WHERE c.Status = spacc.Status
						)
		UNION
		SELECT	spacc.ID
		FROM	dbo.sa_swift_S_PACC spacc
		WHERE EXISTS	(
						SELECT *
						FROM #CommissionType c
						WHERE c.Type = spacc.Type
						);

	-- Empty the hash movement tables
	TRUNCATE TABLE Staging.msit_CommissionStatementPeriods_Hash_Movement;
	TRUNCATE TABLE Staging.msit_MIWarehouseCodesAndDescriptions_Hash_Movement;
	TRUNCATE TABLE Staging.mstt_Policies_Hash_Movement;
	TRUNCATE TABLE Staging.mstt_PolicyTransactions_Hash_Movement;
	TRUNCATE TABLE Staging.mstt_ProductHierarchy_Hash_Movement;
	TRUNCATE TABLE Staging.sa_swift_CodeUnallocatedReasons_Hash_Movement;
	TRUNCATE TABLE Staging.sa_swift_EDIFACTCommissionStatementContents_Hash_Movement;
	TRUNCATE TABLE Staging.sa_swift_EDIFACTCommissionStatementHeader_Hash_Movement;
	TRUNCATE TABLE Staging.sa_swift_S_PACC_Hash_Movement;
	TRUNCATE TABLE Staging.sa_swift_S_PACCSU_Hash_Movement;
	TRUNCATE TABLE Staging.sa_swift_S_PACCUN_Hash_Movement;
	TRUNCATE TABLE Staging.sa_swift_S_STMTCT_Hash_Movement;

	EXEC dbo.msp_ProcessLog 'EXP', '02) End Identify expectation movements', null, 'mstp_Expectation', 'Openwork';

	------------------------------------------------------------------------------------------------------------------
	/*
		3 - Update mstt_Expectation
	*/

	-- Create Commission Statement Periods Lookup
	TRUNCATE TABLE #CommissionStatementPeriods;

	WITH theDates AS
	(
		SELECT	@StartDate AS theDate
		UNION ALL
		SELECT	DATEADD(DAY, 1, theDate)
		FROM	theDates
		WHERE	DATEADD(DAY, 1, theDate) <= @EndDate
	)
	INSERT #CommissionStatementPeriods([date],[month]) 
		SELECT	 theDate
				,csp.Month
		FROM theDates
		JOIN dbo.msit_CommissionStatementPeriods csp ON theDate BETWEEN csp.PeriodStartDate and csp.PeriodEndDate
		OPTION (MAXRECURSION 0);

	-- Create Commission Status Lookup
	TRUNCATE TABLE #CommissionStatus;

	INSERT #CommissionStatus([Status],[Description]) 
		SELECT	 CONVERT(TINYINT, cs.Code)
				,CONVERT(VARCHAR(50), COALESCE(cs.ShortDescription, cs.LongDescription, cs.Description))
		FROM	dbo.msit_MIWarehouseCodesAndDescriptions cs
		WHERE	cs.ColumnName = 'CommissionStatus';

	-- Create Commission Type Lookup
	TRUNCATE TABLE #CommissionType;

	INSERT #CommissionType([Type],[Description]) 
		SELECT	 CONVERT(TINYINT, ct.Code)
				,CONVERT(VARCHAR(50), COALESCE(ct.ShortDescription, ct.LongDescription, ct.Description))
		FROM	dbo.msit_MIWarehouseCodesAndDescriptions ct
		WHERE	ct.ColumnName = 'CommissionType';


	-- Rows to Delete
	DELETE	dbo.mstt_Expectation
	WHERE	ID NOT IN (SELECT ID FROM dbo.sa_swift_S_PACC);

	-- Rows to Upsert
	MERGE	dbo.mstt_Expectation AS Target
	USING	(
			SELECT	 spacc.ID
					,spacc.STATEMENT
					,spacc.DATE_DUE
					,spacc.AMOUNT_DUE
					,spacc.DATE_RECV
					,spacc.AMOUNT_REC
					,spacc.TYPE
					,cstd.Description AS Type_Description
					,spacc.STATUS
					,cssd.Description AS StatusDescription
					,spacc.ADJUST
					,spacc.COMP_CODE
					,spacc.Rebate
					,spacc.StatementCreatedFrom
					,spacc.VAT
					,spacc.UnallocatedReasonCode
					,spacc.RenewalType
					,spacc.TransactionID
					,spacc.FutureExpectationID
					,spacc.Manual
					,spacc.Authorised
					,spacc.OriginalAmountReceived
					,paccun.Agent_Code
					,paccsu.INIT_ID
					,spacc.CreatedDate AS CreateDate
					,spacc.CLIENT_NUM
					,spacc.NOTES
					,spacc.CreatedBy
					,spacc.AuthorisedBy
					,spacc.AuthorisedDate
					,spacc.ParentID
					,rea.Description AS UnallocReasonDesc
					,pt.PolicyID
					,pt.CommType
					,pt.CodeCommissionShapeID AS CommShapeID
					,pt.Frequency
					,ISNULL(pt.CommProductCode, p.ProductCode) AS TranProduct
					,pt.IssuedDate
					,pt.WrittenDate
					,ddrm.Month AS DueDateReportMonth
					,rdrm.Month AS  RecDateReportMonth
					,efh.ID AS EDIStatementID
					,efc.ID AS EDIContentID
					,sld.CreatedDateTime AS StatementLoadDate
					,p.PolicyRef AS CaseID
					,p.CONT_NUM AS ProviderRef
					,p.CLIENT_NUM AS FirstClientID
					,ph.ZFSGroupFlag AS ZFSGroup
					,ph.RevenueCategoryCode AS RevenueCategoryCode
					,ph.ProductSubGroupCode AS ProdSubGroupCode
					,ph.ProductGroupCode AS ProdGroupCode
					,ph.APE_Flag AS APEFlag
			FROM		dbo.sa_swift_S_PACC spacc
			LEFT JOIN	dbo.mstt_PolicyTransactions pt ON spacc.TransactionID = pt.ID
			LEFT JOIN	dbo.mstt_Policies p ON pt.PolicyID = p.POL_NUM  
			LEFT JOIN	dbo.mstt_ProductHierarchy ph on ph.ProductCode = ISNULL(pt.CommProductCode, p.ProductCode)
			LEFT JOIN	dbo.sa_swift_S_PACCUN paccun ON paccun.PACC_ID = spacc.ID
			LEFT JOIN	(SELECT SUSP_ID, MIN(INIT_ID) AS INIT_ID FROM sa_swift_S_PACCSU GROUP BY SUSP_ID) paccsu ON paccsu.SUSP_ID = spacc.ID
			LEFT JOIN	dbo.sa_swift_CodeUnallocatedReasons rea ON rea.code = spacc.UnallocatedReasonCode
			LEFT JOIN	dbo.sa_swift_S_STMTCT sld ON sld.STATEMENT = spacc.STATEMENT
			LEFT JOIN	dbo.sa_swift_EDIFACTCommissionStatementHeader efh ON efh.StatementID = spacc.STATEMENT
			LEFT JOIN	(SELECT PACC_ID, MIN(ID) AS ID FROM msit_EDIFACTCommissionStatementContents GROUP BY PACC_ID) efc ON efc.PACC_ID = spacc.ID
			LEFT JOIN	#CommissionStatementPeriods ddrm ON ddrm.date = DATEADD(DAY, 0, DATEDIFF(DAY, 0, spacc.DATE_DUE))
			LEFT JOIN	#CommissionStatementPeriods rdrm ON rdrm.date = DATEADD(DAY, 0, DATEDIFF(DAY, 0, spacc.DATE_RECV))
			LEFT JOIN	#CommissionStatus cssd ON cssd.Status = spacc.Status
			LEFT JOIN	#CommissionType cstd ON cstd.Type = spacc.Type
			WHERE	EXISTS	(
							SELECT	*
							FROM	Staging.mstt_Expectation_Movement
							WHERE	ID = spacc.ID
							)
			) AS Source
				ON Target.ID = Source.ID
	WHEN NOT MATCHED BY TARGET THEN
		INSERT	(ID 
				,STATEMENT
				,DATE_DUE
				,AMOUNT_DUE
				,DATE_RECV
				,AMOUNT_REC
				,TYPE
				,Type_Description
				,STATUS
				,StatusDescription
				,ADJUST
				,COMP_CODE
				,Rebate
				,StatementCreatedFrom
				,VAT
				,UnallocatedReasonCode
				,RenewalType
				,TransactionID
				,FutureExpectationID
				,Manual
				,Authorised
				,OriginalAmountReceived
				,AGENT_CODE
				,INIT_ID
				,IncomeRecognitionDate
				,CashReceivedDate
				,CreateDate
				,CLIENT_NUM
				,NOTES
				,CreatedBy
				,AuthorisedBy
				,AuthorisedDate
				,ParentID
				,UnallocReasonDesc
				,PolicyID
				,CommType
				,CommShapeID
				,Frequency
				,TranProduct
				,IssuedDate
				,WrittenDate
				,DueDateReportMonth
				,RecDateReportMonth
				,EDIStatementID
				,EDIContentID
				,StatementLoadDate
				,CaseID
				,ProviderRef
				,FirstClientID
				,ZFSGroup
				,RevenueCategoryCode
				,ProdSubGroupCode
				,ProdGroupCode
				,APEFlag
				)
		VALUES	(Source.ID 
				,Source.STATEMENT
				,Source.DATE_DUE
				,Source.AMOUNT_DUE
				,Source.DATE_RECV
				,Source.AMOUNT_REC
				,Source.TYPE
				,Source.Type_Description
				,Source.STATUS
				,Source.StatusDescription
				,Source.ADJUST
				,Source.COMP_CODE
				,Source.Rebate
				,Source.StatementCreatedFrom
				,Source.VAT
				,Source.UnallocatedReasonCode
				,Source.RenewalType
				,Source.TransactionID
				,Source.FutureExpectationID
				,Source.Manual
				,Source.Authorised
				,Source.OriginalAmountReceived
				,Source.AGENT_CODE
				,Source.INIT_ID
				,Source.DATE_RECV
				,Source.DATE_RECV
				,Source.CreateDate
				,Source.CLIENT_NUM
				,Source.NOTES
				,Source.CreatedBy
				,Source.AuthorisedBy
				,Source.AuthorisedDate
				,Source.ParentID
				,Source.UnallocReasonDesc
				,Source.PolicyID
				,Source.CommType
				,Source.CommShapeID
				,Source.Frequency
				,Source.TranProduct
				,Source.IssuedDate
				,Source.WrittenDate
				,Source.DueDateReportMonth
				,Source.RecDateReportMonth
				,Source.EDIStatementID
				,Source.EDIContentID
				,Source.StatementLoadDate
				,Source.CaseID
				,Source.ProviderRef
				,Source.FirstClientID
				,Source.ZFSGroup
				,Source.RevenueCategoryCode
				,Source.ProdSubGroupCode
				,Source.ProdGroupCode
				,Source.APEFlag
				)
	WHEN MATCHED THEN 
		UPDATE SET	 STATEMENT = Source.STATEMENT
					,DATE_DUE = Source.DATE_DUE
					,AMOUNT_DUE = Source.AMOUNT_DUE
					,DATE_RECV = Source.DATE_RECV
					,AMOUNT_REC = Source.AMOUNT_REC
					,TYPE = Source.TYPE
					,Type_Description = Source.Type_Description
					,STATUS = Source.STATUS
					,StatusDescription = Source.StatusDescription
					,ADJUST = Source.ADJUST
					,COMP_CODE = Source.COMP_CODE
					,Rebate = Source.Rebate
					,StatementCreatedFrom = Source.StatementCreatedFrom
					,VAT = Source.VAT
					,UnallocatedReasonCode = Source.UnallocatedReasonCode
					,RenewalType = Source.RenewalType
					,TransactionID = Source.TransactionID
					,FutureExpectationID = Source.FutureExpectationID
					,Manual = Source.Manual
					,Authorised = Source.Authorised
					,OriginalAmountReceived = Source.OriginalAmountReceived
					,AGENT_CODE = Source.AGENT_CODE
					,INIT_ID = Source.INIT_ID
					,IncomeRecognitionDate = Source.DATE_RECV
					,CashReceivedDate = Source.DATE_RECV
					,CreateDate = Source.CreateDate
					,CLIENT_NUM = Source.CLIENT_NUM
					,NOTES = Source.NOTES
					,CreatedBy = Source.CreatedBy
					,AuthorisedBy = Source.AuthorisedBy
					,AuthorisedDate = Source.AuthorisedDate
					,ParentID = Source.ParentID
					,UnallocReasonDesc = Source.UnallocReasonDesc
					,PolicyID = Source.PolicyID
					,CommType = Source.CommType
					,CommShapeID = Source.CommShapeID
					,Frequency = Source.Frequency
					,TranProduct = Source.TranProduct
					,IssuedDate = Source.IssuedDate
					,WrittenDate = Source.WrittenDate
					,DueDateReportMonth = Source.DueDateReportMonth
					,RecDateReportMonth = Source.RecDateReportMonth
					,EDIStatementID = Source.EDIStatementID
					,EDIContentID = Source.EDIContentID
					,StatementLoadDate = Source.StatementLoadDate
					,CaseID = Source.CaseID
					,ProviderRef = Source.ProviderRef
					,FirstClientID = Source.FirstClientID
					,ZFSGroup = Source.ZFSGroup
					,RevenueCategoryCode = Source.RevenueCategoryCode
					,ProdSubGroupCode = Source.ProdSubGroupCode
					,ProdGroupCode = Source.ProdGroupCode
					,APEFlag = Source.APEFlag
					;

	--ID262 - Override IncomeRecognitionDate using Transaction Types mapping to 1,4,10
	WITH cte_Expectation AS
	(
		SELECT	 Type
				,TransactionID
				,MIN(DATE_RECV) AS MinDateRecv
		FROM	dbo.mstt_Expectation
		WHERE	Status IN (2,3)
		AND		Type IN (1,4,10)
		GROUP BY Type
				,TransactionID
	)
	UPDATE	e
	SET		IncomeRecognitionDate = ex.MinDateRecv
	FROM	dbo.mstt_Expectation e
	JOIN	cte_Expectation ex ON ex.TransactionID = e.TransactionID
							AND ex.type =	CASE
												WHEN e.type in (1,2,17) THEN 1 
												WHEN e.type IN (4,15,18) THEN 4
												WHEN e.type IN (10,16,19) THEN 10 
											END
	WHERE	ISNULL(e.IncomeRecognitionDate, @Now) <> ISNULL(ex.MinDateRecv, @Now);

	--ID262 - Override CashReceivedDate for Suspense expectations
	WITH cte_paccsu AS
	(
		SELECT	 INIT_ID
				,MIN(SUSP_ID) AS SUSP_ID
		FROM	dbo.msit_S_PACCSU
		GROUP BY INIT_ID
	)
	UPDATE	e
	SET		 SuspenseID = p.SUSP_ID
			,CashReceivedDate = s.DATE_RECV
	FROM	dbo.mstt_Expectation e
	JOIN	cte_paccsu p ON p.INIT_ID = e.ID
	JOIN	dbo.mstt_Expectation s	ON s.ID = p.SUSP_ID
	WHERE	ISNULL(e.SuspenseID, 0) <> ISNULL(p.SUSP_ID, 0)
	OR		ISNULL(e.CashReceivedDate, @Now) <> ISNULL(s.DATE_RECV, @Now);

	-- Empty the movement table
	TRUNCATE TABLE [Staging].[mstt_Expectation_Movement];

	EXEC dbo.msp_ProcessLog 'EXP', '03) End Update mstt_Expectation', null, 'mstp_Expectation', 'Openwork';
END TRY
BEGIN CATCH
	DECLARE	 @ErrorNumber INT = ERROR_NUMBER()
			,@Message VARCHAR(MAX) = ERROR_MESSAGE()
			,@Severity INT = ERROR_SEVERITY()
			,@State SMALLINT = ERROR_STATE()
			;

	EXEC dbo.msp_ProcessLog 'EXP', '99) FAILED mstp_Expectation', null, 'mstp_Expectation', 'Openwork';
 
	RAISERROR (@Message, @Severity, @State);
END CATCH
GO
/****** Object:  StoredProcedure [dbo].[mstp_Expectation_20190118]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER OFF
GO

CREATE PROCEDURE [dbo].[mstp_Expectation_20190118] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

Date    Amended By  Change Details
========  ==========  ==============
16/01/08  A Groves  Performance Improvements:
            1)  Dropped indexes prior to INSERT followed by INDEX CREATES
                which also updates stats to make following UPDATES faster.
            2)  Default IncomeRecognitionDate and CashReceivedDate populated
              by INSERT rather than separate UPDATE.  
            3)  IncomeRecognitionDate updated in 1 statement using a derived
              table rather than a temp table and 2 statements.
            4)  Added separate UPDATEs to initial INSERT where possible.
*******************************************************************************/


--Clear the target table first
Truncate Table mstt_Expectation

exec msp_ProcessLog 'EXP', '01) End TRUNCATE mstt_Expectation', null, 'mstp_Expectation', 'Openwork'

DROP  INDEX mstt_Expectation.IX_mstt_Expectation_Agent_Code 
DROP  INDEX mstt_Expectation.IX_mstt_Expectation_TransactionID 
DROP  INDEX mstt_Expectation.IX_mstt_Expectation_Multiple 
DROP  INDEX mstt_Expectation.IX_mstt_Expectation_Trial 

exec msp_ProcessLog 'EXP', '02) End DROP mstt_Expectation INDEXES', null, 'mstp_Expectation', 'Openwork'

-- Create expanded CommissionStatementPeriods lookup table, to simplify later joins
DECLARE  @StartDate DATETIME = (SELECT MIN(PeriodStartDate) FROM msit_CommissionStatementPeriods)
		,@EndDate DATETIME = (SELECT MAX(PeriodEndDate) FROM msit_CommissionStatementPeriods)
		;

CREATE TABLE #CommissionStatementPeriods
(
  [date]	DATETIME PRIMARY KEY, 
  [month]	DATETIME		
);

-- use the catalog views to generate as many rows as we need
INSERT #CommissionStatementPeriods([date],[month]) 
SELECT	 d
		,(SELECT csp.Month FROM msit_CommissionStatementPeriods csp WHERE d BETWEEN csp.PeriodStartDate and csp.PeriodEndDate)
FROM
(
  SELECT d = DATEADD(DAY, rn - 1, @StartDate)
  FROM 
  (
    SELECT TOP (DATEDIFF(DAY, @StartDate, @EndDate)) 
      rn = ROW_NUMBER() OVER (ORDER BY s1.[object_id])
    FROM sys.all_objects AS s1
    CROSS JOIN sys.all_objects AS s2
    ORDER BY s1.[object_id]
  ) AS x
) AS y;

--Get the data from the Import Table
insert into mstt_Expectation
  (
  ID, 
  STATEMENT, 
  DATE_DUE, 
  AMOUNT_DUE, 
  DATE_RECV, 
  AMOUNT_REC, 
  TYPE, 
  Type_Description, 
  STATUS, 
  StatusDescription, 
  ADJUST, 
  COMP_CODE, 
  Rebate, 
  StatementCreatedFrom, 
  VAT, 
  UnallocatedReasonCode, 
  RenewalType, 
  TransactionID, 
  PolicyTransactionStatus, 
  FutureExpectationID, 
  Manual, 
  Authorised, 
  OriginalAmountReceived, 
  AGENT_CODE, 
  INIT_ID,
  IncomeRecognitionDate, 
  CashReceivedDate, 
  CreateDate,
  CLIENT_NUM,
  NOTES,
  CreatedBy,
  AuthorisedBy,
  AuthorisedDate,
  ParentID,
  UnallocReasonDesc,
  PolicyID,
  CommType,
  CommShapeID,
  Frequency,
  TranProduct,
  IssuedDate,
  WrittenDate,
  DueDateReportMonth,
  RecDateReportMonth,
  EDIStatementID,
  EDIContentID,
  StatementLoadDate,
  CaseID,
  ProviderRef,
  FirstClientID,
  ZFSGroup,
  RevenueCategoryCode,
  ProdSubGroupCode,
  ProdGroupCode,
  APEFlag
  )
select 
  spacc.ID, 
  spacc.STATEMENT, 
  spacc.DATE_DUE, 
  spacc.AMOUNT_DUE, 
  spacc.DATE_RECV, 
  spacc.AMOUNT_REC, 
  spacc.TYPE, 
  cstd.Description,               -- TypeDescription
  spacc.STATUS, 
  cssd.Description,                  -- StatusDescription
  spacc.ADJUST, 
  spacc.COMP_CODE, 
  spacc.Rebate, 
  spacc.StatementCreatedFrom, 
  spacc.VAT, 
  spacc.UnallocatedReasonCode, 
  spacc.RenewalType, 
  spacc.TransactionID, 
  null as PolicyTransactionStatus,
  spacc.FutureExpectationID, 
  spacc.Manual, 
  spacc.Authorised, 
  spacc.OriginalAmountReceived, 
  paccun.Agent_Code,                  -- Agent_Code
  paccsu.INIT_ID,                  -- INIT_ID
  spacc.DATE_RECV, 
  spacc.DATE_RECV, 
  spacc.CreatedDate,
  spacc.CLIENT_NUM,
  spacc.NOTES,
  spacc.CreatedBy,
  spacc.AuthorisedBy,
  spacc.AuthorisedDate,
  spacc.ParentID,
  rea.Description,                 -- UnallocReasonDesc
  pt.PolicyID,
  pt.CommType,
  pt.CodeCommissionShapeID,
  pt.Frequency,
  coalesce(pt.CommProductCode, p.ProductCode),      -- TranProduct  
  pt.IssuedDate,
  pt.WrittenDate,
  ddrm.Month,                   -- DueDateReportMonth
  rdrm.Month,                   -- RecDateReportMonth
  efh.ID,                      -- EDIStatementID
  efc.ID,                   -- EDIContentID
  sld.CreatedDateTime,               -- StatementLoadDate
  p.PolicyRef,                      -- CaseID
  p.CONT_NUM,                       -- ProviderRef
  p.CLIENT_NUM,                     -- FirstClientID 
  ph.ZFSGroupFlag,                    -- ZFSGroup
  ph.RevenueCategoryCode,                 -- RevenueCategoryCode
  ph.ProductSubGroupCode,                 -- ProdSubGroupCode
  ph.ProductGroupCode,                  -- ProdGroupCode
  ph.APE_Flag                       -- APEFlag
from msit_s_pacc spacc
  left outer join mstt_PolicyTransactions pt on spacc.TransactionID = pt.ID
  left outer join mstt_Policies p on pt.PolicyID = p.POL_NUM  
  left outer join mstt_ProductHierarchy ph on ph.ProductCode = coalesce(pt.CommProductCode, p.ProductCode)
  left outer join #CommissionStatementPeriods ddrm on ddrm.date = spacc.DATE_DUE
  left outer join #CommissionStatementPeriods rdrm on rdrm.date = spacc.DATE_RECV
  left outer join msit_EDIFACTCommissionStatementHeader efh on efh.StatementID = spacc.STATEMENT
  left outer join msdt_DropLists cssd on cssd.Code = convert(varchar(6), spacc.Status) and cssd.CodeType = 'CommissionStatus'
  left outer join msdt_DropLists cstd on cstd.Code = convert(varchar(6), spacc.Type) and cstd.CodeType = 'CommissionType'
  left outer join msit_s_paccun paccun on paccun.PACC_ID = spacc.ID
  left outer join (select SUSP_ID, min(INIT_ID) AS 'INIT_ID' from msit_s_paccsu group by SUSP_ID) paccsu on paccsu.SUSP_ID = spacc.ID
  left outer join msit_CodeUnallocatedReasons rea on rea.code = spacc.UnallocatedReasonCode
  left outer join msit_S_STMTCT sld on sld.STATEMENT = spacc.STATEMENT
  left outer join msit_EDIFACTCommissionStatementContents efc on efc.PACC_ID = spacc.ID


exec msp_ProcessLog 'EXP', '03) End INSERT mstt_Expectation', null, 'mstp_Expectation', 'Openwork'

CREATE  INDEX [IX_mstt_Expectation_Agent_Code] 
    ON [dbo].[mstt_Expectation]([AGENT_CODE]) ON [PRIMARY]
CREATE  INDEX [IX_mstt_Expectation_TransactionID] 
    ON [dbo].[mstt_Expectation]([TransactionID]) ON [PRIMARY]
CREATE  INDEX [IX_mstt_Expectation_Multiple] 
    ON [dbo].[mstt_Expectation]([DATE_DUE], [TYPE], [TransactionID], [DATE_RECV]) ON [PRIMARY]
CREATE  INDEX [IX_mstt_Expectation_Trial] 
    ON [dbo].[mstt_Expectation]([DATE_DUE], [TYPE], [TransactionID], [DATE_RECV], [AMOUNT_DUE]) ON [PRIMARY]

exec msp_ProcessLog 'EXP', '04) End CREATE mstt_Expectation INDEXES', null, 'mstp_Expectation', 'Openwork'

--ID262 - Override IncomeRecognitionDate using Transaction Types mapping to 1,4,10
Update e
  set IncomeRecognitionDate = derived_table.MinDateRecv
from 
  (select Type, TransactionID, min(DATE_RECV) as MinDateRecv
   from mstt_Expectation
   where  Status in (2,3)
   and  Type in (1,4,10)
   group  by Type, TransactionID) derived_table
    inner join mstt_Expectation e
          on  e.TransactionID = derived_table.TransactionID
            and derived_table.type = 
              case when e.type in (1,2,17) then 1 
              when e.type in (4,15,18) then 4
              when e.type in (10,16,19) then 10 
              end

exec msp_ProcessLog 'EXP', '05) End UPDATE IncomeRecognitionDate', null, 'mstp_Expectation', 'Openwork'

--ID262 - Override CashReceivedDate for Suspense expectations
Update e
set SuspenseID = p.SUSP_ID,
  CashReceivedDate = s.DATE_RECV
from mstt_Expectation e
  inner join msit_S_PACCSU p
    on e.ID = p.INIT_ID
  inner join mstt_Expectation s
    on p.SUSP_ID = s.ID

exec msp_ProcessLog 'EXP', '06) End UPDATE SuspID & CashReceivedDate', null, 'mstp_Expectation', 'Openwork'


GO
/****** Object:  StoredProcedure [dbo].[mstp_ExpectationAgentSplit]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
