CREATE PROCEDURE [dbo].[mstp_ExpectationAgentSplit] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : ID 19 Populates New Table Mstt_ExpectationAgentSplit
Author  : M Rodrigues
Created : March 2007
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

*******************************************************************************/


-- PROCEDURE BODY GOES HERE

--Clear the target table first
Truncate Table mstt_ExpectationAgentSplit

Select e.TransactionID,
  e.ID,
  e.Type,
  e.Amount_Rec,
  e.DATE_RECV,
  e.AMOUNT_DUE,
  e.DATE_DUE,
  case when e.Type in (1,2,17) then 1
    when e.Type in (4,15,18) then 4
    when e.Type in (10,16,19) then 10
    else e.Type end as CommissionType 
into
#Expectation
  
from mstt_expectation e
where e.Type in (1,2,4,10,15,16,17,18,19)
and e.ID is not NULL


CREATE INDEX idx_Expectation
on #Expectation (TransactionID, ID)   
  
--Get the data from the Import Table
insert mstt_ExpectationAgentSplit
  (ExpectationID,
  CommissionID,
  TransactionID,
  TransactionDate,
  AgentCode,
  Firm,
  CommissionType,
  AgentSplit,
  NBI,
  DA,
  Margin,
  APE,
  Turnover,
  Base,
  Uplift,
  UpliftRate,
  AgentType,
  AgentName,
  ExpectType,
  AmountReceived,
  DateReceived,
  AmountDue,
  DateDue)
Select
  e.ID,
  c.ID,
  c.TransactionID,
  c.TransactionDate,
  c.Agent_Code,
  c.Firm,
  c.CommissionType,
  c.AGENT_PERC,
  c.FixedAmount,
  case when c.CommissionType = 1 then c.DistributionAllowance ELSE FixedAmount end,
  case when c.CommissionType = 1 then c.SalesMargin else '0' end,
  case when c.CommissionType = 1 then c.APE else '0' end,
  case when c.CommissionType = 1 then c.Turnover else '0' end,
  case when c.CommissionType = 1 then c.BaseAmount else '0' end,
  case when c.CommissionType = 1 then c.UpliftAmount else '0' end,
  case when c.CommissionType = 1 then c.FranchiseUpliftPercent else '0' end,
  a.AgentType,
  Coalesce(a.TradingName, a.DESCN),
  e.Type,
  e.Amount_Rec,
  e.DATE_RECV,
  e.AMOUNT_DUE,
  e.DATE_DUE
from #Expectation e
inner join mstt_Commissions c
on e.TransactionID = c.TransactionID
and e.CommissionType = c.CommissionType
  inner join mstt_Agents a
  on a.Code = c.Agent_Code

Update mstt_ExpectationAgentSplit
set SplitAmount = AmountReceived * NBI / DA
from mstt_ExpectationAgentSplit
where CommissionType = 1
and AgentCode <> '10002'
and DA <> 0

Select [ExpectationID], Sum(SplitAmount) as SplitAmount
into #SumSplitAmount
from mstt_ExpectationAgentSplit
where AgentSplit is not null
Group By [ExpectationID]

CREATE INDEX idx_SumSplit ON #SumSplitAmount (ExpectationID)

Update mstt_ExpectationAgentSplit
set SplitAmount = AmountReceived - b.SplitAmount
from mstt_ExpectationAgentSplit a, #SumSplitAmount b
where a.ExpectationID = b.ExpectationID
and a.CommissionType = 1
and AgentCode = '10002'

Update mstt_ExpectationAgentSplit
set SplitAmount = AmountReceived * AgentSplit/100
where SplitAmount is null

Drop table #Expectation

Drop Table #SumSplitAmount

  

GO
