CREATE PROCEDURE [dbo].[mstp_FranchiseSegments] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
*******************************************************************************/
/*****************************************************************************
28/09/05
Shirley
As discussed please do not attempt to derive this field from the Warehouse
as there is no data we can use directly. The business is likely to raise a
CR requesting us to load the data via an Ad Hoc spreadsheet (it's quite a
subjective categorisation currently). This CR may ask you to remove it as a
cube dimension and the slicers from proclarity charts. Until this is
decided please leave it as a dummy dimension with no 'hierarchy'.
However, as the field is critical for League Tables please add a code to
Agent Type 2 records (i.e Franchises) with three values 1 = Protection, 2 =
Mortgage & GI , 3 = Pension & Investment.
Cheers
Mike
******************************************************************************/
--HardCode as per Mike's email above
truncate table msdt_FranchiseSegments
insert into msdt_FranchiseSegments (FranchiseSegmentType,FranchiseSegment)
values ('Protection','1')
insert into msdt_FranchiseSegments (FranchiseSegmentType,FranchiseSegment)
values ('Mortgage & GI','2' )
insert into msdt_FranchiseSegments (FranchiseSegmentType,FranchiseSegment)
values ('Pension & Investment','3' )
if not exists (select * from msdt_FranchiseSegments where FranchiseSegmentID = -99)
 begin
  SET IDENTITY_INSERT msdt_FranchiseSegments ON
  insert into msdt_FranchiseSegments (FranchiseSegmentID, FranchiseSegmentType,FranchiseSegment) 
  values           (-99, 'Unknown', 'Unk')
  SET IDENTITY_INSERT msdt_FranchiseSegments OFF
 end 

