CREATE PROCEDURE [dbo].[mstp_Frequency] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
*******************************************************************************/
truncate table msdt_Frequency
insert into msdt_Frequency (FrequencyCode, FrequencyDescription)
select distinct Frequency, 'Unknown'
from mstt_Commissions
update f
set f.FrequencyDescription = dl.Description
from msdt_Frequency f
  inner join msdt_DropLists dl
    on f.FrequencyCode = dl.Code
where dl.CodeType = 'Frequency'
if not exists (select * from msdt_Frequency where FrequencyId = -99)
 begin
  SET IDENTITY_INSERT msdt_Frequency ON
  insert into msdt_Frequency (FrequencyId, FrequencyCode,FrequencyDescription) 
  values           (-99, 'UNK', 'Unknown')
  SET IDENTITY_INSERT msdt_Frequency OFF
 end 

GO
/****** Object:  StoredProcedure [dbo].[mstp_KPICalc_Adviser]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

create procedure [dbo].[mstp_KPICalc_Adviser] as

begin

--Commence KPI Calculations
Update mstt_Work_AgentQualityAggregation
set SAKPIPercent =  round(
          (
          --Ensure Divisor is not ZERO
          case when (InitialRiskAssessedQty + 
          InitialRandomAssessedQty + 
          InitialOtherAssessedQty) = 0 
            then 0 else 
          --Number of Suitable Advice Fails 
          cast((InitialRiskSuitableAdviceQty  + 
          InitialRandomSuitableAdviceQty  + 
          InitialOtherSuitableAdviceQty) as float)  
            /  
          --Total Cases Assessed 
          cast((InitialRiskAssessedQty + 
          InitialRandomAssessedQty + 
          InitialOtherAssessedQty) as float) end
          ), 3)

--Completion
Update mstt_Work_AgentQualityAggregation
set CQKPIPercent =  round(
          (
          --Ensure Divisor is not ZERO
          case when (InitialRiskAssessedQty + 
          InitialRandomAssessedQty + 
          InitialOtherAssessedQty) = 0 
            then 0 else 
          --Number of Completion Query Fails 
          cast((InitialRiskCompletionQty + 
          InitialRandomCompletionQty + 
          InitialOtherCompletionQty) as float) 
            /  
          --Total Cases Assessed 
          cast((InitialRiskAssessedQty + 
          InitialRandomAssessedQty + 
          InitialOtherAssessedQty) as float) end
          ), 3)

--Amended 20060417 BT - Replace calculation that was storing number of rejects in the KPI percent field 
--            with the proper KPI percent calculation. (ID265)

--Rejections
Update mstt_Work_AgentQualityAggregation
set RejectKPIPercent = Round(
      (
      --Ensure Divisor is not ZERO
      case when (InitialRiskAssessedQty + 
      InitialRandomAssessedQty + 
      InitialOtherAssessedQty) = 0
        then 0 else
      --Number of Rejections
      cast((FinalRiskRejectQty + 
      FinalRandomRejectQty + 
      FinalOtherRejectQty) as float)
      /
      --Total Cases Assessed 
      cast((InitialRiskAssessedQty + 
      InitialRandomAssessedQty + 
      InitialOtherAssessedQty) as float) end 
      ), 3)


--Replacements
--This is NOT a percentage for Advisers, so should this be stored in the 'Percent' column?
Update mstt_Work_AgentQualityAggregation
set ReplacementKPIPercent = case when ComplianceCategoryCode in ('COB','ICOB-PP') then 
              (DisclosedReplacementQty + 
              UndisclosedReplacementQty)
              else 0 end


end

GO
