/****** Object:  StoredProcedure [dbo].[mstp_KPICalc_PS_SQM_Weighted]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

create procedure [dbo].[mstp_KPICalc_PS_SQM_Weighted] as

begin

--Commence KPI Calculations
--SA - Non-MCOB
--[Risk Cases Fails + Other Cases Fails + {(Random Cases Fails / Random Cases Assessed) x 
--(Non-Risk Cases Submitted – Other Cases Assessed)} ] / Total Cases Submitted x 100
Update mstt_Work_AgentQualityAggregation
set SAKPIPercent =  case when InitialRiskSuitableAdviceQty + 
        InitialOtherSuitableAdviceQty +
        InitialRandomSuitableAdviceQty = 0 then 0
        
      when  InitialRandomAssessedQty +
        InitialOtherAssessedQty +
        InitialRiskAssessedQty = 0 then 0
        
        
      when  SubmittedRiskProposalQty + 
        SubmittedRandomProposalQty + 
        SubmittedOtherProposalQty = 0 then  --Calc A
            round((InitialRiskSuitableAdviceQty + 
            InitialOtherSuitableAdviceQty +
            InitialRandomSuitableAdviceQty) /
            cast(InitialRandomAssessedQty +
            InitialOtherAssessedQty +
            InitialRiskAssessedQty as Float), 3)
            
      when  InitialRandomAssessedQty = 0 then --Calc A
            round((InitialRiskSuitableAdviceQty + 
            InitialOtherSuitableAdviceQty +
            InitialRandomSuitableAdviceQty) /
            cast(InitialRandomAssessedQty +
            InitialOtherAssessedQty +
            InitialRiskAssessedQty as Float), 3)      

      
      else  --Calc B
        round(
          (InitialRiskSuitableAdviceQty + 
          InitialOtherSuitableAdviceQty +
            ((InitialRandomSuitableAdviceQty  / 
            cast(InitialRandomAssessedQty as float)) *
              (SubmittedRandomProposalQty + 
              SubmittedOtherProposalQty - 
              InitialOtherAssessedQty)))
          / cast(SubmittedRiskProposalQty + 
            SubmittedRandomProposalQty + 
            SubmittedOtherProposalQty as Float) 
        , 3) 
        
      end


where ComplianceCategoryCode <> 'MCOB'  

--SA - MCOB
--[Other Cases Fails + 
--((Risk Cases Fails / Risk Cases Assessed) * Risk Cases Submitted) + 
--{(Random Fails / Random Assessed) * (Random Cases Submitted - Other Assessed)}] 
--/ Total Submitted x 100
Update mstt_Work_AgentQualityAggregation
set SAKPIPercent = case when  InitialRandomAssessedQty +
        InitialOtherAssessedQty +
        InitialRiskAssessedQty = 0 then 0 
                
      else
        case when SubmittedRiskProposalQty + 
          SubmittedRandomProposalQty + 
          SubmittedOtherProposalQty = 0 then  
        
          case when (InitialRiskSuitableAdviceQty > 0 or 
            InitialOtherSuitableAdviceQty > 0 or
            InitialRandomSuitableAdviceQty > 0) then --Calc A
              round((InitialRiskSuitableAdviceQty + 
              InitialOtherSuitableAdviceQty +
              InitialRandomSuitableAdviceQty) /
              cast(InitialRandomAssessedQty +
              InitialOtherAssessedQty +
              InitialRiskAssessedQty as Float), 3)
              
          else  0 
            --case when (InitialRandomAssessedQty = 0 and
--              InitialRiskAssessedQty = 0) then 
--                case when InitialOtherSuitableAdviceQty = 0 then 0
--                else  round(InitialOtherSuitableAdviceQty / 
--                  cast(InitialOtherAssessedQty as Float), 3)
--                end
          end
        else  case when (InitialRiskAssessedQty <> 0 or InitialRandomAssessedQty <> 0) then 
        
            case when (InitialRiskAssessedQty = 0 and InitialRandomAssessedQty <> 0) then 
              round(InitialRiskAssessedQty + 
              ((InitialRandomSuitableAdviceQty / cast(InitialRandomAssessedQty as Float)) * 
                (SubmittedRandomProposalQty - InitialOtherAssessedQty)) /
                  cast((SubmittedRiskProposalQty + 
                  SubmittedRandomProposalQty + 
                  SubmittedOtherProposalQty) as Float), 3)
            when (InitialRiskAssessedQty <> 0 and InitialRandomAssessedQty = 0) then 
              round(InitialRandomAssessedQty + 
              ((InitialRiskSuitableAdviceQty / cast(InitialRiskAssessedQty as Float)) * 
                SubmittedRiskProposalQty + InitialRandomAssessedQty) /
                    cast((SubmittedRiskProposalQty + 
                    SubmittedRandomProposalQty + 
                    SubmittedOtherProposalQty) as Float), 3)
            else -- The Real Calc C
              round(
                (InitialOtherSuitableAdviceQty +
                ((InitialRiskSuitableAdviceQty / cast(InitialRiskAssessedQty as Float)) * SubmittedRiskProposalQty) +
                ((InitialRandomSuitableAdviceQty / cast(InitialRandomAssessedQty as Float)) * (SubmittedRandomProposalQty - InitialOtherAssessedQty)))
                / cast(SubmittedRiskProposalQty + 
                  SubmittedRandomProposalQty + 
                  SubmittedOtherProposalQty as Float)
              , 3) 
            end
            
          else  round((InitialOtherSuitableAdviceQty / cast(InitialOtherAssessedQty as Float)), 3)
            
          end
        end
      end

where ComplianceCategoryCode = 'MCOB'         

--Completion
Update mstt_Work_AgentQualityAggregation
set CQKPIPercent =  case when InitialRiskCompletionQty + 
        InitialOtherCompletionQty +
        InitialRandomCompletionQty = 0 then 0
        
      when  InitialRandomAssessedQty +
        InitialOtherAssessedQty +
        InitialRiskAssessedQty = 0 then 0
        
        
      when  SubmittedRiskProposalQty + 
        SubmittedRandomProposalQty + 
        SubmittedOtherProposalQty = 0 then  --Calc A
            round((InitialRiskCompletionQty + 
            InitialOtherCompletionQty +
            InitialRandomCompletionQty) /
            cast(InitialRandomAssessedQty +
            InitialOtherAssessedQty +
            InitialRiskAssessedQty as Float), 3)
            
      when  InitialRandomAssessedQty = 0 then --Calc A
            round((InitialRiskCompletionQty + 
            InitialOtherCompletionQty +
            InitialRandomCompletionQty) /
            cast(InitialRandomAssessedQty +
            InitialOtherAssessedQty +
            InitialRiskAssessedQty as Float), 3)      

      
      else  --Calc B
        round(
          (InitialRiskCompletionQty + 
          InitialOtherCompletionQty +
            ((InitialRandomCompletionQty  / 
            cast(InitialRandomAssessedQty as float)) *
              (SubmittedRandomProposalQty + 
              SubmittedOtherProposalQty - 
              InitialOtherAssessedQty)))
          / cast(SubmittedRiskProposalQty + 
            SubmittedRandomProposalQty + 
            SubmittedOtherProposalQty as Float) 
        , 3) end

where ComplianceCategoryCode <> 'MCOB'  


Update mstt_Work_AgentQualityAggregation
set CQKPIPercent = case when  InitialRandomAssessedQty +
        InitialOtherAssessedQty +
        InitialRiskAssessedQty = 0 then 0 
                
      else
        case when SubmittedRiskProposalQty + 
          SubmittedRandomProposalQty + 
          SubmittedOtherProposalQty = 0 then  
        
          case when (InitialRiskCompletionQty > 0 or 
            InitialOtherCompletionQty > 0 or
            InitialRandomCompletionQty > 0) then --Calc A
              round((InitialRiskCompletionQty + 
              InitialOtherCompletionQty +
              InitialRandomCompletionQty) /
              cast(InitialRandomAssessedQty +
              InitialOtherAssessedQty +
              InitialRiskAssessedQty as Float), 3)
              
          else  0 
            --case when (InitialRandomAssessedQty = 0 and
--              InitialRiskAssessedQty = 0) then 
--                case when InitialOtherCompletionQty = 0 then 0
--                else  round(InitialOtherCompletionQty / 
--                  cast(InitialOtherAssessedQty as Float), 3)
--                end
          end
        else  case when (InitialRiskAssessedQty <> 0 or InitialRandomAssessedQty <> 0) then 
        
            case when (InitialRiskAssessedQty = 0 and InitialRandomAssessedQty <> 0) then 
              round(InitialRiskAssessedQty + 
              ((InitialRandomCompletionQty / cast(InitialRandomAssessedQty as Float)) * 
                (SubmittedRandomProposalQty - InitialOtherAssessedQty)) /
                  cast((SubmittedRiskProposalQty + 
                  SubmittedRandomProposalQty + 
                  SubmittedOtherProposalQty) as Float), 3)
            when (InitialRiskAssessedQty <> 0 and InitialRandomAssessedQty = 0) then 
              round(InitialRandomAssessedQty + 
              ((InitialRiskCompletionQty / cast(InitialRiskAssessedQty as Float)) * 
                SubmittedRiskProposalQty + InitialRandomAssessedQty) /
                    cast((SubmittedRiskProposalQty + 
                    SubmittedRandomProposalQty + 
                    SubmittedOtherProposalQty) as Float), 3)
            else -- The Real Calc C
              round(
                (InitialOtherCompletionQty +
                ((InitialRiskCompletionQty / cast(InitialRiskAssessedQty as Float)) * SubmittedRiskProposalQty) +
                ((InitialRandomCompletionQty / cast(InitialRandomAssessedQty as Float)) * (SubmittedRandomProposalQty - InitialOtherAssessedQty)))
                / cast(SubmittedRiskProposalQty + 
                  SubmittedRandomProposalQty + 
                  SubmittedOtherProposalQty as Float)
              , 3) 
            end
            
          else  round((InitialOtherCompletionQty / cast(InitialOtherAssessedQty as Float)), 3)
            
          end
        end
      end


where ComplianceCategoryCode = 'MCOB'


--Amended 20060417 BT - Replace calculation that was storing number of rejects in the KPI percent field 
--            with the proper KPI percent calculation. (ID265)

--Rejections
Update mstt_Work_AgentQualityAggregation
set RejectKPIPercent = Round(
      (
      --Ensure Divisor is not ZERO
      case when (InitialRiskAssessedQty + 
      InitialRandomAssessedQty + 
      InitialOtherAssessedQty) = 0
        then 0 else
      --Number of Rejections
      cast((FinalRiskRejectQty + 
      FinalRandomRejectQty + 
      FinalOtherRejectQty) as float)
      /
      --Total Cases Assessed 
      cast((InitialRiskAssessedQty + 
      InitialRandomAssessedQty + 
      InitialOtherAssessedQty) as float) end 
      ), 3)


--Replacements
Update mstt_Work_AgentQualityAggregation
set ReplacementKPIPercent = case when ComplianceCategoryCode in ('COB','ICOB-PP') then
        round( 
            (--Ensure Divisor is not ZERO
            case when (SubmittedRiskProposalQty + 
            SubmittedRandomProposalQty + 
            SubmittedOtherProposalQty) = 0
              then 0 else
            (DisclosedReplacementQty + 
            UndisclosedReplacementQty)
              /
              cast((SubmittedRiskProposalQty + 
            SubmittedRandomProposalQty + 
            SubmittedOtherProposalQty) as float) end
            ), 3)
            else 0 end

end


GO
/****** Object:  StoredProcedure [dbo].[mstp_KPICalc_RSM_ASD]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

create procedure [dbo].[mstp_KPICalc_RSM_ASD] as

begin

--Commence KPI Calculations
--SA        
Update mstt_Work_AgentQualityAggregation
set SAKPIPercent =  round(
          (
          --Ensure Divisor is not ZERO
          case when (InitialRiskAssessedQty + 
          InitialRandomAssessedQty + 
          InitialOtherAssessedQty) = 0 
            then 0 else 
          --Number of Suitable Advice Fails 
          cast((InitialRiskSuitableAdviceQty  + 
          InitialRandomSuitableAdviceQty  + 
          InitialOtherSuitableAdviceQty) as float)  
            /  
          --Total Cases Assessed 
          cast((InitialRiskAssessedQty + 
          InitialRandomAssessedQty + 
          InitialOtherAssessedQty) as float) end
          ), 3)

--Completion
Update mstt_Work_AgentQualityAggregation
set CQKPIPercent =  round(
          (
          --Ensure Divisor is not ZERO
          case when (InitialRiskAssessedQty + 
          InitialRandomAssessedQty + 
          InitialOtherAssessedQty) = 0 
            then 0 else 
          --Number of Completion Query Fails 
          cast((InitialRiskCompletionQty + 
          InitialRandomCompletionQty + 
          InitialOtherCompletionQty) as float) 
            /  
          --Total Cases Assessed 
          cast((InitialRiskAssessedQty + 
          InitialRandomAssessedQty + 
          InitialOtherAssessedQty) as float) end
          ), 3)

--Rejections
Update mstt_Work_AgentQualityAggregation
set RejectKPIPercent = Round(
      (
      --Ensure Divisor is not ZERO
      case when (InitialRiskAssessedQty + 
      InitialRandomAssessedQty + 
      InitialOtherAssessedQty) = 0
        then 0 else
      --Number of Rejections
      cast((FinalRiskRejectQty + 
      FinalRandomRejectQty + 
      FinalOtherRejectQty) as float)
      /
      --Total Cases Assessed 
      cast((InitialRiskAssessedQty + 
      InitialRandomAssessedQty + 
      InitialOtherAssessedQty) as float) end 
      ), 3)
      

--Replacements
Update mstt_Work_AgentQualityAggregation
set ReplacementKPIPercent = case when ComplianceCategoryCode in ('COB','ICOB-PP') then
        round( 
            (--Ensure Divisor is not ZERO
            case when (SubmittedRiskProposalQty + 
            SubmittedRandomProposalQty + 
            SubmittedOtherProposalQty) = 0
              then 0 else
            (DisclosedReplacementQty + 
            UndisclosedReplacementQty)
              /
              cast((SubmittedRiskProposalQty + 
            SubmittedRandomProposalQty + 
            SubmittedOtherProposalQty) as float) end
            ), 3)
            else 0 end

end


