              where dl.CodeType = 'CommissionType' and a.Type = dl.Code)  --MPC: SR9
  else @DefaultCommissionTypeDesc                       --MPC: SR9
 end as CommissionTypeDesc,                           --MPC: SR9
 a.YTD,
