 a.DUE_DATE,
 a.STATUS,
 a.MEDONE,
 a.Notes,
 a.ContraID,
 isnull(a.StandingOrderCode,@DefaultStandingOrderCode) as StandingOrderCode,--MPC: SR9
 case           --StandingOrderCodeDesc             --MPC: SR9
  when a.StandingOrderCode is not null then (select dl.Description from  msit_CodeStandingOrders dl --MPC: SR9
                    where a.StandingOrderCode = dl.Code)      --MPC: SR9
  else @DefaultStandingOrderDesc                      --MPC: SR9
 end as StandingOrderCodeDesc,                        --MPC: SR9
 isnull(a.JournalEntryCode ,@DefaultJournalEntryCode) as JournalEntryCode,  --MPC: SR9
 case           --JournalEntryCodeDesc              --MPC: SR9
  when a.JournalEntryCode is not null then (select dl.Description from msit_CodeJournalEntries dl --MPC: SR9
                    where a.JournalEntryCode  = dl.Code)      --MPC: SR9
  else @DefaultJournalEntryDesc                       --MPC: SR9
 end as JournalEntryCodeDesc,                       --MPC: SR9
 a.PaymentDueDate,
 a.TransactionID,
 pt.TransactionDate,                            --MPC: SR9
 a.PaymentBasis,
 a.SubjectToVAT,
 a.Authorised,
 a.CreatedBy,
 a.CreatedDate,
 a.AuthorisedBy,
 a.AuthorisedDate,
 a.StandingOrderID,
 a.BaseAmount,
 a.UpliftAmount,
 a.CreateDateTime,
 a.TransAgentSplitHierarchyHistoryID,
 b.StrategicAllianceAgentCode,    --MPC: SR9
 b.AccessAgentCode,         --MPC: SR9
 b.FranchiseAgentCode,        --MPC: SR9
 b.CompanyAgentCode,        --MPC: SR9
 b.OrganisationAgentCode,     --MPC: SR9
 b.DirectlyAuthorisedAgentCode,   --MPC: SR9
 b.Manager1Code,          --MPC: SR9
 b.Manager2Code,          --MPC: SR9
 '       ' as Manager3Code,     --MPC: SR9
 '       ' as Manager4Code,     --MPC: SR9
 a.AGENT_PERC,
 a.FranchiseUpliftPercent,
 csp.Month as CommissionMonth,    --MPC: SR9
 pt.PolicyID,           --MPC: SR9
 po.PolicyRef,            --MPC: SR9
 po.CONT_NUM,           --MPC: SR9
 po.CLIENT_NUM,           --MPC: SR9
 po.SuspendCommInd,         --MPC: SR9
 pt.CommProductCode as TranProduct, --MPC: SR9
 t2.FIRM,             --MPC: SR9
 t2.BACSDate,           --MPC: SR9
 t2.ValidTASHH,           --MPC: SR9 
 t2.SR9Class,           --MPC: SR9
 t2.FIRMTYPE            --MPC: SR9
 ,NULL as DerivedAgentSplit     --MPC:25/01/2010
 ,NULL as DerivedMarginAmount   --MPC:25/01/2010

from
 msit_S_AGMFIL a
 inner join #AGMFILCHANGES X ON X.ID = A.ID       --MPC:25/01/2010
 left outer join mstt_PolicyTransactions pt       --MPC: SR9
  on a.transactionid = pt.id              --MPC: SR9
 left outer join mstt_Policies po             --MPC: SR9
  on pt.policyid = po.pol_num             --MPC: SR9
-- left outer join msit_s_AGMPAY pa           --MPC: SR9
