 left outer join msit_CommissionStatementPeriods csp  --MPC: SR9
  on CAST(CONVERT(NVARCHAR, a.CreateDateTime, 112) AS DATETIME) between csp.PeriodStartDate and csp.PeriodEndDate   --MPC: SR9
 left outer join #InvalidTASHH t1             --MPC: SR9
  on t1.id = a.TransAgentSplitHierarchyHistoryID    --MPC: SR9
 left outer join msit_TransAgentSplitHierarchyHistory b --MPC: SR9
  on a.TransAgentSplitHierarchyHistoryID = b.[ID]   --MPC: SR9
-- inner join mstt_Agents ag              --MPC: SR9
--  on ag.code = a.agent_code             --MPC: SR9
 left outer join #Owner t2                --MPC: SR9
  on t2.AGMFILid = a.ID               --MPC: SR9
-- where a.transactionid *= p.id            --MPC: SR9

select @RowCount = @@rowcount   --MPC:25/01/2010
set @ProcessMessage = @Mode + ' - Select S_AGMFIL Records : Count = ' + convert(varchar(10), @RowCount)   --MPC:25/01/2010
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client    --MPC:25/01/2010

