/************************************************************************************************
  PERFORM DATABASE UPDATES
************************************************************************************************/

--Full Refresh - Truncate Table, Drop Indexes, Insert then Create Undexes
IF @Mode = 'FULL' --MPC:25/01/2010
BEGIN       --MPC:25/01/2010

  --Clear the target table first
  Truncate table mstt_PaymentsPending

  DROP  INDEX mstt_PaymentsPending.IX_PaymentPendingCommType
  DROP  INDEX mstt_PaymentsPending.IX_PaymentPendingAgent
  DROP  INDEX mstt_PaymentsPending.IX_PaymentPendingSO
  DROP  INDEX mstt_PaymentsPending.IX_PaymentsPending_PACC
  DROP  INDEX mstt_PaymentsPending.IX_PaymentsPending_Trial
  DROP  INDEX mstt_PaymentsPending.IX_PaymentsPending_FranAgntCd_AccAgentCd_DirAuthAgntCd_TranID_CreateDT_CommTyp_PymtDuDt_AMT
  DROP  INDEX mstt_PaymentsPending.PK_mstt_PaymentsPending      --MPC: 01/06/08 (1)
  --ALTER TABLE mstt_PaymentsPending DROP CONSTRAINT PK_mstt_PaymentsPending  --MPC: 01/06/08 (1)

  --Main Insert
  insert into mstt_PaymentsPending
  select * from #mstt_PaymentsPending

  select @RowCount = @@rowcount       --MPC:25/01/2010
  set @ProcessMessage = @Mode + ' - mstt_PaymentsPending INSERTED : Count = ' + convert(varchar(10), @RowCount) --MPC:25/01/2010
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client      --MPC:25/01/2010

  CREATE  CLUSTERED  INDEX [PK_mstt_PaymentsPending] ON [dbo].[mstt_PaymentsPending](ID) WITH (DATA_COMPRESSION=PAGE) ON [PRIMARY]
  CREATE  INDEX [IX_PaymentPendingCommType] ON [dbo].[mstt_PaymentsPending](CommissionType,Due_Date) WITH (DATA_COMPRESSION=PAGE) ON [PRIMARY]
  CREATE  INDEX [IX_PaymentPendingAgent] ON [dbo].[mstt_PaymentsPending](Agent_Code,CommissionType,Due_Date,StandingOrderCode) WITH (DATA_COMPRESSION=PAGE) ON [PRIMARY]
  CREATE  INDEX [IX_PaymentPendingSO] ON [dbo].[mstt_PaymentsPending](StandingOrderCode) WITH (DATA_COMPRESSION=PAGE) ON [PRIMARY]
  CREATE  INDEX [IX_PaymentsPending_PACC] ON [dbo].[mstt_PaymentsPending](PACC_ID) WITH (DATA_COMPRESSION=PAGE) ON [PRIMARY]
  CREATE  INDEX [IX_PaymentsPending_Trial] ON [dbo].[mstt_PaymentsPending](ID,CommissionType,PaymentDueDate,Agent_Code,Amount) WITH (DATA_COMPRESSION=PAGE) ON [PRIMARY]
  CREATE  INDEX [IX_PaymentsPending_FranAgntCd_AccAgentCd_DirAuthAgntCd_TranID_CreateDT_CommTyp_PymtDuDt_AMT] ON [dbo].[mstt_PaymentsPending](FranchiseAgentCode,AccessAgentCode,DirectlyAuthorisedAgentCode,TransactionID,CreateDateTime,CommissionType,PaymentDueDate,Amount) WITH (DATA_COMPRESSION=PAGE) ON [PRIMARY]

  exec msp_ProcessLog @PhaseEnd, 'Indexes CREATED', null, @ProgressModule, @Client

  --MPC:25/01/2010  DatabaseUPDATE Changes - START

END --  @Mode = 'FULL'

--Delete existing rows in Movements List then Insert new Movements
IF @Mode = 'MOVE'   
BEGIN

  --DELETE Movements only
  DELETE FROM mstt_PaymentsPending
  WHERE ID IN (Select ID From #AGMFILChanges)   

  select @RowCount = @@rowcount
  set @ProcessMessage = @Mode + ' - Delete Data : Count = ' + convert(varchar(10), @RowCount)   --MPC:25/01/2010
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client      --MPC:25/01/2010

  --Main Insert
  insert into mstt_PaymentsPending
  select * from #mstt_PaymentsPending

  select @RowCount = @@rowcount
  set @ProcessMessage = @Mode + ' - InsertData : Count = ' + convert(varchar(10), @RowCount) --MPC:25/01/2010
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client    --MPC:25/01/2010

  --UPDATE STATISTICS mstt_PaymentsPending with fullscan	--AG 10/10/2016
  UPDATE STATISTICS mstt_PaymentsPending					--AG 21/12/2017

  exec msp_ProcessLog @PhaseEnd, 'UPDATE STATISTICS', null, @ProgressModule, @Client

END --@Mode = 'MOVE'

--MPC:25/01/2010  DatabaseUPDATE Changes - END

/******************************************************************************************************************
    END of PROCESSING
******************************************************************************************************************/
drop table #mstt_PaymentsPending

--END
exec msp_ProcessLog @PhaseEnd, @ProcName, null, @Module, @Client    --MPC:25/01/2010






