/*
--MPC: SR9 - moved to main Select above
update
 mstt_PaymentsPending
Set
 StrategicAllianceAgentCode = b.StrategicAllianceAgentCode,
 AccessAgentCode    = b.AccessAgentCode,
 FranchiseAgentCode   = b.FranchiseAgentCode,
