  exec msp_ProcessLog @PhaseEnd, 'Indexes CREATED', null, @ProgressModule, @Client

  --MPC:25/01/2010  DatabaseUPDATE Changes - START

END --  @Mode = 'FULL'

--Delete existing rows in Movements List then Insert new Movements
IF @Mode = 'MOVE'   
BEGIN

