CREATE PROCEDURE [dbo].[mstp_Plans] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
*******************************************************************************/
-- PROCEDURE BODY GOES HERE
begin
--Clear the target table first
truncate table mstt_Plans
--Get the grain records from the import table
insert into mstt_plans
  (CODE, 
  DESCN, 
  CTP_CODE, 
  POL_TYPE, 
  PENS_TYPE, 
  CommissionCalculation, 
  PlanCategory, 
  PlanCategoryDescription, 
  FullMonitoring, 
  KPIStandard, 
  CorporatePlan, 
  LivePlan, 
  RiskRating, 
  InitialCheckingPeriod, 
  OngoingChecking, 
  CustomerCare, 
  PreApproval, 
  CommissionCalculation2Year)
select 
  CODE,
  DESCN,
  CTP_CODE,
  POL_TYPE,
  PENS_TYPE,
  CommissionCalculation,
  PlanCategory,
  null as PlanCategoryDescription, 
  null as FullMonitoring, 
  null as KPIStandard, 
  CorporatePlan,
  LivePlan,
  RiskRating,
  InitialCheckingPeriod,
  OngoingChecking,
  CustomerCare,
  PreApproval,
  CommissionCalculation2Year
from msit_s_plans
--get the other fields from CodePlanCategories
update p
set   PlanCategoryDescription = cpc.Description, 
  FullMonitoring    = cpc.FullMonitoring, 
  KPIStandard   = cpc.KPIStandard 
from mstt_plans p
  inner join msit_CodePlanCategories cpc 
    on p.PlanCategory = cpc.Code
end

