CREATE PROCEDURE [dbo].[mstp_Policies] WITH RECOMPILE --,ENCRYPTION
	/* Param List */
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary	: %Summary%
Author	: Matt Kennedy
Created	: %DateCreated%  
					
-- Amended : 13/09/2007 - PR - Changes for SR8 - amend code around OriginatingSource
<doc>
	<summary>%Summary%</summary>
	<param name='%Param1Name%'>%Param1Summary%</param>
	<returns>%Returns%</returns>
	<author>Matt Kennedy</author>
	<revision>
		<dateCreated></dateCreated>
		<author>/<author>
		<summary></summary>
	</revision>
</doc>

*******************************************************************************/


-- PROCEDURE BODY GOES HERE
begin

--Clear the target table first
Truncate Table mstt_Policies


--Get the data from the Import Table
insert into mstt_Policies
	(
	POL_NUM,
	CLIENT_NUM,
	JOINT_NUM,
	SCHEME_NUM,
	POL_TYPE,
	PolicyTypeDescription,
	STATUS,
	StatusDescription,
	CONT_NUM,
	COMP_CODE,
	CompanyName,
	PLAN_CODE,
	PlanDescription,
	START_DATE,
	STOP_DATE,
	REN_DATE,
	TERM_Y,
	TERM_M,
	SOLD,
	AdminMethod,
	LA_DATE,
	INFORCE,
	PROP_DATE,
	CONSULTANT,
	PAY_METHOD,
	WP_UL,
	ProductCode,
	ProductCodeDescription,
	TotalPremiumToDate,
	TotalPremiumToDateDate,
	CreateDate,
	BusinessType,
	BusinessTypeDescription,
	CurrentRegularPremium,
	CurrentPremiumFrequency,
	TotalSinglePremiums,
	SubmissionSetID,
	BenefitAmount,
	InTrust,
	Discontinuance,
	DiscontinuanceReasons,
	AssessmentCheckPerformed,
	ApplicationIssued,
	PolicyRef,
	Indexed,
	SellingAgentCode,
	ServicingAgentCode,
	OriginatingSource,
	SalesProcess,
	Risk,
	NBCCReferralReasonCode,
	Replacement,
	UndisclosedReplacement,
	RPA,
	ReplacedPremium,
	MortgageRelated,
	RetirementInvestment,
	PPSwitch,
	EPSReference,
	ReferralCode,
	SuspendCommission,
	SuspendCommissionLastUpdated,
	SoldThroughB30,
	ProductType,			
	ReportingProductCode,	
	RegulationDefault,
	DualSalesProcess,
	APE_Flag,
	RevenueCategoryCode,	
	ProductSubGroupCode,		
	ProductGroupCode,			
	ProductCategoryCode,		
	ProductProviderCode,		
	ReportingProductProviderCode,
	CommRepProductProviderCode,
	ZFSGroupFlag,
	Regulation,
	ProposalTransactionNumber,
	SalesQualityASDLevelCode,
	SalesQualityRSMLevelCode,
	SalesQualitySQMLevelCode,
	SalesQualityPSLevelCode,
	SalesQualityAdviserLevelCode,
	PracticeCode
	)
select 
	POL_NUM, 
	CLIENT_NUM, 
	JOINT_NUM, 
	SCHEME_NUM, 
	POL_TYPE, 
	null as PolicyTypeDescription,
	STATUS, 
	null as StatusDescription,
	CONT_NUM, 
	COMP_CODE,
	null as CompanyName, 
	PLAN_CODE, 
	null as PlanDescription,
	START_DATE, 
	STOP_DATE, 
	REN_DATE, 
	TERM_Y, 
	TERM_M, 
	SOLD, 
	null as AdminMethod,
	LA_DATE, 
	INFORCE, 
	PROP_DATE, 
	CONSULTANT, 
	PAY_METHOD, 
	WP_UL, 
	ProductCode,
	null as ProductCodeDescription,
	TotalPremiumToDate, 
	TotalPremiumToDateDate, 
	CreateDate, 
	BusinessType,
	null as BusinessTypeDescription,
	CurrentRegularPremium, 
	CurrentPremiumFrequency, 
	TotalSinglePremiums, 
	SubmissionSetID, 
	BenefitAmount, 
	InTrust, 
	Discontinuance,
	DiscontinuanceReasons,
	AssessmentCheckPerformed,
	ApplicationIssued,
	PolicyRef,
	Indexed,
	null as SellingAgentCode,
	null as ServicingAgentCode,
	null as OriginatingSource,
	null as SalesProcess,
	null as Risk,
	null as NBCCReferralReasonCode,
	null as Replacement,
	null as UndisclosedReplacement,
	null as RPA,
	null as ReplacedPremium,
	null as MortgageRelated,
	null as RetirementInvestment,
	null as PPSwitch,
	null as EPSReference,
	null as ReferralCode,
	null as SuspendCommission,
	null as SuspendCommissionLastUpdated,
	null as SoldThroughB30,
	null as ProductType,			
	null as ReportingProductCode,	
	null as RegulationDefault,
	null as DualSalesProcess,
	null as APE_Flag,
	null as RevenueCategoryCode,	
	null as ProductSubGroupCode,		
	null as ProductGroupCode,			
	null as ProductCategoryCode,		
	null as ProductProviderCode,		
	null as ReportingProductProviderCode,
	null as CommRepProductProviderCode,
	null as ZFSGroupFlag,
	null as Regulation,
	null as ProposalTransactionNumber,
	null as SalesQualityASDLevelCode,
	null as SalesQualityRSMLevelCode,
	null as SalesQualitySQMLevelCode,
	null as SalesQualityPSLevelCode,
	null as SalesQualityAdviserLevelCode,
	null as PracticeCode
from msit_S_POLMAI

	--JNG
	ORDER BY  
	POL_NUM, 
	CLIENT_NUM, 
	JOINT_NUM, 
	SCHEME_NUM, 
	POL_TYPE, 
	STATUS, 
	CONT_NUM, 
	COMP_CODE,
	PLAN_CODE, 
	START_DATE, 
	STOP_DATE, 
	REN_DATE, 
	TERM_Y, 
	TERM_M, 
	SOLD, 
	LA_DATE, 
	INFORCE, 
	PROP_DATE, 
	CONSULTANT, 
	PAY_METHOD, 
	WP_UL, 
	ProductCode,
	TotalPremiumToDate, 
	TotalPremiumToDateDate, 
	CreateDate, 
	BusinessType,
	CurrentRegularPremium, 
	CurrentPremiumFrequency, 
	TotalSinglePremiums, 
	SubmissionSetID, 
	BenefitAmount, 
	InTrust, 
	Discontinuance,
	DiscontinuanceReasons,
	AssessmentCheckPerformed,
	ApplicationIssued,
	PolicyRef,
	Indexed
	--JNG   



--get other fields from PolicyQualityCheckB30
update t
set 
	OriginatingSource 		= pqc.OriginatingSourceID,
	SalesProcess 			= pqc.SalesProcess,
	Risk 				= pqc.Risk,		
	Replacement 			= pqc.Replacement,
	UndisclosedReplacement 		= pqc.UndisclosedReplacement,
	RPA 				= pqc.RPA,
	ReplacedPremium 		= pqc.ReplacedPremium,
	MortgageRelated 		= pqc.MortgageRelated,
	RetirementInvestment 		= pqc.RetirementInvestment,
	PPSwitch 			= pqc.PPSwitch,
	EPSReference 			= pqc.EPSReference,
	ReferralCode 			= pqc.ReferralCode,
	SuspendCommission 		= pqc.SuspendCommission,
	SuspendCommissionLastUpdated 	= pqc.SuspendCommissionLastUpdated,
	SuspendCommInd			= (case when pqc.SuspendCommission = 1 then 'Y'
									when pqc.SuspendCommission = 0 then 'C'
									else NULL end) --ID 19
from mstt_Policies t
	inner join msit_PolicyQualityCheckB30 pqc
		on t.POL_NUM = pqc.PolicyID

--get other fields from msit_PolicyAgentsB30
update t
set 
	SellingAgentCode 	= pa.SellingAgentCode,
	ServicingAgentCode 	= pa.ServicingAgentCode
from mstt_Policies t
	inner join msit_PolicyAgentsB30 pa
		on t.POL_NUM = pa.PolicyID
		


--get other fields from msit_PolicyB30
update t
set
	SoldThroughB30 = p.SoldThroughB30
from mstt_Policies t
	inner join msit_PolicyB30 p
		on t.POL_NUM = p.PolicyID

--get other fields from Mstt_ProductHierarchy
update t
set 	
	ProductType		= ph.ProductType,			
	ReportingProductCode 	= ph.ReportingProductCode,		
	ProductSubGroupCode 	= ph.ProductSubGroupCode,		
	ProductGroupCode	= ph.ProductGroupCode,			
	ProductCategoryCode 	= ph.ProductCategoryCode,		
	ProductProviderCode 	= ph.ProductProviderCode,		
	ReportingProductProviderCode = ph.ReportingProductProviderCode,
	CommRepProductProviderCode = ph.CommRepProductProviderCode,
	RegulationDefault	= ph.RegulationDefault,
	DualSalesProcess	= ph.DualSalesProcess,
	APE_Flag		= ph.APE_Flag,
	RevenueCategoryCode	= ph.RevenueCategoryCode,
	ZFSGroupFlag		= ph.ZFSGroupFlag
	
from mstt_Policies t
	inner join mstt_ProductHierarchy ph
		on t.ProductCode = ph.ProductCode


					
		
--CR 70: (Regulation) 
--If salesProcess = 0 and DualSalesProcess = Y then set to 'COB' else set to RegulationDefault 
update t
set 
	Regulation =	Case when SalesProcess = 0 and DualSalesProcess = 'Y' then 'COB' 
			else RegulationDefault end
from mstt_Policies t	

--Get NBCCReferralReasonCode
select n.Policy_Id, max(case when n.NBCCReferralReasonCode = 'RISK' then '333333'
					when n.NBCCReferralReasonCode = 'RANDOM' then '222222'
					else '111111' end) as NBCCReferralReasonCode
into #NBCCReferralReasonCode
from mstt_CaseNBCCSelection n
group by n.Policy_Id

update #NBCCReferralReasonCode
set NBCCReferralReasonCode = case when NBCCReferralReasonCode = '333333' then 'RISK'
					when NBCCReferralReasonCode = '222222' then 'RANDOM'
					else 'OTHER' end

update p
set NBCCReferralReasonCode = n.NBCCReferralReasonCode
from mstt_Policies p
	inner join #NBCCReferralReasonCode n
		on p.Pol_Num = n.Policy_Id
		
update p
set NBCCReferralReasonCode = 'OTHER'
from mstt_Policies p
where NBCCReferralReasonCode is null
		
drop table #NBCCReferralReasonCode

		

--get Code descriptions
update t
set PolicyTypeDescription = dl.Description
from mstt_Policies t
	inner join msdt_DropLists dl
		on t.POL_TYPE = dl.Code
where dl.CodeType = 'PolicyType'


update t
set StatusDescription = dl.Description
from mstt_Policies t
	inner join msdt_DropLists dl
		on cast(t.STATUS as varchar(30)) = dl.Code
where dl.CodeType = 'PolicyStatus'


update t
set BusinessTypeDescription = dl.Description
from mstt_Policies t
	inner join msdt_DropLists dl
		on t.BusinessType = dl.Code
where dl.CodeType = 'BusinessType'


update t
set CompanyName = pp.ProductProviderName
from mstt_Policies t
	inner join mstt_ProductProviders pp
		on t.COMP_CODE = pp.ProductProviderCode


update t
set PlanDescription = p.DESCN
from mstt_Policies t
	inner join mstt_Plans p
		on t.PLAN_CODE = p.CODE



end




GO
/****** Object:  StoredProcedure [dbo].[mstp_Policies_Part2]    Script Date: 7/3/2026 3:44:25 PM ******/
