CREATE PROCEDURE [dbo].[mstp_Policies_Part2]
AS
/******************************************************************************
Chris Mellors 23/05/2023
This code was removed from mstp_PolicyTransactions
The intention is to merge this code into mstp_Policies
*********************************************************************************/
BEGIN
	SET NOCOUNT ON;

	--Set the Policy Fields. These fields are done now rather than in the mstp_Policies proc, as they 
	--depend on details that are not known until PolicyTransactions are built.
	--Set the ProposalTransactionNumber. This is used in quality reporting, and will be put on mstt_CaseCheck.
	--Get the lowest numbered InForce Transaction for the Policy
	select pt.PolicyId, min(e.TransactionId) as LowestInForceTransaction
	into #InForceTransactions
	from mstt_PolicyTransactions pt
	  inner join msit_S_PACC e    --MPC: 25/04/08
		on pt.Id = e.TransactionId
	where e.TransactionId is not null
	group by pt.PolicyId
	order by 1

	--Get the highest numbered Proposal Transaction, which is lower than the InforceTransaction above
	select pt.PolicyId, max(pt.Id) as HighestProposalTransaction
	into #ProposalTransactions
	from mstt_PolicyTransactions pt
	  inner join #InForceTransactions ift
		on pt.PolicyId = ift.PolicyId
	where pt.Id < ift.LowestInForceTransaction
	and pt.TransType = '39'
	group by pt.PolicyId
	order by 1

	--Get Highest Proposal Transactions for Policies that do not have Inforce Transactions
	insert into #ProposalTransactions
	select pt.PolicyId, max(pt.Id)
	from mstt_PolicyTransactions pt
	where not exists (select 'x' from #ProposalTransactions pt2
		where pt2.PolicyId = pt.PolicyId)
	and pt.TransType = '39'
	group by pt.PolicyId

	--Update the Policy with the Proposal Transaction number found above
	update p
	set ProposalTransactionNumber = HighestProposalTransaction
	from mstt_Policies p
	  inner join #ProposalTransactions pt
		on p.Pol_Num = pt.PolicyId
	--where p.Regulation <> 'MCOB'      --MPC: 25/03/08

	drop table #InForceTransactions
	drop table #ProposalTransactions

	--set the SalesQualityAdviserLevelCode
	update t
	set  SalesQualityAdviserLevelCode = coalesce(pt.AgentCode,t.ServicingAgentCode) --MPC: 25/03/08
	from mstt_Policies t
	  inner join mstt_PolicyTransactions pt
		on t.ProposalTransactionNumber = pt.Id
	where SalesQualityAdviserLevelCode is null

	--get other fields from AgentQualityHierarchy
	update t
	set SalesQualityASDLevelCode = aqh.SalesQualityASDLevelCode,
	  SalesQualityRSMLevelCode = aqh.SalesQualityRSMLevelCode,
	  SalesQualitySQMLevelCode = aqh.SalesQualitySQMLevelCode,
	  SalesQualityPSLevelCode = aqh.SalesQualityPSLevelCode,
	  PracticeCode = aqh.PracticeCode
	from mstt_Policies t
	  inner join mstt_AgentQualityHierarchy aqh
		on t.SalesQualityAdviserLevelCode = aqh.AgentCode
		and case when t.ProductGroupCode = 3 then t.Start_Date else t.Prop_Date end
		  between aqh.AgentHierarchyStartDate and aqh.AgentHierarchyEndDate
END
GO
