Alan Groves 11/09/2013
Fix required to the Initial Period for PRUPROTECT and L&G products to ensure
the max value is 24 months. Currently this is set incorrectly by the Swift
Commission Shape calculation. However, the calculation cannot be changed 
because the wrong commission amount would then be calculated.

Alan Groves 24/09/2013
Append above fix to update CommBasedOnPercent as well.

Chris Mellors 09/05/23
Redesign from full rebuild to incremental update

*********************************************************************************/
BEGIN
	SET NOCOUNT ON;
	SET XACT_ABORT ON;

	DECLARE	 @StartDate			DATETIME
			,@EndDate			DATETIME
			,@ProcessMessage	VARCHAR(100)
			;

	DECLARE @SummaryOfChanges TABLE(Change VARCHAR(20));

	CREATE TABLE #CommissionStatementPeriods
	(
		[date]	DATETIME NOT NULL PRIMARY KEY CLUSTERED, 
		[month]	DATETIME		
	);

	CREATE TABLE #TransactionType
	(
		[Type]	TINYINT NOT NULL PRIMARY KEY CLUSTERED, 
		[Description]	VARCHAR(50)		
	);

	CREATE TABLE #CommissionType
	(
		[Type]	CHAR(1) NOT NULL PRIMARY KEY CLUSTERED, 
		[Description]	VARCHAR(50)		
	);

	CREATE TABLE #Frequency
	(
		[Type]	TINYINT NOT NULL PRIMARY KEY CLUSTERED, 
		[Description]	VARCHAR(50)		
	);

	CREATE TABLE #IssuedTransactions
	(
		[TransactionId] INT NOT NULL PRIMARY KEY CLUSTERED
	);

	CREATE TABLE #WrittenTransactions
	(
		[PolicyID] INT NOT NULL PRIMARY KEY CLUSTERED,
		[TransactionWrittenDate] DATETIME
	);

	CREATE TABLE #MinTransactionDate
	(
		[TransactionID] INT NOT NULL PRIMARY KEY CLUSTERED,
		[MinTransactionDate] DATETIME
	);

	CREATE TABLE #ActiveTransactions
	(
		[ID] INT NOT NULL PRIMARY KEY CLUSTERED,
		[PolicyID] INT NOT NULL,
		[Amount] FLOAT,
		[ProposalDate] DATETIME,
		[ProposalID] INT,
		[ProposalMinTransactionDate] DATETIME
	);

	CREATE TABLE #Proposals
	(
		[ID] INT NOT NULL PRIMARY KEY CLUSTERED,
		[PolicyID] INT NOT NULL,
		[Amount] FLOAT,
		[ProposalDate] DATETIME,
		[ActiveID] INT,
		[ActiveMinTransactionDate] DATETIME
	);

	/* Generate staging data */

	SELECT	 @StartDate = MIN(PeriodStartDate)
			,@EndDate = MAX(PeriodEndDate)
	FROM	dbo.msit_CommissionStatementPeriods;

	WITH theDates AS
	(
		SELECT	@StartDate AS theDate
		UNION ALL
		SELECT	DATEADD(DAY, 1, theDate)
		FROM	theDates
		WHERE	DATEADD(DAY, 1, theDate) <= @EndDate
	)
	INSERT #CommissionStatementPeriods([date],[month]) 
		SELECT	 theDate
				,csp.Month
		FROM theDates
		JOIN dbo.msit_CommissionStatementPeriods csp ON theDate BETWEEN csp.PeriodStartDate and csp.PeriodEndDate
		OPTION (MAXRECURSION 0);

	INSERT #TransactionType([Type],[Description]) 
		SELECT	 CONVERT(TINYINT, wcd.Code)
				,CONVERT(VARCHAR(50), COALESCE(wcd.ShortDescription, wcd.LongDescription, wcd.Description))
		FROM	dbo.msit_MIWarehouseCodesAndDescriptions wcd
		WHERE	wcd.ColumnName = 'PolicyTransactionType';

	INSERT #CommissionType([Type],[Description]) 
		SELECT	 CONVERT(CHAR(1), wcd.Code)
				,CONVERT(VARCHAR(50), COALESCE(wcd.ShortDescription, wcd.LongDescription, wcd.Description))
		FROM	dbo.msit_MIWarehouseCodesAndDescriptions wcd
		WHERE	wcd.ColumnName = 'CommType'; --Was CommissionType. TPR: 1474

	INSERT #Frequency([Type],[Description]) 
		SELECT	 CONVERT(TINYINT, wcd.Code)
				,CONVERT(VARCHAR(50), COALESCE(wcd.ShortDescription, wcd.LongDescription, wcd.Description))
		FROM	dbo.msit_MIWarehouseCodesAndDescriptions wcd
		WHERE	wcd.ColumnName = 'Frequency';

	INSERT #IssuedTransactions([TransactionId])
		SELECT	DISTINCT TransactionId
		FROM	dbo.sa_swift_S_PACC
		WHERE	TransactionID IS NOT NULL;

	INSERT #WrittenTransactions ([PolicyID], [TransactionWrittenDate])
		SELECT	 PolicyID
				,MIN( TransactionDate ) AS [TransactionWrittenDate]
		FROM	dbo.sa_swift_PolicyTransactions
		WHERE	TransType = 39
		GROUP BY PolicyID;

	INSERT #MinTransactionDate (TransactionID, MinTransactionDate)
		SELECT	 sp.TransactionID
				,MIN(ctid.TransactionDate) AS MinTransactionDate
		FROM	dbo.sa_swift_S_AGTCOM sp
		JOIN	dbo.mstt_Commtraninitialdate ctid ON ctid.ID = sp.ID
		GROUP BY sp.TransactionID;

	INSERT #ActiveTransactions (ID,PolicyID,Amount,ProposalDate)
		SELECT	 ID
				,PolicyID
				,Amount
				,ProposalDate
		FROM	dbo.sa_swift_PolicyTransactions pt
		WHERE	EXISTS	(	SELECT	1 
							FROM	dbo.sa_swift_S_PACC sp
							WHERE	sp.TYPE NOT IN (5,6) 
							AND		sp.STATUS IN (2,3)
							AND		sp.TransactionID = pt.ID
						);

	INSERT #Proposals (PolicyID,ID,Amount,ProposalDate)
		SELECT	 PolicyID
				,ID
				,Amount
				,ProposalDate
		FROM	dbo.sa_swift_PolicyTransactions pt
		WHERE	TransType = 39;

	-- Update Proposals with matching Active
	UPDATE	p
	SET		 p.ActiveID = a.ActiveID
			,p.ActiveMinTransactionDate = mtd.MinTransactionDate
	FROM		#Proposals p
	INNER JOIN	(
					SELECT	 pr.ID
							,MIN(ac.ID) AS ActiveID 
					FROM	#Proposals pr 
					JOIN	#ActiveTransactions ac	ON pr.PolicyID = ac.PolicyID 
													AND		pr.ID < ac.ID
													AND		(	pr.Amount = ac.Amount 
															OR	pr.ProposalDate = ac.ProposalDate
															)
					GROUP BY pr.ID
				) a ON a.ID = p.ID
	LEFT JOIN	#MinTransactionDate mtd ON mtd.TransactionID = a.ActiveID;

	-- Update Active with matching Proposal
	UPDATE	a
	SET		 a.ProposalID = p.ProposalID
			,a.ProposalMinTransactionDate = mtd.MinTransactionDate
	FROM		#ActiveTransactions a
	INNER JOIN	(
					SELECT	 ActiveID
							,MAX(ID) AS ProposalID 
					FROM	#Proposals
					GROUP BY ActiveID
				) p ON p.ActiveID = a.ID
	LEFT JOIN	#MinTransactionDate mtd ON mtd.TransactionID = p.ProposalID;

	/* Update mstt_PolicyTransactions */
	BEGIN TRY
		BEGIN TRANSACTION

		-- Rows to Delete
		DELETE	mpt
		OUTPUT 'DELETE' INTO @SummaryOfChanges
		FROM	dbo.mstt_PolicyTransactions mpt
		WHERE	NOT EXISTS (SELECT 1 FROM dbo.sa_swift_PolicyTransactions spt WHERE spt.ID = mpt.ID);

		-- Rows to Upsert
		WITH InsUpd AS
				(
				SELECT
						 pt.ID 
						,pt.PolicyID
						,pt.TransType
						,tt.Description as TransTypeDesc
						,case when pt.AdminMethod is null or len(pt.AdminMethod) = 0 then 'A' else pt.AdminMethod end AS AdminMethod -- BI262 default to New Business
						,pt.TransactionDate
						,CASE WHEN it.TransactionID IS NOT NULL AND wt.PolicyID IS NOT NULL THEN wt.TransactionWrittenDate WHEN pt.TransType = 39 THEN pt.TransactionDate ELSE NULL END AS TransactionWrittenDate
						,pt.NotificationDate
						,pt.AgentCode
						,pt.SubsequentPurchase
						,pt.TransactionNumber
						,pt.StartDate
						,pt.TermYears
						,pt.TermMonths
						,pt.FinishDate
						,pt.Frequency
						,f.Description as FrequencyDescription
						,CASE WHEN ph.ProductGroupCode = '3' THEN NULL ELSE ABS(pt.Amount) END AS Amount
						,CASE WHEN ph.ProductGroupCode = '3' THEN ABS(pt.Amount) ELSE NULL END AS MortgageAmount
						,CASE	WHEN ph.APE_Flag = 'N'	THEN 0 
								WHEN pt.Frequency = 6	THEN ABS(pt.Amount) / 10 --'S'       --:MPC 16/01/08
								WHEN pt.Frequency = 2	THEN ABS(pt.Amount) * 12 --'M'
								WHEN pt.Frequency = 5	THEN ABS(pt.Amount)		 --'A' 
								WHEN pt.Frequency = 4	THEN ABS(pt.Amount) * 2  --'B' (Half-Yearly)
								WHEN pt.Frequency = 3	THEN ABS(pt.Amount) * 4  --'Q'
								ELSE NULL 
						 END AS APE
						,pt.CurrentRegularAmount
						,pt.CommCompanyCode
						,pt.CommPlanCode
						,pt.CommProductCode
						,pt.CommInputDate
						,pt.CommPayInFull
						,pt.CommType
						,ct.Description as CommissionTypeDesc
						,pt.CommInitialAmount
						,CASE WHEN acia.ID IS NOT NULL THEN ISNULL(ABS(pt.Amount),0) + acia.AdjustmentAmount END AS AdjustedCommInitialAmount
						,pt.CommCalculatedAmount
						,ISNULL(ipf.CommBasedOnPercent, pt.CommBasedOnPercent) AS CommBasedOnPercent
						,pt.CommReducedToPercent
						,pt.CommCalculatedUplift
						,pt.CommExpectedUplift
						,pt.CommDeductedAtSource
						,pt.CommFirstReceiptDate
						,ISNULL(ipf.CommInitialPeriod, pt.CommInitialPeriod) AS CommInitialPeriod
						,pt.CommRenewalFirstPayment
						,pt.CommRenewalAmount
						,CASE WHEN acra.ID IS NOT NULL AND pt.CommType <> 'L' THEN ISNULL(ABS(pt.Amount),0) + acra.AdjustmentAmount END AS AdjustedCommRenewalAmount
						,pt.CommRenewalFrequency
						,pt.CommOverrideDate
						,pt.CommOverrideReason
						,pt.CommReclaim
						,pt.CommFeeNetAmount
						,pt.CommFeeVATAmount
						,pt.CommFeeDateReceived
						,pt.LastPaymentDate
						,pt.CommLevelInstallment
						,pt.CommLevelFinalInstallment
						,pt.CommLevelDebited
						,pt.CommLevelFinalInstallmentDate
						,pt.CommLevelLastInstallmentDate
						,pt.StopPayingLevelCommission
						,pt.CommissionDisclosed
						,pt.CreateDateTime
						,pt.InForceDate
						,pt.ProposalDate
						,pt.NetPremium
						,pt.SuspendCommission
						,pt.CreatedBy
						,pt.CreatedDate
						,pt.AuthorisedBy
						,pt.AuthorisedDate
						,pt.CommReinvestTrailFees
						,pt.CommTrailFeesStartAfter
						,NULL AS CommTrailFeesToNetInForce
						,pt.CommTrailFeesAmount
						,pt.CommTrailFeesPeriod
						,pt.CommBaseAmount
						,pt.CommTrialBalanceGiveUpPercent
						,pt.LastIndemnityLiabilityCalculated
						,pt.OutstandingIndemnityLiability
						,pt.CommOriginalBaseAmount
						,pt.CommOriginalInitialAmount
						,pt.CommAccrualYears
						,pt.CommSacrificeTrailFee
						,pt.SubsequentReason
						,pt.RenewalRate
						,NULL AS AdviceBy
						,pt.CodeCommissionShapeID
						,ph.ProductType
						,CAST(ph.ReportingProductCode AS VARCHAR(255)) AS ReportingProductCode
						,ph.APE_Flag
						,CAST(ph.RevenueCategoryCode AS VARCHAR(255)) AS RevenueCategoryCode
						,CAST(ph.ProductSubGroupCode AS VARCHAR(255)) AS ProductSubGroupCode
						,CAST(ph.ProductGroupCode AS VARCHAR(255)) AS ProductGroupCode
						,CAST(ph.ProductCategoryCode AS VARCHAR(255)) AS ProductCategoryCode
						,ph.ProductProviderCode
						,ph.ReportingProductProviderCode
						,ph.CommRepProductProviderCode
						,ph.ZFSGroupFlag
						,tm.month AS TransactionMonth
						,cm.month AS CommissionMonth
						,CASE WHEN a.ID IS NOT NULL THEN pt.ID WHEN p.ID IS NOT NULL THEN p.ActiveID END AS IssuedTranID
						,CASE WHEN a.ID IS NOT NULL THEN mtd.MinTransactionDate WHEN p.ID IS NOT NULL THEN p.ActiveMinTransactionDate END AS IssuedDate
						,CASE WHEN a.ID IS NOT NULL THEN a.ProposalID WHEN p.ID IS NOT NULL THEN pt.ID END AS WrittenTranID
						,CASE WHEN a.ID IS NOT NULL THEN a.ProposalMinTransactionDate WHEN p.ID IS NOT NULL THEN mtd.MinTransactionDate END AS WrittenDate
				FROM		dbo.sa_swift_PolicyTransactions pt
				LEFT JOIN	dbo.mstt_ProductHierarchy ph ON pt.CommProductCode = ph.ProductCode
				LEFT JOIN	#TransactionType tt ON tt.Type = pt.TransType
				LEFT JOIN	#CommissionType ct ON ct.Type = pt.CommType
				LEFT JOIN	#Frequency f ON f.Type = pt.Frequency
				LEFT JOIN	#CommissionStatementPeriods tm ON tm.date = DATEADD(DAY, 0, DATEDIFF(DAY, 0, pt.TransactionDate))
				LEFT JOIN	(
								SELECT	TransactionID,
										MIN(DATEADD(DAY, 0, DATEDIFF(DAY, 0, DATE_RECV))) AS [Min_Date_Recv]
								FROM	dbo.sa_swift_S_PACC
								WHERE	STATUS IN (2,3)             --MPC: 25/04/08
								AND		DATE_RECV BETWEEN @StartDate AND @EndDate
								GROUP BY TransactionID
							) e ON e.TransactionID = pt.ID
				LEFT JOIN	#CommissionStatementPeriods cm ON cm.date = DATEADD(DAY, 0, DATEDIFF(DAY, 0, e.Min_Date_Recv))
				LEFT JOIN	#IssuedTransactions it ON it.TransactionID = pt.ID
				LEFT JOIN	#WrittenTransactions wt ON wt.PolicyID = pt.PolicyID
				LEFT JOIN	#ActiveTransactions a ON a.ID = pt.ID
				LEFT JOIN	#Proposals p ON p.ID = pt.ID
				LEFT JOIN	#MinTransactionDate mtd ON mtd.TransactionID = pt.ID
				LEFT JOIN	(	-- Fix the Initial Period - AG 11/09/2013
								SELECT	 pt.ID
										,CASE WHEN pt.CommInitialPeriod > 24 THEN 24 ELSE pt.CommInitialPeriod END AS CommInitialPeriod
										,ROUND(	(	(pt.CommBaseAmount+ISNULL(pt.CommDeductedAtSource,0))
												/	(
													CASE WHEN pt.Amount = 0 THEN 1 ELSE ABS(pt.Amount) END 
													*
													CASE pt.Frequency 
														WHEN 1 THEN 52	-- weekly
														WHEN 2 THEN 12	-- monthly
														WHEN 3 THEN 4	-- quarterly
														WHEN 4 THEN 2	-- half yearly
														WHEN 5 THEN 1	-- annually
														WHEN 6 THEN 1	-- single
														WHEN 7 THEN 365	-- daily
														WHEN 8 THEN 26	-- fortnightly
														ELSE 1 
													END
												)
												/	(
														CASE 
															WHEN pt.CommInitialPeriod > 24 THEN 24
															WHEN pt.CommInitialPeriod = 0 THEN 1
															WHEN pt.CommInitialPeriod is null THEN 1
															ELSE pt.CommInitialPeriod 
														END
													)
												) 
												* 1200,3) AS CommBasedOnPercent
								FROM		dbo.sa_swift_PolicyTransactions pt
								INNER JOIN	dbo.sa_swift_CodeCommissionShape ccs on ccs.ID = pt.CodeCommissionShapeID
								INNER JOIN	dbo.sa_swift_CodeCommissionShapePOSMatch ccspm on ccspm.CodeCommissionShapeID = ccs.ID
								WHERE	pt.CommCompanyCode in ('L&G','PRUPROTECT')
								AND		ccspm.POSField = 'product/commission_entitlement/tpsdata/accrual_period'
								AND		ccspm.FieldValue = '2'
								AND		pt.ProposalDate >= '2013-09-26'
							) ipf ON ipf.ID = pt.ID
				LEFT JOIN	(
								SELECT	 ID
										,SUM(ISNULL(AMOUNT_REC,0) - ISNULL(AMOUNT_DUE,0)) AS AdjustmentAmount
								FROM	dbo.sa_swift_S_PACC
								WHERE	ADJUST = 2
								AND		TYPE = 1
								GROUP BY ID
							) AS acia ON acia.ID = pt.ID
				LEFT JOIN	(
								SELECT	 ID
										,SUM(ISNULL(AMOUNT_REC,0) - ISNULL(AMOUNT_DUE,0)) AS AdjustmentAmount
								FROM	dbo.sa_swift_S_PACC
								WHERE	ADJUST = 2
								AND		TYPE = 4
								GROUP BY ID
							) AS acra ON acra.ID = pt.ID
				EXCEPT
				SELECT
						 ID
						,PolicyID
						,TransType
						,TransTypeDesc
						,AdminMethod
						,TransactionDate
						,TransactionWrittenDate
						,NotificationDate
						,AgentCode
						,SubsequentPurchase
						,TransactionNumber
						,StartDate
						,TermYears
						,TermMonths
						,FinishDate
						,Frequency
						,FrequencyDescription
						,Amount
						,MortgageAmount
						,APE
						,CurrentRegularAmount
						,CommCompanyCode
						,CommPlanCode
						,CommProductCode
						,CommInputDate
						,CommPayInFull
						,CommType
						,CommissionTypeDesc
						,CommInitialAmount
						,AdjustedCommInitialAmount
						,CommCalculatedAmount
						,CommBasedOnPercent
						,CommReducedToPercent
						,CommCalculatedUplift
						,CommExpectedUplift
						,CommDeductedAtSource
						,CommFirstReceiptDate
						,CommInitialPeriod
						,CommRenewalFirstPayment
						,CommRenewalAmount
						,AdjustedCommRenewalAmount
						,CommRenewalFrequency
						,CommOverrideDate
						,CommOverrideReason
						,CommReclaim
						,CommFeeNetAmount
						,CommFeeVATAmount
						,CommFeeDateReceived
						,LastPaymentDate
						,CommLevelInstallment
						,CommLevelFinalInstallment
						,CommLevelDebited
						,CommLevelFinalInstallmentDate
						,CommLevelLastInstallmentDate
						,StopPayingLevelCommission
						,CommissionDisclosed
						,CreateDateTime
						,InForceDate
						,ProposalDate
						,NetPremium
						,SuspendCommission
						,CreatedBy
						,CreatedDate
						,AuthorisedBy
						,AuthorisedDate
						,CommReinvestTrailFees
						,CommTrailFeesStartAfter
						,CommTrailFeesToNetInForce
						,CommTrailFeesAmount
						,CommTrailFeesPeriod
						,CommBaseAmount
						,CommTrialBalanceGiveUpPercent
						,LastIndemnityLiabilityCalculated
						,OutstandingIndemnityLiability
						,CommOriginalBaseAmount
						,CommOriginalInitialAmount
						,CommAccrualYears
						,CommSacrificeTrailFee
						,SubsequentReason
						,RenewalRate
						,AdviceBy
						,CodeCommissionShapeID
						,ProductType
						,ReportingProductCode
						,APE_Flag
						,RevenueCategoryCode
						,ProductSubGroupCode
						,ProductGroupCode
						,ProductCategoryCode
						,ProductProviderCode
						,ReportingProductProviderCode
						,CommRepProductProviderCode
						,ZFSGroupFlag
						,TransactionMonth
						,CommissionMonth
						,IssuedTranID
						,IssuedDate
						,WrittenTranID
						,WrittenDate
				FROM	dbo.mstt_PolicyTransactions
				)
		MERGE dbo.mstt_PolicyTransactions AS prev
		USING InsUpd AS curr
			ON curr.[ID] = prev.[ID]
		WHEN MATCHED
			THEN
				UPDATE SET
						 PolicyID							= curr.PolicyID
						,TransType							= curr.TransType
						,TransTypeDesc						= curr.TransTypeDesc
						,AdminMethod						= curr.AdminMethod
						,TransactionDate					= curr.TransactionDate
						,TransactionWrittenDate				= curr.TransactionWrittenDate
						,NotificationDate					= curr.NotificationDate
						,AgentCode							= curr.AgentCode
						,SubsequentPurchase					= curr.SubsequentPurchase
						,TransactionNumber					= curr.TransactionNumber
						,StartDate							= curr.StartDate
						,TermYears							= curr.TermYears
						,TermMonths							= curr.TermMonths
						,FinishDate							= curr.FinishDate
						,Frequency							= curr.Frequency
						,FrequencyDescription				= curr.FrequencyDescription
						,Amount								= curr.Amount
						,MortgageAmount						= curr.MortgageAmount
						,APE								= curr.APE
						,CurrentRegularAmount				= curr.CurrentRegularAmount
						,CommCompanyCode					= curr.CommCompanyCode
						,CommPlanCode						= curr.CommPlanCode
						,CommProductCode					= curr.CommProductCode
						,CommInputDate						= curr.CommInputDate
						,CommPayInFull						= curr.CommPayInFull
						,CommType							= curr.CommType
						,CommissionTypeDesc					= curr.CommissionTypeDesc
						,CommInitialAmount					= curr.CommInitialAmount
						,AdjustedCommInitialAmount			= curr.AdjustedCommInitialAmount
						,CommCalculatedAmount				= curr.CommCalculatedAmount
						,CommBasedOnPercent					= curr.CommBasedOnPercent
						,CommReducedToPercent				= curr.CommReducedToPercent
						,CommCalculatedUplift				= curr.CommCalculatedUplift
						,CommExpectedUplift					= curr.CommExpectedUplift
						,CommDeductedAtSource				= curr.CommDeductedAtSource
						,CommFirstReceiptDate				= curr.CommFirstReceiptDate
						,CommInitialPeriod					= curr.CommInitialPeriod
						,CommRenewalFirstPayment			= curr.CommRenewalFirstPayment
						,CommRenewalAmount					= curr.CommRenewalAmount
						,AdjustedCommRenewalAmount			= curr.AdjustedCommRenewalAmount
						,CommRenewalFrequency				= curr.CommRenewalFrequency
						,CommOverrideDate					= curr.CommOverrideDate
						,CommOverrideReason					= curr.CommOverrideReason
						,CommReclaim						= curr.CommReclaim
						,CommFeeNetAmount					= curr.CommFeeNetAmount
						,CommFeeVATAmount					= curr.CommFeeVATAmount
						,CommFeeDateReceived				= curr.CommFeeDateReceived
						,LastPaymentDate					= curr.LastPaymentDate
						,CommLevelInstallment				= curr.CommLevelInstallment
						,CommLevelFinalInstallment			= curr.CommLevelFinalInstallment
						,CommLevelDebited					= curr.CommLevelDebited
						,CommLevelFinalInstallmentDate		= curr.CommLevelFinalInstallmentDate
						,CommLevelLastInstallmentDate		= curr.CommLevelLastInstallmentDate
						,StopPayingLevelCommission			= curr.StopPayingLevelCommission
						,CommissionDisclosed				= curr.CommissionDisclosed
						,CreateDateTime						= curr.CreateDateTime
						,InForceDate						= curr.InForceDate
						,ProposalDate						= curr.ProposalDate
						,NetPremium							= curr.NetPremium
						,SuspendCommission					= curr.SuspendCommission
						,CreatedBy							= curr.CreatedBy
						,CreatedDate						= curr.CreatedDate
						,AuthorisedBy						= curr.AuthorisedBy
						,AuthorisedDate						= curr.AuthorisedDate
						,CommReinvestTrailFees				= curr.CommReinvestTrailFees
						,CommTrailFeesStartAfter			= curr.CommTrailFeesStartAfter
						,CommTrailFeesToNetInForce			= curr.CommTrailFeesToNetInForce
						,CommTrailFeesAmount				= curr.CommTrailFeesAmount
						,CommTrailFeesPeriod				= curr.CommTrailFeesPeriod
						,CommBaseAmount						= curr.CommBaseAmount
						,CommTrialBalanceGiveUpPercent		= curr.CommTrialBalanceGiveUpPercent
						,LastIndemnityLiabilityCalculated	= curr.LastIndemnityLiabilityCalculated
						,OutstandingIndemnityLiability		= curr.OutstandingIndemnityLiability
						,CommOriginalBaseAmount				= curr.CommOriginalBaseAmount
						,CommOriginalInitialAmount			= curr.CommOriginalInitialAmount
						,CommAccrualYears					= curr.CommAccrualYears
						,CommSacrificeTrailFee				= curr.CommSacrificeTrailFee
						,SubsequentReason					= curr.SubsequentReason
						,RenewalRate						= curr.RenewalRate
						,AdviceBy							= curr.AdviceBy
						,CodeCommissionShapeID				= curr.CodeCommissionShapeID
						,ProductType						= curr.ProductType
						,ReportingProductCode				= curr.ReportingProductCode
						,APE_Flag							= curr.APE_Flag
						,RevenueCategoryCode				= curr.RevenueCategoryCode
						,ProductSubGroupCode				= curr.ProductSubGroupCode
						,ProductGroupCode					= curr.ProductGroupCode
						,ProductCategoryCode				= curr.ProductCategoryCode
						,ProductProviderCode				= curr.ProductProviderCode
						,ReportingProductProviderCode		= curr.ReportingProductProviderCode
						,CommRepProductProviderCode			= curr.CommRepProductProviderCode
						,ZFSGroupFlag						= curr.ZFSGroupFlag
						,TransactionMonth					= curr.TransactionMonth
						,CommissionMonth					= curr.CommissionMonth
						,IssuedTranID						= curr.IssuedTranID
						,IssuedDate							= curr.IssuedDate
						,WrittenTranID						= curr.WrittenTranID
						,WrittenDate						= curr.WrittenDate
		WHEN NOT MATCHED BY TARGET
			THEN
				INSERT	(ID
						,PolicyID
						,TransType
						,TransTypeDesc
						,AdminMethod
						,TransactionDate
						,TransactionWrittenDate
						,NotificationDate
						,AgentCode
						,SubsequentPurchase
						,TransactionNumber
						,StartDate
						,TermYears
						,TermMonths
						,FinishDate
						,Frequency
						,FrequencyDescription
						,Amount
						,MortgageAmount
						,APE
						,CurrentRegularAmount
						,CommCompanyCode
						,CommPlanCode
						,CommProductCode
						,CommInputDate
						,CommPayInFull
						,CommType
						,CommissionTypeDesc
						,CommInitialAmount
						,AdjustedCommInitialAmount
						,CommCalculatedAmount
						,CommBasedOnPercent
