						,APE_Flag
						,RevenueCategoryCode
						,ProductSubGroupCode
						,ProductGroupCode
						,ProductCategoryCode
						,ProductProviderCode
						,ReportingProductProviderCode
						,CommRepProductProviderCode
						,ZFSGroupFlag
						,TransactionMonth
						,CommissionMonth
						,IssuedTranID
						,IssuedDate
						,WrittenTranID
						,WrittenDate
						)
				VALUES	(curr.ID
						,curr.PolicyID
						,curr.TransType
						,curr.TransTypeDesc
						,curr.AdminMethod
						,curr.TransactionDate
						,curr.TransactionWrittenDate
						,curr.NotificationDate
						,curr.AgentCode
						,curr.SubsequentPurchase
						,curr.TransactionNumber
						,curr.StartDate
						,curr.TermYears
						,curr.TermMonths
						,curr.FinishDate
						,curr.Frequency
						,curr.FrequencyDescription
						,curr.Amount
						,curr.MortgageAmount
						,curr.APE
						,curr.CurrentRegularAmount
						,curr.CommCompanyCode
						,curr.CommPlanCode
						,curr.CommProductCode
						,curr.CommInputDate
						,curr.CommPayInFull
						,curr.CommType
						,curr.CommissionTypeDesc
						,curr.CommInitialAmount
						,curr.AdjustedCommInitialAmount
						,curr.CommCalculatedAmount
						,curr.CommBasedOnPercent
						,curr.CommReducedToPercent
						,curr.CommCalculatedUplift
						,curr.CommExpectedUplift
						,curr.CommDeductedAtSource
						,curr.CommFirstReceiptDate
						,curr.CommInitialPeriod
						,curr.CommRenewalFirstPayment
						,curr.CommRenewalAmount
						,curr.AdjustedCommRenewalAmount
						,curr.CommRenewalFrequency
						,curr.CommOverrideDate
						,curr.CommOverrideReason
						,curr.CommReclaim
						,curr.CommFeeNetAmount
						,curr.CommFeeVATAmount
						,curr.CommFeeDateReceived
						,curr.LastPaymentDate
						,curr.CommLevelInstallment
						,curr.CommLevelFinalInstallment
						,curr.CommLevelDebited
						,curr.CommLevelFinalInstallmentDate
						,curr.CommLevelLastInstallmentDate
						,curr.StopPayingLevelCommission
						,curr.CommissionDisclosed
						,curr.CreateDateTime
						,curr.InForceDate
						,curr.ProposalDate
						,curr.NetPremium
						,curr.SuspendCommission
						,curr.CreatedBy
						,curr.CreatedDate
						,curr.AuthorisedBy
						,curr.AuthorisedDate
						,curr.CommReinvestTrailFees
						,curr.CommTrailFeesStartAfter
						,curr.CommTrailFeesToNetInForce
						,curr.CommTrailFeesAmount
						,curr.CommTrailFeesPeriod
						,curr.CommBaseAmount
						,curr.CommTrialBalanceGiveUpPercent
						,curr.LastIndemnityLiabilityCalculated
						,curr.OutstandingIndemnityLiability
						,curr.CommOriginalBaseAmount
						,curr.CommOriginalInitialAmount
						,curr.CommAccrualYears
						,curr.CommSacrificeTrailFee
						,curr.SubsequentReason
						,curr.RenewalRate
						,curr.AdviceBy
						,curr.CodeCommissionShapeID
						,curr.ProductType
						,curr.ReportingProductCode
						,curr.APE_Flag
						,curr.RevenueCategoryCode
						,curr.ProductSubGroupCode
						,curr.ProductGroupCode
						,curr.ProductCategoryCode
						,curr.ProductProviderCode
						,curr.ReportingProductProviderCode
						,curr.CommRepProductProviderCode
						,curr.ZFSGroupFlag
						,curr.TransactionMonth
						,curr.CommissionMonth
						,curr.IssuedTranID
						,curr.IssuedDate
						,curr.WrittenTranID
						,curr.WrittenDate
						)
		OUTPUT $action INTO @SummaryOfChanges;

		COMMIT TRANSACTION;

		SELECT @ProcessMessage	= 'DELETE: ' + (SELECT CAST(COUNT(*) AS VARCHAR(10)) AS Qty FROM @SummaryOfChanges WHERE Change = 'DELETE') + ';  '
								+ 'INSERT: ' + (SELECT CAST(COUNT(*) AS VARCHAR(10)) AS Qty FROM @SummaryOfChanges WHERE Change = 'INSERT') + ';  '
								+ 'UPDATE: ' + (SELECT CAST(COUNT(*) AS VARCHAR(10)) AS Qty FROM @SummaryOfChanges WHERE Change = 'UPDATE');
		EXEC dbo.msp_ProcessLog 'LOG', @ProcessMessage, NULL, 'mstp_PolicyTransactions', 'Openwork';
	END TRY
	BEGIN CATCH
		DECLARE	 @ErrorNumber INT = ERROR_NUMBER()
				,@Message VARCHAR(MAX) = ERROR_MESSAGE()
				,@Severity INT = ERROR_SEVERITY()
				,@State SMALLINT = ERROR_STATE()
				;

		ROLLBACK TRANSACTION;

		RAISERROR (@Message, @Severity, @State);
	END CATCH;

	IF @@TRANCOUNT > 0
		ROLLBACK TRANSACTION;

	/*
		Cleanup
	*/
	DROP TABLE #CommissionStatementPeriods;
	DROP TABLE #TransactionType;
	DROP TABLE #CommissionType;
	DROP TABLE #Frequency;
	DROP TABLE #IssuedTransactions;
	DROP TABLE #WrittenTransactions;
	DROP TABLE #MinTransactionDate;
	DROP TABLE #ActiveTransactions;
	DROP TABLE #Proposals;
END
GO
