CREATE PROCEDURE [dbo].[mstp_PopulateReportingServicesTables] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

Date    Author    Description
========  ========  ===========
22/04/08  A Groves  Remove procs:
        1)  msp_Average_Turnover
        2)  mstp_TrialBalanceReport
        and place in the Head office Systems step
        of the batch job.  These procs are currently
        considered redundant and may be removed 
        altogether in time.
14/08/2008       P.Robathan        Add calls for ABC Leagues
*******************************************************************************/
set dateformat dmy
declare 
 @PhaseStart          varchar(50),
