/****** Object:  StoredProcedure [dbo].[mstp_ProductHierarchy]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**************************************************************************************************
Created by: Kris Zywczyk
Created on: 2010-07-23
Description: Update mstp_ProductHierarchy table

Changes:
--------
When        By whom        What changed
---------------------------------------------------------------------------------------------------
03/05/2012	Mike Cawood		SR153273 - Add 2 new columns RDRType and RetentionRateFactor

**************************************************************************************************/
CREATE procedure [dbo].[mstp_ProductHierarchy]
as
begin
  set nocount on;
  declare @RowCount int;
  
  --Delete nonexisting records 
  -------------------------------------
  delete t
  from dbo.mstt_ProductHierarchy t
       left outer join dbo.mstt_CodeBIProducts s on t.ProductCode = s.ProductCode
  where s.ProductCode is null;
  
  --Check results
  set @RowCount = @@rowcount;
  if @RowCount > 0
    print(convert(varchar(18), @RowCount)+' rows deleted from dbo.mstt_ProductHierarchy.');
    
  --Insert new data
  -------------------------------------
  insert into dbo.mstt_ProductHierarchy(ProductCode,
                                        ProductName,
                                        ProductType,
                                        ReportingProductCode,
                                        RegulationDefault,
                                        DualSalesProcess,
                                        APE_Flag,
                                        RevenueCategoryCode,
                                        ProductSubGroupCode,
                                        ProductSubGroupName,
                                        ProductGroupCode,
                                        ProductGroupName,
                                        ProductCategoryCode,
                                        ProductCategoryName,
                                        ProductProviderCode,
                                        ReportingProductProviderCode,
                                        CommRepProductProviderCode,
                                        ZFSGroupFlag,
                                        LeagueIncludeFlag,
                                        SinglePremBasisCode,
                                        SinglePremABCRate,
                                        RegularPremBasisCode,
                                        RegularPremABCRate,
                                        StructuredProduct,		--MPC: 03/05/2012 - SR153273
										RDRType,				--MPC: 03/05/2012 - SR153273
										RetentionRateFactor)	--MPC: 03/05/2012 - SR153273
  select ProductCode                  = cbp.ProductCode,
         ProductName                  = cbp.ProductName,
         ProductType                  = cbp.ProductType,
         ReportingProductCode         = cbp.ReportingProductCode,
         RegulationDefault            = cbp.RegulationDefault,
         DualSalesProcess             = cbp.DualSalesProcess,
         APE_Flag                     = cbp.APE_Flag,
         RevenueCategoryCode          = cbp.RevenueCategoryCode,
         ProductSubGroupCode          = crpc.ProductSubGroupCode,
         ProductSubGroupName          = cpsg.ProductSubGroupName,
         ProductGroupCode             = cpsg.ProductGroupCode,
         ProductGroupName             = cpg.ProductGroupName,
         ProductCategoryCode          = cpg.ProductCategoryCode,
         ProductCategoryName          = cpc.ProductCategoryName,
         ProductProviderCode          = cbp.ProductProviderCode,
         ReportingProductProviderCode = crc.ReportingProductProviderCode,
         CommRepProductProviderCode   = pp.ReportingProductProviderCode,
         ZFSGroupFlag                 = xref.ZFSGroupFlag,
         LeagueIncludeFlag            = cbp.LeagueIncludeFlag,
         SinglePremBasisCode          = cbp.SinglePremBasisCode,
         SinglePremABCRate            = cbp.SinglePremABCRate,
         RegularPremBasisCode         = cbp.RegularPremBasisCode,
         RegularPremABCRate           = cbp.RegularPremABCRate,
         StructuredProduct            = cbp.StructuredProduct,		--MPC: 03/05/2012 - SR153273
		 RDRType					  = cbp.RDRType,				--MPC: 03/05/2012 - SR153273
		 RetentionRateFactor		  = cbp.RetentionRateFactor		--MPC: 03/05/2012 - SR153273
  from dbo.mstt_CodeBIProducts cbp
       left outer join dbo.mstt_ProductHierarchy t on cbp.ProductCode = t.ProductCode
       inner join dbo.mstt_CodeReportingProductCode crpc      on cbp.ReportingProductCode = crpc.ReportingProductCode
       inner join dbo.mstt_CodeProductSubGroup cpsg           on crpc.ProductSubGroupCode = cpsg.ProductSubGroupCode
       inner join dbo.mstt_CodeProductGroup cpg               on cpsg.ProductGroupCode = cpg.ProductGroupCode
       inner join dbo.mstt_CodeProdProviderReportingXref xref on cbp.ProductProviderCode = xref.ProductProviderCode
       inner join dbo.mstt_CodeReportingProductProvider crc   on xref.ReportingProductProviderCode = crc.ReportingProductProviderCode
       inner join dbo.mstt_CodeReportingProductProvider pp    on xref.CommRepProductProviderCode = pp.ReportingProductProviderCode
       inner join dbo.mstt_CodeProductCategory cpc            on cpg.ProductCategoryCode = cpc.ProductCategoryCode
  where t.ProductCode is null
  order by cbp.ProductCode;
  
  --Check results
  set @RowCount = @@rowcount;
  if @RowCount > 0
    print(convert(varchar(18), @RowCount)+' rows inserted into dbo.mstt_ProductHierarchy.');
  
  --Update data
  -------------------------------------
  update t
  set ProductName                  = x.ProductName,
      ProductType                  = x.ProductType,
      ReportingProductCode         = x.ReportingProductCode,
      RegulationDefault            = x.RegulationDefault,
      DualSalesProcess             = x.DualSalesProcess,
      APE_Flag                     = x.APE_Flag,
      RevenueCategoryCode          = x.RevenueCategoryCode,
      ProductSubGroupCode          = x.ProductSubGroupCode,
      ProductSubGroupName          = x.ProductSubGroupName,
      ProductGroupCode             = x.ProductGroupCode,
      ProductGroupName             = x.ProductGroupName,
      ProductCategoryCode          = x.ProductCategoryCode,
      ProductCategoryName          = x.ProductCategoryName,
      ProductProviderCode          = x.ProductProviderCode,
      ReportingProductProviderCode = x.ReportingProductProviderCode,
      CommRepProductProviderCode   = x.CommRepProductProviderCode,
      ZFSGroupFlag                 = x.ZFSGroupFlag,
      LeagueIncludeFlag            = x.LeagueIncludeFlag,
      SinglePremBasisCode          = x.SinglePremBasisCode,
      SinglePremABCRate            = x.SinglePremABCRate,
      RegularPremBasisCode         = x.RegularPremBasisCode,
      RegularPremABCRate           = x.RegularPremABCRate,
      StructuredProduct            = x.StructuredProduct,		--MPC: 03/05/2012 - SR153273
      RDRType					   = x.RDRType,					--MPC: 03/05/2012 - SR153273
      RetentionRateFactor		   = x.RetentionRateFactor		--MPC: 03/05/2012 - SR153273
  from (select ProductCode                  = cbp.ProductCode,
               ProductName                  = cbp.ProductName,
               ProductType                  = cbp.ProductType,
               ReportingProductCode         = cbp.ReportingProductCode,
               RegulationDefault            = cbp.RegulationDefault,
               DualSalesProcess             = cbp.DualSalesProcess,
               APE_Flag                     = cbp.APE_Flag,
               RevenueCategoryCode          = cbp.RevenueCategoryCode,
               ProductSubGroupCode          = crpc.ProductSubGroupCode,
               ProductSubGroupName          = cpsg.ProductSubGroupName,
               ProductGroupCode             = cpsg.ProductGroupCode,
               ProductGroupName             = cpg.ProductGroupName,
               ProductCategoryCode          = cpg.ProductCategoryCode,
               ProductCategoryName          = cpc.ProductCategoryName,
               ProductProviderCode          = cbp.ProductProviderCode,
               ReportingProductProviderCode = crc.ReportingProductProviderCode,
               CommRepProductProviderCode   = pp.ReportingProductProviderCode,
               ZFSGroupFlag                 = xref.ZFSGroupFlag,
               LeagueIncludeFlag            = cbp.LeagueIncludeFlag,
               SinglePremBasisCode          = cbp.SinglePremBasisCode,
               SinglePremABCRate            = cbp.SinglePremABCRate,
               RegularPremBasisCode         = cbp.RegularPremBasisCode,
               RegularPremABCRate           = cbp.RegularPremABCRate,
               StructuredProduct            = cbp.StructuredProduct,		--MPC: 03/05/2012 - SR153273
			   RDRType						= cbp.RDRType,					--MPC: 03/05/2012 - SR153273
			   RetentionRateFactor			= cbp.RetentionRateFactor		--MPC: 03/05/2012 - SR153273
        from dbo.mstt_CodeBIProducts cbp
             inner join dbo.mstt_CodeReportingProductCode crpc      on cbp.ReportingProductCode = crpc.ReportingProductCode
             inner join dbo.mstt_CodeProductSubGroup cpsg           on crpc.ProductSubGroupCode = cpsg.ProductSubGroupCode
             inner join dbo.mstt_CodeProductGroup cpg               on cpsg.ProductGroupCode = cpg.ProductGroupCode
             inner join dbo.mstt_CodeProdProviderReportingXref xref on cbp.ProductProviderCode = xref.ProductProviderCode
             inner join dbo.mstt_CodeReportingProductProvider crc   on xref.ReportingProductProviderCode = crc.ReportingProductProviderCode
             inner join dbo.mstt_CodeReportingProductProvider pp    on xref.CommRepProductProviderCode = pp.ReportingProductProviderCode
             inner join dbo.mstt_CodeProductCategory cpc            on cpg.ProductCategoryCode = cpc.ProductCategoryCode
        except
        select h.ProductCode,
               h.ProductName,
               h.ProductType,
               h.ReportingProductCode,
               h.RegulationDefault,
               h.DualSalesProcess,
               h.APE_Flag,
               h.RevenueCategoryCode,
               h.ProductSubGroupCode,
               h.ProductSubGroupName,
               h.ProductGroupCode,
               h.ProductGroupName,
               h.ProductCategoryCode,
               h.ProductCategoryName,
               h.ProductProviderCode,
               h.ReportingProductProviderCode,
               h.CommRepProductProviderCode,
               h.ZFSGroupFlag,
               h.LeagueIncludeFlag,
               h.SinglePremBasisCode,
               h.SinglePremABCRate,
               h.RegularPremBasisCode,
               h.RegularPremABCRate,
               h.StructuredProduct,		--MPC: 03/05/2012 - SR153273
			   h.RDRType,				--MPC: 03/05/2012 - SR153273
			   h.RetentionRateFactor	--MPC: 03/05/2012 - SR153273
        from dbo.mstt_ProductHierarchy h) as x
       inner join dbo.mstt_ProductHierarchy t on x.ProductCode = t.ProductCode;
  
  --Check results
  set @RowCount = @@rowcount;
  if @RowCount > 0
    print(convert(varchar(18), @RowCount)+' rows updated in dbo.mstt_ProductHierarchy.');
end;
GO
