CREATE PROCEDURE [dbo].[mstp_ProductionAdjustments] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Amended Nov 2007 - Pr - to use new xref table owhot_OSCARSwiftAgentXref 

Dec 2007 - Mike Cawood - change truncate to Delete to leave Suspense, OMS and Ledger Adjustments

*******************************************************************************/

/******************************************************************************
Ticket 1560
======
Fix applied by Mike Cawood (Feb'08)

Match Production Adjustments to msdt_Products table using Product code rather than ID.
This avoids SUSP_ entries being matched to wrong Product (as their ProductID is static).

COMMENTED OUT -- Insert Adjustsments from msit_MIWarehouseCodesandDescriptions table -- COMMENTED OUT

*******************************************************************************/


-- PROCEDURE BODY GOES HERE
BEGIN

DECLARE @DefaultPolicyNumber        INT
DECLARE @DefaultTransactionID       INT
DECLARE @DefaultCommissionTransactionID   INT
DECLARE @DefaultFranchiseSizeID     INT
DECLARE @DefaultFranchiseSegmentID      INT
DECLARE @DefaultAdviserID       INT
DECLARE @DefaultAgentCode       VARCHAR(50)
DECLARE @DefaultBusinessTypeID      INT
DECLARE @DefaultProductID       INT
DECLARE @DefaultDateWrittenID     INT
DECLARE @DefaultDateIssuedID      INT
DECLARE @DefaultPipelineFlagID      INT
DECLARE @DefaultPipelineAgeBandID   INT
DECLARE @DefaultComparisonID      INT
DECLARE @DefaultCommissionBasisID   INT
DECLARE @DefaultFrequencyID     INT
DECLARE @DefaultBusinessReasonID    INT
DECLARE @DefaultSubmissionMethodID    INT

SET @DefaultPolicyNumber      = -8
SET @DefaultTransactionID     = -8
SET @DefaultCommissionTransactionID = -8
SET @DefaultFranchiseSizeID     = (SELECT CAST(DefaultValue AS INT) FROM mstt_DefaultCodeValues WHERE CodeColumn = 'FranchiseSizeID')
SET @DefaultFranchiseSegmentID    = (SELECT CAST(DefaultValue AS INT) FROM mstt_DefaultCodeValues WHERE CodeColumn = 'FranchiseSegmentID')
SET @DefaultAdviserID       = (SELECT CAST(DefaultValue AS INT) FROM mstt_DefaultCodeValues WHERE CodeColumn = 'AdviserID')
SET @DefaultAgentCode       = (SELECT DefaultValue FROM mstt_DefaultCodeValues WHERE CodeColumn = 'AgentCode')
SET @DefaultBusinessTypeID    = (SELECT BusinessTypeID FROM dbo.msdt_BusinessType WHERE BusinessType = 'Issued')
SET @DefaultProductID       = (SELECT CAST(DefaultValue AS INT) FROM mstt_DefaultCodeValues WHERE CodeColumn = 'ProductID')
SET @DefaultCommissionTransactionID = (SELECT CAST(DefaultValue AS INT) FROM mstt_DefaultCodeValues WHERE CodeColumn = 'CommmissionTransactionID')
SET @DefaultDateWrittenID   = (SELECT CAST(DefaultValue AS INT) FROM mstt_DefaultCodeValues WHERE CodeColumn = 'DateWrittenID')
SET @DefaultDateIssuedID    = (SELECT CAST(DefaultValue AS INT) FROM mstt_DefaultCodeValues WHERE CodeColumn = 'DateIssuedID')
SET @DefaultPipelineFlagID    = (SELECT FlagID FROM msdt_PipelineFlag WHERE PipelineFlag = 'No')
SET @DefaultPipelineAgeBandID   = (SELECT CAST(DefaultValue AS INT) FROM mstt_DefaultCodeValues WHERE CodeColumn = 'PipelineAgeBandID')
SET @DefaultComparisonID    = (SELECT ComparisonID FROM msdt_Comparison WHERE Comparison = 'Actual')
SET @DefaultCommissionBasisID   = (SELECT CAST(DefaultValue AS INT) FROM mstt_DefaultCodeValues WHERE CodeColumn = 'CommissionBasisID')
SET @DefaultFrequencyID     = (SELECT CAST(DefaultValue AS INT) FROM mstt_DefaultCodeValues WHERE CodeColumn = 'FrequencyID')
SET @DefaultBusinessReasonID    = (SELECT BusinessReasonId FROM dbo.msdt_BusinessReason WHERE BusinessReasonDescription = 'New Business')
SET @DefaultSubmissionMethodID    = (SELECT CAST(DefaultValue AS INT) FROM mstt_DefaultCodeValues WHERE CodeColumn = 'SubmissionMethodID')

-- Clear the Production Adjustments table.

--TRUNCATE TABLE mstt_ProductionAdjustments :MPC
-- Leave Suspense, OMS and Ledger adjustments on table as these will not be reloaded from NIFADJ.txt 
Delete from mstt_ProductionAdjustments
where TransactionID = -8    -- used for Adjustments from Prod Adj upload file

--Inactive Franchises
SELECT  @DefaultPolicyNumber  PolicyNumber,
  ad.AgentCode    AgentCode,
  @DefaultTransactionID TransactionId,
  @DefaultCommissionTransactionID CommissionTransactionID,
  ad.AdviserID    AdviserId,
  @DefaultBusinessTypeID  BusinessTypeId,
  @DefaultProductID ProductID,
  swift_code    ProductCode,
  @DefaultDateWrittenID DateWrittenId,
  @DefaultDateIssuedID  DateIssuedId,
  @DefaultDateIssuedID  TransactionDateId,
  /* Assuming import date format can be any of:
    '5/6/02 00:00:00',    '5/6/02'
    '05/06/02 00:00:00',  '05/06/02'
    '05/06/2002 00:00:00','05/06/2002'
    '5/6/2002 00:00:00',  '5/6/2002'
  */
  CASE LEN(SUBSTRING(REPLACE(EFF_DATE,' 00:00:00',''),CHARINDEX('/',EFF_DATE,4)+1, 10))
    WHEN 2 THEN CONVERT(smalldatetime,EFF_DATE,3)
    WHEN 4 THEN CONVERT(smalldatetime,EFF_DATE,103)
    ELSE CONVERT(smalldatetime,EFF_DATE,3) -- Will Error
  END DateIssued,
--  CONVERT(smalldatetime,EFF_DATE,3) DateIssued,
  @DefaultPipelineFlagID  PipelineFlagId,
  @DefaultPipelineAgeBandID PipelineAgeBandId,
  ad.FranchiseSizeId  FranchiseSizeId,
  ad.FranchiseSegmentId FranchiseSegmentId,
  @DefaultComparisonID  ComparisonId,
  @DefaultCommissionBasisID CommissionBasisId,
  @DefaultFrequencyID FrequencyId,
  @DefaultBusinessReasonID BusinessReasonId,
  @DefaultSubmissionMethodID SubmissionMethodId,
  CAST(ape_amount AS FLOAT) Turnover,
  CAST(ape_amount AS FLOAT) APE,
  CAST(nbi_amount AS FLOAT) NBI,
  0     DA,
  0     Margin,
  0     Cases,
  0     DaysInPipeline,
  pad.type    AdjustmentCode,
  pad.Comment   Comment,
  pad.roll_up   ProductionFlag,
  2000 + cast(right(convert(varchar(3), 999 - [YEAR]),2) as int) as  'Year'
INTO  #Staging_ProdAdjustmentData
FROM  dbo.msit_ProdAdjustmentData pad
  inner join msdt_AdviserDummies ad
    on 'INACTIVE_'+cast(cast(pad.Agent_Id as int) as varchar(50)) = ad.AgentCode
WHERE 
del_ind <> 'Y'
AND [qc_date] IS NOT NULL
AND
(
  CAST(ape_amount AS FLOAT) <> 0
  OR CAST(nbi_amount AS FLOAT) <> 0
)

insert into #Staging_ProdAdjustmentData
SELECT  @DefaultPolicyNumber  PolicyNumber,
  osa.AgentCode   AgentCode,
  @DefaultTransactionID TransactionId,
  @DefaultCommissionTransactionID CommissionTransactionID,
  adv.AdviserID   AdviserId,
  @DefaultBusinessTypeID  BusinessTypeId,
  @DefaultProductID ProductID,
  swift_code    ProductCode,
  @DefaultDateWrittenID DateWrittenId,
  @DefaultDateIssuedID  DateIssuedId,
  @DefaultDateIssuedID  TransactionDateId,
  /* Assuming import date format can be any of:
    '5/6/02 00:00:00',    '5/6/02'
    '05/06/02 00:00:00',  '05/06/02'
    '05/06/2002 00:00:00','05/06/2002'
    '5/6/2002 00:00:00',  '5/6/2002'
  */
  CASE LEN(SUBSTRING(REPLACE(EFF_DATE,' 00:00:00',''),CHARINDEX('/',EFF_DATE,4)+1, 10))
    WHEN 2 THEN CONVERT(smalldatetime,EFF_DATE,3)
    WHEN 4 THEN CONVERT(smalldatetime,EFF_DATE,103)
    ELSE CONVERT(smalldatetime,EFF_DATE,3) -- Will Error
  END DateIssued,
--  CONVERT(smalldatetime,EFF_DATE,3) DateIssued,
  @DefaultPipelineFlagID  PipelineFlagId,
  @DefaultPipelineAgeBandID PipelineAgeBandId,
  adv.FranchiseSizeId FranchiseSizeId,
  adv.FranchiseSegmentId  FranchiseSegmentId,
  @DefaultComparisonID  ComparisonId,
  @DefaultCommissionBasisID CommissionBasisId,
  @DefaultFrequencyID FrequencyId,
  @DefaultBusinessReasonID BusinessReasonId,
  @DefaultSubmissionMethodID SubmissionMethodId,
  CAST(ape_amount AS FLOAT) Turnover,
  CAST(ape_amount AS FLOAT) APE,
  CAST(nbi_amount AS FLOAT) NBI,
  0     DA,
  0     Margin,
  0     Cases,
  0     DaysInPipeline,
  pad.type    AdjustmentCode,
  pad.Comment   Comment,
  pad.roll_up   ProductionFlag,
  2000 + cast(right(convert(varchar(3), 999 - [YEAR]),2) as int) as  'Year'
FROM  dbo.msit_ProdAdjustmentData pad
  INNER JOIN Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref  osa
    ON pad.AGENT_ID = osa.OSCAR_ID
    AND osa.AgentLevel = 'B'
  INNER JOIN dbo.msdt_Adviser adv
    ON osa.AgentCode = adv.AgentCode
WHERE 
del_ind <> 'Y'
AND [qc_date] IS NOT NULL
AND
(
  CAST(ape_amount AS FLOAT) <> 0
  OR CAST(nbi_amount AS FLOAT) <> 0
)

/***
**** -- NB: May need to split out dbo.msdt_Adviser to ensure missing
**** --     advisers are still put into the table but with a -99 AdviserID/FranchiseSizeId/FranchiseSegmentId
****
**** --     msit_OscarSwiftAgents is used to filter out older codes which
**** --     are not needed.
***/

/*
-- Insert Adjustments from MI Warehouse Codes and Descriptions table  :MPC

insert into #Staging_ProdAdjustmentData
SELECT  @DefaultPolicyNumber  PolicyNumber,
  wcd.Code    AgentCode,
  @DefaultTransactionID TransactionId,
  @DefaultCommissionTransactionID CommissionTransactionID,
  ad.AdviserID    AdviserID,
  @DefaultBusinessTypeID  BusinessTypeId,
  @DefaultProductID ProductID,
  substring(wcd.LongDescription,1,8) ProductCode,
  @DefaultDateWrittenID DateWrittenId,
  @DefaultDateIssuedID  DateIssuedId,
  @DefaultDateIssuedID  TransactionDateId,
  CAST(CONVERT(NVARCHAR, wcd.ShortDescription, 112) AS DATETIME)  DateIssued,
  @DefaultPipelineFlagID  PipelineFlagId,
  @DefaultPipelineAgeBandID PipelineAgeBandId,
  ad.FranchiseSizeId  FranchiseSizeId,
  ad.FranchiseSegmentId FranchiseSegmentId,
  @DefaultComparisonID  ComparisonId,
  @DefaultCommissionBasisID CommissionBasisId,
  @DefaultFrequencyID FrequencyId,
  @DefaultBusinessReasonID BusinessReasonId,
  @DefaultSubmissionMethodID SubmissionMethodId,
  case when wcd.ColumnName = 'LG_ADJUST_APE' then CAST(wcd.Description AS FLOAT) else 0 end   Turnover,
  case when wcd.ColumnName = 'LG_ADJUST_APE' then CAST(wcd.Description AS FLOAT) else 0 end   APE,
  case when wcd.ColumnName = 'LG_ADJUST_NBI' then CAST(wcd.Description AS FLOAT) else 0 end   NBI,
  0     DA,
  0     Margin,
  0     Cases,
  0     DaysInPipeline,
  'WAREHOUSE'   AdjustmentCode,
  'Manual Adjustment' Comment,
  'Y'     ProductionFlag,
  csp.Year as 'Year'
FROM  dbo.msit_MIWarehouseCodesandDescriptions wcd
  inner join msdt_Adviser ad
    on ad.AgentCode = wcd.Code
  inner join msit_CommissionStatementPeriods csp
    on csp.Month = wcd.ShortDescription
WHERE wcd.ColumnName = 'LG_ADJUST_APE' or wcd.ColumnName = 'LG_ADJUST_NBI' 

-- End of MI Warehouse Codes and Descriptions Insert    :MPC
*/

-- Match product codes
update t
set ProductID = p.ProductID
from #Staging_ProdAdjustmentData t
  inner join msdt_Products p
    on t.ProductCode = p.ProductCode


/*
    Change Date Issued for Production 'Adjustments' ONLY !
       When the Issued Date year is different to the year field the Issued Date needs to be
       changed to reflect the Year field.
       For Example,
       Issued Date  Year  New Issued Date   Notes
       17/12/2005 2005  17/12/2005      Not changed
       17/12/2005 2006  01/01/2006      Changed to reflect the Year field
       06/01/2006 2006  06/01/2006      Not changed
       06/01/2006 2005  31/12/2005      Changed to reflect the Year field
*/
update #Staging_ProdAdjustmentData
set DateIssued = case 
          when (datepart(year,DateIssued) > [Year]) then cast([Year] as nvarchar) + '1231'
          when(datepart(year,DateIssued) < [Year]) then cast([Year] as nvarchar) + '0101' 
          else DateIssued
         end
where ProductionFlag = 'Y'
and   datepart(year,DateIssued) <> [Year]
and AdjustmentCode <> 'WAREHOUSE'   --:MPC

-- Match Issued Dates
update t
set DateIssuedID  = c.DateID,
    TransactionDateID = c.DateID
from #Staging_ProdAdjustmentData t
  inner join msdt_CalendarTime c
    on t.DateIssued = c.[DateTime]
  inner join mst_DateTimeControl dtc
    on c.EntryTypeID = dtc.EntryTypeID
where dtc.EntryType = 'DateIssued'


--insert the new fact rows.
insert into mstt_ProductionAdjustments
(
  PolicyNumber, 
  AgentCode, 
  TransactionId, 
  CommissionTransactionID,
  AdviserId, 
  BusinessTypeId, 
  ProductId, 
  DateWrittenId, 
  DateIssuedId, 
  TransactionDateId,
  PipelineFlagId, 
  PipelineAgeBandId, 
  FranchiseSizeId, 
  FranchiseSegmentId, 
  ComparisonId, 
  CommissionBasisId,
  FrequencyId,
  BusinessReasonId,
  SubmissionMethodId,
  Turnover, 
  APE, 
  NBI, 
  DA, 
  Margin, 
  Cases, 
  DaysInPipeline,
  ProductCode,
  AdjustmentCode,
  Comment,
  ProductionFlag,
  [Year]
)
select 
  PolicyNumber, 
  AgentCode, 
  TransactionID, 
  CommissionTransactionID,
  AdviserID, 
  BusinessTypeID, 
  ProductID, 
  DateWrittenID, 
  DateIssuedID, 
  TransactionDateID,
  PipelineFlagID, 
  PipeLineAgeBandID,
  FranchiseSizeID, 
  FranchiseSegmentID, 
  ComparisonID, 
  CommissionBasisId,
  FrequencyId,
  BusinessReasonId,
  SubmissionMethodId,
  nullif(Turnover,0), 
  nullif(APE,0), 
  nullif(NBI,0), 
  nullif(DA,0), 
  nullif(Margin,0), 
  nullif(Cases,0), 
  nullif(DaysInPipeline,0),
  ProductCode,
  AdjustmentCode,
  Comment,
  ProductionFlag,
  [Year]
from #Staging_ProdAdjustmentData


--Drop our temp objects.
drop table #Staging_ProdAdjustmentData

-- Reset ProductID on Suspense Production Adjustments     --MPC: Feb'08

update t                --MPC: Feb'08
set ProductID = p.ProductID           --MPC: Feb'08
from mstt_ProductionAdjustments t         --MPC: Feb'08
  inner join msdt_Products p          --MPC: Feb'08
    on p.ProductCode = substring(t.productcode,6,8)   --MPC: Feb'08
where substring(t.productcode,1,5) = 'SUSP_' and t.TransactionID = -9 --MPC: Feb'08


END
GO
/****** Object:  StoredProcedure [dbo].[mstp_ProductProviders]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
