/**************************************************************************************************
Created by: Kris Zywczyk
Created on: 2010-07-22
Description: Update mstt_ProductProviders table

Changes:
--------
When        By whom        What changed
---------------------------------------------------------------------------------------------------
2010-09-15 Kris Zywczyk    Comparison method amended
**************************************************************************************************/
create procedure [dbo].[mstp_ProductProviders]
as
begin
  set nocount on;
  declare @RowCount int;
  
  --Delete nonexisting records 
  -------------------------------------
  delete t
  from dbo.mstt_ProductProviders t
       left outer join dbo.sa_swift_S_COMANY s on t.ProductProviderCode = s.CODE
  where s.CODE is null;
  
  --Check results
  set @RowCount = @@rowcount;
  if @RowCount > 0
    print(convert(varchar(18), @RowCount)+' rows deleted from dbo.mstt_ProductProviders.');
    
  --Insert new data
  -------------------------------------
  insert into dbo.mstt_ProductProviders(ProductProviderCode,
                                        ProductProviderName,
                                        ReportingProductProviderCode,
                                        ReportingProductProviderName,
                                        CommRepProductProviderCode,
                                        CommRepProductProviderName,
                                        ZFSGroupFlag,
                                        EN_NON,
                                        EN_IND,
                                        WL_NON,
                                        WL_IND,
                                        TA_NON,
                                        TA_IND,
                                        TA_SINGLE,
                                        PHI_NON,
                                        PHI_IND,
                                        IB_SINGLE,
                                        UT_SINGLE,
                                        AN_SINGLE,
                                        REN_LIFE,
                                        IPP_NON,
                                        IPP_IND,
                                        IPA_SINGLE,
                                        IPB_SINGLE,
                                        DIS_NON,
                                        DIS_IND,
                                        PR_SINGLE,
                                        REN_PENS,
                                        IND_DISC,
                                        PEP_NON,
                                        PEP_IND,
                                        CTP_CODE)
  select ProductProviderCode          = p.CODE,
         ProductProviderName          = p.DESCN,
         ReportingProductProviderCode = rc.ReportingProductProviderCode,
         ReportingProductProviderName = rc.ReportingProductProviderName,
         CommRepProductProviderCode   = rrc.ReportingProductProviderCode,
         CommRepProductProviderName   = rrc.ReportingProductProviderName,
         ZFSGroupFlag                 = xref.ZFSGroupFlag,
         EN_NON                       = p.EN_NON,
         EN_IND                       = p.EN_IND,
         WL_NON                       = p.WL_NON,
         WL_IND                       = p.WL_IND,
         TA_NON                       = p.TA_NON,
         TA_IND                       = p.TA_IND,
         TA_SINGLE                    = p.TA_SINGLE,
         PHI_NON                      = p.PHI_NON,
         PHI_IND                      = p.PHI_IND,
         IB_SINGLE                    = p.IB_SINGLE,
         UT_SINGLE                    = p.UT_SINGLE,
         AN_SINGLE                    = p.AN_SINGLE,
         REN_LIFE                     = p.REN_LIFE,
         IPP_NON                      = p.IPP_NON,
         IPP_IND                      = p.IPP_IND,
         IPA_SINGLE                   = p.IPA_SINGLE,
         IPB_SINGLE                   = p.IPB_SINGLE,
         DIS_NON                      = p.DIS_NON,
         DIS_IND                      = p.DIS_IND,
         PR_SINGLE                    = p.PR_SINGLE,
         REN_PENS                     = p.REN_PENS,
         IND_DISC                     = p.IND_DISC,
         PEP_NON                      = p.PEP_NON,
         PEP_IND                      = p.PEP_IND,
         CTP_CODE                     = p.CTP_CODE
  from dbo.sa_swift_S_COMANY p
       left outer join dbo.mstt_ProductProviders t on p.CODE = t.ProductProviderCode
       left outer join dbo.mstt_CodeProdProviderReportingXref xref on p.CODE = xref.ProductProviderCode
       left outer join dbo.mstt_CodeReportingProductProvider rrc on xref.CommRepProductProviderCode = rrc.ReportingProductProviderCode
       left outer join dbo.mstt_CodeReportingProductProvider rc on xref.ReportingProductProviderCode = rc.ReportingProductProviderCode
  where p.CODE is not null and
        t.ProductProviderCode is null
  option (force order);
  
  --Check results
  set @RowCount = @@rowcount;
  if @RowCount > 0
    print(convert(varchar(18), @RowCount)+' rows inserted into dbo.mstt_ProductProviders.');
  
  --Update data
  -------------------------------------
  with ProductProvidersDifference
  as (select ProductProviderCode          = p.CODE,
             ProductProviderName          = p.DESCN,
             ReportingProductProviderCode = rc.ReportingProductProviderCode,
             ReportingProductProviderName = rc.ReportingProductProviderName,
             CommRepProductProviderCode   = rrc.ReportingProductProviderCode,
             CommRepProductProviderName   = rrc.ReportingProductProviderName,
             ZFSGroupFlag                 = xref.ZFSGroupFlag,
             EN_NON                       = p.EN_NON,
             EN_IND                       = p.EN_IND,
             WL_NON                       = p.WL_NON,
             WL_IND                       = p.WL_IND,
             TA_NON                       = p.TA_NON,
             TA_IND                       = p.TA_IND,
             TA_SINGLE                    = p.TA_SINGLE,
             PHI_NON                      = p.PHI_NON,
             PHI_IND                      = p.PHI_IND,
             IB_SINGLE                    = p.IB_SINGLE,
             UT_SINGLE                    = p.UT_SINGLE,
             AN_SINGLE                    = p.AN_SINGLE,
             REN_LIFE                     = p.REN_LIFE,
             IPP_NON                      = p.IPP_NON,
             IPP_IND                      = p.IPP_IND,
             IPA_SINGLE                   = p.IPA_SINGLE,
             IPB_SINGLE                   = p.IPB_SINGLE,
             DIS_NON                      = p.DIS_NON,
             DIS_IND                      = p.DIS_IND,
             PR_SINGLE                    = p.PR_SINGLE,
             REN_PENS                     = p.REN_PENS,
             IND_DISC                     = p.IND_DISC,
             PEP_NON                      = p.PEP_NON,
             PEP_IND                      = p.PEP_IND,
             CTP_CODE                     = p.CTP_CODE
      from dbo.sa_swift_S_COMANY p
           left outer join dbo.mstt_CodeProdProviderReportingXref xref on p.CODE = xref.ProductProviderCode
           left outer join dbo.mstt_CodeReportingProductProvider rrc on xref.CommRepProductProviderCode = rrc.ReportingProductProviderCode
           left outer join dbo.mstt_CodeReportingProductProvider rc on xref.ReportingProductProviderCode = rc.ReportingProductProviderCode
      where p.CODE is not null
      except
      select ProductProviderCode,
             ProductProviderName,
             ReportingProductProviderCode,
             ReportingProductProviderName,
             CommRepProductProviderCode,
             CommRepProductProviderName,
             ZFSGroupFlag,
             EN_NON,
             EN_IND,
             WL_NON,
             WL_IND,
             TA_NON,
             TA_IND,
             TA_SINGLE,
             PHI_NON,
             PHI_IND,
             IB_SINGLE,
             UT_SINGLE,
             AN_SINGLE,
             REN_LIFE,
             IPP_NON,
             IPP_IND,
             IPA_SINGLE,
             IPB_SINGLE,
             DIS_NON,
             DIS_IND,
             PR_SINGLE,
             REN_PENS,
             IND_DISC,
             PEP_NON,
             PEP_IND,
             CTP_CODE
      from dbo.mstt_ProductProviders) 
      
  update t
  set ProductProviderName          = x.ProductProviderName,
      ReportingProductProviderCode = x.ReportingProductProviderCode,
      ReportingProductProviderName = x.ReportingProductProviderName,
      CommRepProductProviderCode   = x.CommRepProductProviderCode,
      CommRepProductProviderName   = x.CommRepProductProviderName,
      ZFSGroupFlag                 = x.ZFSGroupFlag,
      EN_NON                       = x.EN_NON,
      EN_IND                       = x.EN_IND,
      WL_NON                       = x.WL_NON,
      WL_IND                       = x.WL_IND,
      TA_NON                       = x.TA_NON,
      TA_IND                       = x.TA_IND,
      TA_SINGLE                    = x.TA_SINGLE,
      PHI_NON                      = x.PHI_NON,
      PHI_IND                      = x.PHI_IND,
      IB_SINGLE                    = x.IB_SINGLE,
      UT_SINGLE                    = x.UT_SINGLE,
      AN_SINGLE                    = x.AN_SINGLE,
      REN_LIFE                     = x.REN_LIFE,
      IPP_NON                      = x.IPP_NON,
      IPP_IND                      = x.IPP_IND,
      IPA_SINGLE                   = x.IPA_SINGLE,
      IPB_SINGLE                   = x.IPB_SINGLE,
      DIS_NON                      = x.DIS_NON,
      DIS_IND                      = x.DIS_IND,
      PR_SINGLE                    = x.PR_SINGLE,
      REN_PENS                     = x.REN_PENS,
      IND_DISC                     = x.IND_DISC,
      PEP_NON                      = x.PEP_NON,
      PEP_IND                      = x.PEP_IND,
      CTP_CODE                     = x.CTP_CODE
  from dbo.mstt_ProductProviders t
       inner join ProductProvidersDifference x on t.ProductProviderCode = x.ProductProviderCode;
  
  --Check results
  set @RowCount = @@rowcount;
  if @RowCount > 0
    print(convert(varchar(18), @RowCount)+' rows updated in dbo.mstt_ProductProviders.');
end;
GO
