CREATE PROCEDURE [dbo].[mstp_Products] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : Matt Kennedy
Created : %DateCreated%  
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>Matt Kennedy</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
*******************************************************************************/
-- PROCEDURE BODY GOES HERE
BEGIN
declare @DefaultProductID     int
declare @DefaultProductCode     varchar(50)
declare @DefaultProductName     varchar(50)
declare @DefaultReportingProductCode    varchar(50)
declare @DefaultReportingProductName    varchar(50)
declare @DefaultProductSubGroupCode   varchar(50)
declare @DefaultProductSubGroupName   varchar(50)
declare @DefaultProductGroupCode    varchar(50)
declare @DefaultProductGroupName    varchar(50)
declare @DefaultProductCategoryCode   varchar(50)
declare @DefaultProductCategoryName   varchar(50)
declare @DefaultProductProviderCode   varchar(50)
declare @DefaultProductProviderName   varchar(50)
declare @DefaultReportingProductProviderCode  varchar(50)
declare @DefaultReportingProductProviderName  varchar(50)
set @DefaultProductID       = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'ProductID')
set @DefaultProductCode       = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'ProductCode')
set @DefaultProductName       = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'ProductName')
set @DefaultReportingProductCode    = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'ReportingProductCode')
set @DefaultReportingProductName    = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'ReportingProductName')
set @DefaultProductSubGroupCode     = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'ProductSubGroupCode')
set @DefaultProductSubGroupName     = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'ProductSubGroupName')
set @DefaultProductGroupCode      = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'ProductGroupCode')
set @DefaultProductGroupName      = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'ProductGroupName')
set @DefaultProductCategoryCode     = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'ProductCategoryCode')
set @DefaultProductCategoryName     = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'ProductCategoryName')
set @DefaultProductProviderCode     = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'ProductProviderCode')
set @DefaultProductProviderName     = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'ProductProviderName')
set @DefaultReportingProductProviderCode  = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'ReportingProductProviderCode')
set @DefaultReportingProductProviderName  = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'ReportingProductProviderName')
--Clear down the Product Table
Truncate table msdt_Products
insert into msdt_Products
  (
  ProductCode, 
  ProductName, 
  ReportingProductCode, 
  ReportingProductName, 
  ProductSubGroupCode, 
  ProductSubGroupName, 
  ProductGroupCode, 
  ProductGroupName, 
  ProductCategoryCode, 
  ProductCategoryName, 
  ProductProviderCode, 
  ProductProviderName, 
  ReportingProductProviderCode, 
  ReportingProductProviderName
  )
select  ph.ProductCode, 
  cbp.ProductName, 
  ph.ReportingProductCode, 
  crpc.ReportingProductName, 
  ph.ProductSubGroupCode, 
  cpsg.ProductSubGroupName, 
  ph.ProductGroupCode, 
  cpg.ProductGroupName, 
  ph.ProductCategoryCode, 
  cpc.ProductCategoryName, 
  null as ProductProviderCode, 
  null as ProductProviderName, 
  ph.ReportingProductProviderCode, 
  ReportingProductProviderName
from mstt_ProductHierarchy ph
  inner join mstt_CodeBIProducts cbp
    on ph.ProductCode = cbp.ProductCode
  inner join mstt_CodeReportingProductCode crpc
    on ph.ReportingProductCode = crpc.ReportingProductCode
  inner join mstt_CodeProductSubGroup cpsg
    on ph.ProductSubGroupCode = cpsg.ProductSubGroupCode
  inner join mstt_CodeProductGroup cpg
    on ph.ProductGroupCode = cpg.ProductGroupCode
  inner join mstt_CodeProductCategory cpc
    on ph.ProductCategoryCode = cpc.ProductCategoryCode
  inner join mstt_CodeReportingProductProvider crpp
    on ph.ReportingProductProviderCode = crpp.ReportingProductProviderCode
where not exists (select 'x' from msdt_Products p where p.ProductCode = ph.ProductCode)   
--  update msdt_Products
--  set ProductGroupName = case when ProductGroupName = ProductCategoryName then ProductGroupName + ' Group' else ProductGroupName end,
--    ProductSubGroupName = case when ProductSubGroupName = ProductGroupName then ProductSubGroupName + ' Sub Group' else ProductSubGroupName end,
--    ReportingProductName = case when ReportingProductName = ProductSubGroupName then ReportingProductName + ' Reporting Product' else ReportingProductName end  
if not exists (select * from msdt_Products where ProductID = @DefaultProductID)
  begin
    SET IDENTITY_INSERT msdt_Products ON
    INSERT INTO msdt_Products 
    (
    ProductID, 
    ProductCode, 
    ProductName, 
    ReportingProductCode, 
    ReportingProductName, 
    ProductSubGroupCode, 
    ProductSubGroupName, 
    ProductGroupCode, 
    ProductGroupName, 
    ProductCategoryCode, 
    ProductCategoryName, 
    ProductProviderCode, 
    ProductProviderName, 
    ReportingProductProviderCode, 
    ReportingProductProviderName
    )
    select 
    @DefaultProductID, @DefaultProductCode, @DefaultProductName,
    @DefaultReportingProductCode, @DefaultReportingProductName,
    @DefaultProductSubGroupCode, @DefaultProductSubGroupName,
    @DefaultProductGroupCode, @DefaultProductGroupName,
    @DefaultProductCategoryCode, @DefaultProductCategoryName,
    @DefaultProductProviderCode, @DefaultProductProviderName,
    @DefaultReportingProductProviderCode, @DefaultReportingProductProviderName
--  update msdt_Products
--  set ProductGroupName = case when ProductGroupName = ProductCategoryName then ProductGroupName + ' Group' else ProductGroupName end,
--    ProductSubGroupName = case when ProductSubGroupName = ProductGroupName then ProductSubGroupName + ' Sub Group' else ProductSubGroupName end,
--    ReportingProductName = case when ReportingProductName = ProductSubGroupName then ReportingProductName + ' Reporting Product' else ReportingProductName end  
    SET IDENTITY_INSERT msdt_Products OFF
  end
  --Clear down the Product Table
  Truncate table msdt_ProductDummies
  --Insert the Dummy Products (product group level)
  insert into msdt_ProductDummies
  (
  ProductCode, 
  ProductName, 
  ReportingProductCode, 
  ReportingProductName, 
  ProductSubGroupCode, 
  ProductSubGroupName, 
  ProductGroupCode, 
  ProductGroupName, 
  ProductCategoryCode, 
  ProductCategoryName, 
  ProductProviderCode, 
  ProductProviderName, 
  ReportingProductProviderCode, 
  ReportingProductProviderName
  )
select  distinct
  cpg.ProductGroupName+'_DUMMY_CODE'  as ProductCode, 
  cpg.ProductGroupName      as ProductName, 
  cpg.ProductGroupName+'_DUMMY_CODE'  as ReportingProductCode, 
  cpg.ProductGroupName      as ReportingProductName, 
  cpg.ProductGroupName+'_DUMMY_CODE'  as ProductSubGroupCode, 
  cpg.ProductGroupName      as ProductSubGroupName, 
  cpg.ProductGroupCode,
  cpg.ProductGroupName, 
  ph.ProductCategoryCode, 
  cpc.ProductCategoryName, 
  'UNK' as ProductProviderCode, 
  'Unknown' as ProductProviderName, 
  'UNK' as ReportingProductProviderCode, 
  'Unknown' as ReportingProductProviderName
from mstt_ProductHierarchy ph
  inner join mstt_CodeBIProducts cbp
    on ph.ProductCode = cbp.ProductCode
  inner join mstt_CodeReportingProductCode crpc
    on ph.ReportingProductCode = crpc.ReportingProductCode
  inner join mstt_CodeProductSubGroup cpsg
    on ph.ProductSubGroupCode = cpsg.ProductSubGroupCode
  inner join mstt_CodeProductGroup cpg
    on ph.ProductGroupCode = cpg.ProductGroupCode
  inner join mstt_CodeProductCategory cpc
    on ph.ProductCategoryCode = cpc.ProductCategoryCode
  inner join mstt_CodeReportingProductProvider crpp
    on ph.ReportingProductProviderCode = crpp.ReportingProductProviderCode
where not exists (select 'x' from msdt_ProductDummies pd
    where pd.ProductCode = cpg.ProductGroupName+'_DUMMY_CODE')
--update msdt_ProductDummies
--  set ProductGroupName = case when ProductGroupName = ProductCategoryName then ProductGroupName + ' Group' else ProductGroupName end
END

GO
/****** Object:  StoredProcedure [dbo].[mstp_QualityDelegates]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**************************************************************************************************
Created by: Kris Zywczyk
Created on: 2010-07-21
Description: Update msct_QualityDelegates table

Changes:
--------
When        By whom        What changed
---------------------------------------------------------------------------------------------------

**************************************************************************************************/
create procedure [dbo].[mstp_QualityDelegates]
as
begin
  set nocount on;

  --Delete non existing delegations
  delete t
  from dbo.msct_QualityDelegates t
       left outer join (select DomainLogin = rtrim(ltrim(s.DomainLogin)),
                               DelegateOf  = rtrim(ltrim(s.DelegateOf))
                        from dbo.msit_QualityDelegates s
                        where rtrim(isnull(s.DomainLogin, '')) <> '' and
                              rtrim(isnull(s.DelegateOf, '')) <> '' and
                              left(ltrim(s.DomainLogin), 9) = 'OPENWORK\' and
                              left(ltrim(s.DelegateOf), 9) = 'OPENWORK\'
                        group by rtrim(ltrim(s.DomainLogin)),
                                 rtrim(ltrim(s.DelegateOf))) as x on t.DomainLogin = x.DomainLogin and
                                                                     t.DelegateOf  = x.DelegateOf
  where x.DomainLogin is null;
  
  --Insert new delegations
  insert into dbo.msct_QualityDelegates(DomainLogin,
                                        DelegateOf)
  select DomainLogin = rtrim(ltrim(s.DomainLogin)),
         DelegateOf  = rtrim(ltrim(s.DelegateOf))
  from dbo.msit_QualityDelegates s
       left outer join dbo.msct_QualityDelegates t on rtrim(ltrim(s.DomainLogin)) = t.DomainLogin and
                                                      rtrim(ltrim(s.DelegateOf))  = t.DelegateOf
  where rtrim(isnull(s.DomainLogin, '')) <> '' and
        rtrim(isnull(s.DelegateOf, '')) <> '' and
        left(ltrim(s.DomainLogin), 9) = 'OPENWORK\' and
        left(ltrim(s.DelegateOf), 9) = 'OPENWORK\' and
        t.DomainLogin is null
  group by rtrim(ltrim(s.DomainLogin)),
           rtrim(ltrim(s.DelegateOf));
end;
