CREATE procedure [dbo].[mstp_QualityProcess_Daily] 
as 

begin
--Daily Quality Tasks

--Build the Questions
exec mstp_CaseComplianceQuestion

--Build Case checks
exec mstp_CaseCheck

--Build Complaints
exec mstp_Complaint
exec mstp_ComplaintReason

--Build Targets
exec mstp_QualityTarget

--Do CORP Aggs
declare @MaxAQAMonth datetime
declare @RunMonth datetime

set @MaxAQAMonth = (select max(ReportMonth) 
      from mstt_AgentQualityAggregation
      where KPILevel = 'ADVISERKPI') -- First day of the month that we have Non-CORP Aggs for 
set @RunMonth = dateAdd(mm, 1, @MaxAQAMonth)   

exec mstp_AgentQualityAggregation_BaseValues @RunMonth
exec mstp_AgentQualityAggregation_BaseValues_Rolling6 @RunMonth
exec mstp_AgentQualityAggregation_CORP_SingleMonth @RunMonth 
exec mstp_AgentQualityAggregation_CORP_Rolling6 @RunMonth 

--ID284 - Stop daily execution of mstp_AgentQualityCases as this causes discrepanices when reconciling with monthly aggregations
--Ticket 184 - procedure now run in Monthly proc mstp_QualityProcess_Monthly

--Populate the table for Cases Assessed and Reasons for Failure sections
--exec mstp_AgentQualityCases

end

GO
/****** Object:  StoredProcedure [dbo].[mstp_QualityProcess_Monthly]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE procedure [dbo].[mstp_QualityProcess_Monthly]
as 

begin

/* 
Mike Cawood - 10 July 2007 - Ticket 184
Refresh mstt_AgentsQualityCases table (moved from Daily process) to ensure Data is consistent 
between the Reasons and ASD KPI reports and those reports based on Aggregate tables.
*/


declare @MaxAQAMonth datetime
declare @FirstDayOfReportMonth datetime

set @MaxAQAMonth = (select max(ReportMonth) from mstt_AgentQualityAggregation
      where KPILevel = 'ADVISERKPI')
set @FirstDayOfReportMonth = dateadd(mm, 1, @MaxAQAMonth)

-- select @MaxAQAMonth
-- select @FirstDayOfReportMonth

-- Ticket 184 MPC - refresh mstt_AgentQualityCases (to keep in line with Aggregates)
exec mstp_AgentQualityCases

--Build the Quality Hierarchy
exec mstp_AgentQualityHierarchy_Daily @FirstDayOfReportMonth

--Build KPI Aggregations
exec mstp_AgentQualityAggregation_BaseValues @FirstDayOfReportMonth
exec mstp_AgentQualityAggregation_BaseValues_Rolling6 @FirstDayOfReportMonth
exec mstp_AgentQualityAggregation_Adviser_SingleMonth @FirstDayOfReportMonth
exec mstp_AgentQualityAggregation_Adviser_Rolling6 @FirstDayOfReportMonth
exec mstp_AgentQualityAggregation_PS_SingleMonth @FirstDayOfReportMonth
exec mstp_AgentQualityAggregation_PS_Rolling6 @FirstDayOfReportMonth
exec mstp_AgentQualityAggregation_PSSummary_SingleMonth @FirstDayOfReportMonth
exec mstp_AgentQualityAggregation_PSSummary_Rolling6 @FirstDayOfReportMonth
exec mstp_AgentQualityAggregation_SQM_SingleMonth @FirstDayOfReportMonth
exec mstp_AgentQualityAggregation_SQM_Rolling6 @FirstDayOfReportMonth
exec mstp_AgentQualityAggregation_SQMSummary_SingleMonth @FirstDayOfReportMonth
exec mstp_AgentQualityAggregation_SQMSummary_Rolling6 @FirstDayOfReportMonth
exec mstp_AgentQualityAggregation_SQMPS_SingleMonth @FirstDayOfReportMonth
exec mstp_AgentQualityAggregation_SQMPS_Rolling6 @FirstDayOfReportMonth
exec mstp_AgentQualityAggregation_RSM_SingleMonth @FirstDayOfReportMonth
exec mstp_AgentQualityAggregation_RSM_Rolling6 @FirstDayOfReportMonth
exec mstp_AgentQualityAggregation_RSMSummary_SingleMonth @FirstDayOfReportMonth
exec mstp_AgentQualityAggregation_RSMSummary_Rolling6 @FirstDayOfReportMonth
exec mstp_AgentQualityAggregation_ASD_SingleMonth @FirstDayOfReportMonth
exec mstp_AgentQualityAggregation_ASD_Rolling6 @FirstDayOfReportMonth
exec mstp_AgentQualityAggregation_ASDSummary_SingleMonth @FirstDayOfReportMonth
exec mstp_AgentQualityAggregation_ASDSummary_Rolling6 @FirstDayOfReportMonth
truncate table mstt_Work_AgentQualityAggregation

--Build 'CURRENT' Aggregations.
--This requires deleting all 'Current' Aggregations throughout history,
--and rebuilding them.
delete from mstt_AgentQualityAggregation
where HierarchyTypeCode = 'CURRENT'

declare @MaxKPIAggMonth datetime
declare @MaxCurrentAggMonth datetime

set @MaxKPIAggMonth = (select max(ReportMonth) 
      from mstt_AgentQualityAggregation
      where KPILevel = 'SQMKPI'
      and HierarchyTypeCode = 'KPI')

set @MaxCurrentAggMonth = isnull((select max(ReportMonth) 
      from mstt_AgentQualityAggregation
      where KPILevel = 'SQMKPI'
      and HierarchyTypeCode = 'CURRENT'), '01 Jan 1900')

-- select @MaxKPIAggMonth
-- select @MaxCurrentAggMonth

while @MaxCurrentAggMonth < @MaxKPIAggMonth

begin
  set @FirstDayOfReportMonth = (select min(ReportMonth) 
          from mstt_AgentQualityAggregation
          where KPILevel = 'SQMKPI'
          and HierarchyTypeCode = 'KPI'
          and ReportMonth > @MaxCurrentAggMonth)

  truncate table mstt_Work_AgentQualityAggregation
  exec mstp_AgentQualityAggregation_PS_SingleMonth_Current @FirstDayOfReportMonth
  exec mstp_AgentQualityAggregation_PS_Rolling6_Current @FirstDayOfReportMonth
  exec mstp_AgentQualityAggregation_PSSummary_SingleMonth_Current @FirstDayOfReportMonth
  exec mstp_AgentQualityAggregation_PSSummary_Rolling6_Current @FirstDayOfReportMonth
  exec mstp_AgentQualityAggregation_Practice_SingleMonth_Current @FirstDayOfReportMonth
  exec mstp_AgentQualityAggregation_Practice_Rolling6_Current @FirstDayOfReportMonth
  exec mstp_AgentQualityAggregation_SQM_SingleMonth_Current @FirstDayOfReportMonth
  exec mstp_AgentQualityAggregation_SQM_Rolling6_Current @FirstDayOfReportMonth
  exec mstp_AgentQualityAggregation_SQMSummary_SingleMonth_Current @FirstDayOfReportMonth
  exec mstp_AgentQualityAggregation_SQMSummary_Rolling6_Current @FirstDayOfReportMonth
  exec mstp_AgentQualityAggregation_SQMPS_SingleMonth_Current @FirstDayOfReportMonth
  exec mstp_AgentQualityAggregation_SQMPS_Rolling6_Current @FirstDayOfReportMonth
  exec mstp_AgentQualityAggregation_RSM_SingleMonth_Current @FirstDayOfReportMonth
  exec mstp_AgentQualityAggregation_RSM_Rolling6_Current @FirstDayOfReportMonth
  exec mstp_AgentQualityAggregation_RSMSummary_SingleMonth_Current @FirstDayOfReportMonth
  exec mstp_AgentQualityAggregation_RSMSummary_Rolling6_Current @FirstDayOfReportMonth
  exec mstp_AgentQualityAggregation_ASD_SingleMonth_Current @FirstDayOfReportMonth
  exec mstp_AgentQualityAggregation_ASD_Rolling6_Current @FirstDayOfReportMonth
  exec mstp_AgentQualityAggregation_ASDSummary_SingleMonth_Current @FirstDayOfReportMonth
  exec mstp_AgentQualityAggregation_ASDSummary_Rolling6_Current @FirstDayOfReportMonth
  truncate table mstt_Work_AgentQualityAggregation
  
  set @MaxCurrentAggMonth = isnull((select max(ReportMonth) 
        from mstt_AgentQualityAggregation
        where KPILevel = 'SQMKPI'
        and HierarchyTypeCode = 'CURRENT'), '01 Jan 1900')

end


--Build Product Aggregations
exec mstp_AgentProductAggregation_Adviser
exec mstp_AgentProductAggregation_PS
exec mstp_AgentProductAggregation_PRACTICE
exec mstp_AgentProductAggregation_SQM
exec mstp_AgentProductAggregation_RSM
exec mstp_AgentProductAggregation_ASD
exec mstp_AgentProductAggregation_Corp

update statistics mstt_AgentQualityAggregation
update statistics mstt_CaseCheck
update statistics mstt_Clients
update statistics mstt_Policies
update statistics mstt_Agents
update statistics mstt_AgentQualityHierarchy

exec mscp_AdvisersInQualitySpan
exec mstp_QualityProcess_Daily

end


GO
