CREATE PROCEDURE [dbo].[mstp_ReasonForLeaving] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
*******************************************************************************/
truncate table msdt_ReasonForLeaving
insert into msdt_ReasonForLeaving (ReasonForLeavingCode, ReasonForLeavingDescription)
select distinct ReasonForLeaving, null
from mstt_Agents
where ReasonForLeaving is not null
update rl
set rl.ReasonForLeavingDescription = dl.Description
from msdt_ReasonForLeaving rl
  inner join msdt_DropLists dl
    on rl.ReasonForLeavingCode = dl.Code
where dl.CodeType = 'ReasonForLeaving'
if not exists (select * from msdt_ReasonForLeaving where ReasonForLeavingId = -99)
 begin
  SET IDENTITY_INSERT msdt_ReasonForLeaving ON
  insert into msdt_ReasonForLeaving (ReasonForLeavingId, ReasonForLeavingCode,ReasonForLeavingDescription) 
  values           (-99, 'UNK', 'Unknown')
  SET IDENTITY_INSERT msdt_ReasonForLeaving OFF
 end 

