/****** Object:  StoredProcedure [dbo].[mstp_Recruitment]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO



CREATE PROCEDURE [dbo].[mstp_Recruitment] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : Matt Kennedy
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>Matt Kennedy</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

*******************************************************************************/


-- PROCEDURE BODY GOES HERE
BEGIN


/***************************** TPR 802 ***********************************/
--need to store historical data in order to produce figures per month
--therefore no need to truncate mstt_Recruitment
--Terry Lister 23/11/2005:
--The mechanism for providing recruitment data to the Sales BI warehouse will
--provide a spreadsheet on a regular (probably daily) basis.  In a given
--month, this spreadsheet should overwrite the previous data for the month,
--so that when viewing recruitment data during that month it will change as
--time goes on.  The field Period Start will contain the day/month/year to
--which the data relates.
-- 
--At the end of a month, the spreadsheet will show the details for that
--month.  A snapshot of this data should be stored in warehouse so that when
--viewed after the end of the month, it never changes. 
/***************************** TPR 802 ***********************************/

truncate table mstt_Recruitment


set DateFormat dmy

--if mstt table holds the same PeriodStart (or same month but different date) to msit then remove it and add the latest one from msit
--if msit holds new month then add to mstt 

declare @ImportPeriodStart       datetime,
  @PostedPeriodStart       datetime,
  @DefaultRecruitPeriodStart datetime,
  @PostedDate      nvarchar(6),
  @ImportDate            nvarchar(6)


set @DefaultRecruitPeriodStart = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'RecruitPeriodStart')
set @ImportPeriodStart         = (select max([Period Start]) from msit_Recruitment) --assuming should only ever be 1 date or same date for all rows?????
set @PostedPeriodStart         = isnull((select max([PeriodStart]) from mstt_Recruitment), @DefaultRecruitPeriodStart)
set @PostedDate          = (select convert(nvarchar(6), @PostedPeriodStart,112))
set @ImportDate          = (select convert(nvarchar(6), @ImportPeriodStart,112))


begin

  select 
    [Period Start] as PeriodStart, 
    --Period, 
    ForeName as RecruitFirstName, 
    case when nullif(Surname, ' ') is not null then Surname else null end as RecruitSurname, 
    null as RecruitOSCARCode, 
    case when nullif(Surname, ' ') is not null then [Agent Code] else null end as RecruitSWIFTCode,
    case when nullif(Surname, ' ') is null then coalesce([Franchise Name], Surname) else null end as FranchiseName, 
    null as FranchiseOSCARCode, 
    case when nullif(Surname, ' ') is null then [Agent Code] else null end as FranchiseSWIFTCode,
    Type as RecruitType, 
    --RecruitCategory, 
    Status as RecruitStatus,
    cast('Unknown' as nvarchar(255)) as RecruitStatusDescription,
    [Pipeline Stage] as PipelineStage,
    cast('Unknown' as nvarchar(255)) as PipelineStageDescription,
    [ASD or CRM] as ASDorCRM,
    --null as SwiftASMAgentID, 
    --CR 57:
    [ASD ID] as SwiftASMAgentID,
    cast([RSM ID] as varchar(255)) as SwiftRSMAgentID, 
    [Pipe Start] as PipelineStartDate, 
    coalesce([Status Date], cast(nullif([Prospect Start Date],'') as smalldatetime)) as StatusDate,
    Income, 
    Age, 
    [Previous Role] as PreviousRole, 
    [Ind Exp] as IndustryExperience, 
    [Target Turnover] as TargetTurnover, 
    [RSM Name] as RSMName
  into #mstt_Recruitment
  from msit_Recruitment
  where
    [Period Start] = @ImportPeriodStart
  
  
  --CR 57: Use the Dummy RSM for the Given ASD, if RSM is not present
  update rec
  set SwiftRSMAgentID = ltrim(rtrim(isnull(a_RSM.Code, 'UNK')))
  from #mstt_Recruitment rec
    inner join mstt_Agents a
      on rec.SwiftASMAgentID = a.Code 
    inner join mstt_Agents a_RSM
      on a_RSM.Manager4Code = a.Code
  where nullif(rec.SwiftRSMAgentID,' ') is null
  and a_RSM.DESCN like '%RSM%'
    
  --Sellers with no Swift Code, but they DO have an RSM
  update r
  set RecruitSwiftCode =  isnull(RecruitFirstName, '')+' '
        +isnull(RecruitSurname, '')+' '
        +isnull(SwiftRSMAgentID, '')
  from #mstt_Recruitment r
  where nullif(RecruitSurname,' ') is not null
  and nullif(RecruitSwiftCode,' ') is null
  and nullif(SwiftRSMAgentID,' ') is not null
  
  --Sellers, without a swift code, or RSM
  update r
  set RecruitSwiftCode =  isnull(RecruitFirstName, '')+' '
        +isnull(RecruitSurname, '')+' '
        +'UNK'  
  from #mstt_Recruitment r
  where nullif(RecruitSurname,' ') is not null
  and nullif(SwiftRSMAgentID,' ') is null
  and nullif(RecruitSwiftCode,' ') is null
  
  
  --Franchises, that DO have a Swift Code
  update r
  set RecruitSwiftCode =  isnull(FranchiseSwiftCode, '')
  from #mstt_Recruitment r
  where nullif(FranchiseSwiftCode,' ') is not null
  
  
  --Franchises, WITHOUT a Swift Code, but with an RSM
  update r
  set RecruitSwiftCode =  isnull(FranchiseName, '')+' '+isnull(SwiftRSMAgentID, ''),
    FranchiseSwiftCode = isnull(FranchiseName, '')+' '+isnull(SwiftRSMAgentID, '')
  from #mstt_Recruitment r
  where nullif(FranchiseName,' ') is not null
  and nullif(FranchiseSwiftCode,' ') is null
  and nullif(SwiftRSMAgentID,' ') is not null
  
  
  
  --Franchises, without a Swift Code, or RSM
  update r
  set RecruitSwiftCode =  isnull(FranchiseName, '')+' '+'UNK',
    FranchiseSwiftCode = isnull(FranchiseName, '')+' '+'UNK'
  from #mstt_Recruitment r
  where nullif(FranchiseSwiftCode,' ') is null
  and nullif(FranchiseName,' ') is not null
  and nullif(SwiftRSMAgentID,' ') is null
  
  
  --Append new month or latest version to mstt_Recruitment
  insert into mstt_Recruitment
  (
    PeriodStart, 
    --Period, 
    RecruitFirstName, 
    RecruitSurname, 
    RecruitOSCARCode, 
    RecruitSwiftCode, 
    FranchiseName, 
    FranchiseOSCARCode, 
    FranchiseSwiftCode, 
    RecruitType, 
    --RecruitCategory, 
    RecruitStatus, 
    RecruitStatusDescription,
    PipelineStage,
    PipelineStageDescription,
    ASDorCRM,
    SwiftASMAgentID, 
    SwiftRSMAgentID, 
    PipelineStartDate, 
    StatusDate, 
    Income, 
    Age, 
    PreviousRole, 
    IndustryExperience, 
    TargetTurnover, 
    RSMName
  )
  
  select 
    PeriodStart,
    RecruitFirstName,
    RecruitSurname,
    RecruitOSCARCode,
    RecruitSwiftCode,
    FranchiseName,
    FranchiseOSCARCode,
    FranchiseSwiftCode,
    RecruitType,
    RecruitStatus,
    RecruitStatusDescription,
    PipelineStage,
    PipelineStageDescription ,
    ASDorCRM,
    SwiftASMAgentID,
    SwiftRSMAgentID,
    PipelineStartDate,
    StatusDate,
    Income,
    Age,
    PreviousRole, 
    IndustryExperience,
    TargetTurnover,
    RSMName
  from 
   #mstt_Recruitment
  
  drop table #mstt_Recruitment

  select * into #Recruitment
  from mstt_Recruitment
  where recruitstatus = 'APPS'

  delete from mstt_Recruitment
  where recruitstatus = 'APPS'

  insert into mstt_Recruitment
  select Distinct
    case when (ag.DateStarted = '1 Jun 2005' and OscarDateStarted is not null) 
      then ag.OscarDateStarted else DateStarted end  as PeriodStart, 
    null as Period, 
    rtrim(FirstNames) as RecruitFirstName, 
    rtrim(Name) as RecruitSurname, 
    OscarAgentId as RecruitOSCARCode, 
    Code as RecruitSwiftCode, 
    rtrim(isnull(r.FranchiseName, ad.Franchise)) as FranchiseName, 
    null as FranchiseOSCARCode, 
    rtrim(isnull(r.FranchiseSwiftCode, ad.FranchiseCode)) as FranchiseSwiftCode, 
    r.RecruitType as RecruitType, 
    r.RecruitCategory as RecruitCategory, 
    'APPS' as RecruitStatus, 
    null as RecruitStatusDescription, 
    'EMP' as PipelineStage, 
    null as PipelineStageDescription, 
    r.ASDorCRM as ASDorCRM, 
    isnull(r.SwiftASMAgentID, ad.AreaSalesManagerCode) as SwiftASMAgentID, 
    isnull(r.SwiftRSMAgentID, ad.RegionalSalesManagerCode) as SwiftRSMAgentID, 
    null as PipelineStartDate, 
    case when (ag.DateStarted = '1 Jun 2005' and OscarDateStarted is not null) 
      then ag.OscarDateStarted else DateStarted end as StatusDate, 
    null as Income, 
    null as Age, 
    r.PreviousRole as PreviousRole, 
    r.IndustryExperience as IndustryExperience, 
    r.TargetTurnover as TargetTurnover, 
    null as RSMName
  from mstt_Agents ag
    inner join msdt_Adviser ad
      on ag.Code = ad.AgentCode
    left join #Recruitment r
      on ag.Code = r.RecruitSwiftCode
  where ag.CompetentStatus <> '5'
  and AgentType in ('4', '43', '51', '2', '46', '47', '49') -- This is the rule applied to the Capacity Data, so these two areas should match.

  update t
  set RecruitStatusDescription = rl.Description
  from mstt_Recruitment t
    inner join msit_RecruitmentLegends rl
      on t.RecruitStatus = rl.Code
  where rl.Code is not null
  
  update t
  set PipelineStageDescription = rl.Description
  from mstt_Recruitment t
    inner join msit_RecruitmentLegends rl
      on t.PipelineStage = rl.Code
  where rl.Code is not null
  
  update t
  set RecruitStatusDescription = RecruitStatus
  from mstt_Recruitment t
  where RecruitStatusDescription = 'Unknown'
  and RecruitStatus is not null
  
  update t
  set PipelineStageDescription = PipelineStage
  from mstt_Recruitment t
  where PipelineStageDescription = 'Unknown'
  and PipelineStage is not null

drop table #Recruitment

end

END


GO
/****** Object:  StoredProcedure [dbo].[mstp_RecruitmentFact]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
create PROCEDURE [dbo].[mstp_RecruitmentFact] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : Matt Kennedy
Created : %DateCreated%  
          
    Date    Author    Description
    29/09/2008  A Groves  Replaced getdate() with ProcessDate to enable proc
                to run before midnight.
    15/06/2009  P Robathan  Change Update from statement as SQL Server 2005 changes
                sort order if inner join returns more than one table

*******************************************************************************/


-- PROCEDURE BODY GOES HERE
BEGIN

truncate table msft_Recruitment

set dateformat dmy

--TPR 801: This is required for Projected Turnover This Year calculation
declare @AverageNumberOfDaysInPipe  int,
    @ProcessDate        datetime  -- AG 29/09/2008

set @AverageNumberOfDaysInPipe  = (select convert(int,DefaultValue) from mstt_DefaultCodeValues where CodeColumn = 'AverageNumberOfDaysInPipe')

set @ProcessDate        = (select ProcessDate from mst_ImportControl where Type = 'Openwork' and Module = 'Swift') -- AG 29/09/2008

insert into msft_Recruitment 
(
  PeriodStart, 
  Period, 
  DateID, 
  RecruitFirstName, 
  RecruitSurname, 
  RecruitSwiftCode, 
  RecruitID, 
  FranchiseName, 
  FranchiseSwiftCode, 
  RecruitType, 
  RecruitCategory, 
  RecruitStatus, 
  RecruitStatusDescription,
  PipelineStageCode,
  PipelineStageDescription,
  SwiftASMAgentID, 
  SwiftRSMAgentID, 
  PipelineStartDate, 
  PipelineStartDateID, 
  StatusDate, 
  StatusDateID, 
  Income, 
  Age, 
  PreviousRole, 
  IndustryExperience, 
  TargetTurnover, --TPR 801: This is the Projected Turnover Full Year 
  RSMName, 
  NumberRecruits
)
select 
  case when r.RecruitStatus = 'NPW' then StatusDate else PeriodStart end as PeriodStart, 
  Period, 
  -99 as DateID,
  RecruitFirstName, 
  RecruitSurname, 
  RecruitSwiftCode, 
  -99 as RecruitID,
  r.FranchiseName, 
  FranchiseSwiftCode, 
  r.RecruitType, 
  RecruitCategory, 
  r.RecruitStatus, 
  RecruitStatusDescription,
  PipelineStage,
  PipelineStageDescription,
  SwiftASMAgentID, 
  SwiftRSMAgentID, 
  PipelineStartDate, 
  -99 as PipeLineStartDateId,
  StatusDate, 
  -99 as StatusDateId,
  Income, 
  Age, 
  PreviousRole, 
  IndustryExperience, 
  TargetTurnover, 
  RSMName,
  1
from mstt_Recruitment r

update r
set RecruitID = (select max(rd.RecruitID) from msdt_Recruits rd where r.RecruitSwiftCode = rd.RecruitCode)
from msft_Recruitment r

/* PR Jun 2009 Update statement replaced with statement above
update r
set RecruitID = rd.RecruitID
from msft_Recruitment r
  inner join msdt_Recruits rd
    on r.RecruitSwiftCode = rd.RecruitCode
*/

-- KS 31/05/06 - TPRs around Recruitment numbers
select distinct RecruitId
into #DA_Recruits
from msdt_Recruits r, mstt_Agents a
where r.FranchiseCode = a.Code
and a.agenttypedescription = 'Directly Authorised'

delete from msft_Recruitment
where RecruitId in (select distinct RecruitId from #DA_Recruits)

drop table #DA_Recruits

update t
set DateID = c.DateID
from msft_Recruitment t
  inner join msdt_CalendarTime c
    on t.PeriodStart = c.[DateTime]
  inner join mst_DateTimeControl dtc
    on c.EntryTypeID = dtc.EntryTypeID
where dtc.EntryType = 'DateIssued'

update t
set ComparisonId = (select ComparisonId from msdt_Comparison where Comparison = 'Actual')
from msft_Recruitment t

update t
set ProjectedTurnoverThisYear = (TargetTurnover) * 
  convert(float,(convert(int,datediff(dd,dateadd(dd,@AverageNumberOfDaysInPipe, PipelineStartDate),
    convert(datetime,(convert(nvarchar(4),year(@ProcessDate),112) + '12'+ '31'))))) ) / 365 -- AG 29/09/2008
from msft_Recruitment t
 


--Load Targets into Recruitment Fact Table
insert into msft_Recruitment
(
DateID, 
ComparisonId,
RecruitID, 
RecruitType, 
RecruitCategory, 
RecruitStatus, 
RecruitStatusDescription, 
PipelineStageCode, 
PipelineStageDescription, 
PipelineStartDateID,  
StatusDateID, 
PreviousRole, 
IndustryExperience, 
NumberRecruits
)
select 
  DateId,
  ComparisonId,
  AdviserId as RecruitId,
  'Unknown' as RecruitType,
  'Unknown' as RecruitCategory,
  'APPS' as RecruitStatus,
  (select top 1 Description from msit_RecruitmentLegends where Code = 'APPS'),
  'UNK' as PipelineStageCode,
  'Unknown' as PipelineStageDescription,
  -99 as PipeLineStartDateId,
  -99 as StatusDateId,
  'Unknown' as PreviousRole,
  'UNK' as IndustryExperience,
  RecruitsAppointed as NumberRecruits

from mstt_TargetRecruitment

where isnull(RecruitsAppointed, 0) <> 0

union all

select 
  DateId,
  ComparisonId,
  AdviserId as RecruitId,
  'Unknown' as RecruitType,
  'Unknown' as RecruitCategory,
  'PIPE' as RecruitStatus,
  (select top 1 Description from msit_RecruitmentLegends where Code = 'PIPE'),
  'UNK' as PipelineStageCode,
  'Unknown' as PipelineStageDescription,
  -99 as PipeLineStartDateId,
  -99 as StatusDateId,
  'Unknown' as PreviousRole,
  'UNK' as IndustryExperience,
  RecruitsInPipeline as NumberRecruits

from mstt_TargetRecruitment

where isnull(RecruitsInPipeline, 0) <> 0

update t
set ProjectedTurnoverThisYear = 0
from msft_Recruitment t
where ProjectedTurnoverThisYear is null



END



GO
/****** Object:  StoredProcedure [dbo].[mstp_Recruits]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
