CREATE PROCEDURE [dbo].[mstp_Recruits] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : Matt Kennedy
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>Matt Kennedy</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

*******************************************************************************/


-- PROCEDURE BODY GOES HERE
BEGIN


truncate table msdt_Recruits



insert into msdt_Recruits 
(
RecruitName, 
RecruitCode, 
RecruitType, 
RecruitStatus, 
FranchiseCode, 
FranchiseName, 
RegionalSalesManagerCode, 
RegionalSalesManager, 
AreaSalesManagerCode, 
AreaSalesManager, 
[Exec]
)


--Get sellers who have a valid Swift Code, and an RSM Code
select distinct 
  RecruitFirstName+' '+RecruitSurname   as RecruitName,  
  RecruitSwiftCode      as RecruitCode, 
  RecruitType,
  RecruitStatus,
  'UNK'         as FranchiseCode, 
  'Yet to be allocated'     as FranchiseName,
  SwiftRSMAgentID       as RegionalSalesManagerCode,
  'Unknown'         as RegionalSalesManager,
  case when r.ASDorCRM <> 'ASD' 
    then 'CRM'
    else SwiftASMAgentID end  as AreaSalesManagerCode,
  'Yet to be allocated'     as AreaSalesManager,
  'Yet to be allocated'       as [Exec]
from mstt_Recruitment r
inner join mstt_Agents a
  on r.RecruitSwiftCode = a.Code
where nullif(r.RecruitSurname, ' ') is not null
and nullif(r.RecruitSwiftCode, ' ') is not null
and nullif(SwiftRSMAgentID, ' ') is not null



union all

--Get sellers who have a valid Swift Code, and NO RSM Code
select distinct 
  RecruitFirstName+' '+RecruitSurname   as RecruitName,  
  RecruitSwiftCode      as RecruitCode, 
  RecruitType,
  RecruitStatus,
  'UNK'         as FranchiseCode, 
  'Yet to be allocated'       as FranchiseName,
  'UNK'         as RegionalSalesManagerCode,
  'Yet to be allocated'         as RegionalSalesManager,
  case when r.ASDorCRM <> 'ASD' 
    then 'CRM'
    else SwiftASMAgentID end  as AreaSalesManagerCode,
  'Yet to be allocated'       as AreaSalesManager,
  'Yet to be allocated'         as [Exec]
from mstt_Recruitment r
inner join mstt_Agents a
  on r.RecruitSwiftCode = a.Code
where nullif(r.RecruitSurname, ' ') is not null
and nullif(r.RecruitSwiftCode, ' ') is not null
and nullif(SwiftRSMAgentID, ' ') is null


union all

--Get the sellers who have a 'Non Swift' Swift Code, but DO have an RSM Code
select distinct 
  RecruitFirstName+' '+RecruitSurname   as RecruitName,
  RecruitSwiftCode      as RecruitCode, 
  RecruitType,
  RecruitStatus,
  'UNK'           as FranchiseCode,
  'Yet to be allocated'         as FranchiseName,
  SwiftRSMAgentID       as RegionalSalesManagerCode,
  'Yet to be allocated'         as RegionalSalesManager,
  case when r.ASDorCRM <> 'ASD' 
    then 'CRM'
    else SwiftASMAgentID end  as AreaSalesManagerCode,
  'Yet to be allocated'       as AreaSalesManager,
  'Yet to be allocated'         as [Exec]
from mstt_Recruitment r
where nullif(r.RecruitSurname, ' ') is not null
and not exists (select 'x' from mstt_Agents a where r.RecruitSwiftCode = a.Code)
and nullif(r.SwiftRSMAgentID, ' ') is not null

union all

--Get the sellers who have a 'Non Swift' Swift Code, but no RSM
select distinct 
  RecruitFirstName+' '+RecruitSurname   as RecruitName,
  RecruitSwiftCode      as RecruitCode, 
  RecruitType,
  RecruitStatus,
  'UNK'           as FranchiseCode,
  'Yet to be allocated'         as FranchiseName,
  'UNK'         as RegionalSalesManagerCode,
  'Yet to be allocated'         as RegionalSalesManager,
  case when r.ASDorCRM <> 'ASD' 
    then 'CRM'
    else SwiftASMAgentID end  as AreaSalesManagerCode,
  'Yet to be allocated'       as AreaSalesManager,
  'Yet to be allocated'         as [Exec]
from mstt_Recruitment r
where nullif(r.RecruitSurname, ' ') is not null
and not exists (select 'x' from mstt_Agents a where r.RecruitSwiftCode = a.Code)
and nullif(r.SwiftRSMAgentID, ' ') is null



union all


--get Franchises who have a valid Franchise Code, and an RSM code
select distinct 
  FranchiseName       as RecruitName,  
  RecruitSwiftCode      as RecruitCode, 
  RecruitType,
  RecruitStatus,
  FranchiseSwiftCode      as FranchiseCode, 
  FranchiseName         as FranchiseName,
  SwiftRSMAgentId       as RegionalSalesManagerCode,
  'Yet to be allocated'       as RegionalSalesManager,
  case when r.ASDorCRM <> 'ASD' 
    then 'CRM'
    else SwiftASMAgentID end  as AreaSalesManagerCode,
  'Yet to be allocated'       as AreaSalesManager,
  'Yet to be allocated'         as [Exec]
from mstt_Recruitment r
inner join mstt_Agents a
  on r.FranchiseSwiftCode = a.Code
where nullif(r.FranchiseName, ' ') is not null
and nullif(r.FranchiseSwiftCode, ' ') is not null
and nullif(r.SwiftRSMAgentID, ' ') is not null


union all

--get Franchises who have valid Codes, but no RSM
select distinct 
  FranchiseName       as RecruitName,  
  RecruitSwiftCode      as RecruitCode, 
  RecruitType,
  RecruitStatus,
  FranchiseSwiftCode      as FranchiseCode, 
  FranchiseName         as FranchiseName,
  'UNK'         as RegionalSalesManagerCode,
  'Yet to be allocated'       as RegionalSalesManager,
  case when r.ASDorCRM <> 'ASD' 
    then 'CRM'
    else SwiftASMAgentID end  as AreaSalesManagerCode,
  'Yet to be allocated'       as AreaSalesManager,
  'Yet to be allocated'         as [Exec]
from mstt_Recruitment r
inner join mstt_Agents a
  on r.FranchiseSwiftCode = a.Code
where nullif(FranchiseName, ' ') is not null
and nullif(SwiftRSMAgentID, ' ') is null


union all

--Get the franchises who have a Non-Swift Code, and valid RSM Code
select distinct 
  FranchiseName       as RecruitName, 
  RecruitSwiftCode      as RecruitCode, 
  RecruitType,
  RecruitStatus,
  FranchiseName+' '+SwiftRSMAgentID as FranchiseCode,
  FranchiseName         as FranchiseName,
  SwiftRSMAgentID       as RegionalSalesManagerCode,
  'Yet to be allocated'         as RegionalSalesManager,
  case when r.ASDorCRM <> 'ASD' 
    then 'CRM'
    else SwiftASMAgentID end  as AreaSalesManagerCode,
  'Yet to be allocated'       as AreaSalesManager,
  'Yet to be allocated'         as [Exec]
from mstt_Recruitment r
where not exists (select 'x' from mstt_Agents a where r.FranchiseSwiftCode = a.Code)
and nullif(r.SwiftRSMAgentID, ' ') is not null
and nullif(r.FranchiseName, ' ') is not null

union all

--Get the franchises who have a Non-Swift Code, and no RSM Code
select distinct 
  FranchiseName       as RecruitName, 
  RecruitSwiftCode      as RecruitCode, 
  RecruitType,
  RecruitStatus,
  FranchiseName+' '+SwiftRSMAgentID as FranchiseCode,
  FranchiseName         as FranchiseName,
  'UNK'         as RegionalSalesManagerCode,
  'Yet to be allocated'         as RegionalSalesManager,
  case when r.ASDorCRM <> 'ASD' 
    then 'CRM'
    else SwiftASMAgentID end  as AreaSalesManagerCode,
  'Yet to be allocated'       as AreaSalesManager,
  'Yet to be allocated'         as [Exec]
from mstt_Recruitment r
where not exists (select 'x' from mstt_Agents a where r.FranchiseSwiftCode = a.Code)
and nullif(r.SwiftRSMAgentID, ' ') is null
and nullif(r.FranchiseName, ' ') is not null



--Get Missing Franchise Codes
update rec
set FranchiseCode = isnull(coalesce(a.FranchiseCode, a.DirectlyAuthorisedCode, a.OfficeCode), 'UNK')
from msdt_Recruits rec
  inner join mstt_Agents a
    on rec.RecruitCode = a.Code
where rec.FranchiseCode = 'UNK'

--Get Missing Franchise Name
update rec
set FranchiseName = ltrim(rtrim(isnull(a.DESCN, 'Yet to be allocated')))
from msdt_Recruits rec
  inner join mstt_Agents a
    on rec.FranchiseCode = a.Code
where rec.FranchiseName in ('Unknown','Yet to be allocated')


--Get Missing RSM Code
update rec
set RegionalSalesManagerCode = ltrim(rtrim(isnull(a.Manager2Code, 'UNK')))
from msdt_Recruits rec
  inner join mstt_Agents a
    on rec.FranchiseCode = a.Code 
where rec.RegionalSalesManagerCode = 'UNK'

--CR 57: Use the Dummy RSM for the Given ASD, if RSM is not present
update rec
set RegionalSalesManagerCode = ltrim(rtrim(isnull(a_RSM.Code, 'UNK')))
from msdt_Recruits rec
  inner join mstt_Agents a
    on rec.AreaSalesManagerCode = a.Code 
  inner join mstt_Agents a_RSM
    on a_RSM.Manager4Code = a.Code
where rec.RegionalSalesManagerCode = 'UNK'
and a_RSM.DESCN like '%RSM%'

--Get Missing RSM Name
update rec
set RegionalSalesManager = ltrim(rtrim(isnull(a.DESCN, 'Yet to be allocated')))
from msdt_Recruits rec
  inner join mstt_Agents a
    on rec.RegionalSalesManagerCode = a.Code
where rec.RegionalSalesManagerCode <> 'UNK'


--Get Missing ASM Code
update rec
set AreaSalesManagerCode = ltrim(rtrim(isnull(a.Manager4Code, 'UNK')))
from msdt_Recruits rec
  inner join mstt_Agents a
    on rec.RegionalSalesManagerCode = a.Code 
where rec.AreaSalesManagerCode = 'UNK'


--Get Missing ASM Name
update rec
set AreaSalesManager = ltrim(rtrim(isnull(a.DESCN, 'Yet to be allocated')))
from msdt_Recruits rec
  inner join mstt_Agents a
    on rec.AreaSalesManagerCode = a.Code

    
update rec
set AreaSalesManager = 'Central Recruitment'
from msdt_Recruits rec
where AreaSalesManagerCode = 'CRM'
    


update rec
set [Exec] = e.Code
from msdt_Recruits rec
  inner join mstt_Agents a
    on rec.AreaSalesManagerCode = a.Code
  inner join mstt_Agents e
    on a.CompanyCode = e.Code


update rec 
set FranchiseSizeId = a.FranchiseSizeId
from msdt_Recruits rec
  inner join msdt_Adviser a
    on rec.FranchiseCode = a.FranchiseCode

update msdt_Recruits 
set FranchiseSizeId = -99
where FranchiseSizeId is null

update msdt_Recruits 
set RecruitSourceId = -99
where RecruitSourceId is null

if not exists (select * from msdt_Recruits where RecruitId = -99)
  begin
    set identity_insert msdt_Recruits on
    
    insert into msdt_Recruits 
      (RecruitId,
      RecruitName, 
      RecruitCode, 
      RecruitType, 
      RecruitStatus, 
      RecruitSourceId,
      FranchiseCode, 
      FranchiseName,
      FranchiseSizeId,
      RegionalSalesManagerCode, 
      RegionalSalesManager, 
      AreaSalesManagerCode, 
      AreaSalesManager, 
      [Exec])
    select 
      -99,
      'Unknown', 
      'UNK', 
      'Unknown', 
      'UNK', 
      -99,
      'UNK', 
      'Yet to be allocated',
      -99, 
      'UNK', 
      'Yet to be allocated', 
      'UNK', 
      'Yet to be allocated', 
      'Yet to be allocated'
  
    set identity_insert msdt_Recruits off
  
  end


END




GO
