declare @DefaultDirectlyAuthorisedAgentCode        varchar(50)
declare @DefaultManager1Code                       varchar(50)
declare @DefaultManager2Code                       varchar(50)
declare @DefaultManager3Code                       varchar(50)
declare @DefaultManager4Code                       varchar(50)
declare @DefaultRegionName                         varchar(50)
declare @ProcessDate                 datetime -- AG 29/09/2008



set @DefaultCompanyCode                   = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'CompanyCode')
set @DefaultCompanyName                   = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'CompanyName')
set @DefaultAreaSalesManagerName          = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AreaSalesManagerName')
set @DefaultAreaSalesManagerCode          = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AreaSalesManagerCode')
set @DefaultAreaName                      = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AreaName')
set @DefaultAreaCode                      = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AreaCode')
set @DefaultRegionalSalesManagerName      = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'RegionalSalesManagerName')
set @DefaultRegionalSalesManagerCode      = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'RegionalSalesManagerCode')
set @DefaultSalesQualityManagerName       = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'SalesQualityManagerName')
set @DefaultSalesQualityManagerCode       = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'SalesQualityManagerCode')
set @DefaultFranchiseName                 = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'FranchiseName')
set @DefaultFranchiseCode                 = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'FranchiseCode')
set @DefaultFranchiseSizeID               = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'FranchiseSizeID')
set @DefaultFranchiseSegmentID            = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'FranchiseSegmentID')
set @DefaultPracticePrincipalName         = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'PracticePrincipalName')
set @DefaultPracticePrincipalCode         = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'PracticePrincipalCode')
set @DefaultPracticeSupervisorName        = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'PracticeSupervisorName')
set @DefaultPracticeSupervisorCode        = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'PracticeSupervisorCode')
set @DefaultPracticeAdministratorName     = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'PracticeAdministratorName')
set @DefaultPracticeAdministratorCode     = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'PracticeAdministratorCode')
set @DefaultAdviserID                     = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'AdviserID')
set @DefaultAdviserName                   = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AdviserName')
set @DefaultAgentCode                     = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AgentCode')
set @DefaultBusinessTypeID                = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'BusinessTypeID')
set @DefaultProductID                     = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'ProductID')
set @DefaultCommissionTransactionID       = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'CommmissionTransactionID')
set @DefaultDateWrittenID                 = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'DateWrittenID')
set @DefaultDateIssuedID                  = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'DateIssuedID')
set @DefaultPipelineFlagID                = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'PipelineFlagID')
set @DefaultPipelineAgeBandID             = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'PipelineAgeBandID')
set @DefaultComparisonID                  = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'ComparisonID')
set @DefaultCommissionBasisID             = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'CommissionBasisID')
set @DefaultFrequencyID                   = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'FrequencyID')
set @DefaultBusinessReasonID              = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'BusinessReasonID')
set @DefaultSubmissionMethodID            = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'SubmissionMethodID')
set @DefaultStrategicAllianceAgentCode    = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'StrategicAllianceAgentCode')
set @DefaultAccessAgentCode               = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AccessAgentCode')
set @DefaultFranchiseAgentCode            = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'FranchiseAgentCode')
set @DefaultCompanyAgentCode              = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'CompanyAgentCode')
set @DefaultOrganisationAgentCode         = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'OrganisationAgentCode')
set @DefaultDirectlyAuthorisedAgentCode   = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'DirectlyAuthorisedAgentCode')
set @DefaultManager1Code                  = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'Manager1Code')
set @DefaultManager2Code                  = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'Manager2Code')
set @DefaultManager3Code                  = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'Manager3Code')
set @DefaultManager4Code                  = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'Manager4Code')
set @DefaultRegionName                    = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'RegionName')
set @ProcessDate              = (select ProcessDate from mst_ImportControl where Type = 'Openwork' and Module = 'Swift') -- AG 29/09/2008




--Clear the sales fact table.
Truncate table msft_Sales

--Get the grain records into a Temp Table. 
--This table will be used as a placeholder while we get 
--all the dimension surrogate keys etc. We then load the final fact table
--with just the keys and measures.
--'-99' is used by default for the Surrogate keys, as this ensures that there are no
--nulls in the key fields, which would either result in the cube build failing, 
--or the rows with the null field(s) being skipped, thus under-reporting the measures.

--Get the 'Commission' records.
select 
  c.PolicyID                           as PolicyNumber,
  c.Agent_Code                         as AgentCode,
  c.TransactionID                      as TransactionID,
  c.ID                                 as CommissionTransactionID,
  @DefaultAdviserID                    as AdviserID,
  case 
  when c.PolTranTransType = 39 then 'Written' 
    else 'Issued' end                as BusinessType,
  @DefaultBusinessTypeID               as BusinessTypeID,
  c.ProductCode,
  @DefaultProductID                    as ProductID,
  convert(datetime, 
  convert(varchar(10), 
  c.transactionwrittendate, 103), 103) as DateWritten,
  @DefaultDateWrittenID                as DateWrittenID,
  case 
  when c.PolTranTransType <> 39 then 
  convert(datetime, 
  convert(varchar(10), 
  c.transactiondate, 103), 103) 
  else null end                        as DateIssued,
  @DefaultDateIssuedID                 as DateIssuedID,
  convert(datetime, 
  convert(varchar(10),
  c.transactiondate, 103), 103)        as TransactionDate,
  @DefaultDateIssuedID                 as TransactionDateID,
  cast('No' as varchar(10))            as PipelineFlag,
  @DefaultPipelineFlagID               as PipelineFlagID,
  @DefaultPipelineAgeBandID            as PipelineAgeBandID,
  c.FranchiseSize                      as FranchiseSize,
  @DefaultFranchiseSizeID              as FranchiseSizeID,
  cast(' ' as varchar(10))             as FranchiseSegment,
  @DefaultFranchiseSegmentID           as FranchiseSegmentID,
  'Actual'                             as ComparisonType,
  @DefaultComparisonID                 as ComparisonID,
  c.AdminMethod                        as CommissionBasis,
  @DefaultCommissionBasisId            as CommissionBasisId,
  c.Frequency                          as Frequency,  
  @DefaultFrequencyId                  as FrequencyId,
  c.BusinessReason                     as BusinessReason,
  @DefaultBusinessReasonId             as BusinessReasonId,
  c.OriginatingSource                  as SubmissionMethod,
  @DefaultSubmissionMethodId           as SubmissionMethodId,
  isnull(StrategicAllianceAgentCode, @DefaultStrategicAllianceAgentCode)      as StrategicAllianceAgentCode,
  isnull(AccessAgentCode, @DefaultAccessAgentCode)                            as AccessAgentCode,
  isnull(FranchiseAgentCode, @DefaultFranchiseAgentCode)                      as FranchiseAgentCode,
  isnull(CompanyAgentCode, @DefaultCompanyName)                               as CompanyAgentCode,
  isnull(OrganisationAgentCode, @DefaultOrganisationAgentCode)                as OrganisationAgentCode,
  isnull(DirectlyAuthorisedAgentCode, @DefaultDirectlyAuthorisedAgentCode)    as DirectlyAuthorisedAgentCode,
  isnull(Manager1Code, @DefaultManager1Code)                                  as Manager1Code,
  isnull(Manager2Code, @DefaultManager2Code)                                  as Manager2Code,
  isnull(Manager3Code, @DefaultManager3Code)                                  as Manager3Code,
  isnull(Manager4Code, @DefaultManager4Code)                                  as Manager4Code,
  isnull(Firm, @DefaultFranchiseAgentCode)                                    as Firm,
  cast(c.Turnover as Float)                       as Turnover,
  cast(c.APE as Float)                            as APE,
  cast(c.FixedAmount as Float)                    as NBI,
  cast(0 as Float)                                as DA,
  cast(c.SalesMargin as Float)                    as Margin,
  cast(1 * (c.Agent_Perc / 100) as Float)         as Cases,
  cast(0 as Float)                                as DaysInPipeline

into #SalesStaging_Commissions    
  
from mstt_Commissions c

where (c.PolTranTransType = 39 or 
  c.TransactionId in (select distinct TransactionId 
                         from mstt_Expectation 
                         where TransactionId is not null))  --Only Issued and Written transactions
and c.GrossOrNet = 'G'      --Only 'Franchise' figures (ie NOT Openwork figures)
and c.CommissionType = 1


--Update Sales table for Distribution Allowance
Update
 #SalesStaging_Commissions
set
 DA =  isnull(NBI,0) + isnull(Margin,0)


/*

MK: Commenting out this section, as it was decided that for a PolicyTransaction to be 
  considered a 'Sale', there MUST be an associated Commission Record (S_AGTCOM in Swift)
  
  
--Get the Policy Transactions records


select 
  pt.PolicyID as PolicyNumber,
  pt.AgentCode as AgentCode,
  pt.ID as TransactionID,
  @DefaultCommissionTransactionID as CommissionTransactionID,
  @DefaultAdviserID as AdviserID,
  case when pt.TransType = 17 then 'Issued' else 'Written' end as BusinessType,
  @DefaultBusinessTypeID as BusinessTypeID,
  p.ProductCode,
  @DefaultProductID as ProductID,
  pt.TransactionWrittenDate as DateWritten,
  @DefaultDateWrittenID as DateWrittenID,
  case when pt.TransType = 17 then pt.TransactionDate else null end as DateIssued,
  @DefaultDateIssuedID as DateIssuedID,
  cast('No' as varchar(10)) as PipelineFlag,
  @DefaultPipelineFlagID as PipelineFlagID,
  @DefaultPipelineAgeBandID as PipelineAgeBandID,
  cast(' ' as varchar(10)) as FranchiseSize,
  @DefaultFranchiseSizeID as FranchiseSizeID,
  cast(' ' as varchar(10)) as FranchiseSegment,
  @DefaultFranchiseSegmentID as FranchiseSegmentID,
  'Actual' as ComparisonType,
  @DefaultComparisonID as ComparisonID,
  cast(null as varchar(7)) as StrategicAllianceAgentCode,
  cast(null as varchar(7)) as AccessAgentCode,
  cast(null as varchar(7)) as FranchiseAgentCode,
  cast(null as varchar(7)) as CompanyAgentCode,
  cast(null as varchar(7)) as OrganisationAgentCode,
  cast(null as varchar(7)) as DirectlyAuthorisedAgentCode,
  cast(null as varchar(7)) as Manager1Code,
  cast(null as varchar(7)) as Manager2Code,
  cast(null as varchar(7)) as Manager3Code,
  cast(null as varchar(7)) as Manager4Code,
  cast(0 as Float) as Turnover,
  cast(APE as Float) as APE,
  cast(0 as Float) as NBI,
  cast(0 as Float) as DA,
  cast(0 as Float) as Margin,
  cast(0 as Float) as Cases,
  cast(0 as Float) as DaysInPipeline

into #SalesStaging_PolicyTransactions   
  
from mstt_PolicyTransactions pt
  inner join mstt_Policies p
    on pt.PolicyID = p.POL_NUM
*/



--Combine these records into one temp table.
select q.PolicyNumber, 
  q.TransactionID, 
  q.AgentCode, 
  q.AdviserID, 
  q.CommissionTransactionID,
  max(BusinessType)                               as BusinessType, 
  max(BusinessTypeID)                             as BusinessTypeID, 
  max(ProductCode)                                as ProductCode, 
  max(ProductID)                                  as ProductID, 
  max(DateWritten)                                as DateWritten, 
  max(DateWrittenID)                              as DateWrittenID, 
  max(DateIssued)                                 as DateIssued, 
  max(DateIssuedID)                               as DateIssuedID, 
  max(TransactionDate)                            as TransactionDate, 
  max(TransactionDateID)                          as TransactionDateID,   
  max(PipelineFlag)                               as PipelineFlag,
  max(PipelineFlagID)                             as PipelineFlagID, 
  max(PipelineAgeBandID)                          as PipelineAgeBandID,
  max(FranchiseSize)                              as FranchiseSize, 
  max(FranchiseSizeID)                            as FranchiseSizeID, 
  max(FranchiseSegment)                           as FranchiseSegment,
  max(FranchiseSegmentID)                         as FranchiseSegmentID, 
  max(ComparisonType)                             as ComparisonType, 
  max(ComparisonID)                               as ComparisonID, 
  max(CommissionBasis)                            as CommissionBasis,
  max(CommissionBasisId)                          as CommissionBasisId,
  max(Frequency)                                  as Frequency, 
  max(FrequencyId)                                as FrequencyId,
  max(BusinessReason)                             as BusinessReason,
  max(BusinessReasonId)                           as BusinessReasonId,
  max(SubmissionMethod)                           as SubmissionMethod,
  max(SubmissionMethodId)                         as SubmissionMethodId,
  isnull(max(StrategicAllianceAgentCode), @DefaultStrategicAllianceAgentCode)     as StrategicAllianceAgentCode, 
  isnull(max(AccessAgentCode), @DefaultAccessAgentCode)                           as AccessAgentCode, 
  isnull(max(FranchiseAgentCode), @DefaultFranchiseAgentCode)                     as FranchiseAgentCode, 
  isnull(max(CompanyAgentCode), @DefaultCompanyName)                              as CompanyAgentCode, 
  isnull(max(OrganisationAgentCode), @DefaultOrganisationAgentCode)               as OrganisationAgentCode, 
  isnull(max(DirectlyAuthorisedAgentCode), @DefaultDirectlyAuthorisedAgentCode)   as DirectlyAuthorisedAgentCode, 
  isnull(max(Manager1Code), @DefaultManager1Code)                                 as Manager1Code, 
  isnull(max(Manager2Code), @DefaultManager2Code)                                 as Manager2Code, 
  isnull(max(Manager3Code), @DefaultManager3Code)                                 as Manager3Code, 
  isnull(max(Manager4Code), @DefaultManager4Code)                                 as Manager4Code, 
  isnull(max(Firm), @DefaultFranchiseAgentCode)                                   as Firm, 
  sum(Turnover)                                       as Turnover, 
  sum(APE)                                            as APE, 
  sum(NBI)                                            as NBI, 
  sum(DA)                                             as DA, 
  sum(Margin)                                         as Margin, 
  sum(Cases)                                          as Cases, 
  sum(DaysInPipeline)                                 as DaysInPipeline

into #SalesStaging_Consolidated

from 
(
--select * from #SalesStaging_PolicyTransactions
--union all
select * from #SalesStaging_Commissions
) q
group by q.PolicyNumber, 
  q.TransactionID, 
  q.AgentCode, 
  q.AdviserID, 
  q.CommissionTransactionID
order by 1, 2, 3



--Now we need to check the Franchise that we were given 
--on these records to see if we need to add this structure to the msdt_adviser table.
--This is because, for example, a seller could do a sale on behalf of a completely different
--franchise than that to which they belong.

--Get the distinct 'hierarchy' from the fact records.
--only get AgentCatgories that exist in msdt_Adviser
select distinct 
  isnull(c.AgentCode, @DefaultAgentCode)        as AgentCode, 
  isnull(c.Firm, @DefaultFranchiseAgentCode)    as FranchiseAgentCode,
  ' ' as IsNew
into #TransactionHierarchy
from #SalesStaging_Consolidated c
  inner join mstt_Agents a
    on c.AgentCode = a.Code
where a.AgentCategory in (select distinct AgentCategory 
            from mstt_Agents ag, msdt_Adviser ad
            where ag.Code = ad.AgentCode)
order by 1,2



--Check to see if this is a 'new' hierarchy - ie one that is NOT in msdt_Adviser.
update t
set IsNew = 'Y'
from #TransactionHierarchy t
where not exists (select 'x' from msdt_Adviser a
    where t.AgentCode = a.AgentCode
    and t.FranchiseAgentCode = a.FranchiseCode)


--Get the 'new' records into a temp table with the structure of the msdt_Adviser table
select  cast(@DefaultCompanyName as varchar(255))            as [Exec], 
  cast(@DefaultAreaSalesManagerName as varchar(255))       as AreaSalesManager, 
  cast(@DefaultManager4Code as varchar(255))               as AreaSalesManagerCode, 
  null                                                     as AreaSalesQualityManager, 
  null                                                     as AreaSalesQualityManagerCode, 
  cast(@DefaultAreaName as varchar(255))                   as AreaName, 
  cast('UNK' as varchar(255))                              as AreaCode, 
  cast(@DefaultRegionalSalesManagerName as varchar(255))   as RegionalSalesManager, 
  cast(@DefaultManager2Code as varchar(255))               as RegionalSalesManagerCode, 
  cast(@DefaultRegionName as varchar(255))                 as RegionName, 
  cast('UNK' as varchar(255))                              as RegionCode, 
  null                                                     as SalesQualityManager, 
  null                                                     as SalesQualityManagerCode, 
  cast(@DefaultFranchiseName as varchar(255))              as Franchise, 
  isnull(FranchiseAgentCode, @DefaultFranchiseAgentCode)   as FranchiseCode, 
  @DefaultFranchiseSizeID                                  as FranchiseSizeID, 
  @DefaultFranchiseSegmentID                               as FranchiseSegmentID, 
  cast(@DefaultPracticePrincipalName as varchar(255))      as PracticePrincipal, 
  cast(@DefaultPracticePrincipalCode as varchar(255))      as PracticePrincipalCode, 
  cast(@DefaultPracticeSupervisorName as varchar(255))     as PracticeSupervisor, 
  cast(@DefaultPracticeSupervisorCode as varchar(255))     as PracticeSupervisorCode, 
  cast(@DefaultPracticeAdministratorName as varchar(255))  as PracticeAdministrator, 
  cast(@DefaultPracticeAdministratorCode as varchar(255))  as PracticeAdministratorCode, 
  cast(@DefaultAdviserName as varchar(255))                as Adviser, 
  AgentCode                                                as AgentCode, 
  null                                                     as TransactionDate, 
  null                                                     as DomainName, 
  null                                                     as ChangeDate, 
  0                                                        as IsCurrent

into 
  #NewAgents
from 
  #TransactionHierarchy 
where
  IsNew = 'Y'



--update this record set with the missing fields - names etc... from msdt_Adviser, joining on FranchiseCode
--We go to this table because msdt_Adviser is already populated with the current values
--for the fields above Franchise Level.
update t
set [Exec]                     = a.[Exec], 
  AreaSalesManager           = a.AreaSalesManager, 
  AreaSalesManagerCode       = a.AreaSalesManagerCode, 
  AreaName                   = a.AreaName, 
  AreaCode                   = a.AreaCode, 
  RegionalSalesManager       = a.RegionalSalesManager, 
  RegionalSalesManagerCode   = a.RegionalSalesManagerCode, 
  RegionName                 = a.RegionName, 
  RegionCode                 = a.RegionCode, 
  Franchise                  = a.Franchise,
  FranchiseSizeId            = a.FranchiseSizeId,
  FranchiseSegmentId         = a.FranchiseSegmentId
from #NewAgents t
  inner join msdt_Adviser a
    on t.FranchiseCode = a.FranchiseCode


update t
set Adviser = a.DESCN
from #NewAgents t
  inner join mstt_Agents a
    on t.AgentCode = a.Code
 

--insert the 'new' records to the adviser table.
insert into msdt_Adviser
  ([Exec], AreaSalesManager, AreaSalesManagerCode, AreaSalesQualityManager, AreaSalesQualityManagerCode, 
  AreaName, AreaCode, RegionalSalesManager, RegionalSalesManagerCode, 
  RegionName, RegionCode, SalesQualityManager, SalesQualityManagerCode, 
  Franchise, FranchiseCode, FranchiseSizeID, FranchiseSegmentID, 
  PracticePrincipal, PracticePrincipalCode, PracticeSupervisor, PracticeSupervisorCode, 
  PracticeAdministrator, PracticeAdministratorCode, Adviser, AgentCode, 
  TransactionDate, DomainName, ChangeDate, IsCurrent)
select [Exec], AreaSalesManager, AreaSalesManagerCode, AreaSalesQualityManager, AreaSalesQualityManagerCode, 
  AreaName, AreaCode, RegionalSalesManager, RegionalSalesManagerCode, 
  RegionName, RegionCode, SalesQualityManager, SalesQualityManagerCode, 
  Franchise, FranchiseCode, FranchiseSizeID, FranchiseSegmentID, 
  PracticePrincipal, PracticePrincipalCode, PracticeSupervisor, PracticeSupervisorCode, 
  PracticeAdministrator, PracticeAdministratorCode, Adviser, AgentCode, 
  TransactionDate, DomainName, ChangeDate, IsCurrent
from #NewAgents



--Set the PipelineFlag and DaysInPipeline
update t
  set DaysInPipeline = datediff(d, DateWritten, isnull(DateIssued, @ProcessDate)) -- AG 29/09/2008
from #SalesStaging_Consolidated t



update t
set PipelineFlag = 'Yes'
from #SalesStaging_Consolidated t
where BusinessType = 'Written' 
and DateIssued is null


--Resolve the surrogate keys
update t
set AdviserID = a.AdviserID,
  FranchiseSizeID = a.FranchiseSizeID,
  FranchiseSegmentID = a.FranchiseSegmentID
from #SalesStaging_Consolidated t
  inner join msdt_Adviser a
    on t.AgentCode = a.AgentCode
        and  Coalesce(nullif(Firm, @DefaultFranchiseAgentCode), 
         nullif(FranchiseAgentCode, @DefaultFranchiseAgentCode), 
             nullif(DirectlyAuthorisedAgentCode, @DefaultFranchiseAgentCode),
             nullif(StrategicAllianceAgentCode, @DefaultFranchiseAgentCode), 
             nullif(AccessAgentCode, @DefaultFranchiseAgentCode), 
             @DefaultFranchiseAgentCode) = a.FranchiseCode



update t
set BusinessTypeID = b.BusinessTypeID
from #SalesStaging_Consolidated t
  inner join msdt_BusinessType b
    on t.BusinessType = b.BusinessType



update t
set ProductID = p.ProductID
from #SalesStaging_Consolidated t
  inner join msdt_Products p
    on t.ProductCode = p.ProductCode



update t
set DateWrittenID = c.DateID
from #SalesStaging_Consolidated t
  inner join msdt_CalendarTime c
    on t.DateWritten = c.[DateTime]
  inner join mst_DateTimeControl dtc
    on c.EntryTypeID = dtc.EntryTypeID
where dtc.EntryType = 'DateWritten'



update t
set DateIssuedID = c.DateID
from #SalesStaging_Consolidated t
  inner join msdt_CalendarTime c
    on t.DateIssued = c.[DateTime]
  inner join mst_DateTimeControl dtc
    on c.EntryTypeID = dtc.EntryTypeID
where dtc.EntryType = 'DateIssued'



update t
set TransactionDateID = c.DateID
from #SalesStaging_Consolidated t
  inner join msdt_CalendarTime c
    on t.TransactionDate = c.[DateTime]
  inner join mst_DateTimeControl dtc
    on c.EntryTypeID = dtc.EntryTypeID
where dtc.EntryType = 'DateIssued'



update t
set PipelineFlagID = p.FlagID
from #SalesStaging_Consolidated t
  inner join msdt_PipelineFlag p
    on t.PipelineFlag = p.PipelineFlag



update t
set PipelineAgeBandID = p.AgeID
from #SalesStaging_Consolidated t
  inner join msdt_PipelineAge p
    on t.DaysInPipeline = p.Age



update t
set ComparisonID = c.ComparisonID
from #SalesStaging_Consolidated t
  inner join msdt_Comparison c
    on t.ComparisonType = c.Comparison
    


update t
set CommissionBasisId = c.CommissionBasisID
from #SalesStaging_Consolidated t
  inner join msdt_CommissionBasis c
    on t.CommissionBasis = c.CommissionBasisCode
    

    
update t
set FrequencyId = f.FrequencyId
from #SalesStaging_Consolidated t
  inner join msdt_Frequency f
    on cast(t.Frequency as varchar(50)) = f.FrequencyCode

    
    
update t
set BusinessReasonId = br.BusinessReasonID
from #SalesStaging_Consolidated t
  inner join msdt_BusinessReason br
    on t.BusinessReason = br.BusinessReasonCode

    
    
update t
set SubmissionMethodID = sm.SubmissionMethodID
from #SalesStaging_Consolidated t
  inner join msdt_SubmissionMethod sm
    on cast(t.SubmissionMethod as varchar(50)) = sm.SubmissionMethodCode
    
    
    


/*

MK: Commenting out this section, as we are NOT trying to update any fact rows. The rule is now that we
  will simply be truncating the Sales Table EACH DAY, therefore no need to build contra records, 
  or update any fact rows.

--let's now delete the records that we do not want to put into the sales fact table, 
--because they are already there and are unchanged.
delete sc
from #SalesStaging_Consolidated sc
  inner join msft_Sales s
    on sc.PolicyNumber    = s.PolicyNumber
    and sc.TransactionID    = s.TransactionID
    and sc.CommissionTransactionID  = s.CommissionTransactionID
    and sc.AdviserID    = s.AdviserID
    and isnull(sc.Turnover,0)   = isnull(s.Turnover,0)
    and isnull(sc.APE,0)    = isnull(s.APE,0)
    and isnull(sc.NBI,0)    = isnull(s.NBI,0)
    and isnull(sc.DA,0)     = isnull(s.DA,0)
    and isnull(sc.Margin,0)   = isnull(s.Margin,0)
    and isnull(sc.Cases,0)    = isnull(s.Cases,0)


--now we need to decide whether we need to generate a 'contra' record, because
--we have an update for the fact record. That is, either the hierarchy has changed, 
--or the value of the measure(s).
select s.* 
into #ContraRecords
from #SalesStaging_Consolidated sc
  inner join msft_Sales s
    on sc.PolicyNumber = s.PolicyNumber
    and sc.TransactionID = s.TransactionID
    and sc.CommissionTransactionID = s.CommissionTransactionID
where sc.AdviserID    <> s.AdviserID
or isnull(sc.Turnover,0)  <> isnull(s.Turnover,0)
or isnull(sc.APE,0)     <> isnull(s.APE,0)
or isnull(sc.NBI,0)     <> isnull(s.NBI,0)
or isnull(sc.DA,0)    <> isnull(s.DA,0)
or isnull(sc.Margin,0)    <> isnull(s.Margin,0)
or isnull(sc.Cases,0)     <> isnull(s.Cases,0)


--Contra-ise the records
update c
set   Turnover  = Turnover  * -1, 
  APE     = APE     * -1, 
  NBI     = NBI     * -1, 
  DA    = DA    * -1, 
  Margin    = Margin  * -1, 
  Cases     = Cases   * -1, 
  DaysInPipeline  = DaysInPipeline * -1
from #ContraRecords c

--insert the contras to the fact table
insert into msft_Sales 
(
PolicyNumber, AgentCode, TransactionId, CommissionTransactionID, AdviserId, BusinessTypeId, ProductId, 
DateWrittenId, DateIssuedId, TransactionDateID, PipelineFlagId, PipelineAgeBandId, FranchiseSizeId, 
FranchiseSegmentId, ComparisonId, Turnover, APE, NBI, DA, Margin, Cases, DaysInPipeline
)
select 
PolicyNumber, AgentCode, TransactionID, CommissionTransactionID, AdviserID, BusinessTypeID, ProductID, 
DateWrittenID, DateIssuedID, TransactionDateID, PipelineFlagID, PipelineAgeBandID, FranchiseSizeID, 
FranchiseSegmentID, ComparisonID, nullif(Turnover,0), nullif(APE,0), nullif(NBI,0), nullif(DA,0), nullif(Margin,0), nullif(Cases,0), nullif(DaysInPipeline,0)
from #ContraRecords

*/

--insert the new fact rows.
insert into msft_Sales
  (
  PolicyNumber, 
  AgentCode, 
  TransactionId, 
  CommissionTransactionID,
  AdviserId, 
  BusinessTypeId, 
  ProductId, 
  DateWrittenId, 
  DateIssuedId, 
  TransactionDateId,
  PipelineFlagId, 
  PipelineAgeBandId, 
  FranchiseSizeId, 
  FranchiseSegmentId, 
  ComparisonId, 
  CommissionBasisId,
  FrequencyId,
  BusinessReasonId,
  SubmissionMethodId,
  Turnover, 
  APE, 
  NBI, 
  DA, 
  Margin, 
  Cases, 
  DaysInPipeline
  )
select 
  PolicyNumber, 
  AgentCode, 
  TransactionID, 
  CommissionTransactionID,
  AdviserID, 
  BusinessTypeID, 
  ProductID, 
  DateWrittenID, 
  DateIssuedID, 
  TransactionDateID,
  PipelineFlagID, 
  PipeLineAgeBandID,
  FranchiseSizeID, 
  FranchiseSegmentID, 
  ComparisonID, 
  CommissionBasisId,
  FrequencyId,
  BusinessReasonId,
  SubmissionMethodId,
  nullif(Turnover,0), 
  nullif(APE,0), 
  nullif(NBI,0), 
  nullif(DA,0), 
  nullif(Margin,0), 
  nullif(Cases,0), 
  nullif(DaysInPipeline,0)
from #SalesStaging_Consolidated


--Now we need to check to see if we need to remove the pipelineflag from any written records.
--This suggests that an 'Issued' transaction has appeared for a written transaction.
update f
set PipeLineFlagID = (select FlagID from msdt_PipelineFlag where PipelineFlag = 'No')
from msft_Sales f
  inner join #SalesStaging_Consolidated sc
    on f.PolicyNumber = sc.PolicyNumber
    and f.AgentCode = sc.AgentCode
    and f.Turnover = sc.Turnover
  inner join msdt_BusinessType bt
    on f.BusinessTypeID = bt.BusinessTypeID
where sc.BusinessType = 'Issued'
and bt.BusinessType = 'Written'


--Reset the DaysInPipeline. If something is still in the pipeline, then the value needs to be re-generated.
update f
set DaysInPipeline = datediff(d, dw.DateTime, 
      case when f.DateIssuedID = @DefaultDateIssuedID  
          then @ProcessDate 
          else di.DateTime end) -- AG 29/09/2008
from msft_Sales f
  inner join msdt_CalendarTime dw
    on f.DateWrittenID = dw.DateID
  inner join msdt_CalendarTime di
    on f.DateIssuedID = di.DateID 
  inner join msdt_PipelineFlag pf
    on f.PipelineFlagID = pf.FlagID
where pf.PipeLineFlag = 'Yes'



--Drop our temp objects.
drop table #SalesStaging_Commissions
drop table #SalesStaging_Consolidated
drop table #TransactionHierarchy
drop table #NewAgents 
--drop table #ContraRecords



END


GO
/****** Object:  StoredProcedure [dbo].[mstp_SalesFromFranchisePlans]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[mstp_SalesFromFranchisePlans] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
*******************************************************************************/
-- PROCEDURE BODY GOES HERE
BEGIN
declare @PipelineYes        int
declare @PipelineNo       int
declare @DefaultCommissionBasisID   int
declare @DefaultFrequencyID     int
declare @DefaultBusinessReasonID    int
declare @DefaultSubmissionMethodID    int
set @PipelineYes      = (select FlagID from msdt_PipelineFlag where PipelineFlag = 'Yes')
set @PipelineNo       = (select FlagID from msdt_PipelineFlag where PipelineFlag = 'No')
set @DefaultCommissionBasisID   = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'CommissionBasisID')
set @DefaultFrequencyID     = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'FrequencyID')
set @DefaultBusinessReasonID    = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'BusinessReasonID')
set @DefaultSubmissionMethodID    = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'SubmissionMethodID')
select 
  -9 as PolicyNumber,
  AdviserDummyCode as AgentCode,
  -9 as TransactionId,
  -9 as CommissionTransactionId,
  AdviserId,
  BusinessTypeId,
  ProductId,
  cast(convert(varchar(30), dateCode, 118) as datetime) as TransactionDate,
  case when BusinessType in ('Written', 'Pipeline') then DateId else -99 end as DateWrittenId,
  case when BusinessType = 'Issued' then DateId else -99 end as DateIssuedId,
  -99 as TransactionDateId,
  case when BusinessType = 'Pipeline' then @PipelineYes else @PipelineNo end as PipelineFlagId,
  -99 as PipelineAgeBandId,
  -99 as FranchiseSizeId,
  -99 as FranchiseSegmentId,
  ComparisonId,
  nullif(Turnover,0) as Turnover,
  null as DaysInPipeline
into #SalesFromFranchisePlans
from mstt_TargetFranchisePlans
/*
select cast(convert(varchar(30), dateCode, 118) as datetime), * from mstt_TargetProduction
*/
update t
set TransactionDateID = c.DateID
from #SalesFromFranchisePlans t
  inner join msdt_CalendarTime c
    on t.TransactionDate = c.[DateTime]
  inner join mst_DateTimeControl dtc
    on c.EntryTypeID = dtc.EntryTypeID
where dtc.EntryType = 'DateIssued'
declare @ActualComparisonID int
set @ActualComparisonID = (select ComparisonID from msdt_Comparison where Comparison = 'Actual')
delete from msft_Sales
where PolicyNumber = -9 --@DefaultPolicyNumber
and TransactionID = -9 --@DefaultTransactionID
and CommissionTransactionID = -9 --@DefaultCommissionTransactionID
and ComparisonID <> @ActualComparisonID --This combination is specific to Transition Issued Production.
insert into msft_Sales
  (PolicyNumber, 
  AgentCode, 
  TransactionId, 
  CommissionTransactionID, 
  AdviserId, 
  BusinessTypeId, 
  ProductId, 
  DateWrittenId, 
  DateIssuedId, 
  TransactionDateId, 
  PipelineFlagId, 
  PipelineAgeBandId, 
  FranchiseSizeId, 
  FranchiseSegmentId, 
  ComparisonId, 
  CommissionBasisId,
  FrequencyId,
  BusinessReasonId,
  SubmissionMethodId,
  Turnover, 
  APE, 
  NBI, 
  DA, 
  Margin, 
  Cases, 
  DaysInPipeline)
select 
  PolicyNumber, 
  AgentCode, 
  TransactionId, 
  CommissionTransactionID, 
  AdviserId, 
  BusinessTypeId, 
  ProductId, 
  DateWrittenId, 
  DateIssuedId, 
  TransactionDateId, 
  PipelineFlagId, 
  PipelineAgeBandId, 
  FranchiseSizeId, 
  FranchiseSegmentId, 
  ComparisonId, 
  @DefaultCommissionBasisId,
  @DefaultFrequencyId,
  @DefaultBusinessReasonId,
  @DefaultSubmissionMethodId,
  Turnover, 
  null as APE, 
  null as NBI, 
  null as DA, 
  null as Margin, 
  null as Cases, 
  DaysInPipeline
from #SalesFromFranchisePlans
drop table #SalesFromFranchisePlans
END

