CREATE PROCEDURE [dbo].[mstp_SalesFromTransitionIssuedProduction] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : Matt Kennedy
Created : %DateCreated%  
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>Matt Kennedy</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
*******************************************************************************/
-- PROCEDURE BODY GOES HERE
BEGIN
declare @DefaultFranchiseSizeID     int
declare @DefaultFranchiseSegmentID      int
declare @DefaultCommissionTransactionID   int
declare @DefaultDateWrittenID     int
declare @DefaultDateIssuedID      int
declare @DefaultPipelineFlagID      int
declare @DefaultPipelineAgeBandID   int
declare @DefaultComparisonID      int
declare @DefaultFranchiseAgentCode    varchar(50)
declare @DefaultPolicyNumber      int
declare @DefaultTransactionID     int
declare @DefaultCommissionBasisID   int
declare @DefaultFrequencyID     int
declare @DefaultBusinessReasonID    int
declare @DefaultSubmissionMethodID    int
set @DefaultFranchiseSizeID     = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'FranchiseSizeID')
set @DefaultFranchiseSegmentID    = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'FranchiseSegmentID')
set @DefaultCommissionTransactionID = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'CommmissionTransactionID')
set @DefaultDateWrittenID   = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'DateWrittenID')
set @DefaultDateIssuedID    = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'DateIssuedID')
set @DefaultPipelineFlagID    = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'PipelineFlagID')
set @DefaultPipelineAgeBandID   = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'PipelineAgeBandID')
set @DefaultComparisonID    = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'ComparisonID')
set @DefaultFranchiseAgentCode    = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'FranchiseAgentCode')
set @DefaultPolicyNumber    = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'PolicyNumber')
set @DefaultTransactionID   = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'TransactionID')
set @DefaultCommissionBasisID   = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'CommissionBasisID')
set @DefaultFrequencyID     = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'FrequencyID')
set @DefaultBusinessReasonID    = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'BusinessReasonID')
set @DefaultSubmissionMethodID    = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'SubmissionMethodID')
--Get the grain records into a Temp Table. 
--This table will be used as a placeholder while we get 
--all the dimension surrogate keys etc. We then load the final fact table
--with just the keys and measures.
--'-99' is used by default for the Surrogate keys, as this ensures that there are no
--nulls in the key fields, which would either result in the cube build failing, 
--or the rows with the null field(s) being skipped, thus under-reporting the measures.
select 
  @DefaultPolicyNumber    as PolicyNumber,
  SellerSwiftCode     as AgentCode,
  @DefaultTransactionID     as TransactionID,
  AdviserID,
  BusinessType,
  BusinessTypeID,
  SwiftProductCode    as ProductCode,
  ProductID,
  null        as DateWritten,
  @DefaultDateWrittenID     as DateWrittenID,
  PeriodEndDate       as DateIssued,
  DateIssuedID,
  'No'        as PipelineFlag,
  @DefaultPipelineFlagID    as PipelineFlagID,
  @DefaultPipelineAgeBandID   as PipelineAgeBandID,
  FranchiseSize,
  FranchiseSizeID,
  FranchiseSegment,
  FranchiseSegmentID,
  'Actual'      as ComparisonType,
  @DefaultComparisonID    as ComparisonID,
  FranchiseSwiftCode    as FranchiseAgentCode,
  BusinessReasonId    as BusinessReasonId,
  nullif(Turnover,0)    as Turnover, 
  nullif(APE,0)     as APE, 
  nullif(NBI,0)     as NBI, 
  nullif(DA,0)      as DA, 
  nullif(Margin,0)    as Margin, 
  nullif(Cases,0)     as Cases, 
  cast(0 as Float)    as DaysInPipeline
into #SalesStaging_IssuedProduction   
from mstt_TransitionIssuedProduction
where AdviserID <> -99
and SellerSwiftCode is not null
--select * from #SalesStaging_Commissions
/*
select * from #SalesStaging_PolicyTransactions
where TransactionID in (8,12,46,49)
select * from #SalesStaging_Commissions
where TransactionID in (8,12,46,49)
select q.* --q.PolicyNumber, q.TransactionID, q.AdviserID
from 
(
select * from #SalesStaging_PolicyTransactions
union all
select * from #SalesStaging_Commissions
) q
order by 1, 5 desc, 3, 2
*/
select AgentCode, AdviserID, DateIssued, DateIssuedID, ProductCode, ProductID, 
  max(PolicyNumber)   as PolicyNumber,
  max(TransactionID)    as TransactionID,
  max(BusinessType)     as BusinessType, 
  max(BusinessTypeID)     as BusinessTypeID, 
  max(DateWritten)    as DateWritten, 
  max(DateWrittenID)    as DateWrittenID, 
  max(PipelineFlag)   as PipelineFlag,
  max(PipelineFlagID)     as PipelineFlagID, 
  max(PipelineAgeBandID)    as PipelineAgeBandID,
  max(FranchiseSize)    as FranchiseSize, 
  max(FranchiseSizeID)    as FranchiseSizeID, 
  max(FranchiseSegment)   as FranchiseSegment,
  max(FranchiseSegmentID)   as FranchiseSegmentID, 
  max(ComparisonType)     as ComparisonType, 
  max(ComparisonID)     as ComparisonID, 
  isnull(max(FranchiseAgentCode), @DefaultFranchiseAgentCode) as FranchiseAgentCode, 
  max(BusinessReasonId)   as BusinessReasonId,
  sum(Turnover)       as Turnover, 
  sum(APE)      as APE, 
  sum(NBI)      as NBI, 
  sum(DA)       as DA, 
  sum(Margin)       as Margin, 
  sum(Cases)      as Cases, 
  sum(DaysInPipeline)     as DaysInPipeline
into #SalesStaging_Consolidated
from #SalesStaging_IssuedProduction
group by AgentCode, AdviserID, DateIssued, DateIssuedID, ProductCode, ProductID
/*
select AgentCode, AdviserID, DateIssued, DateIssuedID, ProductCode, ProductID from #SalesStaging_Consolidated
order by 1, 2
select AgentCode, AdviserID, DateIssued, DateIssuedID, ProductCode, ProductID, APE
from #SalesStaging_Consolidated
where agentcode = 1020
order by AgentCode, AdviserID, DateIssued, DateIssuedID, ProductCode, ProductID, APE
select *
--AgentCode, AdviserID, DateIssued, DateIssuedID, ProductCode, ProductID, APE
from #SalesStaging_IssuedProduction
where agentcode = 1020
order by AgentCode, AdviserID, DateIssued, DateIssuedID, ProductCode, ProductID, APE
select AgentCode, AdviserID, DateIssued, DateIssuedID, ProductCode, ProductID, sum(APE)
from #SalesStaging_Consolidated
where agentcode = 1020
group by AgentCode, AdviserID, DateIssued, DateIssuedID, ProductCode, ProductID
order by AgentCode, AdviserID, DateIssued, DateIssuedID, ProductCode, ProductID
select AgentCode, AdviserID, DateIssued, DateIssuedID, ProductCode, ProductID, sum(APE)
from #SalesStaging_IssuedProduction
where agentcode = 1020
group by AgentCode, AdviserID, DateIssued, DateIssuedID, ProductCode, ProductID
order by AgentCode, AdviserID, DateIssued, DateIssuedID, ProductCode, ProductID
select AgentCode, AdviserID, DateIssued, DateIssuedID, ProductCode, ProductID, count(*)
from #SalesStaging_IssuedProduction
--where agentcode = 1020
group by AgentCode, AdviserID, DateIssued, DateIssuedID, ProductCode, ProductID
order by count(*) desc, AgentCode, AdviserID, DateIssued, DateIssuedID, ProductCode, ProductID
select sum(ape) from #SalesStaging_Consolidated
select sum(ape) from #SalesStaging_IssuedProduction
*/
/*
select * from #SalesStaging_Consolidated
order by AgentCode
select distinct transactionID from mstt_Commissions
select * from mstt_policytransactions
where ID in (8,12,46,49)
*/
/*
--Now we need to check the Franchise, Manager1Code, Manager2Code etc that we were given 
--on these records to see if we need to add this structure to the msdt_adviser table.
select distinct 
  isnull(AgentCode, 'UNK') as AgentCode, 
  isnull(FranchiseAgentCode, 'UNK') as FranchiseAgentCode, 
  --isnull(Manager1Code, 'UNK') as Manager1Code, 
  isnull(Manager2Code, 'UNK') as Manager2Code, 
  --isnull(Manager3Code, 'UNK') as Manager3Code, 
  isnull(Manager4Code, 'UNK') as Manager4Code, 
  isnull(CompanyAgentCode, 'UNK') as CompanyAgentCode, 
  ' ' as IsNew
into #TransactionHierarchy
from #SalesStaging_Consolidated
order by 1,2,3,4,5
*/
/*
select agentcode, franchisecode, 
  --SalesQualitymanagercode, 
  regionalsalesmanagercode,  
  --AreaSalesQualityManagerCode, 
  AreaSalesManagerCode,
  [Exec]
from msdt_Adviser
where agentcode in ( select agentcode from #TransactionHierarchy)
order by 1,2,3,4,5
select * from #TransactionHierarchy
order by 1,2,3,4,5
*/
/*
