  null
  --cast('Unknown' as varchar(255))
            as SalesQualityManager, 
  null
  --isnull(Manager1Code, 'UNK') 
            as SalesQualityManagerCode, 
  cast('Unknown' as varchar(255))   as Franchise, 
  isnull(FranchiseAgentCode, 'UNK') as FranchiseCode, 
  -99           as FranchiseSizeID, 
  -99           as FranchiseSegmentID, 
  cast('Unknown' as varchar(255))   as PracticePrincipal, 
  cast('Unknown' as varchar(255))   as PracticePrincipalCode, 
  cast('Unknown' as varchar(255))   as PracticeSupervisor, 
  cast('Unknown' as varchar(255))   as PracticeSupervisorCode, 
  cast('Unknown' as varchar(255))   as PracticeAdministrator, 
  cast('Unknown' as varchar(255))   as PracticeAdministratorCode, 
  cast('Unknown' as varchar(255))   as Adviser, 
  AgentCode       as AgentCode, 
  null          as TransactionDate, 
  null          as DomainName, 
  null          as ChangeDate, 
  0           as IsCurrent
into 
