--    and t.Manager2Code = a.RegionalSalesManagerCode
--    --and t.Manager3Code = a.AreaSalesQualityManagerCode
--    and t.Manager4Code = a.AreaSalesManagerCode
--    and t.CompanyAgentCode = a.[Exec]
-- update t
-- set BusinessTypeID = b.BusinessTypeID
-- from #SalesStaging_Consolidated t
--  inner join msdt_BusinessType b
--    on t.BusinessType = b.BusinessType
-- update t
-- set ProductID = p.ProductID
-- from #SalesStaging_Consolidated t
--  inner join msdt_Products p
--    on t.ProductCode = p.Products
-- update t
-- set DateWrittenID = c.DateID
-- from #SalesStaging_Consolidated t
--  inner join msdt_CalendarTime c
--    on t.DateWritten = c.[DateTime]
-- update t
-- set DateIssuedID = c.DateID
-- from #SalesStaging_Consolidated t
--  inner join msdt_CalendarTime c
--    on t.DateIssued = c.[DateTime]
update t
set PipelineFlagID = p.FlagID
from #SalesStaging_Consolidated t
  inner join msdt_PipelineFlag p
    on t.PipelineFlag = p.PipelineFlag
-- update t
-- set PipelineAgeBandID = p.AgeID
-- from #SalesStaging_Consolidated t
--  inner join msdt_PipelineAge p
--    on t.DaysInPipeline = p.Age
-- update t
-- set FranchiseSizeID = f.FranchiseSizeID
-- from #SalesStaging_Consolidated t
--  inner join msdt_FranchiseSize f
--    on t.FranchiseSize = f.FranchiseSize
-- update t
-- set FranchiseSegmentID = f.FranchiseSegmentID
-- from #SalesStaging_Consolidated t
--  inner join msdt_FranchiseSegments f
--    on t.FranchiseSegment = f.FranchiseSegment
update t
set ComparisonID = c.ComparisonID
from #SalesStaging_Consolidated t
  inner join msdt_Comparison c
    on t.ComparisonType = c.Comparison
/*
select * from #SalesStaging_Consolidated
where agentcode = 10004
select * from msdt_Adviser
where agentcode = 10004
select * from msft_Sales
*/
--Clear down the existing Transition Data
declare @ActualComparisonID int
set @ActualComparisonID = (select ComparisonID from msdt_Comparison where Comparison = 'Actual')
delete from msft_Sales
where PolicyNumber = @DefaultPolicyNumber
and TransactionID = @DefaultTransactionID
and CommissionTransactionID = @DefaultCommissionTransactionID
and ComparisonID = @ActualComparisonID --This combination is specific to Transition Issued Production. 
insert into msft_Sales
  (
  PolicyNumber, 
  AgentCode, 
  TransactionId, 
  CommissionTransactionID,
  AdviserId, 
  BusinessTypeId, 
  ProductId, 
  DateWrittenId, 
  DateIssuedId, 
  TransactionDateId,
  PipelineFlagId, 
  PipelineAgeBandId, 
  FranchiseSizeId, 
  FranchiseSegmentId, 
  ComparisonId, 
  CommissionBasisId,
  FrequencyId,
  BusinessReasonId,
  SubmissionMethodId,
  Turnover, 
  APE, 
  NBI, 
  DA, 
  Margin, 
  Cases, 
  DaysInPipeline
  )
select 
  PolicyNumber, 
  AgentCode, 
  TransactionID, 
  @DefaultCommissionTransactionID as CommissionTransactionID,
  AdviserID, 
  BusinessTypeID, 
  ProductID, 
  DateWrittenID, 
  DateIssuedID, 
  isnull(coalesce(nullif(DateWrittenID,-99), nullif(DateIssuedID,-99)),-99),
  PipelineFlagID, 
  PipeLineAgeBandID,
  FranchiseSizeID, 
  FranchiseSegmentID, 
  ComparisonID, 
  @DefaultCommissionBasisId,
  @DefaultFrequencyId,
  BusinessReasonId,
  @DefaultSubmissionMethodId,
  Turnover, 
  APE, 
  NBI, 
  DA, 
  Margin, 
  Cases, 
  DaysInPipeline
from #SalesStaging_Consolidated
drop table #SalesStaging_IssuedProduction
drop table #SalesStaging_Consolidated
/* 
--drop table #TransactionHierarchy
--drop table #NewAgents 
truncate table msft_Sales
*/
END

