CREATE PROCEDURE [dbo].[mstp_TargetCompany] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : Matt Kennedy
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>Matt Kennedy</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

*******************************************************************************/


-- PROCEDURE BODY GOES HERE
begin

declare @DefaultRevision varchar(10)

set @DefaultRevision = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'Revision')

--Clear the target table first
Truncate Table mstt_TargetCompany

insert into mstt_TargetCompany
  (
  DateCode, 
  DateID, 
  TargetYear,
  TargetMonth,
  TargetRevision, 
  ComparisonId,
  SwiftASMAgentId,
  SwiftRSMAgentId,
  Franchises, 
  Advisers, 
  FranchiseLeavers, 
  SellerLeavers, 
  AverageFranchiseProductivityIssuedTurnover, 
  AverageSellerProductivityIssuedTurnover, 
  RSMFranchiseRatio, 
  MinimumPerformanceLevel
  )
select 
  null as DateCode,
  null as DateID,
  [Target Year], 
  [Month],
  [Level], --CR 80: This is what is in the spreadsheet, and will be displayed to the User as the Comparison Type
  --case when [ASM Swift Code] is null and [RSM Swift Code] is null then 'Company Level ' + isnull(Revision, @DefaultRevision)
  --  when [ASM Swift Code] is not null and [RSM Swift Code] is null then 'Area Level ' + isnull(Revision, @DefaultRevision)
  --  when [ASM Swift Code] is not null and [RSM Swift Code] is not null then 'Region Level ' + isnull(Revision, @DefaultRevision) 
  --  else isnull(Revision, @DefaultRevision) end,
  -- Above commented out under CR80
  -99 as ComparisonId,
  [ASM Swift Code],
  [RSM Swift Code],  
  Franchises, 
  Advisers, 
  [Franchise Leavers], 
  [Adviser Leavers], 
  [Ave Franchise Turnover], 
  [Ave Adviser Turn], 
  [RSM / Franchise Ratio], 
  [MPL (Turnover)]
from 
  msit_TargetsCorporate
where 
  Franchises is not null
  or Advisers is not null
  or [Franchise Leavers] is not null 
  or [Adviser Leavers] is not null
  or [Ave Franchise Turnover] is not null
  or [Ave Adviser Turn] is not null
  or [RSM / Franchise Ratio] is not null
  or [MPL (Turnover)] is not null


-- Generate the DateCode, using the TargetYear and TargetMonth. 
-- Set it to the first day of the month - or first of year if no month available.
update t
set DateCode =  cast(
    cast(TargetYear as char(4)) 
    + case when TargetMonth is not null then 
        case when TargetMonth < 10 then '0'+ cast(TargetMonth as varchar(2)) 
        else cast(TargetMonth as varchar(2)) end 
      else '01' end
    + '01'
    as int)
from mstt_TargetCompany t

--Insert any new TargetRevisions into the msdt_Comparison table
insert into msdt_Comparison (Comparison)
select distinct TargetRevision
from mstt_TargetCompany tc
where not exists (select 'x' from msdt_Comparison c
      where c.Comparison = tc.TargetRevision)


--Resolve the Surrogate Keys
update t
set DateID = c.DateID
from mstt_TargetCompany t
  inner join msdt_CalendarTime c
    on t.DateCode = c.YearMonthDay

update t
set ComparisonID = c.ComparisonID
from mstt_TargetCompany t
  inner join msdt_Comparison c
    on t.TargetRevision = c.Comparison

end


GO
/****** Object:  StoredProcedure [dbo].[mstp_TargetFranchisePlans]    Script Date: 7/3/2026 3:44:25 PM ******/
