create procedure [dbo].[mstp_TargetFranchisePlans]  -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
*******************************************************************************/
-- PROCEDURE BODY GOES HERE
begin
truncate table mstt_TargetFranchisePlans
insert into mstt_TargetFranchisePlans
(
TargetYear,
TargetMonth,
ComparisonType,
BusinessType,
ProductGroupCode,
FranchiseCode,
Turnover
)
select  YearId as TargetYear, 
  1 as TargetMonth, 
  'Franchise Plan' as ComparisonType, 
  'Issued' as BusinessType,
  ProductGroupCode, 
  PlanCode as FranchiseCode,
  January as Turnover
from msit_TargetFranchisePlans
union all 
select  YearId as TargetYear, 
  2 as TargetMonth, 
  'Franchise Plan' as ComparisonType, 
  'Issued' as BusinessType,
  ProductGroupCode, 
  PlanCode as FranchiseCode,
  February as Turnover
from msit_TargetFranchisePlans
union all 
select  YearId as TargetYear, 
  3 as TargetMonth, 
  'Franchise Plan' as ComparisonType, 
  'Issued' as BusinessType,
  ProductGroupCode, 
  PlanCode as FranchiseCode,
  March as Turnover
from msit_TargetFranchisePlans
union all 
select  YearId as TargetYear, 
  4 as TargetMonth, 
  'Franchise Plan' as ComparisonType, 
  'Issued' as BusinessType,
  ProductGroupCode, 
  PlanCode as FranchiseCode,
  April as Turnover
from msit_TargetFranchisePlans
union all 
select  YearId as TargetYear, 
  5 as TargetMonth, 
  'Franchise Plan' as ComparisonType, 
  'Issued' as BusinessType,
  ProductGroupCode, 
  PlanCode as FranchiseCode,
  May as Turnover
from msit_TargetFranchisePlans
union all 
select  YearId as TargetYear, 
  6 as TargetMonth, 
  'Franchise Plan' as ComparisonType, 
  'Issued' as BusinessType,
  ProductGroupCode, 
  PlanCode as FranchiseCode,
  June as Turnover
from msit_TargetFranchisePlans
union all 
select  YearId as TargetYear, 
  7 as TargetMonth, 
  'Franchise Plan' as ComparisonType, 
  'Issued' as BusinessType,
  ProductGroupCode, 
  PlanCode as FranchiseCode,
  July as Turnover
from msit_TargetFranchisePlans
union all 
select  YearId as TargetYear, 
  8 as TargetMonth, 
  'Franchise Plan' as ComparisonType, 
  'Issued' as BusinessType,
  ProductGroupCode, 
  PlanCode as FranchiseCode,
  August as Turnover
from msit_TargetFranchisePlans
union all 
select  YearId as TargetYear, 
  9 as TargetMonth, 
  'Franchise Plan' as ComparisonType, 
  'Issued' as BusinessType,
  ProductGroupCode, 
  PlanCode as FranchiseCode,
  September as Turnover
from msit_TargetFranchisePlans
union all 
select  YearId as TargetYear, 
  10 as TargetMonth, 
  'Franchise Plan' as ComparisonType, 
  'Issued' as BusinessType,
  ProductGroupCode, 
  PlanCode as FranchiseCode,
  October as Turnover
from msit_TargetFranchisePlans
union all 
select  YearId as TargetYear, 
  11 as TargetMonth, 
  'Franchise Plan' as ComparisonType, 
  'Issued' as BusinessType,
  ProductGroupCode, 
  PlanCode as FranchiseCode,
  November as Turnover
from msit_TargetFranchisePlans
union all 
select  YearId as TargetYear, 
  12 as TargetMonth, 
  'Franchise Plan' as ComparisonType, 
  'Issued' as BusinessType,
  ProductGroupCode, 
  PlanCode as FranchiseCode,
  December as Turnover
from msit_TargetFranchisePlans
-- Generate the DateCode, using the TargetYear and TargetMonth. 
-- Set it to the first day of the month - or first of year if no month available.
update t
set DateCode =  cast(
    cast(TargetYear as char(4)) 
    + case when TargetMonth is not null then 
        case when TargetMonth < 10 then '0'+ cast(TargetMonth as varchar(2)) 
        else cast(TargetMonth as varchar(2)) end 
      else '01' end
    + '01'
    as int)
from mstt_TargetFranchisePlans t
-- Find the dummy adviser for the Franchise. This relies on the rule that the Dummy Adviser Code 
-- for a Franchise will be FranchiseCode + '_FRANCHISE_DUMMY_CODE'
update t
set AdviserDummyCode = FranchiseCode+'_FRANCHISE_DUMMY_CODE'
from mstt_TargetFranchisePlans t
--Get the Dummy Product Code. This relies on the rule that the Dummy Product Code for
--a Product Group is ProductGroup + '_DUMMY_CODE'
update t
set ProductDummyCode = pg.ProductGroupName+'_DUMMY_CODE'
from mstt_TargetFranchisePlans t
  inner join mstt_CodeProductGroup pg
    on t.ProductGroupCode = pg.ProductGroupCode
where t.ProductDummyCode is null
--Insert any new Comparison Types into the msdt_Comparison table
insert into msdt_Comparison (Comparison)
select distinct ComparisonType
from mstt_TargetFranchisePlans t
where not exists (select 'x' from msdt_Comparison c
      where c.Comparison = t.ComparisonType)
--Resolve the Surrogate Keys
update t
set DateID = c.DateID
from mstt_TargetFranchisePlans t
  inner join msdt_CalendarTime c
    on t.DateCode = c.YearMonthDay
  inner join mst_DateTimeControl dtc
    on c.EntryTypeID = dtc.EntryTypeID
where dtc.EntryType = 'DateIssued'
and t.BusinessType = 'Issued'
update t
set BusinessTypeID = b.BusinessTypeID
from mstt_TargetFranchisePlans t
  inner join msdt_BusinessType b
    on t.BusinessType = b.BusinessType
update t
set ComparisonID = c.ComparisonID
from mstt_TargetFranchisePlans t
  inner join msdt_Comparison c
    on t.ComparisonType = c.Comparison
update t
set AdviserID = -99
from mstt_TargetFranchisePlans t
update t
set AdviserID = a.AdviserID
from mstt_TargetFranchisePlans t
  inner join msdt_AdviserDummies a
    on t.AdviserDummyCode = a.AgentCode
update t
set ProductID = p.ProductID
from mstt_TargetFranchisePlans t
  inner join msdt_ProductDummies p
    on t.ProductDummyCode = p.ProductCode
end

GO
