CREATE PROCEDURE [dbo].[mstp_TargetProduction] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : Matt Kennedy
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>Matt Kennedy</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

*******************************************************************************/


-- PROCEDURE BODY GOES HERE
begin

declare @DefaultRevision varchar(10)

set @DefaultRevision = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'Revision')

--Clear the target table first
truncate table mstt_TargetProduction

--Get the Written Targets
insert into mstt_TargetProduction
  (
  DateCode, 
  DateID, 
  TargetYear, 
  TargetMonth, 
  --TargetRevision, (Revised under CR80)
  ComparisonType,
  ComparisonID, 
  BusinessType,
  ProductGroupSwiftCode, 
  ProductDummyCode, 
  ProductID, 
  AreaSwiftCode, 
  RegionSwiftCode, 
  SwiftASMAgentID, 
  SwiftRSMAgentID, 
  FranchiseDummyCode, 
  FranchiseSize, 
  FranchiseSizeID, 
  FranchiseSegment, 
  FranchiseSegmentID, 
  AdviserDummyCode, 
  AdviserID, 
  --NTUCases, 
  Turnover, 
  APE, 
  NBI, 
  DA, 
  Margin, 
  Cases
  )
select 
  null as DateCode,
  -99 as DateID,
  [Target Year], 
  [Month],
  [Level], --isnull(Revision, @DefaultRevision), (Revised under CR80)
  -99 as ComparisonID,
  'Written' as BusinessType,
  [Product Grp], 
  null as ProductDummyCode,
  -99 as ProductID,
  null as AreaSwiftCode, 
  null as RegionSwiftCode, 
  [ASM Swift Code], 
  [RSM SWIFT Code],
  null as FranchiseDummyCode,
  null as FranchiseSize,
  -99 as  FranchiseSizeID, 
  null as FranchiseSegment, 
  -99 as FranchiseSegmentID, 
  null as AdviserDummyCode, 
  -99 as AdviserID,
  --NTUCases,
  [Written Turn],
  [Written Turn] as APE,
  null as NBI,
  null as DA,
  null as Margin, 
  [Written Cases]
from 
  msit_TargetsProduction
where 
  [Target Year] is not null
or  [Product Grp] is not null


--Get the Issued Targets
insert into mstt_TargetProduction
  (
  DateCode, 
  DateID, 
  TargetYear, 
  TargetMonth, 
  --TargetRevision, (Revised under CR80)
  ComparisonType,
  ComparisonID, 
  BusinessType,
  ProductGroupSwiftCode, 
  ProductDummyCode, 
  ProductID, 
  AreaSwiftCode, 
  RegionSwiftCode, 
  SwiftASMAgentID, 
  SwiftRSMAgentID, 
  FranchiseDummyCode, 
  FranchiseSize, 
  FranchiseSizeID, 
  FranchiseSegment, 
  FranchiseSegmentID, 
  AdviserDummyCode, 
  AdviserID, 
  --NTUCases, 
  Turnover, 
  APE, 
  NBI, 
  DA, 
  Margin, 
  Cases
  )
select 
  null as DateCode,
  -99 as DateID,
  [Target Year], 
  [Month],
  [Level], --isnull(Revision, @DefaultRevision), (Revised under CR80) 
  -99 as ComparisonID,
  'Issued' as BusinessType,
  [Product Grp], 
  null as ProductDummyCode,
  -99 as ProductID,
  null as AreaSwiftCode, 
  null as RegionSwiftCode, 
  [ASM Swift Code], 
  [RSM SWIFT Code],
  null as FranchiseDummyCode,
  null as FranchiseSize,
  -99 as  FranchiseSizeID, 
  null as FranchiseSegment, 
  -99 as FranchiseSegmentID, 
  null as AdviserDummyCode, 
  -99 as AdviserID,
  --NTUCases,
  [Issued Turn],
  [Issued Turn] as APE,
  null as NBI,
  null as DA,
  null as Margin, 
  [Issued Cases]
from 
  msit_TargetsProduction
where 
  [Target Year] is not null
or  [Product Grp] is not null


--Get the Pipeline Targets
insert into mstt_TargetProduction
  (
  DateCode, 
  DateID, 
  TargetYear, 
  TargetMonth, 
  --TargetRevision, (Revised under CR80)
  ComparisonType, 
  ComparisonID, 
  BusinessType,
  ProductGroupSwiftCode, 
  ProductDummyCode, 
  ProductID, 
  AreaSwiftCode, 
  RegionSwiftCode, 
  SwiftASMAgentID, 
  SwiftRSMAgentID, 
  FranchiseDummyCode, 
  FranchiseSize, 
  FranchiseSizeID, 
  FranchiseSegment, 
  FranchiseSegmentID, 
  AdviserDummyCode, 
  AdviserID, 
  --NTUCases, 
  Turnover, 
  APE, 
  NBI, 
  DA, 
  Margin, 
  Cases
  )
select 
  null as DateCode,
  -99 as DateID,
  [Target Year], 
  [Month],
  [Level], --isnull(Revision, @DefaultRevision), (Revised under CR80) 
  -99 as ComparisonID,
  'Pipeline' as BusinessType,
  [Product Grp], 
  null as ProductDummyCode,
  -99 as ProductID,
  null as AreaSwiftCode, 
  null as RegionSwiftCode, 
  [ASM Swift Code], 
  [RSM SWIFT Code],
  null as FranchiseDummyCode,
  null as FranchiseSize,
  -99 as  FranchiseSizeID, 
  null as FranchiseSegment, 
  -99 as FranchiseSegmentID, 
  null as AdviserDummyCode, 
  -99 as AdviserID,
  --NTUCases,
  [Pipeline Turnover],
  [Pipeline Turnover] as APE,
  null as NBI,
  null as DA,
  null as Margin, 
  [Pipeline Cases]
from 
  msit_TargetsCorporate
where 
  [Product Grp] is not null


-- Generate the DateCode, using the TargetYear and TargetMonth. 
-- Set it to the first day of the month - or first of year if no month available.
update t
set DateCode =  cast(
    cast(TargetYear as char(4)) 
    + case when TargetMonth is not null then 
        case when TargetMonth < 10 then '0'+ cast(TargetMonth as varchar(2)) 
        else cast(TargetMonth as varchar(2)) end 
      else '01' end
    + '01'
    as int)
from mstt_TargetProduction t

/*
This section being commented out under CR80. The Comparison Type shown to the user will be what is
put into the spreadsheet in the 'Level' column.

-- Set the Comparison Type. This is based on what level of the Hierarchy the Target is set at.
-- Company Level
update t
set ComparisonType = 'Company Level '+TargetRevision
from mstt_TargetProduction t
where SwiftASMAgentID is null

-- Area Level
update t
set ComparisonType = 'Area Level '+TargetRevision
from mstt_TargetProduction t
where SwiftASMAgentID is NOT null
and SwiftRSMAgentID is null

-- Region Level
update t
set ComparisonType = 'Region Level '+TargetRevision
from mstt_TargetProduction t
where SwiftRSMAgentID is NOT null

*/

-- If the ASM is null, then this is a Company level target. As such, find the dummy adviser 
-- for the Company. This relies on the rule that the Dummy Adviser Code for the Company 
-- will be 'EXEC_DUMMY_CODE'
update t
set AdviserDummyCode = 'EXEC_DUMMY_CODE'
from mstt_TargetProduction t
where SwiftASMAgentID is null


-- If the RSM is null, then this is an Area Level target. As such, find the dummy adviser 
-- for that Area. This relies on the rule that the Dummy Adviser Code for an Area 
-- will be AreaName + '_ASM_DUMMY_CODE'
update t
set AdviserDummyCode = SwiftASMAgentID+'_ASM_DUMMY_CODE'
from mstt_TargetProduction t
where SwiftRSMAgentID is null
and AdviserDummyCode is null

-- If the RSM is NOT null, then this is a Region Level target. As such, find the dummy adviser 
-- for that Region. This relies on the rule that the Dummy Adviser Code for a Region 
-- will be RegionName + '_RSM_DUMMY_CODE'
update t
set AdviserDummyCode = SwiftRSMAgentID+'_RSM_DUMMY_CODE'
from mstt_TargetProduction t
where SwiftRSMAgentID is not null
and AdviserDummyCode is null

--Get the Dummy Product Code. This relies on the rule that the Dummy Product Code for
--a Product Group is ProductGroup + '_DUMMY_CODE'
update t
set ProductDummyCode = ProductGroupSwiftCode+'_DUMMY_CODE'
from mstt_TargetProduction t
where ProductDummyCode is null

--Insert any new TargetRevisions into the msdt_Comparison table
insert into msdt_Comparison (Comparison)
select distinct ComparisonType
from mstt_TargetProduction tp
where not exists (select 'x' from msdt_Comparison c
      where c.Comparison = tp.ComparisonType)



--Resolve the Surrogate Keys
update t
set DateID = c.DateID
from mstt_TargetProduction t
  inner join msdt_CalendarTime c
    on t.DateCode = c.YearMonthDay
  inner join mst_DateTimeControl dtc
    on c.EntryTypeID = dtc.EntryTypeID
where dtc.EntryType = 'DateIssued'
and t.BusinessType = 'Issued'

update t
set DateID = c.DateID
from mstt_TargetProduction t
  inner join msdt_CalendarTime c
    on t.DateCode = c.YearMonthDay
  inner join mst_DateTimeControl dtc
    on c.EntryTypeID = dtc.EntryTypeID
where dtc.EntryType = 'DateWritten'
and t.BusinessType in ('Written', 'Pipeline')


update t
set BusinessTypeID = b.BusinessTypeID
from mstt_TargetProduction t
  inner join msdt_BusinessType b
    on isnull(nullif(t.BusinessType, 'Pipeline'), 'Written') = b.BusinessType


update t
set ComparisonID = c.ComparisonID
from mstt_TargetProduction t
  inner join msdt_Comparison c
    on t.ComparisonType = c.Comparison



update t
set AdviserID = a.AdviserID
from mstt_TargetProduction t
  inner join msdt_AdviserDummies a
    on t.AdviserDummyCode = a.AgentCode


update t
set ProductID = p.ProductID
from mstt_TargetProduction t
  inner join msdt_ProductDummies p
    on t.ProductDummyCode = p.ProductCode

end


