/****** Object:  StoredProcedure [dbo].[mstp_TargetRecruitment]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO



CREATE PROCEDURE [dbo].[mstp_TargetRecruitment] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : Matt Kennedy
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>Matt Kennedy</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

*******************************************************************************/


-- PROCEDURE BODY GOES HERE
begin

declare @DefaultRevision varchar(10)

set @DefaultRevision = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'Revision')

--Clear the target table first
truncate table mstt_TargetRecruitment

insert into mstt_TargetRecruitment
  (
  DateCode, 
  DateID, 
  TargetYear,
  TargetMonth,
  TargetRevision, 
  ComparisonType,
  ComparisonId,
  ASMSwiftAgentID,
  RSMSwiftAgentID,
  AdviserDummyCode,
  AdviserId,
  RecruitsAppointed, 
  RecruitsInPipeline, 
  PercentRecruitsStillActiveAfter12months
  )
select
  null as DateCode,
  null as DateID,
  [Target Year], 
  [Month],
  isnull(Revision, @DefaultRevision), 
  [Level], --+isnull(Revision, @DefaultRevision), (Commented out the addition of Revision under CR80)
  -99 as ComparisonId,
  [ASM Swift Code],
  [RSM Swift Code],
  null as AdviserDummyCode,
  null as AdviserId,
  [Recruits Appt], 
  [Recruits In Pipleine], 
  [% Recruits still active]
from 
  msit_TargetsCorporate
where 
  [Recruits Appt] is not null
  or [Recruits In Pipleine] is not null 
  or [% Recruits still active] is not null


-- Generate the DateCode, using the TargetYear and TargetMonth. 
-- Set it to the first day of the month - or first of year if no month available.
update t
set DateCode =  cast(
    cast(TargetYear as char(4)) 
    + case when TargetMonth is not null then 
        case when TargetMonth < 10 then '0'+ cast(TargetMonth as varchar(2)) 
        else cast(TargetMonth as varchar(2)) end 
      else '01' end
    + '01'
    as int)
from mstt_TargetRecruitment t

/*
This section being commented out under CR80. The Comparison Type shown to the user will be what is
put into the spreadsheet in the 'Level' column.

-- Set the Comparison Type. This is based on what level of the Hierarchy the Target is set at.
-- Company Level
update t
set ComparisonType = 'Company Level '+TargetRevision
from mstt_TargetRecruitment t
where ASMSwiftAgentID is null

-- Area Level
update t
set ComparisonType = 'Area Level '+TargetRevision
from mstt_TargetRecruitment t
where ASMSwiftAgentID is NOT null
and RSMSwiftAgentID is null

-- Region Level
update t
set ComparisonType = 'Region Level '+TargetRevision
from mstt_TargetRecruitment t
where RSMSwiftAgentID is NOT null
*/


-- If the ASM is null, then this is a Company level target. As such, find the dummy adviser 
-- for the Company. This relies on the rule that the Dummy Adviser Code for the Company 
-- will be 'EXEC_DUMMY_CODE'
update t
set AdviserDummyCode = 'EXEC_DUMMY_CODE'
from mstt_TargetRecruitment t
where ASMSwiftAgentID is null


-- If the RSM is null, then this is an Area Level target. As such, find the dummy adviser 
-- for that Area. This relies on the rule that the Dummy Adviser Code for an Area 
-- will be AreaName + '_ASM_DUMMY_CODE'
update t
set AdviserDummyCode = ASMSwiftAgentID+'_ASM_DUMMY_CODE'
from mstt_TargetRecruitment t
where RSMSwiftAgentID is null
and AdviserDummyCode is null

-- If the RSM is NOT null, then this is a Region Level target. As such, find the dummy adviser 
-- for that Region. This relies on the rule that the Dummy Adviser Code for a Region 
-- will be RegionName + '_RSM_DUMMY_CODE'
update t
set AdviserDummyCode = RSMSwiftAgentID+'_RSM_DUMMY_CODE'
from mstt_TargetRecruitment t
where RSMSwiftAgentID is not null
and AdviserDummyCode is null


--Insert any new TargetRevisions into the msdt_Comparison table
insert into msdt_Comparison (Comparison)
select distinct ComparisonType
from mstt_TargetRecruitment t
where not exists (select 'x' from msdt_Comparison c
      where c.Comparison = t.ComparisonType)


--Resolve the Surrogate Keys
update t
set DateID = c.DateID
from mstt_TargetRecruitment t
  inner join msdt_CalendarTime c
    on t.DateCode = c.YearMonthDay
  inner join mst_DateTimeControl dtc
    on c.EntryTypeID = dtc.EntryTypeID
where dtc.EntryType = 'DateIssued'



update t
set ComparisonID = c.ComparisonID
from mstt_TargetRecruitment t
  inner join msdt_Comparison c
    on t.ComparisonType = c.Comparison



update t
set AdviserID = a.AdviserID
from mstt_TargetRecruitment t
  inner join msdt_AdviserDummies a
    on t.AdviserDummyCode = a.AgentCode



end


GO
