CREATE  procedure [dbo].[mstp_TIP_GI] as

begin

--revised process, now appending only one month's data to the mstt_TIP_GI table
/*
truncate table mstt_TIP_GI
*/

--***********************************************************************************************
--UKPL GI Dataset
--***********************************************************************************************

--********************
select * into #StagingUKPL from msit_TIP_GI_UKPL


--********************
Select Agent_ID, Sum(Amount) as SumOfAmount, Run_Date, (Sum(Amount))*1.27 as [Gross Fees]
into #TransitionUKPL
from #StagingUKPL
group by Agent_ID, Run_Date, Ledger_Code
Having (((Ledger_Code) > 1200))
order by Run_Date desc


--********************
Select (dateadd(mm,datediff(mm,0,getdate())-1,0)) as Date, 
  ' ' as Policy,
  'TPGIUK' as [Product Point  4],
  ' ' as [Sales Contract Code],
  ' ' as [Distributor Code], 
  Agent_ID as [Franchise ID], 
  ' ' as [Annual/Single Premium],
  'Single' as Frequency, 
  [Gross Fees] AS Fee,
  (Sum([Gross Fees]))/(0.35/1)/320 as [Issued Cases], 
  ' ' as ' ',
  'New Business' as [NBP Reason]
Into #MsitGIUKPL
from #TransitionUKPL
Group by Run_Date, Agent_ID, [Gross Fees]
Having (((Run_Date) = (dateadd(mm,datediff(mm,0,getdate()),0))))
order by Agent_id

--***********************************************************************************************
--Paymentshield Openwork Dataset
--***********************************************************************************************
update msit_TIP_GI_PayShieldOW
set Premium = Replace(Premium,'£','')
update msit_TIP_GI_PayShieldOW
set Branch_No = Replace(Branch_No,'_BYO','')
update msit_TIP_GI_PayShieldOW
set Branch_No = Replace(Branch_No,'_BP','')


--********************
select * into #StagingPSOW from msit_TIP_GI_PayShieldOW


--********************
Select #StagingPSOW.Branch_Name, 
  #StagingPSOW.Branch_No, 
  sum(convert(decimal(15,2),#StagingPSOW.Premium)) as Premium,
  count(#StagingPSOW.PolicyStatus) as Cases,
  Xref.AgentCode as SellerLogAgentCode,
  HOXref.Oscar_ID as Agent_ID
into #selectcasesPSOW
from #StagingPSOW
  left outer join owhot_PaymentshieldSwiftAgentXref Xref 
    on #StagingPSOW.Branch_No = Xref.PayshieldAgent
  left outer join Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref HOXref
    on Xref.AgentCode = HOXref.AgentCode
where (PolicyStatus = 'Completed')
  and ((OnRiskDate > dateadd(mm,datediff(mm,0,dbo.owf_FirstDayOfMth(getdate()))-1,-1) and 
  OnRiskDate < dateadd(mm,datediff(mm,0,dbo.owf_FirstDayOfMth(getdate())),0))
  or
  (OnRiskDate > dateadd(mm,datediff(mm,0,dbo.owf_FirstDayOfMth(getdate()))-13,-1) and
  OnRiskDate < dateadd(mm,-12,dbo.owf_FirstDayOfMth(getdate()))))
Group by #StagingPSOW.Branch_No, #StagingPSOW.Branch_Name, Xref.AgentCode, HOXref.Oscar_ID


--********************
Select Branch_Name
  , Branch_No
  , Cases
  , (Premium * 12 * 0.35) AS Fee
  , SellerLogAgentCode
  , Agent_ID
into #transitionpsow
from #selectcasespsow


--********************
Select (dateadd(mm,datediff(mm,0,getdate())-1,0)) as Date, 
  ' ' as Policy,
  'TPGIPS' as [Product Point  4],
  ' ' as [Sales Contract Code],
  ' ' as [Distributor Code], 
  Agent_ID as [Franchise ID], 
  ' ' as [Annual/Single Premium],
  'Single' as Frequency, 
  Fee,
  Cases, 
  ' ' as ' ',
  'New Business' as [NBP Reason]
Into #MsitGIPSOW
from #TransitionPSOW


--***********************************************************************************************
--Paymentshield Reeds Rains Dataset
--***********************************************************************************************

update msit_TIP_GI_PayShieldRR
set Premium = Replace(Premium,'£','')


--********************
select * into #StagingPSRR from msit_TIP_GI_PayShieldRR


--********************
Select 
  sum(convert(decimal(15,2),Premium)) as Premium,
  count(Branch_Name) as Cases
into #selectcasespsrr
from #StagingPSRR
  left outer join owhot_PaymentshieldSwiftAgentXref Xref 
    on #StagingPSRR.Branch_No = Xref.PayshieldAgent
  left outer join Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref HOXref
    on Xref.AgentCode = HOXref.AgentCode
where (PolicyStatus = 'Completed')
  and ((OnRiskDate > dateadd(mm,datediff(mm,0,dbo.owf_FirstDayOfMth(getdate()))-1,-1) and 
  OnRiskDate < dateadd(mm,datediff(mm,0,dbo.owf_FirstDayOfMth(getdate())),0))
  or
  (OnRiskDate > dateadd(mm,datediff(mm,0,dbo.owf_FirstDayOfMth(getdate()))-13,-1) and
  OnRiskDate < dateadd(mm,-12,dbo.owf_FirstDayOfMth(getdate()))))
  and (left(#StagingPSRR.Branch_No,2) = 'RR')


--********************
Select (Premium * 12 * 0.35) AS Fee
  , Cases
into #transitionpsrr
from #selectcasespsrr


--********************
Select (dateadd(mm,datediff(mm,0,getdate())-1,0)) as Date, 
  ' ' as Policy,
  'TPGIPS' as [Product Point  4],
  ' ' as [Sales Contract Code],
  ' ' as [Distributor Code], 
  '142328' as [Franchise ID], 
  ' ' as [Annual/Single Premium],
  'Single' as Frequency, 
  Fee,
  Cases, 
  ' ' as ' ',
  'New Business' as [NBP Reason]
Into #MsitGIPSrr
from #TransitionPSrr


--***********************************************************************************************
insert into mstt_TIP_GI
(
TransactionDate, 
Policy, 
SourceProduct, 
SalesContractCode, 
DistributorCode, 
FranchiseId, 
Premium, 
Frequency, 
APE, 
Cases, 
Fee, 
NBPReason
)
select 
[Date], 
[Policy], 
[Product Point  4], 
[Sales Contract Code], 
[Distributor Code], 
[Franchise ID], 
[Annual/Single Premium], 
[Frequency], 
[Fee], 
[Issued Cases], 
null ,
[NBP Reason]
from #MsitGIUKPL
where [Date] is not null

insert into mstt_TIP_GI
(
TransactionDate, 
Policy, 
SourceProduct, 
SalesContractCode, 
DistributorCode, 
FranchiseId, 
Premium, 
Frequency, 
APE, 
Cases, 
Fee, 
NBPReason
)
select 
[Date], 
[Policy], 
[Product Point  4], 
[Sales Contract Code], 
[Distributor Code], 
[Franchise ID], 
[Annual/Single Premium], 
[Frequency], 
[Fee], 
Cases, 
null ,
[NBP Reason]
from #MsitGIPSOW
where [Date] is not null

insert into mstt_TIP_GI
(
TransactionDate, 
Policy, 
SourceProduct, 
SalesContractCode, 
DistributorCode, 
FranchiseId, 
Premium, 
Frequency, 
APE, 
Cases, 
Fee, 
NBPReason
)
select 
[Date], 
[Policy], 
[Product Point  4], 
[Sales Contract Code], 
[Distributor Code], 
[Franchise ID], 
[Annual/Single Premium], 
[Frequency], 
[Fee], 
Cases, 
null ,
[NBP Reason]
from #MsitGIPSRR
where [Date] is not null


--revised process, now only loading one month's date
/*
from msit_TIP_GI_JAN
where [Date] is not null
union all
select 
[Date], [Policy], [Product Point  4], [Sales Contract Code], [Distributor Code], [Franchise ID], [Annual/Single Premium], [Frequency], [Fee], [Issued Cases], null, [NBP Reason]
from msit_TIP_GI_FEB
where [Date] is not null
union all
select 
[Date], [Policy], [Product Point  4], [Sales Contract Code], [Distributor Code], [Franchise ID], [Annual/Single Premium], [Frequency], [Fee], [Issued Cases], null, [NBP Reason]
from msit_TIP_GI_MAR
where [Date] is not null
union all
select 
[Date], [Policy], [Product Point  4], [Sales Contract Code], [Distributor Code], [Franchise ID], [Annual/Single Premium], [Frequency], [Fee], [Issued Cases], null, [NBP Reason]
from msit_TIP_GI_APR
where [Date] is not null
union all
select 
[Date], [Policy], [Product Point  4], [Sales Contract Code], [Distributor Code], [Franchise ID], [Annual/Single Premium], [Frequency], [Fee], [Issued Cases], null, [NBP Reason]
from msit_TIP_GI_MAY
where [Date] is not null
union all
select 
[Date], [Policy], [Product Point  4], [Sales Contract Code], [Distributor Code], [Franchise ID], [Annual/Single Premium], [Frequency], [Fee], [Issued Cases], null, [NBP Reason]
from msit_TIP_GI_JUN
where [Date] is not null
union all
select 
[Date], [Policy], [Product Point  4], [Sales Contract Code], [Distributor Code], [Franchise ID], [Annual/Single Premium], [Frequency], [Fee], [Issued Cases], null, [NBP Reason]
from msit_TIP_GI_JUL
where [Date] is not null
union all
select 
[Date], [Policy], [Product Point  4], [Sales Contract Code], [Distributor Code], [Franchise ID], [Annual/Single Premium], [Frequency], [Fee], [Issued Cases], null, [NBP Reason]
from msit_TIP_GI_AUG
where [Date] is not null
union all
select 
[Date], [Policy], [Product Point  4], [Sales Contract Code], [Distributor Code], [Franchise ID], [Annual/Single Premium], [Frequency], [Fee], [Issued Cases], null, [NBP Reason]
from msit_TIP_GI_SEP
where [Date] is not null
union all
select 
[Date], [Policy], [Product Point  4], [Sales Contract Code], [Distributor Code], [Franchise ID], [Annual/Single Premium], [Frequency], [Fee], [Issued Cases], null, [NBP Reason]
from msit_TIP_GI_OCT
where [Date] is not null
union all
select 
[Date], [Policy], [Product Point  4], [Sales Contract Code], [Distributor Code], [Franchise ID], [Annual/Single Premium], [Frequency], [Fee], [Issued Cases], null, [NBP Reason]
from msit_TIP_GI_NOV
where [Date] is not null
union all
select 
[Date], [Policy], [Product Point  4], [Sales Contract Code], [Distributor Code], [Franchise ID], [Annual/Single Premium], [Frequency], [Fee], [Issued Cases], null, [NBP Reason]
from msit_TIP_GI_DEC
where [Date] is not null
*/

--Set the ProductCode
update t
set ProductCode = SourceProduct
from mstt_TIP_GI t


--Set the FranchiseCode, using the provided Translation Table
update t
set FranchiseCode = osa.SwiftAgentId
from mstt_TIP_GI t
  inner join msit_OscarSwiftAgents osa
    on t.FranchiseId = cast(osa.OscarAgentId as int)
where osa.AgentType = 'B'

--CR60: As this data is at Franchise Level, attempt to set the AgentCode 
--to tbe 'I'ndividual that is related to the 'B'usiness we just 
--retrieved in the previous update. If we get a match, this suggests
--that the Franchise is a Sole Trader.
update t
set AgentCode = osa.SwiftAgentId
from mstt_TIP_GI t
  inner join msit_OscarSwiftAgents osa
    on t.FranchiseId = cast(osa.OscarAgentId as int)
where osa.AgentType = 'I'

--If we did not get a match, then use the Swift Franchise Code as the 
--AgentCode. This will mean that when the AdviserId is retrieved in 
--later processes, the 'Business' will be picked up as the seller,
--and will therefore have ' (Franchise)' in the name, as per CR 60.
update t
set AgentCode = FranchiseCode
from mstt_TIP_GI t
where AgentCode is null



--set the agentCode from the AdviserDummies table, for the entries
--where we just retrieved a FranchiseCode
--CR 60: Commenting this out, as we should not be needing the dummy entry any more
--update t
--set AgentCode = t.FranchiseCode+'_FRANCHISE_DUMMY_CODE'
--from mstt_TIP_GI t
--where t.AgentCode is null


--Set the FranchiseCode and AgentCode where the Franchise exists in the Inactive OW Franch list
update t
set   FranchiseCode = ad.AgentCode,
  AgentCode = ad.AgentCode
from mstt_TIP_GI t
  inner join msdt_AdviserDummies ad
    on 'INACTIVE_'+cast(cast(t.FranchiseId as int) as varchar(50)) = ad.AgentCode
where t.AgentCode is null


/* CR 105 - Use new XREF table to try and match more data to the hierarchy  */

--Update from New xref, where Seller_I_UID is not null
update s
set FranchiseCode = b.OW_B_UID
from mstt_TIP_GI s
  inner join msit_BI_OW_SOY_POPULATION b
    on cast(s.FranchiseId as int) = cast(b.Franchise as int)
where s.AgentCode is null
and b.OW_B_UID is not null

--Interestingly, we now try to match the Franchise to the Seller in the XREF
update s
set FranchiseCode = b.OW_B_UID
from mstt_TIP_GI s
  inner join msit_BI_OW_SOY_POPULATION b
    on cast(s.FranchiseId as int) = cast(b.Seller as int)
where s.AgentCode is null and s.FranchiseCode is null
and b.OW_B_UID is not null


--Try to match more records via XREF to Inactive Franchises
--Link on Franchise in XREF
update s
set   FranchiseCode = ad.AgentCode
from mstt_TIP_GI s
  inner join msit_BI_OW_SOY_POPULATION b
    on cast(s.FranchiseId as int) = cast(b.Openwork_ID as int) 
  inner join msit_InactiveOWFranch iof
    on cast(b.Franchise as int) = cast(iof.Agent_ID as int) 
  inner join msdt_AdviserDummies ad
    on 'INACTIVE_'+cast(cast(iof.Agent_ID as int) as varchar(50)) = ad.AgentCode
where s.AgentCode is null and s.FranchiseCode is null

--Link on Seller in XREF
update s
set   FranchiseCode = ad.AgentCode
from mstt_TIP_GI s
  inner join msit_BI_OW_SOY_POPULATION b
    on cast(s.FranchiseId as int) = cast(b.Seller as int) 
  inner join msit_InactiveOWFranch iof
    on cast(b.Franchise as int) = cast(iof.Agent_ID as int) 
  inner join msdt_AdviserDummies ad
    on 'INACTIVE_'+cast(cast(iof.Agent_ID as int) as varchar(50)) = ad.AgentCode
where s.AgentCode is null and s.FranchiseCode is null




--CR60: Attempt to set the AgentCode to tbe 'I'ndividual that is related 
--to the 'B'usiness we just retrieved in the previous update. If we get a 
--match, this suggests that the Franchise is a Sole Trader.
update s
set AgentCode = o_i.SwiftAgentId
from mstt_TIP_GI s
  inner join msit_OscarSwiftAgents o_b
    on s.FranchiseCode = o_b.SwiftAgentId
  inner join msit_OscarSwiftAgents o_i
    on o_b.OscarAgentId = o_i.OscarAgentId
where o_i.AgentType = 'I'
and s.AgentCode is null


--Finally, set the AgentCode to the FranchiseCode, if the AgentCode is not yet set.
update s
set AgentCode = FranchiseCode
from mstt_TIP_GI s
where AgentCode is null
and FranchiseCode is not null

/*  END CR 105  */

--As part of the 'Seller Transfer' CR, we must determine the Franchise Code at the time of the sale.

--Determine the FranchiseSwiftCode at the time of Sale.
--We use the AgentHierarchyHistory table, which has some issues. To get around these issues,
--create a temp AgentHierarchyHistory table with only valid entries. This is based on rules
--as defined in the Quality project.
select AgentCode, 
  DefaultValue, 
  StartDate, 
  EndDate, 
  Status, 
  DetailAgentCode, 
  ParticipantType
into #AgentHierarchyHistory 
from msit_AgentHierarchyHistory
where 1=0

CREATE INDEX AgentHierarchyHistory_AgentCode ON #AgentHierarchyHistory (AgentCode)

insert into #AgentHierarchyHistory  
select ahh4.AgentCode, 
  ahh4.DefaultValue, 
  ahh4.StartDate, 
  ahh4.EndDate, 
  ahh4.Status, 
  ahh4.DetailAgentCode, 
  ahh4.ParticipantType 
from msit_AgentHierarchyHistory ahh4
  inner join 
    (--Get the max Id if there are multiple entries for a 
    --StartDate/EndDate/ParticipantType combo
    select max(ahh2.Id) as Id, 
      ahh2.AgentCode, 
      ahh2.ParticipantType, 
      ahh2.StartDate, 
      ahh2.EndDate 
    from msit_AgentHierarchyHistory ahh2
      inner join (--Get the latest end date for each start date
          select ahh.AgentCode, 
            ahh.ParticipantType, 
            ahh.StartDate, 
            max(isnull(ahh.EndDate, '31 Dec 9999')) as EndDate
          from msit_agenthierarchyhistory ahh
          group by ahh.AgentCode, ahh.ParticipantType, ahh.StartDate ) ahh1
        on ahh2.AgentCode = ahh1.AgentCode
        and ahh2.ParticipantType = ahh1.ParticipantType
        and ahh2.StartDate = ahh1.StartDate
        and isnull(ahh2.EndDate, '31 Dec 9999') = ahh1.EndDate
    group by ahh2.AgentCode, 
      ahh2.ParticipantType, 
      ahh2.StartDate, 
      ahh2.EndDate ) ahh3
    on ahh4.id = ahh3.Id
where ahh4.ParticipantType in (6,7,8,9)   
and isnull(ahh4.EndDate, '31 dec 2999') >= '01 Jan 2006'
and ahh4.StartDate <> isnull(ahh4.EndDate, '31 dec 2999')
order by 1

--Create a temp table to use to retrieve the Franchises. Will use this later to update the TIP table.
select distinct 
  cast(null as DateTime) as PeriodEndDate,
  TransactionDate, 
  AgentCode as SellerSwiftCode, 
  cast(null as varchar(7)) as FranchiseSwiftCode
into #AgentFranchise
from mstt_tip_GI tip
  inner join mstt_Agents a
    on tip.AgentCode = a.Code
where a.AgentCategory in (select distinct AgentCategory 
            from mstt_Agents ag, msdt_Adviser ad
            where ag.Code = ad.AgentCode)
and tip.AgentCode is not null

--Set the PeriodEndDate. This is the date to use in order to determine the Franchise as at the
--time of sale.

select af.TransactionDate, min(csp.PeriodEndDate) as PeriodEndDate
into #PeriodEndDates
from #AgentFranchise af
  inner join msit_CommissionStatementPeriods csp
    on af.TransactionDate <= csp.PeriodEndDate
group by af.TransactionDate

update af
set PeriodEndDate = ped.PeriodEndDate
from #AgentFranchise af
  inner join #PeriodEndDates ped
    on af.TransactionDate = ped.TransactionDate
    
drop table #PeriodEndDates

select af.SellerSwiftCode, af.PeriodEndDate, ahh.StartDate, ahh.DetailAgentCode, ahh.ParticipantType
into #TheDetails
from #AgentFranchise af
  inner join #AgentHierarchyHistory ahh
    on af.SellerSwiftCode = ahh.AgentCode
where ahh.StartDate = (select max(ahh2.StartDate) 
      from #AgentHierarchyHistory ahh2
      where ahh2.AgentCode = ahh.AgentCode
      and ahh2.ParticipantType = ahh.ParticipantType
      and ahh2.StartDate <= af.PeriodEndDate)
      
--Must get the FIRST entry for each Agent in #AgentHierarchyHistory, so we can use this for 
--transactions prior to 1-Jan-2006 (where there is no #Ahh record for the period of the transaction)

select ahh.AgentCode, 
  ahh.DefaultValue, 
  ahh.StartDate, 
  ahh.EndDate, 
  ahh.Status, 
  ahh.DetailAgentCode, 
  ahh.ParticipantType 
into #FirstAgentHierarchyHistory
from #AgentHierarchyHistory ahh
where ahh.StartDate = (select min(ahh2.StartDate) 
            from #AgentHierarchyHistory ahh2
            where ahh2.AgentCode = ahh.AgentCode
            and ahh2.ParticipantType = ahh.ParticipantType)


insert into #TheDetails
select distinct af.SellerSwiftCode, af.PeriodEndDate, ahh.StartDate, ahh.DetailAgentCode, ahh.ParticipantType
from #AgentFranchise af
  inner join #FirstAgentHierarchyHistory ahh
    on af.SellerSwiftCode = ahh.AgentCode
where not exists (select 'x' from #TheDetails td
    where td.SellerSwiftCode = af.SellerSwiftCode
    and td.PeriodEndDate = af.PeriodEndDate)
    
--Ensure that if a seller reports to more than one of a 6,7,8 or 9 at the same point in time
--then all but the '7' (Franchise) must be removed from the equation.

select td.SellerSwiftCode, td.PeriodEndDate, td.ParticipantType
into #RecordsToDelete
from #TheDetails td
  inner join (select td2.SellerSwiftCode, 
            td2.PeriodEndDate, 
            count(distinct td2.ParticipantType) as Num
        from #TheDetails td2
        group by td2.SellerSwiftCode, 
            td2.PeriodEndDate
        having count(distinct td2.ParticipantType) > 1) sub
    on td.SellerSwiftCode = sub.SellerSwiftCode
    and td.PeriodEndDate = sub.PeriodEndDate
where td.ParticipantType <> 7


delete td
from #TheDetails td
  inner join #RecordsToDelete rtd
    on td.SellerSwiftCode = rtd.SellerSwiftCode
    and td.PeriodEndDate = rtd.PeriodEndDate
    and td.ParticipantType = rtd.ParticipantType

    
update af
set FranchiseSwiftCode = td.DetailAgentCode
from #AgentFranchise af
  inner join #TheDetails td
    on af.SellerSwiftCode = td.SellerSwiftCode
    and af.PeriodEndDate = td.PeriodEndDate

--Even after all this, we see a few entries where the Firm is not set. Many of these can be explained
--(sort of) by the fact that the sales are against Franchises. We can pick these out by joining to
--msdt_Adviser on Agent_Code = AgentCode and find the entries where AgentCode = FranchiseCode, and
--then simply use Agent_Code as the firm.

update af
set FranchiseSwiftCode = af.SellerSwiftCode
from #AgentFranchise af
  inner join msdt_Adviser ad
    on af.SellerSwiftCode = ad.AgentCode
where ad.AgentCode = ad.FranchiseCode
and af.FranchiseSwiftCode is null

--Some more can be explained by missing AgentHierarchyHistory records. In this case, we retrieve the franchise
--(in this case, the 'firm') from the mstt_Agents record for this seller.

update af
set FranchiseSwiftCode = ag.Firm
from #AgentFranchise af
  inner join mstt_Agents ag
    on af.SellerSwiftCode = ag.Code
where af.FranchiseSwiftCode is null   


update tip
set FranchiseCode = af.FranchiseSwiftCode
from mstt_tip_GI tip
  inner join #AgentFranchise af
    on tip.AgentCode = af.SellerSwiftCode
    and tip.TransactionDate = af.TransactionDate
    
drop table #StagingUKPL
drop table #TransitionUKPL
drop table #MsitGIUKPL
drop table #StagingPSOW
drop table #selectcasesPSOW
drop table #transitionpsow
drop table #MsitGIPSOW
drop table #StagingPSRR
drop table #TransitionPSRR
drop table #MsitGIPSrr
drop table #AgentFranchise
drop table #TheDetails
drop table #RecordsToDelete
drop table #FirstAgentHierarchyHistory
drop table #AgentHierarchyHistory




end



