GO
CREATE PROCEDURE [dbo].[mstp_TransitionCapacity_SellersFranchise] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS
/******************************************************************************
Copyright (C) Moore Stephens Consulting Limited 2005
Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>
*******************************************************************************/
truncate table mstt_TransitionCapacity_SellersFranchise
declare 
  @DefaultSwiftAgentCode        nvarchar(255),
  @DefaultSwiftFranchiseCode      nvarchar(255)
set @DefaultSwiftAgentCode     = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AgentCode')   
set @DefaultSwiftFranchiseCode = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'FranchiseAgentCode')    
insert into mstt_TransitionCapacity_SellersFranchise 
 (  OscarCode,
  FullName,
  Oscar_Main_Serial,
  Oscar_Main_Prefix,
  Oscar_Main_Suffix,
  Oscar_Status,
  Oscar_Status_Date,
  Oscar_Appointed,
  Specialist_Code,
  Oscar_Agent_Type,
  Openwork,
  Specialist_Short_Desc,
  Specialist_Lond_Desc,
  Oscar_Manager_Code,
  Oscar_Manager_Name,
  Oscar_Manager_Prefix,
  Oscar_Manager_Serial,
  Oscar_Manager_Suffix,
  SwiftAgentCode,
  SwiftFranchiseCode,
  FranchiseOrSeller
 )
select
  AGENT_ID,
  FULLNAME,
  MAIN_SERIAL,
  MAIN_PREFIX,
  MAIN_SUFFIX,
  STATUS,
  STATUS_DATE,
  APPOINTED,
  SPECIALIST_CODE,
  AGENT_TYPE,
  OPENWORK,
  SPECIALIST_SHORT_DESC,
  SPECIALIST_LONG_DESC,
  MANAGER_ID,
  MANGER_NAME,
  MANGER_PREFIX,
  MANAGER_SERIAL,
  MANAGER_SUFFIX,
  @DefaultSwiftAgentCode,
  @DefaultSwiftFranchiseCode,
  'S'
from 
 msit_TransitionCapacity_Sellers --using this source which has single row for each adviser
union all 
select
  AGENT_ID,
  FULLNAME,
  MAIN_SERIAL,
  MAIN_PREFIX,
  MAIN_SUFFIX,
  STATUS,
  STATUS_DATE,
  APPOINTED,
  SPECIALIST_CODE,
  AGENT_TYPE,
  OPENWORK,
  SPECIALIST_SHORT_DESC,
  SPECIALIST_LONG_DESC,
  MANAGER_ID,
  MANGER_NAME,
  MANGER_PREFIX,
  MANAGER_SERIAL,
  MANAGER_SUFFIX,
  @DefaultSwiftAgentCode,
  @DefaultSwiftFranchiseCode,
  'F'
from 
 msit_TransitionCapacity_Franchise
--JOIN TO OSCAR TRANSLATION TABLE TO DERIVE SWIFTAGENTID
--SELLER
update 
 mstt_TransitionCapacity_SellersFranchise
set 
 SwiftAgentCode = osa.SwiftAgentID
from 
 mstt_TransitionCapacity_SellersFranchise tc,
 msit_OscarSwiftAgents osa
where
 osa.AgentType      = 'I' and
 tc.FranchiseOrSeller = 'S' and
 tc.OscarCode     = osa.OscarAgentID and
 tc.Oscar_MAIN_SERIAL = convert(nvarchar(255),osa.OSCARAgentSerial) and
 tc.Oscar_MAIN_PREFIX = osa.OSCARAgentPrefix and
 tc.Oscar_MAIN_SUFFIX = osa.OSCARAgentSuffix
--FRANCHISE
update 
 mstt_TransitionCapacity_SellersFranchise
set 
 SwiftFranchiseCode = osa.SwiftAgentID
from 
 mstt_TransitionCapacity_SellersFranchise tc,
 msit_OscarSwiftAgents osa
where
 osa.AgentType      = 'B' and
 tc.FranchiseOrSeller = 'F' and
 tc.OscarCode     = osa.OscarAgentID and
 tc.Oscar_MAIN_SERIAL = convert(nvarchar(255),osa.OSCARAgentSerial) and
 tc.Oscar_MAIN_PREFIX = osa.OSCARAgentPrefix and
 tc.Oscar_MAIN_SUFFIX = osa.OSCARAgentSuffix

GO
