CREATE PROCEDURE [dbo].[mstp_TransitionIssuedProduction] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

*******************************************************************************/


-- PROCEDURE BODY GOES HERE
BEGIN

declare @DefaultFranchiseSizeID                    int
declare @DefaultFranchiseSegmentID                 int
declare @DefaultAdviserID                          int
declare @DefaultBusinessTypeID                     int
declare @DefaultProductID                          int
declare @DefaultDateIssuedID                       int
declare @DefaultBusinessReasonID                   int
declare @DefaultCompanyName                        varchar(50)
declare @DefaultAreaSalesManagerName               varchar(50)
declare @DefaultAreaName                           varchar(50)
declare @DefaultRegionalSalesManagerName           varchar(50)
declare @DefaultFranchiseName                      varchar(50)
declare @DefaultFranchiseAgentCode                 varchar(50)
declare @DefaultPracticePrincipalName              varchar(50)
declare @DefaultPracticePrincipalCode              varchar(50)
declare @DefaultPracticeSupervisorName             varchar(50)
declare @DefaultPracticeSupervisorCode             varchar(50)
declare @DefaultPracticeAdministratorName          varchar(50)
declare @DefaultPracticeAdministratorCode          varchar(50)
declare @DefaultAdviserName                        varchar(50)
declare @DefaultManager2Code                       varchar(50)
declare @DefaultManager4Code                       varchar(50)
declare @DefaultRegionName                         varchar(50)

set @DefaultFranchiseSizeID               = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'FranchiseSizeID')
set @DefaultFranchiseSegmentID            = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'FranchiseSegmentID')
set @DefaultAdviserID                     = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'AdviserID')
set @DefaultBusinessTypeID                = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'BusinessTypeID')
set @DefaultProductID                     = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'ProductID')
set @DefaultDateIssuedID                  = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'DateIssuedID')
set @DefaultBusinessReasonID              = (select cast(DefaultValue as int) from mstt_DefaultCodeValues where CodeColumn = 'BusinessReasonID')
set @DefaultCompanyName                   = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'CompanyName')
set @DefaultAreaSalesManagerName          = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AreaSalesManagerName')
set @DefaultAreaName                      = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AreaName')
set @DefaultRegionalSalesManagerName      = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'RegionalSalesManagerName')
set @DefaultFranchiseName                 = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'FranchiseName')
set @DefaultFranchiseAgentCode            = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'FranchiseCode')
set @DefaultPracticePrincipalName         = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'PracticePrincipalName')
set @DefaultPracticePrincipalCode         = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'PracticePrincipalCode')
set @DefaultPracticeSupervisorName        = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'PracticeSupervisorName')
set @DefaultPracticeSupervisorCode        = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'PracticeSupervisorCode')
set @DefaultPracticeAdministratorName     = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'PracticeAdministratorName')
set @DefaultPracticeAdministratorCode     = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'PracticeAdministratorCode')
set @DefaultAdviserName                   = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'AdviserName')
set @DefaultManager2Code                  = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'Manager2Code')
set @DefaultManager4Code                  = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'Manager4Code')
set @DefaultRegionName                    = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'RegionName')





truncate table mstt_TransitionIssuedProduction

insert into mstt_TransitionIssuedProduction
  (
  PeriodStartDate, 
  PeriodEndDate, 
  Period, 
  DateIssuedID, 
  BusinessType, 
  BusinessTypeID, 
  SellerOSCARAgentCode, 
  SellerOSCARAgentID, 
  SellerStatus, 
  SellerName,
  SellerSwiftCode, 
  SellerDummyCode, 
  AdviserID, 
  FranchiseOSCARAgentCode, 
  FranchiseOSCARAgentID, 
  FranchiseName, 
  FranchiseStatus, 
  FranchiseSwiftCode, 
  FranchiseDummyCode, 
  FranchiseSize, 
  FranchiseSizeID, 
  FranchiseSegment, 
  FranchiseSegmentID, 
  SwiftProductCategory,
  SwiftProductCode,
  ProductGroup, 
  ProductGroupSwiftCode, 
  ProductDummyCode, 
  ProductID, 
  BusinessReason,
  BusinessReasonId,
  IssuedTurnover, 
  IssuedNBI, 
  IssuedCases, 
  Turnover, 
  APE, 
  NBI, 
  DA, 
  Margin, 
  Cases
  )
select 
  sub.TransactionDate           as PeriodStartDate,
  null                          as PeriodEndDate,
  null                          as Period,
  @DefaultDateIssuedID          as DateIssuedID,
  'Issued'                      as BusinessType,
  @DefaultBusinessTypeID        as BusinessTypeID,
  null                          as SellerOSCARAgentCode, 
  null                          as SellerOSCARAgentId, 
  null                          as SellerStatus, 
  null                          as SellerName, 
  sub.AgentCode                 as SellerSwiftCode,
  null                          as SellerDummyCode,
  @DefaultAdviserID             as AdviserID,
  null                          as Franchise_Agent_Code, 
  null                          as Franchise_Agent_ID, 
  null                          as Franchise_Name, 
  null                          as Franchise_Status,
  sub.FranchiseCode             as FranchiseSwiftCode,
  null                          as FranchiseDummyCode,
  null                          as FranchiseSize,
  @DefaultFranchiseSizeID       as FranchiseSizeID,
  null                          as FranchiseSegment,
  @DefaultFranchiseSegmentID    as FranchiseSegmentID,
  null                          as SwiftProductCategory,
  sub.ProductCode               as SwiftProductCode,
  null                          as ProductGroup,
  null                          as ProductGroupSwiftCode,
  null                          as ProductDummyCode,
  @DefaultProductID             as ProductID,
  case when sub.NBPReason = 'New Business' then 'NB'
    when sub.NBPReason like 'Negotiated%' then 'NI'
    else 'I' end              as BusinessReason,
  @DefaultBusinessReasonId      as BusinessReasonId,
  null                          as IssuedTurnover, 
  null                          as IssuedNBI, 
  null                          as IssuedCases,
  sub.APE                       as Turnover,    --Note: This is what Mike Cawood told me to do!
  sub.APE                       as APE,   
  sub.Fee                       as NBI, 
  null                          as DA,
  null                          as Margin,
  sub.Cases                     as Cases          
from 
(
select TransactionDate, Policy, SourceProduct, SalesContractCode, DistributorCode, 
FranchiseId, Premium, Frequency, APE, Cases, Fee, NBPReason, AgentCode, FranchiseCode, ProductCode
from mstt_TIP_GI
union all
select TransactionDate, Policy, SourceProduct, SalesContractCode, DistributorCode, 
FranchiseId, Premium, Frequency, APE, Cases, Fee, NBPReason, AgentCode, FranchiseCode, ProductCode
from mstt_TIP_MORT
union all
select TransactionDate, Policy, SourceProduct, SalesContractCode, DistributorCode, 
FranchiseId, Premium, Frequency, APE, Cases, Fee, NBPReason, AgentCode, FranchiseCode, ProductCode
from mstt_TIP_ScotEq
union all
select TransactionDate, Policy, SourceProduct, SalesContractCode, DistributorCode, 
FranchiseId, Premium, Frequency, APE, Cases, Fee, NBPReason, AgentCode, FranchiseCode, ProductCode
from mstt_TIP_Sterling
union all
select TransactionDate, Policy, SourceProduct, SalesContractCode, DistributorCode, 
FranchiseId, Premium, Frequency, APE, Cases, Fee, NBPReason, AgentCode, FranchiseCode, ProductCode
from mstt_TIP_Zurich
) sub



--Set the PeriodEndDate (last day of the month, using PeriodStartDate)
update t
set PeriodEndDate = DateAdd(day, -1, DateAdd(month, DateDiff(month, 0, PeriodStartDate)+1, 0)) 
from mstt_TransitionIssuedProduction t


--Determine the FranchiseSwiftCode at the time of Sale.
--We use the AgentHierarchyHistory table, which has some issues. To get around these issues,
--create a temp AgentHierarchyHistory table with only valid entries. This is based on rules
--as defined in the Quality project.
select AgentCode, 
  DefaultValue, 
  StartDate, 
  EndDate, 
  Status, 
  DetailAgentCode, 
  ParticipantType
into #AgentHierarchyHistory 
from msit_AgentHierarchyHistory
where 1=0

CREATE INDEX AgentHierarchyHistory_AgentCode ON #AgentHierarchyHistory (AgentCode)

insert into #AgentHierarchyHistory  
select ahh4.AgentCode, 
  ahh4.DefaultValue, 
  ahh4.StartDate, 
  ahh4.EndDate, 
  ahh4.Status, 
  ahh4.DetailAgentCode, 
  ahh4.ParticipantType 
from msit_AgentHierarchyHistory ahh4
  inner join 
    (--Get the max Id if there are multiple entries for a 
    --StartDate/EndDate/ParticipantType combo
    select max(ahh2.Id) as Id, 
      ahh2.AgentCode, 
      ahh2.ParticipantType, 
      ahh2.StartDate, 
      ahh2.EndDate 
    from msit_AgentHierarchyHistory ahh2
      inner join (--Get the latest end date for each start date
          select ahh.AgentCode, 
            ahh.ParticipantType, 
            ahh.StartDate, 
            max(isnull(ahh.EndDate, '31 Dec 9999')) as EndDate
          from msit_agenthierarchyhistory ahh
          group by ahh.AgentCode, ahh.ParticipantType, ahh.StartDate ) ahh1
        on ahh2.AgentCode = ahh1.AgentCode
        and ahh2.ParticipantType = ahh1.ParticipantType
        and ahh2.StartDate = ahh1.StartDate
        and isnull(ahh2.EndDate, '31 Dec 9999') = ahh1.EndDate
    group by ahh2.AgentCode, 
      ahh2.ParticipantType, 
      ahh2.StartDate, 
      ahh2.EndDate ) ahh3
    on ahh4.id = ahh3.Id
where ahh4.ParticipantType in (6,7,8,9)   
and isnull(ahh4.EndDate, '31 dec 2999') >= '01 Jan 2006'
and ahh4.StartDate <> isnull(ahh4.EndDate, '31 dec 2999')
order by 1

--Create a temp table to use to retrieve the Franchises. Will use this later to update the TIP table.
select distinct PeriodEndDate, SellerSwiftCode, cast(null as varchar(7)) as FranchiseSwiftCode
into #AgentFranchise
from mstt_TransitionIssuedProduction tip
  inner join mstt_Agents a
    on tip.SellerSwiftCode = a.Code
where a.AgentCategory in (select distinct AgentCategory 
            from mstt_Agents ag, msdt_Adviser ad
            where ag.Code = ad.AgentCode)
and tip.FranchiseSwiftCode is null


select af.SellerSwiftCode, af.PeriodEndDate, ahh.StartDate, ahh.DetailAgentCode, ahh.ParticipantType
into #TheDetails
from #AgentFranchise af
  inner join #AgentHierarchyHistory ahh
    on af.SellerSwiftCode = ahh.AgentCode
where ahh.StartDate = (select max(ahh2.StartDate) 
      from #AgentHierarchyHistory ahh2
      where ahh2.AgentCode = ahh.AgentCode
      and ahh2.ParticipantType = ahh.ParticipantType
      and ahh2.StartDate <= af.PeriodEndDate)
      
--Must get the FIRST entry for each Agent in #AgentHierarchyHistory, so we can use this for 
--transactions prior to 1-Jan-2006 (where there is no #Ahh record for the period of the transaction)

select ahh.AgentCode, 
  ahh.DefaultValue, 
  ahh.StartDate, 
  ahh.EndDate, 
  ahh.Status, 
  ahh.DetailAgentCode, 
  ahh.ParticipantType 
into #FirstAgentHierarchyHistory
from #AgentHierarchyHistory ahh
where ahh.StartDate = (select min(ahh2.StartDate) 
            from #AgentHierarchyHistory ahh2
            where ahh2.AgentCode = ahh.AgentCode
            and ahh2.ParticipantType = ahh.ParticipantType)


insert into #TheDetails
select distinct af.SellerSwiftCode, af.PeriodEndDate, ahh.StartDate, ahh.DetailAgentCode, ahh.ParticipantType
from #AgentFranchise af
  inner join #FirstAgentHierarchyHistory ahh
    on af.SellerSwiftCode = ahh.AgentCode
where not exists (select 'x' from #TheDetails td
    where td.SellerSwiftCode = af.SellerSwiftCode
    and td.PeriodEndDate = af.PeriodEndDate)
    
--Ensure that if a seller reports to more than one of a 6,7,8 or 9 at the same point in time
--then all but the '7' (Franchise) must be removed from the equation.

select td.SellerSwiftCode, td.PeriodEndDate, td.ParticipantType
into #RecordsToDelete
from #TheDetails td
  inner join (select td2.SellerSwiftCode, 
            td2.PeriodEndDate, 
            count(distinct td2.ParticipantType) as Num
        from #TheDetails td2
        group by td2.SellerSwiftCode, 
            td2.PeriodEndDate
        having count(distinct td2.ParticipantType) > 1) sub
    on td.SellerSwiftCode = sub.SellerSwiftCode
    and td.PeriodEndDate = sub.PeriodEndDate
where td.ParticipantType <> 7

delete td
from #TheDetails td
  inner join #RecordsToDelete rtd
    on td.SellerSwiftCode = rtd.SellerSwiftCode
    and td.PeriodEndDate = rtd.PeriodEndDate
    and td.ParticipantType = rtd.ParticipantType

    
update af
set FranchiseSwiftCode = td.DetailAgentCode
from #AgentFranchise af
  inner join #TheDetails td
    on af.SellerSwiftCode = td.SellerSwiftCode
    and af.PeriodEndDate = td.PeriodEndDate

--Even after all this, we see a few entries where the Firm is not set. Many of these can be explained
--(sort of) by the fact that the sales are against Franchises. We can pick these out by joining to
--msdt_Adviser on Agent_Code = AgentCode and find the entries where AgentCode = FranchiseCode, and
--then simply use Agent_Code as the firm.

update af
set FranchiseSwiftCode = af.SellerSwiftCode
from #AgentFranchise af
  inner join msdt_Adviser ad
    on af.SellerSwiftCode = ad.AgentCode
where ad.AgentCode = ad.FranchiseCode
and af.FranchiseSwiftCode is null

--Some more can be explained by missing AgentHierarchyHistory records. In this case, we retrieve the franchise
--(in this case, the 'firm') from the mstt_Agents record for this seller.

update af
set FranchiseSwiftCode = ag.Firm
from #AgentFranchise af
  inner join mstt_Agents ag
    on af.SellerSwiftCode = ag.Code
where af.FranchiseSwiftCode is null   


update tip
set FranchiseSwiftCode = af.FranchiseSwiftCode
from mstt_TransitionIssuedProduction tip
  inner join #AgentFranchise af
    on tip.SellerSwiftCode = af.SellerSwiftCode
    and tip.PeriodEndDate = af.PeriodEndDate
where tip.FranchiseSwiftCode is null

drop table #AgentFranchise
drop table #TheDetails
drop table #RecordsToDelete
drop table #FirstAgentHierarchyHistory
drop table #AgentHierarchyHistory
    
--Now we need to check the Seller/Franchise combos
--on these records to see if we need to add this structure to the msdt_adviser table.

--Get the distinct 'hierarchy' from the fact records.
select distinct 
  SellerSwiftCode as AgentCode,
  FranchiseSwiftCode as FranchiseAgentCode,
  ' ' as IsNew
into #TransactionHierarchy
from mstt_TransitionIssuedProduction tip
  inner join mstt_Agents a
    on tip.SellerSwiftCode = a.Code
  inner join msdt_Adviser ad
    on tip.SellerSwiftCode = ad.AgentCode
where a.AgentCategory in (select distinct AgentCategory 
            from mstt_Agents ag, msdt_Adviser ad
            where ag.Code = ad.AgentCode)
order by 1,2



--Check to see if this is a 'new' hierarchy - ie one that is NOT in msdt_Adviser.
update t
set IsNew = 'Y'
from #TransactionHierarchy t
where not exists (select 'x' from msdt_Adviser a
    where t.AgentCode = a.AgentCode
    and t.FranchiseAgentCode = a.FranchiseCode)


--Get the 'new' records into a temp table with the structure of the msdt_Adviser table
select  cast(@DefaultCompanyName as varchar(255))                as [Exec], 
  cast(@DefaultAreaSalesManagerName as varchar(255))       as AreaSalesManager, 
  cast(@DefaultManager4Code as varchar(255))               as AreaSalesManagerCode, 
  null                                                     as AreaSalesQualityManager, 
  null                                                     as AreaSalesQualityManagerCode, 
  cast(@DefaultAreaName as varchar(255))                   as AreaName, 
  cast('UNK' as varchar(255))                              as AreaCode, 
  cast(@DefaultRegionalSalesManagerName as varchar(255))   as RegionalSalesManager, 
  cast(@DefaultManager2Code as varchar(255))               as RegionalSalesManagerCode, 
  cast(@DefaultRegionName as varchar(255))                 as RegionName, 
  cast('UNK' as varchar(255))                              as RegionCode, 
  null                                                     as SalesQualityManager, 
  null                                                     as SalesQualityManagerCode, 
  cast(@DefaultFranchiseName as varchar(255))              as Franchise, 
  isnull(FranchiseAgentCode, @DefaultFranchiseAgentCode)   as FranchiseCode, 
  @DefaultFranchiseSizeID                                  as FranchiseSizeID, 
  @DefaultFranchiseSegmentID                               as FranchiseSegmentID, 
  cast(@DefaultPracticePrincipalName as varchar(255))      as PracticePrincipal, 
  cast(@DefaultPracticePrincipalCode as varchar(255))      as PracticePrincipalCode, 
  cast(@DefaultPracticeSupervisorName as varchar(255))     as PracticeSupervisor, 
  cast(@DefaultPracticeSupervisorCode as varchar(255))     as PracticeSupervisorCode, 
  cast(@DefaultPracticeAdministratorName as varchar(255))  as PracticeAdministrator, 
  cast(@DefaultPracticeAdministratorCode as varchar(255))  as PracticeAdministratorCode, 
  cast(@DefaultAdviserName as varchar(255))                as Adviser, 
  AgentCode                                                as AgentCode, 
  null                                                     as TransactionDate, 
  null                                                     as DomainName, 
  null                                                     as ChangeDate, 
  0                                                        as IsCurrent

into 
  #NewAgents
from 
  #TransactionHierarchy 
where
  IsNew = 'Y'



--update this record set with the missing fields - names etc... from msdt_Adviser, joining on FranchiseCode
--We go to this table because msdt_Adviser is already populated with the current values
--for the fields above Franchise Level.
update t
set [Exec]                     = a.[Exec], 
  AreaSalesManager           = a.AreaSalesManager, 
  AreaSalesManagerCode       = a.AreaSalesManagerCode, 
  AreaName                   = a.AreaName, 
  AreaCode                   = a.AreaCode, 
  RegionalSalesManager       = a.RegionalSalesManager, 
  RegionalSalesManagerCode   = a.RegionalSalesManagerCode, 
  RegionName                 = a.RegionName, 
  RegionCode                 = a.RegionCode, 
  Franchise                  = a.Franchise,
  FranchiseSizeId            = a.FranchiseSizeId,
  FranchiseSegmentId         = a.FranchiseSegmentId
from #NewAgents t
  inner join msdt_Adviser a
    on t.FranchiseCode = a.FranchiseCode


update t
set Adviser = a.DESCN
from #NewAgents t
  inner join mstt_Agents a
    on t.AgentCode = a.Code
 

--insert the 'new' records to the adviser table.
insert into msdt_Adviser
  ([Exec], AreaSalesManager, AreaSalesManagerCode, AreaSalesQualityManager, AreaSalesQualityManagerCode, 
  AreaName, AreaCode, RegionalSalesManager, RegionalSalesManagerCode, 
  RegionName, RegionCode, SalesQualityManager, SalesQualityManagerCode, 
  Franchise, FranchiseCode, FranchiseSizeID, FranchiseSegmentID, 
  PracticePrincipal, PracticePrincipalCode, PracticeSupervisor, PracticeSupervisorCode, 
  PracticeAdministrator, PracticeAdministratorCode, Adviser, AgentCode, 
  TransactionDate, DomainName, ChangeDate, IsCurrent)
select [Exec], AreaSalesManager, AreaSalesManagerCode, AreaSalesQualityManager, AreaSalesQualityManagerCode, 
  AreaName, AreaCode, RegionalSalesManager, RegionalSalesManagerCode, 
  RegionName, RegionCode, SalesQualityManager, SalesQualityManagerCode, 
  Franchise, FranchiseCode, FranchiseSizeID, FranchiseSegmentID, 
  PracticePrincipal, PracticePrincipalCode, PracticeSupervisor, PracticeSupervisorCode, 
  PracticeAdministrator, PracticeAdministratorCode, Adviser, AgentCode, 
  TransactionDate, DomainName, ChangeDate, IsCurrent
from #NewAgents

drop table #NewAgents
drop table #TransactionHierarchy

--Resolve surrogate key IDs

--DateIssuedID
update t
set DateIssuedID = c.DateID
from mstt_TransitionIssuedProduction t
  inner join msdt_CalendarTime c
    on t.PeriodEndDate = c.[DateTime]
  inner join mst_DateTimeControl dtc
    on c.EntryTypeID = dtc.EntryTypeID
where dtc.EntryType = 'DateIssued'


--BusinessTypeID
update t
set BusinessTypeID = bt.BusinessTypeID
from mstt_TransitionIssuedProduction t
  inner join msdt_BusinessType bt
    on t.BusinessType = bt.BusinessType

--AdviserID
update t
set AdviserID = a.AdviserID
from mstt_TransitionIssuedProduction t
  inner join msdt_Adviser a
    on t.SellerSwiftCode = a.AgentCode
    and t.FranchiseSwiftCode = a.FranchiseCode
--where a.IsCurrent = 1

--AdviserID for Dummies
update t
set AdviserID = ad.AdviserID
from mstt_TransitionIssuedProduction t
  inner join msdt_AdviserDummies ad
    on t.SellerSwiftCode = ad.AgentCode
    and t.FranchiseSwiftCode = ad.FranchiseCode


--FranchiseSizeID
update t
set FranchiseSizeID = a.FranchiseSizeID
from mstt_TransitionIssuedProduction t
  inner join msdt_Adviser a
    on t.AdviserId = a.AdviserId



--ProductID
update t
set ProductID = p.ProductID
from mstt_TransitionIssuedProduction t
  inner join msdt_Products p
    on t.SwiftProductCode = p.ProductCode
    
--BusinessReasonId
update t
set BusinessReasonId = br.BusinessReasonId
from mstt_TransitionIssuedProduction t
  inner join msdt_BusinessReason br
    on t.BusinessReason = br.BusinessReasonCode   



END



