CREATE PROCEDURE [dbo].[mstp_TrialBalanceReport] -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
  <author>%Author</author>
  <revision>
    <dateCreated></dateCreated>
    <author>/<author>
    <summary></summary>
  </revision>
</doc>

*******************************************************************************/


-- PROCEDURE BODY GOES HERE
begin

set dateFormat mdy


declare @RunDate datetime  
declare @StartDate varchar (10) 
declare @EndDate varchar (10) 

set @RunDate = (dateadd(MONTH, datediff(MONTH,0,getdate()) ,-1))    -- The Date of the 'business day' of the Swift Extract
set @StartDate = CONVERT(VARCHAR, DATEADD(yy, DATEDIFF(yy,0,@RunDate), 0), 101)  -- in the format 'dd/mm/yyyy'
set @EndDate = convert(varchar, @RunDate, 101)  -- in the format 'dd/mm/yyyy'

--Clear out any rows for this run date, in case we are running the ETL twice in one day
delete from mstt_TrialBalanceReport
where convert(varchar, [Create_Timestamp], 103) = CONVERT(VARCHAR, (Select getdate() - day(getdate())+1)-1, 103) -- use convert to strip out time component

insert into mstt_TrialBalanceReport ([Category_Desc], [Commission_Desc], [Opening_Amount], [Movement_Amount], [Closing_Amount], [Error_MSG])
exec cscp_FINSTAT0028_SW '', @StartDate, @EndDate

update mstt_TrialBalanceReport
set [Create_Timestamp] = @RunDate
where [Create_Timestamp] is null


set dateformat dmy


end



GO
