CREATE PROCEDURE [dbo].[mstp_TrialBalanceReportReload] @EndOfMonth Varchar (50) -- WITH RECOMPILE,ENCRYPTION
  /* Param List */
AS

/******************************************************************************

Copyright (C) Moore Stephens Consulting Limited 2005

Summary : %Summary%
Author  : %Author%
Created : %DateCreated%  
          
<doc>
  <summary>%Summary%</summary>
  <param name='%Param1Name%'>%Param1Summary%</param>
  <returns>%Returns%</returns>
