/****** Object:  StoredProcedure [dbo].[mstp_UserSurrogates]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**************************************************************************************************
Created by: Kris Zywczyk
Created on: 2010-07-21
Description: Update msct_UserSurrogates table

Changes:
--------
When        By whom        What changed
---------------------------------------------------------------------------------------------------

**************************************************************************************************/
create procedure [dbo].[mstp_UserSurrogates]
as
begin
  set nocount on;

  --Delete non existing delegations
  delete t
  from dbo.msct_UserSurrogates t
       left outer join (select DomainLogin = rtrim(ltrim(s.DomainLogin)),
                               SurrogateOf = rtrim(ltrim(s.SurrogateOf))
                        from dbo.msit_UserSurrogates s
                        where rtrim(isnull(s.DomainLogin, '')) <> '' and
                              rtrim(isnull(s.SurrogateOf, '')) <> '' and
                              left(ltrim(s.DomainLogin), 9) = 'OPENWORK\' and
                              left(ltrim(s.SurrogateOf), 9) = 'OPENWORK\'
                        group by rtrim(ltrim(s.DomainLogin)),
                                 rtrim(ltrim(s.SurrogateOf))) as x on t.DomainLogin = x.DomainLogin and
                                                                      t.SurrogateOf = x.SurrogateOf
  where x.DomainLogin is null;
  
  --Insert new delegations
  insert into dbo.msct_UserSurrogates(DomainLogin,
                                      SurrogateOf)
  select DomainLogin = rtrim(ltrim(s.DomainLogin)),
         SurrogateOf = rtrim(ltrim(s.SurrogateOf))
  from dbo.msit_UserSurrogates s
       left outer join dbo.msct_UserSurrogates t on rtrim(ltrim(s.DomainLogin)) = t.DomainLogin and
                                                    rtrim(ltrim(s.SurrogateOf)) = t.SurrogateOf
  where rtrim(isnull(s.DomainLogin, '')) <> '' and
        rtrim(isnull(s.SurrogateOf, '')) <> '' and
        left(ltrim(s.DomainLogin), 9) = 'OPENWORK\' and
        left(ltrim(s.SurrogateOf), 9) = 'OPENWORK\' and
        t.DomainLogin is null
  group by rtrim(ltrim(s.DomainLogin)),
           rtrim(ltrim(s.SurrogateOf));
end;
GO
