CREATE procedure [dbo].[owgl_CheckFranchiseAuth]
 @userId nvarchar(255),
 @franId nvarchar(20)

as

select 
  dLogin =  a.domainLogin,
  franRef = c.code
              --franRef = c.code
from
   glo_userAccessControl a
inner join msdt_adviser b on a.adviserID = b.adviserID
inner join mstt_agents  c on b.franchiseCode = c.code
where
  a.domainLogin = @userId
and b.franchiseCode = @franId
and c.agentType in (2,46,49)

