CREATE procedure [dbo].[owgl_GetFranchiseList]
 @userId nvarchar(255)

as

select distinct
  franRef = c.code,
  franName =  case when tradingName is null then
          DESCN
        else
          tradingName
        end
from
   glo_userAccessControl a
inner join msdt_adviser b on a.adviserID = b.adviserID
inner join mstt_agents  c on b.franchiseCode = c.code
where
  a.domainLogin = @userId
and c.agentType in (2,46,49)
order by 1 





