CREATE       PROCEDURE [dbo].[owgl_GL_Adv_Admin_Insert]
@ReferenceType AS Varchar(10),
@DomainLogin AS Varchar(50),
@AdviserID      AS Varchar(50),
@Application   AS Varchar(20),
@UserRole      AS Varchar(20),
@UpdatedBy     AS Varchar(10)
AS

declare @ptlcode as varchar(50)
declare @code1 as varchar(50)
declare @Name1 as varchar(50)

declare @tcount int

SELECT @tcount = (SELECT COUNT(*) from glo_UserAccessControl where Rtrim(Ltrim(AdviserID)) = RTrim(Ltrim(@AdviserID)) and (Rtrim(Ltrim(DomainLogin)) = RTrim(Ltrim(@DomainLogin))))

if @tcount < 1
begin
INSERT INTO glo_UserAccessControl
VALUES (@AdviserID, 'Openwork\'+@DomainLogin, @ReferenceType, @Application, @UserRole, GetDate(), @UpdatedBy, '001')


select @code1 = agentcode from msdt_Adviser where adviserid = @AdviserID
update glo_UserAccessControl
set agentcode = @code1
where AdviserID = @AdviserID

insert into owgl_GoodLeaversControl
values(@code1, 'Dummy')

end else begin
raiserror('Duplication Error!! The user already exist, if you need any further help, please contact IT support: 0870 050 1670 or 01793 567599 ',16,1,@AdviserID)    
return
end 





