GO
SET QUOTED_IDENTIFIER ON
GO

CREATE        PROCEDURE [dbo].[owglo_getAdviserID] 
  -- Add the parameters for the stored procedure here
             @pcode   varchar(50)
      
AS
BEGIN

create table #temp
    (
     Code varchar(50)
         ,Descn varchar(50)
     ,TradingName varchar(50)
         ,AdvisorID varchar (50)         
    )

declare @pcode1 as varchar(50)
declare @acode as varchar(50)

if @pcode = ''  begin
  set @pcode = null
end else begin
set @pcode1 =  '%' + @pcode + '%'
end

insert into #temp(Code, Descn, TradingName, AdvisorID)
select  a.code,
        a.Descn , 
    a.TradingName,
        null 
  from mstt_Agents a
       Where ((agenttype in (2,46,49)) and Descn like @pcode1)


--bill another array here to get each record
declare advisor_cursor cursor
for
 select
    [Code]

from #temp
 for read only

declare
  @anum                 varchar(20)

open advisor_cursor
fetch advisor_cursor
into
  @anum

declare 
      @data varchar(50)


while (@@fetch_status = 0)
begin
set @data = null
 
select @data = adviserid from msdt_Adviser where agentcode = @anum

update #temp
  set AdvisorID =  @data
where Code = @anum


fetch advisor_cursor
into
  @anum
end

close advisor_cursor
deallocate advisor_cursor


--second part of query
select @acode = code from #temp

select         
                a.Descn       as Name, 
    a.TradingName       as Enterprise, 
        a.AdvisorID as Adviserid,
        a.code as agentcode                       
          --      (select adviserid from msdt_Adviser where agentcode = @acode) as Adviserid,
           --     a.code as agentcode                    
         from #temp a

drop table #temp

End


GO
