CREATE PROCEDURE [dbo].[owhop_addEDIStmtExcl] 
  -- Add the parameters for the stored procedure here
  @userId char(30) 
  ,@statement int
  ,@type char(2)
  
AS
BEGIN
  -- SET NOCOUNT ON added to prevent extra result sets from
  -- interfering with SELECT statements.
  SET NOCOUNT ON;

    -- Insert statements for procedure here
  insert into Head_Office_Systems.dbo.owhot_EDI_statement_exclude (statement,addedBy,addedDate)
    values(@statement,@userId,getdate());

   -- do this as an update incase they are just changing the type and the row already existed
  if @type <> ''  begin
    update Head_Office_Systems.dbo.owhot_EDI_statement_exclude
    set   type = @type
      ,addedBy = @userID
      ,addedDate = getdate()
    where statement = @statement
  end

END


GO
/****** Object:  StoredProcedure [dbo].[owhop_AgentHierarchyValidation]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE procedure [dbo].[owhop_AgentHierarchyValidation]
with recompile
as
 
--########################################################################
--
-- Object  : procedure
-- Name    : mspr_Charges_AgentHierarchyValidation.sql
-- Owner   : MPC
-- Created : 16 March 2007
-- Project : Charges Application 
--
--########################################################################

select 
agentcode as Agent,ag.descn as AgentName,ag.AgentTypeDescription as AgentType,
case ag.competentstatus when 1 then 'Active' when 2 then 'Left' when 3 then 'Dead'
when 4 then 'Canc' when 5 then 'PreApp' when 6 then 'NPW' else 'N/A' end as AgentStatus,
case participanttype when 6 then 'DA' when 7 then 'Franchise' when 8 then 'Strat All' when 9 then 'Access' 
end as Type,
detailagentcode as LinkAgt,ad.descn as LinkAgtName,
ad.AgentTypeDescription as LinkAgtType,
case ad.competentstatus when 1 then 'Active' when 2 then 'Left' when 3 then 'Dead'
when 4 then 'Canc' when 5 then 'PreApp' when 6 then 'NPW' else 'N/A' end as LinkAgtStatus,
case ah.Status when 1 then 'Active' else 'Inactive' end as Status,
case ah.DefaultValue when 1 then 'On' else 'Off' end as DefaultFlag,ah.StartDate,ah.EndDate,
case 
when ah.status = 1 and ah.enddate is not NULL then 'End Date set on Active Row'
when ah.status = 1 and ah.participanttype = 6 and ah.detailagentcode <> ag.Firm then 'Invalid DA Code'
when ah.status = 1 and ah.participanttype = 7 and ah.detailagentcode <> ag.Firm then 'Invalid Franchise Code'
when ah.status = 1 and ah.participanttype = 8 and ah.detailagentcode <> ag.Firm then 'Invalid Strat All Code'
when ah.status = 1 and ah.participanttype = 9 and ah.detailagentcode <> ag.Firm then 'Invalid Access Code'
end as Error
into #Error1
from msit_agenthierarchyhistory ah
left outer join mstt_agents ag on ag.code = ah.agentcode
left outer join mstt_agents ad on ad.code = ah.detailagentcode
where 
( (ah.status = 1 and ah.enddate is not NULL) 
or (ah.status = 1 and ah.detailagentcode <> ag.Firm) )
and ah.participanttype in (7) -- Franchise only
order by Error,ah.agentcode,ah.participanttype,ah.startdate,ah.defaultvalue desc

select 
agentcode as C_Agent,participanttype as C_Type,detailagentcode as C_Detail,startdate as C_Start
,count(*) as Count
into #Combs
from msit_agenthierarchyhistory 
where participanttype in (6,7,8,9)
group by agentcode,detailagentcode,participanttype,startdate
order by agentcode,detailagentcode,participanttype,startdate

select 
agentcode as C_Agent,participanttype as C_Type,detailagentcode as C_Detail,startdate as C_Start
,count(*) as Count
into #ActiveCombs
from msit_agenthierarchyhistory 
where status = 1 and defaultvalue = 1 and participanttype in (6,7,8,9)
group by agentcode,detailagentcode,participanttype,startdate
order by agentcode,detailagentcode,participanttype,startdate

select distinct
agentcode as Agent,ag.descn as AgentName,ag.AgentTypeDescription as AgentType,
case ag.competentstatus when 1 then 'Active' when 2 then 'Left' when 3 then 'Dead'
when 4 then 'Canc' when 5 then 'PreApp' when 6 then 'NPW' else 'N/A' end as AgentStatus,
case participanttype 
when 0 then 'Org' when 1 then 'Company' when 2 then 'Manager4' when 3 then 'Manager3'
when 4 then 'Manager2' when 5 then 'Manager1' when 6 then 'DA' when 7 then 'Franchise' 
when 8 then 'Strat All' when 9 then 'Access' when 10 then 'PFA Comp' 
when 11 then 'Sale Sup' when 12 then 'Span Sup' end as Type,
detailagentcode as LinkAgt,ad.descn as LinkAgtName,
ad.AgentTypeDescription as LinkAgtType,
case ad.competentstatus when 1 then 'Active' when 2 then 'Left' when 3 then 'Dead'
when 4 then 'Canc' when 5 then 'PreApp' when 6 then 'NPW' else 'N/A' end as LinkAgtStatus,
case ah.Status when 1 then 'Active' else 'Inactive' end as Status,
case ah.DefaultValue when 1 then 'On' else 'Off' end as DefaultFlag,ah.StartDate,ah.EndDate,
case when t1.c_agent is null and t2.c_agent is null then 'No Active Entry for Relationship' 
when t1.c_agent is not null and t1.count > 1 then 'More than One Active Entry'
end as Error
into #Error2
from msit_agenthierarchyhistory ah
left outer join mstt_agents ag on ag.code = ah.agentcode
left outer join mstt_agents ad on ad.code = ah.detailagentcode
left outer join #ActiveCombs t1 on t1.c_agent = ah.agentcode and t1.c_type = ah.participanttype
and t1.c_detail = ah.detailagentcode and t1.c_start = ah.startdate
left outer join #ActiveCombs t2 on t2.c_agent = ah.agentcode and t2.c_type = ah.participanttype
left outer join #Combs t3 on t3.c_agent = ah.agentcode and t3.c_type = ah.participanttype
and t3.c_detail = ah.detailagentcode and t3.c_start = ah.startdate
left outer join #Combs t4 on t4.c_agent = ah.agentcode and t4.c_type = ah.participanttype
and t4.c_detail <> ah.detailagentcode 
where 
( (t1.c_agent is null and t2.c_agent is null and t4.c_agent is not null) 
or (t1.c_agent is not null and t1.count > 1) )
and ah.participanttype in (7) -- Franchise only

select * from #Error1
UNION ALL
select * from #Error2
order by Error,agent,type,startdate,defaultflag desc

drop table #Combs
drop table #ActiveCombs
drop table #Error1
drop table #Error2

GO
/****** Object:  StoredProcedure [dbo].[owhop_BACSTotalsAllDates]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[owhop_BACSTotalsAllDates] 
--with recompile	--AG 15/06/2017

as

set nocount on

/******************************************************************************

-----------    Mike Cawood SR9 CHANGES May 2008  ----------------------------

This scan attempts to reconcile each BACS Payment (held at Business level) to the
Swift payments that were exported at the same time for that Business. 

To identify the owning firm this processing has been amended in SR9 to use the 
new version of the FIRM on mstt_PaymentsPending. 

Amendments
==========
Mike Cawood		9 July 2010     Replace mstt_AgentPayments by sa_swift_S_AGMPAY.
Alan Groves		07/12/2010		This scan is about to blow the Excel 65K limit
								so this change at Debbie Burchell's recommendation
								is to limit the scan to the last six months worth
								of data.	
Alan Groves		15/06/2017		SR464996. This change relates to the removal of
								the DTS daily scans where theis proc is now run
								in a job step instead of DTS "ow_daily_scans_main".
								The changes are:
								(1) Logging via "msp_ProcessLog" added. Values 
										hardcoded, as parameters not passed into
										this proc to maintain compatibility with
										the DTS call during the cutover period.
								(2) "WITH RECOMPILE" removed.								 
*******************************************************************************/


-- PROCEDURE BODY GOES HERE

set nocount on
set ANSI_WARNINGS off

--AG 15/06/2017 Start	
declare		@RowCount		int,
			@Process		varchar(100),
			@ProcessMessage	varchar(100),
			@PhaseStart		varchar(50),
			@PhaseEnd		varchar(50),
			@PhaseLog		varchar(50),
			@Client			varchar(50),
			@Module			varchar(50)

set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @PhaseLog		= 'LOG'			
set @Process		= object_name(@@procid)
set @Client			= 'Openwork'
set @Module			= 'Daily Scans'

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client
--AG 15/06/2017 End

-------------- SR9 CHANGES START ----------------------------------------------------

-- Truncate the current table
truncate table owhot_BACSTotalsAllDates

-- Select Exported Totals by Business and Bacs Date from the Paid List (S_AGMPAY table)
select	pp.Firm as BusinessUID,
		rtrim(ag.DESCN) as BusinessName,
		ag.competentstatusdescription as BusinessStatus,
		ag.agenttypedescription as BusinessType,
		ap.export_date as BACSDate,
		count(distinct ap.id) as Payments,
		round(sum(pp.amount),2) as UnpaidListAmount,
		round(sum(ap.amount),2) as PaidListAmount,
		round(sum(pp.amount),2) - round(sum(ap.amount),2) as ControlDiff
into	#Totals
from	sa_swift_S_AGMPAY ap       --MPC 09/07/2010
		inner join mstt_paymentsPending pp on ap.agmid = pp.id
		inner join mstt_Agents ag on ag.code = pp.FIRM
where	ap.Exported = 'T' 
and		ag.agentType in (2,46,49) 
and		dateadd(dd,0,datediff(dd,0,ap.export_date)) >= dateadd(mm,-6,datediff(dd,0,getdate()))	-- AG 07/12/2010
group	by pp.Firm,rtrim(ag.DESCN),
		ag.competentstatusdescription,
		ag.agenttypedescription,
		ap.export_date
order	by pp.Firm,
		ap.export_date

insert into owhot_BACSTotalsAllDates
-- Insert BACS Table details plus matched details from Paid List Totals 
select	bac.agentcode as BusinessUID,
		coalesce(t1.BusinessName,rtrim(ag.DESCN)) as BusinessName,
		coalesce(t1.BusinessStatus,ag.competentstatusdescription) as BusinessStatus,
		coalesce(t1.BusinessType,ag.agenttypedescription) as BusinessType,
		bac.exportdate as BACSDate,
		isnull(t1.Payments,0) as Payments,
		isnull(t1.UnpaidListAmount,0) as UnpaidListAmount,
		isnull(t1.PaidListAmount,0) as PaidListAmount,
		isnull(t1.Controldiff,0) as ControlDiff,
		round(bac.amountpaid,2) as BACSPayment,
		(round(bac.amountpaid,2) - isnull(t1.PaidListAmount,0)) as BACSDiff
from	msit_reportbacsexport bac
		inner join mstt_agents ag on ag.code = bac.agentcode
		left outer join #Totals t1 on bac.agentcode = t1.businessuid and t1.bacsdate = bac.exportdate
where	dateadd(dd,0,datediff(dd,0,bac.ExportDate)) >= dateadd(mm,-6,datediff(dd,0,getdate()))	-- AG 07/12/2010

UNION ALL

-- Insert Paid List Totals not matched to existing BACS Total
select	t1.*,
		0.00 as BACSPayment,
		round((0.00 - t1.PaidListAmount),2) as BACSDiff
from	#Totals t1
		left outer join msit_reportbacsexport bac on bac.agentcode = t1.businessuid and t1.bacsdate = bac.exportdate
where	bac.id is null
order	by 5 desc,1

--AG 15/06/2017 Start	
set @RowCount = @@rowcount
	
set @ProcessMessage = 'Table Insert. Number of rows = ' + convert(varchar(20),@RowCount)	
exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client
--AG 15/06/2017 End

drop table #Totals

-------------- SR9 CHANGES END ----------------------------------------------------

/* -------------- REMOVED IN SR9 ----------------------------------------------------

if exists (select * from dbo.sysobjects where id = object_id(N'[dbo].[owhot_BACSTotalsAllDates]') and OBJECTPROPERTY(id, N'IsUserTable') = 1)
drop table [dbo].[owhot_BACSTotalsAllDates]

-- First Select Commission payments with valid TASHH links
-- TASHH Invalid (a) no codes; (b) 2 or more codes; (c) invalid code 

select distinct tash.id
into #TASH_Errors 
from msit_transagentsplithierarchyhistory tash
where ( 
   (tash.franchiseagentcode is null and tash.accessagentcode is null and tash.directlyauthorisedagentcode is null)
or (tash.franchiseagentcode is not null and tash.accessagentcode is not null) 
or (tash.franchiseagentcode is not null and tash.directlyauthorisedagentcode is not null) 
or (tash.accessagentcode is not null and tash.directlyauthorisedagentcode is not null)
or (tash.franchiseagentcode is not null and tash.franchiseagentcode not in (select code from mstt_agents where agenttype = 2))
or (tash.accessagentcode is not null and tash.accessagentcode not in (select code from mstt_agents where agenttype = 46))
or (tash.directlyauthorisedagentcode is not null and tash.directlyauthorisedagentcode not in (select code from mstt_agents where agenttype = 49))
)
order by tash.id

select 
coalesce(tash.franchiseagentcode,tash.accessagentcode,tash.directlyauthorisedagentcode) as BusinessUID,
coalesce(a1.tradingname,a1.descn) as BusinessName,
case a1.CompetentStatus
when 1 then 'Active' when 2 then 'Left' when 3 then 'Dead' when 4 then 'Canc' when 5 then 'PreApp'
when 6 then 'NPW' else 'Unk' end as BusinessStatus,
case a1.agt_type
when 2 then 'Franchise' when 46 then 'Access' when 47 then 'StrAll' when 49 then 'DA'
when 3 then 'Intro' when 4 then 'Seller' when 5 then 'Admin' when 43 then 'Prin'
when 45 then '10PC Share' when 51 then 'PPrin' when 52 then 'Manager1' when 53 then 'Manager2' 
when 54 then 'Manager3' when 55 then 'Manager4' else 'Unk' end as BusinessType,
pa.export_date as BACSDate,
--*
count (*) as Payments,sum(un.amount) as UnpaidListAmount,sum(pa.amount) as PaidListAmount,
avg(bac.amountpaid) as BACSPayment,round((sum(pa.amount)- avg(bac.amountpaid)),2) as BACSDiff

into #PayTotCommwithValidHierarchy

from msit_s_agmfil un
inner join msit_s_agmpay pa on pa.agmid = un.id
inner join msit_transagentsplithierarchyhistory tash 
on tash.id = un.transagentsplithierarchyhistoryid
inner join msit_s_agents a1 on a1.code = 
coalesce(tash.franchiseagentcode,tash.accessagentcode,tash.directlyauthorisedagentcode)
inner join msit_s_agents a2 on a2.code = un.agent_code
inner join msit_reportbacsexport bac on bac.agentcode = 
coalesce(tash.franchiseagentcode,tash.accessagentcode,tash.directlyauthorisedagentcode)
and bac.exportdate = pa.export_date
left outer join #tash_errors t1 on t1.id = un.transagentsplithierarchyhistoryid

where 
un.agent_code not in ('10002','10004')
and pa.exported = 'T' 
and a1.agt_type in (2,46,49)      -- Businesses only
--and un.type in (1,2,4,10,15,16,17,18,19)  -- Commission Payments only
and a2.agt_type in (3,4,5,43,45,51,52,53,54,55) -- Sellers only (including Sellers now Managers)
and t1.id is null       -- Exclude Erroneous TASHH

group by 
coalesce(tash.franchiseagentcode,tash.accessagentcode,tash.directlyauthorisedagentcode),
coalesce(a1.tradingname,a1.descn),
a1.CompetentStatus,
a1.agt_type, 
pa.export_date

order by 1

-- Next Select Commission payments with missing TASHH link or where TASHH agent not a Business or TASHH Erroneous
-- and use hierarchy at PropDate to assign Business

select distinct un.transactionid as TranID,un.agent_code as Agent,ag.agt_type,
CAST(CONVERT(NVARCHAR, pt.ProposalDate, 112) AS DATETIME) as PropDate,
'Business' as Level,un.agent_code as Business
into #MissingHierarchy_Business
from msit_s_agmfil un
inner join msit_policytransactions pt on pt.id = un.transactionid
inner join msit_s_agents ag on ag.code = un.agent_code
--left outer join  msit_transagentsplithierarchyhistory tash on tash.id = un.transagentsplithierarchyhistoryid 
--left outer join msit_s_agents a2 
--on a2.code = coalesce(tash.franchiseagentcode,tash.accessagentcode,tash.directlyauthorisedagentcode)
where un.type in (1,2,4,10,15,16,17,18,19)
--and un.transagentsplithierarchyhistoryid is null or a2.agt_type in (2,46,49))
and un.agent_code not in (10002,10004)
and ag.agt_type in (2,46,49)
order by 1,2

select distinct un.transactionid as TranID,agent_code as Agent,ag.agt_type,
CAST(CONVERT(NVARCHAR, pt.ProposalDate, 112) AS DATETIME) as PropDate,
'Seller' as Level,NULL as Business
into #MissingHierarchy_Seller
from msit_s_agmfil un
inner join mstt_policytransactions pt on pt.id = un.transactionid
inner join msit_s_agents ag on ag.code = un.agent_code
left outer join  msit_transagentsplithierarchyhistory tash on tash.id = un.transagentsplithierarchyhistoryid 
left outer join msit_s_agents a2 
on a2.code = coalesce(tash.franchiseagentcode,tash.accessagentcode,tash.directlyauthorisedagentcode)
left outer join #tash_errors t1 on t1.id = un.transagentsplithierarchyhistoryid
where un.type in (1,2,4,10,15,16,17,18,19)
and (un.transagentsplithierarchyhistoryid is null or a2.agt_type not in (2,46,49) or t1.id is not null)
and un.agent_code not in (10002,10004)
and ag.agt_type in (3,4,5,43,45,51,52,53,54,55)   -- Sellers only (including Sellers now Managers)
order by 1,2

update #MissingHierarchy_Seller
set Business = coalesce(ahh.detailagentcode,ag.firm)
from #MissingHierarchy_Seller t1
left outer join msit_agenthierarchyhistory ahh on t1.agent = ahh.agentcode
and t1.propdate between ahh.startdate and isnull(ahh.enddate,'31 dec 9999') and ahh.participanttype in (6,7,9)
inner join mstt_agents ag on ag.code = t1.agent

select * into #MissingHierarchy from #MissingHierarchy_Seller
UNION ALL
select * from #MissingHierarchy_Business
order by 1,2

select 
t1.Business as BusinessUID,coalesce(a1.tradingname,a1.descn) as BusinessName,
case a1.CompetentStatus
when 1 then 'Active' when 2 then 'Left' when 3 then 'Dead' when 4 then 'Canc' when 5 then 'PreApp'
when 6 then 'NPW' else 'Unk' end as BusinessStatus,
case a1.agt_type
when 2 then 'Franchise' when 46 then 'Access' when 47 then 'StrAll' when 49 then 'DA'
when 3 then 'Intro' when 4 then 'Seller' when 5 then 'Admin' when 43 then 'Prin'
when 45 then '10PC Share' when 51 then 'PPrin' when 52 then 'Manager1' when 53 then 'Manager2' 
when 54 then 'Manager3' when 55 then 'Manager4' else 'Unk' end as BusinessType,
pa.export_date as BACSDate,
--*
count (*) as Payments,sum(un.amount) as UnpaidListAmount,sum(pa.amount) as PaidListAmount,
avg(bac.amountpaid) as BACSPayment,round((sum(pa.amount)- avg(bac.amountpaid)),2) as BACSDiff

into #PayTotCommwithInvalidHierarchy

from msit_s_agmfil un
inner join msit_s_agmpay pa on pa.agmid = un.id
inner join #MissingHierarchy t1 on t1.tranid = un.transactionid and t1.agent = un.agent_code
inner join msit_s_agents a1 on a1.code = t1.Business 
inner join msit_reportbacsexport bac on bac.agentcode = t1.Business
and bac.exportdate = pa.export_date
left outer join #tash_errors t2 on t2.id = un.transagentsplithierarchyhistoryid

where 
un.agent_code not in ('10002','10004')
and pa.exported = 'T' 
and un.type in (1,2,4,10,15,16,17,18,19)  -- Commission Payments only
and (t2.id is not null or un.transagentsplithierarchyhistoryid is null)

group by 
t1.Business,
coalesce(a1.tradingname,a1.descn),
a1.CompetentStatus,
a1.agt_type, 
pa.export_date

order by 1

-- Now select Manual payments (including Standing Orders)
-- If Seller Code used (should always be Business but...) then default to current Firm

select 
case when a2.agt_type in (2,46,49) then un.agent_code else a2.firm end as BusinessUID,
case when a2.agt_type in (2,46,49) then coalesce(a2.tradingname,a2.descn) 
else coalesce(a3.tradingname,a3.descn) end as BusinessName,
case when a2.agt_type in (2,46,49) then (
case a2.competentstatus
when 1 then 'Active' when 2 then 'Left' when 3 then 'Dead' when 4 then 'Canc'
when 5 then 'PreApp' when 6 then 'NPW' else 'Unk' end)
else (case a3.competentstatus
when 1 then 'Active' when 2 then 'Left' when 3 then 'Dead' when 4 then 'Canc'
when 5 then 'PreApp' when 6 then 'NPW' else 'Unk' end) end as BusinessStatus,
case when a2.agt_type in (2,46,49) then (
case a2.agt_type 
when 2 then 'Franchise' when 46 then 'Access' when 47 then 'StrAll' when 49 then 'DA'
when 3 then 'Intro' when 4 then 'Seller' when 5 then 'Admin' when 43 then 'Prin' when 45 then '10PC Share'
when 51 then 'PPrin' when 52 then 'Manager1' when 53 then 'Manager2' when 54 then 'Manager3' 
when 55 then 'Manager4' else 'Unk' end)
else (case a3.agt_type 
when 2 then 'Franchise' when 46 then 'Access' when 47 then 'StrAll' when 49 then 'DA'
when 3 then 'Intro' when 4 then 'Seller' when 5 then 'Admin' when 43 then 'Prin' when 45 then '10PC Share'
when 51 then 'PPrin' when 52 then 'Manager1' when 53 then 'Manager2' when 54 then 'Manager3' 
when 55 then 'Manager4' else 'Unk' end) end as BusinessType,
pa.export_date as BACSDate,
--*
count (*) as Payments,sum(un.amount) as UnpaidListAmount,sum(pa.amount) as PaidListAmount,
avg(bac.amountpaid) as BACSPayment,round((sum(pa.amount)- avg(bac.amountpaid)),2) as BACSDiff

into #PayTotManuals

from msit_s_agmfil un
inner join msit_s_agmpay pa on pa.agmid = un.id
inner join msit_s_agents a2 on a2.code = un.agent_code
left outer join msit_s_agents a3 on a3.code = a2.Firm 
inner join msit_reportbacsexport bac 
on bac.agentcode = case when a2.agt_type in (2,46,49) then un.agent_code else a2.firm end
and bac.exportdate = pa.export_date

where 
un.agent_code not in ('10002','10004')
and pa.exported = 'T' 
and un.type in (0,3,7,8,14,20,21)
and (a2.agt_type in (2,46,49) or a3.agt_type in (2,46,49))
and un.transagentsplithierarchyhistoryid is null

group by 
case when a2.agt_type in (2,46,49) then un.agent_code else a2.firm end,
case when a2.agt_type in (2,46,49) then coalesce(a2.tradingname,a2.descn) 
else coalesce(a3.tradingname,a3.descn) end,
case when a2.agt_type in (2,46,49) then (
case a2.competentstatus
when 1 then 'Active' when 2 then 'Left' when 3 then 'Dead' when 4 then 'Canc'
when 5 then 'PreApp' when 6 then 'NPW' else 'Unk' end)
else (case a3.competentstatus
when 1 then 'Active' when 2 then 'Left' when 3 then 'Dead' when 4 then 'Canc'
when 5 then 'PreApp' when 6 then 'NPW' else 'Unk' end) end,
case when a2.agt_type in (2,46,49) then (
case a2.agt_type 
when 2 then 'Franchise' when 46 then 'Access' when 47 then 'StrAll' when 49 then 'DA'
when 3 then 'Intro' when 4 then 'Seller' when 5 then 'Admin' when 43 then 'Prin' when 45 then '10PC Share'
when 51 then 'PPrin' when 52 then 'Manager1' when 53 then 'Manager2' when 54 then 'Manager3' 
when 55 then 'Manager4' else 'Unk' end)
else (case a3.agt_type 
when 2 then 'Franchise' when 46 then 'Access' when 47 then 'StrAll' when 49 then 'DA'
when 3 then 'Intro' when 4 then 'Seller' when 5 then 'Admin' when 43 then 'Prin' when 45 then '10PC Share'
when 51 then 'PPrin' when 52 then 'Manager1' when 53 then 'Manager2' when 54 then 'Manager3' 
when 55 then 'Manager4' else 'Unk' end) end,
pa.export_date 

order by 1

Select * into #PayTot_ALL from #PayTotManuals
UNION ALL
Select * from #PayTotCommwithValidHierarchy
UNION ALL
Select * from #PayTotCommwithInvalidHierarchy
order by 1

select bac.agentcode as BusinessUID,coalesce(ag.tradingname,ag.descn) as BusinessName,
case ag.CompetentStatus
when 1 then 'Active' when 2 then 'Left' when 3 then 'Dead' when 4 then 'Canc' when 5 then 'PreApp'
when 6 then 'NPW' else 'Unk' end as BusinessStatus,
case ag.agt_type
when 2 then 'Franchise' when 46 then 'Access' when 47 then 'StrAll' when 49 then 'DA'
when 3 then 'Intro' when 4 then 'Seller' when 5 then 'Admin' when 43 then 'Prin'
when 45 then '10PC Share' when 51 then 'PPrin' when 52 then 'Manager1' when 53 then 'Manager2' 
when 54 then 'Manager3' when 55 then 'Manager4' else 'Unk' end as BusinessType,
bac.exportdate as BACSDate,0 as Payments,0 as UnpaidListAmount,0 as PaidListAmount,
bac.amountpaid as BACSPayment,round(-1 * bac.amountpaid,2) as BACSDiff

into #OtherBACS

from msit_reportbacsexport bac
inner join msit_s_agents ag on ag.code = bac.agentcode
left outer join #PayTot_ALL t1 
on t1.businessuid = bac.agentcode and t1.bacsdate = bac.exportdate 
where t1.businessuid is null

order by bac.agentcode,bac.exportdate

Select * into #PayTotals 
from #PayTot_ALL
UNION ALL
Select * from #OtherBACS
order by 1,5

Select 
BusinessUID,BusinessName,BusinessStatus,BusinessType,BACSDate,
Sum(Payments) as Payments,sum(UnpaidListAmount) as UnpaidListAmount,sum(PaidListAmount) as PaidListAmount,
cast(Sum(UnpaidListAmount - PaidListAmount) as decimal(15,2)) as ControlDiff,
avg(BACSPayment) as BACSPayment,round((sum(PaidListAmount)- avg(BACSPayment)),2) as BACSDiff

into owhot_BACSTotalsAllDates
from #PayTotals 

Group by 
BusinessUID,
BusinessName,
BusinessStatus,
BusinessType,
BACSDate

Order by bacsdate desc,businessuid

drop table #tash_errors
drop table #MissingHierarchy_Business
drop table #MissingHierarchy_Seller
drop table #MissingHierarchy
Drop Table #PayTotManuals
Drop Table #PayTotCommwithInvalidHierarchy
Drop Table #PayTotCommwithValidHierarchy
Drop Table #PayTot_ALL
Drop Table #OtherBACS
Drop Table #PayTotals

*/-------------- REMOVED IN SR9 ----------------------------------------------------









GO
