CREATE PROCEDURE [dbo].[owhop_BIStats] AS


if exists (select * from dbo.sysobjects where id = object_id(N'[dbo].[owhot_BIStats]') and OBJECTPROPERTY(id, N'IsUserTable') = 1)
drop table dbo.owhot_BIStats

set ansi_nulls off

declare       @DateFrom   DateTime

set @DateFrom = dateadd(month, -2, getdate())

select   *
into     #joblog_temp
from     joblog
Where  ((process = 'Truncate Import Table [msit_AgentAuthorisation]' AND Phase = 'Start')
   or    process = 'Zurich_Openwork_DimsAndCubes_Redesign, Error: 0'
   or   (process = 'owhop_suspense_add' and phase = 'end'))
  and    DtTm > @DateFrom



select   a.DtTm as 'Start'
       , b.DtTm as 'Available'
       , c.DtTm as 'Finish'
       , datediff(minute, a.dttm, b.dttm) as 'Mins to Available'
       , datediff(minute, a.dttm, c.dttm) as 'Mins to Finish'
into owhot_BIStats
from     #joblog_temp a
       , #joblog_temp b
       , #joblog_temp c
where    datediff(hour, a.dttm, b.dttm) between 0 and 12
  and    datediff(hour, a.dttm, c.dttm) between 0 and 12
  and    c.DtTm > @DateFrom
  and   (a.process = 'Truncate Import Table [msit_AgentAuthorisation]' AND a.Phase = 'Start')
  and    b.process = 'Zurich_Openwork_DimsAndCubes_Redesign, Error: 0'
  and   (c.process = 'owhop_suspense_add' and c.phase = 'end')
order by Start desc

drop table #joblog_temp
return
GO
