CREATE   procedure [dbo].[owhop_BQMGetFranchiseDet]
  @franRef  varchar(10)
as

/*########################################################################

Amended		: 
	Paul Robathan 01/07/13 - use new hierarchy table mi_insight_UserHierarchy
	to get details

########################################################################*/

declare @agentType int

-- check what type of agent this is
select @agentType = AgentType
from mstt_Agents
where code = @franRef
if @agentType in (52, 53, 55) begin  --manager 1,2,4


SELECT   
		agents_0.CODE
       , agents_0.DESCN AS Name
     , agents_0.AgentCategory As Agent_Category
       , agents_0.AgentType
       , agents_0.AgentTypeDescription
       , agents_0.eMAil AS eMail
       , agents_0.Telephone AS Telephone
       , agents_0.Address1 as Address1
       , agents_0.Address2 as Address2
       , agents_0.Address3 as Address3
       , agents_0.Address4 as Address4
       , agents_0.Address5 as Address5
       , agents_0.PostCode as PostCode
       , case  when agents_1.AgentCategory ='ASD' then '' else agents_1.Code end AS Panel_Mgr_Code
       , case  when agents_1.AgentCategory ='ASD' then '' else Agents_1.DESCN end AS Panel_Mgr_Name
       , case  when agents_1.AgentCategory ='ASD' then '' else Agents_1.AgentCategory end AS Panel_Mgr_Category
       , case  when agents_1.AgentCategory ='ASD' then '' else Agents_1.email end AS Panel_Mgr_email
       , case  when agents_1.AgentCategory ='ASD' then '' else Agents_1.Telephone end AS Panel_Mgr_Telephone
       , case  when agents_1.AgentCategory ='ASD' then '' else agents_1.Address1 end as Panel_Mgr_Address1
       , case  when agents_1.AgentCategory ='ASD' then '' else agents_1.Address2 end as Panel_Mgr_Address2
       , case  when agents_1.AgentCategory ='ASD' then '' else agents_1.Address3 end as Panel_Mgr_Address3
       , case  when agents_1.AgentCategory ='ASD' then '' else agents_1.Address4 end as Panel_Mgr_Address4
       , case  when agents_1.AgentCategory ='ASD' then '' else agents_1.Address5 end as Panel_Mgr_Address5
       , case  when agents_1.AgentCategory ='ASD' then '' else agents_1.PostCode end as Panel_Mgr_PostCode
       , case  when agents_1.AgentCategory ='ASD' then Agents_1.Code else Agents_2.Code end AS Area_Mgr_Code
       , case  when agents_1.AgentCategory ='ASD' then Agents_1.DESCN else Agents_2.DESCN end AS Area_Mgr_Name
       , case  when agents_1.AgentCategory ='ASD' then Agents_1.AgentCategory else Agents_2.AgentCategory end AS Area_Mgr_Category
       , case  when agents_1.AgentCategory ='ASD' then Agents_1.email else Agents_2.email end AS Area_Mgr_email
       , case  when agents_1.AgentCategory ='ASD' then Agents_1.Telephone else Agents_2.Telephone end AS Area_Mgr_Telephone
       , case  when agents_1.AgentCategory ='ASD' then agents_1.Address1 else agents_2.Address1 end as Area_Mgr_Address1
       , case  when agents_1.AgentCategory ='ASD' then agents_1.Address2 else agents_2.Address2 end as Area_Mgr_Address2
       , case  when agents_1.AgentCategory ='ASD' then agents_1.Address3 else agents_2.Address3 end as Area_Mgr_Address3
       , case  when agents_1.AgentCategory ='ASD' then agents_1.Address4 else agents_2.Address4 end as Area_Mgr_Address4
       , case  when agents_1.AgentCategory ='ASD' then agents_1.Address5 else agents_2.Address5 end as Area_Mgr_Address5
       , case  when agents_1.AgentCategory ='ASD' then agents_1.PostCode else agents_2.PostCode end as Area_Mgr_PostCode
FROM  mstt_Agents Agents_0 
LEFT OUTER JOIN mi_insight_UserHierarchy uh on uh.UserUID = agents_0.code
LEFT OUTER JOIN mstt_Agents Agents_1 ON
    Agents_1.CODE = isnull(uh.BQMUID,agents_0.SaleSupervisorCode)
  AND agents_1.code <> '10007'
  AND agents_1.code <> '10012' 
LEFT OUTER JOIN mstt_Agents Agents_2 ON 
    Agents_2.CODE  = isnull(uh.ADUID,agents_1.SaleSupervisorCode)
  and agents_2.code <> '10007' 
  AND agents_2.code <> '10012' 
WHERE  1=1
  and agents_0.agenttypeB30 = 2
    and agents_0.code = @franRef


end
else
begin


SELECT   agents_0.CODE
       , agents_0.DESCN AS Name
	   , agents_0.AgentCategory As Agent_Category
       , agents_0.AgentType
       , agents_0.AgentTypeDescription
       , agents_0.eMAil AS eMail
       , agents_0.Telephone AS Telephone
       , agents_0.Address1 as Address1
       , agents_0.Address2 as Address2
       , agents_0.Address3 as Address3
       , agents_0.Address4 as Address4
       , agents_0.Address5 as Address5
       , agents_0.PostCode as PostCode
       , case  when agents_1.AgentCategory ='ASD' then '' else agents_1.Code end AS Panel_Mgr_Code
       , case  when agents_1.AgentCategory ='ASD' then '' else Agents_1.DESCN end AS Panel_Mgr_Name
       , case  when agents_1.AgentCategory ='ASD' then '' else Agents_1.AgentCategory end AS Panel_Mgr_Category
       , case  when agents_1.AgentCategory ='ASD' then '' else Agents_1.email end AS Panel_Mgr_email
       , case  when agents_1.AgentCategory ='ASD' then '' else Agents_1.Telephone end AS Panel_Mgr_Telephone
       , case  when agents_1.AgentCategory ='ASD' then '' else agents_1.Address1 end as Panel_Mgr_Address1
       , case  when agents_1.AgentCategory ='ASD' then '' else agents_1.Address2 end as Panel_Mgr_Address2
       , case  when agents_1.AgentCategory ='ASD' then '' else agents_1.Address3 end as Panel_Mgr_Address3
       , case  when agents_1.AgentCategory ='ASD' then '' else agents_1.Address4 end as Panel_Mgr_Address4
       , case  when agents_1.AgentCategory ='ASD' then '' else agents_1.Address5 end as Panel_Mgr_Address5
       , case  when agents_1.AgentCategory ='ASD' then '' else agents_1.PostCode end as Panel_Mgr_PostCode
       , case  when agents_1.AgentCategory ='ASD' then Agents_1.Code else Agents_2.Code end AS Area_Mgr_Code
       , case  when agents_1.AgentCategory ='ASD' then Agents_1.DESCN else Agents_2.DESCN end AS Area_Mgr_Name
       , case  when agents_1.AgentCategory ='ASD' then Agents_1.AgentCategory else Agents_2.AgentCategory end AS Area_Mgr_Category
       , case  when agents_1.AgentCategory ='ASD' then Agents_1.email else Agents_2.email end AS Area_Mgr_email
       , case  when agents_1.AgentCategory ='ASD' then Agents_1.Telephone else Agents_2.Telephone end AS Area_Mgr_Telephone
       , case  when agents_1.AgentCategory ='ASD' then agents_1.Address1 else agents_2.Address1 end as Area_Mgr_Address1
       , case  when agents_1.AgentCategory ='ASD' then agents_1.Address2 else agents_2.Address2 end as Area_Mgr_Address2
       , case  when agents_1.AgentCategory ='ASD' then agents_1.Address3 else agents_2.Address3 end as Area_Mgr_Address3
       , case  when agents_1.AgentCategory ='ASD' then agents_1.Address4 else agents_2.Address4 end as Area_Mgr_Address4
       , case  when agents_1.AgentCategory ='ASD' then agents_1.Address5 else agents_2.Address5 end as Area_Mgr_Address5
       , case  when agents_1.AgentCategory ='ASD' then agents_1.PostCode else agents_2.PostCode end as Area_Mgr_PostCode
FROM  mstt_Agents Agents_0 
LEFt OUTER JOIN mi_insight_UserHierarchy uh on uh.UserUID = agents_0.code
LEFT OUTER JOIN mstt_Agents Agents_1 ON
    uh.BQMUID = Agents_1.CODE 
LEFT OUTER JOIN mstt_Agents Agents_2 ON 
    ADUID = Agents_2.CODE 
WHERE  1=1
    and agents_0.code = @franRef

end
GO
