/****** Object:  StoredProcedure [dbo].[owhop_BusinessMPL_GetDetails]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER OFF
GO

cREATE PROCEDURE [dbo].[owhop_BusinessMPL_GetDetails]
@BusinessCode AS Varchar(7)

AS

--########################################################################
--
-- Object  : procedure
-- Name    : owhop_BusinessMPL_GetDetails.sql
-- Owner   : MPC
-- Created : 2 May 2007
-- Project : Openwork Head Office Systems - Charges Application 
--
-- Procedure called by Business MPL Summary Report. 
-- Called with one paramter:
--
-- @BusinessCode
-- Determines Business for which MPL Charge details to be extracted.
-- 
--########################################################################

-- Access MPL Charges Table and find Prevailing Charge.
select distinct Month, '1 Jan 1900' as ChargeMonth
into #Months 
from owhot_MPLCharges
where BusinessCode = @BusinessCode 
order by Month

select T1.Month,max(CH.Month) as ChargeMonth 
into #ChargeMonth 
from #Months T1,owhot_OpenworkCharges CH
where CH.Month <= T1.Month
group by T1.Month
order by T1.Month

select T1.Month,T1.ChargeMonth,MPLThreshold
into #MPLCharge
from #ChargeMonth T1   
inner join owhot_OpenworkCharges CH on T1.ChargeMonth = CH.Month

-- Extract details.
SELECT  COALESCE(ag.TradingName,ag.DESCN) as BusinessName,
             csp.MonthName,
  mc.MPLThreshold,
  mpl.*,
        coalesce(IU.Description, mpl.UpdatedBy) AS Updater
FROM owhot_MPLCharges mpl 
INNER JOIN mstt_Agents ag ON mpl.BusinessCode = ag.Code 
LEFT OUTER  JOIN msit_CommissionStatementPeriods csp ON mpl.[Month] = csp.[Month] 
INNER JOIN #MPLCharge mc ON mpl.[Month] = mc.[Month]
LEFT OUTER JOIN msit_intusers iu on iu.Name = mpl.UpdatedBy
WHERE BusinessCode = @BusinessCode
ORDER BY mpl.[Month] Desc

drop table #Months
drop table #ChargeMonth
drop table #MPLCharge

GO
