CREATE PROCEDURE [dbo].[owhop_ChargesAdmin_GetDetails]
AS

SELECT  TOP 15 csp.MonthName, 
  coalesce(users.[Description],oc.UpdatedBy) As UpdatedBy,
  oc.[Month],
  oc.DateUpdated,
  oc.MPLCharge,
  oc.MPLThreshold,
  oc.PracPrinCharge,
  oc.PenInvCharge,
  oc.MortgageCharge,
  oc.GICharge,
  oc.ICOBCharge
FROM owhot_OpenworkCharges oc INNER JOIN msit_CommissionStatementPeriods csp
  ON oc.[Month] = csp.[Month] LEFT OUTER JOIN msit_intusers users
    ON users.[Name] = oc.UpdatedBy
ORDER BY oc.[Month] Desc


