CREATE PROCEDURE [dbo].[owhop_ChargesAdmin_GetMonths]
AS

DECLARE @MPLMonth AS Datetime
DECLARE @SVMonth AS Datetime

SELECT @MPLMonth = Max([Month]) FROM owhot_MPLCharges 
SELECT @SVMonth = Max([Month]) FROM owhot_SupervisorChargeBusiness

SELECT  
  p1.MPLMonth,
  p1.MPLMonthName,
  p2.SVMonth,
  p2.SVMonthName
FROM  (SELECT [Month] AS MPLMonth,
    MonthName AS MPLMonthName
   FROM msit_CommissionStatementPeriods
   WHERE [Month] = @MPLMonth) as p1
,
  (SELECT [Month] AS SVMonth,
    MonthName AS SVMonthName
   FROM msit_CommissionStatementPeriods
   WHERE [Month] = @SVMonth ) as p2


GO
/****** Object:  StoredProcedure [dbo].[owhop_ChargesAdmin_GetPeriod]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER OFF
GO

CREATE PROCEDURE [dbo].[owhop_ChargesAdmin_GetPeriod]
AS

DECLARE @Month as datetime
DECLARE @SVMonth as datetime

SELECT @Month = MAX([Month]) FROM owhot_MPLCharges
SELECT @SVMonth = MAX([Month]) FROM owhot_SupervisorChargeBusiness
-- In case one MPL or supervisors have been run for a different period get the latest of the 2
IF @Month < @SVMonth
BEGIN
  SET @Month = @SVMonth
END
-- Set @Month so that we get the latest run period and the next one to be run
SET @Month = DATEADD(Month, 1, @Month)

SELECT Top 2 [Month],
       MonthName
FROM msit_CommissionStatementPeriods
WHERE [Month] <= @Month
ORDER By [Month] Desc

GO
/****** Object:  StoredProcedure [dbo].[owhop_ChargesAdmin_Insert]    Script Date: 7/3/2026 3:44:25 PM ******/
