GO

CREATE PROCEDURE [dbo].[owhop_ChargesAdmin_Insert]
@Month          AS Datetime,
@UpdatedBy      AS Varchar(10),
@MPLCharge      AS Float,
@MPLThreshold   AS Float,
@PracPrinCharge AS Float,
@PenInvCharge   AS Float,
@MortgageCharge AS Float,
@GICharge       AS Float,
@ICOBCharge     AS Float
AS

IF EXISTS (SELECT 1 FROM owhot_OpenworkCharges WHERE [Month] = @Month)
BEGIN
    DELETE FROM owhot_OpenworkCharges WHERE [Month] = @Month
END

INSERT INTO owhot_OpenworkCharges
VALUES (@Month, @UpdatedBy, GetDate(), @MPLCharge, @MPLThreshold, @PracPrinCharge, @PenInvCharge, @MortgageCharge, @GICharge, @ICOBCharge)


GO
/****** Object:  StoredProcedure [dbo].[owhop_ChargesScheduledRun]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE procedure [dbo].[owhop_ChargesScheduledRun]

with recompile
as

--########################################################################
--
-- Object  : procedure
-- Name    : owhop_ChargesScheduledRun
-- Owner   : MAC
-- Created : 6 June 2007
-- Project : Openwork Head Office Systems - Charges Application. Job to run as part of 
--                                          charges batch schedule.

-- Set up Process Log parameters

declare 
 @PhaseStart     varchar(50),
 @PhaseEnd       varchar(50),
 @Client         varchar(50),
 @Module         varchar(50),
 @Process        varchar(100)

set @PhaseStart = 'START'
set @PhaseEnd   = 'END'
set @Client     = 'Openwork'
set @Module     = 'Head Office'
set @Process    = 'Head Office Charges Batch Run'

-- Log Start of Run
exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

-- Set up batch parameters

declare @YesterdaysDate varchar (10)
set @YesterdaysDate = Convert(varchar (10), getdate()-1,111)

-- Execute procedures
set @Process    = 'owhop_mplchargescalculation'
exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client
exec dbo.owhop_mplchargescalculation     'B',@Yesterdaysdate,'Automatic'
exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

set @Process    = 'owhop_supervisionchargescalculation'
exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client
exec dbo.owhop_supervisionchargescalculation   'B',@Yesterdaysdate,'Automatic'
exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

-- Log end of Run
set @Process    = 'Head Office Charges Batch Run'
exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client
GO
