CREATE PROCEDURE [dbo].[owhop_Common_GetHeadOfficeAuthorisation]
@ReferenceName AS Varchar(50),
@Application AS Varchar(20),
@ReferenceType AS Varchar(10)
AS

SELECT *
FROM owhot_HeadOfficeAuthorisation
WHERE ReferenceName = COALESCE(@ReferenceName, ReferenceName)
  AND Application = COALESCE(@Application, Application) 
  And ReferenceType = COALESCE(@ReferenceType, ReferenceType)
OR
  ReferenceName = @ReferenceName
  AND (UserRole = 'Supervisor' or UserRole = 'GroupSupervisor')

GO
