--########################################################################
--
-- Object  : procedure
-- Name    : owhop_DailySuspenseUpdate.sql
-- Owner   : Steve Walker
-- Created : 16/10/2007
--
--########################################################################

CREATE                procedure [dbo].[owhop_DailySuspenseUpdate]
@EDIFiles as char(10)
,@ProviderDesc varchar(20)
,@Date varchar(10)
,@CasesAutomatch as char(10)
,@ValueAutomatch as char(10)
,@Casessuspense as char(10)
,@Valuesuspense as char(10)
,@CasesManualMatch as char(10)
,@ValueManualMatch as char(10)
,@Casesawaiting as char(10)
,@Valueawaiting as char(10)
,@Casesclawbacks as char(10)
,@Valueclawbacks as char(10)
,@CasesnoClient as char(10)
,@ValuenoClient as char(10)
,@CasesnoExpectation as char(10)
,@ValuenoExpectation as char(10)
,@CasesotherQuery as char(10)
,@ValueotherQuery as char(10)
,@CasescontraEntry as char(10)
,@ValuecontraEntry as char(10)
,@CasestoDo as char(10)
,@ValuetoDo as char(10)
,@CasesbacklogMatched as char(10)
,@ValuebacklogMatched as char(10)
,@CasesbacklogAwaiting as char(10)
,@ValuebacklogAwaiting as char(10)
,@CasesbacklogOther as char(10)
,@ValuebacklogOther as char(10)



AS
BEGIN
declare @RunDate datetime   set @RunDate= CAST(CONVERT(NVARCHAR,@Date,112) as datetime)


declare @providertype int set @providertype = case @ProviderDesc when 'Mortgages Other' then  1  when 'Sterling/SIML Other' then 2 
--'Sterling/SIML Other' then 2 
when 'Scot Eq Other' then 3 when 'Zurich/TALA Other' then 4 end

SET NOCOUNT ON;
Declare @FoundDate DateTime
Declare @FoundProvider int


Select @FoundDate = [Date] from Head_Office_Systems.dbo.owhot_Manual_Stats Where [Date] = @RunDate
Select @FoundProvider = providertype from Head_Office_Systems.dbo.owhot_Manual_Stats Where providertype = @providertype


If (@FoundDate IS NULL and @FoundProvider IS NULL)
BEGIN
insert into Head_Office_Systems.dbo.owhot_Manual_Stats
(
[Date],
providertype,
totalstatements,
autoMatchedCases,
autoMatchedValue,
suspenseCases,
suspenseValue,
manualMatchedCases,
manualMatchedValue,
awaitingMatchCases,
awaitingMatchValue,
clawbackCases,
clawbackValue,
noClientCases,
noClientValue,
noExpCases,
noExpValue,
otherCases,
otherValue,
contraCases,
contraValue,
toDoCases,
toDoValue,
bkMatchedCases,
bkMatchedValue,
bkAwaitMatchCases,
bkAwaitMatchValue,
bkOtherCases,
bkOtherValue
)
Values(
@RunDate,
@providertype,
@EDIFiles,
@CasesAutomatch,
@ValueAutomatch,
@Casessuspense,
@Valuesuspense,
@CasesManualMatch,
@ValueManualMatch,
@Casesawaiting,
@Valueawaiting,
@Casesclawbacks,
@Valueclawbacks,
@CasesnoClient,
@ValuenoClient,
@CasesnoExpectation,
@ValuenoExpectation,
@CasesotherQuery,
@ValueotherQuery,
@CasescontraEntry,
@ValuecontraEntry,
@CasestoDo,
@ValuetoDo,
@CasesbacklogMatched,
@ValuebacklogMatched,
@CasesbacklogAwaiting,
@ValuebacklogAwaiting,
@CasesbacklogOther,
@ValuebacklogOther
);
SELECT SCOPE_IDENTITY() AS [SCOPE_IDENTITY]
END

Else 
BEGIN 
Delete From Head_Office_Systems.dbo.owhot_Manual_Stats
Where ([Date] = @RunDate) and (providertype = @providertype)

insert into Head_Office_Systems.dbo.owhot_Manual_Stats
(
[Date],
providertype,
totalstatements,
autoMatchedCases,
autoMatchedValue,
suspenseCases,
suspenseValue,
manualMatchedCases,
manualMatchedValue,
awaitingMatchCases,
awaitingMatchValue,
clawbackCases,
clawbackValue,
noClientCases,
noClientValue,
noExpCases,
noExpValue,
otherCases,
otherValue,
contraCases,
contraValue,
toDoCases,
toDoValue,
bkMatchedCases,
bkMatchedValue,
bkAwaitMatchCases,
bkAwaitMatchValue,
bkOtherCases,
bkOtherValue
)
Values(
@RunDate,
@providertype,
@EDIFiles,
@CasesAutomatch,
@ValueAutomatch,
@Casessuspense,
@Valuesuspense,
@CasesManualMatch,
@ValueManualMatch,
@Casesawaiting,
@Valueawaiting,
@Casesclawbacks,
@Valueclawbacks,
@CasesnoClient,
@ValuenoClient,
@CasesnoExpectation,
@ValuenoExpectation,
@CasesotherQuery,
@ValueotherQuery,
@CasescontraEntry,
@ValuecontraEntry,
@CasestoDo,
@ValuetoDo,
@CasesbacklogMatched,
@ValuebacklogMatched,
@CasesbacklogAwaiting,
@ValuebacklogAwaiting,
@CasesbacklogOther,
@ValuebacklogOther
);
SELECT SCOPE_IDENTITY() AS [SCOPE_IDENTITY]
END



END









