SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/****************************************************************************
  	 Program:  	owhop_deleteMPLCharges					
	  Author:	Unknown
Date created:	Unknown (maybe 2007?)							
											
Description:	This proc is used by the MPL Admin screen (Head Office Systems) 
				to delete businesses from the MPL Standing Order file that is
				loaded into Swift. 

				Note: At the time of writing (17/03/2011) all the parameters
				passed in to the proc are null except @ID.

			
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
17/03/2011	A Groves	Delete equivalent row from the letters file.
07/04/2017	A Groves	SR464996/CH16204. Replace DTS scripts with start of job 
						that contains SSIS replacement scripts: 
						1) "MPLChargeStandingOrderTriggerExtract.dtsx"
						2) "MPLChargeLetterTriggerExtract.dtsx"	
****************************************************************************/
CREATE PROCEDURE [dbo].[owhop_deleteMPLCharges]
	@ID as int 
	,@StandingorderCode as varchar(100)
	,@BusinessCode as nvarchar(50)
	,@DueDate as varchar(20)
	,@EndDate as varchar(20)
	,@Amount as varchar(20)
	,@Frequency as varchar(10)
	,@Description as varchar(10)

AS

-- 17/03/2011 Start

declare @BusinessToDelete	varchar(7)

select	@BusinessToDelete = BusinessCode
from	Head_Office_Systems.dbo.MPLChargeStandingOrderTriggers 
where	[ID] = @ID

-- 17/03/2011 End

delete Head_Office_Systems.dbo.MPLChargeStandingOrderTriggers          
where [ID] = @ID

-- AG 07/04/2017 Start
-- exec mscp-run-dts-package 'owdts_mplchargestandingordertriggerextract'
update dbo.owt_JobControl
		set JobStartRequired = 1,
			DateLastUpdatedByCaller = GETDATE()
where JobCode = 'MPL-CHARGE-STD-ORDS'

declare @JobName varchar(300)
select	@JobName = JobName
from	dbo.owt_JobControl
where	JobCode = 'MPL-CHARGE-STD-ORDS'

if dbo.owf_JobStillRunning(@JobName) = 0
	exec msdb.dbo.sp_start_job @JobName
-- AG 07/04/2017 End

-- 17/03/2011 Start

delete owhot_MPLChargeLetterTriggers
where BusinessCode = @BusinessToDelete

-- 17/03/2011 End

-- AG 07/04/2017 Start
-- exec mscp-run-dts-package 'owdts_mplchargelettertriggerextract'
update dbo.owt_JobControl
	set JobStartRequired = 1,
		DateLastUpdatedByCaller = GETDATE()
where JobCode = 'MPL-CHARGE-LETTERS'

select	@JobName = JobName
from	dbo.owt_JobControl
where	JobCode = 'MPL-CHARGE-LETTERS'

if dbo.owf_JobStillRunning(@JobName) = 0
	exec msdb.dbo.sp_start_job @JobName
-- AG 07/04/2017 End


GO
