/****** Object:  StoredProcedure [dbo].[owhop_EcodeInitialLoad]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO




CREATE  procedure [dbo].[owhop_EcodeInitialLoad]
with recompile
as

set dateformat ymd

--########################################################################
--
-- Object  : procedure
-- Name    : owhop_EcodeInitialLoad
-- Owner   : PR
-- Created : 19/10/2007
--
--########################################################################

---------------------------------------------------------------------------------------------------
--- First clear down the table (precautionary)
---------------------------------------------------------------------------------------------------

truncate table Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref

---------------------------------------------------------------------------------------------------
--- Initial load of table owhot_OSCARSwiftAgentXref from msit_OscarSwiftAgents  and mstt_Agents
---------------------------------------------------------------------------------------------------

insert into Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref
Select
  oa.OSCARAgentID,
  oa.OSCARAgentPrefix,
  oa.OSCARAgentSerial,
  oa.OSCARAgentSuffix,
  case when oa.AgentType = 'B' then 'B' when (oa.AgentType = 'I' and a.AgentType in (52, 53, 54, 55)) then 'M' else 'S' end,
  oa.SwiftAgentID,
  NULL ,
  NULL ,
  NULL ,
  NULL ,
  NULL ,
  coalesce(oa.OSCARDateStarted, a.DateStarted, a.CDIStatusDate),
  NULL ,
  NULL ,
  getdate(),
  'Automatic',
  NULL ,
  NULL 
  
from msit_OscarSwiftAgents oa
inner join mstt_Agents a on a.Code = oa.SwiftAgentID

---------------------------------------------------------------------------------------------------
--- Next step is to load historical data.  Create temp table first for selected data on owhot_OSCARSwiftAgentXref
---------------------------------------------------------------------------------------------------
 

Select
  ID,
  OSCAR_ID,
  OSCAR_Prefix,
  OSCAR_Serial,
  OSCAR_Suffix,
  AgentLevel,
  AgentCode,
  StartDate,
  convert(varchar(1),NULL) as 'PREV_ROLE',
  convert(datetime,NULL) as 'ROLE_DATE'
into
 #AgentHistory
from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref
where AgentLevel in ('M','S') 


update #AgentHistory
set 
  PREV_ROLE = case when (select count(*) from mstt_AgentsHistory ah where ah.Code  = a.AgentCode and ah.AgentType in (3,4,5,43,45,51) and ah.Active = 0 and GivesAdvice = 'Y' ) > 0 then 'M' else NULL end,
  ROLE_DATE = (select MAX(ah.ValidToDate) from mstt_AgentsHistory ah where ah.Code  = a.AgentCode and ah.AgentType in (3,4,5,43,45,51) and ah.Active = 0)

from #AgentHistory a
where a.AgentLevel = 'M'

update #AgentHistory
set 
  PREV_ROLE = case when (select count(*) from mstt_AgentsHistory ah where ah.Code  = a.AgentCode and ah.AgentType in (52, 53, 54, 55) and ah.Active = 0) > 0 then 'S' else NULL end,
  ROLE_DATE = (select Max(ah.ValidToDate) from mstt_AgentsHistory ah where ah.Code  = a.AgentCode and ah.AgentType in (52, 53, 54, 55) and ah.Active = 0)

from #AgentHistory a
where a.AgentLevel = 'S'


delete from #AgentHistory where PREV_ROLE is NULL 
---------------------------------------------------------------------------------------------------
--- insert historical roles
---------------------------------------------------------------------------------------------------

insert into Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref
select
  a.OSCAR_ID,
  a.OSCAR_Prefix,
  a.OSCAR_Serial,
  a.OSCAR_Suffix,
  a.PREV_ROLE,
  a.AgentCode,
  NULL ,
  NULL ,
  NULL ,
  NULL ,
  NULL ,
  a.StartDate,
  a.ROLE_DATE ,
  NULL ,
  getdate(),
  'Automatic',
  NULL ,
  NULL 
from #AgentHistory a


---------------------------------------------------------------------------------------------------
--- update original record
---------------------------------------------------------------------------------------------------

update Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref
  set StartDate = DateAdd(day, 1, a.ROLE_DATE)
from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref x
inner join #AgentHistory a on a.ID = x.ID

drop table #AgentHistory 

---------------------------------------------------------------------------------------------------
--- update business details from history
---------------------------------------------------------------------------------------------------

Select
  ID,
  AgentCode,
  StartDate,
  convert(varchar(7),NULL) as 'DetailAgentCode',
  convert(datetime,NULL) as 'END_DATE'

into
 #AgentHistory1
from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref
where AgentLevel = 'S'

update #AgentHistory1
set 
  DetailAgentCode = (select top 1 DetailAgentCode from msit_AgentHierarchyHistory ah where ah.AgentCode  = a.AgentCode and ah.ParticipantType in (6,7,8,9) and ah.DefaultValue = 1 and ah.StartDate <= a.StartDate order by ah.StartDate desc),
  END_DATE = (select top 1 EndDate from msit_AgentHierarchyHistory ah where ah.AgentCode = a.AgentCode and ah.ParticipantType in (6,7,8,9) and ah.DefaultValue = 1 and ah.StartDate <= a.StartDate order by ah.StartDate desc)

from #AgentHistory1 a
 
update #AgentHistory1
set 
  DetailAgentCode = (select top 1 DetailAgentCode from msit_AgentHierarchyHistory ah where ah.AgentCode  = a.AgentCode and ah.ParticipantType in (6,7,8,9) and ah.DefaultValue = 1 and ah.StartDate >= a.StartDate order by ah.StartDate),
  END_DATE = (select top 1 EndDate from msit_AgentHierarchyHistory ah where ah.AgentCode = a.AgentCode and ah.ParticipantType in (6,7,8,9) and ah.DefaultValue = 1 and ah.StartDate >= a.StartDate order by ah.StartDate)

from #AgentHistory1 a
where a.Detailagentcode is null

delete from #AgentHistory1 where DetailAgentCode is NULL 

update Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref
  set BusinessCode = a.DetailAgentCode, 
      EndDate = a.END_DATE
from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref x
inner join #AgentHistory1 a on a.AgentCode = x.AgentCode
where x.AgentLevel = 'S'

-- Apply Business details 

select Agentcode,OSCAR_ID,OSCAR_Prefix,OSCAR_Serial,OSCAR_Suffix
into #BusCodes
from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref
where AgentLevel = 'B'

update Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref 
        set Business_OSCAR_ID = y.OSCAR_ID,
      Business_OSCAR_Prefix = y.OSCAR_Prefix,
      Business_OSCAR_Serial = y.OSCAR_Serial,
      Business_OSCAR_Suffix = y.OSCAR_Suffix
from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref x
inner join #Buscodes y on y.Agentcode = x.BusinessCode
where x.AgentLevel = 'S'

drop table #AgentHistory1 
drop table #BusCodes

-- Apply Business Ecodes from Oscar AgentInfo table

update Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref
set business_oscar_id = ai.host_id,
business_oscar_prefix = ai.host_prefix,
business_oscar_serial = ai.host_serial,
business_oscar_suffix = ai.host_suffix
from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref x
inner join msit_agentinfo ai on ai.main_serial = x.oscar_serial
inner join msit_oscarswiftagents oa on oa.oscaragentserial = ai.host_serial and oa.agenttype = 'B'
where x.agentlevel = 'S'
and x.business_oscar_serial <> ai.host_serial

update Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref
set BusinessCode = oa.swiftagentid
from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref x
inner join msit_oscarswiftagents oa on x.business_oscar_serial = oscaragentserial
where x.agentlevel = 'S'
and x.businesscode <> oa.swiftagentid
and oa.agenttype = 'B'

-- Apply Statr and End dates from Swift hierarchy

update Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref
set startdate = ahh.startdate,
    enddate = ahh.enddate
from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref x
inner join msit_agenthierarchyhistory ahh 
on ahh.agentcode = x.agentcode and ahh.detailagentcode = x.businesscode
where x.agentlevel = 'S'
and ahh.participanttype in (6,7,8,9)
and defaultvalue = 1


GO
/****** Object:  StoredProcedure [dbo].[owhop_EDIStatementTotals]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/********************************************************************************************
Program:	owhop_EDIStatementTotals

Author:		A Groves

Date:		06/06/2017

Purpose:	This proc was introduced when the Daily Scan DTS scripts were being decommissioned
			to enable a Logi report to report on the EDI Statement Totals in a performant
			manner. Previously the DTS script simply output to Excel this:
				Select * from owhov_EdiStatementTotals
			However, the above statement took over 8 minutes to run.

			Debbie Beattie has asked for all columns to be included in the Logi report which
			means no efficiency gains can be achieved by removing the join between the EDI 
			Header and Contents tables.
			
			So, for now, the original view will be used by this proc to populate a new table
			called owhot_EDIStatementTotals in overnight processing.
			
			If needed, additional indexes can be added to table owhot_EDIStatementTotals to 
			achieve the required level of Logi performance.

			This stored proc should be called as follows:
			
			exec dbo.owhop_EDIStatementTotals 'Openwork', 'Daily Scans'
			
AMENDMENT HISTORY
=================

Date		Author			Description
----		------			-----------

*********************************************************************************************/
CREATE PROCEDURE [dbo].[owhop_EDIStatementTotals]
	@Client		varchar(50),
	@Module		varchar(50)
AS

SET ANSI_WARNINGS OFF	
set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@CreateDateTime				datetime

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @PhaseLog		= 'LOG'
set @PhaseError		= 'ERROR'
set @Process		= object_name(@@procid)
set @CreateDateTime	= getdate()

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION

	/****************************************************************************

		Populate the dbo.owhot_EDIStatementTotals table

	****************************************************************************/

	truncate table dbo.owhot_EDIStatementTotals
	
	insert into dbo.owhot_EDIStatementTotals
	(
		Statement,
		FileDate,
		FileName,
		DateLoaded,
		Provider,
		PolicyCount,
		PaymentCount,
		TotalPayment,
		UnmatchedSuspenseCount,
		UnmatchedSuspenseAmount,
		MatchedSuspenseCount,
		MatchedSuspenseAmount,
		DateInserted
	)
	select	Statement,
			FileDate,
			FileName,
			DateLoaded,
			Provider,
			PolicyCount,
			PaymentCount,
			TotalPayment,
			UnmatchedSuspenseCount,
			UnmatchedSuspenseAmount,
			MatchedSuspenseCount,
			MatchedSuspenseAmount,
			@CreateDateTime as DateInserted
	from	dbo.owhov_EdiStatementTotals

	set @RowCount = @@rowcount
	
	set @ProcessMessage = 'Table Insert. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/
GO
