CREATE                PROCEDURE [dbo].[owhop_getEcodeList]

@agentlevel varchar(10),
@String1 varchar(20)

        
        
AS
--########################################################################
--
-- Object  : procedure
-- Name    : owhop_getEcodeList
-- Owner   : ???
-- Created : ???????
-- Amended : PR 27/08/2009 Amend Index hint to use SQL 2005 method
--########################################################################

begin
declare @String2 varchar(20)
if @String1 = '' begin
  set @String1 = '%'
        set @String2 = '%'
end else begin
 set @String2 = '%' +@String1 + '%'
end


select 
ec.ID
,ec.Agentcode as UID
,mAg.DESCN as Name
,convert(varchar(10),ec.StartDate, 103)as StartDate
,convert(varchar(10),ec.EndDate, 103) as EndDate
,ec.oscar_prefix + ec.oscar_serial + ec.oscar_suffix as ECode

,case when ec.agentlevel ='S' and ec.EndDate <> null then 'Yes' else ''end as PFAtransfer
,mCl.NI_Number as Nino 

--,ec.AgentLevel as Level
,case ec.AgentLevel when 'S' then 'Sel' when 'B' then 'Bus' when 'M' then 'Mgr' end as Level
,ec.BusinessCode
,convert(varchar(10),ec.CreateDate,103) as Createdon
,ec.NoEcode
--,U1.Description as Createdby
,case ec.Createdby when 'Automatic' then 'Automatic' else U1.Description end as Createdby
,convert(varchar(10),ec.DateUpdated,103) as DateUpdated
,U.Description as Updatedby
--,ec.Updatedby
,case when ec.Agentlevel = 'S' then coalesce(Ag1.TradingName, Ag1.DESCN) end as BusinessName --else coalesce(mAg.TradingName, mAg.DESCN) end as BusinessName
--,(ec.Business_OSCAR_Prefix + ec.Business_OSCAR_Serial + ec.Business_OSCAR_Suffix) as BusinessEcode
,case when ec.Agentlevel = 'S' then (Ag1.OSCARAgentPrefix + Ag1.OSCARAgentSerial + Ag1.OSCARAgentSuffix) end as BusinessEcode--else (mAg.OSCARAgentPrefix + mAg.OSCARAgentSerial + mAg.OSCARAgentSuffix) end as BusinessEcode
,case when ec.Agentlevel = 'S' then Ag1.AgentTypeDescription end as BusinessType--else mAg.AgentTypeDescription end as BusinessType

from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref ec
left outer join mstt_Agents mAg on mAg.code = ec.agentcode
left outer join mstt_Agents Ag1 on Ag1.code = ec.businesscode

--left outer join mstt_Clients mCl (index=client1) on mCl.Refer = ec.agentcode and  mCl.Client_Typ = 4 
left outer join mstt_Clients mCl with (index(client1)) on mCl.Refer = ec.agentcode and  mCl.Client_Typ = 4   -- PR use SQL 2005 method for index hint
--inner join mstt_Clients mCl (index=client1) on mCl.Refer = ec.agentcode and mCl.Client_Typ = 4
left outer join msit_IntUsers U on U.Name = ec.Updatedby
left outer join msit_IntUsers U1 on U1.Name = ec.Createdby
--check mCl.Client_Typ = 4 and if row missing
where  (ec.AgentLevel = @agentlevel or @agentlevel = '%')
 --and ((mAg.DESCN = @String1 + '%') or (mAg.TradingName = @String1 + '%') or ((ec.oscar_prefix + ec.oscar_serial + ec.oscar_suffix) = @String1 + '%') or ((mAg.OSCARAgentPrefix + mAg.OSCARAgentSerial + mAg.OSCARAgentSuffix) = @String1 + '%') or (@String1 = '%'))
and ((mAg.DESCN Like @String2) or (mAg.TradingName Like @String2) or ((ec.oscar_prefix + ec.oscar_serial + ec.oscar_suffix) Like @String2 + '%') or ((mAg.OSCARAgentPrefix + mAg.OSCARAgentSerial + mAg.OSCARAgentSuffix) Like @String2) or (@String1 = '%'))
 
order by ec.Agentlevel, ec.Agentcode
end
























