CREATE PROCEDURE [dbo].[owhop_getMatchedOMSSanctions]
	@Processed as varchar(1)
as
--########################################################################
--
-- Object  : procedure
-- Name    : owhop_getMatchedOMSSanctions
-- Owner   : PR
-- Created : December 2009
-- Project : Openwork Head Office Systems - Sanctions List
--
-- The proc retrieves OMS sanction records that have been matched. If @Processed = 0 then only non processed
-- records retrieved else all selected
--########################################################################

begin
	declare @recordprocessed as bit
	set @recordprocessed = 0

	if @Processed = '%'
	begin
		set @recordprocessed = 1
	end
	
	select Client_Num, Refer, Client_Title,  Client_FirstName,Client_LastName,convert(varchar(10),Client_DOB,103) as Client_DOB, Name6,Name1, Title, DOB,GroupID,convert(varchar(10),FileCreated,103) as FileCreated, 
	Processed,convert(varchar(10),ProcessedDate,103) as ProcessedDate,Comment
	from Head_Office_Systems.dbo.owhot_SanctionsOMSMatched
	where Processed = @recordprocessed or @Processed = '%'
	order by Client_LastName,Client_FirstName,processed,processeddate desc
end

