CREATE            PROCEDURE [dbo].[owhop_getMissingEcodes]

@agentlevel varchar(10),
@String1 varchar(20)
        
AS
begin
declare @String2 varchar(20)
if @String1 = '' begin
  set @String1 = '%'
 set @String2 = '%'
end else begin
 set @String2 = '%' +@String1 + '%'
end

declare @missing table 
 (
 UID    varchar(7), 
 Name     varchar(255), 
 StartDate      varchar(10), 
 Level    varchar(10), 
 NINO     varchar(15), 
 PFATransfer  varchar(10), 
 BusinessUID  varchar(7), 
 BusinessName varchar(255), 
 BusinessEcode  varchar(10),
 BusinessType   varchar(50),
 Ecode          varchar(7),
 NoEcode        varchar(1),
 CreatedBy      varchar(50)

 )

--declare @agentlevel char(10) set @agentlevel = 'Manager' 'Seller' 'Business' ''


if (@agentlevel = 'Business' or @agentlevel = 'All')
begin
  insert into
    @missing 
  select 
     UID = a.Code,
       Name = a.DESCN,
     StartDate = convert(varchar(10),coalesce(a.OscarDateStarted,a.DateStarted),103),
     Level = 'Business',
     NINO = '',
     PFATransfer = '',
     BusinessUID = '',
     BusinessName = '',
     BusinessEcode = '',
     BusinessType = a.AgentTypeDescription,
           Ecode = '',
           NoEcode ='',
           CreatedBy=''
  
  from mstt_Agents a
  where a.Code not in (select AgentCode from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref where AgentLevel = 'B' )
        and a.AgentType in(2,46,47,49) and a.CompetentStatus in (1,2) and a.OSCARAgentSerial is NULL
            and ((a.DESCN Like @String2) or (a.TradingName Like @String2) or ((a.OSCARAgentPrefix + a.OSCARAgentSerial + a.OSCARAgentSuffix) Like @String2) or (@String1 = '%'))

end

if (@agentlevel = 'Manager' or @agentlevel = 'All')
begin
  insert into
    @missing 
  select 
     UID = a.Code,
       Name = a.DESCN,
     StartDate = convert(varchar(10),coalesce(a.OscarDateStarted,a.DateStarted),103),
     Level = 'Manager',
     NINO = isnull(c.NI_NUMBER,''),
     PFATransfer = '',
     BusinessUID = '',
     BusinessName = '',
     BusinessEcode = '',
     BusinessType = a.AgentTypeDescription,
           Ecode = '',
           NoEcode ='',
           CreatedBy=''
  
  from mstt_Agents a
  inner join mstt_Clients c on c.Refer = a.Code and c.Client_Typ = 4
  where a.Code not in (select AgentCode from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref where AgentLevel = 'M' )
      and a.AgentType in(52, 53, 54 ,55) and a.CompetentStatus in (1,2,3) and a.GivesAdvice = 'Y' and a.OSCARAgentSerial is NULL
            and ((a.DESCN Like @String2) or (a.TradingName Like @String2) or ((a.OSCARAgentPrefix + a.OSCARAgentSerial + a.OSCARAgentSuffix) Like @String2) or (@String1 = '%'))


end

if (@agentlevel = 'Seller' or @agentlevel = 'All')
begin
  insert into
    @missing
  select 
     UID = a.Code,
       Name = a.DESCN,
     StartDate = convert(varchar(10),coalesce(a.OscarDateStarted,a.DateStarted),103),
     Level = 'Seller',
     NINO = isnull(c.NI_NUMBER,''),
     PFATransfer = '',
     BusinessUID = a.Firm,
     BusinessName = isnull(b.TradingName,b.DESCN),
     BusinessEcode = b.OSCARAgentPrefix + b.OSCARAgentSerial + b.OSCARAgentSuffix,
     BusinessType = b.AgentTypeDescription,
           Ecode = '',
           NoEcode ='',
           CreatedBy=''
  
  from mstt_Agents a
  inner join mstt_Clients c on c.Refer = a.Code and c.Client_Typ = 4
  inner join mstt_Agents b on b.Code = a.Firm
  where a.Code not in (select AgentCode from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref where AgentLevel = 'S' )
          and a.AgentType in(3, 4, 5, 43, 45, 51) and a.CompetentStatus in (1,2,3) and a.GivesAdvice = 'Y' and a.OSCARAgentSerial is NULL
              and ((a.DESCN Like @String2) or (a.TradingName Like @String2) or ((a.OSCARAgentPrefix + a.OSCARAgentSerial + a.OSCARAgentSuffix) Like @String2) or (@String1 = '%'))

  select 
     a.Code as 'UID',
       a.DESCN as 'Name',
     c.NI_NUMBER as 'NINO',
     a.Firm as 'BusinessUID'
  
  into #missing2
    from mstt_Agents a
  inner join mstt_Clients c on c.Refer = a.Code and c.Client_Typ = 4
  inner join Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref x on x.AgentCode = a.Code and x.AgentLevel = 'S' and x.NoEcode is NULL 
  where a.AgentType in(3, 4, 5, 43, 45, 51) and a.CompetentStatus in (1,2,3) and a.GivesAdvice = 'Y' and a.OSCARAgentSerial is NULL
        and ((a.DESCN Like @String2) or (a.TradingName Like @String2) or ((a.OSCARAgentPrefix + a.OSCARAgentSerial + a.OSCARAgentSuffix) Like @String2) or (@String1 = '%'))
  group by a.Code,a.DESCN,c.NI_NUMBER,a.Firm


  insert into
    @missing
  select 
     UID = m.UID,
       Name = m.Name,
     StartDate = convert(varchar(10),DateAdd(dd,1,(select top 1 x.EndDate from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref x where x.AgentCode = m.UID and x.AgentLevel = 'S' and x.EndDate is not NULL order by x.EndDate DESC)),103),
     Level = 'Seller',
     NINO = isnull(m.NINO,''),
     PFATransfer = 'Yes',
     BusinessUID = m.BusinessUID ,
     BusinessName = isnull(a.TradingName,a.DESCN),
     BusinessEcode = a.OSCARAgentPrefix + a.OSCARAgentSerial + a.OSCARAgentSuffix,
     BusinessType = a.AgentTypeDescription,
           Ecode = '',
           NoEcode ='',
           CreatedBy=''
  
  from #missing2 m
  inner join mstt_Agents a on a.Code = m.BusinessUID
  where m.UID not in (select AgentCode from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref x where x.AgentLevel = 'S' and x.EndDate is NULL and (x.BusinessCode is NOT NULL and x.BusinessCode = m.BusinessUID))
--        and ((a.DESCN = @String1) or (a.TradingName = @String1) or ((a.OSCARAgentPrefix + a.OSCARAgentSerial + a.OSCARAgentSuffix) = @String1) or (@String1 = '%'))
  
  drop table #missing2
          
end

select 
  UID,
  Name,
  StartDate,
  Level,
  NINO,
  PFATransfer,
  BusinessUID,
  BusinessName,
  BusinessEcode,
  BusinessType,
        Ecode,
        NoEcode,
        CreatedBy

from @missing
order by level, UID

end













