/****** Object:  StoredProcedure [dbo].[owhop_getSuspenseList]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO









CREATE               PROCEDURE [dbo].[owhop_getSuspenseList]
   @statement as char(10)
  ,@period as char(2)
  ,@assignedTo as char(25)
  ,@status as char(75)
  ,@case as char(10)
  ,@policy as char(50)
  ,@team as varchar(15)
        ,@glbstmtnum as char(10)
        ,@agentuid as char(10)
        ,@agentbusuid as char(10)
        ,@unallocatedreasoncode as char(10)
        ,@DateFrom as datetime
        ,@DateTo as datetime
        
        
AS
begin


if @statement = ''  begin
  set @statement = '0'
end
if @assignedTo = ''  begin
  set @assignedTo = '%'
end
if @status = '' or @status = 'All' begin
  set @status = '%'
end
if @policy = ''  begin
  set @policy = '%'
end
if @case = ''  begin
  set @case = '0'
end

if @agentuid = ''  begin
  set @agentuid = '%'
end
if @agentbusuid = ''  begin
  set @agentbusuid = '%'
end
if @unallocatedreasoncode = ''  begin
  set @unallocatedreasoncode = '%'
end
if @glbstmtnum = ''  begin
  set @glbstmtnum = '0'
end

declare @From char(1)    set @From = '1'
declare @To char(1)    set @To = '1'


select @From = ISDATE(@DateFrom)
select @To = ISDATE(@DateTo)




if @DateFrom = '01/01/1900' begin
   set @From = '0'
 end 


if @DateTo = '01/01/1900' begin
   set @To = '0'
 end 

--select @pteam = isNumeric(@team)
--if @provider = '2' and @team = '2' begin
 --set @provider ='TALA'
 --end else begin
 -- if @provider ='3' and @team ='2' begin
   -- set @provider ='NON TALA'
   -- end else begin
    --set @provider ='%'
  --  end
--end

declare @periodstartdate datetime
set @periodstartdate = (select max(periodstartdate) from msit_commissionstatementperiods
      where dateadd(dd,-1,getdate()) >= periodstartdate)

create table #matches (statement int)
if @period ='1' begin
  insert into #Matches (statement)
--  select distinct statementID
        select distinct py.statement
--  from msit_edifactcommissionstatementheader sh
        from msit_s_stmtct py
--        from owhot_paymentAudit pya
--  left outer join owhot_edi_statement_exclude ese on ese.statement = sh.statementID
        left outer join Head_Office_Systems.dbo.owhot_edi_statement_exclude ese on ese.statement = py.statement
        where py.stmnt_Date >= @periodstartdate
--      where pya.DateRec >= @periodstartdate
--  where sh.dateProcessed >= @periodstartdate
  and (py.statement = @statement or @statement = '0')
  and ese.statement is null
          and   (-- do the team test
              
    (@team = '0') -- all teams
    or --  mortgage ( non of those specified below
    (@team = '1' and py.comp_code not in  ('ZURICH','ZURICH LEG','ZURICH NEW','SCOT E','SCOT EQ','SIML','STERLING') )
    or --  zurich All
    (@team = '2' and py.comp_code in  ('ZURICH','ZURICH LEG','ZURICH NEW') )
                or -- zurich Tala
                (@team = '3' and py.comp_code in  ('ZURICH','ZURICH LEG','ZURICH NEW'))
                or -- zurich Non Tala
                (@team = '4' and py.comp_code in  ('ZURICH','ZURICH LEG','ZURICH NEW'))
    or --  scot eq
    (@team = '5' and py.comp_code in  ('SCOT E','SCOT EQ') )
    or -- siml / sterling
    (@team = '6' and py.comp_code in  ('SIML','STERLING') )
                or
             --  (@pteam = 0 and pya.provider = @team) 
               (py.comp_code = @team)                    
  )
end else begin
 if @period ='2' begin
  insert into #Matches (statement)
--  select distinct statementID
        select distinct py.statement
        from msit_s_stmtct py
--- from msit_edifactcommissionstatementheader sh
        --from owhot_paymentAudit pya
--  left outer join owhot_edi_statement_exclude ese on ese.statement = sh.statementID and ese.type=1
        left outer join Head_Office_Systems.dbo.owhot_edi_statement_exclude ese on ese.statement = py.statement and ese.type=1
--  where sh.dateProcessed < @periodstartdate
--        where pya.DateRec < @periodstartdate
        where py.stmnt_Date < @periodstartdate
  and (py.statement = @statement or @statement = '0')
  and ese.statement is null
  and   (-- do the team test
              
    (@team = '0') -- all teams
    or --  mortgage ( non of those specified below
    (@team = '1' and py.comp_code not in  ('ZURICH','ZURICH LEG','ZURICH NEW','SCOT E','SCOT EQ','SIML','STERLING') )
    or --  zurich All
    (@team = '2' and py.comp_code in  ('ZURICH','ZURICH LEG','ZURICH NEW') )
                or -- zurich Tala
                (@team = '3' and py.comp_code in  ('ZURICH','ZURICH LEG','ZURICH NEW'))
                or -- zurich Non Tala
                (@team = '4' and py.comp_code in  ('ZURICH','ZURICH LEG','ZURICH NEW'))
    or --  scot eq
    (@team = '5' and py.comp_code in  ('SCOT E','SCOT EQ') )
    or -- siml / sterling
    (@team = '6' and py.comp_code in  ('SIML','STERLING') )
                or
             --  (@pteam = 0 and pya.provider = @team) 
               (py.comp_code = @team)                    
  )
  end else begin
        insert into #Matches (statement)
--  select distinct statementID
        select distinct py.statement
  --from msit_edifactcommissionstatementheader sh
       from msit_s_stmtct py
        left outer join Head_Office_Systems.dbo.owhot_edi_statement_exclude ese on ese.statement = py.statement
  where 

        py.statement = @statement or @statement = '0'
  and ese.statement is null
  and   (-- do the team test
              
    (@team = '0') -- all teams
    or --  mortgage ( non of those specified below
    (@team = '1' and py.comp_code not in  ('ZURICH','ZURICH LEG','ZURICH NEW','SCOT E','SCOT EQ','SIML','STERLING') )
    or --  zurich All
    (@team = '2' and py.comp_code in  ('ZURICH','ZURICH LEG','ZURICH NEW') )
                or -- zurich Tala
                (@team = '3' and py.comp_code in  ('ZURICH','ZURICH LEG','ZURICH NEW'))
                or -- zurich Non Tala
                (@team = '4' and py.comp_code in  ('ZURICH','ZURICH LEG','ZURICH NEW'))
    or --  scot eq
    (@team = '5' and py.comp_code in  ('SCOT E','SCOT EQ') )
    or -- siml / sterling
    (@team = '6' and py.comp_code in  ('SIML','STERLING') )
                or
             --  (@pteam = 0 and pya.provider = @team) 
               (py.comp_code = @team)                    
  )

  end
end

CREATE  INDEX [temp1] ON [#matches]([statement])


select top 500

susp.*

,pya.statement
,pya.provider
--,pya.StatementCreateDate as StateDate --? check with mike
,pya.DateRec as StateDate

,a1.descn as AgentName
,coalesce(pa.servicingagentcode,pa.sellingagentcode) as AgentUID
,a1.firm as AgentBusUID
,a2.descn as AgentBusName

,pya.ediclient as Client
,pya.policynumber as EDIPolicy
,pya.CaseID
,pya.EDIPremium
,pya.EDIpayFreq as Freq
,pya.EDIAmount
,pya.unallocreasoncode as uReasonCode
,pya.EDIReason
,pya.unallocreasondesc as ReasonDesc
,pya.EDIAgentCode as EDIAgentCode
,st.Notes as StatementNotes

from owhot_paymentAudit pya
--from paymentAuditView pya
inner join #matches t2 on pya.statement = t2.statement
inner join Head_Office_Systems.dbo.owhot_suspense susp on susp.pacc_ID = pya.expID
left outer join msit_s_STMTCT st on st.statement = pya.statement
left outer join msit_policyagentsb30 pa on pa.policyid = pya.policyid
left outer join msit_s_agents a1 on a1.code = coalesce(pa.sellingagentcode,pa.servicingagentcode)
left outer join msit_s_agents a2 on a2.code = a1.firm
left outer join msit_S_POLMAI pol on pol.pol_num = pya.policyid
where     (susp.allocatedTo = @assignedTo or @assignedTo = '%')
  and (susp.status = @status or @status = '%')
   and  (pya.CaseID = @case or @case = '0')
    and (pya.policynumber = @policy or @policy = '%')

   and  ((@From = 1 and pya.daterec >= @DateFrom) or (@From = 0 and pya.daterec < dateadd(year,10,getdate())))
   and  ((@To = 1 and pya.daterec <= @DateTo) or (@To = 0 and pya.daterec < dateadd(year,10,getdate())))



and (pya.unallocreasoncode = @unallocatedreasoncode or @unallocatedreasoncode = '%')
and (pa.servicingagentcode = @agentuid or pa.sellingagentcode = @agentuid or @agentuid = '%')
and     (susp.glbstmtnum = @glbstmtnum or @glbstmtnum = '0')
and     (a1.firm = @agentbusuid or @agentbusuid = '%') 
and     (-- sort tala
  (@team = '3' and pol.productcode = 'TALA')
  or (@team = '4' and pol.productcode not in  ('TALA','NON TALA'))
  or @team not in ('3','4')
  ) 


---Validation for suspense extraction records
and     (
        (pya.StatementType='EDI' and pya.Matchcategory='In Suspense')
         or
        (pya.statementType='EDI' and pya.Matchcategory Like 'Match%' and pya.Matchdate >= dateadd(dd,-44,getdate())) 
        or

        (pya.statementtype = 'manual' and pya.provider = 'scot eq' and pya.matchcategory like 'In%')
        or
        (pya.statementType='Manual' and pya.Provider='Scot Eq' and pya.Matchcategory Like 'Match%' and pya.Matchdate >= dateadd(dd,-44,getdate())) 
        )
 
---End End extraction validation records

order by susp.pacc_id
drop table #matches
end
















