CREATE procedure [dbo].[owhop_HeadOfficeScheduledRun]

with recompile
as

--########################################################################
--
-- Object  : procedure
-- Name    : owhop_HeadOfficeScheduledRun
-- Owner   : MAC
-- Created : 09 Oct 2007
-- Project : Openwork Head Office Systems - Suspense Work Allocation Tool Table population
--                                          

-- Set up Process Log parameters

declare 
 @PhaseStart     varchar(50),
 @PhaseEnd       varchar(50),
 @Client         varchar(50),
 @Module         varchar(50),
 @Process        varchar(100)

set @PhaseStart              = 'START'
set @PhaseEnd                = 'END'
set @Client                         = 'suspense'
set @Module                    = 'owhop_HeadOfficeScheduledRun'
set @Process     = 'owhop_PaymentAuditExtract'


exec msp_ProcessLog @PhaseStart,@Process, null, @Module, @Client
exec owhop_PaymentAuditExtract
exec msp_ProcessLog @PhaseEnd,@Process, null, @Module, @Client

set @Process     = 'owhop_suspense_add'

exec msp_ProcessLog @PhaseStart,@Process, null, @Module, @Client
exec owhop_suspense_add
exec msp_ProcessLog @PhaseEnd,@Process, null, @Module, @Client
