/****** Object:  StoredProcedure [dbo].[owhop_ICOBDailySales]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE    PROCEDURE [dbo].[owhop_ICOBDailySales]
AS

/*
AMENDMENTS
==========
1.  Mike Cawood   21/09/2009    SR10 - new OBP OriginatingSource codes.
                  Include ETi and OBP non-Manual cases. 
                  OTPm cases excluded as regulation is MCOB. 
*/

Truncate table Head_Office_Systems.dbo.owhot_ICOBDailySales

insert into Head_Office_Systems.dbo.owhot_ICOBDailySales
Select distinct po.cont_num AS PolicyNumber
      , po.policyref AS CaseID
      , (convert(varchar, pt.transactiondate, 102)) AS PolicyTransactionDate
     -- , pt.transactiondate AS PolicyTransactionDate
      ,     ag1.code as ASDCode
      ,     ag1.descn as ASDName
      ,     ag2.code as RSMCode
      ,     ag2.descn as RSMName
      ,     cbip.productcode as ProductCode
      ,     cbip.productname as ProductName
      ,     (convert(varchar, po.createdate, 102)) AS PolicyCreateDate
--      ,     po.createdate AS PolicyCreateDate
      ,     pt.TransTypeDesc
      ,     (convert(varchar, pt.TransactionDate, 102)) AS TransactionDate
 --     ,     pt.TransactionDate AS TransactionDate
      ,     pt.AgentCode AS AdviceByAgent
      ,     ag.descn as AdviceByName
      ,     pt.TransactionNumber
      ,     (convert(varchar, pt.CreateDateTime, 102)) AS CreateDateTime
--      ,     pt.CreateDateTime AS CreateDateTime

From dbo.mstt_PolicyTransactions pt
      inner join dbo.mstt_Policies po
            on pt.policyid = po.Pol_Num
      left outer join dbo.mstt_agents ag
            on pt.AgentCode = ag.Code
      left outer join dbo.mstt_agents ag1 
            on po.SalesQualityASDLevelCode = ag1.Code
      left outer join dbo.mstt_agents ag2
            on po.SalesQualityRSMLevelCode = ag2.Code
      left outer join dbo.mstt_CodeBIProducts cbip
            on pt.CommProductCode = cbip.ProductCode
      left outer join dbo.mstt_AgentsHistory ah
            on ah.code = pt.agentcode
    left outer join msit_CodeOriginatingSources OS    --SR10 :MPC 21/09/2009
      on OS.ID = po.OriginatingSource         --SR10 :MPC 21/09/2009
where 
--      po.originatingsource = '2'    --SR10 :MPC 21/09/2009
      isnull(OS.CODE,'Unknown') not like '%MAN%'      --Exclude Manual Cases SR10 :MPC 21/09/2009
      and po.salesprocess = '1'
      and po.regulation like 'ICOB%'
      and ah.agentcategory not like 'Nasp%'
      and (pt.transactiondate >= convert(Varchar, Getdate() -1, 101) 
--      and (pt.transactiondate >= convert(Varchar, Getdate() -20, 101) 
      and pt.transactiondate < convert(Varchar,Getdate(), 101))
      and (pt.transactionnumber = '1')


GO
