/****** Object:  StoredProcedure [dbo].[owhop_ManualSuspense]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************************
AMENDMENTS
==========
Date		Author		Description
----		------		-----------
21/09/2009	Mike Cawood	SR10 - new OBP OriginatingSource codes. Source now holds Code from Swift Code table. 
						Column on results table amended to varchar(6).
02/08/2016	A Groves	1) SR442681. A PRU and a NATWEST policy have the same external policy number
							(cont_num=81817898). However, although payments were received for the PRU 
							policy, it was never submitted by the adviser, so only the NATWEST policy 
							exists on Swift. The duplicates have caused this proc to merge details of the
							two policies. This has been fixed by including the provider code where cont_num
							is used. PolicyID and POL_NUM should not need the provider code as these are
							auto-generated by Swift and so should never duplicate. 
						   Note that the join to #DupPol deliberately excludes the provider code. This
						    is assumed to be by design and has therefore been left as is.
						2) Indexes added to address performance issues found during testing.
						3) With recompile removed on DBA recommendation (Daniel Lunnon).
16/06/2017	Alan Groves	SR464996. This change relates to the removal of the DTS daily scans where theis proc 
							is now run in a job step instead of DTS "ow_daily_scans_main".
							This change introduces logging via "msp_ProcessLog". Values are hardcoded, as 
							parameters not passed into this proc to maintain compatibility with the DTS call 
							during the cutover period.		
**********************************************************************************************************/
CREATE PROCEDURE [dbo].[owhop_ManualSuspense] 

as

set nocount on

--AG 16/06/2017 Start	
declare		@RowCount		int,
			@Process		varchar(100),
			@ProcessMessage	varchar(100),
			@PhaseStart		varchar(50),
			@PhaseEnd		varchar(50),
			@PhaseLog		varchar(50),
			@Client			varchar(50),
			@Module			varchar(50)

set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @PhaseLog		= 'LOG'			
set @Process		= object_name(@@procid)
set @Client			= 'Openwork'
set @Module			= 'Daily Scans'

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client
--AG 16/06/2017 End

if exists (select * from dbo.sysobjects where id = object_id(N'[dbo].[owhot_ManualSuspense]') and OBJECTPROPERTY(id, N'IsUserTable') = 1)
drop table [dbo].[owhot_ManualSuspense]

set nocount on
-----------------------------
-- Manual Suspense List
-----------------------------

select distinct policyid 
into #IssuedPols
from mstt_policytransactions
where id in (select distinct transactionid from mstt_expectation where status in (2,3))
order by policyid

create index idx_IssuedPols_PolicyID on #IssuedPols (PolicyID)	-- AG 02/08/2016

select cont_num as Policy
into #DupPol
from mstt_policies
where cont_num is not null and len(cont_num) > 0
group by cont_num having count(*) > 1
order by 1

create index idx_DupPol_Policy on #DupPol (Policy)	-- AG 02/08/2016

select distinct
ex.ID as ID,case when t4.policy is not null then 'Yes' end as DupCase,
coalesce(un.Policy,ex.providerref) as EDIPolicy,
ED.initials as EDInits,
un.Client as EDISurname,
ed.PremiumType as EDIPremTyp,ed.PremiumAmount as EDIPremium,
ex.amount_rec as EDIAmount,
case 
when ex.amount_rec < 0 then 'Negative'
when ex.amount_rec >= 0 and ex.amount_rec < 10 then 'Less Than 10'
when ex.amount_rec >= 10 and ex.amount_rec < 100 then 'Less Than 100' 
when ex.amount_rec >= 100 and ex.amount_rec < 500 then 'Less Than 500'
when ex.amount_rec >= 500 and ex.amount_rec < 1000 then 'Less Than 1000'
when ex.amount_rec >= 1000 then 'More Than 1000'
end as ValueBand,
ex.date_due as EDIDueDate,
ex.date_recv as EDIRecDate,
case datepart(mm,ex.Date_recv)
when 01 then 'JAN' when 02 then 'FEB' when 03 then 'MAR' when 04 then 'APR' when 05 then 'MAY' when 06 then 'JUN'
when 07 then 'JUL' when 08 then 'AUG' when 09 then 'SEP' when 10 then 'OCT' when 11 then 'NOV' when 12 then 'DEC'
end as EDIRecMonth,
coalesce(pa.servicingagentcode,un.agent_code) as EDIAgent,p.policyref as EDICaseID,
case ed.paymentfrequency 
when 'X' then 'Sin' when 'M' then 'Mth' when 'A' then 'Ann' when 'S' then 'Sin'
--else 'Unk'
end as EDIPayFreq,
case ed.paymenttype 
when 1 then 'Comm' when 4 then 'Claw' when 99 then 'Adj'
--else 'Unk'
end as EDIPayType,
--ed.transactionid as EDITxn,

st.statement as Statement,st.stmnt_date as StateDate,
case st.state when 1 then 'Unproc' when 2 then 'Proc' end as Process,
st.comp_code as Provider,

ex.unallocatedreasoncode as Unalloc, 
--ex.amount_rec as SuspAmount,ex.date_recv as SuspDate,
--ex.type as SuspType,ex.status as Status,ex.adjust as Adj,

p.policyref as CaseID,p.cont_num as ExtPolNo,p.productcode as Product,
coalesce(p.createdate,p.prop_date) as CreatedDate,
case
when coalesce(p.createdate,p.prop_date) is not null then 'Loaded'
end as OnSwift,
--p.client_num as Client1,p.joint_num as Client2

case p.replacement 
when 1 then 'RepA' when 2 then 'RepB' when 3 then 'RepC'
end as Repl,

ISNULL(OS.CODE,'Unknown') as [Source],    --SR10 :MPC 21/09/2009
--case p.originatingsource          --SR10 :MPC 21/09/2009
--when 1 then 'Man' when 2 then 'ETi' when 3 then 'OTPm' when 4 then 'OTPc' else 'Unk' end as Source, --SR10 :MPC 21/09/2009

coalesce(pa.servicingagentcode,pa.sellingagentcode) as AgentUID,
a1.descn as AgentName,
case
when pa.sellingagentcode is null and pa.servicingagentcode is not null then 'Serv'
when pa.servicingagentcode is null and pa.sellingagentcode is not null then 'Sell'
when pa.sellingagentcode is not null and pa.servicingagentcode is not null
and pa.sellingagentcode = pa.servicingagentcode then 'Sell'
when pa.sellingagentcode is not null and pa.servicingagentcode is not null
and pa.sellingagentcode <> pa.servicingagentcode then 'Serv'
end as AgentRole,
a1.firm as AgentBusUID,
coalesce (a2.tradingname,a2.descn) as AgentBusName,
a2.manager2code as RSMUID,a3.descn as RSMName,
a2.manager4code as ASDUID,a4.descn as ASDName

,case when p.pol_num is not null and t1.policyid is not null then 'Issued'
when p.pol_num is not null and t1.policyid is null then 'Not Issued' 
else 'No Policy' end as PolicyStatus

,case when ex.amount_rec < 0 then 'Accrual Clawback'
when ed.CommissionType = 'Y' then 'Initial Indemnity'
when ed.CommissionType = 'I' then 'Initial Accrual'
when ed.CommissionType = 'R' then 'Renewal'
when ed.CommissionType = 'X' then 'Trail'
when ed.PaymentType = '04' then 'Clawback'
Else 'Unknown' end as EDIPaymentType,
ed.CommissionType as EDICommType

into owhot_ManualSuspense

FROM mstt_Expectation ex  
left outer JOIN msit_s_paccun un on un.pacc_id = ex.id
left outer JOIN msit_EDIFACTCommissionStatementContents ed ON ed.Pacc_ID = ex.ID 
left outer join msit_s_STMTCT st on st.statement = ex.statement
left outer join msit_EDIFACTCommissionStatementHeader edh on edh.statementid = st.statement
left outer join mstt_policies p on p.cont_num = coalesce(un.Policy,ex.providerref) and p.COMP_CODE = ex.COMP_CODE	-- AG 02/08/2016
left outer join msit_policyagentsb30 pa on pa.policyid = p.pol_num
left outer join #issuedpols t1 on t1.policyid = p.pol_num
left outer join #DupPol t4 on t4.policy = p.cont_num
left outer join msit_s_agents a1 on a1.code = coalesce(pa.servicingagentcode,pa.sellingagentcode)
left outer join msit_s_agents a2 on a2.code = a1.firm
left outer join msit_s_agents a3 on a3.code = a2.manager2code
left outer join msit_s_agents a4 on a4.code = a2.manager4code
left outer join msit_CodeOriginatingSources OS on OS.ID = p.OriginatingSource   --SR10 :MPC 21/09/2009

where ex.TYPE IN (5, 6) AND ex.init_ID is null and ed.id is NULL

ORDER BY ex.ID

--AG 16/06/2017 Start	
set @RowCount = @@rowcount
	
set @ProcessMessage = 'Table Insert. Number of rows = ' + convert(varchar(20),@RowCount)	
exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client
--AG 16/06/2017 End

drop table #issuedpols
drop table #duppol




GO
/****** Object:  StoredProcedure [dbo].[owhop_ManualSuspense_History]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/********************************************************************************************
Program:	owhop_ManualSuspense_History

Author:		A Groves

Date:		14/06/2017

Purpose:	This proc was introduced when the Daily Scan DTS scripts were being decommissioned.
			Its purpose is to build up history of the Manual Suspense List which previously
			was available via the scans from previous days.

			This stored proc should be called as follows:
			
			exec dbo.owhop_ManualSuspense_History 'Openwork', 'Daily Scans'
			
AMENDMENT HISTORY
=================

Date		Author			Description
----		------			-----------

*********************************************************************************************/
CREATE PROCEDURE [dbo].[owhop_ManualSuspense_History]
	@Client		varchar(50),
	@Module		varchar(50)
AS

SET ANSI_WARNINGS OFF	
set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@CreateDateTime				datetime

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @PhaseLog		= 'LOG'
set @PhaseError		= 'ERROR'
set @Process		= object_name(@@procid)
set @CreateDateTime	= getdate()

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION

	/****************************************************************************

		Remove data older than the retention period.

	****************************************************************************/

	delete from dbo.owhot_ManualSuspense_History
	where ReportDate < dateadd(dd,-95,getdate())
	
	set @RowCount = @@rowcount
	
	set @ProcessMessage = 'Delete Past Retention Period. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

	/****************************************************************************

		Remove any data loaded today to make this proc re-runnable.

	****************************************************************************/

	delete from dbo.owhot_ManualSuspense_History
	where ReportDate = dateadd(dd,0,datediff(dd,0,getdate()))
	
	set @RowCount = @@rowcount
	
	set @ProcessMessage = 'Delete Today''s Data. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

	/****************************************************************************

		Populate the dbo.owhot_ManualSuspense_History table.

	****************************************************************************/

	insert into dbo.owhot_ManualSuspense_History
	(
		EDIContentsID,
		DupCase,
		EDIPolicy,
		EDInits,
		EDISurname,
		EDIPremTyp,
		EDIPremium,
		EDIAmount,
		ValueBand,
		EDIDueDate,
		EDIRecDate,
		EDIRecMonth,
		EDIAgent,
		EDICaseID,
		EDIPayFreq,
		EDIPayType,
		Statement,
		StateDate,
		Process,
		Provider,
		Unalloc,
		CaseID,
		ExtPolNo,
		Product,
		CreatedDate,
		OnSwift,
		Repl,
		Source,
		AgentUID,
		AgentName,
		AgentRole,
		AgentBusUID,
		AgentBusName,
		RSMUID,
		RSMName,
		ASDUID,
		ASDName,
		PolicyStatus,
		EDIPaymentType,
		EDICommType,
		ReportDate,
		DateInserted
	)
	select	ID,
			DupCase,
			EDIPolicy,
			EDInits,
			EDISurname,
			EDIPremTyp,
			EDIPremium,
			EDIAmount,
			ValueBand,
			EDIDueDate,
			EDIRecDate,
			EDIRecMonth,
			EDIAgent,
			EDICaseID,
			EDIPayFreq,
			EDIPayType,
			Statement,
			StateDate,
			Process,
			Provider,
			Unalloc,
			CaseID,
			ExtPolNo,
			Product,
			CreatedDate,
			OnSwift,
			Repl,
			Source,
			AgentUID,
			AgentName,
			AgentRole,
			AgentBusUID,
			AgentBusName,
			RSMUID,
			RSMName,
			ASDUID,
			ASDName,
			PolicyStatus,
			EDIPaymentType,
			EDICommType,
			@CreateDateTime as ReportDate,
			@CreateDateTime as DateInserted
	from	dbo.owhot_ManualSuspense

	set @RowCount = @@rowcount
	
	set @ProcessMessage = 'Table Insert. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/
GO
