CREATE                                   procedure [dbo].[owhop_MissingEcodeAdd]
 @UID as char(7) 
,@Ecode as char(7)
,@NoEcode as char(1)
,@level as char(20)
,@BusinessUID as char(7) 
,@BusinessEcode as char(7) 
,@StartDate as datetime
,@CreatedBy as char(50)



AS
BEGIN

declare @Agentlevel char(1) set @Agentlevel = case @level when 'Business' then  'B'  when 'Seller' then 'S' 
when 'Manager' then 'M' end

SET NOCOUNT ON;

if @ecode <> '' begin
declare @code char(7)
select @code = main_serial from msit_AgentInfo where substring(@ecode,2,5) = main_serial and main_prefix = left(@ecode, 1) and main_suffix = right(@ecode, 1)
  if @@rowcount =0 begin
    raiserror('Ecode %s not Valid',16,1,@Ecode)
    return
  end else begin
if (@ecode <> '' and @noecode = 'z') begin
     set @noecode = null-- ''

--Rule For Sellers the Ecode must be populated for its Business before its own Ecode can be input
  if(@Agentlevel ='S' and @BusinessEcode is null) begin
  raiserror('Cannot input Seller Ecode until Ecode defined for Business',16,1,@BusinessEcode)
  return
  end
--ends


declare @codeX char(7)

--select @codeX = agentcode from owhot_OSCARSwiftAgentXref where substring(@ecode,2,5) = Oscar_Serial and Agentlevel = @Agentlevel 
--new changes 21/11/2007 validation 3.1
select @codeX = agentcode from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref where substring(@ecode,2,5) = Oscar_Serial and agentlevel = 'S' and AgentCode <> @UID 
   if (@codeX <> '' and @Agentlevel ='S') begin
                set @codeX = case @codeX when 'S' then 'Seller' end 
    raiserror('Ecode already linked to Seller',16,1,@codeX)
    return
            end else begin


            --new changes 21/11/2007 validation 3.2
             declare @codeX1 char(8)
             select @codeX1 = Agentlevel from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref where substring(@ecode,2,5) = Oscar_Serial and (Agentlevel <> 'S') and (AgentCode <> @UID) 
             if (@codeX1 <> '' and @Agentlevel<>'S') begin
                set @codeX1 = case @codeX1 when 'B' then 'Business' when 'M' then 'Manager' end
    raiserror('Ecode already linked to %s',16,1,@codeX1)
    return
              --End new
    end


              
           -- Oscar as Swift as difened on the msit_AgentInfo display error
          declare @hserial char(7)                    
          select @hserial = host_serial from msit_AgentInfo where host_serial = substring(@BusinessEcode,2,5) AND main_serial = substring(@Ecode,2,5)--substring(@BusinessEcode2,2,5)
            if (@@rowcount =0 and @Agentlevel ='S') begin
               raiserror('Ecode not linked to current Business  ',16,1,@hserial)
      return
             end else begin
                
       declare @oscar_code char(7)
       select @oscar_code = agent_id from msit_AgentInfo where substring(@ecode,2,5) = main_serial

--Take business ecode from screen
       declare @Business_OSCAR_ID char(7)
       select @Business_OSCAR_ID = AGENT_ID from msit_AgentInfo where main_serial =  substring(@BusinessEcode,2,5)


     insert into Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref
       (
        OSCAR_Prefix,
        OSCAR_Serial,
        OSCAR_Suffix,
        AgentLevel,
        AgentCode,
        Business_OSCAR_ID,
        Business_OSCAR_Prefix,
        Business_OSCAR_Serial,
        Business_OSCAR_Suffix,
        BusinessCode,
        StartDate,
        NoEcode,
        CreateDate,
        CreatedBy,
        OSCAR_ID
         )
        Values(
        left(@Ecode, 1),
        substring(@Ecode,2,5),
        right(@Ecode, 1),
        @Agentlevel,
        @UID,
        @Business_OSCAR_ID,
        left(@BusinessEcode, 1),
        substring(@BusinessEcode,2,5),
        right(@BusinessEcode, 1),
        @BusinessUID,
        @StartDate,
        @NoEcode,
        getdate(),
        @CreatedBy,
        @oscar_code
       );
       SELECT SCOPE_IDENTITY() AS [SCOPE_IDENTITY]




----Update record back on Mstt_Agents with correct Business Ecode from Screen
--if(@Agentlevel ='S') begin
   Update mstt_Agents
   set OscarAgentID = @oscar_code 
   ,OscarAgentPrefix = left(@ecode, 1)
   ,OscarAgentSerial = substring(@ecode,2,5)
   ,OscarAgentSuffix = right(@ecode, 1)

   where code = @UID
--end
--End Update of Mstt_Agents

  end
    end

  end else begin
      raiserror('Ecode cannot be input if No Code is Yes',16,1,@Ecode)
      return
   end
end
--@ecode =''
end else begin
    if @NoEcode = 'z' begin
      raiserror('Sorry... No input found %s ',16,1,@Ecode)
      return
    end else begin

       declare @oscar_code2 char(7)
       select @oscar_code2 = agent_id from msit_AgentInfo where substring(@ecode,2,5) = main_serial

       --Take business ecode from screen
       declare @Business_OSCAR_ID2 char(7)
       select @Business_OSCAR_ID2 = AGENT_ID from msit_AgentInfo where main_serial =  substring(@BusinessEcode,2,5)

      insert into Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref
       (OSCAR_ID,
        OSCAR_Prefix,
        OSCAR_Serial,
        OSCAR_Suffix,
        AgentLevel,
        AgentCode,
        Business_OSCAR_ID,
        Business_OSCAR_Prefix,
        Business_OSCAR_Serial,
        Business_OSCAR_Suffix,
        BusinessCode,
        StartDate,
        NoEcode,
        CreateDate,
        CreatedBy
        )
        Values(
        @oscar_code2,
        left(@Ecode, 1),
        substring(@Ecode,2,5),
        right(@Ecode, 1),
        @Agentlevel,
        @UID,
        @Business_OSCAR_ID2,
        left(@BusinessEcode, 1),
        substring(@BusinessEcode,2,5),
        right(@BusinessEcode, 1),
        @BusinessUID,
        @StartDate,
        @NoEcode,
        getdate(),
        @CreatedBy
   );
       SELECT SCOPE_IDENTITY() AS [SCOPE_IDENTITY]





----Update record back on Mstt_Agents with correct Business Ecode from Screen
--if(@Agentlevel ='S') begin
   Update mstt_Agents
   set OscarAgentID = @oscar_code2
   ,OscarAgentPrefix = left(@ecode, 1)
   ,OscarAgentSerial = substring(@ecode,2,5)
   ,OscarAgentSuffix = right(@ecode, 1)
   where code = @UID
--end
--End Update of Mstt_Agents

end
end


END







