/****** Object:  StoredProcedure [dbo].[owhop_MPLChargeBusinessSummaryforMonth]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE procedure [dbo].[owhop_MPLChargeBusinessSummaryforMonth]
    @Month datetime    = '1 Jan 1900'

with recompile
as

--########################################################################
--
-- Object  : procedure
-- Name    : owhop_MPLChargeBusinessSummaryforMonth.sql
-- Owner   : MPC
-- Created : 2 April 2007
-- Project : Openwork Head Office Systems - Charges Application 
--
-- Procedure called by MPL Charge Business Summary For Month Report. 
-- Called with one paramter:
--
-- @Month
-- Determines Commission Period for which data to be updated. 
-- Extracts data from owhot_MPLCharges for month supplied.
-- 
--########################################################################

-- Access MPL Charges Table and find Prevailing Charge.
select max(Month) as ChargeMonth 
into #ChargeMonth 
from owhot_OpenworkCharges 
where Month <= @Month

select ChargeMonth,UpdatedBy,DateUpdated,MPLCharge,MPLThreshold,@Month as RunMonth
into #MPLCharge
from owhot_OpenworkCharges 
inner join #ChargeMonth on Month = ChargeMonth

Select  MPL.BusinessCode,
  AG.DESCN as BusinessName,
  MPL.Month,
  MPL.MPLCharge,
  CH.MPLThreshold,
  MPL.Total_Turnover,
  MPL.SWIFT_Turnover,
  MPL.TPF_Turnover,
  MPL.OSCAR_Turnover,
  MPL.ProdAdjustments,
  MPL.CompAdjustments,
  MPL.LastUpdated,
  MPL.UpdatedBy,
  IU.Description,
  MPL.ChargeEffDate,
  MPL.ChargeCalcDate
From owhot_MPLCharges MPL
inner join mstt_Agents AG on AG.Code = MPL.BusinessCode
left outer join #MPLCharge CH on CH.RunMonth = MPL.Month
left outer join msit_intusers IU on IU.Name = MPL.UpdatedBy
where MPL.Month = @Month
Order by MPL.BusinessCode

drop table #ChargeMonth
drop table #MPLCharge


GO
/****** Object:  StoredProcedure [dbo].[owhop_MPLChargebyMonthforBusiness]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE procedure [dbo].[owhop_MPLChargebyMonthforBusiness]
    @Business   varchar(7)   = NULL

with recompile
as

--########################################################################
--
-- Object  : procedure
-- Name    : owhop_MPLChargebyMonthforBusiness.sql
-- Owner   : MPC
-- Created : 2 April 2007
-- Project : Openwork Head Office Systems - Charges Application 
--
-- Procedure called by MPL Charge Business Summary Report. 
-- Called with one paramter:
--
-- @Business
-- Determines Business for which MPL Charge details to be extracted.
-- 
--########################################################################

-- Access MPL Charges Table and find Prevailing Charge.
select distinct Month, '1 Jan 1900' as ChargeMonth
into #Months 
from owhot_MPLCharges 
order by Month

select T1.Month,max(CH.Month) as ChargeMonth 
into #ChargeMonth 
from #Months T1,owhot_OpenworkCharges CH
where CH.Month <= T1.Month
group by T1.Month
order by T1.Month

select T1.Month,T1.ChargeMonth,UpdatedBy,DateUpdated,MPLCharge,MPLThreshold
into #MPLCharge 
from #ChargeMonth T1   
inner join owhot_OpenworkCharges CH on T1.ChargeMonth = CH.Month

-- Extract MPL Charge details for Business

Select  MPL.BusinessCode,
  AG.DESCN as BusinessName,
  MPL.Month,
  MPL.MPLCharge,
  T1.MPLThreshold,
  MPL.Total_Turnover,
  MPL.SWIFT_Turnover,
  MPL.TPF_Turnover,
  MPL.OSCAR_Turnover,
  MPL.ProdAdjustments,
  MPL.CompAdjustments,
  MPL.LastUpdated,
  MPL.UpdatedBy,
  IU.Description,
  MPL.ChargeEffDate,
  MPL.ChargeCalcDate
From owhot_MPLCharges MPL
inner join mstt_Agents AG on AG.Code = MPL.BusinessCode
inner join #MPLCharge T1 on T1.Month = MPL.Month
left outer join msit_intusers IU on IU.Name = MPL.UpdatedBy
where MPL.BusinessCode = @Business
Order by MPL.BusinessCode,MPL.Month Desc

drop table #Months
drop table #ChargeMonth
drop table #MPLCharge


GO
/****** Object:  StoredProcedure [dbo].[owhop_MPLChargeLetterTriggerExtract]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

/****************************************************************************
  	 Program:  	owhop_MPLChargeLetterTriggerExtract					
	  Author:	Unknown
Date created:	Unknown (maybe 2007?)							
											
Description:	This proc is executed by the BI Batch to automatically create
				the Letters file to advise the Practice Principal of their  
				MPL Charge.
			
	Amendment History								
	-----------------								
											
	Date		Who			Description				
	----		---			-----------			
	17/03/2011	A Groves	Derive the BDD and AD from Insight data (as requested
							by Maggie Courts of PSD).  Previously, the BQM was
							selected which became wrong when the Swift hierarchy 
							was updated on 31/01/2011 and the Swift Manager 2 
							Panel name was no longer reliably the same as the BQM.	
	21/03/2011	A Groves	Use f_CleanText to ensure no spurious commas in
							the address lines because this stops the mail
							merge from working correctly.
****************************************************************************/
CREATE procedure [dbo].[owhop_MPLChargeLetterTriggerExtract]

with recompile
as

--########################################################################
--
-- Procedure generates one paramter:
--
-- @Month
-- Determines Commission Period for which data to be extracted. 
-- Extracts data from owhot_MPLCharges for latest month.
-- 
--########################################################################

set nocount on

declare @Month datetime
set @Month = (select max(Month) from owhot_MPLCharges)

declare @LastMonth datetime
set @LastMonth = dateadd(mm,-1,@Month)

-- Access MPL Charges Table and find Prevailing Charge.
select max(Month) as ChargeMonth 
into #ChargeMonth 
from owhot_OpenworkCharges 
where Month <= @Month

select ChargeMonth,UpdatedBy,DateUpdated,MPLCharge,MPLThreshold,@Month as RunMonth
into #MPLCharge
from owhot_OpenworkCharges 
inner join #ChargeMonth on Month = ChargeMonth

-- Extract Trigger Details
delete dbo.owhot_MPLChargeLetterTriggers;

select BusinessCode,Month
into #LastMonth
from owhot_MPLCharges
where Month = @LastMonth and MPLCharge > 0
order by BusinessCode

insert into owhot_MPLChargeLetterTriggers 
(
	BusinessCode,
	Confidentiality,
	BusinessAddressee,
	BusinessName,
	BusinessAddress1,
	BusinessAddress2,
	BusinessAddress3,
	BusinessAddress4,
	BusinessAddress5,
	BusinessPostcode,
	MPLCharge,
	MPLThreshold,
	BusinessTurnover,
	Month,
	BDDCode,
	BDDName,
	ADCode,
	ADName
)
Select  MPL.BusinessCode ,
		'Strictly Private and Confidential' ,
		'FAO Practice Principal' ,
		AG.DESCN ,
		dbo.owf_CleanText(AG.Address1),
		dbo.owf_CleanText(AG.Address2),
		dbo.owf_CleanText(AG.Address3),
		dbo.owf_CleanText(AG.Address4),
		dbo.owf_CleanText(AG.Address5),
		dbo.owf_CleanText(AG.Postcode),
		cast(MPL.MPLCharge as decimal(15,2)) ,
		cast(CH.MPLThreshold as decimal(15,2)) ,
		cast(MPL.Total_Turnover as decimal(15,2)) ,
		MPL.Month,
		BH.BDD_UID,
		BH.BDD_Name,
		BH.AD_UID,
		BH.AD_Name
From	owhot_MPLCharges MPL
		inner join mstt_Agents AG on AG.Code = MPL.BusinessCode
		left outer join f_Insight_GetBusinessSalesHierarchy() BH on BH.BusinessUID = MPL.BusinessCode
		left outer join #MPLCharge CH on CH.RunMonth = MPL.Month
where	MPL.Month = @Month 
and		MPL.MPLCharge > 0
and		MPL.BusinessCode not in (select BusinessCode from #LastMonth)

drop table #ChargeMonth
drop table #MPLCharge
drop table #LastMonth

GO
/****** Object:  StoredProcedure [dbo].[owhop_MPLCharges_GetDetails]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[owhop_MPLCharges_GetDetails]
@BusinessCode AS Varchar(7),
@Month AS Datetime

AS

SET @Month = COALESCE(@Month, (SELECT MAX([Month]) FROM owhot_MPLCharges))

DECLARE @MPLTreshold as int
SELECT top 1 @MPLTreshold = MPLThreshold FROM owhot_OpenworkCharges WHERE [Month] <= @Month
order by [Month] Desc

SELECT  ag.DESCN as BusinessName,
  @MPLTreshold AS MPLThreshold,
  coalesce(users.[Description],mpl.UpdatedBy) As UpdatedByName,
  mpl.*
FROM owhot_MPLCharges mpl INNER JOIN mstt_Agents ag
    ON mpl.BusinessCode = ag.Code LEFT OUTER JOIN msit_intusers users
    ON users.[Name] = mpl.UpdatedBy
WHERE BusinessCode like '%' + COALESCE(@BusinessCode, BusinessCode) + '%' 
AND mpl.[Month] = @Month
AND mpl.MPLCharge IS NOT NULL AND mpl.MPLCharge <> 0
ORDER BY BusinessCode



GO
