CREATE PROCEDURE [dbo].[owhop_MPLCharges_GetPeriod]
AS

SELECT DISTINCT(mpl.[Month]),
       csp.MonthName
FROM owhot_MPLCharges mpl INNER JOIN msit_CommissionStatementPeriods csp
ON mpl.[Month] = csp.[Month]
ORDER BY mpl.[Month] DESC

GO
/****** Object:  StoredProcedure [dbo].[owhop_MPLCharges_GetPeriodDetails]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

create  PROCEDURE [dbo].[owhop_MPLCharges_GetPeriodDetails]
@SMonth AS Datetime
,@EMonth AS Datetime
AS

SET @EMonth = COALESCE(@EMonth, (SELECT MAX([Month]) FROM owhot_MPLCharges))
SET @SMonth = COALESCE(@SMonth, @EMonth)

select distinct Month, '1 Jan 1900' as MPLMonth
into #Months 
from owhot_MPLCharges

select T1.Month,max(CH.Month) as MPLMonth 
into #ChargeMonth 
from #Months T1,owhot_OpenworkCharges CH
where CH.Month <= T1.Month
group by T1.Month
order by T1.Month

select T1.Month,T1.MPLMonth,MPLThreshold
into #MPLCharge
from #ChargeMonth T1   
inner join owhot_OpenworkCharges CH on T1.MPLMonth = CH.Month


SELECT  coalesce(ag.TradingName, ag.Descn) as BusinessName,
  T2.MPLThreshold,
  coalesce(users.[Description],mpl.UpdatedBy) As UpdatedByName,
  mpl.*
  ,csp.MonthName as Period
FROM owhot_MPLCharges mpl 
INNER JOIN #MPLCharge T2 on mpl.month = T2.month
inner join msit_commissionStatementPeriods csp on csp.month = mpl.month
INNER JOIN mstt_Agents ag ON mpl.BusinessCode = ag.Code 
LEFT OUTER JOIN msit_intusers users ON users.[Name] = mpl.UpdatedBy
WHERE  mpl.[Month] >= @SMonth
and mpl.[Month] <= @EMonth
AND mpl.MPLCharge IS NOT NULL AND mpl.MPLCharge <> 0
ORDER BY BusinessCode,mpl.[Month]


drop table #Months
drop table #ChargeMonth
drop table #MPLCharge


GO
/****** Object:  StoredProcedure [dbo].[owhop_MPLChargesCalculation]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[owhop_MPLChargesCalculation]
    @RecalcFlag  varchar(1)  = 'N',
    @RecalcMonth datetime    = '1 Jan 1900',
--    @RecalcMonth datetime    = '1 Sep 2008',
    @UpdatedBy   varchar(10) = 'Automatic'
with recompile
as

/*########################################################################

 Object  : procedure
 Name    : owhop_MPLChargesCalculation.sql
 Owner   : MPC
 Created : 2 April 2007
 Project : Openwork Head Office Systems - Charges Application 

 Procedure operates with three parameters:

 @RecalcFlag 
 Has three settings:

 'Y' : this recalculates the MPL Charges for the Recalc Commission Statement period supplied.
 When called from the Charge Admin page this is set to lastest month on the MPL table.
 This is the only setting used from the Charge Admin page. 
 Deletes and reinserts entries on owhot_MPLCharges for the Recalc Period only.

 'N' : used for Ad Hoc back population of previous periods. 
 Deletes and reinserts entries on owhot_MPLCharges for the Recalc Period only.

 'B' : used when procedure is run in Warehouse daily batch schedule
 Defaults to latest closed Commission Month.
 On first day when procedure detects a new closed Commission period for which data is not present
 then insers data into owhot_MPLCharges table for the Recalc Period only.
 
 @RecalcMonth
 Determines Commission Period for which data to be updated.
 If not set to first of month then procedure defaults to last closed Commission Period.
 Defaulted to getdate when procedure is run in Warehouse daily batch schedule
 Cannot be later than last closed Commission Period or earlier than '1 Feb 2007' (Jan 2007)

 @UpdatedBy
 Denotes the Portal Id (without Domain) of user requesting run. Defaults to 'Automatic'.

 Amendment History
 -----------------

 Date		Author		Description
 ----------	----------- -------------------------------------------------
 09/02/2011	A Groves	Since the business agreed to Anne Harrison no longer
						loading transition data, the MPL calculation is now
						under-counting APE resulting in a MPL charge being 
						incorrectly calculated.  This change is to remove 
						transition from the calculation and introduce missing
						data from the Adviser Listing which currently includes
						OMS and Paymentshield.
						All Adviser Listing turnover grabbed by one select
						statement and the two charges updates now combined
						as one statement.
01/03/2011	A Groves	Removed Name, Status and Type and Order By from initial 
						selections (#OAL, #PRodAdj, #CompAdj) as pulled in by 
						#Turnover.
02/03/2011	A Groves	Combined production and league adjustments into one
						temporary table as done with the #OAL temp table
						to improve simplicity and reduce the amount of coding. 
29/02/2016	A Groves	SR420882 - Remove Owl businesses which are not subject 
						to MPL charges.	
28/03/2017	A Groves	SR464996/CH16204. Replace DTS scripts with start of job 
						that contains SSIS replacement scripts: 
						1) "MPLChargeStandingOrderTriggerExtract.dtsx"
						2) "MPLChargeLetterTriggerExtract.dtsx"
########################################################################*/

declare @OwlManager2Code varchar(7)					-- AG 29/02/2016

select  @OwlManager2Code = cde.Code					-- AG 29/02/2016
from	msit_MIWarehouseCodesAndDescriptions cde	
where	cde.ColumnName = 'Manager2Code' 
and		cde.Description = 'Owl Financial'

-- DEFINE RUN DATES
declare @RunDateTime datetime
set @RunDateTime = getdate()

declare @Yesterday datetime
set @yesterday = CAST(CONVERT(NVARCHAR,dateadd(dd,-1,getdate()),112) as datetime)

declare @LastClosedMonth datetime
set @LastClosedMonth = (select max(Month) from msit_CommissionStatementPeriods where PeriodEndDate <= @yesterday)

declare @LastChargeMonth datetime
set @LastChargeMonth = (select isnull(max(Month),'1 Jan 1901')  from owhot_MPLCharges) 

-- Default End month to last closed Commission Month
declare @EndMonth datetime
Set @EndMonth = @LastClosedMonth

-- Override default End Month with Recalc Month if valid
IF @RecalcMonth < @LastClosedMonth  -- Recalc Date cannnot be later than last closed period
and @RecalcMonth > '1 Jan 2007'   -- Recalc Date cannot efer to a Commission Period earlier then 2007
and datepart(dd,@RecalcMonth) = 1 -- Recalc Date must be dated first of month
and @RecalcFlag <> 'B'      -- Do not reset for Batch run
BEGIN
	Set @EndMonth = (Select Month from msit_CommissionStatementPeriods where @RecalcMonth = Month)
END


-- EXTRACT DATA for Last 12 Closed Months 
declare @StartMonth datetime
set @StartMonth = dateadd(mm,-11,@EndMonth)

declare @OscarStartDate datetime
set @OscarStartDate = (select OSCARStartDate from msit_CommissionStatementPeriods where Month = @StartMonth)

declare @OscarEndDate datetime
set @OscarEndDate = (select OSCAREndDate from msit_CommissionStatementPeriods where Month = @EndMonth)

declare @SWIFTStartDate datetime
set @SWIFTStartDate = (select PeriodStartDate from msit_CommissionStatementPeriods where Month = @StartMonth)

declare @SWIFTEndDate datetime
set @SWIFTEndDate = (select PeriodEndDate from msit_CommissionStatementPeriods where Month = @EndMonth)


-- Extract Turnover Data into MPL Charges Table for Run Month and preceding 11 months
-- Start of Update processing

IF @RecalcFlag = 'N' OR (@RecalcFlag = 'B' AND @LastChargeMonth < @EndMonth)
BEGIN

	exec msp_ProcessLog 'START', 'Calculating MPL Charge', null, 'Head Office', 'Openwork'

	-- Clear down existing data for the Month to be Loaded
	DELETE from owhot_MPLCharges where Month = @EndMonth


	-- Extract Production & League Adjustments
	select	pa.agentcode as BusinessUID,
			convert(decimal(15,2),sum(case when pa.ProductionFlag = 'Y' then isnull(pa.Turnover,0) else 0 end)) as ProductionAdj,
			convert(decimal(15,2),sum(case when pa.ProductionFlag <> 'Y' then isnull(pa.Turnover,0) else 0 end)) as LeagueAdj
	into	#Adj
	from	mstt_ProductionAdjustments pa
			inner join mstt_agents ag on ag.code = pa.agentcode
			inner join msdt_calendartime ct on ct.dateid = pa.dateissuedid
	where	ag.agenttype in (2)						-- Franchises
	and		ag.competentstatus in (1)				-- Active
	and		ag.Manager2Code <> @OwlManager2Code		-- AG 29/02/2016
	and		ct.datetime between @OscarStartDate and @SwiftEndDate
	group	by pa.agentcode


	select	OAL.BusinessCode as BusinessUID,
			convert(decimal(15,2),sum(case when OAL.source = 'Openwork 2006' then isnull(APE,0) else 0 end)) as SwiftTurnover,
			convert(decimal(15,2),sum(case when OAL.source = 'Openwork 2005' then isnull(APE,0) else 0 end)) as OscarTurnover,
			convert(decimal(15,2),sum(case when OAL.source not in ('Openwork 2006','Openwork 2005') then isnull(APE,0) else 0 end)) as TPFTurnover	-- i.e. OMS and Payshield
	into	#OAL
	from	msit_OpenworkAdviserListing OAL
			inner join mstt_agents ag on ag.code = OAL.BusinessCode
	where	OAL.Month between @StartMonth and @EndMonth
	and		ag.AgentType in (2)						-- Enterprises only - Access Agents and Directly Authorised don't have MPL in their contracts
	and		ag.CompetentStatus in (1)				-- Active only
	and		ag.Manager2Code <> @OwlManager2Code		-- AG 29/02/2016
	group	by OAL.BusinessCode


	-- Prepare Overall Totals
	select	ag.code as BusinessUID,
			coalesce(ag.TradingName,ag.DESCN) as BusinessName,
			'Active' as Status,
			ag.agenttypedescription as Type,
			@StartMonth as FromMonth,
			@LastClosedMonth as ToMonth,
			@rundatetime as LastUpdated,
			isnull(OAL.SwiftTurnover,0) as SwiftTurnover,
			isnull(OAL.OscarTurnover,0) as OscarTurnover,
			isnull(OAL.TPFTurnover,0) as TPFTurnover,
			isnull(ADJ.ProductionAdj,0) as Adjustments,
			isnull(ADJ.LeagueAdj,0) as CompAdjust,
			(isnull(OAL.SwiftTurnover,0) + isnull(OAL.OscarTurnover,0) + isnull(OAL.TPFTurnover,0) 
				+ isnull(ADJ.ProductionAdj,0)+ isnull(ADJ.LeagueAdj,0)) as TotalTurnover
	into	#Turnover
	from	mstt_agents ag 
			left outer join #OAL OAL on OAL.businessuid = ag.code
			left outer join #Adj ADJ on ADJ.businessuid = ag.code
	where	ag.agenttype in (2)						-- Enterprises only - Access Agents and Directly Authorised don't have MPL in their contracts
	and		ag.competentstatus in (1)				-- Active
	and		ag.Manager2Code <> @OwlManager2Code		-- AG 29/02/2016


	-- Insert Turnover data into Table
	INSERT into owhot_MPLCharges
	(
	 BusinessCode,
	 Month,
	 LastUpdated,
	 UpdatedBy,
	 Total_Turnover,
	 Swift_Turnover,
	 TPF_Turnover,
	 Oscar_Turnover,
	 ProdAdjustments,
	 CompAdjustments,
	 MPLCharge,
	 ChargeEffDate,
	 ChargeCalcDate
	)
	select	BusinessUID,
			@EndMonth,
			@RunDateTime,
			@UpdatedBy,
			TotalTurnover,
			SWIFTTurnover,
			TPFTurnover,
			OSCARTurnover,
			Adjustments,
			CompAdjust,
			NULL,
			NULL,
			NULL
	from	#Turnover

	drop table #OAL
	drop table #Adj
	drop table #Turnover

	exec msp_ProcessLog 'END', 'Calculating MPL Charge', null, 'Head Office', 'Openwork'

END

-- END of Update Processing

-- Access MPL Charges Table and find Prevailing Charge.
select	max(Month) as ChargeMonth 
into	#ChargeMonth 
from	owhot_OpenworkCharges 
where	Month <= @EndMonth

select	ChargeMonth,
		UpdatedBy,
		DateUpdated,
		MPLCharge,
		MPLThreshold,
		@EndMonth as RunMonth
into	#MPLCharge
from	owhot_OpenworkCharges 
		inner join #ChargeMonth on Month = ChargeMonth

-- If no valid Charge present then exit Calculation processing

IF (Select Count(*) from #MPLCharge) > 0 
AND (@RecalcFlag <> 'B' OR (@RecalcFlag = 'B' AND @LastChargeMonth < @EndMonth))
BEGIN

	-- Derive Franchise Agent Details from Agent History table as at end of Commission Period
	select	Code,
			max(ValidFromDate) as EffDate
	into	#AgentDate
	from	mstt_AgentsHistory
	where	AgentType = 2 
	and		Manager2Code <> @OwlManager2Code		-- AG 29/02/2016
	and		ValidFromDate <= @SwiftEndDate
	Group	by Code
	Order	by Code

	select	AGH.Code,
			AGH.AgentType,
			AGH.CompetentStatus,
			AGH.DateStarted,
			AGH.ValidFromDate
	into	#Agents
	from	mstt_AgentsHistory AGH
			inner join #AgentDate 
				on #AgentDate.Code = AGH.Code 
				and #AgentDate.EffDate = AGH.ValidFromDate
	order	by AGH.Code

	-- MPL Charges derived for active Franchises trading for at least 15 months from the end of the MPL period
	update	owhot_MPLCharges
		set		UpdatedBy		= @UpdatedBy,
				LastUpdated		= @RunDatetime,
				MPLCharge		= (case when MPL.Total_Turnover < #MPLCharge.MPLThreshold then #MPLCharge.MPLCharge else 0.00 end),
				ChargeEffDate	= #MPLCharge.ChargeMonth,
				ChargeCalcDate  = @RunDateTime
	from	owhot_MPLCharges MPL
			inner join #MPLCharge on #MPLCharge.RunMonth = MPL.Month
			inner join #Agents AG on AG.Code = MPL.BusinessCode
	where	MPL.Month = @EndMonth
	and		AG.CompetentStatus = 1
	and		AG.DateStarted < dateadd(mm,-15,@swiftenddate)


	drop table #ChargeMonth
	drop table #AgentDate
	drop table #Agents
	drop table #MPLCharge

END

-- End of charges processing

-- Create MPL Trigger files

IF (@EndMonth = @LastClosedMonth AND @RecalcFlag <> 'B') 
OR (@RecalcFlag = 'B' AND @LastChargeMonth < @EndMonth)
BEGIN

	exec owhop_MPLChargeStandingOrderDataProcessing
	--AG 28/03/2017 Start
	--exec mscp-run-dts-package 'owdts_mplchargestandingordertriggerextract'
	update dbo.owt_JobControl
		set JobStartRequired = 1,
			DateLastUpdatedByCaller = GETDATE()
	where JobCode = 'MPL-CHARGE-STD-ORDS'

	declare @JobName varchar(300)
	select	@JobName = JobName
	from	dbo.owt_JobControl
	where	JobCode = 'MPL-CHARGE-STD-ORDS'

	if dbo.owf_JobStillRunning(@JobName) = 0
		exec msdb.dbo.sp_start_job @JobName
	--AG 28/03/2017 End

	/******************************************************/
	
	exec owhop_MPLChargeLetterTriggerExtract
	
	--AG 28/03/2017 Start
	--exec mscp-run-dts-package 'owdts_mplchargelettertriggerextract'
	update dbo.owt_JobControl
		set JobStartRequired = 1,
			DateLastUpdatedByCaller = GETDATE()
	where JobCode = 'MPL-CHARGE-LETTERS'

	select	@JobName = JobName
	from	dbo.owt_JobControl
	where	JobCode = 'MPL-CHARGE-LETTERS'

	if dbo.owf_JobStillRunning(@JobName) = 0
		exec msdb.dbo.sp_start_job @JobName
	--AG 28/03/2017 End

END

-- End of Trigger processing
GO
