CREATE procedure [dbo].[owhop_MPLChargeStandingOrderExtract]


with recompile
as

--########################################################################
--
-- Object  : procedure
-- Name    : owhop_MPLChargesStandingOrderExtract.sql
-- Owner   : MPC
-- Created : 26 April 2007
-- Project : Openwork Head Office Systems - Charges Application 
--
-- Procedure operates with one parameter:
--
-- @Month
-- Determines Commission Period for which data to be updated. 
-- When procedure triggered by owhop_MPLChargesCalculation will be set to last closed Commission period.
-- Extracts data from owhot_MPLCharges for month.
-- 
-- 
--########################################################################

declare @Month datetime
set @Month = (select max(Month) from owhot_MPLCharges)

declare @Today datetime
set @Today = CAST(CONVERT(NVARCHAR,getdate(),112) as datetime)

declare @Enddate datetime
set @enddate = CAST(CONVERT(NVARCHAR,dateadd(dd,2,getdate()),112) as datetime)

/*
Select  '0000053' as StandingOrderCode,
  BusinessCode,
  CAST(CONVERT(NVARCHAR, @Today, 103) AS varchar(10)) as DueDate,
  CAST(CONVERT(NVARCHAR, @EndDate, 103) AS varchar(10)) as EndDate,
  cast( (-1*abs(MPLCharge)) as decimal(15,2)) as Amount,
  '6' as Frequency,
  Null as Description
From owhot_MPLCharges
where month = @Month
and MPLCharge > 0

*/
--new added 02/11/2009
Select  StandingOrderCode,
  BusinessCode,
  DueDate,
  EndDate,
  Amount,
  Frequency,
  Description
From Head_Office_Systems.dbo.MPLChargeStandingOrderTriggers


GO
/****** Object:  StoredProcedure [dbo].[owhop_MTG_SuspenseEDIList_all]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[owhop_MTG_SuspenseEDIList_all] AS

/*
AMENDMENTS
==========
1.  Alan Groves   30/09/2009    SR10 - new OBP OriginatingSource codes.
                  Source now holds Code from Swift Code table. 
                  Column on results table amended to varchar(6).
*/

set nocount on


if exists (select * from dbo.sysobjects where id = object_id(N'[dbo].[owhot_MTG_SuspenseEDIList_NODUPS]') and OBJECTPROPERTY(id, N'IsUserTable') = 1)
drop table [dbo].[owhot_MTG_SuspenseEDIList_NODUPS]

if exists (select * from dbo.sysobjects where id = object_id(N'[dbo].[owhot_MTG_SuspenseEDIList_withDUPS]') and OBJECTPROPERTY(id, N'IsUserTable') = 1)
drop table [dbo].[owhot_MTG_SuspenseEDIList_withDUPS]

    
/*    
select distinct policyid    
into #IssuedPols    
from mstt_policytransactions    
where id in (select distinct transactionid from mstt_expectation where status in (2,3))   
and productgroupcode = 3 -- mortgage    
order by policyid   
*/    
    
select distinct policyid    
into #PolTrans    
from mstt_policytransactions    
--where productgroupcode = 3    
    
select policyid, min(createdatetime) as Date    
into #PolProps    
from mstt_policytransactions    
where transtype = 39    
--and productgroupcode = 3    
group by policyid   
order by policyid   
    
select cont_num as Policy   
into #DupPol    
from mstt_policies    
where cont_num is not null and len(cont_num) > 0    
--and plan_code = 'mrtg'    
group by cont_num having count(*) > 1   
order by 1    
    
---------------------only for no dups------------------------------------   
select Policy,min(pol_num) as Pol_Num   
into #DupPolNum   
from mstt_policies po   
inner join #duppol t1 on t1.policy = po.cont_num    
group by t1.policy    
order by t1.policy    
---------------------only for no dups------------------------------------   
    
    
select pt.policyid,max(ex.id) as ExpID    
into #ActiveExp   
from mstt_Expectation ex    
inner join mstt_policytransactions pt on pt.id = ex.transactionid   
--where pt.productgroupcode = 3   
group by pt.policyid    
order by pt.policyid    
    
select t1.*,ex.Statement as ActiveStatement,ex.Date_Recv as ActiveDate,st.Notes as ActiveCompletionFile   
into #InitBreak   
from #ActiveExp t1    
inner join mstt_expectation ex on ex.id = t1.ExpID    
inner join msit_s_stmtct st on st.statement = ex.statement    
    

--------------------- no dups------------------------------------   
select DISTINCT   
ED.ID as ID,case when t4.policy is not null then 'Yes' end as DupPol,   
--ED.initials as EDInits,   
case when ed.Fullname is not null and len(ed.Fullname) > 0 then ed.FullName else ED.Surname end as EDIFullName,   
case when len(ed.memberreferencenumber) > 0 then ed.memberreferencenumber     
when len(ed.policynumber) > 0 then ed.policynumber end as EDIPolicy,    
--ed.PremiumType as EDIPremTyp,   
ed.PremiumAmount as EDIPremium,ed.amountreceived as EDIAmount,    
--case when ed.amountreceived < 0 then 'Negative'   
--when ed.amountreceived >= 0 and ed.amountreceived < 10 then 'Less Than 10'    
--when ed.amountreceived >= 10 and ed.amountreceived < 100 then 'Less Than 100'     
--when ed.amountreceived >= 100 and ed.amountreceived < 500 then 'Less Than 500'    
--when ed.amountreceived >= 500 and ed.amountreceived < 1000 then 'Less Than 1000'    
--when ed.amountreceived >= 1000 then 'More Than 1000' end as ValueBand,    
--ed.commissionduedate as EDIDueDate,ed.commissionreceiveddate as EDIRecDate,   
--case datepart(mm,ed.commissionreceiveddate)   
--when 01 then 'JAN' when 02 then 'FEB' when 03 then 'MAR' when 04 then 'APR' when 05 then 'MAY' when 06 then 'JUN'   
--when 07 then 'JUL' when 08 then 'AUG' when 09 then 'SEP' when 10 then 'OCT' when 11 then 'NOV' when 12 then 'DEC'   
--end as EDIRecMonth,   
ed.IFAReference as EDIAgent,ed.IFAReferenceNumber as EDICaseID,   
--case ed.paymentfrequency    
--when 'X' then 'Sin' when 'M' then 'Mth' when 'A' then 'Ann' when 'S' then 'Sin' else 'Unk' end as EDIPayFreq,   
--case ed.paymenttype when 1 then 'Comm' when 4 then 'Claw' when 99 then 'Adj' else 'Unk' end as EDIPayType,    
--ed.transactionid as EDITxn,   
    
st.statement as Statement,st.stmnt_date as StateDate,   
case st.state     
when 1 then 'Unproc'    
when 2 then 'Proc'    
end as Process,   
st.comp_code as Provider,   
    
ex.unallocatedreasoncode as Unalloc,    
--ex.amount_rec as SuspAmount,ex.date_recv as SuspDate,   
--ex.type as SuspType,ex.status as Status,ex.adjust as Adj,   
    
coalesce(p1.policyref,p2.policyref) as CaseID,coalesce(p1.cont_num,p2.cont_num) as ExtPolNo,    
--coalesce(p1.createdate,p2.createdate,p.prop_date) as CreatedDate,   
case when coalesce(p1.policyref,p2.policyref) is null and coalesce(p1.cont_num,p2.cont_num) is null   
and isnull(ed.ifareferencenumber,0) = 0 then 'Yes' else 'No' end as Invalid,    
coalesce(p1.productcode,p2.productcode,ed.productcode) as Product,    
    
ISNULL(OS.CODE,'Unknown') as [Source],    --SR10 :AG 30/09/2009
--case coalesce(p1.originatingsource,p2.originatingsource)                    --SR10 :AG 30/09/2009
--when 0 then 'Man' when 1 then 'ETi' when 2 then 'ETr' when 3 then 'MBL' when 4 then 'Tri'   --SR10 :AG 30/09/2009
--when 5 then 'CTP' when 6 then 'OTPc' else 'Unk' end as Source,                --SR10 :AG 30/09/2009   
coalesce(pa.servicingagentcode,pa.sellingagentcode) as AgentUID,    
    
a1.descn as AgentName,    
    
case when pa.sellingagentcode is null and pa.servicingagentcode is not null then 'Serv'   
when pa.servicingagentcode is null and pa.sellingagentcode is not null then 'Sell'    
when pa.sellingagentcode is not null and pa.servicingagentcode is not null    
and pa.sellingagentcode = pa.servicingagentcode then 'Sell'   
when pa.sellingagentcode is not null and pa.servicingagentcode is not null    
and pa.sellingagentcode <> pa.servicingagentcode then 'Serv'    
end as AgentRole,   
    
a1.firm as AgentBusUID,   
coalesce (a2.tradingname,a2.descn) as AgentBusName,   
a2.manager2code as RSMUID,a3.descn as RSMName,    
a2.manager4code as ASDUID,a4.descn as ASDName,    
    
st.Notes as SuspenseCompletionFile,   
    
case when t2.policyid is not null then 'Transaction'    
when t2.policyid is null and coalesce(p1.pol_num,p2.pol_num) is not null then 'Policy Only'     
else 'No Policy' end as PolicyState,    
    
t5.ActiveStatement,t5.ActiveDate,t5.ActiveCompletionFile,   
    
t3.date as PropCreateDate   
    
--case when ex.amount_rec < 0 then 'Accrual Clawback' when ed.CommissionType = 'Y' then 'Initial Indemnity'   
--when ed.CommissionType = 'I' then 'Initial Accrual' when ed.CommissionType = 'R' then 'Renewal'   
--when ed.CommissionType = 'X' then 'Trail' when ed.PaymentType = '04' then 'Clawback'    
--Else 'Unknown' end as EDIPaymentType    


INTO owhot_MTG_SuspenseEDIList_NODUPS   
FROM  msit_EDIFACTCommissionStatementContents ed    
INNER JOIN msit_S_PACC ex ON ed.Pacc_ID = ex.ID     
INNER JOIN msit_EDIFACTCommissionStatementHeader edh on edh.id = ed.statementheaderid   
INNER JOIN msit_s_STMTCT st on st.statement = edh.statementid   
INNER JOIN msit_codeprodproviderreportingxref ppx on ppx.productprovidercode = st.comp_code   
left outer JOIN msit_codeproducts cpr on cpr.code = ed.productcode    
left outer join mstt_policies p1 on p1.policyref = ed.ifareferencenumber    
left outer join mstt_policies p2    
on p2.cont_num = case when len(ed.memberreferencenumber) > 0 then ed.memberreferencenumber    
when len(ed.policynumber) > 0 then ed.policynumber end    
--left outer join msit_policyqualitycheckb30 q on q.policyid = coalesce(p1.pol_num,p2.pol_num)    
left outer join msit_policyagentsb30 pa on pa.policyid = coalesce(p1.pol_num,p2.pol_num)    
--left outer join #issuedpols t1 on t1.policyid = coalesce(p1.pol_num,p2.pol_num)   
left outer join #poltrans t2 on t2.policyid = coalesce(p1.pol_num,p2.pol_num)   
left outer join #polprops t3 on t3.policyid = coalesce(p1.pol_num,p2.pol_num)   
left outer join #DupPolNum t4 on t4.policy = coalesce(p1.cont_num,p2.cont_num)    
    
left outer join #InitBreak t5 on t5.policyid = coalesce(p1.pol_num,p2.pol_num)    
left outer join msit_s_agents a1 on a1.code = coalesce(pa.servicingagentcode,pa.sellingagentcode)   
left outer join msit_s_agents a2 on a2.code = a1.firm   
left outer join msit_s_agents a3 on a3.code = a2.manager2code   --Use Mortgage provider payments only
left outer join msit_s_agents a4 on a4.code = a2.manager4code   --Select Mortgage products if code recognised
left outer join msit_CodeOriginatingSources OS            --SR10 :AG 30/09/2009
on OS.ID = isnull(p1.OriginatingSource,p2.OriginatingSource)    --SR10 :AG 30/09/2009
    
where ex.TYPE IN (5, 6) AND ex.ID NOT IN (SELECT susp_id FROM msit_s_paccsu)    
and ppx.commrepproductprovidercode = 'mortgage'   
and (cpr.code is null or cpr.plancode = 'MRTG')   
--Dedup results by using first policy on DB or if duplicate policy but EDI case ID not the first pol_num    
and (t4.pol_num is null or t4.pol_num = coalesce(p1.pol_num,p2.pol_num)     
or (t4.pol_num is not null and t4.pol_num <> coalesce(p1.pol_num,p2.pol_num) and t4.policy = p1.cont_num))    
    
ORDER BY ed.ID    
--------------------- no dups------------------------------------   

--------------------- dups------------------------------------    

select DISTINCT
ED.ID as ID,case when t4.policy is not null then 'Yes' end as DupPol,
--ED.initials as EDInits,
case when ed.Fullname is not null and len(ed.Fullname) > 0 then ed.FullName else ED.Surname end as EDIFullName,
case when len(ed.memberreferencenumber) > 0 then ed.memberreferencenumber 
when len(ed.policynumber) > 0 then ed.policynumber end as EDIPolicy,
--ed.PremiumType as EDIPremTyp,
ed.PremiumAmount as EDIPremium,ed.amountreceived as EDIAmount,
--case when ed.amountreceived < 0 then 'Negative'
--when ed.amountreceived >= 0 and ed.amountreceived < 10 then 'Less Than 10'
--when ed.amountreceived >= 10 and ed.amountreceived < 100 then 'Less Than 100' 
--when ed.amountreceived >= 100 and ed.amountreceived < 500 then 'Less Than 500'
--when ed.amountreceived >= 500 and ed.amountreceived < 1000 then 'Less Than 1000'
--when ed.amountreceived >= 1000 then 'More Than 1000' end as ValueBand,
--ed.commissionduedate as EDIDueDate,ed.commissionreceiveddate as EDIRecDate,
--case datepart(mm,ed.commissionreceiveddate)
--when 01 then 'JAN' when 02 then 'FEB' when 03 then 'MAR' when 04 then 'APR' when 05 then 'MAY' when 06 then 'JUN'
--when 07 then 'JUL' when 08 then 'AUG' when 09 then 'SEP' when 10 then 'OCT' when 11 then 'NOV' when 12 then 'DEC'
--end as EDIRecMonth,
ed.IFAReference as EDIAgent,ed.IFAReferenceNumber as EDICaseID,
--case ed.paymentfrequency
--when 'X' then 'Sin' when 'M' then 'Mth' when 'A' then 'Ann' when 'S' then 'Sin' else 'Unk' end as EDIPayFreq,
--case ed.paymenttype when 1 then 'Comm' when 4 then 'Claw' when 99 then 'Adj' else 'Unk' end as EDIPayType,
--ed.transactionid as EDITxn,

st.statement as Statement,st.stmnt_date as StateDate,
case st.state 
when 1 then 'Unproc'
when 2 then 'Proc'
end as Process,
st.comp_code as Provider,

ex.unallocatedreasoncode as Unalloc, 
--ex.amount_rec as SuspAmount,ex.date_recv as SuspDate,
--ex.type as SuspType,ex.status as Status,ex.adjust as Adj,

coalesce(p1.policyref,p2.policyref) as CaseID,coalesce(p1.cont_num,p2.cont_num) as ExtPolNo,
--coalesce(p1.createdate,p2.createdate,p.prop_date) as CreatedDate,
case when coalesce(p1.policyref,p2.policyref) is null and coalesce(p1.cont_num,p2.cont_num) is null
and isnull(ed.ifareferencenumber,0) = 0 then 'Yes' else 'No' end as Invalid,
coalesce(p1.productcode,p2.productcode,ed.productcode) as Product,

ISNULL(OS.CODE,'Unknown') as [Source],    --SR10 :AG 30/09/2009
--case coalesce(p1.originatingsource,p2.originatingsource)                    --SR10 :AG 30/09/2009
--when 0 then 'Man' when 1 then 'ETi' when 2 then 'ETr' when 3 then 'MBL' when 4 then 'Tri'   --SR10 :AG 30/09/2009
--when 5 then 'CTP' when 6 then 'OTPc' else 'Unk' end as Source,                --SR10 :AG 30/09/2009

coalesce(pa.servicingagentcode,pa.sellingagentcode) as AgentUID,

a1.descn as AgentName,

case when pa.sellingagentcode is null and pa.servicingagentcode is not null then 'Serv'
when pa.servicingagentcode is null and pa.sellingagentcode is not null then 'Sell'
when pa.sellingagentcode is not null and pa.servicingagentcode is not null
and pa.sellingagentcode = pa.servicingagentcode then 'Sell'
when pa.sellingagentcode is not null and pa.servicingagentcode is not null
and pa.sellingagentcode <> pa.servicingagentcode then 'Serv'
end as AgentRole,

a1.firm as AgentBusUID,
coalesce (a2.tradingname,a2.descn) as AgentBusName,
a2.manager2code as RSMUID,a3.descn as RSMName,
a2.manager4code as ASDUID,a4.descn as ASDName,

st.Notes as SuspenseCompletionFile,

case when t2.policyid is not null then 'Transaction' 
when t2.policyid is null and coalesce(p1.pol_num,p2.pol_num) is not null then 'Policy Only' 
else 'No Policy' end as PolicyState,

t5.ActiveStatement,t5.ActiveDate,t5.ActiveCompletionFile,

t3.date as PropCreateDate

--case when ex.amount_rec < 0 then 'Accrual Clawback' when ed.CommissionType = 'Y' then 'Initial Indemnity'
--when ed.CommissionType = 'I' then 'Initial Accrual' when ed.CommissionType = 'R' then 'Renewal'
--when ed.CommissionType = 'X' then 'Trail' when ed.PaymentType = '04' then 'Clawback' 
--Else 'Unknown' end as EDIPaymentType

INTO owhot_MTG_SuspenseEDIList_withDUPS
FROM  msit_EDIFACTCommissionStatementContents ed 
INNER JOIN msit_S_PACC ex ON ed.Pacc_ID = ex.ID 
INNER JOIN msit_EDIFACTCommissionStatementHeader edh on edh.id = ed.statementheaderid
INNER JOIN msit_s_STMTCT st on st.statement = edh.statementid
INNER JOIN msit_codeprodproviderreportingxref ppx on ppx.productprovidercode = st.comp_code
left outer JOIN msit_codeproducts cpr on cpr.code = ed.productcode
left outer join mstt_policies p1 on p1.policyref = ed.ifareferencenumber
left outer join mstt_policies p2 
on p2.cont_num = case when len(ed.memberreferencenumber) > 0 then ed.memberreferencenumber 
when len(ed.policynumber) > 0 then ed.policynumber end
--left outer join msit_policyqualitycheckb30 q on q.policyid = coalesce(p1.pol_num,p2.pol_num)
left outer join msit_policyagentsb30 pa on pa.policyid = coalesce(p1.pol_num,p2.pol_num)
--left outer join #issuedpols t1 on t1.policyid = coalesce(p1.pol_num,p2.pol_num)
left outer join #poltrans t2 on t2.policyid = coalesce(p1.pol_num,p2.pol_num)
left outer join #polprops t3 on t3.policyid = coalesce(p1.pol_num,p2.pol_num)
--left outer join #DupPolNum t4 on t4.policy = coalesce(p1.pol_num,p2.pol_num)
left outer join #DupPol t4 on t4.policy = coalesce(p1.cont_num,p2.cont_num)
left outer join #InitBreak t5 on t5.policyid = coalesce(p1.pol_num,p2.pol_num)
left outer join msit_s_agents a1 on a1.code = coalesce(pa.servicingagentcode,pa.sellingagentcode)
left outer join msit_s_agents a2 on a2.code = a1.firm
left outer join msit_s_agents a3 on a3.code = a2.manager2code
left outer join msit_s_agents a4 on a4.code = a2.manager4code
left outer join msit_CodeOriginatingSources OS            --SR10 :AG 30/09/2009
on OS.ID = isnull(p1.OriginatingSource,p2.OriginatingSource)    --SR10 :AG 30/09/2009

where ex.TYPE IN (5, 6) AND ex.ID NOT IN (SELECT susp_id FROM msit_s_paccsu)
and ppx.commrepproductprovidercode = 'mortgage'
and (cpr.code is null or cpr.plancode = 'MRTG')

--and (t4.pol_num is null or t4.pol_num = coalesce(p1.pol_num,p2.pol_num)) --Dedup results by using first policy on DB


ORDER BY ed.ID

--------------------- dups------------------------------------    

    
--drop table #issuedpols    
drop table #poltrans    
drop table #polprops    
drop table #duppol    
drop table #duppolnum   
drop table #activeexp   
drop table #initbreak   






GO
/****** Object:  StoredProcedure [dbo].[owhop_MTG_SuspenseEDIList_History]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/********************************************************************************************
Program:	owhop_MTG_SuspenseEDIList_History

Author:		A Groves

Date:		12/06/2017

Purpose:	This proc was introduced when the Daily Scan DTS scripts were being decommissioned.
			Its purpose is to build up history of the Mortgage Suspense List which previously
			was available via the scans from previous days.

			This stored proc should be called as follows:
			
			exec dbo.owhop_MTG_SuspenseEDIList_History 'Openwork', 'Daily Scans'
			
AMENDMENT HISTORY
=================

Date		Author			Description
----		------			-----------

*********************************************************************************************/
CREATE PROCEDURE [dbo].[owhop_MTG_SuspenseEDIList_History]
	@Client		varchar(50),
	@Module		varchar(50)
AS

SET ANSI_WARNINGS OFF	
set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@CreateDateTime				datetime

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @PhaseLog		= 'LOG'
set @PhaseError		= 'ERROR'
set @Process		= object_name(@@procid)
set @CreateDateTime	= getdate()

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION

	/****************************************************************************

		Remove data older than the retention period.

	****************************************************************************/

	delete from dbo.owhot_MTG_SuspenseEDIList_History
	where ReportDate < dateadd(dd,-95,getdate())
	
	set @RowCount = @@rowcount
	
	set @ProcessMessage = 'Delete Past Retention Period. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

	/****************************************************************************

		Remove any data loaded today to make this proc re-runnable.

	****************************************************************************/

	delete from dbo.owhot_MTG_SuspenseEDIList_History
	where ReportDate = dateadd(dd,0,datediff(dd,0,getdate()))
	
	set @RowCount = @@rowcount
	
	set @ProcessMessage = 'Delete Today''s Data. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

	/****************************************************************************

		Populate the dbo.owhot_MTG_SuspenseEDIList_History table.

	****************************************************************************/

	insert into dbo.owhot_MTG_SuspenseEDIList_History
	(
		EDIContentsID,
		DupPol,
		EDIFullName,
		EDIPolicy,
		EDIPremium,
		EDIAmount,
		EDIAgent,
		EDICaseID,
		Statement,
		StateDate,
		Process,
		Provider,
		Unalloc,
		CaseID,
		ExtPolNo,
		Invalid,
		Product,
		Source,
		AgentUID,
		AgentName,
		AgentRole,
		AgentBusUID,
		AgentBusName,
		RSMUID,
		RSMName,
		ASDUID,
		ASDName,
		SuspenseCompletionFile,
		PolicyState,
		ActiveStatement,
		ActiveDate,
		ActiveCompletionFile,
		PropCreateDate,
		ReportDate,
		DateInserted
	)
	select	ID,
			DupPol,
			EDIFullName,
			EDIPolicy,
			EDIPremium,
			EDIAmount,
			EDIAgent,
			EDICaseID,
			Statement,
			StateDate,
			Process,
			Provider,
			Unalloc,
			CaseID,
			ExtPolNo,
			Invalid,
			Product,
			Source,
			AgentUID,
			AgentName,
			AgentRole,
			AgentBusUID,
			AgentBusName,
			RSMUID,
			RSMName,
			ASDUID,
			ASDName,
			SuspenseCompletionFile,
			PolicyState,
			ActiveStatement,
			ActiveDate,
			ActiveCompletionFile,
			PropCreateDate,
			@CreateDateTime as ReportDate,
			@CreateDateTime as DateInserted
	from	dbo.owhot_MTG_SuspenseEDIList_NODUPS

	set @RowCount = @@rowcount
	
	set @ProcessMessage = 'Table Insert. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/
GO
/****** Object:  StoredProcedure [dbo].[owhop_MTG_SuspenseEDIList_NODUPS]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[owhop_MTG_SuspenseEDIList_NODUPS] AS

/*********************************************************************************************
AMENDMENTS
==========
Date	Author				Description
----	------				-----------
21/09/2009	Mike Caswood	SR10 - new OBP OriginatingSource codes.
							Source now holds Code from Swift Code table. 
							Column on results table amended to varchar(6).
16/06/2017	Alan Groves		SR464996. This change relates to the removal of the DTS daily scans 
							where theis proc is now run in a job step instead of DTS 
							"ow_daily_scans_main". This change introduces logging via 
							"msp_ProcessLog". Values are hardcoded, as parameters are not passed 
							into this proc to maintain compatibility with the DTS call during 
							the cutover period.									
**********************************************************************************************/

set nocount on

--AG 16/06/2017 Start	
declare		@RowCount		int,
			@Process		varchar(100),
			@ProcessMessage	varchar(100),
			@PhaseStart		varchar(50),
			@PhaseEnd		varchar(50),
			@PhaseLog		varchar(50),
			@Client			varchar(50),
			@Module			varchar(50)

set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @PhaseLog		= 'LOG'			
set @Process		= object_name(@@procid)
set @Client			= 'Openwork'
set @Module			= 'Daily Scans'

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client
--AG 16/06/2017 End

if exists (select * from dbo.sysobjects where id = object_id(N'[dbo].[owhot_MTG_SuspenseEDIList_NODUPS]') and OBJECTPROPERTY(id, N'IsUserTable') = 1)
drop table [dbo].[owhot_MTG_SuspenseEDIList_NODUPS]

set nocount on

select distinct policyid 
into #PolTrans
from mstt_policytransactions

select policyid, min(createdatetime) as Date
into #PolProps
from mstt_policytransactions
where transtype = 39
--and productgroupcode = 3
group by policyid

select cont_num as Policy
into #DupPol
from mstt_policies
where cont_num is not null and len(cont_num) > 0
--and plan_code = 'mrtg'
group by cont_num having count(*) > 1

select Policy,min(pol_num) as Pol_Num
into #DupPolNum
from mstt_policies po
inner join #duppol t1 on t1.policy = po.cont_num
group by t1.policy

select pt.policyid,max(ex.id) as ExpID 
into #ActiveExp
from mstt_Expectation ex
inner join mstt_policytransactions pt on pt.id = ex.transactionid
--where pt.productgroupcode = 3
group by pt.policyid

select t1.*,ex.Statement as ActiveStatement,ex.Date_Recv as ActiveDate,st.Notes as ActiveCompletionFile
into #InitBreak
from #ActiveExp t1
inner join mstt_expectation ex on ex.id = t1.ExpID
inner join msit_s_stmtct st on st.statement = ex.statement

select DISTINCT
ED.ID as ID,case when t4.policy is not null then 'Yes' end as DupPol,
--ED.initials as EDInits,
case when ed.Fullname is not null and len(ed.Fullname) > 0 then ed.FullName else ED.Surname end as EDIFullName,
case when len(ed.memberreferencenumber) > 0 then ed.memberreferencenumber 
when len(ed.policynumber) > 0 then ed.policynumber end as EDIPolicy,
ed.PremiumAmount as EDIPremium,ed.amountreceived as EDIAmount,
ed.IFAReference as EDIAgent,ed.IFAReferenceNumber as EDICaseID,

st.statement as Statement,st.stmnt_date as StateDate,
case st.state 
when 1 then 'Unproc'
when 2 then 'Proc'
end as Process,
st.comp_code as Provider,

ex.unallocatedreasoncode as Unalloc, 

coalesce(p1.policyref,p2.policyref) as CaseID,coalesce(p1.cont_num,p2.cont_num) as ExtPolNo,
case when coalesce(p1.policyref,p2.policyref) is null and coalesce(p1.cont_num,p2.cont_num) is null
and isnull(ed.ifareferencenumber,0) = 0 then 'Yes' else 'No' end as Invalid,
coalesce(p1.productcode,p2.productcode,ed.productcode) as Product,

ISNULL(OS.CODE,'Unknown') as [Source],    --SR10 :MPC 21/09/2009
--case coalesce(p1.originatingsource,p2.originatingsource)                    --SR10 :MPC 21/09/2009
--when 0 then 'Man' when 1 then 'ETi' when 2 then 'ETr' when 3 then 'MBL' when 4 then 'Tri'   --SR10 :MPC 21/09/2009
--when 5 then 'CTP' when 6 then 'OTPc' else 'Unk' end as Source,                --SR10 :MPC 21/09/2009

coalesce(pa.servicingagentcode,pa.sellingagentcode) as AgentUID,

a1.descn as AgentName,

case when pa.sellingagentcode is null and pa.servicingagentcode is not null then 'Serv'
when pa.servicingagentcode is null and pa.sellingagentcode is not null then 'Sell'
when pa.sellingagentcode is not null and pa.servicingagentcode is not null
and pa.sellingagentcode = pa.servicingagentcode then 'Sell'
when pa.sellingagentcode is not null and pa.servicingagentcode is not null
and pa.sellingagentcode <> pa.servicingagentcode then 'Serv'
end as AgentRole,

a1.firm as AgentBusUID,
coalesce (a2.tradingname,a2.descn) as AgentBusName,
a2.manager2code as RSMUID,a3.descn as RSMName,
a2.manager4code as ASDUID,a4.descn as ASDName,

st.Notes as SuspenseCompletionFile,

case when t2.policyid is not null then 'Transaction' 
when t2.policyid is null and coalesce(p1.pol_num,p2.pol_num) is not null then 'Policy Only' 
else 'No Policy' end as PolicyState,

t5.ActiveStatement,t5.ActiveDate,t5.ActiveCompletionFile,

t3.date as PropCreateDate


INTO owhot_MTG_SuspenseEDIList_NODUPS
FROM  msit_EDIFACTCommissionStatementContents ed 
INNER JOIN msit_S_PACC ex ON ed.Pacc_ID = ex.ID 
INNER JOIN msit_EDIFACTCommissionStatementHeader edh on edh.id = ed.statementheaderid
INNER JOIN msit_s_STMTCT st on st.statement = edh.statementid
INNER JOIN msit_codeprodproviderreportingxref ppx on ppx.productprovidercode = st.comp_code
left outer JOIN msit_codeproducts cpr on cpr.code = ed.productcode
left outer join mstt_policies p1 on p1.policyref = ed.ifareferencenumber
left outer join mstt_policies p2 
on p2.cont_num = case when len(ed.memberreferencenumber) > 0 then ed.memberreferencenumber 
when len(ed.policynumber) > 0 then ed.policynumber end
left outer join msit_policyagentsb30 pa on pa.policyid = coalesce(p1.pol_num,p2.pol_num)
left outer join #poltrans t2 on t2.policyid = coalesce(p1.pol_num,p2.pol_num)
left outer join #polprops t3 on t3.policyid = coalesce(p1.pol_num,p2.pol_num)
left outer join #DupPolNum t4 on t4.policy = coalesce(p1.cont_num,p2.cont_num)
left outer join #InitBreak t5 on t5.policyid = coalesce(p1.pol_num,p2.pol_num)
left outer join msit_s_agents a1 on a1.code = coalesce(pa.servicingagentcode,pa.sellingagentcode)
left outer join msit_s_agents a2 on a2.code = a1.firm
left outer join msit_s_agents a3 on a3.code = a2.manager2code
left outer join msit_s_agents a4 on a4.code = a2.manager4code
left outer join msit_CodeOriginatingSources OS            --SR10 :MPC 21/09/2009
on OS.ID = isnull(p1.OriginatingSource,p2.OriginatingSource)    --SR10 :MPC 21/09/2009

where ex.TYPE IN (5, 6) AND ex.ID NOT IN (SELECT susp_id FROM msit_s_paccsu)
and ppx.commrepproductprovidercode = 'mortgage'   --Use Mortgage provider payments only
and (cpr.code is null or cpr.plancode = 'MRTG')   --Select Mortgage products if code recognised 
--Dedup results by using first policy on DB or if duplicate policy but EDI Case ID not the first pol_num
and (t4.pol_num is null or t4.pol_num = coalesce(p1.pol_num,p2.pol_num) 
or (t4.pol_num is not null and t4.pol_num <> coalesce(p1.pol_num,p2.pol_num) and t4.policy = p1.cont_num)) 

ORDER BY ed.ID

--AG 16/06/2017 Start	
set @RowCount = @@rowcount
	
set @ProcessMessage = 'Table Insert. Number of rows = ' + convert(varchar(20),@RowCount)	
exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client
--AG 16/06/2017 End


GO
/****** Object:  StoredProcedure [dbo].[owhop_MTG_SuspenseEDIList_withDUPS]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[owhop_MTG_SuspenseEDIList_withDUPS] AS

/*
AMENDMENTS
==========
1.  Mike Cawood   21/09/2009    SR10 - new OBP OriginatingSource codes.
                  Source now holds Code from Swift Code table. 
                  Column on results table amended to varchar(6).
*/

set nocount on

if exists (select * from dbo.sysobjects where id = object_id(N'[dbo].[owhot_MTG_SuspenseEDIList_withDUPS]') and OBJECTPROPERTY(id, N'IsUserTable') = 1)
drop table [dbo].[owhot_MTG_SuspenseEDIList_withDUPS]


select distinct policyid 
into #PolTrans
from mstt_policytransactions
--where productgroupcode = 3

select policyid, min(createdatetime) as Date
into #PolProps
from mstt_policytransactions
where transtype = 39
group by policyid

select cont_num as Policy
into #DupPol
from mstt_policies
where cont_num is not null and len(cont_num) > 0
group by cont_num having count(*) > 1


select pt.policyid,max(ex.id) as ExpID 
into #ActiveExp
from mstt_Expectation ex
inner join mstt_policytransactions pt on pt.id = ex.transactionid
group by pt.policyid

select t1.*,ex.Statement as ActiveStatement,ex.Date_Recv as ActiveDate,st.Notes as ActiveCompletionFile
into #InitBreak
from #ActiveExp t1
inner join mstt_expectation ex on ex.id = t1.ExpID
inner join msit_s_stmtct st on st.statement = ex.statement

select DISTINCT
ED.ID as ID,case when t4.policy is not null then 'Yes' end as DupPol,
--ED.initials as EDInits,
case when ed.Fullname is not null and len(ed.Fullname) > 0 then ed.FullName else ED.Surname end as EDIFullName,
case when len(ed.memberreferencenumber) > 0 then ed.memberreferencenumber 
when len(ed.policynumber) > 0 then ed.policynumber end as EDIPolicy,
ed.PremiumAmount as EDIPremium,ed.amountreceived as EDIAmount,
ed.IFAReference as EDIAgent,ed.IFAReferenceNumber as EDICaseID,

st.statement as Statement,st.stmnt_date as StateDate,
case st.state 
when 1 then 'Unproc'
when 2 then 'Proc'
end as Process,
st.comp_code as Provider,

ex.unallocatedreasoncode as Unalloc, 

coalesce(p1.policyref,p2.policyref) as CaseID,coalesce(p1.cont_num,p2.cont_num) as ExtPolNo,
case when coalesce(p1.policyref,p2.policyref) is null and coalesce(p1.cont_num,p2.cont_num) is null
and isnull(ed.ifareferencenumber,0) = 0 then 'Yes' else 'No' end as Invalid,
coalesce(p1.productcode,p2.productcode,ed.productcode) as Product,

ISNULL(OS.CODE,'Unknown') as [Source],    --SR10 :MPC 21/09/2009
--case coalesce(p1.originatingsource,p2.originatingsource)                    --SR10 :MPC 21/09/2009
--when 0 then 'Man' when 1 then 'ETi' when 2 then 'ETr' when 3 then 'MBL' when 4 then 'Tri'   --SR10 :MPC 21/09/2009
--when 5 then 'CTP' when 6 then 'OTPc' else 'Unk' end as Source,                --SR10 :MPC 21/09/2009

coalesce(pa.servicingagentcode,pa.sellingagentcode) as AgentUID,

a1.descn as AgentName,

case when pa.sellingagentcode is null and pa.servicingagentcode is not null then 'Serv'
when pa.servicingagentcode is null and pa.sellingagentcode is not null then 'Sell'
when pa.sellingagentcode is not null and pa.servicingagentcode is not null
and pa.sellingagentcode = pa.servicingagentcode then 'Sell'
when pa.sellingagentcode is not null and pa.servicingagentcode is not null
and pa.sellingagentcode <> pa.servicingagentcode then 'Serv'
end as AgentRole,

a1.firm as AgentBusUID,
coalesce (a2.tradingname,a2.descn) as AgentBusName,
a2.manager2code as RSMUID,a3.descn as RSMName,
a2.manager4code as ASDUID,a4.descn as ASDName,

st.Notes as SuspenseCompletionFile,

case when t2.policyid is not null then 'Transaction' 
when t2.policyid is null and coalesce(p1.pol_num,p2.pol_num) is not null then 'Policy Only' 
else 'No Policy' end as PolicyState,

t5.ActiveStatement,t5.ActiveDate,t5.ActiveCompletionFile,

t3.date as PropCreateDate

INTO owhot_MTG_SuspenseEDIList_withDUPS
FROM  msit_EDIFACTCommissionStatementContents ed 
INNER JOIN msit_S_PACC ex ON ed.Pacc_ID = ex.ID 
INNER JOIN msit_EDIFACTCommissionStatementHeader edh on edh.id = ed.statementheaderid
INNER JOIN msit_s_STMTCT st on st.statement = edh.statementid
INNER JOIN msit_codeprodproviderreportingxref ppx on ppx.productprovidercode = st.comp_code
left outer JOIN msit_codeproducts cpr on cpr.code = ed.productcode
left outer join mstt_policies p1 on p1.policyref = ed.ifareferencenumber
left outer join mstt_policies p2 
on p2.cont_num = case when len(ed.memberreferencenumber) > 0 then ed.memberreferencenumber 
when len(ed.policynumber) > 0 then ed.policynumber end
--left outer join msit_policyqualitycheckb30 q on q.policyid = coalesce(p1.pol_num,p2.pol_num)
left outer join msit_policyagentsb30 pa on pa.policyid = coalesce(p1.pol_num,p2.pol_num)
--left outer join #issuedpols t1 on t1.policyid = coalesce(p1.pol_num,p2.pol_num)
left outer join #poltrans t2 on t2.policyid = coalesce(p1.pol_num,p2.pol_num)
left outer join #polprops t3 on t3.policyid = coalesce(p1.pol_num,p2.pol_num)
--left outer join #DupPolNum t4 on t4.policy = coalesce(p1.pol_num,p2.pol_num)
left outer join #DupPol t4 on t4.policy = coalesce(p1.cont_num,p2.cont_num)
left outer join #InitBreak t5 on t5.policyid = coalesce(p1.pol_num,p2.pol_num)
left outer join msit_s_agents a1 on a1.code = coalesce(pa.servicingagentcode,pa.sellingagentcode)
left outer join msit_s_agents a2 on a2.code = a1.firm
left outer join msit_s_agents a3 on a3.code = a2.manager2code
left outer join msit_s_agents a4 on a4.code = a2.manager4code
left outer join msit_CodeOriginatingSources OS            --SR10 :MPC 21/09/2009
on OS.ID = isnull(p1.OriginatingSource,p2.OriginatingSource)    --SR10 :MPC 21/09/2009

where ex.TYPE IN (5, 6) AND ex.ID NOT IN (SELECT susp_id FROM msit_s_paccsu)
and ppx.commrepproductprovidercode = 'mortgage'   --Use Mortgage provider payments only
and (cpr.code is null or cpr.plancode = 'MRTG')   --Select Mortgage products if code recognised 

ORDER BY ed.ID




GO
/****** Object:  StoredProcedure [dbo].[owhop_NinaStenning]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE Procedure [dbo].[owhop_NinaStenning] with recompile as

set ansi_nulls off

if exists (select * from dbo.sysobjects where id = object_id(N'[dbo].[owhot_NinaStenning]') and OBJECTPROPERTY(id, N'IsUserTable') = 1)
drop table dbo.owhot_NinaStenning

declare @yesterday datetime
set @yesterday = CAST(CONVERT(NVARCHAR,dateadd(dd,-1,getdate()),112) as datetime)
declare @lastweek datetime
set @lastweek = CAST(CONVERT(NVARCHAR,dateadd(dd,-7,getdate()),112) as datetime)


if exists (select * from dbo.sysobjects where id = object_id(N'[dbo].dbo.owhot_NinaStenning') and OBJECTPROPERTY(id, N'IsUserTable') = 1)
drop table [dbo].[owhot_NinaStenning ]

SELECT     dbo.mstt_Commissions.*, dbo.cscv_AgentsHierarchy.AgentDesc, dbo.cscv_AgentsHierarchy.FirmDescn, dbo.mstt_Policies.CONT_NUM, 
                      dbo.mstt_CodeProductGroup.ProductGroupName, dbo.mstt_CodeReportingProductCode.ReportingProductName, dbo.cscv_AgentsHierarchy.RSMName, 
                      dbo.cscv_AgentsHierarchy.ASDName, dbo.mstt_PolicyTransactions.Amount, dbo.msit_S_LIFE.SUM_ASS, 
                      dbo.mstt_PolicyTransactions.FrequencyDescription, dbo.mstt_PolicyTransactions.Frequency AS Expr1, 
                      dbo.mstt_Commissions.TransactionDate AS Expr2, dbo.mstt_Commissions.AdminMethod AS Expr3, 
                      dbo.mstt_Commissions.AdminMethodDescription AS Expr4
into owhot_NinaStenning 
FROM         dbo.mstt_Commissions LEFT OUTER JOIN
                      dbo.msit_S_LIFE ON dbo.mstt_Commissions.PolicyID = dbo.msit_S_LIFE.POL_NUM LEFT OUTER JOIN
                      dbo.mstt_PolicyTransactions ON dbo.mstt_Commissions.TransactionID = dbo.mstt_PolicyTransactions.ID LEFT OUTER JOIN
                      dbo.mstt_CodeReportingProductCode ON 
                      dbo.mstt_Commissions.ReportingProductCode = dbo.mstt_CodeReportingProductCode.ReportingProductCode LEFT OUTER JOIN
                      dbo.mstt_CodeProductGroup ON dbo.mstt_Commissions.ProductGroupCode = dbo.mstt_CodeProductGroup.ProductGroupCode LEFT OUTER JOIN
                      dbo.mstt_Policies ON dbo.mstt_Commissions.PolicyID = dbo.mstt_Policies.POL_NUM LEFT OUTER JOIN
                      dbo.cscv_AgentsHierarchy ON dbo.mstt_Commissions.AGENT_CODE = dbo.cscv_AgentsHierarchy.AgentCode
WHERE     (dbo.mstt_Commissions.TransactionDate >= @lastweek) AND (dbo.mstt_Commissions.TransactionDate <= @yesterday) AND 
                      (dbo.mstt_Commissions.CommissionType = 1) AND (dbo.mstt_Commissions.PolTranTransType = 39) AND 
                      (dbo.mstt_Commissions.AGENT_CODE <> '10002') AND (dbo.mstt_Commissions.ProductGroupCode = 'Protection')
GO
/****** Object:  StoredProcedure [dbo].[owhop_PaymentAuditExtract]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE procedure [dbo].[owhop_PaymentAuditExtract]
with recompile
as
 
--########################################################################
--
-- Object  : procedure
-- Name    : owhop_PaymentAuditExtract.sql
-- Owner   : MPC
-- Created : 15/08/2007
--
--########################################################################

set nocount on

 drop  INDEX [dbo].[owhot_PaymentAudit].[provider]

 drop  INDEX [dbo].[owhot_PaymentAudit].[rec_loaddate]

 drop  INDEX [dbo].[owhot_PaymentAudit].[rec_suspensedate] 

 drop  INDEX [dbo].[owhot_PaymentAudit].[rec_automatchdate]

 drop  INDEX [dbo].[owhot_PaymentAudit].[statementtype] 

 drop  INDEX [dbo].[owhot_PaymentAudit].[Rec_ProviderType]

 drop  INDEX [dbo].[owhot_PaymentAudit].[dailystats] 

 drop  INDEX [dbo].[owhot_PaymentAudit].[expid] 


truncate table owhot_PaymentAudit

-- Derive Payment History details from Unpaid and Paid List

select pacc_id,min(createdatetime) as UnpaidListDate,
sum(case when pp.agent_code = 10002 then pp.amount else 0 end) as Margin,
min(paymentdate) as PaidListDate,min(Exported) as Exported,min(export_date) as BACSDate,
sum(case when ap.agent_code not in (10002,10004) then isnull(ap.amount,0) else 0 end) as BACSAmount
into #Processed
from mstt_paymentspending pp
left outer join mstt_agentpayments ap on ap.agmid = pp.id
where pacc_ID is not null
group by pacc_id
--order by pacc_id

CREATE  INDEX [ix_paccid] ON [#Processed]([Pacc_ID]) ON [PRIMARY]

-- Select EDI Payments loaded onto Expectation table

Select 
coalesce(st.statement,edh.Statementid) as Statement,edh.ID as EDIHeaderID,
case st.state when 1 then 'Unprocessed' when 2 then 'Processed' end as StatementStatus,
st.createddatetime as StatementCreateDate,
case when edh.id is null and cast(st.Total as decimal(15,2)) = 0 then 'Global' 
when edh.id is null and cast(st.Total as decimal(15,2)) <> 0 then 'Manual'
when edh.id is not null then 'EDI' else 'Unknown' end as StatementType,
case when edc.id is not null and ex.id is null then 'Not Loaded' 
when cast((case when ex.type in (2,15,16,17,18,19) then -1 else 1 end * ex.amount_rec) as decimal(15,2)) <> cast(edc.amountreceived as decimal(15,2))
and edc.id is not null and ex.id is not null then 'Loaded - Value Mismatch'
when cast(ex.amount_rec as decimal(15,2)) = cast(edc.amountreceived as decimal(15,2))
and edc.id is not null and ex.id is not null then 'Loaded - Value Match' end as EDILoadStatus,
edc.id as EDIContentID,edc.AmountReceived as EDIAmount,
case when len(edc.memberreferencenumber) > 0 then edc.memberreferencenumber 
when len(edc.policynumber) > 0 then edc.policynumber end as PolicyNumber,
case when edc.Fullname is not null and len(edc.Fullname) > 0 then edc.Fullname
else substring((rtrim(edc.Surname) + ' ' + rtrim(edc.initials)),1,255) end as EDIClient,
case when ex.amount_rec < 0 then 'Accrual Clawback' when edc.CommissionType = 'Y' then 'Initial Indemnity'
when edc.CommissionType = 'I' then 'Initial Accrual' when edc.CommissionType = 'R' then 'Renewal'
when edc.CommissionType = 'X' then 'Trail' when edc.PaymentType = '04' then 'Clawback'
Else 'Unknown' end as EDIPayTypeDesc,
case edc.paymentfrequency when 'X' then 'Sin' when 'M' then 'Mth' when 'A' then 'Ann'
when 'S' then 'Sin' else 'Unk' end as EDIPayFreq,
edc.policytype as EDIPolType,edc.commissiontype as EDICommType,edc.paymenttype as EDIPayType,
edc.PremiumType as EDIPremTyp,edc.PremiumAmount as EDIPremium,edc.IFAReference as EDIAgentCode,
edc.IFAReferenceNumber as EDIRefNo,edc.ReasonCode as EDIReason,
coalesce(st.comp_code,ex.comp_code,e2.comp_code) as Provider,coalesce(ex.ID,edc.PACC_ID) as ExpID,ex.Type,
case ex.type when 1 then 'IC' when 2 then 'IC Clawback' when 3 then 'Agent' when 4 then 'RC' when 5 then 'Suspense' 
when 6 then 'Suspense' when 10 then 'Trail' when 15 then 'RC Clawback' when 16 then 'TF Clawback' 
when 17 then 'IC Adjust' when 18 then 'RC Adjust' when 19 then 'TF Adjust' end as TypeDesc,ex.Status,
case ex.status when 1 then 'Unmatched' when 2 then 'Matched' when 3 then 'Processed' end as StatusDesc,
ex.amount_due as AmountDue,ex.Date_due as DateDue,ex.amount_rec as AmountRec,ex.date_recv as DateRec,
ex.unallocatedreasoncode as UnallocReasonCode,ex.UnallocReasonDesc,ex.transactionid as TxnID,
ex.PolicyID,ex.CaseID,ex.providerref as ExpPolicy,ex.FirstClientID as ClientID,
su.amount as SuspMatchAmt,coalesce(su.createddatetime,e2.date_recv) as MatchDate,ex.INIT_ID as MatchID,
case when ex.Type in (5,6) and su.id is null then 'In Suspense'
when ex.Type not in (5,6) and ex.SuspenseID is null then 'Automatch'
when su.id is not null and e2.id is not null and e2.type in (5,6) 
and cast((ex.amount_rec + e2.amount_rec) as decimal(15,2)) = 0 then 'Match - Contra'
when su.Init_ID is not null and e2.ID is null then 'Match - Missing'
when cast(ex.amount_rec as decimal(15,2)) <> cast(su.amount as decimal(15,2)) then 'Match - Partial'
when (case when e2.type in (2,5,6,15,16,17,18,19) then -1 else 1 end) * -- Sign changes when matched to these types
cast(e2.amount_rec as decimal(15,2)) <> cast(su.amount as decimal(15,2)) then 'Match - Leakage'
when cast(ex.amount_rec as decimal(15,2)) = cast(su.amount as decimal(15,2)) then 'Match - Full' end as MatchCategory,
e2.type as MatchType,
case e2.type when 1 then 'IC' when 2 then 'IC Clawback' when 3 then 'Agent' when 4 then 'RC' when 5 then 'Suspense' 
when 6 then 'Suspense' when 10 then 'Trail' when 15 then 'RC Clawback' when 16 then 'TF Clawback' 
when 17 then 'IC Adjust' when 18 then 'RC Adjust' when 19 then 'TF Adjust' end as MatchTypeDesc,e2.Status as MatchStatus,
case e2.status when 1 then 'Unmatched' when 2 then 'Matched' when 3 then 'Processed' end as MatchStatusDesc,
e2.amount_due as MatchDue,e2.Date_due as MatchDateDue,e2.amount_rec as MatchRec,e2.date_recv as MatchDateRec,
e2.transactionid as MatchTranId,e2.PolicyID as MatchPolicyID,e2.CaseID as MatchCaseID,
e2.providerref as MatchPolicy,e2.FirstClientID as MatchClientID,
case when ex.status = 3 and ex.type not in (5,6) and t1.pacc_id is null then 'Missing'
when ex.status = 3 and ex.type not in (5,6) and t1.pacc_id is not null then 'Loaded' end as UnpaidStatus,
t1.UnpaidListDate,t1.Margin,t1.PaidListDate,
case t1.Exported when 'T' then 'Yes' when 'F' then 'No' end as BACSPaid,t1.BACSDate,t1.BACSAmount,
NULL as REC_ProviderType,
case when edh.id is null and cast(st.Total as decimal(15,2)) <> 0 then ex.Date_Recv
when edh.id is not null then ex.Date_Recv end as REC_LoadDate,
case when edh.id is null and cast(st.Total as decimal(15,2)) <> 0 and ex.Type in (5,6) then ex.Date_Recv 
when edh.id is not null and ex.Type in (5,6) then ex.Date_Recv end as REC_SuspenseDate,
case when edh.id is null and cast(st.Total as decimal(15,2)) <> 0 and ex.Type not in (5,6) 
and ex.SuspenseID is NULL then ex.Date_Recv
when edh.id is not null and ex.Type not in (5,6) and ex.SuspenseID is NULL then ex.Date_Recv
end as REC_AutomatchDate,
case when edh.id is null and cast(st.Total as decimal(15,2)) <> 0 and ex.Type in (5,6) 
and e2.id is not NULL then coalesce(su.CreatedDateTime,e2.Date_Recv)
when edh.id is not null and ex.Type in (5,6) and e2.id is not NULL 
then coalesce(su.CreatedDateTime,e2.Date_Recv) end as REC_MatchDate
--,*
into #Extract1
from msit_edifactcommissionstatementcontents edc
left outer join msit_edifactcommissionstatementheader edh on edh.id = edc.statementheaderid
left outer join msit_s_stmtct st on st.statement = edh.statementid
left outer join mstt_expectation ex on ex.id = edc.pacc_id
left outer join msit_s_paccsu su on su.susp_id = ex.id
left outer join mstt_expectation e2 on e2.id = su.init_id
left outer join #Processed t1 on t1.Pacc_ID = ex.id
--order by edc.id,edh.statement,edc.pacc_id

-- Load EDI data extracted above

Insert into owhot_PaymentAudit
(Statement,
EDIHeaderID,
StatementStatus,
StatementCreateDate,
StatementType,
EDILoadStatus,
EDIContentID,
EDIAmount,
PolicyNumber,
EDIClient,
EDIPayTypeDesc,
EDIPayFreq,
EDIPolType,
EDICommType,
EDIPayType,
EDIPremTyp,
EDIPremium,
EDIAgentCode,
EDIRefNo,
EDIReason,
Provider,
ExpID,
Type,
TypeDesc,
Status,
StatusDesc,
AmountDue,
DateDue,
AmountRec,
DateRec,
UnallocReasonCode,
UnallocReasonDesc,
TxnID,
PolicyID,
CaseID,
ExpPolicy,
ClientID,
SuspMatchAmt,
MatchDate,
MatchID,
MatchCategory,
MatchType,
MatchTypeDesc,
MatchStatus,
MatchStatusDesc,
MatchDue,
MatchDateDue,
MatchRec,
MatchDateRec,
MatchTranId,
MatchPolicyID,
MatchCaseID,
MatchPolicy,
MatchClientID,
UnpaidStatus,
UnpaidListDate,
Margin,
PaidListDate,
BACSPaid,
BACSDate,
BACSAmount,
REC_ProviderType,
REC_LoadDate,
REC_SuspenseDate,
REC_AutomatchDate,
REC_MatchDate
)
Select Statement,
EDIHeaderID,
StatementStatus,
StatementCreateDate,
StatementType,
EDILoadStatus,
EDIContentID,
EDIAmount,
PolicyNumber,
EDIClient,
EDIPayTypeDesc,
EDIPayFreq,
EDIPolType,
EDICommType,
EDIPayType,
EDIPremTyp,
EDIPremium,
EDIAgentCode,
EDIRefNo,
EDIReason,
Provider,
ExpID,
Type,
TypeDesc,
Status,
StatusDesc,
AmountDue,
DateDue,
AmountRec,
DateRec,
UnallocReasonCode,
UnallocReasonDesc,
TxnID,
PolicyID,
CaseID,
ExpPolicy,
ClientID,
SuspMatchAmt,
MatchDate,
MatchID,
MatchCategory,
MatchType,
MatchTypeDesc,
MatchStatus,
MatchStatusDesc,
MatchDue,
MatchDateDue,
MatchRec,
MatchDateRec,
MatchTranId,
MatchPolicyID,
MatchCaseID,
MatchPolicy,
MatchClientID,
UnpaidStatus,
UnpaidListDate,
Margin,
PaidListDate,
BACSPaid,
BACSDate,
BACSAmount,
REC_ProviderType,
REC_LoadDate,
REC_SuspenseDate,
REC_AutomatchDate,
REC_MatchDate
from #Extract1

drop table #Extract1

-- Select non-EDI Payments on Expectation table (exclude Matched payments from EDI Extract)

CREATE  INDEX [expid] ON [dbo].[owhot_PaymentAudit]([ExpID]) ON [PRIMARY]

Select 
coalesce(st.statement,edh.Statementid) as Statement,edh.ID as EDIHeaderID,
case st.state when 1 then 'Unprocessed' when 2 then 'Processed' end as StatementStatus,
st.createddatetime as StatementCreateDate,
case when edh.id is null and cast(st.Total as decimal(15,2)) = 0 then 'Global' 
when edh.id is null and cast(st.Total as decimal(15,2)) <> 0 then 'Manual'
when edh.id is not null then 'EDI' else 'Unknown' end as StatementType,
case when edc.id is not null and ex.id is null then 'Not Loaded' 
when cast((case when ex.type in (2,15,16,17,18,19) then -1 else 1 end * ex.amount_rec) as decimal(15,2)) <> cast(edc.amountreceived as decimal(15,2))
and edc.id is not null and ex.id is not null then 'Loaded - Value Mismatch'
when cast(ex.amount_rec as decimal(15,2)) = cast(edc.amountreceived as decimal(15,2))
and edc.id is not null and ex.id is not null then 'Loaded - Value Match' end as EDILoadStatus,
edc.id as EDIContentID,edc.AmountReceived as EDIAmount,
case when len(edc.memberreferencenumber) > 0 then edc.memberreferencenumber 
when len(edc.policynumber) > 0 then edc.policynumber end as PolicyNumber,
case when edc.Fullname is not null and len(edc.Fullname) > 0 then edc.Fullname
else substring((rtrim(edc.Surname) + ' ' + rtrim(edc.initials)),1,255) end as EDIClient,
case when ex.amount_rec < 0 then 'Accrual Clawback' when edc.CommissionType = 'Y' then 'Initial Indemnity'
when edc.CommissionType = 'I' then 'Initial Accrual' when edc.CommissionType = 'R' then 'Renewal'
when edc.CommissionType = 'X' then 'Trail' when edc.PaymentType = '04' then 'Clawback'
Else 'Unknown' end as EDIPayTypeDesc,
case edc.paymentfrequency when 'X' then 'Sin' when 'M' then 'Mth' when 'A' then 'Ann'
when 'S' then 'Sin' else 'Unk' end as EDIPayFreq,
edc.policytype as EDIPolType,edc.commissiontype as EDICommType,edc.paymenttype as EDIPayType,
edc.PremiumType as EDIPremTyp,edc.PremiumAmount as EDIPremium,edc.IFAReference as EDIAgentCode,
edc.IFAReferenceNumber as EDIRefNo,edc.ReasonCode as EDIReason,
coalesce(st.comp_code,ex.comp_code,e2.comp_code) as Provider,coalesce(ex.ID,edc.PACC_ID) as ExpID,ex.Type,
case ex.type when 1 then 'IC' when 2 then 'IC Clawback' when 3 then 'Agent' when 4 then 'RC' when 5 then 'Suspense' 
when 6 then 'Suspense' when 10 then 'Trail' when 15 then 'RC Clawback' when 16 then 'TF Clawback' 
when 17 then 'IC Adjust' when 18 then 'RC Adjust' when 19 then 'TF Adjust' end as TypeDesc,ex.Status,
case ex.status when 1 then 'Unmatched' when 2 then 'Matched' when 3 then 'Processed' end as StatusDesc,
ex.amount_due as AmountDue,ex.Date_due as DateDue,ex.amount_rec as AmountRec,ex.date_recv as DateRec,
ex.unallocatedreasoncode as UnallocReasonCode,ex.UnallocReasonDesc,ex.transactionid as TxnID,
ex.PolicyID,ex.CaseID,ex.providerref as ExpPolicy,ex.FirstClientID as ClientID,
su.amount as SuspMatchAmt,coalesce(su.createddatetime,e2.date_recv) as MatchDate,ex.INIT_ID as MatchID,
case when ex.Type in (5,6) and su.id is null then 'In Suspense'
when ex.Type not in (5,6) and ex.SuspenseID is null then 'Automatch'
when su.id is not null and e2.id is not null and e2.type in (5,6) 
and cast((ex.amount_rec + e2.amount_rec) as decimal(15,2)) = 0 then 'Match - Contra'
when su.Init_ID is not null and e2.ID is null then 'Match - Missing'
when cast(ex.amount_rec as decimal(15,2)) <> cast(su.amount as decimal(15,2)) then 'Match - Partial'
when (case when e2.type in (2,5,6,15,16,17,18,19) then -1 else 1 end) * -- Sign changes when matched to these types
cast(e2.amount_rec as decimal(15,2)) <> cast(su.amount as decimal(15,2)) then 'Match - Leakage'
when cast(ex.amount_rec as decimal(15,2)) = cast(su.amount as decimal(15,2)) then 'Match - Full' end as MatchCategory,
e2.type as MatchType,
case e2.type when 1 then 'IC' when 2 then 'IC Clawback' when 3 then 'Agent' when 4 then 'RC' when 5 then 'Suspense' 
when 6 then 'Suspense' when 10 then 'Trail' when 15 then 'RC Clawback' when 16 then 'TF Clawback' 
when 17 then 'IC Adjust' when 18 then 'RC Adjust' when 19 then 'TF Adjust' end as MatchTypeDesc,e2.Status as MatchStatus,
case e2.status when 1 then 'Unmatched' when 2 then 'Matched' when 3 then 'Processed' end as MatchStatusDesc,
e2.amount_due as MatchDue,e2.Date_due as MatchDateDue,e2.amount_rec as MatchRec,e2.date_recv as MatchDateRec,
e2.transactionid as MatchTranId,e2.PolicyID as MatchPolicyID,e2.CaseID as MatchCaseID,
e2.providerref as MatchPolicy,e2.FirstClientID as MatchClientID,
case when ex.status = 3 and ex.type not in (5,6) and t1.pacc_id is null then 'Missing'
when ex.status = 3 and ex.type not in (5,6) and t1.pacc_id is not null then 'Loaded' end as UnpaidStatus,
t1.UnpaidListDate,t1.Margin,t1.PaidListDate,
case t1.Exported when 'T' then 'Yes' when 'F' then 'No' end as BACSPaid,t1.BACSDate,t1.BACSAmount,
NULL as REC_ProviderType,
case when edh.id is null and cast(st.Total as decimal(15,2)) <> 0 then ex.Date_Recv
when edh.id is not null then ex.Date_Recv end as REC_LoadDate,
case when edh.id is null and cast(st.Total as decimal(15,2)) <> 0 and ex.Type in (5,6) then ex.Date_Recv 
when edh.id is not null and ex.Type in (5,6) then ex.Date_Recv end as REC_SuspenseDate,
case when edh.id is null and cast(st.Total as decimal(15,2)) <> 0 and ex.Type not in (5,6) 
and ex.SuspenseID is NULL then ex.Date_Recv
when edh.id is not null and ex.Type not in (5,6) and ex.SuspenseID is NULL then ex.Date_Recv
end as REC_AutomatchDate,
case when edh.id is null and cast(st.Total as decimal(15,2)) <> 0 and ex.Type in (5,6) 
and e2.id is not NULL then coalesce(su.CreatedDateTime,e2.Date_Recv)
when edh.id is not null and ex.Type in (5,6) and e2.id is not NULL 
then coalesce(su.CreatedDateTime,e2.Date_Recv) end as REC_MatchDate
--,*
into #Extract2
from mstt_expectation ex
left outer join msit_edifactcommissionstatementcontents edc on EDC.pacc_id = ex.id
left outer join msit_s_stmtct st on st.statement = ex.statement
left outer join msit_edifactcommissionstatementheader edh on edh.statementid = ex.statement
left outer join msit_s_paccsu su on su.susp_id = ex.id
left outer join mstt_expectation e2 on e2.id = su.init_id
left outer join #Processed t1 on t1.Pacc_ID = ex.id
where ex.id not in (select ExpID from owhot_PaymentAudit)
--order by ex.id

-- Insert non-EDI related Payments

Insert into owhot_PaymentAudit
(Statement,
EDIHeaderID,
StatementStatus,
StatementCreateDate,
StatementType,
EDILoadStatus,
EDIContentID,
EDIAmount,
PolicyNumber,
EDIClient,
EDIPayTypeDesc,
