EDIRefNo,
EDIReason,
Provider,
ExpID,
Type,
TypeDesc,
Status,
StatusDesc,
AmountDue,
DateDue,
AmountRec,
DateRec,
UnallocReasonCode,
UnallocReasonDesc,
TxnID,
PolicyID,
CaseID,
ExpPolicy,
ClientID,
SuspMatchAmt,
MatchDate,
MatchID,
MatchCategory,
MatchType,
MatchTypeDesc,
MatchStatus,
MatchStatusDesc,
MatchDue,
