BACSPaid,
BACSDate,
BACSAmount,
REC_ProviderType,
REC_LoadDate,
REC_SuspenseDate,
REC_AutomatchDate,
REC_MatchDate
)
Select Statement,
EDIHeaderID,
StatementStatus,
StatementCreateDate,
StatementType,
EDILoadStatus,
EDIContentID,
EDIAmount,
PolicyNumber,
EDIClient,
EDIPayTypeDesc,
EDIPayFreq,
EDIPolType,
EDICommType,
EDIPayType,
EDIPremTyp,
EDIPremium,
EDIAgentCode,
EDIRefNo,
EDIReason,
Provider,
ExpID,
Type,
TypeDesc,
Status,
StatusDesc,
AmountDue,
DateDue,
AmountRec,
DateRec,
UnallocReasonCode,
UnallocReasonDesc,
TxnID,
PolicyID,
CaseID,
ExpPolicy,
ClientID,
SuspMatchAmt,
MatchDate,
MatchID,
MatchCategory,
MatchType,
MatchTypeDesc,
MatchStatus,
MatchStatusDesc,
MatchDue,
MatchDateDue,
MatchRec,
MatchDateRec,
MatchTranId,
MatchPolicyID,
MatchCaseID,
MatchPolicy,
MatchClientID,
UnpaidStatus,
UnpaidListDate,
Margin,
PaidListDate,
BACSPaid,
BACSDate,
BACSAmount,
REC_ProviderType,
REC_LoadDate,
REC_SuspenseDate,
REC_AutomatchDate,
REC_MatchDate
from #Extract2

drop table #Extract2

drop  INDEX [#Processed].[ix_paccid]
drop table #Processed

 CREATE  INDEX [provider] ON [dbo].[owhot_PaymentAudit]([Provider]) ON [PRIMARY]


-- Set ProviderType
update owhot_PaymentAudit
set REC_ProviderType = case when pp.commrepproductprovidercode = 'ZURICH' then 1
          when pp.commrepproductprovidercode = 'STERLING' then 2
          when pp.commrepproductprovidercode = 'SCOT EQ' then 3
          when pp.commrepproductprovidercode = 'MORTGAGE' then 4
          else 0 end
from owhot_PaymentAudit pa
left outer join msit_CodeProdProviderReportingXref pp on pa.Provider = pp.ProductProviderCode


