 CREATE  INDEX [dailystats] ON [dbo].[owhot_PaymentAudit]([Statement], [ExpID], [REC_LoadDate], [REC_SuspenseDate], [REC_AutomatchDate], [REC_MatchDate], [Status], [REC_ProviderType], [StatementType], [AmountRec]) ON [PRIMARY]
