/****** Object:  StoredProcedure [dbo].[owhop_Q_CaseCheckListFirstRiskDueDate]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER OFF
GO


CREATE PROCEDURE [dbo].[owhop_Q_CaseCheckListFirstRiskDueDate] AS

if exists (select * from dbo.sysobjects where id = object_id(N'[dbo].[owhot_Q_CaseCheckListFirstRiskDueDate]') and OBJECTPROPERTY(id, N'IsUserTable') = 1)
drop table [dbo].[owhot_Q_CaseCheckListFirstRiskDueDate]
set nocount on

declare @Yesterday datetime
set @yesterday = CAST(CONVERT(NVARCHAR,dateadd(dd,-1,getdate()),112) as datetime)
declare @FirstofMonth datetime
set @FirstofMonth = convert(datetime,convert(nvarchar(6), @yesterday,112) + '01')
--declare @FirstNextMonth datetime
--set @FirstNextMonth = convert(datetime,convert(nvarchar(6), dateadd(mm,1,getdate()),112) + '01')

select policyid,max(id) as LastActive
into #LastActive
from mstt_policytransactions
where transtype in (1,17,23,45)
group by policyid

select pt.policyid,max(id) as LastProp,
max(case when id < t1.Lastactive then id end) as LastPropBeforeActive
into #LastProp
from mstt_policytransactions pt
left outer join #lastactive t1 on t1.policyid = pt.policyid
where transtype in (39)
group by pt.policyid

select cc.policy_id as PolId,cc.trackgroupid as TGID,min(ns.id) as RiskID
into #firstrisk
from mstt_casecheck cc
left outer join mstt_casenbccselection ns on cc.trackgroupid = ns.trackgroupid
--where cc.trackgroupid = 942430
group by cc.policy_id,cc.trackgroupid

select trackgroupid as TGID,min(followupdate) as DueDate
into #DueDate
from msit_trackitems
where followupdate is not null and trackgroupid is not null
group by trackgroupid

select 
po.policyref as CaseID,po.cont_num as ProviderRef,po.comp_code as Provider,
cc.productcode as Product,cc.requesteddate as CreateDate,t4.DueDate,
cc.compliancecategorycode as RegulatoryRegime,cc.nbccreferralreasoncode as ReferralCode,
ns.nbccselectionreasoncode as ReferralType,sr.description as ReferralName,
case when cc.requesteddate is not null then 1 else 0 end as Referred,
case cc.caseacceptedind when 1 then 1 else 0 end as Accepted,
case when cc.casecheckvalidateddate is not null then 1 else 0 end as InitCheckDone,
case when cc.finalcheckvalidateddate is not null then 1 else 0 end as FinCheckDone,
case when cc.doublecheckedby is not null then 1 else 0 end as QCDone,
case when cc.cleareddate is not null then 1 else 0 end as Cleared,
case when cc.trackgroupcode like 'APPL%' then 1 else 0 end as Appeal,
cc.NBCCStatus as InitCheckStatus,iu.Description as AcceptedBy,cc.NBCCFinalStatus as FinalCheckStatus,
cc.nbccinitialfailurereasondesc as InitCheckFailCode,
cc.nbccfinalfailurereasondesc as FinalCheckFailCode,cc.completedstatedescn as CompletedStatus,
cc.policy_id as PolicyID,cc.CaseAcceptedBy as AccByID,
cc.trackgroupid as TrackGroupID,ns.id as SelectID,pt.AgentCode,ag.DESCN as AdvisedByName,
coalesce(cc.proposaltransactionnumber,t5.LastPropBeforeActive,t5.LastProp) as TranID

into owhot_Q_CaseCheckListFirstRiskDueDate
from mstt_casecheck cc
left outer join mstt_casenbccselection ns on cc.trackgroupid = ns.trackgroupid
left outer join mstt_policies po on po.pol_num = cc.policy_id
left outer join msit_intusers iu on iu.id = cc.CaseAcceptedBy
left outer join msit_codenbccselectionreason sr on sr.code = ns.nbccselectionreasoncode
left outer join #firstrisk t3 on t3.polid = cc.policy_id and t3.tgid = cc.trackgroupid
and t3.Riskid = ns.id
left outer join #duedate t4 on t4.tgid = cc.trackgroupid
left outer join #lastprop t5 on t5.policyid = cc.policy_id
left outer join mstt_policytransactions pt 
on pt.id = coalesce(cc.proposaltransactionnumber,t5.LastPropBeforeActive,t5.LastProp)
left outer join mstt_agents ag on ag.code = pt.agentcode
where 
cc.requesteddate between @FirstofMonth and @yesterday
--coalesce(t4.duedate,cc.requesteddate) between @FirstofMonth and @yesterday
and cc.completedstate not in (2,3)
and (ns.id is null or t3.riskid is not null)

order by 
cc.compliancecategorycode,cc.nbccreferralreasoncode,ns.nbccselectionreasoncode,
cc.policy_id,ns.id,cc.trackgroupid


GO
/****** Object:  StoredProcedure [dbo].[owhop_Q_CaseCheckTotalsFirstRisk]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE PROCEDURE [dbo].[owhop_Q_CaseCheckTotalsFirstRisk] with recompile as

if exists (select * from dbo.sysobjects where id = object_id(N'[dbo].[owhot_Q_CaseCheckTotalsFirstRisk]') and OBJECTPROPERTY(id, N'IsUserTable') = 1)

drop table dbo.owhot_Q_CaseCheckTotalsFirstRisk 

declare @Yesterday datetime
set @yesterday = CAST(CONVERT(NVARCHAR,dateadd(dd,-1,getdate()),112) as datetime)
declare @FirstofMonth datetime
set @FirstofMonth = convert(datetime,convert(nvarchar(6), @yesterday,112) + '01')

set nocount on

select cc.policy_id as PolId,cc.trackgroupid as TGID,min(ns.id) as RiskID
into #firstrisk
from mstt_casecheck cc
left outer join mstt_casenbccselection ns on cc.trackgroupid = ns.trackgroupid
group by cc.policy_id,cc.trackgroupid

select trackgroupid as TGID,min(followupdate) as DueDate
into #DueDate
from msit_trackitems
where followupdate is not null and trackgroupid is not null
group by trackgroupid

select 
cc.policy_id,ns.nbccselectionreasoncode,cc.productcode,cc.trackgroupid,
cc.compliancecategorycode,cc.proposaltransactionnumber,ns.id as SelectID,
po.policyref as CaseID,po.cont_num as ProviderRef,po.comp_code as Provider,
case when cc.requesteddate is not null then 1 else 0 end as Referred,
case cc.caseacceptedind when 1 then 1 else 0 end as Accepted,
case when cc.casecheckvalidateddate is not null then 1 else 0 end as InitCheckDone,
case when cc.finalcheckvalidateddate is not null then 1 else 0 end as FinCheckDone,
case when cc.doublecheckedby is not null then 1 else 0 end as QCDone,
case when cc.cleareddate is not null then 1 else 0 end as Cleared,
case when cc.trackgroupcode like 'APPL%' then 1 else 0 end as Appeal,
case when cc.requesteddate is not null then 'Case Check' else 'Pre-Assess' end as TotalType,
cc.nbccstatus,cc.caseacceptedby,cc.nbccfinalstatus,cc.nbccreferralreasoncode,
cc.nbccinitialfailurereasoncode,cc.nbccfinalfailurereasoncode

into #monthcasecheck
from mstt_casecheck cc
left outer join mstt_casenbccselection ns on cc.trackgroupid = ns.trackgroupid
left outer join mstt_policies po on po.pol_num = cc.policy_id
left outer join #firstrisk t3 on t3.polid = cc.policy_id and t3.tgid = cc.trackgroupid
and t3.Riskid = ns.id
left outer join #duedate t4 on t4.tgid = cc.trackgroupid

where 
cc.requesteddate between @FirstofMonth and @yesterday
and cc.completedstate not in (2,3)
and (ns.id is null or t3.riskid is not null)

select 
po.policyref as CaseID,po.productcode as Product,po.regulation as RegulatoryCode,
po.NBCCReferralReasonCode as ReferralType,
case 
when ti.codetrackitemcode in ('NBQC018B') then 'Case Check Not Required' 
when ti.codetrackitemcode in ('NBQC018A') then 'Case Check Required' 
else ns.nbccselectionreasoncode
end as ReferralCode,
iu.description as CreatedBy,case when tg.requesteddate is not null then 1 else 0 end as Referred,
case when tg.caseacceptedby is not null then 1 else 0 end as Accepted,
case when tg.casecheckvalidateddate is not null then 1 else 0 end as InitCheckDone,
case when tg.finalcheckvalidateddate is not null then 1 else 0 end as FinCheckDone,
case when tg.doublecheckedby is not null then 1 else 0 end as QCDone,
case when tg.cleareddate is not null then 1 else 0 end as Cleared,
case when tg.description like 'case check for appeal%' then 1 else 0 end as Appeal,
case when tg.id is not null then 'Pre-Assess' else 'Case Check' end as TotalType
into #PreAssessGroups
from msit_trackgroups tg
inner join msit_trackitems ti on ti.trackgroupid = tg.id
left outer join mstt_policies po on po.pol_num = tg.policyid
left outer join msit_intusers iu on iu.name = tg.username
left outer join mstt_casenbccselection ns on ns.trackgroupid = tg.id

where 
tg.requesteddate between @Firstofmonth and @yesterday
and ((ti.codetrackitemcode in ('NBQC018B') and ti.completedstate in (1))
or (ti.codetrackitemcode in ('NBQC018A') and ti.completedstate in (0,1)))
and tg.completedstate not in (2,3)
and tg.policyid not in (select distinct policy_id from mstt_casecheck)


select t1.compliancecategorycode as RegulatoryRegime,
t1.nbccreferralreasoncode as ReferralType,t1.nbccselectionreasoncode as ReferralCode,
sr.description as ReferralName,t1.totaltype as CaseType,
sum(t1.referred) as TotalReferred,sum(t1.accepted) as TotalAccepted,
sum(t1.Initcheckdone) as TotalInitialCheckDone,sum(t1.fincheckdone) as TotalFinalCheckDone,
sum(t1.qcDone) as TotalQCDone,sum(t1.cleared) as TotalCleared,sum(t1.appeal) as TotalAppeal,
case when pc.code is null then 'N/A' else substring(pc.description,1,5) end as Quota
into owhot_Q_CaseCheckTotalsFirstRisk
from #monthcasecheck t1
left outer join msit_codenbccselectionreason sr on sr.code = t1.nbccselectionreasoncode
left outer join msit_Codebqupolicycategory pc on pc.code = t1.nbccselectionreasoncode
group by t1.compliancecategorycode,t1.nbccreferralreasoncode,t1.nbccselectionreasoncode,
t1.totaltype,sr.description,pc.description,pc.code
--order by t1.compliancecategorycode,t1.nbccreferralreasoncode,t1.nbccselectionreasoncode

--union
insert into owhot_Q_CaseCheckTotalsFirstRisk
select t2.regulatorycode as RegulatoryRegime,
t2.referraltype as ReferralType,
case when sr.description is null then 'Case Check' end as ReferralCode,
t2.referralcode as ReferralName,t2.totaltype as CaseType,
sum(t2.referred) as TotalReferred,sum(t2.accepted) as TotalAccepted,
sum(t2.Initcheckdone) as TotalInitialCheckDone,sum(t2.fincheckdone) as TotalFinalCheckDone,
sum(t2.qcDone) as TotalQCDone,sum(t2.cleared) as TotalCleared,sum(t2.appeal) as TotalAppeal,
case when pc.code is null then 'N/A' else substring(pc.description,1,5) end as Quota
--into owhot_Q_CaseCheckTotalsFirstRisk
from #preassessgroups t2
left outer join msit_codenbccselectionreason sr on sr.code = t2.referralcode
left outer join msit_Codebqupolicycategory pc on pc.code = sr.description
group by t2.regulatorycode,t2.referraltype,t2.referralcode,t2.totaltype,sr.description
,pc.description,pc.code

order by 5,1,2,3

return


GO
