CREATE PROCEDURE [dbo].[owhop_Q_SamplePolicies] with recompile as
set nocount on

if exists (select * from dbo.sysobjects where id = object_id(N'[dbo].[owhot_Q_SamplePolicies]') and OBJECTPROPERTY(id, N'IsUserTable') = 1)
drop table dbo.owhot_Q_SamplePolicies

CREATE TABLE [dbo].[owhot_Q_SamplePolicies] (
  [CaseID] [int] NULL ,
  [Product] [varchar] (100) COLLATE Latin1_General_CI_AS NULL ,
  [ProviderRef] [varchar] (100) COLLATE Latin1_General_CI_AS NULL ,
  [Type] [varchar] (100) COLLATE Latin1_General_CI_AS NULL ,
  [RegulatoryCode] [varchar] (100) COLLATE Latin1_General_CI_AS NULL ,
  [ReferralType] [varchar] (100) COLLATE Latin1_General_CI_AS NULL ,
  [Provider] [varchar] (100) COLLATE Latin1_General_CI_AS NULL ,
  [ReplaceSwitch] [varchar] (100) COLLATE Latin1_General_CI_AS NOT NULL 
) ON [PRIMARY]


declare @Yesterday datetime
set @yesterday = CAST(CONVERT(NVARCHAR,dateadd(dd,-1,getdate()),112) as datetime)

DECLARE product_cursor CURSOR
FOR
   select distinct ph.productcode from mstt_producthierarchy ph
   where producttype = 'SWIFT' and (regulationdefault = 'COB' or dualsalesprocess = 'Y')
   and productcode in (select distinct productcode from mstt_policies)
   and productcode in ('ZALP','ATP','LATP','DMC','LDMC','INV A/C','BONDS','IPP','LIPP','ISA','PEP',
           'LS','LLS','LLSP','GRPSTK','INDSTK','LSCOTSTK')
OPEN product_cursor
DECLARE @productcode varchar(8)
FETCH NEXT FROM product_cursor INTO @productcode
WHILE (@@FETCH_STATUS <> -1)
BEGIN
   IF (@@FETCH_STATUS <> -2)
   BEGIN   
insert into owhot_Q_SamplePolicies 
      SELECT top 50 policyref as CaseID,productcode as Product,cont_num as ProviderRef,
      case when po.pol_num is not null then 'Premium Over £250k' end as Type,
      po.regulation as RegulatoryCode,po.NBCCReferralReasonCode as ReferralType,
      po.comp_code as Provider,
      case when po.replacement = 0 then '' else ' ' end as ReplaceSwitch
      from mstt_policies po
      where po.pol_num not in (select distinct policy_id from mstt_casecheck where policy_id is not null)
      and po.productcode in ('ZALP','ATP','LATP','DMC','LDMC','IPP','LIPP','LS','LLS','LLSP',
           'GRPSTK','INDSTK','LSCOTSTK')
      and po.productcode = @productcode  and po.regulation = 'COB'
--      and (po.regulationdefault = 'COB' or (po.salesprocess = 0 and po.dualsalesprocess = 'Y'))
      and po.policyref is not null 
      and (po.replacement = 0 or po.replacement is null)
      and (po.undisclosedreplacement = 0 or po.undisclosedreplacement is null)
      and po.pol_num in (select distinct policyid from mstt_policytransactions
                         where transtype = 39 and amount > 249999.99
                         and createdatetime between 
                         convert(datetime,convert(nvarchar(6), @yesterday,112) + '01') and getdate())
      group by po.policyref,po.productcode,po.cont_num,po.pol_num,po.regulation,
               po.NBCCReferralReasonCode,po.comp_code,po.replacement
  
      UNION
--insert into owhot_Q_SamplePolicies 
      SELECT top 50 policyref as CaseID,productcode as Product,cont_num as ProviderRef,
      case when po.pol_num is not null then 'Premium Under £250k' end as Type,
      po.regulation as RegulatoryCode,po.NBCCReferralReasonCode as ReferralType,
      po.comp_code as Provider,
      case when po.replacement = 0 then '' else ' ' end as ReplaceSwitch
  from mstt_policies po
      where po.pol_num not in (select distinct policy_id from mstt_casecheck where policy_id is not null)
      and po.productcode in ('ZALP','ATP','LATP','DMC','LDMC','INV A/C','BONDS','IPP','LIPP',
             'LS','LLS','LLSP','GRPSTK','INDSTK','LSCOTSTK')
      and po.productcode = @productcode
      and po.policyref is not null and po.regulation = 'COB'
--      and (po.regulationdefault = 'COB' or (po.salesprocess = 0 and po.dualsalesprocess = 'Y'))
      and (po.replacement = 0 or po.replacement is null)
      and (po.undisclosedreplacement = 0 or po.undisclosedreplacement is null)
      and po.pol_num in (select distinct policyid from mstt_policytransactions
                         where transtype = 39 and amount < 250000.00                      
                         and createdatetime between 
                         convert(datetime,convert(nvarchar(6), @yesterday,112) + '01') and getdate())
      group by po.policyref,po.productcode,po.cont_num,po.pol_num,po.regulation,
               po.NBCCReferralReasonCode,po.comp_code,po.replacement
      UNION
--insert into owhot_Q_SamplePolicies 
      SELECT top 50 policyref as CaseID,productcode as Product,cont_num as ProviderRef,
      case when po.pol_num is not null then 'Replacement' end as Type,
      po.regulation as RegulatoryCode,po.NBCCReferralReasonCode as ReferralType,
      po.comp_code as Provider,
      case 
      when po.replacement = 1 then 'Rep Type A' 
      when po.replacement = 2 then 'Rep Type B' 
      when po.replacement = 3 then 'Rep Type C'
      when po.replacement = 0 and po.undisclosedreplacement = 4 then 'Undisclosed'
      when po.replacement = 0 and ppswitch = -1 then 'Switch'
      end as ReplaceSwitch
     from mstt_policies po
      where po.pol_num not in (select distinct policy_id from mstt_casecheck where policy_id is not null)
      and po.productcode in ('ISA','PEP')
      and po.productcode = @productcode
      and po.policyref is not null and po.regulation = 'COB'
--      and (po.regulationdefault = 'COB' or (po.salesprocess = 0 and po.dualsalesprocess = 'Y'))
      and (po.replacement <> 0 or po.undisclosedreplacement <> 0)
      and po.pol_num in (select distinct policyid from mstt_policytransactions
                         where transtype = 39 and amount < 250000.00                      
                         and createdatetime between 
                         convert(datetime,convert(nvarchar(6), @yesterday,112) + '01') and getdate())
      group by po.policyref,po.productcode,po.cont_num,po.pol_num,po.regulation,po.ppswitch,
               po.NBCCReferralReasonCode,po.comp_code,po.replacement,po.undisclosedreplacement
      order by 2,4,1
      --PRINT ' '
   END
   FETCH NEXT FROM product_cursor INTO @productcode
END
CLOSE product_cursor
DEALLOCATE product_cursor

GO
