CREATE  procedure [dbo].[owhop_SanctionsImport]
		@SanctionsFile  varchar(300),
		@Application	varchar(15)
as

/***********************************************************************************************

 Object  : procedure
 Name    : owhop_SanctionsImport
 Owner   : Paul Robathan
 Created : November 2009
 Project : Openwork Head Office Systems - Sanctions List

 The proc imports a sanctions text file into the staging table owhot_sanctionsLoad using BCP. 
 The date of the list is also loaded via BCP into table owhot_sanctionsloaddate.  The parameter
 to the proc, @SanctionsFile, is used to determine the file
 The second parameter @Application will have a value of OMS or Openwork. This
 will determine which matching process to call
 
	This proc is called as follows:
	
	exec owhop_SanctionsImport 
		@SanctionsFile='\\openwork.local\midb\MIDATA\HeadOfficeSystems\Extracts\sanctionsconlist110215.txt',
		@Application='Openwork'



 AMENDMENT HISTORY
 Date			Author	Description
 ----			------	-----------
 01/04/2011	P Robathan	Add processing around second parameter to cater for OMS being added.
 13/02/2015	A Groves	Added msp_ProcessLog auditing to identify where timeout problem is.
 13/06/2018	S Campbell	Remove XP Command shell processing and replace with a call to SSIS CR#21852

***********************************************************************************************/

Declare @String				varchar(4000),	
		@database			varchar(100),
		@server				varchar(100),
		@environ			varchar(50),
		@PhaseLog			varchar(50),	-- AG 13/02/2015
		@PhaseStart			varchar(50),	-- AG 13/02/2015
		@PhaseEnd			varchar(50),	-- AG 13/02/2015
		@Process			varchar(100),	-- AG 13/02/2015
		@Client				varchar(50),	-- AG 13/02/2015
		@Module				varchar(50),	-- AG 13/02/2015
		@Job				varchar(8000),   -- SC 11/06/2018
		@RunFlag			bit,		    -- SC 11/06/2018
		@StartTime			time,			-- SC 11/06/2018
		@TotalSanctions		int
		
-- AG 13/02/2015 Start	
set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @PhaseLog		= 'LOG'
set @Process		= object_name(@@procid)
set @Client			= 'Openwork'
set @Module			= 'Sanctions'
set @Job			= 'Head Office Systems - Import Sanctions'
set @RunFlag        = 1


exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client
-- AG 13/02/2015 End

exec owp_GetDatabaseDetails 'Openwork', 'Swift', @database output,
							@server output, @environ output



/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--CR#21852 set job running parameter
update	prod_zurich_openwork_datawarehouse.dbo.owt_GeneralPurposeParameters
	set Parameter1Value = @SanctionsFile,
		Parameter1Type = 'varchar(100)',
		DateUpdated = getdate()
where	ParameterSource = '[dbo].[owhop_SanctionsImport]'
and		ParameterFrom = 'Sanctions Import'
and		ParameterTo = 'SanctionsImport.dtsx' 

exec msp_ProcessLog @PhaseLog, '1) owhot_SanctionsLoad - Load & Load Date', null, @Module, @Client	-- AG 13/02/2015

--  set job control to 'job running' and clear down staging tables CR#21852
update prod_zurich_openwork_datawarehouse.dbo.owt_JobControl
set JobRunning = @RunFlag, DateLastUpdatedByCaller = GETDATE()
where JobCode = 'SANCTIONS-IMP'

truncate table Head_Office_Systems.dbo.owhot_sanctionsLoad
truncate table Head_Office_Systems.dbo.owhot_sanctionsloaddate

-- CR#21852 Run SQL agent job to import sanctions file
EXEC msdb..sp_start_job @job_name = @Job

-- Check whether load is still running from previous import  - if yes wait until it has completed

--CR#21852
set @StartTime =  CONVERT(TIME, GETDATE())

while @RunFlag = 1 and  DATEDIFF(MI,@starttime,CONVERT(TIME, GETDATE())) <= 5 -- only loop for 5 minutes before ending
 begin
 waitfor delay '00:00:01'
 select @RunFlag = jobrunning  
 from owt_JobControl 
 where JobCode = 'SANCTIONS-IMP'
 end


-- If no rows in sanctions table - end with error
Set @TotalSanctions =  (Select Count(*) From Head_Office_Systems.dbo.owhot_sanctionsLoad )
--print @TotalSanctions

IF @TotalSanctions = 0
BEGIN
exec msp_ProcessLog @PhaseLog, '0 sanctions loaded', null, @Module, @Client
        RETURN -1
END
exec msp_ProcessLog @PhaseLog,'2) More than 0 sanctions loaded', null, @Module, @Client
--  If load ok then continue

/*  Remove XP command shell processing   -CR#21852

--select @database,@server,@environ
truncate table Head_Office_Systems.dbo.owhot_sanctionsLoad

exec msp_ProcessLog @PhaseLog, '1) owhot_SanctionsLoad - Load', null, @Module, @Client	-- AG 13/02/2015

set @String = 'bcp "Head_Office_Systems.dbo.[owhot_sanctionsLoad]" in "' + @SanctionsFile + '" -c -t; -S' + @server + ' -F2 -T -E'
exec master..xp_cmd---shell @String

--select * from owhot_sanctionsLoad

truncate  table Head_Office_Systems.dbo.owhot_sanctionsloaddate

exec msp_ProcessLog @PhaseLog, '2) owhot_SanctionsLoadDate - Load', null, @Module, @Client	-- AG 13/02/2015

-- this loads the first record in the text file which is the file date set by the Treasury
set @String = 'bcp "Head_Office_Systems.dbo.[owhot_sanctionsloaddate]" in "' + rtrim(@SanctionsFile) + '" -c -t; -S' + @server + ' -L1 -T -E'
exec master..xp_cmd---shell @String
*/

exec msp_ProcessLog @PhaseLog, '2) owhot_SanctionsLoad - Clean', null, @Module, @Client	-- AG 13/02/2015

--  Tidy up Load Date table (remove all bar first row) CR#21852
exec msp_ProcessLog @PhaseLog, '3)  Delete non date data from sanctions loaddate table', null, @Module, @Client
delete from Head_Office_Systems.dbo.owhot_sanctionsloaddate
where DateTitle not like 'Last%'


--select * from owhot_sanctionsloaddate
-- remove blanks and apostrophe at the start of
update Head_Office_Systems.dbo.owhot_sanctionsload
set		DOB = ltrim(rtrim(DOB)),
		ListedOn = ltrim(rtrim(ListedOn)),
		LastUpdated = ltrim(rtrim(LastUpdated)),
		Name1 = case 
					when left(Name1,1) = '''' then substring(Name1,2,len(Name1)-1)
					else Name1
				end,
		Name2 = case 
					when left(Name2,1) = '''' then substring(Name2,2,len(Name2)-1)
					else Name2
				end,
		Name3 = case 
					when left(Name3,1) = '''' then substring(Name3,2,len(Name3)-1)
					else Name3
				end,
		Name4 = case 
					when left(Name4,1) = '''' then substring(Name4,2,len(Name4)-1)
					else Name4
				end,
		Name5 = case 
					when left(Name5,1) = '''' then substring(Name5,2,len(Name5)-1)
					else Name5
				end,
		Name6 = case 
					when left(Name6,1) = '''' then substring(Name6,2,len(Name6)-1)
					else Name6
				end

exec msp_ProcessLog @PhaseLog, '4) owhop_SanctionsLoad - Proc', null, @Module, @Client	-- AG 13/02/2015

exec owhop_SanctionsLoad

if @Application = 'OMS' 
begin
	exec msp_ProcessLog @PhaseLog, '5) owhop_SanctionsOMSMatch - Proc', null, @Module, @Client	-- AG 13/02/2015
	exec owhop_SanctionsOMSMatch
end
else
begin
	exec msp_ProcessLog @PhaseLog, '5) owhop_SanctionsMatch - Proc', null, @Module, @Client	-- AG 13/02/2015
	exec owhop_SanctionsMatch
end

exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client	-- AG 13/02/2015
GO
