CREATE  procedure [dbo].[owhop_SanctionsLoad]
as

--########################################################################
--
-- Object  : procedure
-- Name    : owhop_SanctionsLoad
-- Owner   : PR
-- Created : November 2009
-- Project : Openwork Head Office Systems - Sanctions List
--
-- The proc updates the sanctions file owhot_sanctions using the staging file owhot_sanctionsload.
-- 26/01/2022 S. Tourlidas updated according to the new guidelines and changed the insert statement to include the columns
--########################################################################

-- get the date of the file first and store for later
Declare @fileload as datetime
set @fileload = (select convert(datetime,FileUpdated,103) from Head_Office_Systems.dbo.owhot_sanctionsloaddate)  
--select @fileload

truncate  table Head_Office_Systems.dbo.owhot_sanctions


INSERT INTO Head_Office_Systems.dbo.owhot_sanctions
           ([Name6]
           ,[Name1]
           ,[FirstName]
           ,[Name2]
           ,[Name3]
           ,[Name4]
           ,[Name5]
           ,[Title]
           ,[NameNLScript]
           ,[NLScriptType]
           ,[NLScriptLanguage]
           ,[DOB]
           ,[BirthTown]
           ,[BirthCountry]
           ,[Nationality]
           ,[Passport]
           ,[PassportDetails]
           ,[NINumber]
           ,[NIDetails]
           ,[Position]
           ,[Address1]
           ,[Address2]
           ,[Address3]
           ,[Address4]
           ,[Address5]
           ,[Address6]
           ,[Postcode]
           ,[Country]
           ,[OtherInfo]
           ,[GroupType]
           ,[AliasType]
           ,[AliasQuality]
           ,[Regime]
           ,[ListedOn]
           ,[UKSanctionsListDesignatedDate]
           ,[LastUpdated]
           ,[GroupID]
           ,[FileCreated]
           ,[Created])

    
select  
	Name6,
	Name1,
	case 
		when charindex(' ', Name1) = 0 then rtrim(Name1)
		else LEFT(Name1, charindex(' ', Name1)-1)
	end as FirstName,
	Name2,
	Name3,
	Name4,
	Name5,
	Title,
	NameNLScript,
    NLScriptType,
    NLScriptLanguage,
	DOB,
	BirthTown,
	BirthCountry,
	Nationality,
	Passport,
	PassportDetails ,
	NINo as 'NINumber',
	NIDetails,
	Position, 
	Address1,
	Address2,
	Address3,
	Address4,
	Address5,
	Address6,
	Postcode,
	Country,
	OtherInfo,
	GroupType,
	AliasType, 
	AliasQuality,
	Regime,
	convert(datetime,ListedOn,103) as ListedOn,	
	convert(datetime,UKSanctionsListDesignatedDate,103) as UKSanctionsListDesignatedDate, 
	convert(datetime,LastUpdated,103) as LastUpdated,	
	cast(GroupID as bigint) as GroupID,
	@fileload as FileCreated,
	getdate() as Created
from Head_Office_Systems.dbo.owhot_sanctionsLoad



