/****** Object:  StoredProcedure [dbo].[owhop_SanctionsMatch]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/********************************************************************************************************
 Object  : procedure
 Name    : owhop_SanctionsMatch
 Owner   : PR
 Created : November 2009
 Project : Openwork Head Office Systems - Sanctions List

 The proc compares the sanctions file owhot_sanctions against the swift clients table
 and finds matches where Lastname and first Firstname are the same. If the Client already
 exists in the matched table then it is updated if there has been an update in the Treasury file
 otherwise it is inserted.  The sanctions list from the Treasury might have > 1 record for the
 same person because of dob differences or aliases and this is indicated by GroupId being
 the same for these records.  We however only want to one record to show and then compliance 
 can look at the excel fle to compare

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
19/05/2016	A Groves	SR434894. Performance improvement by replacing user defined function
						dbo.owf_GetEntryDelimited with native SQL Server functions.
						Also added run logging and error handling/reporting to the proc.
********************************************************************************************************/
CREATE procedure [dbo].[owhop_SanctionsMatch]
as

set nocount on

BEGIN TRY

	declare @PhaseStart					varchar(50),
			@PhaseEnd					varchar(50),
			@PhaseLog					varchar(50),
			@PhaseError					varchar(50),
			@Process					varchar(100),
			@ProcessMessage				varchar(100),
			@RowCount					int,
			@ErrMsg						varchar(400),
			@ErrMsgBrief				varchar(100), 
			@Severity 					int,
			@Client						varchar(50),
			@Module						varchar(50),
			@ErrNum						int,
			@ErrSev						int,
			@ErrLine					int,
			@ErrState					int

	set @PhaseStart		= 'START'
	set @PhaseEnd   	= 'END'
	set @PhaseLog		= 'LOG'
	set @PhaseError		= 'ERROR'
	set @Process		= object_name(@@procid)
	set @Client			= 'Openwork'
	set @Module			= 'Sanctions'

	exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

	-- update existing matched cases where the details from the Treasury have been updated, as
	-- indicated by LastUpdated being greated than the stored Lastupdated
	update m
	set
		Refer = c.Refer,
		Client_Title = c.Title,
		Client_FirstName = c.firstnames,
		Client_LastName = c.name,
		Client_DOB = c.Birthdate,
		Name6 = s.Name6,
		Name1 = s.Name1,
		Title = s.Title,
		DOB = s.DOB,
		GroupID = s.GroupID,
		FileCreated = s.FileCreated,
		LastUpdated = s.LastUpdated,
		Processed = 0,
		ProcessedDate = NULL
	from Head_Office_Systems.dbo.owhot_SanctionsMatched m
	inner join mstt_clients c on c.Client_Num = m.Client_Num
	inner join Head_Office_Systems.dbo.owhot_Sanctions s on s.Name6 = m.Name6 and s.Name1 = m.Name1 and s.GroupID = m.GroupID
	where m.LastUpdated < s.LastUpdated

	set @RowCount = @@rowcount
	set @ProcessMessage = 'Update. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client


	-- Now insert new matched cases

	insert into Head_Office_Systems.dbo.owhot_SanctionsMatched
	select distinct
		c.client_num as Client_Num,
		c.Refer as Refer,
		c.Title as Client_Title,
		c.firstnames as Client_FirstName,
		c.name as Client_LastName,
		c.Birthdate as Client_DOB,
		s.Name6 as Name6,
		s.Name1 as Name1,
		s.Title as Title,
		s.DOB as DOB,
 		s.GroupID as GroupID,
		s.FileCreated as FileCreated,
		s.LastUpdated as MatchedDate,
		0 as Processed,
		NULL as ProcessedDate,
		NULL as Comment
	from Head_Office_Systems.dbo.owhot_Sanctions s
		 inner join mstt_clients c 
                    on  ltrim(rtrim(s.Name6)) = ltrim(rtrim(c.name))	-- AG 19/05/2016
                    --and isnull(dbo.owf_GetEntryDelimited([firstnames], 1, ' ', 'N'),'')  = isnull(s.FirstName,'')		AG 19/05/2016
                    and SUBSTRING(ltrim(rtrim(FirstNames)),1,case when patindex('% %',ltrim(rtrim(FirstNames)))-1 > 1 then patindex('% %',ltrim(rtrim(FirstNames)))-1 else LEN(ltrim(rtrim(FirstNames))) end) = isnull(ltrim(rtrim(s.FirstName)),'')	-- AG 19/05/2016
	where not exists (select * from Head_Office_Systems.dbo.owhot_SanctionsMatched m where m.Client_Num = c.client_num)

	set @RowCount = @@rowcount
	set @ProcessMessage = 'Insert. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;      
	set @ErrMsgBrief = left(@ErrMsg,100)
	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	
END CATCH

exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client
GO
/****** Object:  StoredProcedure [dbo].[owhop_SanctionsOMSMatch]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE  procedure [dbo].[owhop_SanctionsOMSMatch]
as

--########################################################################
--
-- Object  : procedure
-- Name    : owhop_SanctionsOMSMatch
-- Owner   : PR
-- Created : April 2010
-- Project : Openwork Head Office Systems - Sanctions List
--
-- The proc compares the sanctions file owhot_sanctions against the OMS swift clients table
-- and finds matches where Lastname and first Firstname are the same. If the Client already
-- exists in the matched table then it is updated if there has been an update in the Treasury file
-- otherwise it is inserted.  The sanctions list from the Treasury might have > 1 record for the
-- same person because of dob differences or aliases and this is indicated by GroupId being
-- the same for these records.  We however only want to one record to show and then compliance 
-- can look at the excel fle to compare
--########################################################################

-- update existing matched cases where the details from the Treasury have been updated, as
-- indicated by LastUpdated being greated than the stored Lastupdated
update m
set
	Refer = c.Refer,
	Client_Title = c.Title,
	Client_FirstName = c.firstnames,
	Client_LastName = c.name,
	Client_DOB = c.Birthdate,
	Name6 = s.Name6,
	Name1 = s.Name1,
	Title = s.Title,
	DOB = s.DOB,
	GroupID = s.GroupID,
	FileCreated = s.FileCreated,
	LastUpdated = s.LastUpdated,
	Processed = 0,
	ProcessedDate = NULL
from Head_Office_Systems.dbo.owhot_SanctionsOMSMatched m
inner join omst_S_CLIENT c on c.Client_Num = m.Client_Num
inner join Head_Office_Systems.dbo.owhot_Sanctions s on s.Name6 = m.Name6 and s.Name1 = m.Name1 and s.GroupID = m.GroupID
where m.LastUpdated < s.LastUpdated

-- Now insert new matched cases

insert into Head_Office_Systems.dbo.owhot_SanctionsOMSMatched
select distinct
	c.client_num as Client_Num,
	c.Refer as Refer,
	c.Title as Client_Title,
	c.firstnames as Client_FirstName,
	c.name as Client_LastName,
	c.Birthdate as Client_DOB,
	s.Name6 as Name6,
	s.Name1 as Name1,
	s.Title as Title,
	s.DOB as DOB,
 	s.GroupID as GroupID,
	s.FileCreated as FileCreated,
	s.LastUpdated as MatchedDate,
	0 as Processed,
	NULL as ProcessedDate,
	NULL as Comment
from Head_Office_Systems.dbo.owhot_Sanctions s
inner join omst_S_CLIENT c on  rtrim(s.Name6) = rtrim(c.name) and isnull(dbo.owf_GetEntryDelimited([firstnames], 1, ' ', 'N'),'')  = isnull(s.FirstName,'') 
where not exists (select * from Head_Office_Systems.dbo.owhot_SanctionsOMSMatched m where m.Client_Num = c.client_num)


GO
