/****** Object:  StoredProcedure [dbo].[owhop_SupervisionChargesCalculation]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

/********************************************************************************************************

 Object  : procedure
 Name    : owhop_SupervisionChargesCalculation.sql
 Owner   : MPC
 Created : 2 April 2007
 Project : Openwork Head Office Systems - Charges Application 

 Procedure operates with three parameters:

 @RecalcFlag 
 Has three settings:

 'Y' : this recalculates the Supervision Charges for the Recalc Commission Statement period supplied.
 When called from the Charge Admin page this is set to lastest month on Supervision table.
 This is the only setting used from the Charge Admin page. 
 Deletes and reinserts entries on owhot_SupervisorChargesBusiness for the Recalc Period only.
 Deletes and reinserts entries on owhot_SupervisorChargesSellers for the Recalc Period only.

 'N' : used for Ad Hoc back population of previous periods. 
 Deletes and reinserts entries on owhot_SupervisorChargesBusiness for the Recalc Period only.
 Deletes and reinserts entries on owhot_SupervisorChargesSellers for the Recalc Period only.

 'B' : used when procedure is run in Warehouse daily batch schedule
 Defaults to latest closed Commission Month.
 On first day when procedure detects a new closed Commission period for which data is not present
 then insers data into owhot_SupervisorChargesBusiness and owhot_SupervisorChargesSellers tables.
 
 @RecalcMonth
 Determines Commission Period for which data to be updated.
 If not set to first of month then procedure defaults to last closed Commission Period.
 Defaulted to getdate when procedure is run in Warehouse daily batch schedule
 Cannot be later than last closed Commission Period or earlier than '1 Feb 2007' (Jan 2007)
 
 @UpdatedBy
 Denotes the Portal Id (without Domain) of user requesting run. Defaults to 'Automatic'.

AMENDMENT HISTORY
=================

Date		Author			Description
----		------			-----------
17/11/2014	A Groves		SR346635 - Remove Owl businesses which are not subject to supervision charges.
28/03/2017	A Groves		SR464996/CH16204. Replace DTS script with start-of-job that contains a SSIS
							replacement script for DTS script "SupervisionChargeStandingOrderTriggerExtract.dtsx".
13/04/2022  P Reed          R57925 - Allow inclusion of OWL supervisors for OpenWork firms 6 changes PFRCHANGE
21/03/2025  P Reed          R302430  - Charge non selling Practice Principals
12/06/2025  P Reed          R327865 - Add exclusions to the supervision charge (using swift notes tables)
*********************************************************************************************************/
CREATE procedure [dbo].[owhop_SupervisionChargesCalculation]
    @RecalcFlag  varchar(1) = 'N',
    @RecalcMonth datetime   = '1 Jan 1900',
    @UpdatedBy   varchar(10) = 'Automatic'
with recompile
as

declare @OwlManager2Code varchar(7)					-- AG 17/11/2014

select  @OwlManager2Code = cde.Code					-- AG 17/11/2014
from	msit_MIWarehouseCodesAndDescriptions cde	
where	cde.ColumnName = 'Manager2Code' 
and		cde.Description = 'Owl Financial'

-- DEFINE RUN DATES
declare @RunDateTime datetime
set @RunDateTime = getdate()

declare @Yesterday datetime
set @yesterday = CAST(CONVERT(NVARCHAR,dateadd(dd,-1,getdate()),112) as datetime)

declare @LastCalendarMonth datetime
set @LastCalendarMonth = (select max(Month) from msit_CommissionStatementPeriods where OSCAREndDate <= @yesterday)

declare @LastChargeMonth datetime
set @LastChargeMonth = (select isnull(max(Month),'1 Jan 1901') from owhot_SupervisorChargeBusiness) 

-- Default Run Month to last closed Commission Month
declare @RunMonth datetime
Set @RunMonth = @LastCalendarMonth

-- Override default Run Month with Recalc Month if valid
IF @RecalcMonth < @LastCalendarMonth  -- Recalc Date cannnot be later than last closed period
and @RecalcMonth > '1 Jan 2007'   -- Recalc Date cannot refer to a Commission Period earlier then 2007
and datepart(dd,@RecalcMonth) = 1 -- Recalc Date must be dated first of month
and @RecalcFlag <> 'B'      -- Do not reset for Batch run
BEGIN
Set @RunMonth = (Select Month from msit_CommissionStatementPeriods where @RecalcMonth = Month)
END

declare @StartDate datetime
set @StartDate = (select OSCARStartDate from msit_CommissionStatementPeriods where Month = @RunMonth)

declare @EndDate datetime
set @EndDate = (select OSCAREndDate from msit_CommissionStatementPeriods where Month = @RunMonth)

declare @LeaverDate datetime  -- Include Leavers within last 6 months
set @LeaverDate = dateadd(mm,-6,@startdate)

If @RecalcFlag <> 'B' OR (@RecalcFlag = 'B' AND @LastChargeMonth < @RunMonth)
BEGIN

-- Extract appropriate Business and Seller Details into Agents table ----------------

select AG.Code,AG.Firm,AG.AgentTYpe,AG.CompetentStatus,AG.DateLeaving,AG.CanSupervise,AG.GivesAdvice,
AG.AgentCategory,AG.AgentCategoryDescription,AG.DateStarted,AG.OscarDateStarted,AG.CDIStatusDate,
AG.spansupervisorCode,ag.Manager2Code  --PFRCHANGE1 13/04/2022 add manager2code
into #Agents 
from mstt_agents AG
where 1=0

END

-- If not processing Last Calendar Month extract Agent Details as at end of Run Month from Agents History table
IF @RunMonth <> @LastCalendarMonth AND @RecalcFlag <> 'B'
BEGIN

select Code,max(ValidFromDate) as EffDate
into #AgentDate
from mstt_AgentsHistory
where AgentType in (2,46,49,3,4,5,43,45,51,52,53,54,55) -- Business, Seller and Manager Types only 
and ValidFromDate <= @EndDate
--and Manager2Code <> @OwlManager2Code			-- AG 17/11/2014 ----PFRCHANGE2 13/04/2022 comment out
Group by Code
Order by Code

insert into #Agents
select AGH.Code,AGH.Firm,AGH.AgentTYpe,AGH.CompetentStatus,AGH.DateLeaving,AGH.CanSupervise,AGH.GivesAdvice,
AGH.AgentCategory,AGH.AgentCategoryDescription,AGH.DateStarted,AGH.OscarDateStarted,AGH.CDIStatusDate,
AGH.spansupervisorCode,agh.Manager2Code  --PFRCHANGE3 13/04/2022 add manager2code
from mstt_AgentsHistory AGH
inner join #AgentDate AGD on AGD.Code = AGH.Code and AGD.EffDate = AGH.ValidFromDate
order by AGH.Code

drop table #AgentDate

END

-- If processing Last Calendar Month Extract Agent Details as at end of Run Month from mstt_Agents
IF (@RunMonth = @LastCalendarMonth AND @RecalcFlag <> 'B') OR (@RecalcFlag = 'B' AND @LastChargeMonth < @RunMonth)
BEGIN

insert into #Agents
select AG.Code,AG.Firm,AG.AgentTYpe,AG.CompetentStatus,AG.DateLeaving,AG.CanSupervise,AG.GivesAdvice,
AG.AgentCategory,AG.AgentCategoryDescription,AG.DateStarted,AG.OscarDateStarted,AG.CDIStatusDate,
AG.spansupervisorCode,ag.Manager2Code  --PFRCHANGE4 13/04/2022 add manager2code
from mstt_Agents AG
--where AG.Manager2Code <> @OwlManager2Code			-- AG 17/11/2014 -- PFRCHANGE5 13/04/2022 comment out
order by AG.Code
END

--- END of Agent processing --------------

-- Start of Update processing

IF @RecalcFlag = 'N' 
OR (@RunMonth = @LastCalendarMonth AND @RecalcFlag = 'Y')
OR (@RecalcFlag = 'B' AND @LastChargeMonth < @RunMonth)
-- Recalc N or Processing Last Calendar Month
BEGIN

-- Clear down existing data for the Month to be Loaded
DELETE from owhot_SupervisorChargeBusiness where Month = @RunMonth
DELETE from owhot_SupervisorChargeSellers  where Month = @RunMonth

-- Insert Business details into Supervision Business Table (Franchises and Access Agents)
INSERT into owhot_SupervisorChargeBusiness
(BusinessCode,Month,LastUpdated,UpdatedBy,
TotalCharge,ChargeEffDate,ChargeCalcDate,GICount,ICOBCount,
MortgageCount,PenInvCount,PracPrinCount,SupervisorCount,TotalChargedCount)
select 
Code,     -- BusinessCode
@RunMonth,    -- Month
@RunDateTime,   -- LastUpdated
@UpdatedBy,   -- UpdatedBy
NULL,     -- TotalCharge
NULL,     -- ChargeEffDate
NULL,     -- ChargeCalcDate
NULL,     -- GICount
NULL,     -- ICOBCount
NULL,     -- MortgageCount
NULL,     -- PenInvCount
NULL,     -- PracPrinCount
NULL,     -- SupervisorCount
NULL      -- TotalChargedCount
from #Agents
where AgentType in (2,46)
and (CompetentStatus = 1 
     or (CompetentStatus = 2 and CDIStatusDate >= @LeaverDate))
	  and manager2code!=@OwlManager2Code   --PFRCHANGE6  --add line so only adds the OPENWORK FIRMS 13/04/2022

-- Insert Seller details into Supervison Seller Table
INSERT into owhot_SupervisorChargeSellers
(BusinessCode,Month,LastUpdated,UpdatedBy,AgentCharge,ChargeEffDate,ChargeCalcDate,
Code,Status,StatusDesc,CanSupervise,GivesAdvice,Category,CategoryDesc,DateStarted,DateLeft,
StatusDate,Type,TypeDesc,Transfer,TransferFirm,TranEffDate,SupervisedBy,SupervisorType,
Comp_PenInv,Comp_Mort,Comp_ICOB,Comp_GI,ChargeType)
select 
AG.Firm,      -- BusinessCode
@RunMonth,      -- Month
@RunDateTime,     -- LastUpdated
@UpdatedBy,     -- UpdatedBy
NULL,       -- AgentCharge
NULL,       -- ChargeEffDate
NULL,       -- ChargeCalcDate
AG.Code,      -- Seller Code
AG.CompetentStatus,   -- Status
case AG.CompetentStatus when 1 then 'Active' when 2 then 'Left' when 3 then 'Dead'
when 4 then 'Canc' when 5 then 'PreApp' when 6 then 'NPW' end,  --StatusDesc
case AG.CanSupervise when 1 then 'Y' else 'N' end,    -- CanSupervise
case AG.GivesAdvice when 'Y' then 'Y' else 'N' end,   -- GivesAdvice
AG.AgentCategory,   -- Category
AG.AgentCategoryDescription,  -- CategoryDesc
coalesce(AG.OscarDateStarted,AG.DateStarted),     -- DateStarted
AG.DateLeaving,     -- DateLeft
AG.CDIStatusDate,   -- StatusDate
AG.AgentType,     -- Type
case AG.AgentType when 3 then 'IAR' when 4 then 'PFA' when 5 then 'Admin' when 43 then 'Prac Prin' 
when 45 then '10% Share' when 51 then 'PFA Prin' end,   -- TypeDesc
NULL,       -- Transfer
NULL,       -- TransferFirm
NULL,       -- TranEffDate
AG.SpanSupervisorCode,    -- SupervisedBy
NULL,       -- SupervisorType
NULL,       -- Comp_PenInv
NULL,       -- Comp_Mort
NULL,       -- Comp_ICOB
NULL,       -- Comp_GI
NULL        -- ChargeType
from #Agents AG
inner join owhot_SupervisorChargeBusiness SB on SB.BusinessCode = AG.Firm
where AG.AgentType in (3,4,5,43,45,51)
and (AG.CompetentStatus in (1,5) 
     or (AG.CompetentStatus in (2,3) and AG.CDIStatusDate >= @LeaverDate))
and SB.Month = @RunMonth

-- Extract Seller Moves in Period
Select AgentCode as Seller,DetailAgentCode as Business,ParticipantType as RelType,StartDate,EndDate,Status,DefaultValue
into #SellerMoves
from msit_AgentHierarchyHistory
where ParticipantType in (6,7,8,9)    -- Business/Seller Relationship
and EndDate between @StartDate and @EndDate -- Relationship ended in period
and DefaultValue = 1        -- Valid Relationship
--and (datepart(yy,startdate) <> datepart(yy,enddate)   -- Start/End in Diff Year
--     or datepart(mm,startdate) = datepart(mm,enddate))  -- Start/End in Diff Year
order by AgentCode

-- Identify earliest and Latest Moves in Period
-- Need to do this to ignore Transfers within Period
Select Seller,Min(EndDate) as FirstDate,Max(EndDate) as LastDate
into #SellerDates
from #SellerMoves
group by Seller
order by Seller

-- Update Seller Transfer In Details for Current Business (as at end of Period)
update owhot_SupervisorChargeSellers
set Transfer     = 'In',
    TransferFirm = t2.Business,
    TranEffDate  = dateadd(dd,1,t1.LastDate)  -- Add one day to give Start Date
from owhot_SupervisorChargeSellers SS
inner join #SellerDates t1 on t1.Seller = SS.Code
inner join #SellerMoves t2 on t2.Seller = t1.Seller and t1.LastDate = t2.EndDate
where SS.Month = @Runmonth 
and SS.BusinessCode <> t2.Business

-- Insert Transfer Out Seller row for Previous Business (as at Start of Period)
INSERT into owhot_SupervisorChargeSellers
(BusinessCode,Month,LastUpdated,UpdatedBy,AgentCharge,ChargeEffDate,ChargeCalcDate,
Code,Status,StatusDesc,CanSupervise,GivesAdvice,Category,CategoryDesc,DateStarted,DateLeft,
StatusDate,Type,TypeDesc,Transfer,TransferFirm,TranEffDate,SupervisedBy,SupervisorType,
Comp_PenInv,Comp_Mort,Comp_ICOB,Comp_GI,ChargeType)
select 
t2.Business,      -- BusinessCode
@RunMonth,      -- Month
@RunDateTime,     -- LastUpdated
@UpdatedBy,     -- UpdatedBy
NULL,       -- AgentCharge
NULL,       -- ChargeEffDate
NULL,       -- ChargeCalcDate
AG.Code,      -- Seller Code
AG.CompetentStatus,   -- Status
case AG.CompetentStatus when 1 then 'Active' when 2 then 'Left' when 3 then 'Dead'
when 4 then 'Canc' when 5 then 'PreApp' when 6 then 'NPW' end,      --StatusDesc
case AG.CanSupervise when 1 then 'Y' else 'N' end,        -- CanSupervise
case AG.GivesAdvice when 'Y' then 'Y' else 'N' end,       -- GivesAdvice
AG.AgentCategory,   -- Category
AG.AgentCategoryDescription,  -- CategoryDesc
coalesce(AG.OscarDateStarted,AG.DateStarted),         -- DateStarted
AG.DateLeaving,     -- DateLeft
AG.CDIStatusDate,   -- StatusDate
AG.AgentType,     -- Type
case AG.AgentType when 3 then 'IAR' when 4 then 'PFA' when 5 then 'Admin' when 43 then 'Prac Prin' 
when 45 then '10% Share' when 51 then 'PFA Prin' end,       -- TypeDesc
'Out',        -- Transfer
AG.Firm,      -- TransferFirm
t1.FirstDate,     -- TranEffDate
AG.SpanSupervisorCode,    -- SupervisedBy
NULL,       -- SupervisorType
NULL,       -- Comp_PenInv
NULL,       -- Comp_Mort
NULL,       -- Comp_ICOB
NULL,       -- Comp_GI
NULL        -- ChargeType
from #Agents AG
inner join #SellerDates t1 on t1.Seller = Code
inner join #SellerMoves t2 on t2.Seller = t1.Seller and t1.FirstDate = t2.EndDate
where t2.Business <> AG.Firm

-- update supervisorType
update owhot_SupervisorChargeSellers
set SupervisorType = case when AG.AgentType in ('52','53','54','55') then 'Manager' 
        when AG.AgentType in ('3','4','5','43','45','51') then 'Prac Super'
        else 'Other' end
from owhot_SupervisorChargeSellers SS
inner join #Agents AG on AG.Code = SS.SupervisedBy
where SS.Month = @RunMonth

-- Extract Seller Competency Details for Period
select act.ID,act.AgentCode,act.CodeComplianceCategoryID as CategoryID,
case act.CodeComplianceCategoryID 
when 1 then 'ICOB' when 2 then 'GI' when 3 then 'Mort' when 4 then 'PenInv' end as Category,
act.AgentControlFunctionCode as StatusCode,case act.AgentControlFunctionCode 
when 'FC' then 'Full' when 'IC' then 'Interim' when 'NA' then 'N/A' when 'NC' then 'Not'
when 'S1' then 'Stage 1' when 'SC' then 'Suspended' when 'SS' then 'Sick/Mat' else 'N/A'
end as Status,act.DateAppointed,act.AchievedDate,isnull(act.EndDate,'31 Dec 2999') as EndDate,aci.DateCreated
into #Competencies
from mstt_agentCompetence act
inner join msit_agentCompetence aci on aci.id = act.id
where act.CodeComplianceCategoryID in (1,2,3,4)
and (act.EndDate is null or act.EndDate >= @StartDate)
Order by act.AgentCode,act.CodeComplianceCategoryID,act.ID

-- Apply Seller Competencies to Seller Table
/*
update owhot_SupervisorChargeSellers
set Comp_PenInv   = case when t1.CategoryID = 4 and t1.EndDate <= @EndDate then 'Ended' 
       when t1.CategoryID = 4 and t1.EndDate > @EndDate then t1.Status end,
    Comp_Mort     = case when t1.CategoryID = 3 and t1.EndDate <= @EndDate then 'Ended' 
       when t1.CategoryID = 3 and t1.EndDate > @EndDate then t1.Status end,
    Comp_ICOB     = case when t1.CategoryID = 1 and t1.EndDate <= @EndDate then 'Ended' 
       when t1.CategoryID = 1 and t1.EndDate > @EndDate then t1.Status end,
    Comp_GI       = case when t1.CategoryID = 2 and t1.EndDate <= @EndDate then 'Ended' 
       when t1.CategoryID = 2 and t1.EndDate > @EndDate then t1.Status end
from owhot_SupervisorChargeSellers SS
inner join #Competencies t1 on t1.AgentCode = SS.Code
where SS.Month = @Runmonth 
*/

update owhot_SupervisorChargeSellers
set Comp_PenInv   = case when t1.CategoryID = 4 and t1.EndDate <= @EndDate then 'Ended' 
       when t1.CategoryID = 4 and t1.EndDate > @EndDate then t1.Status end
from owhot_SupervisorChargeSellers SS
inner join #Competencies t1 on t1.AgentCode = SS.Code and t1.CategoryID = 4
where SS.Month = @Runmonth 

update owhot_SupervisorChargeSellers
set Comp_Mort     = case when t1.CategoryID = 3 and t1.EndDate <= @EndDate then 'Ended' 
       when t1.CategoryID = 3 and t1.EndDate > @EndDate then t1.Status end
from owhot_SupervisorChargeSellers SS
inner join #Competencies t1 on t1.AgentCode = SS.Code and t1.CategoryID = 3
where SS.Month = @Runmonth 

update owhot_SupervisorChargeSellers
set Comp_ICOB    = case when t1.CategoryID = 1 and t1.EndDate <= @EndDate then 'Ended' 
      when t1.CategoryID = 1 and t1.EndDate > @EndDate then t1.Status end
from owhot_SupervisorChargeSellers SS
inner join #Competencies t1 on t1.AgentCode = SS.Code and t1.CategoryID = 1
where SS.Month = @Runmonth 

update owhot_SupervisorChargeSellers
set Comp_GI   =    case when t1.CategoryID = 2 and t1.EndDate <= @EndDate then 'Ended' 
      when t1.CategoryID = 2 and t1.EndDate > @EndDate then t1.Status end
from owhot_SupervisorChargeSellers SS
inner join #Competencies t1 on t1.AgentCode = SS.Code and t1.CategoryID = 2
where SS.Month = @Runmonth 

-- Derive Seller Charge Type
update owhot_SupervisorChargeSellers
set ChargeType = case
     when SS.Type in (43,51) and SS.GivesAdvice = 'Y' and SS.SupervisorType = 'Manager' then 'PP'
     when SS.Type in (43,51) and SS.CanSupervise = 'Y' and SS.SupervisorType = 'Manager' then 'NS Sup'
     when SS.Type not in (43,51) and SS.CanSupervise = 'Y' and SS.SupervisorType = 'Manager' then 'PFA Sup'
     when SS.GivesAdvice = 'Y' and SS.Comp_PenInv not in ('N/A','Not') and SS.SupervisorType = 'Manager' then 'P&I'
     when SS.GivesAdvice = 'Y' and SS.Comp_Mort not in ('N/A','Not') and SS.SupervisorType = 'Manager' then 'Mort'
     when SS.GivesAdvice = 'Y' and SS.Comp_ICOB not in ('N/A','Not') and SS.SupervisorType = 'Manager' then 'ICOB'
     when SS.GivesAdvice = 'Y' and SS.Comp_GI not in ('N/A','Not') and SS.SupervisorType = 'Manager' then 'GI' 
	 --when SS.Type in (43) and SS.GivesAdvice = 'N' and SS.SupervisorType = 'Manager' and @runmonth>='2025-04-01 00:00:00.000' then 'PP' --R302430  PFR 2025
     --WHEN ss.TYpe in (43,51) and NOT (SS.supervisortype is null and SS.GivesAdvice='Y' and SS.CanSupervise='N') and @runmonth>='2025-04-01 00:00:00.000' then 'PP'  --R302430  PFR 2025
	 WHEN ss.TYpe in (43,51) and NOT ((SS.supervisortype is null or SS.SupervisorType='Prac Super') and SS.GivesAdvice='Y' and SS.CanSupervise='N') and @runmonth>='2025-04-01 00:00:00.000' then 'PP'  --R302430  PFR 2025
	 end
from owhot_SupervisorChargeSellers SS
where SS.Month = @Runmonth
and ( SS.Status = 1 or (SS.Status in (2,3) and SS.StatusDate >= @StartDate) ) -- Active or Inactive this Period
and isnull(SS.Transfer,'No') <> 'In'  -- Did not Transfer INTO Business during Period
and SS.DateStarted < @StartDate   -- Include if Start Date earlier than Period Start Date

drop table #SellerDates
drop table #SellerMoves
drop table #Competencies
drop table #Agents

END

-- END of Business/Seller Update Processing------------------------------------------------------------------

-- Access Charges Table and find Prevailing Supervision Charges
select max(Month) as ChargeMonth 
into #ChargeMonth 
from owhot_OpenworkCharges 
where Month <= @RunMonth

select t1.ChargeMonth,OC.UpdatedBy,OC.DateUpdated,@RunMonth as RunMonth,
OC.PracPrincharge,OC.PenInvCharge,OC.MortgageCharge,OC.ICOBCharge,OC.GICharge
into #SupCharges
from owhot_OpenworkCharges OC
inner join #ChargeMonth t1 on OC.Month = t1.ChargeMonth



--new code June 2025 R327865
--move exclusions to their own exclusion table along with the notes from agent_notes
--add to exclusions table each run (so we have a full list of every time this was run)
	IF OBJECT_ID('tempdb..#exclusions') IS NOT NULL
    DROP TABLE #exclusions
	IF OBJECT_ID('tempdb..#exclusions1') IS NOT NULL   --exclusions1 is the deduped version
    DROP TABLE #exclusions1

	select * into #exclusions from prod_zurich_openwork_datawarehouse.dbo.mstt_agentnotes
	where subject like '%RSC_EXEMPT%' 

	select * into #exclusions1 from #exclusions a
	where subject like '%RSC_EXEMPT%' 
	AND ID IN (select max(id) from  #exclusions b where a.AgentCode=b.AgentCode and a.Subject like '%RSC_EXEMPT%' and b.Subject like '%RSC_EXEMPT%')
	--so at this point #exclusions1 is de-duped


insert into [dbo].[owhot_SupervisorChargeExclusions]
	([BusinessCode] ,
	[Month],
	[LastUpdated],
	[UpdatedBy],
	[AgentCharge],
	[ChargeEffDate] ,
	[ChargeCalcDate],
	[Code],
	[Status],
	[StatusDesc],
	[CanSupervise],
	[GivesAdvice],
	[Category],
	[CategoryDesc],
	[DateStarted],
	[DateLeft],
	[StatusDate],
	[Type],
	[TypeDesc],
	[Transfer],
	[TransferFirm],
	[TranEffDate],
	[SupervisedBy],
	[SupervisorType],
	[Comp_PenInv],
	[Comp_Mort],
	[Comp_ICOB],
	[Comp_GI],
	[ChargeType],
	[noteAgentCode],
	[noteSubject],
	[noteUsername],
	[NoteDateTime],
	[Note],
	[dateinserted])  select [BusinessCode] ,
	[Month],
	[LastUpdated],
	[UpdatedBy],
	[AgentCharge],
	[ChargeEffDate] ,
	[ChargeCalcDate],
	[Code],
	[Status],
	[StatusDesc],
	[CanSupervise],
	[GivesAdvice],
	[Category],
	[CategoryDesc],
	[DateStarted],
	[DateLeft],
	[StatusDate],
	[Type],
	[TypeDesc],
	[Transfer],
	[TransferFirm],
	[TranEffDate],
	[SupervisedBy],
	[SupervisorType],
	[Comp_PenInv],
	[Comp_Mort],
	[Comp_ICOB],
	[Comp_GI],
	[ChargeType],
	e1.[AgentCode],
	e1.[Subject],
	e1.[Username],
	e1.[NoteDateTime],
	e1.[Note],getdate() from owhot_SupervisorChargeSellers ss
	join #exclusions1 e1 on e1.AgentCode=ss.Code
where SS.Month = @RunMonth --this becomes @runmonth when live
and @RunMonth>='2025-07-01 00:00:00.000'
and ss.chargetype='PP' and e1.subject like '%RSC_EXEMPT%' AND e1.SUBJECT NOT LIKE '%RSC_EXEMPT DEAL%';

--then set the chargetype to null for those ones that are exempt
update ss
set ss.chargetype=NULL
FROM 
owhot_SupervisorChargeSellers ss
join #exclusions1 e1 on e1.AgentCode=ss.Code
where SS.Month = @RunMonth --this becomes @runmonth when live
and @RunMonth>='2025-07-01 00:00:00.000'
and ss.chargetype='PP' and e1.subject like '%RSC_EXEMPT%' AND e1.SUBJECT NOT LIKE '%RSC_EXEMPT DEAL%';


--end new code June 2025 R327865










-- If no valid Charge present then exit Calculation processing

IF (Select Count(*) from #SupCharges) > 0 
AND ((@RecalcFlag = 'B' AND @LastChargeMonth < @RunMonth) OR @RecalcFlag <> 'B')
BEGIN

-- Apply Seller Supervision Charges
update owhot_SupervisorChargeSellers
set UpdatedBy   = @UpdatedBy,
    LastUpdated   = @RunDatetime,
    ChargeEffDate = t1.ChargeMonth,
    ChargeCalcDate  = @RunDateTime,
    AgentCharge   = case
            when SS.ChargeType in ('PP','NS Sup','PFA Sup') then PracPrinCharge
            when SS.ChargeType in ('P&I') then PenInvCharge
            when SS.ChargeType in ('Mort') then MortgageCharge
            when SS.ChargeType in ('ICOB') then ICOBCharge
            when SS.ChargeType in ('GI') then GICharge
        else NULL end
from owhot_SupervisorChargeSellers SS
inner join #SupCharges t1 on t1.RunMonth = SS.Month
where SS.Month = @RunMonth 
and SS.Status in (1,2,3)

-- Derive Business Totals
Select BusinessCode,sum(isnull(AgentCharge,0)) as TotalCharge,
sum(case when ChargeType = 'GI' then 1 else 0 end) as GICount,
sum(case when ChargeType = 'ICOB' then 1 else 0 end) as ICOBCount,
sum(case when ChargeType = 'Mort' then 1 else 0 end) as MortgageCount,
sum(case when ChargeType = 'P&I' then 1 else 0 end) as PenInvCount,
sum(case when ChargeType = 'PP' then 1 else 0 end) as PracPrinCount,
sum(case when ChargeType in ('NS Sup','PFA Sup') then 1 else 0 end) as SupervisorCount,
sum(case when ChargeType is not NULL then 1 else 0 end) as TotalChargedCount
into #BusinessTotals
from owhot_SupervisorChargeSellers
where Month = @RunMonth 
and Status in (1,2,3)
group by BusinessCode
order by BusinessCode

-- Apply Business Details to Table
update owhot_SupervisorChargeBusiness
set UpdatedBy   = @UpdatedBy,
    LastUpdated   = @RunDatetime,
    TotalCharge   = t1.TotalCharge,
    GICount   = t1.GICount,
    ICOBCount   = t1.ICOBCount,
    MortgageCount = t1.MortgageCount,
    PenInvCount   = t1.PenInvCount,
    PracPrinCount = t1.PracPrinCount,
    SupervisorCount = t1.SupervisorCount,
    TotalChargedCount = t1.TotalChargedCount,
    ChargeEffDate = t2.ChargeMonth,
    ChargeCalcDate  = @RunDateTime
from owhot_SupervisorChargeBusiness SB
inner join #BusinessTotals t1 on t1.Businesscode = SB.BusinessCode
inner join #SupCharges t2 on t2.Runmonth = SB.Month
where SB.Month = @RunMonth

drop table #BusinessTotals

END

drop table #ChargeMonth
drop table #SupCharges

-- End of charges processing

-- Create Supervision Charge Trigger file

IF (@RunMonth = @LastCalendarMonth AND @RecalcFlag <> 'B') 
OR (@RecalcFlag = 'B' AND @LastChargeMonth < @RunMonth)
BEGIN
	exec owhop_SupervisionChargeStandingOrderDataProcessing
	--AG 28/03/2017 Start
	--exec mscp-run-dts-package 'owdts_supervisionchargestandingordertriggerextract'
	update dbo.owt_JobControl
		set JobStartRequired = 1,
			DateLastUpdatedByCaller = GETDATE()
	where JobCode = 'SUP-CHARGE-STD-ORDS'

	declare @JobName varchar(300)
	select	@JobName = JobName
	from	dbo.owt_JobControl
	where	JobCode = 'SUP-CHARGE-STD-ORDS'

	if dbo.owf_JobStillRunning(@JobName) = 0
		exec msdb.dbo.sp_start_job @JobName
	--AG 28/03/2017 End
END

-- End of Trigger processing


GO
/****** Object:  StoredProcedure [dbo].[owhop_SupervisionChargesCalculation_backup_12_06_2025]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

/********************************************************************************************************

 Object  : procedure
 Name    : owhop_SupervisionChargesCalculation.sql
 Owner   : MPC
 Created : 2 April 2007
 Project : Openwork Head Office Systems - Charges Application 

 Procedure operates with three parameters:

 @RecalcFlag 
 Has three settings:

 'Y' : this recalculates the Supervision Charges for the Recalc Commission Statement period supplied.
 When called from the Charge Admin page this is set to lastest month on Supervision table.
 This is the only setting used from the Charge Admin page. 
 Deletes and reinserts entries on owhot_SupervisorChargesBusiness for the Recalc Period only.
 Deletes and reinserts entries on owhot_SupervisorChargesSellers for the Recalc Period only.

 'N' : used for Ad Hoc back population of previous periods. 
 Deletes and reinserts entries on owhot_SupervisorChargesBusiness for the Recalc Period only.
 Deletes and reinserts entries on owhot_SupervisorChargesSellers for the Recalc Period only.

 'B' : used when procedure is run in Warehouse daily batch schedule
 Defaults to latest closed Commission Month.
 On first day when procedure detects a new closed Commission period for which data is not present
 then insers data into owhot_SupervisorChargesBusiness and owhot_SupervisorChargesSellers tables.
 
 @RecalcMonth
 Determines Commission Period for which data to be updated.
 If not set to first of month then procedure defaults to last closed Commission Period.
 Defaulted to getdate when procedure is run in Warehouse daily batch schedule
 Cannot be later than last closed Commission Period or earlier than '1 Feb 2007' (Jan 2007)
 
 @UpdatedBy
 Denotes the Portal Id (without Domain) of user requesting run. Defaults to 'Automatic'.

AMENDMENT HISTORY
=================

Date		Author			Description
----		------			-----------
17/11/2014	A Groves		SR346635 - Remove Owl businesses which are not subject to supervision charges.
28/03/2017	A Groves		SR464996/CH16204. Replace DTS script with start-of-job that contains a SSIS
							replacement script for DTS script "SupervisionChargeStandingOrderTriggerExtract.dtsx".
13/04/2022  P Reed          R57925 - Allow inclusion of OWL supervisors for OpenWork firms 6 changes PFRCHANGE
21/03/2025  P Reed          R302430  - Charge non selling Practice Principals
*********************************************************************************************************/
CREATE procedure [dbo].[owhop_SupervisionChargesCalculation_backup_12_06_2025]
    @RecalcFlag  varchar(1) = 'N',
    @RecalcMonth datetime   = '1 Jan 1900',
    @UpdatedBy   varchar(10) = 'Automatic'
with recompile
as

declare @OwlManager2Code varchar(7)					-- AG 17/11/2014

select  @OwlManager2Code = cde.Code					-- AG 17/11/2014
from	msit_MIWarehouseCodesAndDescriptions cde	
where	cde.ColumnName = 'Manager2Code' 
and		cde.Description = 'Owl Financial'

-- DEFINE RUN DATES
declare @RunDateTime datetime
set @RunDateTime = getdate()

declare @Yesterday datetime
set @yesterday = CAST(CONVERT(NVARCHAR,dateadd(dd,-1,getdate()),112) as datetime)

declare @LastCalendarMonth datetime
set @LastCalendarMonth = (select max(Month) from msit_CommissionStatementPeriods where OSCAREndDate <= @yesterday)

declare @LastChargeMonth datetime
set @LastChargeMonth = (select isnull(max(Month),'1 Jan 1901') from owhot_SupervisorChargeBusiness) 

-- Default Run Month to last closed Commission Month
declare @RunMonth datetime
Set @RunMonth = @LastCalendarMonth

-- Override default Run Month with Recalc Month if valid
IF @RecalcMonth < @LastCalendarMonth  -- Recalc Date cannnot be later than last closed period
and @RecalcMonth > '1 Jan 2007'   -- Recalc Date cannot refer to a Commission Period earlier then 2007
and datepart(dd,@RecalcMonth) = 1 -- Recalc Date must be dated first of month
and @RecalcFlag <> 'B'      -- Do not reset for Batch run
BEGIN
Set @RunMonth = (Select Month from msit_CommissionStatementPeriods where @RecalcMonth = Month)
END

declare @StartDate datetime
set @StartDate = (select OSCARStartDate from msit_CommissionStatementPeriods where Month = @RunMonth)

declare @EndDate datetime
set @EndDate = (select OSCAREndDate from msit_CommissionStatementPeriods where Month = @RunMonth)

declare @LeaverDate datetime  -- Include Leavers within last 6 months
set @LeaverDate = dateadd(mm,-6,@startdate)

If @RecalcFlag <> 'B' OR (@RecalcFlag = 'B' AND @LastChargeMonth < @RunMonth)
BEGIN

-- Extract appropriate Business and Seller Details into Agents table ----------------

select AG.Code,AG.Firm,AG.AgentTYpe,AG.CompetentStatus,AG.DateLeaving,AG.CanSupervise,AG.GivesAdvice,
AG.AgentCategory,AG.AgentCategoryDescription,AG.DateStarted,AG.OscarDateStarted,AG.CDIStatusDate,
AG.spansupervisorCode,ag.Manager2Code  --PFRCHANGE1 13/04/2022 add manager2code
into #Agents 
from mstt_agents AG
where 1=0

END

-- If not processing Last Calendar Month extract Agent Details as at end of Run Month from Agents History table
IF @RunMonth <> @LastCalendarMonth AND @RecalcFlag <> 'B'
BEGIN

select Code,max(ValidFromDate) as EffDate
into #AgentDate
from mstt_AgentsHistory
where AgentType in (2,46,49,3,4,5,43,45,51,52,53,54,55) -- Business, Seller and Manager Types only 
and ValidFromDate <= @EndDate
--and Manager2Code <> @OwlManager2Code			-- AG 17/11/2014 ----PFRCHANGE2 13/04/2022 comment out
Group by Code
Order by Code

insert into #Agents
select AGH.Code,AGH.Firm,AGH.AgentTYpe,AGH.CompetentStatus,AGH.DateLeaving,AGH.CanSupervise,AGH.GivesAdvice,
AGH.AgentCategory,AGH.AgentCategoryDescription,AGH.DateStarted,AGH.OscarDateStarted,AGH.CDIStatusDate,
AGH.spansupervisorCode,agh.Manager2Code  --PFRCHANGE3 13/04/2022 add manager2code
from mstt_AgentsHistory AGH
inner join #AgentDate AGD on AGD.Code = AGH.Code and AGD.EffDate = AGH.ValidFromDate
order by AGH.Code

drop table #AgentDate

END

-- If processing Last Calendar Month Extract Agent Details as at end of Run Month from mstt_Agents
IF (@RunMonth = @LastCalendarMonth AND @RecalcFlag <> 'B') OR (@RecalcFlag = 'B' AND @LastChargeMonth < @RunMonth)
BEGIN

insert into #Agents
select AG.Code,AG.Firm,AG.AgentTYpe,AG.CompetentStatus,AG.DateLeaving,AG.CanSupervise,AG.GivesAdvice,
AG.AgentCategory,AG.AgentCategoryDescription,AG.DateStarted,AG.OscarDateStarted,AG.CDIStatusDate,
AG.spansupervisorCode,ag.Manager2Code  --PFRCHANGE4 13/04/2022 add manager2code
from mstt_Agents AG
--where AG.Manager2Code <> @OwlManager2Code			-- AG 17/11/2014 -- PFRCHANGE5 13/04/2022 comment out
order by AG.Code
END

--- END of Agent processing --------------

-- Start of Update processing

IF @RecalcFlag = 'N' 
OR (@RunMonth = @LastCalendarMonth AND @RecalcFlag = 'Y')
OR (@RecalcFlag = 'B' AND @LastChargeMonth < @RunMonth)
-- Recalc N or Processing Last Calendar Month
BEGIN

-- Clear down existing data for the Month to be Loaded
DELETE from owhot_SupervisorChargeBusiness where Month = @RunMonth
DELETE from owhot_SupervisorChargeSellers  where Month = @RunMonth

-- Insert Business details into Supervision Business Table (Franchises and Access Agents)
INSERT into owhot_SupervisorChargeBusiness
(BusinessCode,Month,LastUpdated,UpdatedBy,
TotalCharge,ChargeEffDate,ChargeCalcDate,GICount,ICOBCount,
MortgageCount,PenInvCount,PracPrinCount,SupervisorCount,TotalChargedCount)
select 
Code,     -- BusinessCode
@RunMonth,    -- Month
@RunDateTime,   -- LastUpdated
@UpdatedBy,   -- UpdatedBy
NULL,     -- TotalCharge
NULL,     -- ChargeEffDate
NULL,     -- ChargeCalcDate
NULL,     -- GICount
NULL,     -- ICOBCount
NULL,     -- MortgageCount
NULL,     -- PenInvCount
NULL,     -- PracPrinCount
NULL,     -- SupervisorCount
NULL      -- TotalChargedCount
from #Agents
where AgentType in (2,46)
and (CompetentStatus = 1 
     or (CompetentStatus = 2 and CDIStatusDate >= @LeaverDate))
	  and manager2code!=@OwlManager2Code   --PFRCHANGE6  --add line so only adds the OPENWORK FIRMS 13/04/2022

-- Insert Seller details into Supervison Seller Table
INSERT into owhot_SupervisorChargeSellers
(BusinessCode,Month,LastUpdated,UpdatedBy,AgentCharge,ChargeEffDate,ChargeCalcDate,
Code,Status,StatusDesc,CanSupervise,GivesAdvice,Category,CategoryDesc,DateStarted,DateLeft,
StatusDate,Type,TypeDesc,Transfer,TransferFirm,TranEffDate,SupervisedBy,SupervisorType,
Comp_PenInv,Comp_Mort,Comp_ICOB,Comp_GI,ChargeType)
select 
AG.Firm,      -- BusinessCode
@RunMonth,      -- Month
@RunDateTime,     -- LastUpdated
@UpdatedBy,     -- UpdatedBy
NULL,       -- AgentCharge
NULL,       -- ChargeEffDate
NULL,       -- ChargeCalcDate
AG.Code,      -- Seller Code
AG.CompetentStatus,   -- Status
case AG.CompetentStatus when 1 then 'Active' when 2 then 'Left' when 3 then 'Dead'
when 4 then 'Canc' when 5 then 'PreApp' when 6 then 'NPW' end,  --StatusDesc
case AG.CanSupervise when 1 then 'Y' else 'N' end,    -- CanSupervise
case AG.GivesAdvice when 'Y' then 'Y' else 'N' end,   -- GivesAdvice
AG.AgentCategory,   -- Category
AG.AgentCategoryDescription,  -- CategoryDesc
coalesce(AG.OscarDateStarted,AG.DateStarted),     -- DateStarted
AG.DateLeaving,     -- DateLeft
AG.CDIStatusDate,   -- StatusDate
AG.AgentType,     -- Type
case AG.AgentType when 3 then 'IAR' when 4 then 'PFA' when 5 then 'Admin' when 43 then 'Prac Prin' 
when 45 then '10% Share' when 51 then 'PFA Prin' end,   -- TypeDesc
NULL,       -- Transfer
NULL,       -- TransferFirm
NULL,       -- TranEffDate
AG.SpanSupervisorCode,    -- SupervisedBy
NULL,       -- SupervisorType
NULL,       -- Comp_PenInv
NULL,       -- Comp_Mort
NULL,       -- Comp_ICOB
NULL,       -- Comp_GI
NULL        -- ChargeType
from #Agents AG
inner join owhot_SupervisorChargeBusiness SB on SB.BusinessCode = AG.Firm
where AG.AgentType in (3,4,5,43,45,51)
and (AG.CompetentStatus in (1,5) 
     or (AG.CompetentStatus in (2,3) and AG.CDIStatusDate >= @LeaverDate))
and SB.Month = @RunMonth

-- Extract Seller Moves in Period
Select AgentCode as Seller,DetailAgentCode as Business,ParticipantType as RelType,StartDate,EndDate,Status,DefaultValue
into #SellerMoves
from msit_AgentHierarchyHistory
where ParticipantType in (6,7,8,9)    -- Business/Seller Relationship
and EndDate between @StartDate and @EndDate -- Relationship ended in period
and DefaultValue = 1        -- Valid Relationship
--and (datepart(yy,startdate) <> datepart(yy,enddate)   -- Start/End in Diff Year
--     or datepart(mm,startdate) = datepart(mm,enddate))  -- Start/End in Diff Year
order by AgentCode

-- Identify earliest and Latest Moves in Period
-- Need to do this to ignore Transfers within Period
Select Seller,Min(EndDate) as FirstDate,Max(EndDate) as LastDate
into #SellerDates
from #SellerMoves
group by Seller
order by Seller

-- Update Seller Transfer In Details for Current Business (as at end of Period)
update owhot_SupervisorChargeSellers
set Transfer     = 'In',
    TransferFirm = t2.Business,
    TranEffDate  = dateadd(dd,1,t1.LastDate)  -- Add one day to give Start Date
from owhot_SupervisorChargeSellers SS
inner join #SellerDates t1 on t1.Seller = SS.Code
inner join #SellerMoves t2 on t2.Seller = t1.Seller and t1.LastDate = t2.EndDate
where SS.Month = @Runmonth 
and SS.BusinessCode <> t2.Business

-- Insert Transfer Out Seller row for Previous Business (as at Start of Period)
INSERT into owhot_SupervisorChargeSellers
(BusinessCode,Month,LastUpdated,UpdatedBy,AgentCharge,ChargeEffDate,ChargeCalcDate,
Code,Status,StatusDesc,CanSupervise,GivesAdvice,Category,CategoryDesc,DateStarted,DateLeft,
StatusDate,Type,TypeDesc,Transfer,TransferFirm,TranEffDate,SupervisedBy,SupervisorType,
Comp_PenInv,Comp_Mort,Comp_ICOB,Comp_GI,ChargeType)
select 
t2.Business,      -- BusinessCode
@RunMonth,      -- Month
@RunDateTime,     -- LastUpdated
@UpdatedBy,     -- UpdatedBy
NULL,       -- AgentCharge
NULL,       -- ChargeEffDate
NULL,       -- ChargeCalcDate
AG.Code,      -- Seller Code
AG.CompetentStatus,   -- Status
case AG.CompetentStatus when 1 then 'Active' when 2 then 'Left' when 3 then 'Dead'
when 4 then 'Canc' when 5 then 'PreApp' when 6 then 'NPW' end,      --StatusDesc
case AG.CanSupervise when 1 then 'Y' else 'N' end,        -- CanSupervise
case AG.GivesAdvice when 'Y' then 'Y' else 'N' end,       -- GivesAdvice
AG.AgentCategory,   -- Category
AG.AgentCategoryDescription,  -- CategoryDesc
coalesce(AG.OscarDateStarted,AG.DateStarted),         -- DateStarted
AG.DateLeaving,     -- DateLeft
AG.CDIStatusDate,   -- StatusDate
AG.AgentType,     -- Type
case AG.AgentType when 3 then 'IAR' when 4 then 'PFA' when 5 then 'Admin' when 43 then 'Prac Prin' 
when 45 then '10% Share' when 51 then 'PFA Prin' end,       -- TypeDesc
'Out',        -- Transfer
AG.Firm,      -- TransferFirm
t1.FirstDate,     -- TranEffDate
AG.SpanSupervisorCode,    -- SupervisedBy
NULL,       -- SupervisorType
NULL,       -- Comp_PenInv
NULL,       -- Comp_Mort
NULL,       -- Comp_ICOB
NULL,       -- Comp_GI
NULL        -- ChargeType
from #Agents AG
inner join #SellerDates t1 on t1.Seller = Code
inner join #SellerMoves t2 on t2.Seller = t1.Seller and t1.FirstDate = t2.EndDate
where t2.Business <> AG.Firm

-- update supervisorType
update owhot_SupervisorChargeSellers
set SupervisorType = case when AG.AgentType in ('52','53','54','55') then 'Manager' 
        when AG.AgentType in ('3','4','5','43','45','51') then 'Prac Super'
        else 'Other' end
from owhot_SupervisorChargeSellers SS
inner join #Agents AG on AG.Code = SS.SupervisedBy
where SS.Month = @RunMonth

-- Extract Seller Competency Details for Period
select act.ID,act.AgentCode,act.CodeComplianceCategoryID as CategoryID,
case act.CodeComplianceCategoryID 
when 1 then 'ICOB' when 2 then 'GI' when 3 then 'Mort' when 4 then 'PenInv' end as Category,
act.AgentControlFunctionCode as StatusCode,case act.AgentControlFunctionCode 
when 'FC' then 'Full' when 'IC' then 'Interim' when 'NA' then 'N/A' when 'NC' then 'Not'
when 'S1' then 'Stage 1' when 'SC' then 'Suspended' when 'SS' then 'Sick/Mat' else 'N/A'
end as Status,act.DateAppointed,act.AchievedDate,isnull(act.EndDate,'31 Dec 2999') as EndDate,aci.DateCreated
into #Competencies
from mstt_agentCompetence act
inner join msit_agentCompetence aci on aci.id = act.id
where act.CodeComplianceCategoryID in (1,2,3,4)
and (act.EndDate is null or act.EndDate >= @StartDate)
Order by act.AgentCode,act.CodeComplianceCategoryID,act.ID

-- Apply Seller Competencies to Seller Table
/*
update owhot_SupervisorChargeSellers
set Comp_PenInv   = case when t1.CategoryID = 4 and t1.EndDate <= @EndDate then 'Ended' 
       when t1.CategoryID = 4 and t1.EndDate > @EndDate then t1.Status end,
    Comp_Mort     = case when t1.CategoryID = 3 and t1.EndDate <= @EndDate then 'Ended' 
       when t1.CategoryID = 3 and t1.EndDate > @EndDate then t1.Status end,
    Comp_ICOB     = case when t1.CategoryID = 1 and t1.EndDate <= @EndDate then 'Ended' 
       when t1.CategoryID = 1 and t1.EndDate > @EndDate then t1.Status end,
    Comp_GI       = case when t1.CategoryID = 2 and t1.EndDate <= @EndDate then 'Ended' 
       when t1.CategoryID = 2 and t1.EndDate > @EndDate then t1.Status end
from owhot_SupervisorChargeSellers SS
inner join #Competencies t1 on t1.AgentCode = SS.Code
where SS.Month = @Runmonth 
*/

update owhot_SupervisorChargeSellers
set Comp_PenInv   = case when t1.CategoryID = 4 and t1.EndDate <= @EndDate then 'Ended' 
       when t1.CategoryID = 4 and t1.EndDate > @EndDate then t1.Status end
from owhot_SupervisorChargeSellers SS
inner join #Competencies t1 on t1.AgentCode = SS.Code and t1.CategoryID = 4
where SS.Month = @Runmonth 

update owhot_SupervisorChargeSellers
set Comp_Mort     = case when t1.CategoryID = 3 and t1.EndDate <= @EndDate then 'Ended' 
       when t1.CategoryID = 3 and t1.EndDate > @EndDate then t1.Status end
from owhot_SupervisorChargeSellers SS
inner join #Competencies t1 on t1.AgentCode = SS.Code and t1.CategoryID = 3
where SS.Month = @Runmonth 

update owhot_SupervisorChargeSellers
set Comp_ICOB    = case when t1.CategoryID = 1 and t1.EndDate <= @EndDate then 'Ended' 
      when t1.CategoryID = 1 and t1.EndDate > @EndDate then t1.Status end
from owhot_SupervisorChargeSellers SS
inner join #Competencies t1 on t1.AgentCode = SS.Code and t1.CategoryID = 1
where SS.Month = @Runmonth 

update owhot_SupervisorChargeSellers
set Comp_GI   =    case when t1.CategoryID = 2 and t1.EndDate <= @EndDate then 'Ended' 
      when t1.CategoryID = 2 and t1.EndDate > @EndDate then t1.Status end
from owhot_SupervisorChargeSellers SS
inner join #Competencies t1 on t1.AgentCode = SS.Code and t1.CategoryID = 2
where SS.Month = @Runmonth 

-- Derive Seller Charge Type
update owhot_SupervisorChargeSellers
set ChargeType = case
     when SS.Type in (43,51) and SS.GivesAdvice = 'Y' and SS.SupervisorType = 'Manager' then 'PP'
     when SS.Type in (43,51) and SS.CanSupervise = 'Y' and SS.SupervisorType = 'Manager' then 'NS Sup'
     when SS.Type not in (43,51) and SS.CanSupervise = 'Y' and SS.SupervisorType = 'Manager' then 'PFA Sup'
     when SS.GivesAdvice = 'Y' and SS.Comp_PenInv not in ('N/A','Not') and SS.SupervisorType = 'Manager' then 'P&I'
     when SS.GivesAdvice = 'Y' and SS.Comp_Mort not in ('N/A','Not') and SS.SupervisorType = 'Manager' then 'Mort'
     when SS.GivesAdvice = 'Y' and SS.Comp_ICOB not in ('N/A','Not') and SS.SupervisorType = 'Manager' then 'ICOB'
     when SS.GivesAdvice = 'Y' and SS.Comp_GI not in ('N/A','Not') and SS.SupervisorType = 'Manager' then 'GI' 
	 --when SS.Type in (43) and SS.GivesAdvice = 'N' and SS.SupervisorType = 'Manager' and @runmonth>='2025-04-01 00:00:00.000' then 'PP' --R302430  PFR 2025
     --WHEN ss.TYpe in (43,51) and NOT (SS.supervisortype is null and SS.GivesAdvice='Y' and SS.CanSupervise='N') and @runmonth>='2025-04-01 00:00:00.000' then 'PP'  --R302430  PFR 2025
	 WHEN ss.TYpe in (43,51) and NOT ((SS.supervisortype is null or SS.SupervisorType='Prac Super') and SS.GivesAdvice='Y' and SS.CanSupervise='N') and @runmonth>='2025-04-01 00:00:00.000' then 'PP'  --R302430  PFR 2025
	 end
from owhot_SupervisorChargeSellers SS
where SS.Month = @Runmonth
and ( SS.Status = 1 or (SS.Status in (2,3) and SS.StatusDate >= @StartDate) ) -- Active or Inactive this Period
and isnull(SS.Transfer,'No') <> 'In'  -- Did not Transfer INTO Business during Period
and SS.DateStarted < @StartDate   -- Include if Start Date earlier than Period Start Date

drop table #SellerDates
drop table #SellerMoves
drop table #Competencies
drop table #Agents

END

-- END of Business/Seller Update Processing------------------------------------------------------------------

-- Access Charges Table and find Prevailing Supervision Charges
select max(Month) as ChargeMonth 
into #ChargeMonth 
from owhot_OpenworkCharges 
where Month <= @RunMonth

select t1.ChargeMonth,OC.UpdatedBy,OC.DateUpdated,@RunMonth as RunMonth,
OC.PracPrincharge,OC.PenInvCharge,OC.MortgageCharge,OC.ICOBCharge,OC.GICharge
into #SupCharges
from owhot_OpenworkCharges OC
inner join #ChargeMonth t1 on OC.Month = t1.ChargeMonth

-- If no valid Charge present then exit Calculation processing

IF (Select Count(*) from #SupCharges) > 0 
AND ((@RecalcFlag = 'B' AND @LastChargeMonth < @RunMonth) OR @RecalcFlag <> 'B')
BEGIN

-- Apply Seller Supervision Charges
update owhot_SupervisorChargeSellers
set UpdatedBy   = @UpdatedBy,
    LastUpdated   = @RunDatetime,
    ChargeEffDate = t1.ChargeMonth,
    ChargeCalcDate  = @RunDateTime,
    AgentCharge   = case
            when SS.ChargeType in ('PP','NS Sup','PFA Sup') then PracPrinCharge
            when SS.ChargeType in ('P&I') then PenInvCharge
            when SS.ChargeType in ('Mort') then MortgageCharge
            when SS.ChargeType in ('ICOB') then ICOBCharge
            when SS.ChargeType in ('GI') then GICharge
        else NULL end
from owhot_SupervisorChargeSellers SS
inner join #SupCharges t1 on t1.RunMonth = SS.Month
where SS.Month = @RunMonth 
and SS.Status in (1,2,3)

-- Derive Business Totals
Select BusinessCode,sum(isnull(AgentCharge,0)) as TotalCharge,
sum(case when ChargeType = 'GI' then 1 else 0 end) as GICount,
sum(case when ChargeType = 'ICOB' then 1 else 0 end) as ICOBCount,
sum(case when ChargeType = 'Mort' then 1 else 0 end) as MortgageCount,
sum(case when ChargeType = 'P&I' then 1 else 0 end) as PenInvCount,
sum(case when ChargeType = 'PP' then 1 else 0 end) as PracPrinCount,
sum(case when ChargeType in ('NS Sup','PFA Sup') then 1 else 0 end) as SupervisorCount,
sum(case when ChargeType is not NULL then 1 else 0 end) as TotalChargedCount
into #BusinessTotals
from owhot_SupervisorChargeSellers
where Month = @RunMonth 
and Status in (1,2,3)
group by BusinessCode
order by BusinessCode

-- Apply Business Details to Table
update owhot_SupervisorChargeBusiness
set UpdatedBy   = @UpdatedBy,
    LastUpdated   = @RunDatetime,
    TotalCharge   = t1.TotalCharge,
    GICount   = t1.GICount,
    ICOBCount   = t1.ICOBCount,
    MortgageCount = t1.MortgageCount,
    PenInvCount   = t1.PenInvCount,
    PracPrinCount = t1.PracPrinCount,
    SupervisorCount = t1.SupervisorCount,
    TotalChargedCount = t1.TotalChargedCount,
    ChargeEffDate = t2.ChargeMonth,
    ChargeCalcDate  = @RunDateTime
from owhot_SupervisorChargeBusiness SB
inner join #BusinessTotals t1 on t1.Businesscode = SB.BusinessCode
inner join #SupCharges t2 on t2.Runmonth = SB.Month
where SB.Month = @RunMonth

drop table #BusinessTotals

END

drop table #ChargeMonth
drop table #SupCharges

-- End of charges processing

-- Create Supervision Charge Trigger file

IF (@RunMonth = @LastCalendarMonth AND @RecalcFlag <> 'B') 
OR (@RecalcFlag = 'B' AND @LastChargeMonth < @RunMonth)
BEGIN
	exec owhop_SupervisionChargeStandingOrderDataProcessing
	--AG 28/03/2017 Start
	--exec mscp-run-dts-package 'owdts_supervisionchargestandingordertriggerextract'
	update dbo.owt_JobControl
		set JobStartRequired = 1,
			DateLastUpdatedByCaller = GETDATE()
	where JobCode = 'SUP-CHARGE-STD-ORDS'

	declare @JobName varchar(300)
	select	@JobName = JobName
	from	dbo.owt_JobControl
	where	JobCode = 'SUP-CHARGE-STD-ORDS'

	if dbo.owf_JobStillRunning(@JobName) = 0
		exec msdb.dbo.sp_start_job @JobName
	--AG 28/03/2017 End
END

-- End of Trigger processing


GO
/****** Object:  StoredProcedure [dbo].[owhop_SupervisionChargesCalculation_backup30_03_2025]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

/********************************************************************************************************

 Object  : procedure
 Name    : owhop_SupervisionChargesCalculation.sql
 Owner   : MPC
 Created : 2 April 2007
 Project : Openwork Head Office Systems - Charges Application 

 Procedure operates with three parameters:

 @RecalcFlag 
 Has three settings:

 'Y' : this recalculates the Supervision Charges for the Recalc Commission Statement period supplied.
 When called from the Charge Admin page this is set to lastest month on Supervision table.
 This is the only setting used from the Charge Admin page. 
 Deletes and reinserts entries on owhot_SupervisorChargesBusiness for the Recalc Period only.
 Deletes and reinserts entries on owhot_SupervisorChargesSellers for the Recalc Period only.

 'N' : used for Ad Hoc back population of previous periods. 
 Deletes and reinserts entries on owhot_SupervisorChargesBusiness for the Recalc Period only.
 Deletes and reinserts entries on owhot_SupervisorChargesSellers for the Recalc Period only.

 'B' : used when procedure is run in Warehouse daily batch schedule
 Defaults to latest closed Commission Month.
 On first day when procedure detects a new closed Commission period for which data is not present
 then insers data into owhot_SupervisorChargesBusiness and owhot_SupervisorChargesSellers tables.
 
 @RecalcMonth
 Determines Commission Period for which data to be updated.
 If not set to first of month then procedure defaults to last closed Commission Period.
 Defaulted to getdate when procedure is run in Warehouse daily batch schedule
 Cannot be later than last closed Commission Period or earlier than '1 Feb 2007' (Jan 2007)
 
 @UpdatedBy
 Denotes the Portal Id (without Domain) of user requesting run. Defaults to 'Automatic'.

AMENDMENT HISTORY
=================

Date		Author			Description
----		------			-----------
17/11/2014	A Groves		SR346635 - Remove Owl businesses which are not subject to supervision charges.
28/03/2017	A Groves		SR464996/CH16204. Replace DTS script with start-of-job that contains a SSIS
							replacement script for DTS script "SupervisionChargeStandingOrderTriggerExtract.dtsx".
13/04/3022  P Reed          R57925 - Allow inclusion of OWL supervisors for OpenWork firms 6 changes PFRCHANGE
*********************************************************************************************************/
CREATE procedure [dbo].[owhop_SupervisionChargesCalculation_backup30_03_2025]
    @RecalcFlag  varchar(1) = 'N',
    @RecalcMonth datetime   = '1 Jan 1900',
    @UpdatedBy   varchar(10) = 'Automatic'
with recompile
as

declare @OwlManager2Code varchar(7)					-- AG 17/11/2014

select  @OwlManager2Code = cde.Code					-- AG 17/11/2014
from	msit_MIWarehouseCodesAndDescriptions cde	
where	cde.ColumnName = 'Manager2Code' 
and		cde.Description = 'Owl Financial'

-- DEFINE RUN DATES
declare @RunDateTime datetime
set @RunDateTime = getdate()

declare @Yesterday datetime
set @yesterday = CAST(CONVERT(NVARCHAR,dateadd(dd,-1,getdate()),112) as datetime)

declare @LastCalendarMonth datetime
set @LastCalendarMonth = (select max(Month) from msit_CommissionStatementPeriods where OSCAREndDate <= @yesterday)

declare @LastChargeMonth datetime
set @LastChargeMonth = (select isnull(max(Month),'1 Jan 1901') from owhot_SupervisorChargeBusiness) 

-- Default Run Month to last closed Commission Month
declare @RunMonth datetime
Set @RunMonth = @LastCalendarMonth

-- Override default Run Month with Recalc Month if valid
IF @RecalcMonth < @LastCalendarMonth  -- Recalc Date cannnot be later than last closed period
and @RecalcMonth > '1 Jan 2007'   -- Recalc Date cannot refer to a Commission Period earlier then 2007
and datepart(dd,@RecalcMonth) = 1 -- Recalc Date must be dated first of month
and @RecalcFlag <> 'B'      -- Do not reset for Batch run
BEGIN
Set @RunMonth = (Select Month from msit_CommissionStatementPeriods where @RecalcMonth = Month)
END

declare @StartDate datetime
set @StartDate = (select OSCARStartDate from msit_CommissionStatementPeriods where Month = @RunMonth)

declare @EndDate datetime
set @EndDate = (select OSCAREndDate from msit_CommissionStatementPeriods where Month = @RunMonth)

declare @LeaverDate datetime  -- Include Leavers within last 6 months
set @LeaverDate = dateadd(mm,-6,@startdate)

If @RecalcFlag <> 'B' OR (@RecalcFlag = 'B' AND @LastChargeMonth < @RunMonth)
BEGIN

-- Extract appropriate Business and Seller Details into Agents table ----------------

select AG.Code,AG.Firm,AG.AgentTYpe,AG.CompetentStatus,AG.DateLeaving,AG.CanSupervise,AG.GivesAdvice,
AG.AgentCategory,AG.AgentCategoryDescription,AG.DateStarted,AG.OscarDateStarted,AG.CDIStatusDate,
AG.spansupervisorCode,ag.Manager2Code  --PFRCHANGE1 13/04/2022 add manager2code
into #Agents 
from mstt_agents AG
where 1=0

END

-- If not processing Last Calendar Month extract Agent Details as at end of Run Month from Agents History table
IF @RunMonth <> @LastCalendarMonth AND @RecalcFlag <> 'B'
BEGIN

select Code,max(ValidFromDate) as EffDate
into #AgentDate
from mstt_AgentsHistory
where AgentType in (2,46,49,3,4,5,43,45,51,52,53,54,55) -- Business, Seller and Manager Types only 
and ValidFromDate <= @EndDate
--and Manager2Code <> @OwlManager2Code			-- AG 17/11/2014 ----PFRCHANGE2 13/04/2022 comment out
Group by Code
Order by Code

insert into #Agents
select AGH.Code,AGH.Firm,AGH.AgentTYpe,AGH.CompetentStatus,AGH.DateLeaving,AGH.CanSupervise,AGH.GivesAdvice,
AGH.AgentCategory,AGH.AgentCategoryDescription,AGH.DateStarted,AGH.OscarDateStarted,AGH.CDIStatusDate,
AGH.spansupervisorCode,agh.Manager2Code  --PFRCHANGE3 13/04/2022 add manager2code
from mstt_AgentsHistory AGH
inner join #AgentDate AGD on AGD.Code = AGH.Code and AGD.EffDate = AGH.ValidFromDate
order by AGH.Code

drop table #AgentDate

END

-- If processing Last Calendar Month Extract Agent Details as at end of Run Month from mstt_Agents
IF (@RunMonth = @LastCalendarMonth AND @RecalcFlag <> 'B') OR (@RecalcFlag = 'B' AND @LastChargeMonth < @RunMonth)
BEGIN

insert into #Agents
select AG.Code,AG.Firm,AG.AgentTYpe,AG.CompetentStatus,AG.DateLeaving,AG.CanSupervise,AG.GivesAdvice,
AG.AgentCategory,AG.AgentCategoryDescription,AG.DateStarted,AG.OscarDateStarted,AG.CDIStatusDate,
AG.spansupervisorCode,ag.Manager2Code  --PFRCHANGE4 13/04/2022 add manager2code
from mstt_Agents AG
--where AG.Manager2Code <> @OwlManager2Code			-- AG 17/11/2014 -- PFRCHANGE5 13/04/2022 comment out
order by AG.Code
END

--- END of Agent processing --------------

-- Start of Update processing

IF @RecalcFlag = 'N' 
OR (@RunMonth = @LastCalendarMonth AND @RecalcFlag = 'Y')
OR (@RecalcFlag = 'B' AND @LastChargeMonth < @RunMonth)
-- Recalc N or Processing Last Calendar Month
BEGIN

-- Clear down existing data for the Month to be Loaded
DELETE from owhot_SupervisorChargeBusiness where Month = @RunMonth
DELETE from owhot_SupervisorChargeSellers  where Month = @RunMonth

-- Insert Business details into Supervision Business Table (Franchises and Access Agents)
INSERT into owhot_SupervisorChargeBusiness
(BusinessCode,Month,LastUpdated,UpdatedBy,
TotalCharge,ChargeEffDate,ChargeCalcDate,GICount,ICOBCount,
MortgageCount,PenInvCount,PracPrinCount,SupervisorCount,TotalChargedCount)
select 
Code,     -- BusinessCode
@RunMonth,    -- Month
@RunDateTime,   -- LastUpdated
@UpdatedBy,   -- UpdatedBy
NULL,     -- TotalCharge
NULL,     -- ChargeEffDate
NULL,     -- ChargeCalcDate
NULL,     -- GICount
NULL,     -- ICOBCount
NULL,     -- MortgageCount
NULL,     -- PenInvCount
NULL,     -- PracPrinCount
NULL,     -- SupervisorCount
NULL      -- TotalChargedCount
from #Agents
where AgentType in (2,46)
and (CompetentStatus = 1 
     or (CompetentStatus = 2 and CDIStatusDate >= @LeaverDate))
	  and manager2code!=@OwlManager2Code   --PFRCHANGE6  --add line so only adds the OPENWORK FIRMS 13/04/2022

-- Insert Seller details into Supervison Seller Table
INSERT into owhot_SupervisorChargeSellers
(BusinessCode,Month,LastUpdated,UpdatedBy,AgentCharge,ChargeEffDate,ChargeCalcDate,
Code,Status,StatusDesc,CanSupervise,GivesAdvice,Category,CategoryDesc,DateStarted,DateLeft,
StatusDate,Type,TypeDesc,Transfer,TransferFirm,TranEffDate,SupervisedBy,SupervisorType,
Comp_PenInv,Comp_Mort,Comp_ICOB,Comp_GI,ChargeType)
select 
AG.Firm,      -- BusinessCode
@RunMonth,      -- Month
@RunDateTime,     -- LastUpdated
@UpdatedBy,     -- UpdatedBy
NULL,       -- AgentCharge
NULL,       -- ChargeEffDate
NULL,       -- ChargeCalcDate
AG.Code,      -- Seller Code
AG.CompetentStatus,   -- Status
case AG.CompetentStatus when 1 then 'Active' when 2 then 'Left' when 3 then 'Dead'
when 4 then 'Canc' when 5 then 'PreApp' when 6 then 'NPW' end,  --StatusDesc
case AG.CanSupervise when 1 then 'Y' else 'N' end,    -- CanSupervise
case AG.GivesAdvice when 'Y' then 'Y' else 'N' end,   -- GivesAdvice
AG.AgentCategory,   -- Category
AG.AgentCategoryDescription,  -- CategoryDesc
coalesce(AG.OscarDateStarted,AG.DateStarted),     -- DateStarted
AG.DateLeaving,     -- DateLeft
AG.CDIStatusDate,   -- StatusDate
AG.AgentType,     -- Type
case AG.AgentType when 3 then 'IAR' when 4 then 'PFA' when 5 then 'Admin' when 43 then 'Prac Prin' 
when 45 then '10% Share' when 51 then 'PFA Prin' end,   -- TypeDesc
NULL,       -- Transfer
NULL,       -- TransferFirm
NULL,       -- TranEffDate
AG.SpanSupervisorCode,    -- SupervisedBy
NULL,       -- SupervisorType
NULL,       -- Comp_PenInv
NULL,       -- Comp_Mort
NULL,       -- Comp_ICOB
NULL,       -- Comp_GI
NULL        -- ChargeType
from #Agents AG
inner join owhot_SupervisorChargeBusiness SB on SB.BusinessCode = AG.Firm
where AG.AgentType in (3,4,5,43,45,51)
and (AG.CompetentStatus in (1,5) 
     or (AG.CompetentStatus in (2,3) and AG.CDIStatusDate >= @LeaverDate))
and SB.Month = @RunMonth

-- Extract Seller Moves in Period
Select AgentCode as Seller,DetailAgentCode as Business,ParticipantType as RelType,StartDate,EndDate,Status,DefaultValue
into #SellerMoves
from msit_AgentHierarchyHistory
where ParticipantType in (6,7,8,9)    -- Business/Seller Relationship
and EndDate between @StartDate and @EndDate -- Relationship ended in period
and DefaultValue = 1        -- Valid Relationship
--and (datepart(yy,startdate) <> datepart(yy,enddate)   -- Start/End in Diff Year
--     or datepart(mm,startdate) = datepart(mm,enddate))  -- Start/End in Diff Year
order by AgentCode

-- Identify earliest and Latest Moves in Period
-- Need to do this to ignore Transfers within Period
Select Seller,Min(EndDate) as FirstDate,Max(EndDate) as LastDate
into #SellerDates
from #SellerMoves
group by Seller
order by Seller

-- Update Seller Transfer In Details for Current Business (as at end of Period)
update owhot_SupervisorChargeSellers
set Transfer     = 'In',
    TransferFirm = t2.Business,
    TranEffDate  = dateadd(dd,1,t1.LastDate)  -- Add one day to give Start Date
from owhot_SupervisorChargeSellers SS
inner join #SellerDates t1 on t1.Seller = SS.Code
inner join #SellerMoves t2 on t2.Seller = t1.Seller and t1.LastDate = t2.EndDate
where SS.Month = @Runmonth 
and SS.BusinessCode <> t2.Business

-- Insert Transfer Out Seller row for Previous Business (as at Start of Period)
INSERT into owhot_SupervisorChargeSellers
(BusinessCode,Month,LastUpdated,UpdatedBy,AgentCharge,ChargeEffDate,ChargeCalcDate,
Code,Status,StatusDesc,CanSupervise,GivesAdvice,Category,CategoryDesc,DateStarted,DateLeft,
StatusDate,Type,TypeDesc,Transfer,TransferFirm,TranEffDate,SupervisedBy,SupervisorType,
Comp_PenInv,Comp_Mort,Comp_ICOB,Comp_GI,ChargeType)
select 
t2.Business,      -- BusinessCode
@RunMonth,      -- Month
@RunDateTime,     -- LastUpdated
@UpdatedBy,     -- UpdatedBy
NULL,       -- AgentCharge
NULL,       -- ChargeEffDate
NULL,       -- ChargeCalcDate
AG.Code,      -- Seller Code
AG.CompetentStatus,   -- Status
case AG.CompetentStatus when 1 then 'Active' when 2 then 'Left' when 3 then 'Dead'
when 4 then 'Canc' when 5 then 'PreApp' when 6 then 'NPW' end,      --StatusDesc
case AG.CanSupervise when 1 then 'Y' else 'N' end,        -- CanSupervise
case AG.GivesAdvice when 'Y' then 'Y' else 'N' end,       -- GivesAdvice
AG.AgentCategory,   -- Category
AG.AgentCategoryDescription,  -- CategoryDesc
coalesce(AG.OscarDateStarted,AG.DateStarted),         -- DateStarted
AG.DateLeaving,     -- DateLeft
AG.CDIStatusDate,   -- StatusDate
AG.AgentType,     -- Type
case AG.AgentType when 3 then 'IAR' when 4 then 'PFA' when 5 then 'Admin' when 43 then 'Prac Prin' 
when 45 then '10% Share' when 51 then 'PFA Prin' end,       -- TypeDesc
'Out',        -- Transfer
AG.Firm,      -- TransferFirm
t1.FirstDate,     -- TranEffDate
AG.SpanSupervisorCode,    -- SupervisedBy
NULL,       -- SupervisorType
NULL,       -- Comp_PenInv
NULL,       -- Comp_Mort
NULL,       -- Comp_ICOB
NULL,       -- Comp_GI
NULL        -- ChargeType
from #Agents AG
inner join #SellerDates t1 on t1.Seller = Code
inner join #SellerMoves t2 on t2.Seller = t1.Seller and t1.FirstDate = t2.EndDate
where t2.Business <> AG.Firm

-- update supervisorType
update owhot_SupervisorChargeSellers
set SupervisorType = case when AG.AgentType in ('52','53','54','55') then 'Manager' 
        when AG.AgentType in ('3','4','5','43','45','51') then 'Prac Super'
        else 'Other' end
from owhot_SupervisorChargeSellers SS
inner join #Agents AG on AG.Code = SS.SupervisedBy
where SS.Month = @RunMonth

-- Extract Seller Competency Details for Period
select act.ID,act.AgentCode,act.CodeComplianceCategoryID as CategoryID,
case act.CodeComplianceCategoryID 
when 1 then 'ICOB' when 2 then 'GI' when 3 then 'Mort' when 4 then 'PenInv' end as Category,
act.AgentControlFunctionCode as StatusCode,case act.AgentControlFunctionCode 
when 'FC' then 'Full' when 'IC' then 'Interim' when 'NA' then 'N/A' when 'NC' then 'Not'
when 'S1' then 'Stage 1' when 'SC' then 'Suspended' when 'SS' then 'Sick/Mat' else 'N/A'
end as Status,act.DateAppointed,act.AchievedDate,isnull(act.EndDate,'31 Dec 2999') as EndDate,aci.DateCreated
into #Competencies
from mstt_agentCompetence act
inner join msit_agentCompetence aci on aci.id = act.id
where act.CodeComplianceCategoryID in (1,2,3,4)
and (act.EndDate is null or act.EndDate >= @StartDate)
Order by act.AgentCode,act.CodeComplianceCategoryID,act.ID

-- Apply Seller Competencies to Seller Table
/*
update owhot_SupervisorChargeSellers
set Comp_PenInv   = case when t1.CategoryID = 4 and t1.EndDate <= @EndDate then 'Ended' 
       when t1.CategoryID = 4 and t1.EndDate > @EndDate then t1.Status end,
    Comp_Mort     = case when t1.CategoryID = 3 and t1.EndDate <= @EndDate then 'Ended' 
       when t1.CategoryID = 3 and t1.EndDate > @EndDate then t1.Status end,
    Comp_ICOB     = case when t1.CategoryID = 1 and t1.EndDate <= @EndDate then 'Ended' 
       when t1.CategoryID = 1 and t1.EndDate > @EndDate then t1.Status end,
    Comp_GI       = case when t1.CategoryID = 2 and t1.EndDate <= @EndDate then 'Ended' 
       when t1.CategoryID = 2 and t1.EndDate > @EndDate then t1.Status end
from owhot_SupervisorChargeSellers SS
inner join #Competencies t1 on t1.AgentCode = SS.Code
where SS.Month = @Runmonth 
*/

update owhot_SupervisorChargeSellers
set Comp_PenInv   = case when t1.CategoryID = 4 and t1.EndDate <= @EndDate then 'Ended' 
       when t1.CategoryID = 4 and t1.EndDate > @EndDate then t1.Status end
from owhot_SupervisorChargeSellers SS
inner join #Competencies t1 on t1.AgentCode = SS.Code and t1.CategoryID = 4
where SS.Month = @Runmonth 

update owhot_SupervisorChargeSellers
set Comp_Mort     = case when t1.CategoryID = 3 and t1.EndDate <= @EndDate then 'Ended' 
       when t1.CategoryID = 3 and t1.EndDate > @EndDate then t1.Status end
from owhot_SupervisorChargeSellers SS
inner join #Competencies t1 on t1.AgentCode = SS.Code and t1.CategoryID = 3
where SS.Month = @Runmonth 

update owhot_SupervisorChargeSellers
set Comp_ICOB    = case when t1.CategoryID = 1 and t1.EndDate <= @EndDate then 'Ended' 
      when t1.CategoryID = 1 and t1.EndDate > @EndDate then t1.Status end
from owhot_SupervisorChargeSellers SS
inner join #Competencies t1 on t1.AgentCode = SS.Code and t1.CategoryID = 1
where SS.Month = @Runmonth 

update owhot_SupervisorChargeSellers
set Comp_GI   =    case when t1.CategoryID = 2 and t1.EndDate <= @EndDate then 'Ended' 
      when t1.CategoryID = 2 and t1.EndDate > @EndDate then t1.Status end
from owhot_SupervisorChargeSellers SS
inner join #Competencies t1 on t1.AgentCode = SS.Code and t1.CategoryID = 2
where SS.Month = @Runmonth 

-- Derive Seller Charge Type
update owhot_SupervisorChargeSellers
set ChargeType = case
     when SS.Type in (43,51) and SS.GivesAdvice = 'Y' and SS.SupervisorType = 'Manager' then 'PP'
     when SS.Type in (43,51) and SS.CanSupervise = 'Y' and SS.SupervisorType = 'Manager' then 'NS Sup'
     when SS.Type not in (43,51) and SS.CanSupervise = 'Y' and SS.SupervisorType = 'Manager' then 'PFA Sup'
     when SS.GivesAdvice = 'Y' and SS.Comp_PenInv not in ('N/A','Not') and SS.SupervisorType = 'Manager' then 'P&I'
     when SS.GivesAdvice = 'Y' and SS.Comp_Mort not in ('N/A','Not') and SS.SupervisorType = 'Manager' then 'Mort'
     when SS.GivesAdvice = 'Y' and SS.Comp_ICOB not in ('N/A','Not') and SS.SupervisorType = 'Manager' then 'ICOB'
     when SS.GivesAdvice = 'Y' and SS.Comp_GI not in ('N/A','Not') and SS.SupervisorType = 'Manager' then 'GI'
     end
from owhot_SupervisorChargeSellers SS
where SS.Month = @Runmonth
and ( SS.Status = 1 or (SS.Status in (2,3) and SS.StatusDate >= @StartDate) ) -- Active or Inactive this Period
and isnull(SS.Transfer,'No') <> 'In'  -- Did not Transfer INTO Business during Period
and SS.DateStarted < @StartDate   -- Include if Start Date earlier than Period Start Date

drop table #SellerDates
drop table #SellerMoves
drop table #Competencies
drop table #Agents

END

-- END of Business/Seller Update Processing------------------------------------------------------------------

-- Access Charges Table and find Prevailing Supervision Charges
select max(Month) as ChargeMonth 
into #ChargeMonth 
from owhot_OpenworkCharges 
where Month <= @RunMonth

select t1.ChargeMonth,OC.UpdatedBy,OC.DateUpdated,@RunMonth as RunMonth,
OC.PracPrincharge,OC.PenInvCharge,OC.MortgageCharge,OC.ICOBCharge,OC.GICharge
into #SupCharges
from owhot_OpenworkCharges OC
inner join #ChargeMonth t1 on OC.Month = t1.ChargeMonth

-- If no valid Charge present then exit Calculation processing

IF (Select Count(*) from #SupCharges) > 0 
AND ((@RecalcFlag = 'B' AND @LastChargeMonth < @RunMonth) OR @RecalcFlag <> 'B')
BEGIN

-- Apply Seller Supervision Charges
update owhot_SupervisorChargeSellers
set UpdatedBy   = @UpdatedBy,
    LastUpdated   = @RunDatetime,
    ChargeEffDate = t1.ChargeMonth,
    ChargeCalcDate  = @RunDateTime,
    AgentCharge   = case
            when SS.ChargeType in ('PP','NS Sup','PFA Sup') then PracPrinCharge
            when SS.ChargeType in ('P&I') then PenInvCharge
            when SS.ChargeType in ('Mort') then MortgageCharge
            when SS.ChargeType in ('ICOB') then ICOBCharge
            when SS.ChargeType in ('GI') then GICharge
        else NULL end
from owhot_SupervisorChargeSellers SS
inner join #SupCharges t1 on t1.RunMonth = SS.Month
where SS.Month = @RunMonth 
and SS.Status in (1,2,3)

-- Derive Business Totals
Select BusinessCode,sum(isnull(AgentCharge,0)) as TotalCharge,
sum(case when ChargeType = 'GI' then 1 else 0 end) as GICount,
sum(case when ChargeType = 'ICOB' then 1 else 0 end) as ICOBCount,
sum(case when ChargeType = 'Mort' then 1 else 0 end) as MortgageCount,
sum(case when ChargeType = 'P&I' then 1 else 0 end) as PenInvCount,
sum(case when ChargeType = 'PP' then 1 else 0 end) as PracPrinCount,
sum(case when ChargeType in ('NS Sup','PFA Sup') then 1 else 0 end) as SupervisorCount,
sum(case when ChargeType is not NULL then 1 else 0 end) as TotalChargedCount
into #BusinessTotals
from owhot_SupervisorChargeSellers
where Month = @RunMonth 
and Status in (1,2,3)
group by BusinessCode
order by BusinessCode

-- Apply Business Details to Table
update owhot_SupervisorChargeBusiness
set UpdatedBy   = @UpdatedBy,
    LastUpdated   = @RunDatetime,
    TotalCharge   = t1.TotalCharge,
    GICount   = t1.GICount,
    ICOBCount   = t1.ICOBCount,
    MortgageCount = t1.MortgageCount,
    PenInvCount   = t1.PenInvCount,
    PracPrinCount = t1.PracPrinCount,
    SupervisorCount = t1.SupervisorCount,
    TotalChargedCount = t1.TotalChargedCount,
    ChargeEffDate = t2.ChargeMonth,
    ChargeCalcDate  = @RunDateTime
from owhot_SupervisorChargeBusiness SB
inner join #BusinessTotals t1 on t1.Businesscode = SB.BusinessCode
inner join #SupCharges t2 on t2.Runmonth = SB.Month
where SB.Month = @RunMonth

drop table #BusinessTotals

END

drop table #ChargeMonth
drop table #SupCharges

-- End of charges processing

-- Create Supervision Charge Trigger file

IF (@RunMonth = @LastCalendarMonth AND @RecalcFlag <> 'B') 
OR (@RecalcFlag = 'B' AND @LastChargeMonth < @RunMonth)
BEGIN
	exec owhop_SupervisionChargeStandingOrderDataProcessing
	--AG 28/03/2017 Start
	--exec mscp-run-dts-package 'owdts_supervisionchargestandingordertriggerextract'
	update dbo.owt_JobControl
		set JobStartRequired = 1,
			DateLastUpdatedByCaller = GETDATE()
	where JobCode = 'SUP-CHARGE-STD-ORDS'

	declare @JobName varchar(300)
	select	@JobName = JobName
	from	dbo.owt_JobControl
	where	JobCode = 'SUP-CHARGE-STD-ORDS'

	if dbo.owf_JobStillRunning(@JobName) = 0
		exec msdb.dbo.sp_start_job @JobName
	--AG 28/03/2017 End
END

-- End of Trigger processing


GO
