CREATE    PROCEDURE [dbo].[owhop_SupervisionChargeStandingOrderDataProcessing]


with recompile
as


declare @Month datetime
set @Month = (select max(Month) from owhot_SupervisorChargeBusiness)

declare @Today datetime
set @Today = CAST(CONVERT(NVARCHAR,getdate(),112) as datetime)

declare @Enddate datetime
set @enddate = CAST(CONVERT(NVARCHAR,dateadd(dd,2,getdate()),112) as datetime)


truncate table Head_Office_Systems.dbo.SupervisionChargeStandingOrderTriggers


insert into Head_Office_Systems.dbo.SupervisionChargeStandingOrderTriggers(StandingorderCode, BusinessCode, DueDate, EndDate, Amount, Frequency, Description)
   Select  '0000066' as StandingOrderCode,
  BusinessCode,
  CAST(CONVERT(NVARCHAR, @Today, 103) AS varchar(10)) as DueDate,
  CAST(CONVERT(NVARCHAR, @EndDate, 103) AS varchar(10)) as EndDate,
  cast( (-1*abs(TotalCharge)) as decimal(15,2)) as Amount,
  '6' as Frequency,
  Null as Description
From owhot_SupervisorChargeBusiness
where month = @Month
and TotalCharge > 0





