CREATE PROCEDURE [dbo].[owhop_SupervisorChargeBusiness_GetDetails]
@BusinessCode AS Varchar(7),
@Month AS Datetime

AS

SET @Month = COALESCE(@Month, (SELECT MAX([Month]) FROM owhot_SupervisorChargeBusiness))

SELECT  ag.Descn as BusinessName,
  coalesce(users.[Description],scb.UpdatedBy) As UpdatedByName,
  scb.*
FROM owhot_SupervisorChargeBusiness scb INNER JOIN mstt_Agents ag
    ON scb.BusinessCode = ag.Code LEFT OUTER JOIN msit_intusers users
  ON users.[Name] = scb.UpdatedBy
WHERE BusinessCode like '%' + COALESCE(@BusinessCode, BusinessCode) + '%' 
AND scb.[Month] = @Month
ORDER BY BusinessCode

