CREATE      procedure [dbo].[owhop_Suspense_add]


with recompile
as
BEGIN

insert into Head_Office_Systems.dbo.owhot_suspense (pacc_id,amendedBy,amendedDate)
select expid
,'Daily Load'
,getDate()
from owhot_paymentAudit a
left outer join Head_Office_Systems.dbo.owhot_suspense b on a.expid = b.pacc_id
where expid is not null
  and b.pacc_id is null


-- set all previously matched records to matched
update Head_Office_Systems.dbo.owhot_suspense
   set status = 'MATCHED'
      ,amendedby = 'Daily Load' 
      ,amendedDate = getdate()
 from mstt_expectation ex
where ex.init_id is not null
  and ex.ID = Head_Office_Systems.dbo.owhot_suspense.pacc_ID 
  and Head_Office_Systems.dbo.owhot_suspense.status <> 'MATCHED'

select 'got here'

-- set all negative receipts as clawback
update Head_Office_Systems.dbo.owhot_suspense
    set status = 'Clawback'
    ,amendedby = 'Daily Load'
    ,amendedDate = getdate()
 from mstt_expectation ex
where ex.ID = Head_Office_Systems.dbo.owhot_suspense.pacc_ID 
  and Head_Office_Systems.dbo.owhot_suspense.status = 'To Do'
  and ex.Amount_rec < 0

-- set all UCE as No Expectation
update Head_Office_Systems.dbo.owhot_suspense
    set status = 'NBS No Commision Expectation'
    ,amendedby = 'Daily Load'
    ,amendedDate = getdate()
 from mstt_expectation ex
where ex.ID = Head_Office_Systems.dbo.owhot_suspense.pacc_ID 
  and Head_Office_Systems.dbo.owhot_suspense.status = 'To Do'
  and ex.unallocatedreasoncode = 'UCE'

-- set all UCD and UPDs as No Client
update Head_Office_Systems.dbo.owhot_suspense
    set status = 'NBS No Client'
    ,amendedby = 'Daily Load'
    ,amendedDate = getdate()
 from mstt_expectation ex
where ex.ID = Head_Office_Systems.dbo.owhot_suspense.pacc_ID 
  and Head_Office_Systems.dbo.owhot_suspense.status = 'To Do'
  and (ex.unallocatedreasoncode = 'UCD' or ex.unallocatedreasoncode = 'UDP')
END






GO
