CREATE    PROCEDURE [dbo].[owhop_suspenseBulkUpdate] 
  -- Add the parameters for the stored procedure here
  @AssignedTo VARchar(25)
  ,@data varchar(8000)
  ,@GlbStmtProc char(1)
        ,@amendBy varchar(50)
 
  
AS
BEGIN



declare @h int


-- parse the XML
exec sp_xml_preparedocument @h OUTPUT, @data

-- get all the parms form the XML
if @AssignedTo <> '' begin

update Head_Office_Systems.dbo.owhot_suspense
set
  allocatedTo = @AssignedTo
 ,amendedBy = @AmendBy
 ,amendedDate = getdate()


from openXML(@h,'/ITEMS/ITEM',1)
  with  (pacc_id char(20)) I

Inner join Head_Office_Systems.dbo.owhot_suspense sus on sus.pacc_id = I.pacc_id

where sus.pacc_id = I.pacc_id

end



if @glbStmtProc<>''  begin

update Head_Office_Systems.dbo.owhot_suspense
set
  glbStmtProc = @glbStmtProc
 ,amendedBy = @AmendBy
 ,amendedDate = getdate()


--select 
--I.pacc_id
--,sus.AllocatedTo
--,sus.glbStmtProc
--,sus.amendedBy
--,sus.amendedDate

from openXML(@h,'/ITEMS/ITEM',1)
  with  (pacc_id char(20)) I

Inner join Head_Office_Systems.dbo.owhot_suspense sus on sus.pacc_id = I.pacc_id

where sus.pacc_id = I.pacc_id

end

END










