create table #Daily
(
Date datetime,
Weekday varchar(10),
ProviderType int,
ProviderDesc varchar(25),
StatType varchar(10),
CountStatement int,
CountLoaded int,
ValueLoaded float,
CountSuspense int,
ValueSuspense float,
CountAutomatch int,
ValueAutomatch float,
PC_CountAutomatch float,
PC_ValueAutomatch float,
CountManualMatch int,
