CountBacklogOther,
ValueBacklogOther
)

select 
@Yesterday as Date,
datename(dw,@Yesterday) as Weekday,
case when REC_ProviderType = 5 and StatementType <> 'EDI' then 6 
when REC_ProviderType = 2 and StatementType <> 'EDI' then 3 
when REC_ProviderType = 0 then 6 else REC_ProviderType end as ProviderType,
case when REC_ProviderType = 0 and StatementType = 'EDI' then 'Zurich' 
when REC_ProviderType = 0 and StatementType <> 'EDI' then 'Zurich/TALA Other' 
when REC_ProviderType = 1 and StatementType = 'EDI' then 'Mortgages' 
when REC_ProviderType = 1 and StatementType <> 'EDI' then 'Mortgages Other'
when REC_ProviderType = 2 and StatementType = 'EDI' then 'Sterling' 
when REC_ProviderType = 2 and StatementType <> 'EDI' then 'Sterling/SIML Other' 
when REC_ProviderType = 3 and StatementType = 'EDI' then 'SIML'
when REC_ProviderType = 3 and StatementType <> 'EDI' then 'Sterling/SIML Other'  
when REC_ProviderType = 4 and StatementType = 'EDI' then 'Scot Eq'
when REC_ProviderType = 4 and StatementType <> 'EDI' then 'Scot Eq Other'
when REC_ProviderType = 5 and StatementType = 'EDI' then 'TALA' 
when REC_ProviderType = 5 and StatementType <> 'EDI' then 'Zurich/TALA Other' 
when REC_ProviderType = 6 and StatementType = 'EDI' then 'Zurich' 

when REC_ProviderType = 6 and StatementType <> 'EDI' then 'Zurich/TALA Other' 
end as ProviderDesc,
pa.statementtype as StatType, 
case when rec_loaddate >= @StartDate then pa.statement end as CountStatement,
case when rec_loaddate >= @StartDate then 1 else 0 end as CountLoaded,
case when rec_loaddate >= @StartDate then AmountRec else 0 end as ValueLoaded,
case when rec_suspensedate >= @StartDate then 1 else 0 end as CountSuspense,
case when rec_suspensedate >= @StartDate then AmountRec else 0 end as ValueSuspense,
case when rec_automatchdate >= @StartDate then 1 else 0 end as CountAutomatch,
case when rec_automatchdate >= @StartDate then AmountRec else 0 end as ValueAutomatch,
0.00 as PC_CountAutomatch,
0.00 as PC_ValueAutomatch,
case when rec_loaddate >= @StartDate and t2.Status = 'Matched' then 1 else 0 end as CountManualMatch,
case when rec_loaddate >= @StartDate and t2.Status = 'Matched' then AmountRec else 0 end as ValueManualMatch,
case when rec_loaddate >= @StartDate and t2.Status = 'Awaiting Matched' then 1 else 0 end as CountAwaiting,
case when rec_loaddate >= @StartDate and t2.Status = 'Awaiting Matched' then AmountRec else 0 end as ValueAwaiting,
0.00 as PC_CountManualAwaiting,
0.00 as PC_ValueManualAwaiting,
0.00 as CountAllMatch,
0.00 as ValueAllMatch,
0.00 as PC_CountAllMatch,
0.00 as PC_ValueAllMatch,
case when rec_loaddate >= @StartDate and t2.Status = 'Clawback' then 1 else 0 end as CountClawbacks,
case when rec_loaddate >= @StartDate and t2.Status = 'Clawback' then AmountRec else 0 end as ValueClawbacks,
case when rec_loaddate >= @StartDate and t2.Status = 'NBS No Client' then 1 else 0 end as CountNoClient,
case when rec_loaddate >= @StartDate and t2.Status = 'NBS No Client' then AmountRec else 0 end as ValueNoClient,
case when rec_loaddate >= @StartDate and t2.Status = 'NBS No Commission Expectation' then 1 else 0 end as CountNoExpectation,
case when rec_loaddate >= @StartDate and t2.Status = 'NBS No Commission Expectation' then AmountRec else 0 end as ValueNoExpectation,
case when rec_loaddate >= @StartDate and t2.Status = 'Other Query' then 1 else 0 end as CountOtherQuery,
case when rec_loaddate >= @StartDate and t2.Status = 'Other Query' then AmountRec else 0 end as ValueOtherQuery,
case when rec_loaddate >= @StartDate and t2.Status = 'Contra Entry' then 1 else 0 end as CountContraEntry,
case when rec_loaddate >= @StartDate and t2.Status = 'Contra Entry' then AmountRec else 0 end as ValueContraEntry,
case when rec_loaddate >= @StartDate and t2.Status = 'To Do' then 1 else 0 end as CountToDo,
case when rec_loaddate >= @StartDate and t2.Status = 'To Do' then AmountRec else 0 end as ValueToDo,
case when rec_loaddate < @StartDate and t2.AmendedDate >= @StartDate and t2.Status = 'Matched' then 1 else 0 end as CountBacklogMatched,
case when rec_loaddate < @StartDate and t2.AmendedDate >= @StartDate and t2.Status = 'Matched' then AmountRec else 0 end as ValueBacklogMatched,
case when rec_loaddate < @StartDate and t2.Status = 'Awaiting Matched' then 1 else 0 end as CountBacklogAwaiting,
case when rec_loaddate < @StartDate and t2.Status = 'Awaiting Matched' then AmountRec else 0 end as ValueBacklogAwaiting,
case when rec_loaddate < @StartDate and t2.Status not in ('Matched','Awaiting Matched') then 1 else 0 end as CountBacklogOther,
case when rec_loaddate < @StartDate and t2.Status not in ('Matched','Awaiting Matched') then AmountRec else 0 end as ValueBacklogOther

--from owhot_paymentaudit pa (index=dailystats)
from owhot_paymentaudit pa with (index(dailystats))   -- PR use SQL 2005 method for index hint
--from #matches pa 
-- left outer join owhot_EDI_Statement_Exclude t1 on t1.statement = pa.statement
 left outer join Head_Office_Systems.dbo.owhot_EDI_Statement_Exclude t1 on t1.statement = pa.statement
-- left outer join Head_Office_Systems.dbo.owhot_suspense t2 (index=pac_id_status)  on t2.pacc_id = pa.expid
 left outer join Head_Office_Systems.dbo.owhot_suspense t2 with (index(pac_id_status)) on t2.pacc_id = pa.expid    -- PR use SQL 2005 method for index hint
where pa.status in (2,3)
  and t1.statement is null        -- Statement not on Excluded Statements table
--  and (t2.status is null or t2.status <> 'DELETED') -- Suspense Item not flagged as Deleted
  and t2.status <> 'DELETED'
  and(
--  (pa.rec_loaddate >= @startdate  )
--  or
--  (pa.rec_suspensedate >= @startdate )
--  or
--  (pa.rec_automatchdate >= @startdate )
  (pa.rec_loaddate >= @startdate  and pa.rec_loaddate <= @enddate)
  or
  (pa.rec_suspensedate >= @startdate and pa.rec_suspensedate <= @enddate)
  or
  (pa.rec_automatchdate >= @startdate and pa.rec_automatchdate <= @enddate)
  )







update #daily
set countallmatch = countmanualmatch + countautomatch,
valueallmatch = valuemanualmatch + valueautomatch

