select max(Date),max(Weekday),ProviderType as Provider,ProviderDesc,
count(distinct countstatement) as CountStatement,
--0 as countStatement,
sum(countloaded) as CasesLoaded,sum(valueloaded) as ValueLoaded,
sum(countsuspense) as CasesSuspense,sum(valuesuspense) as ValueSuspense,
sum(countautomatch) as CasesAutomatch,sum(valueautomatch) as ValueAutomatch,
0.00 as PC_CasesAutomatch,0.00 as PC_ValueAutomatch,
sum(countmanualmatch) as CasesManualMatch,sum(valuemanualmatch) as ValueManualMatch,
sum(countawaiting) as CasesAwaiting,sum(valueawaiting) as ValueAwaiting,
0.00 as PC_CasesManualAwaiting,0.00 as PC_ValueManualAwaiting,
sum(CountAllMatch) as CasesAllMatch,sum(ValueAllMatch) as ValueAllMatch,
0.00 as PC_CasesAllMatch,0.00 as PC_ValueAllMatch,
sum(countclawbacks) as CasesClawbacks,sum(valueclawbacks) as ValueClawbacks,
sum(countnoclient) as CasesNoClient,sum(valuenoclient) as ValueNoClient,
sum(countNoExpectation) as CasesNoExpectation,sum(valueNoExpectation) as ValueNoExpectation,
sum(countOtherQuery) as CasesOtherQuery,sum(valueOtherQuery) as ValueOtherQuery,
sum(countContraEntry) as CasesContraEntry,sum(valueContraEntry) as ValueContraEntry,
sum(countToDo) as CasesToDo,sum(valueToDo) as ValueToDo,
sum(countBacklogMatched) as CasesBacklogMatched,sum(valueBacklogMatched) as ValueBacklogMatched,
sum(countBacklogAwaiting) as CasesBacklogAwaiting,sum(valueBacklogAwaiting) as ValueBacklogAwaiting,
sum(countBacklogOther) as CasesBacklogOther ,sum(valueBacklogOther) as ValueBacklogOther
from #Daily
group by ProviderType,ProviderDesc
--group by Date,Weekday,ProviderType,ProviderDesc
--order by Date,ProviderType,ProviderDesc

select Date,Provider,ProviderDesc,CountStatement as EDIFiles,
--Cases
CasesLoaded as TotalCases,CasesAutomatch,
case when CasesLoaded > 0 then (100*CasesAutomatch)/CasesLoaded end as PC_CasesAutomatch,
CasesSuspense,CasesManualMatch,CasesAwaiting,
case when CasesLoaded > 0 then (100*(CasesAutomatch+CasesAwaiting+CasesManualMatch))/CasesLoaded 
end as PC_CasesManual,
(CasesAutomatch+CasesManualMatch) as CasesMatched,
case when CasesLoaded > 0 then (100*(CasesAutomatch+CasesManualMatch))/CasesLoaded end as PC_CasesMatched,
CasesClawbacks,CasesNoClient,CasesNoExpectation,CasesOtherQuery,CasesContraEntry,CasesToDo,
CasesBacklogMatched,CasesBacklogAwaiting,CasesBacklogOther,
--Values
ValueLoaded as TotalValue,ValueAutomatch,
case when ValueLoaded <> 0 then (100*ValueAutomatch)/abs(ValueLoaded) end as PC_ValueAutomatch,
ValueSuspense,ValueManualMatch,ValueAwaiting,
case when ValueLoaded <> 0 then (100*(ValueAutomatch+ValueAwaiting+ValueManualMatch))/abs(ValueLoaded) 
end as PC_ValueManual,
(ValueAutomatch+ValueManualMatch) as ValueMatched,
case when ValueLoaded <> 0 then (100*(ValueAutomatch+ValueManualMatch))/abs(ValueLoaded)
end as PC_ValueMatched,
ValueClawbacks,ValueNoClient,ValueNoExpectation,ValueOtherQuery,ValueContraEntry,ValueToDo,
ValueBacklogMatched,ValueBacklogAwaiting,ValueBacklogOther
into #Auto
from #Totals
--order by 2,3,1

select Date,
case ProviderType when 1 then 1 when 2 then 3 when 3 then 4 when 4 then 6 end as Provider,
case ProviderType when 1 then 'Mortgages Other' when 2 then 'Sterling/SIML Other'
when 3 then 'Scot Eq Other' when 4 then 'Zurich/TALA Other' end as ProviderDesc,
totalstatements as EDIFiles,
--Case Totals
(automatchedcases+suspensecases) as TotalCases,automatchedcases as CasesAutomatch,
case when (automatchedcases+suspensecases) > 0 
then (100*automatchedcases)/(automatchedcases+suspensecases) end as PC_CasesAutomatch, 
suspensecases as CasesSuspense,manualmatchedcases as CasesManualMatch,awaitingmatchcases as CasesAwaiting,
case when (automatchedcases+suspensecases) > 0 
then (100*(automatchedcases+manualmatchedcases+awaitingmatchcases))/(automatchedcases+suspensecases) 
end as PC_CasesManual, 
(automatchedcases+manualmatchedcases) as CasesMatched,
case when (automatchedcases+suspensecases) > 0
then (100*(manualmatchedcases+automatchedcases))/(automatchedcases+manualmatchedcases) 
end as PC_CasesMatched, 
clawbackcases as CasesClawbacks,noclientcases as CasesNoClient,noExpcases as CasesNoExpectation,
othercases as CasesOtherQuery,contracases as CasesContraEntry,todocases as CasesToDo,
bkmatchedcases as CasesBacklogMatched,bkAwaitMatchCases as CasesBacklogAwaiting,
bkOtherCases as CasesBackLogOther ,
--Value Totals
(automatchedValue+suspenseValue) as TotalValue,automatchedValue as ValueAutomatch,
case when (automatchedValue+suspenseValue) > 0 
then (100*automatchedValue)/abs(automatchedValue+suspenseValue) end as PC_ValueAutomatch, 
suspenseValue as ValueSuspense,manualmatchedValue as ValueManualMatch,awaitingmatchValue as ValueAwaiting,
case when (automatchedValue+suspenseValue) > 0 
then (100*(automatchedValue+manualmatchedValue+awaitingmatchValue))/abs(automatchedValue+suspenseValue) 
end as PC_ValueManual, 
(automatchedValue+manualmatchedValue) as ValueMatched,
case when (automatchedValue+suspenseValue) > 0
then (100*(manualmatchedValue+automatchedValue))/abs(automatchedValue+manualmatchedValue) 
end as PC_ValueMatched, 
clawbackValue as ValueClawbacks,noclientValue as ValueNoClient,noExpValue as ValueNoExpectation,
otherValue as ValueOtherQuery,contraValue as ValueContraEntry,todoValue as ValueToDo,
bkmatchedValue as ValueBacklogMatched,bkAwaitMatchValue as ValueBacklogAwaiting,
bkOtherValue as ValueBackLogOther
into #Manual
from Head_Office_Systems.dbo.owhot_Manual_Stats 
where Date = @yesterday

