update #Results
set 
PC_CasesAutomatch = (100*CasesAutomatch)/TotalCases,
PC_CasesManual = (100*(CasesAutomatch+CasesAwaiting+CasesManualMatch))/TotalCases,
PC_CasesMatched = (100*(CasesAutomatch+CasesManualMatch))/TotalCases
from #Results t1
where t1.Provider = 98 and t1.TotalCases > 0 

update #Results
set PC_ValueAutomatch = (100*ValueAutomatch)/abs(TotalValue),
PC_ValueManual = (100*(ValueAutomatch+ValueAwaiting+ValueManualMatch))/abs(TotalValue),
PC_ValueMatched = (100*(ValueAutomatch+ValueManualMatch))/abs(TotalValue)
from #Results t1
where t1.Provider = 98 and TotalValue <> 0 

