select t1.Date,99 as Provider,'%' as ProviderDesc,NULL as EDIFiles,
NULL as TotalCases,
case when t1.TotalCases > 0 then (100 * t1.CasesAutomatch)/t1.TotalCases end as CasesAutomatch,
NULL as PC_CasesAutomatch,
case when t1.TotalCases > 0 then (100 * t1.CasesSuspense)/t1.TotalCases end as CasesSuspense,
case when t1.TotalCases > 0 then (100 * t1.CasesManualMatch)/t1.TotalCases end as CasesManualMatch,
case when t1.TotalCases > 0 then (100 * t1.CasesAwaiting)/t1.TotalCases end as CasesAwaiting,
NULL as PC_CasesManual,
case when t1.TotalCases > 0 then (100 * t1.CasesMatched)/t1.TotalCases end as CasesMatched,
NULL as PC_CasesMatched,
case when t1.TotalCases > 0 then (100 * t1.CasesClawbacks)/t1.TotalCases end as CasesClawbacks,
case when t1.TotalCases > 0 then (100 * t1.CasesNoClient)/t1.TotalCases end as CasesNoClient,
case when t1.TotalCases > 0 then (100 * t1.CasesNoExpectation)/t1.TotalCases end as CasesNoExpectation,
case when t1.TotalCases > 0 then (100 * t1.CasesOtherQuery)/t1.TotalCases end as CasesOtherQuery,
case when t1.TotalCases > 0 then (100 * t1.CasesContraEntry)/t1.TotalCases end as CasesContraEntry,
case when t1.TotalCases > 0 then (100 * t1.CasesToDo)/t1.TotalCases end as CasesToDo,
NULL as CasesBacklogMatched,NULL as CasesBacklogAwaiting,NULL as CasesBacklogOther ,
NULL as TotalValue,
case when t1.TotalValue > 0 then (100 * t1.ValueAutomatch)/t1.TotalValue end as ValueAutomatch,
NULL as PC_ValueAutomatch,
case when t1.TotalValue > 0 then (100 * t1.ValueSuspense)/t1.TotalValue end as ValueSuspense,
case when t1.TotalValue > 0 then (100 * t1.ValueManualMatch)/t1.TotalValue end as ValueManualMatch,
case when t1.TotalValue > 0 then (100 * t1.ValueAwaiting)/t1.TotalValue end as ValueAwaiting,
NULL as PC_ValueManual,
case when t1.TotalValue > 0 then (100 * t1.ValueMatched)/t1.TotalValue end as ValueMatched,
NULL as PC_ValueMatched,
case when t1.TotalValue > 0 then (100 * t1.ValueClawbacks)/t1.TotalValue end as ValueClawbacks,
case when t1.TotalValue > 0 then (100 * t1.ValueNoClient)/t1.TotalValue end as ValueNoClient,
case when t1.TotalValue > 0 then (100 * t1.ValueNoExpectation)/t1.TotalValue end as ValueNoExpectation,
case when t1.TotalValue > 0 then (100 * t1.ValueOtherQuery)/t1.TotalValue end as ValueOtherQuery,
case when t1.TotalValue > 0 then (100 * t1.ValueContraEntry)/t1.TotalValue end as ValueContraEntry,
case when t1.TotalValue > 0 then (100 * t1.ValueToDo)/t1.TotalValue end as ValueToDo,
NULL as ValueBacklogMatched,NULL as ValueBacklogAwaiting,NULL as ValueBacklogOther
from #Results t1
where t1.Provider = 98 

select * from #Results 
order by provider,providerdesc


--drop table #matches

drop table #daily
drop table #totals
drop table #auto
drop table #manual
drop table #results
















