/****** Object:  StoredProcedure [dbo].[owhop_SuspenseTotalsForPeriod]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO







CREATE      procedure [dbo].[owhop_SuspenseTotalsForPeriod]
@RunDate varchar(10)

with recompile
as
 
--########################################################################
--
-- Object  : procedure
-- Name    : owhop_SuspenseTotalsForPeriod.sql
-- Owner   : MPC
-- Created : 14/09/2007
--
--########################################################################

set nocount on

declare @Today datetime   set @Today = CAST(CONVERT(NVARCHAR,@Rundate,112) as datetime)
declare @Yesterday datetime   set @yesterday = CAST(CONVERT(NVARCHAR,dateadd(dd,-1,@Today),112) as datetime)
declare @startdate datetime set @startdate = (select periodstartdate from msit_commissionstatementperiods 
               where @yesterday between periodstartdate and periodenddate)
declare @enddate datetime set @enddate = (select periodenddate from msit_commissionstatementperiods 
               where @yesterday between periodstartdate and periodenddate)

create table #temp
(
Date datetime,
Weekday varchar(10),
OrigDate datetime,
OrigWeekday varchar(10),
ProviderType int,
CountLoad int,
ValueLoad float,
CountSuspense int,
ValueSuspense float,
CountAutomatch int,
ValueAutomatch float,
CountMatch int,
ValueMatch float
)

   insert into #Temp (Date,Weekday,OrigDate,OrigWeekday,ProviderType,
CountLoad,ValueLoad,CountSuspense,ValueSuspense,CountAutomatch,ValueAutomatch,CountMatch,ValueMatch)
   select case when datename(dw,rec_loaddate) = 'Saturday' then dateadd(dd,-1,rec_loaddate)
    when datename(dw,rec_loaddate) = 'Sunday' then dateadd(dd,-2,rec_loaddate) else rec_loaddate end as Date,
    case when datename(dw,rec_loaddate) = 'Saturday' then 'Friday'
    when datename(dw,rec_loaddate) = 'Sunday' then 'Friday' else datename(dw,rec_loaddate) end as Weekday,
    rec_loaddate as OrigDate,datename(dw,rec_loaddate) as OrigWeekday,
    REC_ProviderType as ProviderType,
     1  as CountLoad,
    AmountRec  as ValueLoad,
     0  as CountSuspense,
     0  as ValueSuspense,
     0  as CountAutomatch,
     0  as ValueAutomatch,
     0  as CountMatch,
     0  as ValueMatch
   from owhot_paymentaudit 
   where status in (2,3) and Rec_ProviderType in (1,2,3,4) 
   and rec_loaddate between @startdate and @enddate

   insert into #Temp (Date,Weekday,OrigDate,OrigWeekday,ProviderType,
CountLoad,ValueLoad,CountSuspense,ValueSuspense,CountAutomatch,ValueAutomatch,CountMatch,ValueMatch)
   select case when datename(dw,rec_suspensedate) = 'Saturday' then dateadd(dd,-1,rec_suspensedate)
    when datename(dw,rec_suspensedate) = 'Sunday' then dateadd(dd,-2,rec_suspensedate) else rec_suspensedate end as Date,
    case when datename(dw,rec_suspensedate) = 'Saturday' then 'Friday'
    when datename(dw,rec_suspensedate) = 'Sunday' then 'Friday' else datename(dw,rec_suspensedate) end as Weekday,
    rec_suspensedate as OrigDate,datename(dw,rec_suspensedate) as OrigWeekday,
    REC_ProviderType as ProviderType,
    0 as CountLoad,
    0 as ValueLoad,
    1 as CountSuspense,
    AmountRec as ValueSuspense,
    0 as CountAutomatch,
    0 as ValueAutomatch,
    0 as CountMatch,
    0 as ValueMatch
   from owhot_paymentaudit 
   where status in (2,3) and Rec_ProviderType in (1,2,3,4) 
   and (rec_suspensedate between @startdate and @enddate)


   insert into #Temp (Date,Weekday,OrigDate,OrigWeekday,ProviderType,
CountLoad,ValueLoad,CountSuspense,ValueSuspense,CountAutomatch,ValueAutomatch,CountMatch,ValueMatch)
   select case when datename(dw,rec_automatchdate) = 'Saturday' then dateadd(dd,-1,rec_automatchdate)
    when datename(dw,rec_automatchdate) = 'Sunday' then dateadd(dd,-2,rec_automatchdate) else rec_automatchdate end as Date,
    case when datename(dw,rec_automatchdate) = 'Saturday' then 'Friday'
    when datename(dw,rec_automatchdate) = 'Sunday' then 'Friday' else datename(dw,rec_automatchdate) end as Weekday,
    rec_automatchdate as OrigDate,datename(dw,rec_automatchdate) as OrigWeekday,
    REC_ProviderType as ProviderType,
    0 as CountLoad,
    0 as ValueLoad,
    0 as CountSuspense,
    0 as ValueSuspense,
    1 as CountAutomatch,
    AmountRec as ValueAutomatch,
    0 as CountMatch,
    0 as ValueMatch
   from owhot_paymentaudit 
   where status in (2,3) and Rec_ProviderType in (1,2,3,4) 
   and (rec_automatchdate between @startdate and @endDate)

   insert into #Temp (Date,Weekday,OrigDate,OrigWeekday,ProviderType,
CountLoad,ValueLoad,CountSuspense,ValueSuspense,CountAutomatch,ValueAutomatch,CountMatch,ValueMatch)
   select case when datename(dw,rec_matchdate) = 'Saturday' then dateadd(dd,-1,rec_matchdate)
    when datename(dw,rec_matchdate) = 'Sunday' then dateadd(dd,-2,rec_matchdate) else rec_matchdate end as Date,
    case when datename(dw,rec_matchdate) = 'Saturday' then 'Friday'
    when datename(dw,rec_matchdate) = 'Sunday' then 'Friday' else datename(dw,rec_matchdate) end as Weekday,
    rec_matchdate as OrigDate,datename(dw,rec_matchdate) as OrigWeekday,
    REC_ProviderType as ProviderType,
    0 as CountLoad,
    0 as ValueLoad,
    0 as CountSuspense,
    0 as ValueSuspense,
    0 as CountAutomatch,
    0 as ValueAutomatch,
    1 as CountMatch,
    AmountRec as ValueMatch
   from owhot_paymentaudit 
   where status in (2,3) and Rec_ProviderType in (1,2,3,4) 
   and (rec_matchdate between @startdate and @enddate)

--select * from #temp

select ProviderType as Provider,convert(varchar(10),Date, 101) as Date,
sum(countload) as CasesLoaded,sum(countsuspense) as CasesSuspense,
sum(countautomatch) as CasesAutomatch,sum(countmatch) as CasesManualMatch,NULL as CasesOtherMatch,
sum(valueload) as ValueLoaded,sum(valuesuspense) as ValueSuspense,
sum(valueautomatch) as ValueAutomatch,sum(valuematch) as ValueManualMatch,NULL as ValueOtherMatch
from #temp
group by ProviderType,convert(varchar(10),Date, 101)
order by ProviderType,Date

drop table #temp









GO
