CREATE                            PROCEDURE [dbo].[owhop_updateEcodeList]
         @ID as char(10)
  ,@ecode as char(7)
  ,@NoEcode as char(1)
        ,@Updatedby as varchar(50)     
AS
begin

if @ecode <> '' begin
declare @code char(7)
select @code = main_serial from msit_AgentInfo where substring(@ecode,2,5) = main_serial and main_prefix = left(@ecode, 1) and main_suffix = right(@ecode, 1)
  if @@rowcount =0 begin
    raiserror('Ecode %s not Valid',16,1,@Ecode)
    return
  end else begin
           if (@noecode <> '') begin
       
raiserror('Ecode  cannot be input if No Code is Yes',16,1,@noecode)--Ecode)
return
         
end else begin
          
           declare @codeX char(7)
           declare @Agentlevel char(1)
           declare @Agentcode char(10)
           select @Agentlevel = agentlevel from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref where ID = @ID 
           select @Agentcode = agentcode from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref where ID = @ID 

--   21/11/2007 modified validation 3.1

           
           
              select @codeX = agentcode from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref where substring(@ecode,2,5) = Oscar_Serial and AgentLevel = 'S' and AgentCode <> @Agentcode
               if (@codeX <> '' and @AgentLevel='S') begin             
                set @codeX = case @codeX when 'S' then 'Seller' end 
    raiserror('Ecode already linked to Seller',16,1,@codeX)
    return
                
               end else begin  

--   new changes 21/11/2007 validation 3.2
             declare @codeX1 char(10)
             declare @agentcde char(7)
              select @agentcde = Agentcode from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref where ID = @ID 
              select @codeX1 = Agentlevel from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref where substring(@ecode,2,5) = Oscar_Serial and AgentLevel <> 'S' and AgentCode <> @agentcde --<> @Agentcode    
               if (@@rowcount >0  and @AgentLevel<>'S') begin
                set @codeX1 = case @codeX1 when 'B' then 'Business' when 'M' then 'Manager' end
    raiserror('Ecode already linked to %s',16,1,@codeX1)
    return
    end
--   end validation 3.1 & 3.2
     
           declare @hserial char(7)
           declare @BusinessEcode char(7)
           
     declare @levela char(1)        
           select @BusinessEcode = Business_OSCAR_Serial from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref xf where xf.OSCAR_Serial = substring(@ecode,2,5) --AND xf.ID = @ID
           select @levela = agentlevel from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref where ID = @ID 
           select @hserial = host_serial from msit_AgentInfo where host_serial = @BusinessEcode
            if (@@rowcount =0 and @levela ='S') begin
               raiserror('Ecode not linked to current Business ',16,1,@hserial)
      return
             end else begin
--   GET BUSINESS CODE FROM SCREEN AND SAVE ONTO THE OWHOT_OSCARSWIFTAGENTXREF TABLE
declare @Business_Oscar_ID1 char(7)
declare @Business_Oscar_Prefix1 char(7)
declare @Business_Oscar_Serial1 char(7)
declare @Business_Oscar_Suffix1 char(7)

select @Business_Oscar_ID1 = OSCARAgentID from mstt_Agents where code = @Agentcode
select @Business_Oscar_Prefix1 = OSCARAgentPrefix from mstt_Agents where code = @Agentcode
select @Business_Oscar_Serial1 = OSCARAgentSerial from mstt_Agents where code = @Agentcode
select @Business_Oscar_Suffix1 = OSCARAgentSuffix from mstt_Agents where code = @Agentcode

--   Update record back on Mstt_Agents with correct Business Ecode from Screen
   declare @oscar_code char(7)
   select @oscar_code = agent_id from msit_AgentInfo where substring(@ecode,2,5) = main_serial


   declare @Business_OSCAR_ID0 char(7)
   select @Business_OSCAR_ID0 = agent_id from msit_AgentInfo where main_serial = @BusinessEcode    


          update Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref
            set    OSCAR_Prefix  = left(@ecode, 1)
            ,OSCAR_Serial = substring(@ecode,2,5)
      ,OSCAR_Suffix = right(@ecode, 1)  
      ,NoEcode = @noecode
            ,DateUpdated = getdate()
            ,UpdatedBy = @Updatedby
  
             where ID = @ID




---------------------------------     
  --  if (@Agentlevel ='S') begin   
--       declare @Bcode char(7)  
       declare @Agentcode1 char(7)    
  --     select @Bcode = BusinessCode from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref xf where xf.ID = @ID
      select @Agentcode1 = agentcode from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref where ID = @ID 
      Update mstt_Agents
      set OscarAgentID = @oscar_code
      ,OscarAgentPrefix = left(@ecode, 1)
      ,OscarAgentSerial = substring(@ecode,2,5)
      ,OscarAgentSuffix = right(@ecode, 1)
       -- where code = @Bcode
        where code = @Agentcode1
 --       end 
------------------------------------
     end
             end
  end
end


end else begin
if @NoEcode is null begin
      raiserror('Sorry... No input found %s ',16,1,@Ecode)
      return
    end else begin   --ELSE NOECODE IS SET TO 'YES'

--   GET BUSINESS CODE FROM SCREEN AND SAVE ONTO THE OWHOT_OSCARSWIFTAGENTXREF TABLE
declare @Business_Oscar_ID char(7)
declare @Business_Oscar_Prefix char(7)
declare @Business_Oscar_Serial char(7)
declare @Business_Oscar_Suffix char(7)

select @Business_Oscar_ID = OSCARAgentID from mstt_Agents where code = @Agentcode
select @Business_Oscar_Prefix = OSCARAgentPrefix from mstt_Agents where code = @Agentcode
select @Business_Oscar_Serial = OSCARAgentSerial from mstt_Agents where code = @Agentcode
select @Business_Oscar_Suffix = OSCARAgentSuffix from mstt_Agents where code = @Agentcode




--   Update record back on Mstt_Agents with correct Business Ecode from Screen
       declare @oscar_code2 char(7)
       select @oscar_code2 = agent_id from msit_AgentInfo where substring(@ecode,2,5) = main_serial

  declare @Business_OSCAR_ID01 char(7)
  select @Business_OSCAR_ID01 = agent_id from msit_AgentInfo where main_serial = @BusinessEcode 


-- Specifically to sellers only - Validation for seller
   if (@Agentlevel ='S') begin
      select @Business_Oscar_ID = agent_id from msit_AgentInfo where main_serial = @BusinessEcode 
      select @Business_Oscar_prefix = Business_OSCAR_Prefix from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref xf where xf.OSCAR_Serial = substring(@ecode,2,5) AND xf.ID = @ID
      select @Business_Oscar_Serial = Business_OSCAR_Serial from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref xf where xf.OSCAR_Serial = substring(@ecode,2,5) AND xf.ID = @ID
      select @Business_Oscar_Suffix = Business_OSCAR_Suffix from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref xf where xf.OSCAR_Serial = substring(@ecode,2,5) AND xf.ID = @ID
   end     

--End
  


update Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref
            set    OSCAR_Prefix  = null
            ,OSCAR_Serial = null
      ,OSCAR_Suffix = null
            ,Oscar_id = null
      ,NoEcode = @noecode
            ,DateUpdated = getdate()
            ,UpdatedBy = @Updatedby
  
             where ID = @ID 


               
   declare @aCode char(7)
   select @aCode = agentcode from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref xf where xf.ID = @ID
   Update mstt_Agents
    set OscarAgentID = null
   ,OscarAgentPrefix = null
   ,OscarAgentSerial = null
   ,OscarAgentSuffix = null
    where code = @aCode

end
end
end 











