/****** Object:  StoredProcedure [dbo].[owhop_updateMPLCharges]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/****************************************************************************
  	 Program:  	owhop_updateMPLCharges					
	  Author:	Unknown
Date created:	Unknown (maybe 2007?)							
											
Description:	This proc is used by the MPL Admin screen (Head Office Systems) 
				to update businesses on the MPL Standing Order file that is
				loaded into Swift. 
			
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
17/03/2011	A Groves	Update equivalent row on the letters file.	
21/03/2011	A Groves	Use f_CleanText to ensure no spurious commas in
							the address lines because this stops the mail
							merge from working correctly.
07/04/2017	A Groves	SR464996/CH16204. Replace DTS scripts with start of job 
						that contains SSIS replacement scripts: 
						1) "MPLChargeStandingOrderTriggerExtract.dtsx"
						2) "MPLChargeLetterTriggerExtract.dtsx"
****************************************************************************/
CREATE PROCEDURE [dbo].[owhop_updateMPLCharges]
	@ID as int 
	,@StandingorderCode as varchar(100)
	,@BusinessCode as nvarchar(50)
	,@DueDate as varchar(20)
	,@EndDate as varchar(20)
	,@Amount as varchar(20)
	,@Frequency as varchar(10)
	,@Description as varchar(10)

AS

declare @BDDUID				nvarchar(7),
		@BDDName			nvarchar(255),
		@ADUID				nvarchar(7),
		@ADName				nvarchar(255),
		@EndMonth			datetime,
		@ChargeMonth		datetime,
		@TotalTurnover		float,
		@MPLCharge			float,
		@MPLThreshold		float,
		@OldBusinessCode	nvarchar(7)			


-- 17/03/2011 Start

select	@OLDBusinessCode = BusinessCode
from	Head_Office_Systems.dbo.MPLChargeStandingOrderTriggers
where	[ID] = @ID

-- 17/03/2011 End

update Head_Office_Systems.dbo.MPLChargeStandingOrderTriggers
	set	BusinessCode = @BusinessCode,
		Amount	= @Amount,
		DueDate	= @DueDate,
		EndDate	= @EndDate           
where [ID] = @ID

-- AG 07/04/2017 Start
-- exec mscp-run-dts-package 'owdts_mplchargestandingordertriggerextract'
update dbo.owt_JobControl
		set JobStartRequired = 1,
			DateLastUpdatedByCaller = GETDATE()
where JobCode = 'MPL-CHARGE-STD-ORDS'

declare @JobName varchar(300)
select	@JobName = JobName
from	dbo.owt_JobControl
where	JobCode = 'MPL-CHARGE-STD-ORDS'

if dbo.owf_JobStillRunning(@JobName) = 0
	exec msdb.dbo.sp_start_job @JobName
-- AG 07/04/2017 End

-- 17/03/2011 Start

-- Obtain BDD and AD from the Business Hierarchy
select	@BDDUID		= BH.BDD_UID,
		@BDDName	= BH.BDD_Name,
		@ADUID		= BH.AD_UID,
		@ADName		= BH.AD_Name
from	f_Insight_GetBusinessSalesHierarchy() BH
where	BH.BusinessUID = @BusinessCode


-- Get latest charge date
select	@EndMonth = max(Month)
from	owhot_MPLCharges


-- Get total turnover for this business
Select	@TotalTurnover = isnull(Total_Turnover,0)
from	owhot_MPLCharges
where	BusinessCode = @BusinessCode
and		Month = @EndMonth


-- Access MPL Charges Table and find Prevailing Charge.
select	@ChargeMonth = max(Month)
from	owhot_OpenworkCharges 
where	Month <= @EndMonth


-- Get the Charge and threshold from the charges table
select	@MPLCharge = MPLCharge,
		@MPLThreshold = MPLThreshold
from	owhot_OpenworkCharges
where	Month = @ChargeMonth


Update Letters
	set BusinessCode		= @BusinessCode,
		BusinessName		= ag.DESCN,
		BusinessAddress1	= dbo.owf_CleanText(ag.Address1),
		BusinessAddress2	= dbo.owf_CleanText(ag.Address2),
		BusinessAddress3	= dbo.owf_CleanText(ag.Address3),
		BusinessAddress4	= dbo.owf_CleanText(ag.Address4),
		BusinessAddress5	= dbo.owf_CleanText(ag.Address5),
		BusinessPostcode	= dbo.owf_CleanText(ag.Postcode),
		MPLCharge			= case isnumeric(@Amount) when 1 then convert(decimal(15,2),abs(@Amount)) else convert(decimal(15,2),abs(@MPLCharge)) end,
		MPLThreshold		= convert(decimal(15,2),@MPLThreshold),
		BusinessTurnover	= convert(decimal(15,2),@TotalTurnover),
		Month				= @EndMonth,
		BDDCode				= @BDDUID,
		BDDName				= @BDDName,
		ADCode				= @ADUID,
		ADName				= @ADName	
from	mstt_Agents ag,
		owhot_MPLChargeLetterTriggers Letters 
where	ag.code = @BusinessCode
and		Letters.BusinessCode = @OldBusinessCode

-- 17/03/2011 End

-- AG 07/04/2017 Start
-- exec mscp-run-dts-package 'owdts_mplchargelettertriggerextract'
update dbo.owt_JobControl
	set JobStartRequired = 1,
		DateLastUpdatedByCaller = GETDATE()
where JobCode = 'MPL-CHARGE-LETTERS'

select	@JobName = JobName
from	dbo.owt_JobControl
where	JobCode = 'MPL-CHARGE-LETTERS'

if dbo.owf_JobStillRunning(@JobName) = 0
	exec msdb.dbo.sp_start_job @JobName
-- AG 07/04/2017 End


GO
