/****** Object:  StoredProcedure [dbo].[owoa_BankAccountSummaryRange]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE procedure [dbo].[owoa_BankAccountSummaryRange]
 @FranchiseCode nvarchar(20),
 @sMonth        datetime,
 @eMonth        datetime,
 @UserId    NVARCHAR(20)
as
-- Select Openwork entries
select source
  ,sum(OpeningBalance) as OpeningBalance
  ,sum(debit) as Debit
  ,sum(credit) as Credit
  ,sum(Payment) as Payment
  ,sum(ClosingBalance) as ClosingBalance 
  ,TotalType
  ,Month
from (
  select
   Source         = 'Openwork',
  --Source    = case when msit_OpenworkBankDetails.Source in ('Openwork 2005' , 'Openwork 2006') then 'Openwork'
  --      else msit_OpenworkBankDetails.Source
  --      end,
   OpeningBalance = case when TotalType = 0 then sum(Amount)
                         else 0.0
                    end,
   Debit          = case when TotalType = 1 then sum(Amount)
                         else 0.0
                    end,
   Credit         = case when TotalType = 2 then sum(Amount)
                         else 0.0
                    end,
   Payment        = case when TotalType = 3 then sum(Amount)
                         else 0.0
                    end,
   ClosingBalance = case when TotalType = 9 then sum(Amount)
                         else 0.0
                    end,
   TotalType      = TotalType,
   Month      = month
  from
   msit_OpenworkBankDetails
  where
   BusinessCode = @FranchiseCode  and
   [Month] <= @eMonth   and
   [Month] >= @sMonth   and 
   Source  in('Openwork 2005','Openwork 2006')
  group by
   source,
   TotalType,
   month
) a
group by  
 source,
 TotalType,
 month

union all

-- select ZAN entries
select
 Source         = Source,
 OpeningBalance = case when TotalType = 0 then sum(Amount)
                       else 0.0
                  end,
 Debit          = case when TotalType = 1 then sum(Amount)
                       else 0.0
                  end,
 Credit         = case when TotalType = 2 then sum(Amount)
                       else 0.0
                  end,
 Payment        = case when TotalType = 3 then sum(Amount)
                       else 0.0
                  end,
 ClosingBalance = case when TotalType = 9 then sum(Amount)
                       else 0.0
                  end,
 TotalType      = TotalType,
 month      = month
from
 msit_ZANBankDetails
where
 BusinessCode = @FranchiseCode and
 [Month] <= @eMonth              and
 [Month] >= @sMonth           
group by
 Source,
 TotalType,
 month


order by Source,[Month]


GO
/****** Object:  StoredProcedure [dbo].[owoa_buildSellerXref]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*****************************************************************************************************
     Program:   owoa_BuildSellerXref          
    Author: ?
Date created: ?             
                      
Description:  This proc populates table "owoa_SellerXref" from scratch each time the
        proc runs.  The table is used in OpenAccess when the user uses the 
        "Select PFA" picklist.  It basically shows all the sellers for the 
        Enterprise allowing the user to filter records on the screen by seller.

        This proc would be called as follows:

        1)  exec owoa_BuildSellerXref
        2)  exec owoa_BuildSellerXref 'N'
        3)  exec owoa_BuildSellerXref 'Y'
          
        
Amendment History               
-----------------               
                      
Date		Who			Description       
----		---			-----------     
21/09/2009	A Groves	1) Debug parameter added.
						2) Truncate rather than delete table owoa_sellerXref for perf improvement.
						3) When populating #MissingCode from the OAL recode the check that the rows 
						   are not already on owoa_SellerXref to boost performance as this proc
						   is slower on SQL2005 than SQL2000.
05/08/2014	D Lunnon	Incorrect Agent Hierarchy History updates on Swift can cause payments
						to be added to OpenAccess with a null BusinessCode. This proc has been
						fixed to cope with a blank BusinessCode to prevent a batch failure.
******************************************************************************************************/
CREATE PROCEDURE [dbo].[owoa_buildSellerXref]
  @debug varchar(1) = 'N'
AS
BEGIN

declare @RecordsAddedPhase1     int,
    @RecordsRemainingPhase1   int,
    @RecordsRemainingPhase2   int,
    @RecordsRemainingPhase3   int,
    @RecordsRemainingPhase4   int,
    @FoundStage2        int,
    @FoundStage3        int,
    @FoundStage4        int,
    @Msg            varchar(100)

if @Debug = 'Y' exec msp_ProcessLog 'START', '01) Create Table #missingCode', null, 'owoa_buildSellerXref', 'Openwork'

--create temp table
create table #missingCode(
      sellerName  varchar(100) COLLATE Latin1_General_CI_AS ,
      sellerCode  varchar(10) COLLATE Latin1_General_CI_AS,
      franchise   varChar(10) COLLATE Latin1_General_CI_AS
      )

if @Debug = 'Y' exec msp_ProcessLog 'START', '02) Delete owoa_SellerXref', null, 'owoa_buildSellerXref', 'Openwork'

--clear the table
--delete from owoa_SellerXref      AG 21/09/2009
truncate table owoa_SellerXref  -- AG 21/09/2009


if @Debug = 'Y' exec msp_ProcessLog 'START', '03) Insert owoa_SellerXref', null, 'owoa_buildSellerXref', 'Openwork'

-- add in the ones that are already good
insert owoa_SellerXref(sellerCode
                  ,sellerName
                  ,franchise
)
select distinct sellerCode
            ,ltrim(rtrim(sellerName))
            ,businessCode
from msit_openworkadviserlisting
where sellerCode is not null and businessCode is not null -- DL 5th Aug 2014 check for nul BusinessCode


-- check how many we did
if @debug = 'Y'
begin
  select @RecordsAddedPhase1 = count(*) from owoa_SellerXref
  select @Msg = '04) Count from owoa_SellerXref = ' + convert(varchar(10),@RecordsAddedPhase1)
  exec msp_ProcessLog 'START', @Msg, null, 'owoa_buildSellerXref', 'Openwork'
end

if @Debug = 'Y' exec msp_ProcessLog 'START', '05) Insert #missingCode', null, 'owoa_buildSellerXref', 'Openwork'

-- copy the remaing rows to the temp table
insert #missingCode(    sellerName
                  ,sellerCode
                  ,franchise
)
select      distinct
      ltrim(rtrim(sellerName))
      ,sellerCode
      ,businessCode
from msit_openworkadviserlisting oal
--where ltrim(rtrim(sellerName)) not in   AG 21/09/2009
--      ( select ltrim(rtrim(sellerName)) AG 21/09/2009
--          from owoa_SellerXref      AG 21/09/2009
--      )                 AG 21/09/2009
where oal.SellerName is not null   and businessCode is not null   -- AG 21/09/2009  5th Aug 2014 DL added BusinessCode not null constraint
and   not exists (select  1       -- AG 21/09/2009
          from  owoa_SellerXref xref 
          where xref.SellerName = ltrim(rtrim(oal.sellerName))
          and   xref.Franchise = oal.BusinessCode)  


-- count how many are left
if @debug = 'Y'
begin
  select @RecordsRemainingPhase1 = count(*) from #missingCode
  select @Msg = '06) Count #missingCode RecsRemainingPhase1 = ' + convert(varchar(10),@RecordsRemainingPhase1)
  exec msp_ProcessLog 'START', @Msg, null, 'owoa_buildSellerXref', 'Openwork'
end


if @Debug = 'Y' exec msp_ProcessLog 'START', '07) Update #missingCode', null, 'owoa_buildSellerXref', 'Openwork'

-- try and find them by the full name
update #missingCode
set sellerCode = a.agentCode
from msdt_adviser a
join #missingCode b
      on ltrim(rtrim(a.adviser)) = b.sellerName and a.franchiseCode = b.franchise


-- how many did we find
if @debug = 'Y'
begin
  select @FoundStage2 = count(*) 
  from #missingCode
  where sellerCode is not null
  select @Msg = '08) Count #missingCode FoundStage2 = ' + convert(varchar(10),@FoundStage2)
  exec msp_ProcessLog 'START', @Msg, null, 'owoa_buildSellerXref', 'Openwork'
end

if @Debug = 'Y' exec msp_ProcessLog 'START', '09) Insert owoa_SellerXref', null, 'owoa_buildSellerXref', 'Openwork'

-- put them in the xref table
insert owoa_SellerXref(sellerCode
                  ,sellerName
                  ,franchise
)
select      sellerCode
      ,sellerName
      ,franchise
from #missingCode
where sellerCode is not null


if @debug = 'Y' exec msp_ProcessLog 'START', '10) Delete from #missingCode', null, 'owoa_buildSellerXref', 'Openwork'

-- get rid of the ones we found
delete from #missingCode
where sellerCode is not null


-- check how many are left
if @Debug = 'Y'
begin 
  select @RecordsRemainingPhase2 = count(*) from #missingCode
  select @Msg = '11) Count #missingCode RecsRemainingPhase2 = ' + convert(varchar(10),@RecordsRemainingPhase2)
  exec msp_ProcessLog 'START', @Msg, null, 'owoa_buildSellerXref', 'Openwork'
end

if @Debug = 'Y' exec msp_ProcessLog 'START', '12) Update #missingCode', null, 'owoa_buildSellerXref', 'Openwork'

-- try and find them by part of the full name
update #missingCode
set sellerCode = b.agentCode
from #missingCode a
join msdt_Adviser b on b.franchisecode = a.franchise
where ltrim(rtrim(b.adviser)) like a.sellername + '%'


-- how many did we find
if @Debug = 'Y' 
begin
  select @FoundStage3 = count(*) 
  from #missingCode
  where sellerCode is not null
  select @Msg = '13) Count #missingCode FoundStage3 = ' + convert(varchar(10),@FoundStage3)
  exec msp_ProcessLog 'START', @Msg, null, 'owoa_buildSellerXref', 'Openwork'
end

if @Debug = 'Y' exec msp_ProcessLog 'START', '14) Insert owoa_SellerXref', null, 'owoa_buildSellerXref', 'Openwork'

-- put them in the xref table
insert owoa_SellerXref(sellerCode
                  ,sellerName
                  ,franchise
)
select      sellerCode
      ,sellerName
      ,franchise
from #missingCode
where sellerCode is not null


if @Debug = 'Y' exec msp_ProcessLog 'START', '15) delete from #missingCode', null, 'owoa_buildSellerXref', 'Openwork'

-- get rid of the ones we found
delete from #missingCode
where sellerCode is not null


-- check how many are left
if @Debug = 'Y' 
begin
  select @RecordsRemainingPhase3 = count(*) from #missingCode
  select @Msg = '16) Count #missingCode RecsRemainingPhase3 = ' + convert(varchar(10),@RecordsRemainingPhase3)
  exec msp_ProcessLog 'START', @Msg, null, 'owoa_buildSellerXref', 'Openwork'
end

if @Debug = 'Y' exec msp_ProcessLog 'START', '17) update #missingCode', null, 'owoa_buildSellerXref', 'Openwork'

-- try and find them by company name ( removing '.' and doing a load of conversions )
update #missingCode
set sellerCode = b.agentCode
from #missingCode a
join msdt_Adviser b on b.franchisecode = a.franchise
where
replace(replace(replace(replace(replace(replace(replace(replace(replace(replace(upper(ltrim(rtrim(b.adviser))),'LIMITED','LTD'),'FINANCIAL','FIN'),'SERVICES','SRV'),'COMPANY','CO'),'FINANCIAL','FIN'),'SOLUTIONS','SOL'),'SERVS','SRV'),'&','AND'),'SOLS','SOL'),'SERV','SRV')
 like
replace(replace(replace(replace(replace(replace(replace(replace(replace(replace(upper(ltrim(rtrim(replace(a.sellerName,'.',' ')))),'LIMITED','LTD'),'FINANCIAL','FIN'),'SERVICES','SRV'),'COMPANY','CO'),'FINANCIAL','FIN'),'SOLUTIONS','SOL'),'SERVS','SRV'),'&','AND'),'SOLS','SOL'),'SERV','SRV') + '%'


-- how many did we find
if @Debug = 'Y' 
begin
  select @FoundStage4 = count(*) 
  from #missingCode
  where sellerCode is not null
  select @Msg = '18) Count #missingCode FoundStage4 = ' + convert(varchar(10),@FoundStage4)
  exec msp_ProcessLog 'START', @Msg, null, 'owoa_buildSellerXref', 'Openwork'
end

if @Debug = 'Y' exec msp_ProcessLog 'START', '19) insert owoa_SellerXref', null, 'owoa_buildSellerXref', 'Openwork'

-- put them in the xref table
insert owoa_SellerXref(sellerCode
                  ,sellerName
                  ,franchise
)
select      sellerCode
      ,sellerName
      ,franchise
from #missingCode
where sellerCode is not null


if @Debug = 'Y' exec msp_ProcessLog 'START', '20) delete from #missingCode', null, 'owoa_buildSellerXref', 'Openwork'

-- get rid of the ones we found
delete from #missingCode
where sellerCode is not null


-- check how many are left
if @Debug = 'Y' 
begin
  select @RecordsRemainingPhase4 = count(*) from #missingCode
  select @Msg = '21) Count #missingCode RecsRemainingPhase4 = ' + convert(varchar(10),@RecordsRemainingPhase4)
  exec msp_ProcessLog 'START', @Msg, null, 'owoa_buildSellerXref', 'Openwork'
end

if @Debug = 'Y' exec msp_ProcessLog 'START', '22) select * from #missingCode', null, 'owoa_buildSellerXref', 'Openwork'


-- show them
--select * from #missingCode


if @Debug = 'Y' exec msp_ProcessLog 'START', '23) owoa_SellerXref - NC', null, 'owoa_buildSellerXref', 'Openwork'

-- add them in with a code of 'NC'
insert owoa_SellerXref(sellerCode
                  ,sellerName
                  ,franchise
)
select      'NC'
      ,sellerName
      ,franchise
from #missingCode
where sellerCode is null


if @Debug = 'Y' exec msp_ProcessLog 'START', '24) owoa_SellerXref - msdt_Adviser', null, 'owoa_buildSellerXref', 'Openwork'

-- now add in all the data from the adviser tablewhere the agent id is in the msft_sales table
insert owoa_SellerXref(sellerCode
                  ,SellerName
                  ,franchise
)
select distinct a.agentCode
      ,ltrim(rtrim(a.adviser))+' - '+a.agentCode
      ,a.franchisecode
from msdt_adviser a
left outer join owoa_SellerXref b on ltrim(rtrim(a.adviser)) = b.sellerName
and a.franchiseCode = b.franchise
inner join msft_sales c on a.agentcode = c.agentCode
where b.sellerCode is null
 and a.agentcode not in (select distinct sellercode from owoa_SellerXref)


if @Debug = 'Y' exec msp_ProcessLog 'START', '25) drop table #missingCode', null, 'owoa_buildSellerXref', 'Openwork'

-- drop the temp table
drop table #missingCode


if @Debug = 'Y' exec msp_ProcessLog 'START', '26) THE END', null, 'owoa_buildSellerXref', 'Openwork'


END




GO
