/****** Object:  StoredProcedure [dbo].[owoa_DownloadMortgageBrokerFees]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*********************************************************************************************************
Program:		owoa_DownloadMortgageBrokerFees						
Author:			Alan Groves
Date created:	23/05/2016							
											
Description
===========
This procedure has been added to the OpenAccess "Adhoc Downloads" to enable practice principals
to view each mortgage case that will get added to their mortgage retention standing order that
will appear on their OpenAccess Account Statement

The OpenAccess "Adhoc Donload request" report drop down list box will show this item as 
"Mortgage Broker Fees".

It is called as follows:
	exec owoa_DownloadMortgageBrokerFees '1001234', '2016-04-01', '2016-04-01'
									
Amendment History								
=================								

Date		Amended By	Change Details
----------	----------	--------------
10/05/2018	A Groves    SR504957/CH21153/CR630. Add VNB (value of new business).
04/06/2018	A Groves	Fixed error where VNB for the case as a whole was being reported rather
						than just the MBF portion.
*************************************************************************************************************/
CREATE PROCEDURE [dbo].[owoa_DownloadMortgageBrokerFees]
		@FranchiseCode	nvarchar(20),
		@StartMonth		datetime,
		@EndMonth		datetime
AS

SET NOCOUNT ON;

BEGIN TRY

	/****************************************************************************

		Variables
																			
	****************************************************************************/

	declare @Client					varchar(50),
			@Module					varchar(50),
			@PhaseStart				varchar(50),
			@PhaseEnd				varchar(50),
			@PhaseLog				varchar(50),
			@PhaseError				varchar(50),
			@Process				varchar(100),
			@ProcessMessage			varchar(100),
			@RowCount				int,
			@ErrMsg					nvarchar(4000),
			@ErrMsgBrief			nvarchar(100),
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@ErrState				int
			
	/****************************************************************************

		Set initial parameters																
																			
	****************************************************************************/		

	set @Client			= 'Openwork'
	set @Module			= 'OpenAccess'
	set @PhaseStart		= 'START'
	set @PhaseEnd   	= 'END'
	set @PhaseLog		= 'LOG'
	set @PhaseError		= 'ERROR'
	set @Process		= object_name(@@procid)

	/****************************************************************************

		Log start
																			
	****************************************************************************/

	exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

	set @ProcessMessage = '@FranchiseCode=' + @FranchiseCode + 
							'; @StartMonth=' + convert(varchar(10),@StartMonth,103) +
							'; @EndMonth=' + convert(varchar(10),@EndMonth,103)
	
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client
						
	/****************************************************************************

		Get the data
																			
	****************************************************************************/		

	select	mbf.FirmUID,
			mbf.FirmName,
			mbf.AdviserUID,
			mbf.AdviserName,
			mbf.PolicyID,
			csp.MonthName,
			mbf.MortgageNumber,
			mbf.AdviceFeeAmount,
			mbf.AgentSplit,
			mbf.RetentionRate,
			mbf.DeductionAmount,
			mbf.ApplicationDate,
			mbf.SubmittedDate,
			mbf.PaymentMatchedDate,
			mbf.ClientName,
			mbf.APE,
			isnull(r.MBF,0) as VNB,						--AG 04/06/2018
			mbf.ElitePoints
	from	dbo.owt_MortgageBrokerFees mbf
			inner join msit_CommissionStatementPeriods csp on csp.Month = mbf.Month
			left join owt_Recognition r on r.SourceID = mbf.PendingPaymentID and r.Source = 'Openwork 2006'		--AG 04/06/2018
	where	mbf.AdviceFeeCharged = 'Yes'
	and		mbf.FirmUID = @FranchiseCode
	and		mbf.Month between @StartMonth and @EndMonth
	
	select @RowCount = @@rowcount

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
   
	-- Error message line 1
	set @ErrMsgBrief = left(@ErrMsg,100)
	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	
	-- Error message line 2 - if any text exists
	set @ErrMsgBrief = substring(@ErrMsg,101,100)
	if len(@ErrMsgBrief) > 0
		exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client

END CATCH

/****************************************************************************

	Log end
																		
****************************************************************************/

set @Process = @Process + '. Rowcount = ' + convert(nvarchar(10), isnull(@RowCount,0))
exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client



GO
