/****** Object:  StoredProcedure [dbo].[owoa_FranchisePerformanceKPI]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[owoa_FranchisePerformanceKPI]
@Franchise varchar(7)
as
BEGIN

/*************************************************************************
 Object  : procedure

 Name    : dbo.owoa_FranchisePerformanceKPI.sql
---------------------------------------------------------------------------

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
24/04/2013	M Cawood	SR207107. Add Elite_Points derivations as this will 
						now be displayed in place of ABC. ABC logic left 
						should it be needed.
10/05/2018	A Groves	SR504957/CH21153/CR630. 
						1) Add VNB (value of new business).
						2) Added rounding to two decimal places to ensure
							YTD and Rolling 12 totals equal the sum of the parts.
*************************************************************************/

set nocount on

create table #ReportPeriods(
  RptMonth  datetime,
  MonthName varchar(20),
  PeriodStartDate datetime,
  PeriodEndDate datetime,
  OscarStartDate  datetime,
  OscarEndDate  datetime
  )

create unique index ix_reportPeriods_1 on #reportPeriods (periodstartdate,periodenddate,RptMonth,MonthName) 
create unique index ix_reportPeriods_2 on #reportPeriods (RptMonth,periodstartdate,periodenddate,MonthName) 

create table #ReportValues(
  RptMonth  datetime,
  ValueType varchar(10),
  Value   float)

insert #ReportPeriods(
  RptMonth,
  MonthName,
  PeriodStartDate,
  PeriodEndDate,
  OscarStartDate,
  OscarEndDate)
select  top 13
  [Month],
  MonthName,
  PeriodStartDate,
  PeriodEndDate,
  OscarStartDate,
  OscarEndDate
from  msit_Commissionstatementperiods csp
where csp.PeriodStartDate > dateadd(m,-13,getdate())
  and csp.PeriodStartDate <= getdate()
order by [month] desc


-- Paid
insert  #ReportValues(
  RptMonth,
  ValueType,
  Value
  )
select  csp.RptMonth,
  min('PAID'),
  sum(totalPayment)
from  msit_openworkAdviserListing oal
  inner join #ReportPeriods csp on csp.RptMonth = oal.month
where   businessCode =  @Franchise
  and   source in('Openwork 2006','Openwork 2005')
group by csp.RptMonth
;
-- Written
insert  #ReportValues(
  RptMonth,
  ValueType,
  Value
  )
select  csp.RptMonth,
  min('WRITTEN')
  ,sum(turnover)
   from mstt_commissions com
   inner join #ReportPeriods csp on CAST(CONVERT(NVARCHAR, com.transactiondate, 112) AS DATETIME) 
    between csp.periodstartdate and csp.periodenddate
   where com.firm = @franchise
     and com.poltrantranstype = 39
   and commissionType = 1
     and com.agent_code <> 10002
Group by csp.rptMonth
-- replaced with above to avoide written moving franchise with seller
--select  csp.RptMonth,
--  min('WRITTEN'),
--  sum(Turnover)
--from  msft_Sales sa
--  inner join msdt_calendartime ct on ct.dateid = sa.datewrittenid
--  inner join #ReportPeriods csp on ct.datetime between csp.PeriodStartDate and csp.PeriodEndDate
--where   sa.agentcode in (select agentcode 
--      from  msdt_adviser 
--      where franchisecode = @Franchise
--      and adviserID > 0)
--  and sa.businesstypeid = 1
--  and Turnover<>0
--group by csp.RptMonth

-- APE
-- Issued Business
insert  #ReportValues(
  RptMonth,
  ValueType,
  Value
  )
select  csp.RptMonth,
  min('APE'),
  sum(APE)
from  msit_openworkAdviserListing oal
  inner join #ReportPeriods csp on csp.RptMonth = oal.month
where   businessCode =  @Franchise
group by RptMonth

-- NBI
insert  #ReportValues(
  RptMonth,
  ValueType,
  Value
  )
select  csp.RptMonth,
  min('NBI'),
  sum(totDue_enhd)
from  msit_openworkAdviserListing oal
  inner join #ReportPeriods csp on csp.RptMonth = oal.month
where   businessCode =  @Franchise
group by csp.RptMonth

-- ABCValue
insert  #ReportValues(
  RptMonth,
  ValueType,
  Value
  )
select  csp.RptMonth,
  min('ABCValue'),
  sum(ABCValue)
from  msit_openworkAdviserListing oal
  inner join #ReportPeriods csp on csp.RptMonth = oal.month
where   businessCode =  @Franchise
group by csp.RptMonth

--SR207107:MPC 24/04/2013: START
-- Elite Points
insert  #ReportValues(
  RptMonth,
  ValueType,
  Value
  )
select  csp.RptMonth,
  'Elite',
  sum(Elite_Points)
from  msit_openworkAdviserListing oal
  inner join #ReportPeriods csp on csp.RptMonth = oal.month
where   businessCode =  @Franchise
group by csp.RptMonth
--SR207107:MPC 24/04/2013: END

--AG 10/05/2018
--VNB Points
insert  #ReportValues(
  RptMonth,
  ValueType,
  Value
  )
select  csp.RptMonth,
  'VNB',
  sum(round(VNB_Points,2))
from  msit_openworkAdviserListing oal
  inner join #ReportPeriods csp on csp.RptMonth = oal.month
where   businessCode =  @Franchise
group by csp.RptMonth

-- output monthly

select  MonthName,
  convert(decimal(10,2),coalesce(sum(case when ValueType='PAID' then Value else 0 end),0)) Paid,
  convert(decimal(10,2),coalesce(sum(case when ValueType='WRITTEN' then Value else 0 end),0)) Written,
  convert(decimal(10,2),coalesce(sum(case when ValueType='APE' then Value else 0 end),0)) APE,
  convert(decimal(10,2),coalesce(sum(case when ValueType='NBI' then Value else 0 end),0)) NBI,
  convert(decimal(10,2),coalesce(sum(case when ValueType='Elite' then Value else 0 end),0)) Elite,		--SR207107:MPC 24/04/2013
  convert(decimal(10,2),coalesce(sum(case when ValueType='ABCValue' then Value else 0 end),0)) ABCValue,
  convert(decimal(10,2),coalesce(sum(case when ValueType='VNB' then Value else 0 end),0)) VNB			--AG 10/05/2018
from  #ReportValues
  full outer join #ReportPeriods on #ReportValues.RptMonth = #ReportPeriods.RptMonth
group by #ReportPeriods.RptMonth,
  #ReportPeriods.MonthName
order by #ReportPeriods.RptMonth

-- get the YTD
select  
  convert(decimal(10,2),coalesce(sum(case when ValueType='PAID' then Value else 0 end),0)) Paid,
  convert(decimal(10,2),coalesce(sum(case when ValueType='WRITTEN' then Value else 0 end),0)) Written,
  convert(decimal(10,2),coalesce(sum(case when ValueType='APE' then Value else 0 end),0)) APE,
  convert(decimal(10,2),coalesce(sum(case when ValueType='NBI' then Value else 0 end),0)) NBI,
  convert(decimal(10,2),coalesce(sum(case when ValueType='Elite' then Value else 0 end),0)) Elite,		--SR207107:MPC 24/04/2013
  convert(decimal(10,2),coalesce(sum(case when ValueType='ABCValue' then Value else 0 end),0)) ABCValue,
  convert(decimal(10,2),coalesce(sum(case when ValueType='VNB' then Value else 0 end),0)) VNB			--AG 10/05/2018
from  #ReportValues
  left join #ReportPeriods on #ReportValues.RptMonth = #ReportPeriods.RptMonth
where right(monthName,4) = datename(YYYY,getdate())

-- get the rolling 12 month
declare @curmonth datetime

select  @curmonth = max([Month])
from  msit_Commissionstatementperiods csp
where csp.PeriodendDate <= getdate()

select  
  convert(decimal(10,2),coalesce(sum(case when ValueType='PAID' then Value else 0 end),0)) Paid,
  convert(decimal(10,2),coalesce(sum(case when ValueType='WRITTEN' then Value else 0 end),0)) Written,
  convert(decimal(10,2),coalesce(sum(case when ValueType='APE' then Value else 0 end),0)) APE,
  convert(decimal(10,2),coalesce(sum(case when ValueType='NBI' then Value else 0 end),0)) NBI,
  convert(decimal(10,2),coalesce(sum(case when ValueType='Elite' then Value else 0 end),0)) Elite,		--SR207107:MPC 24/04/2013
  convert(decimal(10,2),coalesce(sum(case when ValueType='ABCValue' then Value else 0 end),0)) ABCValue,
  convert(decimal(10,2),coalesce(sum(case when ValueType='VNB' then Value else 0 end),0)) VNB
from  #ReportValues
  left join #ReportPeriods on #ReportValues.RptMonth = #ReportPeriods.RptMonth
--where #ReportPeriods.RptMonth >= dateAdd(yyyy,-1,getdate())
where #ReportPeriods.RptMonth >= dateAdd(yyyy,-1,@curmonth)
  and #ReportPeriods.periodEnddate < getdate()

drop table #ReportValues
drop table #ReportPeriods

END
GO
/****** Object:  StoredProcedure [dbo].[owoa_FranchisePerformanceKPI_Backup20180727AG]    Script Date: 7/3/2026 3:44:25 PM ******/
