CREATE PROCEDURE [dbo].[owoa_GetCurrentPeriod] 
  
AS
BEGIN
  SET NOCOUNT ON;

declare @date  datetime

select @date = cast (floor( cast (getDate() as float) ) as datetime)

SELECT 
  max(Month) AS Month 
FROM msit_CommissionStatementPeriods 
WHERE PeriodStartDate <= @date
  and PeriodEndDate >= @date

END


