CREATE  PROCEDURE [dbo].[owoa_GetIOReportProviders] 
/***********************************************************************************
	Object		: procedure
	Name		: owoa_GetIOReportProviders.sql
	Created By  : PR
	Created		: 1 Dec 2014
	Project		: Open Access - Intelliflo report 

	Returns Providers for the Provider list in the Intelliflo report. No parameters

*/	
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;
    -- select the detail value
    select distinct ReportingProductProviderCode as providerCode, 
					ReportingProductProviderName as provider 
	from msdt_Products
	
	UNION

	select distinct productProviderCode as providerCode
		, productProviderName as provider
	from mstt_productproviders where productProviderCode not in (
	select distinct ReportingProductProviderCode 
	from msdt_Products
	)
	order by 2

END
