/*********************************************************************************************************
Program:		dbo.owoa_GetPeriodOwlHierarchy
Author:			Alan Groves
Date created:	20/11/2018
											
Description
===========
This procedure has been added to OpenAccess to fetch the date range for the month passed in as a 
parameter. To be used for the Owl Hierarchy Payments download.

It is called as follows:
	declare @Month datetime
	set @Month = '2018-11-01'	-- Should always be first of the month
	exec dbo.owoa_GetPeriodOwlHierarchy @Month
									
Amendment History								
=================								

Date		Amended By	Change Details
----------	----------	--------------
*************************************************************************************************************/

CREATE PROCEDURE [dbo].[owoa_GetPeriodOwlHierarchy]
	@Month datetime
AS

set nocount on
	
declare @FirstOfMonth   varchar(8)

select @FirstOfMonth = convert(varchar(6),@Month,112) + '01'

select	@Month as PeriodStartDate,
		dateadd(mm,1,convert(datetime,@FirstOfMonth,112))-1 as PeriodEndDate,
		DATENAME(month,@Month) + ' ' + DATENAME(year,@Month) as MonthName
GO
