Description
===========
This procedure has been added to OpenAccess to fetch the range of months to be used 
for the Owl Hierarchy Payments download.

It is called as follows:
	exec dbo.owoa_GetPeriodsOwlHierarchy
									
Amendment History								
=================								

Date		Amended By	Change Details
----------	----------	--------------
*************************************************************************************************************/

CREATE PROCEDURE [dbo].[owoa_GetPeriodsOwlHierarchy]
AS

set nocount on

if exists (select 1 from dbo.owoa_OwlHierarchyPayments)
begin
	select	distinct
			dateadd(mm,datediff(mm,0,DateOfAdviserPayment),0) as Month,
			right(convert(varchar,DateOfAdviserPayment,106),8) as monthName    
	from	dbo.owoa_OwlHierarchyPayments
	order by 1
end
else
begin
	select 	dateadd(mm,datediff(mm,0,getdate()),0) as Month,
			right(convert(varchar,getdate(),106),8) as monthName    
end
GO
