CREATE PROCEDURE [dbo].[owoa_GetPeriodsServices]
AS

set nocount on

if exists (select 1 from dbo.owoa_Services)
begin
	select	distinct
			s.Month,
			left(MonthName ,3) + ' ' + right(MonthName,4) as monthName    
	from	dbo.owoa_Services s
			inner join msit_CommissionStatementPeriods csp on csp.Month = s.Month
	order	by 1
end
else
begin
	select 	dateadd(mm,datediff(mm,0,getdate()),0) as Month,
			right(convert(varchar,getdate(),106),8) as monthName    
end
