GO
SET QUOTED_IDENTIFIER ON
GO


CREATE  PROCEDURE [dbo].[owoa_GetQuarters]
      -- Add the parameters for the stored procedure here

AS
BEGIN
set nocount on 

create table #ReportQuarters(
      QMonth   datetime
      )

insert #ReportQuarters (
      QMonth)
select distinct
      [month]
from msit_FeesNonSWIFTRenewalListing


    -- select the detail value
select
      Qmonth as [month]
--      ,'Quarter ' + datename(qq,Qmonth) + ' ' + dateName(yyyy,Qmonth) as quarter
      ,'Quarter ' + datename(qq,dateadd(dd,-1,Qmonth)) + ' ' + dateName(yyyy,dateadd(dd,-1,Qmonth)) as quarter
      ,datename(mm,dateADD(mm,-3,Qmonth)) + ' ' + datename(yyyy,dateADD(mm,-3,Qmonth)) as month1
      ,datename(mm,dateADD(mm,-2,Qmonth)) + ' ' + datename(yyyy,dateADD(mm,-2,Qmonth)) as month2
      ,datename(mm,dateADD(mm,-1,Qmonth)) + ' ' + datename(yyyy,dateADD(mm,-1,Qmonth)) as month3
from #ReportQuarters
order by qmonth

drop table #ReportQuarters
END




