/****** Object:  StoredProcedure [dbo].[owoa_getSellers]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
    
CREATE   PROCEDURE [dbo].[owoa_getSellers]     
  -- Add the parameters for the stored procedure here    
  @FranchiseCode nvarchar(20)    
  ,@source nvarchar(20)    
     
      
AS    
BEGIN    
if  @source = 'ZAN' begin    
  select distinct     
    sellerName as fullName    
    ,sellerName as Code    
  from msit_ZANadviserlisting    
  where businesscode = @FranchiseCode    
  order by fullname    
end    
else begin    
  select      
    min(sellerName) as fullName    
    ,min(sellerName) as Code    
  from  owoa_sellerXref    
  where franchise = @FranchiseCode    
        and sellerCode <> 'NC'    
 -- and not (sellerName = 'David Kelly - 1001138' and @FranchiseCode = 1000819)  
  group by sellerCode    
  union all    
  select      
    sellerName as fullName    
    ,sellerName as Code    
  from  owoa_sellerXref    
  where franchise = @FranchiseCode    
        and sellerCode = 'NC'    
  order by fullName    
end    
    
END    
    
GO
