/****** Object:  StoredProcedure [dbo].[owoa_OpenAccessScheduledRun]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO



CREATE  procedure [dbo].[owoa_OpenAccessScheduledRun]

with recompile
as

--########################################################################
--
-- Object  : procedure
-- Name    : owoa_OpenAccessScheduledRun
-- Owner   : MPC
-- Created : 14 June 2007
-- Project : Openwork Open Access Systems 
-- Job to run as part of charges batch schedule.

-- Set up Process Log parameters

declare 
 @PhaseStart     varchar(50),
 @PhaseEnd       varchar(50),
 @Client         varchar(50),
 @Module         varchar(50),
 @Process        varchar(100)

set @PhaseStart = 'START'
set @PhaseEnd   = 'END'
set @Client     = 'Openwork'
set @Module     = 'Head Office'
set @Process    = 'OpenAccess Batch Run'

-- Log Start of Run
exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

set @Process    = 'owoa_PipelineExtract'
exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client
exec dbo.owoa_PipelineExtract
exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

-- rebuild the sellerXref table
set @Process    = 'owoa_buildSellerXref'
exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client
exec dbo.owoa_buildSellerXref
exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

-- Log end of Run
set @Process    = 'OpenAccess Batch Run'
exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client
GO
/****** Object:  StoredProcedure [dbo].[owoa_OpenworkAdviserDetail]    Script Date: 7/3/2026 3:44:25 PM ******/
