CREATE procedure [dbo].[owoa_OpenworkAdviserDetail_Backup20180727AG]
 @FranchiseCode nvarchar(20),
 @AdviserCode   nvarchar(255),
 @Source        nvarchar(20),
 @Month         datetime,
 @UserId		NVARCHAR(20) = NULL,
 @Policy        nvarchar(255)

as
BEGIN

/*************************************************************************
 
 Object  : procedure

 Name    : dbo.owoa_OpenworkAdviserDetail.sql

---------------------------------------------------------------------------

 18/07/2008 P.Robathan  Amended as derivation of Term Years/Months incorrect for Openwork 2006 policies

 26/10/2010 M Cawood    Derive Term Years/Months from PolicyTransaction asscoiated with payment (not policy).

 Mike Cawood - 24 April 2013 - SR207107
 Add Elite_Points derivations as this will now be displayed in place of ABC. 

*************************************************************************/

if(@Source = 'OWK')
	SELECT @Source= '%'

declare
 @type			char(20),
 @sourceID		int,
 @transactionID	int,
 @polID		varchar(25),
 @splitP	float,		-- split details for zan / openwork 2005
 @splitName	varchar(30),    -- split details for zan / openwork 2005
 @polStartDate	dateTime

select	top 1
	@type		=Source    -- to ideintify second step in the process!
	,@polID		=policy    -- this is for the next few queries
	,@sourceID	=sourceID  -- this is the ID to use
	,@splitP	=agentSplit     -- split details for ZAN & openwork 2005
	,@splitName	=sellerSurname  -- split details for ZAN & openwork 2005
	,@transactionID =transactionID -- the transaction id for NBI (2006)
	,@polStartDate =startDate -- the start date of the polic for NBI (2005)
from
 msit_OpenWorkAdviserListing
where
 BusinessCode = @FranchiseCode                      and
 (SellerName  = @AdviserCode or @AdviserCode = '%') and
 (Source      = @Source      or @Source      = '%') and
 MONTH		  = @Month and
 alID         =@policy


select
 PaidDate           = case when BACSDate = '1901-01-01' or BACSDate >= getdate() then NULL
                           else substring(convert(nvarchar(11), BACSDate, 103), 1, 2) + '-' + upper(substring(convert(nvarchar(11), BACSDate), 1, 3)) + '-' + substring(convert(nvarchar(11), BACSDate), 10, 2)
                      end,
 SellerCode         = SellerCode,                           --AdviserUID
 SellerForename     = SellerForename,                       --AdviserForename
 SellerSurname      = SellerSurname,                        --AdviserSurname
 SellerName         = SellerName,
 Provider           = Provider,
 ClientSurname      = ClientSurname,                        --Not listed in download code but displayed in download example in spec!!!
 ClientForename     = ClientForename,                       --Not listed in download code but displayed in download example in spec!!!
 ClientName         = Client,
 Source             = Source,
 PolicyNumber       = case when DistributorRef is not null and charindex(' ', DistributorRef) > 0 then Policy + ' : ' + DistributorRef
                           else Policy
                      end,
 Policy             = Policy,                               --PolicyNumber
 DistributorRef     = DistributorRef,
 CaseId             = CaseId,
 ProdType           = ProdType,
 StartDate          = upper(substring(convert(nvarchar(11), StartDate), 1, 3)) + '-' + substring(convert(nvarchar(11), StartDate), 10, 2),
 Freq               = Frequency,
 Premium            = case when Premium = 0 then NULL      --Premium/Inv/MortLoadAmt
                           else Premium
                      end,                              
 CommRate           = case when CommRate = 0 then NULL     --ComRate%
                           else CommRate
                      end,                             
 InitialPeriod      = case when InitialPeriod = 0 then NULL
                           else InitialPeriod
                      end,
 TotalCommDue       = isnull(TotDue_Base,0),
 Accrued_Base       = isnull(Accrued_Base,0),               --AccruedThisPeriod
 StillToAccr_Base   = case when StillToAccr_Base < 0 then 0 --StillToAccrue
                           else isnull(StillToAccr_Base,0)
                      end,
 ITAdvanced_Base    = isnull(ITAdvanced_Base,0),            --ITCommThisPeriod
 EnhancementRate    = isnull(EnhancementRate,0),            --EnhdRate
 TotDue_Enhd        = isnull(TotDue_Enhd,0),      --TotalCommDue
 Accrued_Enhd       = isnull(Accrued_Enhd,0),     --AccruedThisPeriod
 StillToAccr_Enhd   = case when StillToAccr_Enhd < 0 then 0 --StillToAccrue
                           else isnull(StillToAccr_Enhd,0)
                      end,
 ITAdvance_Enhd     = isnull(ITAdvanced_Enhd,0),  --ITCommThisPeriod
 TotalPayment       = isnull(TotalPayment,0),
 PayBasis           = PayBasis,
 TotalCommSacrifice = case when Sacrifice = 0 then NULL     --TotalCommSacrifice£
                           else Sacrifice
                      end,                            
 Split              = AgentSplit,                           
 CommType           = FeeType,
 APE                = case when APE = 0 then NULL
                           else APE
                      end,
 --ABCValue           = case when ABCValue = 0 then NULL	--SR207107:MPC 24/04/2013
 --                         else ABCValue end,				--SR207107:MPC 24/04/2013
 Elite				= case when Elite_Points = 0 then NULL	--SR207107:MPC 24/04/2013
                          else Elite_Points end,			--SR207107:MPC 24/04/2013
 Remarks            = Remarks

from
 msit_OpenWorkAdviserListing
where
 BusinessCode = @FranchiseCode                      and
 (SellerName  = @AdviserCode or @AdviserCode = '%') and
 (Source      = @Source      or @Source      = '%') and
 Month        = @Month and
 Policy = @polID and
 alID = @policy


order by
 SellerName,
 Provider,
 ClientSurname,
 Client,
 Policy,
 BACSDate,
 PaymentDate


IF (@type='Openwork 2005') begin
	-- openwork 2005
	-- additional detail
	select floor(initialPeriod/12) as termYears,initialperiod - (12 * FLOOR(initialPeriod / 12) )  as termMonths
		,ph.productsubgroupname
		,'N/A'  as address1,NULL as address2,NULL as address3,NULL as address4,NULL as address5,NULL as postcode,'N/A' as Tel,'N/A' as mobile,'N/A' as birthdate
	from msit_feesNonSwiftFeeListing a
		left outer join mstt_producthierarchy ph on 'NBI_'+a.productCode = ph.productCode
	where a.ID = @SourceID

	--splits
	select @splitP as split,@splitName as sellerSurname

end else begin

	IF (@type='Payshield') begin
		-- Paymentshield
		-- additional detail
		select 1 as termYears,0  as termMonths
			,'GI' as productsubgroupname
			,'N/A'  as address1,NULL as address2,NULL as address3,NULL as address4,NULL as address5,NULL as postcode,'N/A' as Tel,'N/A' as mobile,'N/A' as birthdate
--			from msit_feesNonSwiftFeeListing a
--			left outer join mstt_producthierarchy ph on 'NBI_'+a.productCode = ph.productCode
--		where a.ID = @SourceID

		--splits
