		IF (@type='OMS') begin
			-- OMS
			-- additional detail
			select floor(isnull(initialPeriod,0)/12) as termYears,isnull(initialperiod,0) - (12 * FLOOR(isnull(initialPeriod,0) / 12) )  as termMonths
			,ph.productsubgroupname
			,'N/A'  as address1,NULL as address2,NULL as address3,NULL as address4,NULL as address5,NULL as postcode,'N/A' as Tel,'N/A' as mobile,'N/A' as birthdate
				-- from msit_commissionStatement a
				from omst_OMSCommissionpayments a
				left outer join mstt_PolicyTransactions pol on a.policyID = pol.id
				left outer join mstt_producthierarchy ph on a.HierarchyProduct = ph.productcode
				--left outer join mstt_clients cli on a.clientid = cli.client_num
			where a.ID = @SourceID
	
			--splits
			select @splitP as split,@splitName as sellerSurname

		end else begin
			--openwork 2006
			-- additional detail
--			select 	isnull(termYears,0) as termYears,isnull(termMonths,0) as termMonths
--			select 	isnull(term_Y,0) as termYears,isnull(term_M,0) as termMonths	--MPC: 26/10/2010 -- PR 18/07/08 replaced line above with this
      select 	isnull(coalesce(pt.termYears,pol.term_Y),0) as termYears,       --MPC: 26/10/2010
              isnull(coalesce(pt.termMonths,pol.term_M),0) as termMonths	    --MPC: 26/10/2010
				      ,ph.productsubgroupname
				      ,cli.address1,cli.address2,cli.address3,cli.address4,cli.address5,cli.postcode,coalesce(tel_work,tel_home,'N/A') as Tel,isnull(tel_mobile,'N/A') as mobile,birthdate
			from msit_commissionStatement a
				left outer join mstt_PolicyTransactions pt on a.Transactionid = pt.id    --MPC: 26/10/2010
				left outer join mstt_Policies pol on a.policyid = pol.pol_num		        -- PR 18/07/08 replaced line above with this
				left outer join mstt_producthierarchy ph on a.productcode = ph.productcode
				left outer join mstt_clients cli on a.clientid = cli.client_num
			where a.ID = @SourceID
		
	
			-- Splits
