/****** Object:  StoredProcedure [dbo].[owoa_OpenworkAdviserListingRange]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[owoa_OpenworkAdviserListingRange]
 @FranchiseCode nvarchar(20),
 @AdviserCode   nvarchar(100),
 @Source        nvarchar(20),
 @sMonth         datetime,
 @eMonth         datetime,
 @Provider  nvarchar(15)
as
BEGIN

/*************************************************************************
 
 Object  : procedure

 Name    : dbo.owoa_OpenworkAdviserListingRange.sql

---------------------------------------------------------------------------
 
 AMENDMENT HISTORY
 =================
 Date		Author		Description
 ----		------		-----------
 12/06/2009 P Robathan	Add Scheme Num and do not show recs with zero comm values 
 24/04/2013	M Cawood	SR207107. Add Elite_Points derivations as this will now be displayed in place of ABC. 
 10/05/2018	A Groves	SR504957/CH21153/CR630. Add VNB (value of new business).
 16/05/2018	A Groves	isnull wrapped around VNB_Points to ensure VNB appears as 
						zero rather than NULL to achieve the same behaviour as Elite.
 20/11/2025 S Lancaster	Changed Elite points to take Adviser Split into account.
 21/01/2026 S Lancaster	Changed Elite points as should only apply adviser split for ongoing fees
*************************************************************************/

if(@Provider = '')
  SELECT @Provider= '%'

if(@Source = 'OWK' or @Source = 'openwork')
  SELECT @Source= '%'

create table #tmpTbl(
 bcode varchar(10) collate Latin1_General_CI_AS
,[bmonth] datetime
)
;

insert into #tmpTbl
select @FranchiseCode,month 
  from msit_CommissionStatementPeriods
 where [Month] >= @sMonth
   and [Month] <= @eMonth
;

-- sort out seller
create table #sellers(
  sellerName varchar(60) collate Latin1_General_CI_AS
)

declare @sellerCode varChar(10)


-- sort out the sellers
if @adviserCode <> '%' begin
  -- get the code of the seller were looking for
  select @sellerCode = sellerCode
  from owoa_sellerXref  
  where sellerName = @advisercode
    and franchise = @FranchiseCode
  -- check if we got a code back
  if @sellerCode in ('NC','',NULL) begin
    -- if not then just put the seller name we received in the file
    insert into #sellers (sellerName )
    values( @advisercode);
  end
  else begin
    -- if we did then put all then names associated with that code in the file
    insert into #sellers (sellerName )
    select sellerName 
      from owoa_sellerXref
     where sellerCode = @sellerCode
       and franchise = @FranchiseCode
  end
end



select
 PaidDate           = case when BACSDate = '1901-01-01' or BACSDate >= getdate() then NULL
                           else substring(convert(nvarchar(11), BACSDate, 103), 1, 2) + '-' + upper(substring(convert(nvarchar(11), BACSDate), 1, 3)) + '-' + substring(convert(nvarchar(11), BACSDate), 10, 2)
                      end,
 SellerCode         = SellerCode,                           --AdviserUID
 SellerForename     = SellerForename,                       --AdviserForename
 SellerSurname      = SellerSurname,                        --AdviserSurname
 SellerName         = SellerName,
 Provider           = Provider,
 ClientSurname      = ClientSurname,                        --Not listed in download code but displayed in download example in spec!!!
 ClientForename     = ClientForename,                       --Not listed in download code but displayed in download example in spec!!!
 ClientName         = Client,
 Source             = Source,
-- ABCValue now Elite Points					--SR207107:MPC 24/04/2013
-- ABCValue           = a.ABCValue,				--SR207107:MPC 24/04/2013

 --Elite				= a.Elite_Points,			--SR207107:MPC 24/04/2013 -- commented out 20/11/2025 replaced with below to take adviser splits into account
 --Elite              = case when AgentSplit in (100,0) then a.Elite_Points -- commented out as adviser splits only to be calculated where fee type is on-going
 --                          when AgentSplit IS NULL then a.Elite_Points
 --                          else a.Elite_Points * (AgentSplit/100)
 --                     end,
 Elite  = case when a.FeeType = 'Ongoing' and a.AgentSplit IS NOT NULL and a.AgentSplit NOT IN (100,0) then a.Elite_Points * (a.AgentSplit/100)
        	else a.Elite_Points
		  end,
 VNB				= isnull(a.VNB_Points,0),	--AG 10/05/2018
 PolicyNumber       = case when DistributorRef is not null and charindex(' ', DistributorRef) > 0 then Policy + ' : ' + DistributorRef
                           else Policy
                      end,
 Policy             = Policy,                               --PolicyNumber
 DistributorRef     = DistributorRef,
 CaseId             = CaseId,
 ProdType           = ProdType,
 StartDate          = upper(substring(convert(nvarchar(11), StartDate), 1, 3)) + '-' + substring(convert(nvarchar(11), StartDate), 10, 2),
 Freq               = Frequency,
 SelPremium         = Premium,
 Premium            = case when Premium = 0 then NULL      --Premium/Inv/MortLoadAmt
                           else Premium
                      end,                              
 CommRate           = case when CommRate = 0 then NULL     --ComRate%
                           else CommRate
                      end,                             
 InitialPeriod      = case when InitialPeriod = 0 then NULL
                           else InitialPeriod
                      end,
 TotalCommDue       = isnull(TotDue_Base,0),
 Accrued_Base       = isnull(Accrued_Base,0),               --AccruedThisPeriod
 StillToAccr_Base   = case when StillToAccr_Base < 0 then 0 --StillToAccrue
                           else isnull(StillToAccr_Base,0)
                      end,
 ITAdvanced_Base    = isnull(ITAdvanced_Base,0),            --ITCommThisPeriod
 EnhancementRate    = isnull(EnhancementRate,0),            --EnhdRate
 TotDue_Enhd        = isnull(TotDue_Enhd,0),      --TotalCommDue
 Accrued_Enhd       = isnull(Accrued_Enhd,0),     --AccruedThisPeriod
 StillToAccr_Enhd   = case when StillToAccr_Enhd < 0 then 0 --StillToAccrue
                           else isnull(StillToAccr_Enhd,0)
                      end,
 ITAdvance_Enhd     = isnull(ITAdvanced_Enhd,0),  --ITCommThisPeriod
 TotalPayment       = isnull(TotalPayment,0),
 PayBasis           = PayBasis,
 TotalCommSacrifice = case when Sacrifice = 0 then NULL     --TotalCommSacrifice£
                           else Sacrifice
                      end,                            
 Split              = case when AgentSplit = 0 then NULL    --Split%
                           else AgentSplit
                      end,                           
 CommType           = FeeType,
 APE                = case when APE = 0 then NULL
                           else APE
                      end,
 Remarks            = Remarks,
 month =  [Month]
,comKey       = alID,
SchemeNum = SchemeNum
--,ProductGroup = isnull(ProductGroup,'Other')
 
from
 msit_OpenWorkAdviserListing a
 join #tmpTbl b on a.businessCode = b.bcode and a.month = b.bmonth
where 
 (SellerName  in (select sellerName from #sellers) or @AdviserCode = '%') and
 (Source      = @Source or (source in ('Openwork 2005','Openwork 2006') and @Source = '%')) and
 (ProviderCode      = @Provider      or @Provider      = '%') and
 (isnull(TotDue_Base,0.00) <> 0 or          -- PR do select records if contain zero values
  isnull(Accrued_Base,0.00)  <> 0 or
  isnull(StillToAccr_Base,0.00)  <> 0 or
  isnull(ITAdvanced_Base,0.00)  <> 0 or
  isnull(TotDue_Enhd,0.00)  <> 0 or
  isnull(Accrued_Enhd,0.00)  <> 0 or
  isnull(StillToAccr_Enhd,0.00)  <> 0 or
  isnull(ITAdvanced_Enhd,0.00)  <> 0 or
  isnull(TotalPayment, 0.0)  <> 0 or
  isnull(APE,0.00)  <> 0 or
  --isnull(ABCValue,0.00)  <> 0)  --SR207107:MPC 24/04/2013
  isnull(Elite_Points,0.00)  <> 0)  --SR207107:MPC 24/04/2013

order by
 SellerName,
 Provider,
 SchemeNum Desc,
 ClientSurname,
 Client,
 Policy,
 BACSDate,
 PaymentDate
;

drop table #tmpTbl
drop table #sellers

END
