/****** Object:  StoredProcedure [dbo].[owoa_OpenworkAdviserListingRange_AG_TEST_PARTNER_OWNER]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[owoa_OpenworkAdviserListingRange_AG_TEST_PARTNER_OWNER]
 @FranchiseCode nvarchar(20),
 @AdviserCode   nvarchar(100),
 @Source        nvarchar(20),
 @sMonth         datetime,
 @eMonth         datetime,
 @Provider  nvarchar(15)
as
BEGIN

/*************************************************************************
 
 Object  : procedure

 Name    : dbo.owoa_OpenworkAdviserListingRange.sql

---------------------------------------------------------------------------

 12 Jun 2009 P. Robathan Add Scheme Num and do not show recs with zero comm values 

 Mike Cawood - 24 April 2013 - SR207107
 Add Elite_Points derivations as this will now be displayed in place of ABC. 

 Alan Groves - 17 January 2017 - SR??????
 Introduced new table "dbo.owoa_PartnerPaymentOwner" to link ex-advisers
 to the current partner who "owns" their case portfolio. This was initially
 requested by Jill Eames of Eames Laurie to help her split payments between
 the two partners: Paul Eames and Paul Fell. 

 16 February 2017. Further config added to table "dbo.owoa_PartnerPaymentOwner"
 to enable specific clients to be allocated to a particular partner.
*************************************************************************/

if(@Provider = '')
  SELECT @Provider= '%'

if(@Source = 'OWK' or @Source = 'openwork')
  SELECT @Source= '%'

create table #tmpTbl(
 bcode varchar(10) collate Latin1_General_CI_AS
,[bmonth] datetime
)
;

insert into #tmpTbl
select @FranchiseCode,month 
  from msit_CommissionStatementPeriods
 where [Month] >= @sMonth
   and [Month] <= @eMonth
;

-- sort out seller
create table #sellers(
  sellerName varchar(60) collate Latin1_General_CI_AS
)

declare @sellerCode varChar(10)


-- sort out the sellers
if @adviserCode <> '%' begin
  -- get the code of the seller were looking for
  select @sellerCode = sellerCode
  from owoa_sellerXref  
  where sellerName = @advisercode
    and franchise = @FranchiseCode
  -- check if we got a code back
  if @sellerCode in ('NC','',NULL) begin
    -- if not then just put the seller name we received in the file
    insert into #sellers (sellerName )
    values( @advisercode);
  end
  else begin
    -- if we did then put all then names associated with that code in the file
    insert into #sellers (sellerName )
    select sellerName 
      from owoa_sellerXref
     where sellerCode = @sellerCode
       and franchise = @FranchiseCode
  end
end



select
 PaidDate           = case when BACSDate = '1901-01-01' or BACSDate >= getdate() then NULL
                           else substring(convert(nvarchar(11), BACSDate, 103), 1, 2) + '-' + upper(substring(convert(nvarchar(11), BACSDate), 1, 3)) + '-' + substring(convert(nvarchar(11), BACSDate), 10, 2)
                      end,
 PartnerCode		= case when ppo2.PartnerName is not null then ppo2.PartnerCode else ppo.PartnerCode end,
 PartnerName		= case when ppo2.PartnerName is not null then ppo2.PartnerName else ppo.PartnerName end,	--AG 17/01/2017
 SellerCode         = a.SellerCode,     --AG 17/01/2017     --AdviserUID
 SellerForename     = SellerForename,                       --AdviserForename
 SellerSurname      = SellerSurname,                        --AdviserSurname
 SellerName         = a.SellerName,
 Provider           = Provider,
 ClientSurname      = a.ClientSurname,						--Not listed in download code but displayed in download example in spec!!!
 ClientForename     = a.ClientForename,						--Not listed in download code but displayed in download example in spec!!!
 ClientName         = Client,
 Source             = a.Source,			--AG 17/01/2017
-- ABCValue now Elite Points			--SR207107:MPC 24/04/2013
-- ABCValue           = a.ABCValue,		--SR207107:MPC 24/04/2013
 Elite				= a.Elite_Points,	--SR207107:MPC 24/04/2013

 PolicyNumber       = case when DistributorRef is not null and charindex(' ', DistributorRef) > 0 then Policy + ' : ' + DistributorRef
                           else Policy
                      end,
 Policy             = Policy,                               --PolicyNumber
 DistributorRef     = DistributorRef,
 CaseId             = CaseId,
 ProdType           = ProdType,
 StartDate          = upper(substring(convert(nvarchar(11), StartDate), 1, 3)) + '-' + substring(convert(nvarchar(11), StartDate), 10, 2),
 Freq               = Frequency,
 SelPremium         = Premium,
 Premium            = case when Premium = 0 then NULL      --Premium/Inv/MortLoadAmt
                           else Premium
                      end,                              
 CommRate           = case when CommRate = 0 then NULL     --ComRate%
                           else CommRate
                      end,                             
 InitialPeriod      = case when InitialPeriod = 0 then NULL
                           else InitialPeriod
                      end,
 TotalCommDue       = isnull(TotDue_Base,0),
 Accrued_Base       = isnull(Accrued_Base,0),               --AccruedThisPeriod
 StillToAccr_Base   = case when StillToAccr_Base < 0 then 0 --StillToAccrue
                           else isnull(StillToAccr_Base,0)
                      end,
 ITAdvanced_Base    = isnull(ITAdvanced_Base,0),            --ITCommThisPeriod
 EnhancementRate    = isnull(EnhancementRate,0),            --EnhdRate
 TotDue_Enhd        = isnull(TotDue_Enhd,0),      --TotalCommDue
 Accrued_Enhd       = isnull(Accrued_Enhd,0),     --AccruedThisPeriod
 StillToAccr_Enhd   = case when StillToAccr_Enhd < 0 then 0 --StillToAccrue
                           else isnull(StillToAccr_Enhd,0)
                      end,
 ITAdvance_Enhd     = isnull(ITAdvanced_Enhd,0),  --ITCommThisPeriod
 TotalPayment       = isnull(TotalPayment,0),
 PayBasis           = PayBasis,
 TotalCommSacrifice = case when Sacrifice = 0 then NULL     --TotalCommSacrifice£
                           else Sacrifice
                      end,                            
 Split              = case when AgentSplit = 0 then NULL    --Split%
                           else AgentSplit
                      end,                           
 CommType           = FeeType,
 APE                = case when APE = 0 then NULL
                           else APE
                      end,
 Remarks            = Remarks,
 month =  [Month]
,comKey       = alID,
SchemeNum = SchemeNum
--,ProductGroup = isnull(ProductGroup,'Other')
,Case when ppo2.ID is not null then 'Yes' else 'No' end as ChangedIndicator
from
 msit_OpenWorkAdviserListing a
 join #tmpTbl b on a.businessCode = b.bcode and a.month = b.bmonth
 left join dbo.owoa_PartnerPaymentOwner ppo				-- AG 16/01/2017 new table to pull in partner payment owner if set up
				on ppo.BusinessCode = a.BusinessCode
				and ppo.Source = a.Source
				and (ppo.SellerCode = a.SellerCode or ppo.SellerName = a.SellerName)
				and @sMonth >= ppo.EffectiveStartDate 
				and @eMonth <= ppo.EffectiveEndDate 
 left join dbo.owoa_PartnerPaymentOwner ppo2			-- AG 16/01/2017 new table to pull in partner payment owner if set up
				on ppo2.BusinessCode = a.BusinessCode	-- with special partner assignment for specific clients
				and ppo2.Source = a.Source
				and ppo2.ClientForename = a.ClientForename
				and ppo2.ClientSurname = a.ClientSurname
				and @sMonth >= ppo2.EffectiveStartDate 
				and @eMonth <= ppo2.EffectiveEndDate 
where 
 (a.SellerName  in (select sellerName from #sellers) or @AdviserCode = '%') and
 (a.Source      = @Source or (a.source in ('Openwork 2005','Openwork 2006') and @Source = '%')) and
 (ProviderCode      = @Provider      or @Provider      = '%') and
 (isnull(TotDue_Base,0.00) <> 0 or          -- PR do select records if contain zero values
  isnull(Accrued_Base,0.00)  <> 0 or
  isnull(StillToAccr_Base,0.00)  <> 0 or
  isnull(ITAdvanced_Base,0.00)  <> 0 or
  isnull(TotDue_Enhd,0.00)  <> 0 or
  isnull(Accrued_Enhd,0.00)  <> 0 or
  isnull(StillToAccr_Enhd,0.00)  <> 0 or
  isnull(ITAdvanced_Enhd,0.00)  <> 0 or
  isnull(TotalPayment, 0.0)  <> 0 or
  isnull(APE,0.00)  <> 0 or
  --isnull(ABCValue,0.00)  <> 0)  --SR207107:MPC 24/04/2013
  isnull(Elite_Points,0.00)  <> 0)  --SR207107:MPC 24/04/2013

order by
 a.SellerName,
 Provider,
 SchemeNum Desc,
 ClientSurname,
 Client,
 Policy,
 BACSDate,
 PaymentDate
;

drop table #tmpTbl
drop table #sellers

END
GO
