/****** Object:  StoredProcedure [dbo].[owoa_OpenworkBankAccountStatementRange]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE procedure [dbo].[owoa_OpenworkBankAccountStatementRange]
 @FranchiseCode nvarchar(20),
 @sMonth         datetime,
 @eMonth         datetime,
 @Source        nvarchar(20),
 @UserId    NVARCHAR(20)
as
begin
if(@Source = 'OWK')
  SELECT @Source= '%'

select
 [Month]         = [Month],
Source = Source,
 Debits          = case when Amount < 0 then Amount
                        else 0
                   end,
 Credits         = case when Amount > 0 then Amount
                        else 0
                   end,
 TotalAmount     = Amount,
 TransactionDate = TransactionDate,
 PaymentType     = PaymentType,
 TransactionType = TransactionType,
 Description     = Description,
 Notes           = Notes,
 Sequence        = Sequence,
 TotalType       = TotalType,
 SortCode        = SortCode
, Provider = Provider
from
 msit_OpenworkBankDetails
where
 BusinessCode = @FranchiseCode and
 [Month] <= @eMonth              and
 [Month] >= @sMonth              and
(Source = @Source or (source in ('Openwork 2005','Openwork 2006') and @Source = '%'))
 order by
 source
,[month]
,sortcode
,transactiondate
,[sequence]
,totaltype
,paymenttype
;

select
 TotalAmount     =sum( Amount)
,TransactionDate = min(TransactionDate)
from
 msit_OpenworkBankDetails a
join (
  select source,min(month) as month
  from 
   msit_OpenworkBankDetails
  where
   BusinessCode = @FranchiseCode  and
   [Month] <= @eMonth              and
   [Month] >= @sMonth              and
  (Source = @Source or (source in ('Openwork 2005','Openwork 2006') and @Source = '%'))
  and paymentType = 0
  group by source
) b on a.source = b.source and a.month = b.month
where
 BusinessCode = @FranchiseCode  and
 (a.Source = @Source or (a.source in ('Openwork 2005','Openwork 2006') and @Source = '%'))
 and paymentType = 0

end

