/****** Object:  StoredProcedure [dbo].[owoa_OwlHierarchyPaymentsDownload]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*********************************************************************************************************
Program:		dbo.owoa_OwlHierarchyPaymentsDownload						
Author:			Alan Groves
Date created:	16/11/2018
											
Description
===========
This procedure has been added to the OpenAccess "Adhoc Downloads" to enable Owl ASMs and
introducers to look at their upfront and deferred hierarchy payments that have been 
generated from sales by OSPAs (Owl Senior Protection Advisers).

The OpenAccess "Adhoc Donload request" report drop down list box will show this item as 
"Owl Hierarchy Payments".

It is called as follows:
	exec dbo.owoa_OwlHierarchyPaymentsDownload '2002281', '2018-12-01', '2018-12-01'
									
Amendment History								
=================								

Date		Amended By	Change Details
----------	----------	--------------
23/11/2018	A Groves	Paul Laggett requested additional column "PctOfPolicyAPE" on 23/11/2018.
						His explanation was: We want the calculation to be Paid amount / policy APE.
						We just want to show the ASM override as a % of the total policy premium.
11/03/2020	A Groves	Following the introduction of mortgages the APE calculation has been amended
						as APE is the DA for mortgages.
*************************************************************************************************************/
CREATE PROCEDURE [dbo].[owoa_OwlHierarchyPaymentsDownload]
		@EnterpriseUID	nvarchar(20),
		@StartMonth		datetime,
		@EndMonth		datetime
AS

SET NOCOUNT ON;

BEGIN TRY

	/****************************************************************************

		Variables
																			
	****************************************************************************/

	declare @Client					varchar(50),
			@Module					varchar(50),
			@PhaseStart				varchar(50),
			@PhaseEnd				varchar(50),
			@PhaseLog				varchar(50),
			@PhaseError				varchar(50),
			@Process				varchar(100),
			@ProcessMessage			varchar(100),
			@RowCount				int,
			@ErrMsg					nvarchar(4000),
			@ErrMsgBrief			nvarchar(100),
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@ErrState				int,
			@EndMonthOriginal		datetime
			
	/****************************************************************************

		Set initial parameters																
																			
	****************************************************************************/		

	set @Client			= 'Openwork'
	set @Module			= 'OpenAccess'
	set @PhaseStart		= 'START'
	set @PhaseEnd   	= 'END'
	set @PhaseLog		= 'LOG'
	set @PhaseError		= 'ERROR'
	set @Process		= object_name(@@procid)

	/****************************************************************************

		Log start
																			
	****************************************************************************/

	exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

	set @EndMonthOriginal = @EndMonth	--Store original parameter value
	
	-- This needs to be changed from first day of the month to last day of the month
	select @EndMonth = dateadd(mm,1,@EndMonth)-1	

	set @ProcessMessage = '@EnterpriseUID=' + @EnterpriseUID + 
							'; @StartMonth=' + convert(varchar(10),@StartMonth,103) +
							'; @EndMonthOriginal=' + convert(varchar(10),@EndMonthOriginal,103) +
							'; @EndMonth=' + convert(varchar(10),@EndMonth,103)
	
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client
						
	/****************************************************************************

		Get the data
																			
	****************************************************************************/		

	select	ohp.AdviserUID, 
			ohp.AdviserName, 
			ohp.CaseID, 
			ohp.PolicyNumber, 
			ohp.Client,
			ohp.CommissionTypeDesc as CommissionType,
			ohp.PaymentBasis,
			case when ohp.PaymentStage = 'Upfront'
				then ohp.PaymentAmount
				else 0.00
			end as PaidAmount,
			case when ohp.PaymentStage = 'Deferred'
				then ohp.PaymentAmount
				else 0.00
			end as DeferredAmount,
			ohp.PctOfAdviserPayment,
			ohp.PaymentStage,
			ohp.PaymentRole,
			ohp.AdviserAmount,
			ohp.AdviserPanel,
			ohp.AdviserBand,
			case when ohp.PlanCode = 'MRTG'			--AG 11/03/2020
				then ohp.DistributionAllowance		--AG 11/03/2020
				else ohp.AnnualisedPremium
			end as AnnualisedPremium,
			convert(decimal(8,4),
				case when ohp.PlanCode = 'MRTG' and ohp.DistributionAllowance <> 0.00 then (ohp.PaymentAmount / ohp.DistributionAllowance) * 100.0	--AG 11/03/2020
					 when ohp.AnnualisedPremium <> 0.00 then (ohp.PaymentAmount / ohp.AnnualisedPremium) * 100.0
					 else 0.00
				end) as PctOfPolicyAPE,
			ohp.ProposalDate,	
			ohp.DateOfAdviserPayment,
			ohp.ProductCode,
			ohp.ProviderCode,
			ohp.InitialPeriod,
			case when ohp.PaymentCollectedDate is null 
				then 'Not Yet Collected'
				else convert(varchar(10),ohp.PaymentCollectedDate,103)
			end as PaymentCollectedDate,
			case when ohp.StandingOrderDescription is null
				then 'Not Yet Collected'
				else  ohp.StandingOrderDescription
			end as StandingOrderDescription
	from	dbo.owoa_OwlHierarchyPayments ohp
	where	ohp.RoleEnterpriseUID = @EnterpriseUID
	and		ohp.DateOfAdviserPayment between @StartMonth and @EndMonth
	order	by ohp.AdviserName, ohp.AdviserUID, ohp.CaseID, ohp.DateOfAdviserPayment, ohp.PaymentStage desc, ohp.CommissionTypeCode
	
	select @RowCount = @@rowcount

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
   
	-- Error message line 1
	set @ErrMsgBrief = left(@ErrMsg,100)
	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	
	-- Error message line 2 - if any text exists
	set @ErrMsgBrief = substring(@ErrMsg,101,100)
	if len(@ErrMsgBrief) > 0
		exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client

END CATCH

/****************************************************************************

	Log end
																		
****************************************************************************/

set @Process = @Process + '. Rowcount = ' + convert(nvarchar(10), isnull(@RowCount,0))
exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client
GO
/****** Object:  StoredProcedure [dbo].[owoa_OwlHierarchyPaymentsDownload_Backup20200327AG]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*********************************************************************************************************
Program:		dbo.owoa_OwlHierarchyPaymentsDownload						
Author:			Alan Groves
Date created:	16/11/2018
											
Description
===========
This procedure has been added to the OpenAccess "Adhoc Downloads" to enable Owl ASMs and
introducers to look at their upfront and deferred hierarchy payments that have been 
generated from sales by OSPAs (Owl Senior Protection Advisers).

The OpenAccess "Adhoc Donload request" report drop down list box will show this item as 
"Owl Hierarchy Payments".

It is called as follows:
	exec dbo.owoa_OwlHierarchyPaymentsDownload '2002281', '2018-12-01', '2018-12-01'
									
Amendment History								
=================								

Date		Amended By	Change Details
----------	----------	--------------
23/11/2018	A Groves	Paul Laggett requested additional column "PctOfPolicyAPE" on 23/11/2018.
						His explanation was: We want the calculation to be Paid amount / policy APE.
						We just want to show the ASM override as a % of the total policy premium.
*************************************************************************************************************/
CREATE PROCEDURE [dbo].[owoa_OwlHierarchyPaymentsDownload_Backup20200327AG]
		@EnterpriseUID	nvarchar(20),
		@StartMonth		datetime,
		@EndMonth		datetime
AS

SET NOCOUNT ON;

BEGIN TRY

	/****************************************************************************

		Variables
																			
	****************************************************************************/

	declare @Client					varchar(50),
			@Module					varchar(50),
			@PhaseStart				varchar(50),
			@PhaseEnd				varchar(50),
			@PhaseLog				varchar(50),
			@PhaseError				varchar(50),
			@Process				varchar(100),
			@ProcessMessage			varchar(100),
			@RowCount				int,
			@ErrMsg					nvarchar(4000),
			@ErrMsgBrief			nvarchar(100),
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@ErrState				int,
			@EndMonthOriginal		datetime
			
	/****************************************************************************

		Set initial parameters																
																			
	****************************************************************************/		

	set @Client			= 'Openwork'
	set @Module			= 'OpenAccess'
	set @PhaseStart		= 'START'
	set @PhaseEnd   	= 'END'
	set @PhaseLog		= 'LOG'
	set @PhaseError		= 'ERROR'
	set @Process		= object_name(@@procid)

	/****************************************************************************

		Log start
																			
	****************************************************************************/

	exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

	set @EndMonthOriginal = @EndMonth	--Store original parameter value
	
	-- This needs to be changed from first day of the month to last day of the month
	select @EndMonth = dateadd(mm,1,@EndMonth)-1	

	set @ProcessMessage = '@EnterpriseUID=' + @EnterpriseUID + 
							'; @StartMonth=' + convert(varchar(10),@StartMonth,103) +
							'; @EndMonthOriginal=' + convert(varchar(10),@EndMonthOriginal,103) +
							'; @EndMonth=' + convert(varchar(10),@EndMonth,103)
	
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client
						
	/****************************************************************************

		Get the data
																			
	****************************************************************************/		

	select	ohp.AdviserUID, 
			ohp.AdviserName, 
			ohp.CaseID, 
			ohp.PolicyNumber, 
			ohp.Client,
			ohp.CommissionTypeDesc as CommissionType,
			ohp.PaymentBasis,
			case when ohp.PaymentStage = 'Upfront'
				then ohp.PaymentAmount
				else 0.00
			end as PaidAmount,
			case when ohp.PaymentStage = 'Deferred'
				then ohp.PaymentAmount
				else 0.00
			end as DeferredAmount,
			ohp.PctOfAdviserPayment,
			ohp.PaymentStage,
			ohp.PaymentRole,
			ohp.AdviserAmount,
			ohp.AdviserPanel,
			ohp.AdviserBand,
			ohp.AnnualisedPremium,
			convert(decimal(8,4),
				case when ohp.AnnualisedPremium <> 0.00
					then (ohp.PaymentAmount / ohp.AnnualisedPremium) * 100.0
					else 0.00
				end) as PctOfPolicyAPE,
			ohp.ProposalDate,	
			ohp.DateOfAdviserPayment,
			ohp.ProductCode,
			ohp.ProviderCode,
			ohp.InitialPeriod,
			case when ohp.PaymentCollectedDate is null 
				then 'Not Yet Collected'
				else convert(varchar(10),ohp.PaymentCollectedDate,103)
			end as PaymentCollectedDate,
			case when ohp.StandingOrderDescription is null
				then 'Not Yet Collected'
				else  ohp.StandingOrderDescription
			end as StandingOrderDescription
	from	dbo.owoa_OwlHierarchyPayments ohp
	where	ohp.RoleEnterpriseUID = @EnterpriseUID
	and		ohp.DateOfAdviserPayment between @StartMonth and @EndMonth
	order	by ohp.AdviserName, ohp.AdviserUID, ohp.CaseID, ohp.DateOfAdviserPayment, ohp.PaymentStage desc, ohp.CommissionTypeCode
	
	select @RowCount = @@rowcount

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
   
	-- Error message line 1
	set @ErrMsgBrief = left(@ErrMsg,100)
	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	
	-- Error message line 2 - if any text exists
	set @ErrMsgBrief = substring(@ErrMsg,101,100)
	if len(@ErrMsgBrief) > 0
		exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client

END CATCH

/****************************************************************************

	Log end
																		
****************************************************************************/

set @Process = @Process + '. Rowcount = ' + convert(nvarchar(10), isnull(@RowCount,0))
exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client
GO
/****** Object:  StoredProcedure [dbo].[owoa_pipelineDetail]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO





CREATE procedure [dbo].[owoa_pipelineDetail]
 @FranchiseCode nvarchar(20),
 @key     nvarchar(20)

as
BEGIN

/*************************************
upd June 2009 P.Robathan Add Structured Prod processing
*************************************/


select  pl.*
    ,cli.address1
    ,cli.address2
    ,cli.address3
    ,cli.address4
    ,cli.address5
    ,cli.POSTCODE
    ,coalesce(cli.TEL_HOME,cli.TEL_WORK,'N/A') as Tel
    ,isnull(TEL_MOBILE,'N/A') as mobile
    ,birthdate
    ,isnull(ph.productsubgroupname,'N/A') as productsubgroupname
    ,isnull(pol.TERM_Y,0) as termYears
    ,isnull(pol.TERM_M,0) as termMonths
    ,case when ph.structuredproduct = 'Y' then 'Structured' else isnull(ph.productGroupName,'N/A') end as prodtype  --PR Jun 2009
    ,coalesce(pol.TotalSinglePremiums ,pol.CurrentRegularPremium,0) as premium
    ,coalesce(ptran.frequencyDescription,cast(pol.currentPremiumFrequency as varchar(10)),'N/A') as freq
    ,case when POL.START_DATE is null THEN 'N/A'
      else upper(substring(convert(nvarchar(11), POL.START_DATE), 1, 3)) + '-' + substring(convert(nvarchar(11), POL.START_DATE), 10, 2)
    end  as startdate
    ,SUM_ASS as sumAssured
    ,isnull(cast(ptran.CommInitialPeriod as char(5)),'N/A') as initialperiod
    ,ptran.commBasedOnPercent as commrate
    ,isnull(pp.productProviderName,'N/A') as providerName
    ,isnull(pol.productcode,'N/A') as productcode
from owoa_pipeline pl
left outer join mstt_clients cli on pl.clientID = cli.CLIENT_NUM
left outer join mstt_policies pol on  pl.PolicyID = pol.POL_NUM
left outer join mstt_producthierarchy ph on pol.productcode = ph.productcode
left outer join mstt_PolicyTransactions ptran on pl.propTranID = ptran.ID
left outer join mstt_productProviders pp on pl.providerCode = pp.productProviderCode
left outer join msit_S_Life sl on pl.PolicyID = sl.Pol_Num
where BusinessCode = @FranchiseCode           
  and PipelineID         =@Key

select distinct 
    b.sellername
    ,b.sellersplit
from owoa_pipeline a
join owoa_pipeline b on a.policyID = b.policyID and a.pipelineStartDate = b.pipelineStartDate
where a.BusinessCode = @FranchiseCode           
  and a.PipelineID         =@Key
order by b.sellersplit desc

END






GO
/****** Object:  StoredProcedure [dbo].[owoa_PipelineExtract]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[owoa_PipelineExtract]
@SuspenseDate datetime, @SuspendedDays int
as
 
/***********************************************************************************
	Object  : procedure
	Name    : owoa_PipelineExtract.sql
	Owner   : MPC
	Created : 14 June 2007
	Project : Open Access - Pipeline Table 

	Truncates and repopulates owoa_Pipeline table

	Call as owoa_PipelineExtract '1 Jan 2008','180'

--------------------------------------------------------------------------------------
	AMENDMENTS
	==========

	Mike Cawood Dec 2007 : 
	Dedup extracts by using Select Distinct

	Mike Cawood 18/04/2008 : 
	Exclude Expectations where Adjust <> 0 (Status Code 3)

	Mike Cawood 07/05/2008 : 
	SR9 - Ignore Payments where OAStatus not set to Valid
	
	Paul Robathan 16/03/2009 : 
	Include cases where OAStatus = Suspended

	Paul Robathan 27/05/2010 : 
	Amend Name extract for Corporate Clients as currently always set to NUll

	Mike Cawood 27/02/2013 : SR211450
	No longer Extract Matched Payments Awaiting Payment unless Policy is Suspended

	Mike Cawood 04/04/2013 : SR218842
	Include Matched Expectations with ADJUST flag set to 1 (this is set in the
	Reconciler) when a difference within tolerance is found.

	Alan Groves 10/05/2013 : SR226624
	Bug in population of @SuspendPaymentDate. Was today's date less 180 months, now
	corrected to be today's date less 180 days.

	Alan Groves 17/05/2013 : SR226624 - Part 2
	Amended the "Payment Agreed" select clause to exclude matched payments linked to 
	deleted statements as these are reporting with PipelineDays > 0
	
	Alan Groves 11/11/2014 : SR331383.
	1) Amended to join to mstt_Commissions with the correct CommissionType from the
	   Expectations table rather than hardcoded to CommissionType = 1 which is inital 
	   comm. This fix is needed to select trail payments correctly.
	2) Changed "and co.agent_code <> 10002" to "and co.agent_code <> '10002'" to
		protect the batch from non-numeric UIDs.
	3) Expectations are not split for trail and renewals like they are for initial,
		so split proportioning has been added just for trail and renewals.
	4) Split proportioning made the same as the Commission Listing to ignore the 
		effect of the BSC and ongoing fee margin pot codes.
		
	Alan Groves 08/12/2014 : SR350654
	1)	Amended for Owl Financial. In order to pay advisers the correct amount, the 
		commission shapes have been set up in such a way that adviser split % does
		not calculate correctly. This change introduces adjustment processing to
		restore the adviser split % to the value that the adviser would expect to see.
	2)  Populated Commission Type where known and Pipeline Type is 1.
	
	Alan Groves 29/03/2017 : SR471256/CH16774
	1)	Added an additional join to @SpecialCaseCommShapes to align with the Open Access
		Commission Listing to show the Owl Financial commission splits correctly (panels
		33 and 34). This change was overlooked - now brought into line.
		
	Alan Groves 14/08/2018 : SR512759/CH22273
	1)	Changed calculation of Owl splits to be arithmetic instead of using banding 
		table "owt_Bandings" and "@SpecialCaseCommShapes". The benfit is that when
		new Owl commission shapes are introduced in the future, then no config work
		would be needed for the splits to yield the required "smoothed" values. 
	2)	This Pipeline has logic in it to drop off old cases. However, the date 
		comparisons are at date/time level which means that every time this proc runs
		(even if just a few minutes apart) then a different row count is returned 
		each time. The code has been changed to manage the drop off at date level
		rather than date/time level to ensure multiple runs in the same day will 
		yield the same results.
************************************************************************************/

-- AG 11/11/2014 Start
declare	@OpenworkMarginPotCode		nvarchar(10),	
		@OpenworkMarginScriptDate	datetime,		
		@OpenworkBSCPotCode			nvarchar(10),	
		@OwlManager2Code			nvarchar(10)	-- AG 08/12/2014

declare @SpecialCaseCommShapes table				-- AG 08/12/2014
(
	CommissionShapeID	int,
	AdviserSplitPct		decimal(12,8),
	OverrideSplitPct	decimal(12,8),
	EffectiveStartDate	datetime,
	EffectiveEndDate	datetime
)

set @OpenworkMarginPotCode = (select Rtrim(longdescription) from msit_MIWarehouseCodesAndDescriptions 
          where columnname = 'OpenworkMarginOnTrail' and description = 'AgentCode')		
set @OpenworkMarginScriptDate = (select cast(longdescription as datetime) from msit_MIWarehouseCodesAndDescriptions 
          where  columnname = 'OpenworkMarginOnTrail' and description = 'ScriptDate')	
set @OpenworkBSCPotCode = (select Rtrim(longdescription) from msit_MIWarehouseCodesAndDescriptions 
          where columnname = 'BusinessServiceCharge' and description = 'AgentCode')		
-- AG 11/11/2014 End
-- AG 08/12/2014 Start
set @OwlManager2Code = (select cde.Code from msit_MIWarehouseCodesAndDescriptions cde	
			where cde.ColumnName = 'Manager2Code' and cde.Description = 'Owl Financial')
-- AG 08/12/2014 End

declare @SuspendPaymentDate datetime;								--SR211450: MPC 27/02/2013
-- AG 10/05/2013 Start
--set @SuspendPaymentDate = dateadd(mm,-1*@SuspendedDays,getdate())	--SR211450: MPC 27/02/2013
set @SuspendPaymentDate = dateadd(dd,-1*@SuspendedDays,getdate())
-- AG 10/05/2013 End
set @SuspendPaymentDate = CONVERT(date,@SuspendPaymentDate)			--AG 14/08/2018 (2)

declare @Months int
set @Months = -1*(select Code from msit_MIWarehouseCodesandDescriptions where ColumnName = 'OA_Pipeline_Months')

declare @OffDate datetime
set @OffDate = dateadd(mm,@Months,getdate())
set @OffDate = CONVERT(date,@OffDate)			--AG 14/08/2018 (2)

declare @DropDate datetime
set @DropDate = (select Code from msit_MIWarehouseCodesandDescriptions where ColumnName = 'OA_Pipeline_DropDate')

--declare @EndDate datetime set @EndDate = @OffDate
--IF @DropDate < @OffDate BEGIN set @EndDate = @DropDate END

declare @RunDate datetime
set @RunDate = dateadd(dd,-1,getdate())

truncate table owoa_Pipeline

--SR211450: MPC 27/02/2013 - START - Moved to improve efficiency
-- Derive Suspense Counts & Apply to Table
select	un.policy,
		sum(case 
				when edc.id is not null 
					and edc.amountreceived > 0 
					and edc.CommissionType in ('I','Y') 
				then 1
				when edc.id is not null 
					and ex.amount_rec > 0 
				then 1 
				else 0 
			end) as Count,
		sum(case 
				when edc.id is not null 
					and edc.amountreceived > 0 
					and edc.CommissionType in ('I','Y') 
				then ex.amount_rec
				when edc.id is not null 
					and ex.amount_rec > 0 
				then ex.amount_rec 
				else 0 
			end) as Amount
into	#SuspenseTotals
from	mstt_expectation ex
		inner join msit_s_paccun un on un.pacc_id = ex.id
		left outer join msit_edifactcommissionstatementcontents edc on edc.pacc_id = ex.id
where	ex.type in (5,6) 			-- Suspense entries
AND		ex.INIT_ID is null			-- Unmatched
group	by un.policy
order	by un.policy
--SR211450: MPC 27/02/2013 - END

--- Insert Proposals without Splits into owoa_Pipeline Table

insert into owoa_Pipeline
(PipelineType,PipelineTypeDesc,SellerCode,SellerName,BusinessCode,StatusCode,StatusDate,StatusDesc,
PropTranID,IssuedTranID,PolicyID,CaseID,PolicyNumber,PipelineStartDate,PipelineDays,ExpectationID,
UnpaidListID,PaidListID,CommType,WrittenDate,IssuedDate,ProviderCode,Basis,ClientID,ClientName,Amount,
BaseAmount,UpliftRate,SellerSplit,NBI,APE,PolicySuspend,PolicySuspendDate,SuspenseCount,SuspenseAmount,
ProductCode,ProdGroupCode,FirstReceipt)

select	DISTINCT 
		1,
		cd1.Description,  --NULL,	--SR211450: MPC 27/02/2013
		pt.agentcode,
		substring(	case 
						when charindex(' ', ag.firstnames) = 0 
						then ag.firstnames 
						else rtrim(substring(ag.firstnames, 1, charindex(' ', ag.firstnames))) 
					end + ' ' + ag.Name,1,50),
		coalesce(ah.detailagentcode,ag.Firm),--1,	--SR211450: MPC 27/02/2013 
		case when ST.Count > 0 then 2 else 1 end,	--SR211450: MPC 27/02/2013
		pt.CreateDateTime,
		cd2.Description,	--NULL,	--SR211450: MPC 27/02/2013
		pt.ID,
		pt.IssuedTranID,
		pt.policyID,
		po.policyref,
		po.cont_num,
		pt.CreateDateTime,
		datediff(dd,pt.CreateDateTime,@RunDate),
		NULL,
		NULL,
		NULL,
		NULL,
		pt.WrittenDate,
		pt.IssuedDate,
		coalesce(pt.commcompanycode,po.comp_code),
		case pt.commtype 
			when 'F' then 'Accrual' 
			when 'L' then 'Level' 
			when 'T' then 'IT' 
		end as Basis,
		po.Client_Num,
		case
			when cl.client_typ = 2 then substring(cl.name,1,50) -- PR 27/05/2010 For Corp Clients use Name as Firstname is always empty as causes the Name to be = Null
			else substring(case 
								when charindex(' ', cl.firstnames) = 0 then cl.firstnames 
								else rtrim(substring(cl.firstnames, 1, charindex(' ', cl.firstnames))) 
							end + ' ' + cl.Name,1,50) 
		end,
		--substring(case when charindex(' ', cl.firstnames) = 0 then cl.firstnames 
		--else rtrim(substring(cl.firstnames, 1, charindex(' ', cl.firstnames))) end + ' ' + cl.Name,1,50),
		NULL,
		NULL,
		NULL,
		NULL,
		NULL,
		NULL,
		po.SuspendCommission,
		po.SuspendCommissionLastUpdated,--NULL,NULL,	--SR211450: MPC 27/02/2013
		ST.Count,
		St.Amount,		--SR211450: MPC 27/02/2013
		coalesce(pt.commproductcode,po.productcode),
		coalesce(pt.productgroupcode,po.productgroupcode),
		NULL
from	mstt_policytransactions pt
		inner join mstt_policies po on po.pol_num = pt.policyid
		left outer join mstt_commissions co on co.transactionid = pt.id and co.commissiontype = 1
		inner join mstt_agents ag on ag.code = pt.agentcode
		inner join mstt_clients cl on cl.client_num = po.client_num
		left outer join msit_agenthierarchyhistory ah 
							on ah.agentcode = pt.agentcode 
							and ah.defaultvalue = 1 
							and ah.participanttype in (6,7,8,9)
							and CAST(CONVERT(NVARCHAR, pt.createdatetime, 112) AS DATETIME) between ah.startdate and ah.enddate
		left outer join mstt_agents a2 on a2.code = coalesce(ah.detailagentcode,ag.Firm)
		left join #SuspenseTotals ST on ST.Policy = po.cont_num --SR211450: MPC 27/02/2013
		left join msit_MiWarehouseCodesandDescriptions cd1 on cd1.ColumnName = 'OA_Pipeline_TypeDesc' and cd1.Code = '1'	--SR211450: MPC 27/02/2013
		left join msit_MiWarehouseCodesandDescriptions cd2 on cd2.ColumnName = 'OA_Pipeline_StatusDesc' and cd2.Code = case when ST.Count > 0 then 2 else 1 end	--SR211450: MPC 27/02/2013
where	pt.Transtype = 39			-- Proposal
AND		(							-- No matching Issued Transaction found
			pt.IssuedTranID is null 		
OR 
		(pt.IssuedTranID is not null and pt.IssuedTranID not in (select distinct transactionid from mstt_Expectation))
		)
AND		convert(date,pt.createdatetime) > @DropDate		-- ignore transactions prior to Drop Date			AG 14/08/2018 (2)
AND		convert(date,pt.createdatetime) > @OffDate		-- ignore transactions after assumed Off period		AG 14/08/2018 (2)
AND		co.id is NULL									-- no Initial Commission splits
AND		ag.agenttype in (2,46,49,3,4,5,43,45,51)		-- Businesses and Sellers only
AND		a2.agenttype in (2,46,49)						-- Businesses only

UNION

--- Insert Proposals with Splits into owoa_Pipeline Table

select	DISTINCT
		1,
		cd1.Description,  --NULL,	--SR211450: MPC 27/02/2013
		co.agent_code,
		substring(	case when charindex(' ', ag.firstnames) = 0 
						then ag.firstnames 
						else rtrim(substring(ag.firstnames, 1, charindex(' ', ag.firstnames))) 
					end + ' ' + ag.Name,1,50),
		co.Firm,--1,	--SR211450: MPC 27/02/2013 
		case when ST.Count > 0 then 2 else 1 end,	--SR211450: MPC 27/02/2013
		pt.CreateDateTime,
		cd2.Description,	--NULL,	--SR211450: MPC 27/02/2013
		pt.ID,
		pt.IssuedTranID,
		pt.policyID,
		po.policyref,
		po.cont_num,
		pt.CreateDateTime,
		datediff(dd,pt.CreateDateTime,@RunDate),
		NULL,
		NULL,
		NULL,
		--NULL,				-- AG 08/12/2014
		co.CommissionType,	-- AG 08/12/2014
		pt.WrittenDate,
		pt.IssuedDate,
		coalesce(pt.commcompanycode,po.comp_code),
		case pt.commtype 
			when 'F' then 'Accrual' 
			when 'L' then 'Level' 
			when 'T' then 'IT' 
		end as Basis,
		po.Client_Num,
		case
			when cl.client_typ = 2 
				then substring(cl.name,1,50) -- PR 27/05/2010 For Corp Clients use Name as Firstname is always empty as causes the Name to be = Null
				else substring(
								case 
									when charindex(' ', cl.firstnames) = 0 
										then cl.firstnames 
										else rtrim(substring(cl.firstnames, 1, charindex(' ', cl.firstnames))) 
								end + ' ' + cl.Name,1,50) 
		end,
		--substring(case when charindex(' ', cl.firstnames) = 0 then cl.firstnames 
		--else rtrim(substring(cl.firstnames, 1, charindex(' ', cl.firstnames))) end + ' ' + cl.Name,1,50),
		case 
			when pt.commtype = 'T' or pt.frequency = 6 or pt.comminitialperiod <= 1 then co.FixedAmount 
			when pt.frequency = 2 and pt.comminitialperiod > 1 then co.FixedAmount/pt.comminitialperiod
			when pt.frequency = 5 and pt.comminitialperiod > 1 then 12 * (co.FixedAmount/pt.comminitialperiod)
			else co.FixedAmount 
		end as Amount,
		case when pt.commtype = 'T' or pt.frequency = 6 or pt.comminitialperiod <= 1 then co.BaseAmount 
			when pt.frequency = 2 and pt.comminitialperiod > 1 then co.BaseAmount/pt.comminitialperiod
			when pt.frequency = 5 and pt.comminitialperiod > 1 then 12 * (co.BaseAmount/pt.comminitialperiod)
			else co.BaseAmount 
		end as BaseAmount,
		co.FranchiseUpliftPercent,
		--co.agent_perc,										   AG 08/12/2014

		--AG 14/08/2018 Start
		case when ag.Manager2Code = @OwlManager2Code then		-- AG 08/12/2014
			case when AdviserSplit.AdviserSplitPerc >= 0.01
				then round(((co.Agent_Perc / AdviserSplit.AdviserSplitPerc) * 100.0) * 4.0, 0) / 4.0					--Rounds to nearest 0.25.
				else co.Agent_Perc
			end
		else
			co.Agent_Perc
        end as Agent_Perc, 
		--AG 14/08/2018 End
		
		co.FixedAmount,
		co.Turnover,
		po.SuspendCommission,
		po.SuspendCommissionLastUpdated,--NULL,NULL,	--SR211450: MPC 27/02/2013
		ST.Count,
		St.Amount,		--SR211450: MPC 27/02/2013
		coalesce(pt.commproductcode,po.productcode),
		coalesce(pt.productgroupcode,po.productgroupcode),
		NULL
from	mstt_policytransactions pt
		inner join mstt_policies po on po.pol_num = pt.policyid
		--AG 14/08/2018 Start
		inner join	(select TransactionID, MAX(Agent_Perc) As AdviserSplitPerc
 					 from	mstt_Commissions
					 where	CommissionType = 1
					 and	AGENT_CODE <> '10002'
					 group	by TransactionID
					) AdviserSplit on AdviserSplit.TransactionID = pt.ID		
		--AG 14/08/2018 End
		inner join mstt_commissions co 
					on co.transactionid = pt.id 
					and co.commissiontype = 1 
					and co.agent_code <> '10002'	-- AG 11/11/2014
		inner join mstt_agents ag on ag.code = co.agent_code
		inner join mstt_clients cl on cl.client_num = po.client_num
		left outer join mstt_agents a2 on a2.code = co.Firm
		left join #SuspenseTotals ST on ST.Policy = po.cont_num --SR211450: MPC 27/02/2013
		left join msit_MiWarehouseCodesandDescriptions cd1 on cd1.ColumnName = 'OA_Pipeline_TypeDesc' and cd1.Code = '1'	--SR211450: MPC 27/02/2013
		left join msit_MiWarehouseCodesandDescriptions cd2 on cd2.ColumnName = 'OA_Pipeline_StatusDesc' and cd2.Code = case when ST.Count > 0 then 2 else 1 end	--SR211450: MPC 27/02/2013
where	pt.Transtype = 39			-- Proposal
AND		(							-- No matching Issued Transaction found
			pt.IssuedTranID is null 		
OR 
		(pt.IssuedTranID is not null and pt.IssuedTranID not in (select distinct transactionid from mstt_Expectation))
		)
AND		convert(date,pt.createdatetime) > @DropDate		-- ignore transactions prior to Drop Date			AG 14/08/2018 (2)
AND		convert(date,pt.CreateDateTime) > @OffDate		-- ignore transactions after assumed Off period		AG 14/08/2018 (2)
AND		ag.agenttype in (2,46,49,3,4,5,43,45,51)		-- Businesses and Sellers only
AND		a2.agenttype in (2,46,49)						-- Businesses only



--- Insert Matched Payments not yet on Unpaid List into owoa_Pipeline Table
--- Exclude Payments created prior to @SuspenseDate   --SR211450: MPC 27/02/2013
--- PipeLineTypeDesc='Payment'; StatusDesc='Payment Agreed'

insert into owoa_Pipeline
(PipelineType,PipelineTypeDesc,SellerCode,SellerName,BusinessCode,StatusCode,StatusDate,StatusDesc,
PropTranID,IssuedTranID,PolicyID,CaseID,PolicyNumber,PipelineStartDate,PipelineDays,ExpectationID,
UnpaidListID,PaidListID,CommType,WrittenDate,IssuedDate,ProviderCode,Basis,ClientID,ClientName,Amount,
BaseAmount,UpliftRate,SellerSplit,NBI,APE,PolicySuspend,PolicySuspendDate,SuspenseCount,SuspenseAmount,
ProductCode,ProdGroupCode,FirstReceipt)
select	DISTINCT
		2 as PipelineType,
		cd1.Description as PipelineTypeDesc,  --NULL,	--SR211450: MPC 27/02/2013
		co.agent_code as SellerCode,
		substring(	case 
						when charindex(' ', ag.firstnames) = 0 then ag.firstnames 
						else rtrim(substring(ag.firstnames, 1, charindex(' ', ag.firstnames))) 
					end + ' ' + ag.Name,1,50) as SellerName,
		co.Firm as BusinessCode,
		case when po.SuspendCommission = 1 
			then 4 
			else 3 
		end as StatusCode,
		ex.date_recv as StatusDate,
		cd2.Description as StatusDesc,  --NULL,	--SR211450: MPC 27/02/2013
		NULL as PropTranID,
		ex.transactionid as IssuedTranID,
		pt.policyid as PolicyID,
		po.policyref as CaseID,
		po.cont_num as PolicyNumber,
		ex.date_recv as PipelineStartDate,
		datediff(dd,ex.Date_Recv,@RunDate) as PipelineDays,
		ex.ID as ExpectationID,
		NULL as UnpaidListID,
		NULL as PaidListID,
		ex.Type as CommType,
		NULL as WrittenDate,
		pt.IssuedDate as IssuedDate,
		coalesce(pt.commcompanycode,po.comp_code) as ProviderCode,
		case pt.commtype 
			when 'F' then 'Accrual' 
			when 'L' then 'Level' 
			when 'T' then 'IT' 
		end as Basis,
		po.Client_Num as ClientID,
		case
			when cl.client_typ = 2 then substring(cl.name,1,50) -- PR 27/05/2010 For Corp Clients use Name as Firstname is always empty as causes the Name to be = Null
			else substring(	case 
								when charindex(' ', cl.firstnames) = 0 then cl.firstnames 
								else rtrim(substring(cl.firstnames, 1, charindex(' ', cl.firstnames))) 
							end + ' ' + cl.Name,1,50) 
		end as ClientName,
		--substring(case when charindex(' ', cl.firstnames) = 0 then cl.firstnames 
		--else rtrim(substring(cl.firstnames, 1, charindex(' ', cl.firstnames))) end + ' ' + cl.Name,1,50),

		round(									-- AG 11/11/2014 Rounding needed in case it is split trail or renewal
		case when ex.type in (2,15,16,17,18,19) 
			then -1 
			else 1 
		end *		--SR211450: MPC 27/02/2013
		case when co.DistributionAllowance is null				-- AG 11/11/2014
				then 1											-- AG 11/11/2014
			 when co.DistributionAllowance > 0 
				then co.FixedAmount/co.DistributionAllowance 
			 else 0 
		end *
		case when ex.Type in (10,16,19,4,15,18) -- AG 11/11/2014 Trail and renewals require split proportion.
			then co.agent_perc/100				-- AG 11/11/2014 Split proportion already on expectation for initial comm.
			else 1								-- AG 11/11/2014
		end *									-- AG 11/11/2014
		case when ex.amount_rec = 0 
			then abs(ex.amount_due) 
			else abs(ex.amount_rec) 		
		end,2) as Amount,						-- AG 11/11/2014 Rounding needed in case it is split trail or renewal
		
		round(									-- AG 11/11/2014 Rounding needed in case it is split trail or renewal
		case when ex.type in (2,15,16,17,18,19) 
				then -1 
				else 1 
		end *		--SR211450: MPC 27/02/2013
		case when co.DistributionAllowance is null				-- AG 11/11/2014
				then 1											-- AG 11/11/2014
			 when co.DistributionAllowance > 0 
				then co.FixedAmount/co.DistributionAllowance 
			 else 0 
		end *
--		case when co.FixedAmount > 0							-- AG 11/11/2014
		case when isnull(co.BaseAmount,0) > 0 and isnull(co.FixedAmount,0) > 0	-- AG 11/11/2014
			then co.BaseAmount/co.FixedAmount 
			else 1 
		end *
		case when ex.Type in (10,16,19,4,15,18) -- AG 11/11/2014 Trail and renewals require split proportion.
			then co.agent_perc/100				-- AG 11/11/2014 Split proportion already on expectation for initial comm.
			else 1								-- AG 11/11/2014
		end *									-- AG 11/11/2014
		case when ex.amount_rec = 0 
			then abs(ex.amount_due) 
			else abs(ex.amount_rec) 
		end,2) as BaseAmount,					-- AG 11/11/2014 Rounding needed in case it is split trail or renewal

		isnull(co.FranchiseUpliftPercent,100) as FranchiseUpliftPercent,	-- AG 11/11/2014. Default to 100
		-- co.agent_perc,										   AG 11/11/2014

		--AG 14/08/2018 Start
		case when ag.Manager2Code = @OwlManager2Code then		-- AG 08/12/2014
				case when AdviserSplit.AdviserSplitPerc >= 0.01
					then round(((co.Agent_Perc / AdviserSplit.AdviserSplitPerc) * 100.0) * 4.0, 0) / 4.0					--Rounds to nearest 0.25.
					else co.Agent_Perc
				end
		--AG 14/08/2018 End
			 when (co.Agent_Perc between 1 and 99) and ex.Type in (10,16,19,4,15,18) and ex.DATE_DUE >= @OpenworkMarginScriptDate then	-- AG 11/11/2014 
			   round(
			   isnull((co.Agent_Perc/(100-
				   isnull((select case when sum(Agent_Perc) = 100 then 0 else sum(Agent_Perc) end from mstt_Commissions 
							where (agent_code = @OpenworkMarginPotCode 
									or agent_code = @OpenworkBSCPotCode) 
							and TransactionID = ex.TransactionID
							and CommissionType = case									
													when ex.Type in (1,2,17) then 1
													when ex.Type in (4,15,18) then 4
													when ex.Type in (10,16,19) then 10
													else 99
												 end),0))),0) 
				* 100,2)
			else
				co.Agent_Perc
        end as Agent_Perc, 

		case	when ex.Type in  (10,16,19,4,15,18)		-- AG 11/11/2014. Trail and renewals do not generate NBI.
					then 0
				--when ex.Type in (2,15,16,17,18,19)	-- AG 11/11/2014
				when ex.Type in (2,17)					-- AG 11/11/2014. Negate initial cklawback and adjustment
					then -1 
				when ex.amount_rec = 0 and ex.amount_due < 0 
					then -1		--SR211450: MPC 27/02/2013
				when ex.amount_rec < 0 
					then -1 
				else 1 
		end * isnull(co.FixedAmount,0) as NBI,			-- AG 11/11/2014

		case	when ex.Type in  (10,16,19,4,15,18)		-- AG 11/11/2014. Trail and renewals do not generate NBI.
					then 0
				--when ex.Type in (2,15,16,17,18,19)	-- AG 11/11/2014
				when ex.Type in (2,17)					-- AG 11/11/2014. Negate initial cklawback and adjustment
					then -1 
				when ex.amount_rec = 0 and ex.amount_due < 0 
					then -1		--SR211450: MPC 27/02/2013
				when ex.amount_rec < 0 
					then -1 
				else 1 
		end * isnull(co.Turnover,0) as APE,				-- AG 11/11/2014

		po.SuspendCommission as PolicySuspend,
		po.SuspendCommissionLastUpdated as PolicySuspendDate,
		NULL as SuspenseCount,
		NULL as SuspenseAmount,
		coalesce(pt.commproductcode,po.productcode) as ProductCode,
		coalesce(pt.productgroupcode,po.productgroupcode) as ProdGroupCode,
		Case	when FM.TranId is not NULL 
					then 'Y' 
		end	as FirstReceipt		--NULL		--SR211450: MPC 27/02/2013
from	mstt_expectation ex
		inner join mstt_policytransactions pt on pt.id = ex.transactionid
		inner join mstt_policies po on po.pol_num = pt.policyid
		inner join mstt_clients cl on cl.client_num = po.client_num
		--AG 14/08/2018 Start
		inner join	(select TransactionID, MAX(Agent_Perc) As AdviserSplitPerc
 					 from	mstt_Commissions
					 where	CommissionType = 1
					 and	AGENT_CODE <> '10002'
					 group	by TransactionID
					) AdviserSplit on AdviserSplit.TransactionID = ex.transactionid		
		--AG 14/08/2018 End
		inner join mstt_commissions co 
					on co.transactionid = ex.transactionid 
					and co.commissiontype = case									-- AG 11/11/2014
												when ex.Type in (1,2,17) then 1
												when ex.Type in (4,15,18) then 4
												when ex.Type in (10,16,19) then 10
												else 99
											end
		inner join mstt_agents ag on ag.code = co.agent_code
		inner join sa_swift_S_STMTCT st on st.statement = ex.statement and st.deleted = 0	-- AG 17/05/2013 Exclude matched payments on deleted statements
		left outer join mstt_agents a2 on a2.code = co.firm
		left outer join mstt_PaymentsPending pp on pp.pacc_id = ex.id
		left join msit_MiWarehouseCodesandDescriptions cd1 on cd1.ColumnName = 'OA_Pipeline_TypeDesc' and cd1.Code = '2'	--SR211450: MPC 27/02/2013
		left join msit_MiWarehouseCodesandDescriptions cd2 on cd2.ColumnName = 'OA_Pipeline_StatusDesc' and cd2.Code = case when po.SuspendCommission = 1 then 4 else 3 end	--SR211450: MPC 27/02/2013
		left join ( select transactionid as TranID,min(ID) as FirstExpID			--SR211450: MPC 27/02/2013
					from mstt_expectation											--SR211450: MPC 27/02/2013
					where Type not in (5,6) and Status in (2,3)						--SR211450: MPC 27/02/2013
					group by transactionid) FM on FM.TranId = ex.transactionid and FM.FirstExpID = ex.ID	--SR211450: MPC 27/02/2013
where	ex.Type in (1,2,17,4,15,18,10,16,19)		-- ALL Payments --SR211450: MPC 27/02/2013
AND		ex.Status = 2								-- Matched (but not on Unpaid List)
AND		ex.Adjust in (0,1)							-- Exclude Adjustments (which never move forward)	--MPC: 18/04/2008		--SR218842: MPC 04/04/2013
AND		pp.ID is NULL								-- Not on Unpaid List
AND		ag.agenttype in (2,46,49,3,4,5,43,45,51)	-- Businesses and Sellers only
AND		a2.agenttype in (2,46,49)					-- Businesses only
AND		coalesce(convert(date,ex.CreateDate),ex.DATE_RECV) > @SuspenseDate		--SR211450: MPC 27/02/2013

--- Insert Pending Payments into owoa_Pipeline Table (only if Policy Suspended)		--SR211450: MPC 27/02/2013
--- Exclude Suspended Payments created earlier than the @SuspendPaymentDate
--- PipeLineTypeDesc='Payment'; StatusDesc='Payment Suspended'

UNION

select	DISTINCT
		2,
		cd1.Description,  --NULL,	--SR211450: MPC 27/02/2013
		cs.agentcode,
		substring(	case 
						when charindex(' ', ag.firstnames) = 0 
						then ag.firstnames 
						else rtrim(substring(ag.firstnames, 1, charindex(' ', ag.firstnames))) 
					end + ' ' + ag.Name,1,50),
		cs.BusinessCode,
		case 
			when cs.SuspendComm = 'Y' 
				then 4 
				else 5 
		end as StatusCode,
		cs.CreateDate,
		cd2.Description,  --NULL,	--SR211450: MPC 27/02/2013
		NULL,
		cs.TransactionId,
		cs.PolicyID,
		cs.CaseID,
		cs.ExtPolicyNumber,
		ex.Date_Recv,
		datediff(dd,ex.Date_Recv,@RunDate),
		cs.ExpectationID,
		cs.PendingPaymentID,
		cs.AgentPaymentsID,
		cs.CommissionType,
		NULL,
		ex.IncomeRecognitionDate,
		cs.ProviderCode,
		case cs.PayBasisCode 
			when 'F' then 'Accrual' 
			when 'L' then 'Level' 
			when 'T' then 'IT' 
		end as Basis,
		cs.ClientID,
		case
			when cl.client_typ = 2 then substring(cl.name,1,50) -- PR 27/05/2010 For Corp Clients use Name as Firstname is always empty as causes the Name to be = Null
			else substring(	case 
								when charindex(' ', cl.firstnames) = 0 then cl.firstnames 
								else rtrim(substring(cl.firstnames, 1, charindex(' ', cl.firstnames))) 
							end + ' ' + cl.Name,1,50) 
		end,
		--substring(case when charindex(' ', cl.firstnames) = 0 then cl.firstnames 
		--else rtrim(substring(cl.firstnames, 1, charindex(' ', cl.firstnames))) end + ' ' + cl.Name,1,50),
		cs.Amount,
		cs.BaseAmount,
		cs.FranchiseUpliftRate,
		--cs.AgentSplit,											  08/12/2014
		
		--AG 14/08/2018 Start	
		case 
		 when ag.Manager2Code = @OwlManager2Code then
				case when AdviserSplit.AdviserSplitPerc >= 0.01
					then round(((cs.AgentSplit / AdviserSplit.AdviserSplitPerc) * 100.0) * 4.0, 0) / 4.0					--Rounds to nearest 0.25.
					else cs.AgentSplit
				end
		--AG 14/08/2018 End	
		 when (cs.AgentSplit between 1 and 99) and cs.CommissionType in (10,16,19) and DueDate >= @OpenworkMarginScriptDate then		
		   isnull((cs.AgentSplit/(100-
		   isnull(CASE																									
					WHEN cs.Amount > 0 then																				
					(select sum(Agent_Perc) from mstt_PaymentsPending where (agent_code = @OpenworkMarginPotCode or agent_code = @OpenworkBSCPotCode) and	
					 pacc_ID=cs.expectationid and isnull(Agent_Perc,0) > 0 and Amount > 0)					
					WHEN cs.Amount < 0 then																				
					(select sum(Agent_Perc) from mstt_PaymentsPending where (agent_code = @OpenworkMarginPotCode or agent_code = @OpenworkBSCPotCode) and	
					 pacc_ID=cs.expectationid and isnull(Agent_Perc,0) > 0 and Amount < 0)					
					ELSE 0																								
					END ,0)	) ) * 100 , cs.AgentSplit)																	
		 else
		  cs.AgentSplit
		end,
		
		cs.INIssued,
		cs.APE,
		po.SuspendCommission,
		po.SuspendCommissionLastUpdated,
		NULL,
		NULL,
		po.productcode,
		po.productgroupcode,
		Case when FM.TranId is not NULL 
			then 'Y' 
		end	--NULL		--SR211450: MPC 27/02/2013
from	msit_CommissionStatement cs
		inner join mstt_Agents ag on ag.code = cs.agentcode
		left outer join mstt_policies po on po.pol_num = cs.policyid
		left outer join mstt_Clients cl on cl.client_num = cs.ClientID
		left outer join mstt_Expectation ex on ex.id = cs.expectationid
		left join msit_MiWarehouseCodesandDescriptions cd1 on cd1.ColumnName = 'OA_Pipeline_TypeDesc' and cd1.Code = '2'	--SR211450: MPC 27/02/2013
		left join msit_MiWarehouseCodesandDescriptions cd2 on cd2.ColumnName = 'OA_Pipeline_StatusDesc' and cd2.Code = case when po.SuspendCommission = 1 then 4 else 3 end	--SR211450: MPC 27/02/2013
		left join ( select transactionid as TranID,min(ID) as FirstExpID			--SR211450: MPC 27/02/2013
					from mstt_expectation											--SR211450: MPC 27/02/2013
					where Type not in (5,6) and Status in (2,3)						--SR211450: MPC 27/02/2013
					group by transactionid) FM on FM.TranId = ex.transactionid and FM.FirstExpID = ex.ID	--SR211450: MPC 27/02/2013
		--AG 14/08/2018 Start
		left join (select	PACC_ID, CONVERT(date,CreateDateTime) as PaymentMatchedDate, MAX(isnull(Agent_Perc,0)) as AdviserSplitPerc
					from	mstt_PaymentsPending
					where	agent_code <> '10002'
					group	by PACC_ID, CONVERT(date,CreateDateTime)
				 ) as AdviserSplit  on  AdviserSplit.PACC_ID = cs.ExpectationID 
									and AdviserSplit.PaymentMatchedDate = cs.CreateDate	-- PaymentDate included to handle backdated agent change (BAC) which does NOT create new expectation records
		--AG 14/08/2018 End
where	cs.reportingclasscode <> 4		-- Exclude Payments to Bank
AND		cs.BACSDate = '1 Jan 1901'	-- Date denotes Pending Payment
--AND cs.OAStatus = 'Valid'		-- Denotes Valid Business Owner Found		--MPC: SR9 - 07/05/2008
--AND cs.OAStatus in ('Suspended','Valid')	-- Denotes Valid Business Owner Found + Suspense PR: 16/03/2009
AND		cs.OAStatus in ('Suspended')		--SR211450: MPC 27/02/2013
AND		cs.CreateDate > @SuspendPaymentDate		--SR211450: MPC 27/02/2013
--AND (ex.Type is null 			-- Standing Order or Manual Payments			--SR211450: MPC 27/02/2013
--or ex.Type in (1,2,17))			-- IC, IC Clawback and IC Adjustments only	--SR211450: MPC 27/02/2013


drop table #SuspenseTotals		--SR211450: MPC 27/02/2013

GO
/****** Object:  StoredProcedure [dbo].[owoa_PipelineExtract_Backup20180817AG]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[owoa_PipelineExtract_Backup20180817AG]
@SuspenseDate datetime, @SuspendedDays int
as
 
/***********************************************************************************
	Object  : procedure
	Name    : owoa_PipelineExtract.sql
	Owner   : MPC
	Created : 14 June 2007
	Project : Open Access - Pipeline Table 

	Truncates and repopulates owoa_Pipeline table

	Call as owoa_PipelineExtract '1 Jan 2008','180'

--------------------------------------------------------------------------------------
	AMENDMENTS
	==========

	Mike Cawood Dec 2007 : 
	Dedup extracts by using Select Distinct

	Mike Cawood 18/04/2008 : 
	Exclude Expectations where Adjust <> 0 (Status Code 3)

	Mike Cawood 07/05/2008 : 
	SR9 - Ignore Payments where OAStatus not set to Valid
	
	Paul Robathan 16/03/2009 : 
	Include cases where OAStatus = Suspended

	Paul Robathan 27/05/2010 : 
	Amend Name extract for Corporate Clients as currently always set to NUll

	Mike Cawood 27/02/2013 : SR211450
	No longer Extract Matched Payments Awaiting Payment unless Policy is Suspended

	Mike Cawood 04/04/2013 : SR218842
	Include Matched Expectations with ADJUST flag set to 1 (this is set in the
	Reconciler) when a difference within tolerance is found.

	Alan Groves 10/05/2013 : SR226624
	Bug in population of @SuspendPaymentDate. Was today's date less 180 months, now
	corrected to be today's date less 180 days.

	Alan Groves 17/05/2013 : SR226624 - Part 2
	Amended the "Payment Agreed" select clause to exclude matched payments linked to 
	deleted statements as these are reporting with PipelineDays > 0
	
	Alan Groves 11/11/2014 : SR331383.
	1) Amended to join to mstt_Commissions with the correct CommissionType from the
	   Expectations table rather than hardcoded to CommissionType = 1 which is inital 
	   comm. This fix is needed to select trail payments correctly.
	2) Changed "and co.agent_code <> 10002" to "and co.agent_code <> '10002'" to
		protect the batch from non-numeric UIDs.
	3) Expectations are not split for trail and renewals like they are for initial,
		so split proportioning has been added just for trail and renewals.
	4) Split proportioning made the same as the Commission Listing to ignore the 
		effect of the BSC and ongoing fee margin pot codes.
		
	Alan Groves 08/12/2014 : SR350654
	1)	Amended for Owl Financial. In order to pay advisers the correct amount, the 
		commission shapes have been set up in such a way that adviser split % does
		not calculate correctly. This change introduces adjustment processing to
		restore the adviser split % to the value that the adviser would expect to see.
	2)  Populated Commission Type where known and Pipeline Type is 1.
	
	Alan Groves 29/03/2017 : SR471256/CH16774
	1)	Added an additional join to @SpecialCaseCommShapes to align with the Open Access
		Commission Listing to show the Owl Financial commission splits correctly (panels
		33 and 34). This change was overlooked - now brought into line.
************************************************************************************/

-- AG 11/11/2014 Start
declare	@OpenworkMarginPotCode		nvarchar(10),	
		@OpenworkMarginScriptDate	datetime,		
		@OpenworkBSCPotCode			nvarchar(10),	
		@OwlManager2Code			nvarchar(10)	-- AG 08/12/2014

declare @SpecialCaseCommShapes table				-- AG 08/12/2014
(
	CommissionShapeID	int,
	AdviserSplitPct		decimal(12,8),
	OverrideSplitPct	decimal(12,8),
	EffectiveStartDate	datetime,
	EffectiveEndDate	datetime
)

set @OpenworkMarginPotCode = (select Rtrim(longdescription) from msit_MIWarehouseCodesAndDescriptions 
          where columnname = 'OpenworkMarginOnTrail' and description = 'AgentCode')		
set @OpenworkMarginScriptDate = (select cast(longdescription as datetime) from msit_MIWarehouseCodesAndDescriptions 
          where  columnname = 'OpenworkMarginOnTrail' and description = 'ScriptDate')	
set @OpenworkBSCPotCode = (select Rtrim(longdescription) from msit_MIWarehouseCodesAndDescriptions 
          where columnname = 'BusinessServiceCharge' and description = 'AgentCode')		
-- AG 11/11/2014 End
-- AG 08/12/2014 Start
set @OwlManager2Code = (select cde.Code from msit_MIWarehouseCodesAndDescriptions cde	
			where cde.ColumnName = 'Manager2Code' and cde.Description = 'Owl Financial')

insert into @SpecialCaseCommShapes		
(
	CommissionShapeID,
	AdviserSplitPct,
	OverrideSplitPct,
	EffectiveStartDate,
	EffectiveEndDate
)
select	KeyValue as CommissionShapeID, 
		convert(decimal(12,8),KeyType) as AdviserSplitPct, 
		convert(decimal(12,8),SelectionType) as OverrideSplitPct, 
		EffectiveStartDate, 
		EffectiveEndDate
from	owt_SelectionControl
where	Process = 'OwlAdviserSplitPct'
-- AG 08/12/2014 End

declare @SuspendPaymentDate datetime;								--SR211450: MPC 27/02/2013
-- AG 10/05/2013 Start
--set @SuspendPaymentDate = dateadd(mm,-1*@SuspendedDays,getdate())	--SR211450: MPC 27/02/2013
set @SuspendPaymentDate = dateadd(dd,-1*@SuspendedDays,getdate())
-- AG 10/05/2013 End

declare @Months int
set @Months = -1*(select Code from msit_MIWarehouseCodesandDescriptions where ColumnName = 'OA_Pipeline_Months')

declare @OffDate datetime
set @OffDate = dateadd(mm,@Months,getdate())

declare @DropDate datetime
set @DropDate = (select Code from msit_MIWarehouseCodesandDescriptions where ColumnName = 'OA_Pipeline_DropDate')

--declare @EndDate datetime set @EndDate = @OffDate
--IF @DropDate < @OffDate BEGIN set @EndDate = @DropDate END

declare @RunDate datetime
set @RunDate = dateadd(dd,-1,getdate())

truncate table owoa_Pipeline

--SR211450: MPC 27/02/2013 - START - Moved to improve efficiency
-- Derive Suspense Counts & Apply to Table
select	un.policy,
		sum(case 
				when edc.id is not null 
					and edc.amountreceived > 0 
					and edc.CommissionType in ('I','Y') 
				then 1
				when edc.id is not null 
					and ex.amount_rec > 0 
				then 1 
				else 0 
			end) as Count,
		sum(case 
				when edc.id is not null 
					and edc.amountreceived > 0 
					and edc.CommissionType in ('I','Y') 
				then ex.amount_rec
				when edc.id is not null 
					and ex.amount_rec > 0 
				then ex.amount_rec 
				else 0 
			end) as Amount
into	#SuspenseTotals
from	mstt_expectation ex
		inner join msit_s_paccun un on un.pacc_id = ex.id
		left outer join msit_edifactcommissionstatementcontents edc on edc.pacc_id = ex.id
where	ex.type in (5,6) 			-- Suspense entries
AND		ex.INIT_ID is null			-- Unmatched
group	by un.policy
order	by un.policy
--SR211450: MPC 27/02/2013 - END

--- Insert Proposals without Splits into owoa_Pipeline Table

insert into owoa_Pipeline
(PipelineType,PipelineTypeDesc,SellerCode,SellerName,BusinessCode,StatusCode,StatusDate,StatusDesc,
PropTranID,IssuedTranID,PolicyID,CaseID,PolicyNumber,PipelineStartDate,PipelineDays,ExpectationID,
UnpaidListID,PaidListID,CommType,WrittenDate,IssuedDate,ProviderCode,Basis,ClientID,ClientName,Amount,
BaseAmount,UpliftRate,SellerSplit,NBI,APE,PolicySuspend,PolicySuspendDate,SuspenseCount,SuspenseAmount,
ProductCode,ProdGroupCode,FirstReceipt)

select	DISTINCT 
		1,
		cd1.Description,  --NULL,	--SR211450: MPC 27/02/2013
		pt.agentcode,
		substring(	case 
						when charindex(' ', ag.firstnames) = 0 
						then ag.firstnames 
						else rtrim(substring(ag.firstnames, 1, charindex(' ', ag.firstnames))) 
					end + ' ' + ag.Name,1,50),
		coalesce(ah.detailagentcode,ag.Firm),--1,	--SR211450: MPC 27/02/2013 
		case when ST.Count > 0 then 2 else 1 end,	--SR211450: MPC 27/02/2013
		pt.CreateDateTime,
		cd2.Description,	--NULL,	--SR211450: MPC 27/02/2013
		pt.ID,
		pt.IssuedTranID,
		pt.policyID,
		po.policyref,
		po.cont_num,
		pt.CreateDateTime,
		datediff(dd,pt.CreateDateTime,@RunDate),
		NULL,
		NULL,
		NULL,
		NULL,
		pt.WrittenDate,
		pt.IssuedDate,
		coalesce(pt.commcompanycode,po.comp_code),
		case pt.commtype 
			when 'F' then 'Accrual' 
			when 'L' then 'Level' 
			when 'T' then 'IT' 
		end as Basis,
		po.Client_Num,
		case
			when cl.client_typ = 2 then substring(cl.name,1,50) -- PR 27/05/2010 For Corp Clients use Name as Firstname is always empty as causes the Name to be = Null
			else substring(case 
								when charindex(' ', cl.firstnames) = 0 then cl.firstnames 
								else rtrim(substring(cl.firstnames, 1, charindex(' ', cl.firstnames))) 
							end + ' ' + cl.Name,1,50) 
		end,
		--substring(case when charindex(' ', cl.firstnames) = 0 then cl.firstnames 
		--else rtrim(substring(cl.firstnames, 1, charindex(' ', cl.firstnames))) end + ' ' + cl.Name,1,50),
		NULL,
		NULL,
		NULL,
		NULL,
		NULL,
		NULL,
		po.SuspendCommission,
		po.SuspendCommissionLastUpdated,--NULL,NULL,	--SR211450: MPC 27/02/2013
		ST.Count,
		St.Amount,		--SR211450: MPC 27/02/2013
		coalesce(pt.commproductcode,po.productcode),
		coalesce(pt.productgroupcode,po.productgroupcode),
		NULL
from	mstt_policytransactions pt
		inner join mstt_policies po on po.pol_num = pt.policyid
		left outer join mstt_commissions co on co.transactionid = pt.id and co.commissiontype = 1
		inner join mstt_agents ag on ag.code = pt.agentcode
		inner join mstt_clients cl on cl.client_num = po.client_num
		left outer join msit_agenthierarchyhistory ah 
							on ah.agentcode = pt.agentcode 
							and ah.defaultvalue = 1 
							and ah.participanttype in (6,7,8,9)
							and CAST(CONVERT(NVARCHAR, pt.createdatetime, 112) AS DATETIME) between ah.startdate and ah.enddate
		left outer join mstt_agents a2 on a2.code = coalesce(ah.detailagentcode,ag.Firm)
		left join #SuspenseTotals ST on ST.Policy = po.cont_num --SR211450: MPC 27/02/2013
		left join msit_MiWarehouseCodesandDescriptions cd1 on cd1.ColumnName = 'OA_Pipeline_TypeDesc' and cd1.Code = '1'	--SR211450: MPC 27/02/2013
		left join msit_MiWarehouseCodesandDescriptions cd2 on cd2.ColumnName = 'OA_Pipeline_StatusDesc' and cd2.Code = case when ST.Count > 0 then 2 else 1 end	--SR211450: MPC 27/02/2013
where	pt.Transtype = 39			-- Proposal
AND		(							-- No matching Issued Transaction found
			pt.IssuedTranID is null 		
OR 
		(pt.IssuedTranID is not null and pt.IssuedTranID not in (select distinct transactionid from mstt_Expectation))
		)
AND		pt.createdatetime > @DropDate				-- ignore transactions prior to Drop Date
AND		pt.createdatetime > @OffDate				-- ignore transactions after assumed Off period
AND		co.id is NULL								-- no Initial Commission splits
AND		ag.agenttype in (2,46,49,3,4,5,43,45,51)	-- Businesses and Sellers only
AND		a2.agenttype in (2,46,49)					-- Businesses only

UNION

--- Insert Proposals with Splits into owoa_Pipeline Table

select	DISTINCT
		1,
		cd1.Description,  --NULL,	--SR211450: MPC 27/02/2013
		co.agent_code,
		substring(	case when charindex(' ', ag.firstnames) = 0 
						then ag.firstnames 
						else rtrim(substring(ag.firstnames, 1, charindex(' ', ag.firstnames))) 
					end + ' ' + ag.Name,1,50),
		co.Firm,--1,	--SR211450: MPC 27/02/2013 
		case when ST.Count > 0 then 2 else 1 end,	--SR211450: MPC 27/02/2013
		pt.CreateDateTime,
		cd2.Description,	--NULL,	--SR211450: MPC 27/02/2013
		pt.ID,
		pt.IssuedTranID,
		pt.policyID,
		po.policyref,
		po.cont_num,
		pt.CreateDateTime,
		datediff(dd,pt.CreateDateTime,@RunDate),
		NULL,
		NULL,
		NULL,
		--NULL,				-- AG 08/12/2014
		co.CommissionType,	-- AG 08/12/2014
		pt.WrittenDate,
		pt.IssuedDate,
		coalesce(pt.commcompanycode,po.comp_code),
		case pt.commtype 
			when 'F' then 'Accrual' 
			when 'L' then 'Level' 
			when 'T' then 'IT' 
		end as Basis,
		po.Client_Num,
		case
			when cl.client_typ = 2 
				then substring(cl.name,1,50) -- PR 27/05/2010 For Corp Clients use Name as Firstname is always empty as causes the Name to be = Null
				else substring(
								case 
									when charindex(' ', cl.firstnames) = 0 
										then cl.firstnames 
										else rtrim(substring(cl.firstnames, 1, charindex(' ', cl.firstnames))) 
								end + ' ' + cl.Name,1,50) 
		end,
		--substring(case when charindex(' ', cl.firstnames) = 0 then cl.firstnames 
		--else rtrim(substring(cl.firstnames, 1, charindex(' ', cl.firstnames))) end + ' ' + cl.Name,1,50),
		case 
			when pt.commtype = 'T' or pt.frequency = 6 or pt.comminitialperiod <= 1 then co.FixedAmount 
			when pt.frequency = 2 and pt.comminitialperiod > 1 then co.FixedAmount/pt.comminitialperiod
			when pt.frequency = 5 and pt.comminitialperiod > 1 then 12 * (co.FixedAmount/pt.comminitialperiod)
			else co.FixedAmount 
		end as Amount,
		case when pt.commtype = 'T' or pt.frequency = 6 or pt.comminitialperiod <= 1 then co.BaseAmount 
			when pt.frequency = 2 and pt.comminitialperiod > 1 then co.BaseAmount/pt.comminitialperiod
			when pt.frequency = 5 and pt.comminitialperiod > 1 then 12 * (co.BaseAmount/pt.comminitialperiod)
			else co.BaseAmount 
		end as BaseAmount,
		co.FranchiseUpliftPercent,
		--co.agent_perc,										   AG 08/12/2014

		case when ag.Manager2Code = @OwlManager2Code then		-- AG 08/12/2014
				case when sccs.CommissionShapeID is not null and convert(decimal(12,2),co.Agent_Perc) = sccs.AdviserSplitPct 
						then sccs.OverrideSplitPct
						else b.BandValue
				end						
			 else
				co.Agent_Perc
        end as Agent_Perc, 

		co.FixedAmount,
		co.Turnover,
		po.SuspendCommission,
		po.SuspendCommissionLastUpdated,--NULL,NULL,	--SR211450: MPC 27/02/2013
		ST.Count,
		St.Amount,		--SR211450: MPC 27/02/2013
		coalesce(pt.commproductcode,po.productcode),
		coalesce(pt.productgroupcode,po.productgroupcode),
		NULL
from	mstt_policytransactions pt
		inner join mstt_policies po on po.pol_num = pt.policyid
		inner join mstt_commissions co 
					on co.transactionid = pt.id 
					and co.commissiontype = 1 
					and co.agent_code <> '10002'	-- AG 11/11/2014
		inner join mstt_agents ag on ag.code = co.agent_code
		inner join mstt_clients cl on cl.client_num = po.client_num
		left outer join mstt_agents a2 on a2.code = co.Firm
		left join #SuspenseTotals ST on ST.Policy = po.cont_num --SR211450: MPC 27/02/2013
		left join msit_MiWarehouseCodesandDescriptions cd1 on cd1.ColumnName = 'OA_Pipeline_TypeDesc' and cd1.Code = '1'	--SR211450: MPC 27/02/2013
		left join msit_MiWarehouseCodesandDescriptions cd2 on cd2.ColumnName = 'OA_Pipeline_StatusDesc' and cd2.Code = case when ST.Count > 0 then 2 else 1 end	--SR211450: MPC 27/02/2013
		left join owt_Bandings b																	-- AG 08/12/2014
					on b.BandType = 'AdviserSplitPct'
					and b.AppliesTo = 'Owl'
					and pt.createdatetime between b.EffectiveStartDate and b.EffectiveEndDate
					and co.Agent_Perc between b.BandStart and b.BandEnd
		left join @SpecialCaseCommShapes sccs 
					on sccs.CommissionShapeID = pt.CodeCommissionShapeID			-- AG 08/12/2014
					and sccs.AdviserSplitPct = convert(decimal(12,2),co.Agent_Perc)	-- AG 29/03/2017 
where	pt.Transtype = 39			-- Proposal
AND		(							-- No matching Issued Transaction found
			pt.IssuedTranID is null 		
OR 
		(pt.IssuedTranID is not null and pt.IssuedTranID not in (select distinct transactionid from mstt_Expectation))
		)
AND		pt.createdatetime > @DropDate				-- ignore transactions prior to Drop Date
AND		pt.createdatetime > @OffDate				-- ignore transactions after assumed Off period
AND		ag.agenttype in (2,46,49,3,4,5,43,45,51)	-- Businesses and Sellers only
AND		a2.agenttype in (2,46,49)					-- Businesses only



--- Insert Matched Payments not yet on Unpaid List into owoa_Pipeline Table
--- Exclude Payments created prior to @SuspenseDate   --SR211450: MPC 27/02/2013
--- PipeLineTypeDesc='Payment'; StatusDesc='Payment Agreed'

insert into owoa_Pipeline
(PipelineType,PipelineTypeDesc,SellerCode,SellerName,BusinessCode,StatusCode,StatusDate,StatusDesc,
PropTranID,IssuedTranID,PolicyID,CaseID,PolicyNumber,PipelineStartDate,PipelineDays,ExpectationID,
UnpaidListID,PaidListID,CommType,WrittenDate,IssuedDate,ProviderCode,Basis,ClientID,ClientName,Amount,
BaseAmount,UpliftRate,SellerSplit,NBI,APE,PolicySuspend,PolicySuspendDate,SuspenseCount,SuspenseAmount,
ProductCode,ProdGroupCode,FirstReceipt)
select	DISTINCT
		2 as PipelineType,
		cd1.Description as PipelineTypeDesc,  --NULL,	--SR211450: MPC 27/02/2013
		co.agent_code as SellerCode,
		substring(	case 
						when charindex(' ', ag.firstnames) = 0 then ag.firstnames 
						else rtrim(substring(ag.firstnames, 1, charindex(' ', ag.firstnames))) 
					end + ' ' + ag.Name,1,50) as SellerName,
		co.Firm as BusinessCode,
		case when po.SuspendCommission = 1 
			then 4 
			else 3 
		end as StatusCode,
		ex.date_recv as StatusDate,
		cd2.Description as StatusDesc,  --NULL,	--SR211450: MPC 27/02/2013
		NULL as PropTranID,
		ex.transactionid as IssuedTranID,
		pt.policyid as PolicyID,
		po.policyref as CaseID,
		po.cont_num as PolicyNumber,
		ex.date_recv as PipelineStartDate,
		datediff(dd,ex.Date_Recv,@RunDate) as PipelineDays,
		ex.ID as ExpectationID,
		NULL as UnpaidListID,
		NULL as PaidListID,
		ex.Type as CommType,
		NULL as WrittenDate,
		pt.IssuedDate as IssuedDate,
		coalesce(pt.commcompanycode,po.comp_code) as ProviderCode,
		case pt.commtype 
			when 'F' then 'Accrual' 
			when 'L' then 'Level' 
			when 'T' then 'IT' 
		end as Basis,
		po.Client_Num as ClientID,
		case
			when cl.client_typ = 2 then substring(cl.name,1,50) -- PR 27/05/2010 For Corp Clients use Name as Firstname is always empty as causes the Name to be = Null
			else substring(	case 
								when charindex(' ', cl.firstnames) = 0 then cl.firstnames 
								else rtrim(substring(cl.firstnames, 1, charindex(' ', cl.firstnames))) 
							end + ' ' + cl.Name,1,50) 
		end as ClientName,
		--substring(case when charindex(' ', cl.firstnames) = 0 then cl.firstnames 
		--else rtrim(substring(cl.firstnames, 1, charindex(' ', cl.firstnames))) end + ' ' + cl.Name,1,50),

		round(									-- AG 11/11/2014 Rounding needed in case it is split trail or renewal
		case when ex.type in (2,15,16,17,18,19) 
			then -1 
			else 1 
		end *		--SR211450: MPC 27/02/2013
		case when co.DistributionAllowance is null				-- AG 11/11/2014
				then 1											-- AG 11/11/2014
			 when co.DistributionAllowance > 0 
				then co.FixedAmount/co.DistributionAllowance 
			 else 0 
		end *
		case when ex.Type in (10,16,19,4,15,18) -- AG 11/11/2014 Trail and renewals require split proportion.
			then co.agent_perc/100				-- AG 11/11/2014 Split proportion already on expectation for initial comm.
			else 1								-- AG 11/11/2014
		end *									-- AG 11/11/2014
		case when ex.amount_rec = 0 
			then abs(ex.amount_due) 
			else abs(ex.amount_rec) 		
		end,2) as Amount,						-- AG 11/11/2014 Rounding needed in case it is split trail or renewal
		
		round(									-- AG 11/11/2014 Rounding needed in case it is split trail or renewal
		case when ex.type in (2,15,16,17,18,19) 
				then -1 
				else 1 
		end *		--SR211450: MPC 27/02/2013
		case when co.DistributionAllowance is null				-- AG 11/11/2014
				then 1											-- AG 11/11/2014
			 when co.DistributionAllowance > 0 
				then co.FixedAmount/co.DistributionAllowance 
			 else 0 
		end *
--		case when co.FixedAmount > 0							-- AG 11/11/2014
		case when isnull(co.BaseAmount,0) > 0 and isnull(co.FixedAmount,0) > 0	-- AG 11/11/2014
			then co.BaseAmount/co.FixedAmount 
			else 1 
		end *
		case when ex.Type in (10,16,19,4,15,18) -- AG 11/11/2014 Trail and renewals require split proportion.
			then co.agent_perc/100				-- AG 11/11/2014 Split proportion already on expectation for initial comm.
			else 1								-- AG 11/11/2014
		end *									-- AG 11/11/2014
		case when ex.amount_rec = 0 
			then abs(ex.amount_due) 
			else abs(ex.amount_rec) 
		end,2) as BaseAmount,					-- AG 11/11/2014 Rounding needed in case it is split trail or renewal

		isnull(co.FranchiseUpliftPercent,100) as FranchiseUpliftPercent,	-- AG 11/11/2014. Default to 100
		-- co.agent_perc,										   AG 11/11/2014

		case when ag.Manager2Code = @OwlManager2Code then		-- AG 08/12/2014
				case when sccs.CommissionShapeID is not null and convert(decimal(12,2),co.Agent_Perc) = sccs.AdviserSplitPct 
						then sccs.OverrideSplitPct
						else b.BandValue
				end						
			 when (co.Agent_Perc between 1 and 99) and ex.Type in (10,16,19,4,15,18) and ex.DATE_DUE >= @OpenworkMarginScriptDate then	-- AG 11/11/2014 
			   round(
			   isnull((co.Agent_Perc/(100-
				   isnull((select case when sum(Agent_Perc) = 100 then 0 else sum(Agent_Perc) end from mstt_Commissions 
							where (agent_code = @OpenworkMarginPotCode 
									or agent_code = @OpenworkBSCPotCode) 
							and TransactionID = ex.TransactionID
							and CommissionType = case									
													when ex.Type in (1,2,17) then 1
													when ex.Type in (4,15,18) then 4
													when ex.Type in (10,16,19) then 10
													else 99
												 end),0))),0) 
				* 100,2)
			else
				co.Agent_Perc
        end as Agent_Perc, 

		case	when ex.Type in  (10,16,19,4,15,18)		-- AG 11/11/2014. Trail and renewals do not generate NBI.
					then 0
				--when ex.Type in (2,15,16,17,18,19)	-- AG 11/11/2014
				when ex.Type in (2,17)					-- AG 11/11/2014. Negate initial cklawback and adjustment
					then -1 
				when ex.amount_rec = 0 and ex.amount_due < 0 
					then -1		--SR211450: MPC 27/02/2013
				when ex.amount_rec < 0 
					then -1 
				else 1 
		end * isnull(co.FixedAmount,0) as NBI,			-- AG 11/11/2014

		case	when ex.Type in  (10,16,19,4,15,18)		-- AG 11/11/2014. Trail and renewals do not generate NBI.
					then 0
				--when ex.Type in (2,15,16,17,18,19)	-- AG 11/11/2014
				when ex.Type in (2,17)					-- AG 11/11/2014. Negate initial cklawback and adjustment
					then -1 
				when ex.amount_rec = 0 and ex.amount_due < 0 
					then -1		--SR211450: MPC 27/02/2013
				when ex.amount_rec < 0 
					then -1 
				else 1 
		end * isnull(co.Turnover,0) as APE,				-- AG 11/11/2014

		po.SuspendCommission as PolicySuspend,
		po.SuspendCommissionLastUpdated as PolicySuspendDate,
		NULL as SuspenseCount,
		NULL as SuspenseAmount,
		coalesce(pt.commproductcode,po.productcode) as ProductCode,
		coalesce(pt.productgroupcode,po.productgroupcode) as ProdGroupCode,
		Case	when FM.TranId is not NULL 
					then 'Y' 
		end	as FirstReceipt		--NULL		--SR211450: MPC 27/02/2013
from	mstt_expectation ex
		inner join mstt_policytransactions pt on pt.id = ex.transactionid
		inner join mstt_policies po on po.pol_num = pt.policyid
		inner join mstt_clients cl on cl.client_num = po.client_num
		inner join mstt_commissions co 
					on co.transactionid = ex.transactionid 
					and co.commissiontype = case									-- AG 11/11/2014
												when ex.Type in (1,2,17) then 1
												when ex.Type in (4,15,18) then 4
												when ex.Type in (10,16,19) then 10
												else 99
											end
		inner join mstt_agents ag on ag.code = co.agent_code
		inner join sa_swift_S_STMTCT st on st.statement = ex.statement and st.deleted = 0	-- AG 17/05/2013 Exclude matched payments on deleted statements
		left outer join mstt_agents a2 on a2.code = co.firm
		left outer join mstt_PaymentsPending pp on pp.pacc_id = ex.id
		left join msit_MiWarehouseCodesandDescriptions cd1 on cd1.ColumnName = 'OA_Pipeline_TypeDesc' and cd1.Code = '2'	--SR211450: MPC 27/02/2013
		left join msit_MiWarehouseCodesandDescriptions cd2 on cd2.ColumnName = 'OA_Pipeline_StatusDesc' and cd2.Code = case when po.SuspendCommission = 1 then 4 else 3 end	--SR211450: MPC 27/02/2013
		left join ( select transactionid as TranID,min(ID) as FirstExpID			--SR211450: MPC 27/02/2013
					from mstt_expectation											--SR211450: MPC 27/02/2013
					where Type not in (5,6) and Status in (2,3)						--SR211450: MPC 27/02/2013
					group by transactionid) FM on FM.TranId = ex.transactionid and FM.FirstExpID = ex.ID	--SR211450: MPC 27/02/2013
		left join owt_Bandings b																-- AG 08/12/2014
					on b.BandType = 'AdviserSplitPct'
					and b.AppliesTo = 'Owl'
					and coalesce(ex.CreateDate,ex.DATE_RECV) between b.EffectiveStartDate and b.EffectiveEndDate
					and co.Agent_Perc between b.BandStart and b.BandEnd
		left join @SpecialCaseCommShapes sccs 
					on sccs.CommissionShapeID = ex.CommShapeID						-- AG 08/12/2014
					and sccs.AdviserSplitPct = convert(decimal(12,2),co.Agent_Perc)	-- AG 29/03/2017 
where	ex.Type in (1,2,17,4,15,18,10,16,19)		-- ALL Payments --SR211450: MPC 27/02/2013
AND		ex.Status = 2								-- Matched (but not on Unpaid List)
AND		ex.Adjust in (0,1)							-- Exclude Adjustments (which never move forward)	--MPC: 18/04/2008		--SR218842: MPC 04/04/2013
AND		pp.ID is NULL								-- Not on Unpaid List
AND		ag.agenttype in (2,46,49,3,4,5,43,45,51)	-- Businesses and Sellers only
AND		a2.agenttype in (2,46,49)					-- Businesses only
AND		coalesce(ex.CreateDate,ex.DATE_RECV) > @SuspenseDate		--SR211450: MPC 27/02/2013

--- Insert Pending Payments into owoa_Pipeline Table (only if Policy Suspended)		--SR211450: MPC 27/02/2013
--- Exclude Suspended Payments created earlier than the @SuspendPaymentDate
--- PipeLineTypeDesc='Payment'; StatusDesc='Payment Suspended'

UNION

select	DISTINCT
		2,
		cd1.Description,  --NULL,	--SR211450: MPC 27/02/2013
		cs.agentcode,
		substring(	case 
						when charindex(' ', ag.firstnames) = 0 
						then ag.firstnames 
						else rtrim(substring(ag.firstnames, 1, charindex(' ', ag.firstnames))) 
					end + ' ' + ag.Name,1,50),
		cs.BusinessCode,
		case 
			when cs.SuspendComm = 'Y' 
				then 4 
				else 5 
		end as StatusCode,
		cs.CreateDate,
		cd2.Description,  --NULL,	--SR211450: MPC 27/02/2013
		NULL,
		cs.TransactionId,
		cs.PolicyID,
		cs.CaseID,
		cs.ExtPolicyNumber,
		ex.Date_Recv,
		datediff(dd,ex.Date_Recv,@RunDate),
		cs.ExpectationID,
		cs.PendingPaymentID,
		cs.AgentPaymentsID,
		cs.CommissionType,
		NULL,
		ex.IncomeRecognitionDate,
		cs.ProviderCode,
		case cs.PayBasisCode 
			when 'F' then 'Accrual' 
			when 'L' then 'Level' 
			when 'T' then 'IT' 
		end as Basis,
		cs.ClientID,
		case
			when cl.client_typ = 2 then substring(cl.name,1,50) -- PR 27/05/2010 For Corp Clients use Name as Firstname is always empty as causes the Name to be = Null
			else substring(	case 
								when charindex(' ', cl.firstnames) = 0 then cl.firstnames 
								else rtrim(substring(cl.firstnames, 1, charindex(' ', cl.firstnames))) 
							end + ' ' + cl.Name,1,50) 
		end,
		--substring(case when charindex(' ', cl.firstnames) = 0 then cl.firstnames 
		--else rtrim(substring(cl.firstnames, 1, charindex(' ', cl.firstnames))) end + ' ' + cl.Name,1,50),
		cs.Amount,
		cs.BaseAmount,
		cs.FranchiseUpliftRate,
		--cs.AgentSplit,											  08/12/2014
		
		case when ag.Manager2Code = @OwlManager2Code then		-- AG 08/12/2014
			case when sccs.CommissionShapeID is not null and convert(decimal(12,2),cs.AgentSplit) = sccs.AdviserSplitPct 
				then sccs.OverrideSplitPct
				else b.BandValue
			end
		 when (cs.AgentSplit between 1 and 99) and cs.CommissionType in (10,16,19) and DueDate >= @OpenworkMarginScriptDate then		
		   isnull((cs.AgentSplit/(100-
		   isnull(CASE																									
					WHEN cs.Amount > 0 then																				
					(select sum(Agent_Perc) from mstt_PaymentsPending where (agent_code = @OpenworkMarginPotCode or agent_code = @OpenworkBSCPotCode) and	
					 pacc_ID=cs.expectationid and isnull(Agent_Perc,0) > 0 and Amount > 0)					
					WHEN cs.Amount < 0 then																				
					(select sum(Agent_Perc) from mstt_PaymentsPending where (agent_code = @OpenworkMarginPotCode or agent_code = @OpenworkBSCPotCode) and	
					 pacc_ID=cs.expectationid and isnull(Agent_Perc,0) > 0 and Amount < 0)					
					ELSE 0																								
					END ,0)	) ) * 100 , cs.AgentSplit)																	
		 else
		  cs.AgentSplit
		end,
		
		cs.INIssued,
		cs.APE,
		po.SuspendCommission,
		po.SuspendCommissionLastUpdated,
		NULL,
		NULL,
		po.productcode,
		po.productgroupcode,
		Case when FM.TranId is not NULL 
			then 'Y' 
		end	--NULL		--SR211450: MPC 27/02/2013
from	msit_CommissionStatement cs
		inner join mstt_Agents ag on ag.code = cs.agentcode
		left outer join mstt_policies po on po.pol_num = cs.policyid
		left outer join mstt_Clients cl on cl.client_num = cs.ClientID
		left outer join mstt_Expectation ex on ex.id = cs.expectationid
		left join msit_MiWarehouseCodesandDescriptions cd1 on cd1.ColumnName = 'OA_Pipeline_TypeDesc' and cd1.Code = '2'	--SR211450: MPC 27/02/2013
		left join msit_MiWarehouseCodesandDescriptions cd2 on cd2.ColumnName = 'OA_Pipeline_StatusDesc' and cd2.Code = case when po.SuspendCommission = 1 then 4 else 3 end	--SR211450: MPC 27/02/2013
		left join ( select transactionid as TranID,min(ID) as FirstExpID			--SR211450: MPC 27/02/2013
					from mstt_expectation											--SR211450: MPC 27/02/2013
					where Type not in (5,6) and Status in (2,3)						--SR211450: MPC 27/02/2013
					group by transactionid) FM on FM.TranId = ex.transactionid and FM.FirstExpID = ex.ID	--SR211450: MPC 27/02/2013
		left join owt_Bandings b																-- AG 08/12/2014
					on b.BandType = 'AdviserSplitPct'
					and b.AppliesTo = 'Owl'
					and cs.CreateDate between b.EffectiveStartDate and b.EffectiveEndDate
					and cs.AgentSplit between b.BandStart and b.BandEnd
		left join @SpecialCaseCommShapes sccs 
					on sccs.CommissionShapeID = cs.CommShapeID						-- AG 08/12/2014
					and sccs.AdviserSplitPct = convert(decimal(12,2),cs.AgentSplit)	-- AG 29/03/2017 
where	cs.reportingclasscode <> 4		-- Exclude Payments to Bank
AND		cs.BACSDate = '1 Jan 1901'	-- Date denotes Pending Payment
--AND cs.OAStatus = 'Valid'		-- Denotes Valid Business Owner Found		--MPC: SR9 - 07/05/2008
--AND cs.OAStatus in ('Suspended','Valid')	-- Denotes Valid Business Owner Found + Suspense PR: 16/03/2009
AND		cs.OAStatus in ('Suspended')		--SR211450: MPC 27/02/2013
AND		cs.CreateDate > @SuspendPaymentDate		--SR211450: MPC 27/02/2013
--AND (ex.Type is null 			-- Standing Order or Manual Payments			--SR211450: MPC 27/02/2013
--or ex.Type in (1,2,17))			-- IC, IC Clawback and IC Adjustments only	--SR211450: MPC 27/02/2013


drop table #SuspenseTotals		--SR211450: MPC 27/02/2013

GO
/****** Object:  StoredProcedure [dbo].[owoa_PipelineExtract_NewOwlSplitsCalcAG]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[owoa_PipelineExtract_NewOwlSplitsCalcAG]
@SuspenseDate datetime, @SuspendedDays int
as
 
/***********************************************************************************
	Object  : procedure
	Name    : owoa_PipelineExtract.sql
	Owner   : MPC
	Created : 14 June 2007
	Project : Open Access - Pipeline Table 

	Truncates and repopulates owoa_Pipeline table

	Call as owoa_PipelineExtract '1 Jan 2008','180'

--------------------------------------------------------------------------------------
	AMENDMENTS
	==========

	Mike Cawood Dec 2007 : 
	Dedup extracts by using Select Distinct

	Mike Cawood 18/04/2008 : 
	Exclude Expectations where Adjust <> 0 (Status Code 3)

	Mike Cawood 07/05/2008 : 
	SR9 - Ignore Payments where OAStatus not set to Valid
	
	Paul Robathan 16/03/2009 : 
	Include cases where OAStatus = Suspended

	Paul Robathan 27/05/2010 : 
	Amend Name extract for Corporate Clients as currently always set to NUll

	Mike Cawood 27/02/2013 : SR211450
	No longer Extract Matched Payments Awaiting Payment unless Policy is Suspended

	Mike Cawood 04/04/2013 : SR218842
	Include Matched Expectations with ADJUST flag set to 1 (this is set in the
	Reconciler) when a difference within tolerance is found.

	Alan Groves 10/05/2013 : SR226624
	Bug in population of @SuspendPaymentDate. Was today's date less 180 months, now
	corrected to be today's date less 180 days.

	Alan Groves 17/05/2013 : SR226624 - Part 2
	Amended the "Payment Agreed" select clause to exclude matched payments linked to 
	deleted statements as these are reporting with PipelineDays > 0
	
	Alan Groves 11/11/2014 : SR331383.
	1) Amended to join to mstt_Commissions with the correct CommissionType from the
	   Expectations table rather than hardcoded to CommissionType = 1 which is inital 
	   comm. This fix is needed to select trail payments correctly.
	2) Changed "and co.agent_code <> 10002" to "and co.agent_code <> '10002'" to
		protect the batch from non-numeric UIDs.
	3) Expectations are not split for trail and renewals like they are for initial,
		so split proportioning has been added just for trail and renewals.
	4) Split proportioning made the same as the Commission Listing to ignore the 
		effect of the BSC and ongoing fee margin pot codes.
		
	Alan Groves 08/12/2014 : SR350654
	1)	Amended for Owl Financial. In order to pay advisers the correct amount, the 
		commission shapes have been set up in such a way that adviser split % does
		not calculate correctly. This change introduces adjustment processing to
		restore the adviser split % to the value that the adviser would expect to see.
	2)  Populated Commission Type where known and Pipeline Type is 1.
	
	Alan Groves 29/03/2017 : SR471256/CH16774
	1)	Added an additional join to @SpecialCaseCommShapes to align with the Open Access
		Commission Listing to show the Owl Financial commission splits correctly (panels
		33 and 34). This change was overlooked - now brought into line.
		
	Alan Groves 14/08/2018 : SR512759/CH22273
	1)	Changed calculation of Owl splits to be arithmetic instead of using banding 
		table "owt_Bandings" and "@SpecialCaseCommShapes". The benfit is that when
		new Owl commission shapes are introduced in the future, then no config work
		would be needed for the splits to yield the required "smoothed" values. 
	2)	This Pipeline has logic in it to drop off old cases. However, the date 
		comparisons are at date/time level which means that every time this proc runs
		(even if just a few minutes apart) then a different row count is returned 
		each time. The code has been changed to manage the drop off at date level
		rather than date/time level to ensure multiple runs in the same day will 
		yield the same results.
************************************************************************************/

-- AG 11/11/2014 Start
declare	@OpenworkMarginPotCode		nvarchar(10),	
		@OpenworkMarginScriptDate	datetime,		
		@OpenworkBSCPotCode			nvarchar(10),	
		@OwlManager2Code			nvarchar(10)	-- AG 08/12/2014

declare @SpecialCaseCommShapes table				-- AG 08/12/2014
(
	CommissionShapeID	int,
	AdviserSplitPct		decimal(12,8),
	OverrideSplitPct	decimal(12,8),
	EffectiveStartDate	datetime,
	EffectiveEndDate	datetime
)

set @OpenworkMarginPotCode = (select Rtrim(longdescription) from msit_MIWarehouseCodesAndDescriptions 
          where columnname = 'OpenworkMarginOnTrail' and description = 'AgentCode')		
set @OpenworkMarginScriptDate = (select cast(longdescription as datetime) from msit_MIWarehouseCodesAndDescriptions 
          where  columnname = 'OpenworkMarginOnTrail' and description = 'ScriptDate')	
set @OpenworkBSCPotCode = (select Rtrim(longdescription) from msit_MIWarehouseCodesAndDescriptions 
          where columnname = 'BusinessServiceCharge' and description = 'AgentCode')		
-- AG 11/11/2014 End
-- AG 08/12/2014 Start
set @OwlManager2Code = (select cde.Code from msit_MIWarehouseCodesAndDescriptions cde	
			where cde.ColumnName = 'Manager2Code' and cde.Description = 'Owl Financial')
-- AG 08/12/2014 End

declare @SuspendPaymentDate datetime;								--SR211450: MPC 27/02/2013
-- AG 10/05/2013 Start
--set @SuspendPaymentDate = dateadd(mm,-1*@SuspendedDays,getdate())	--SR211450: MPC 27/02/2013
set @SuspendPaymentDate = dateadd(dd,-1*@SuspendedDays,getdate())
-- AG 10/05/2013 End
set @SuspendPaymentDate = CONVERT(date,@SuspendPaymentDate)			--AG 14/08/2018 (2)

declare @Months int
set @Months = -1*(select Code from msit_MIWarehouseCodesandDescriptions where ColumnName = 'OA_Pipeline_Months')

declare @OffDate datetime
set @OffDate = dateadd(mm,@Months,getdate())
set @OffDate = CONVERT(date,@OffDate)			--AG 14/08/2018 (2)

declare @DropDate datetime
set @DropDate = (select Code from msit_MIWarehouseCodesandDescriptions where ColumnName = 'OA_Pipeline_DropDate')

--declare @EndDate datetime set @EndDate = @OffDate
--IF @DropDate < @OffDate BEGIN set @EndDate = @DropDate END

declare @RunDate datetime
set @RunDate = dateadd(dd,-1,getdate())

truncate table AG_TEST_owoa_Pipeline

--SR211450: MPC 27/02/2013 - START - Moved to improve efficiency
-- Derive Suspense Counts & Apply to Table
select	un.policy,
		sum(case 
				when edc.id is not null 
					and edc.amountreceived > 0 
					and edc.CommissionType in ('I','Y') 
				then 1
				when edc.id is not null 
					and ex.amount_rec > 0 
				then 1 
				else 0 
			end) as Count,
		sum(case 
				when edc.id is not null 
					and edc.amountreceived > 0 
					and edc.CommissionType in ('I','Y') 
				then ex.amount_rec
				when edc.id is not null 
					and ex.amount_rec > 0 
				then ex.amount_rec 
				else 0 
			end) as Amount
into	#SuspenseTotals
from	mstt_expectation ex
		inner join msit_s_paccun un on un.pacc_id = ex.id
		left outer join msit_edifactcommissionstatementcontents edc on edc.pacc_id = ex.id
where	ex.type in (5,6) 			-- Suspense entries
AND		ex.INIT_ID is null			-- Unmatched
group	by un.policy
order	by un.policy
--SR211450: MPC 27/02/2013 - END

--- Insert Proposals without Splits into owoa_Pipeline Table

insert into AG_TEST_owoa_Pipeline
(PipelineType,PipelineTypeDesc,SellerCode,SellerName,BusinessCode,StatusCode,StatusDate,StatusDesc,
PropTranID,IssuedTranID,PolicyID,CaseID,PolicyNumber,PipelineStartDate,PipelineDays,ExpectationID,
UnpaidListID,PaidListID,CommType,WrittenDate,IssuedDate,ProviderCode,Basis,ClientID,ClientName,Amount,
BaseAmount,UpliftRate,SellerSplit,NBI,APE,PolicySuspend,PolicySuspendDate,SuspenseCount,SuspenseAmount,
ProductCode,ProdGroupCode,FirstReceipt)

select	DISTINCT 
		1,
		cd1.Description,  --NULL,	--SR211450: MPC 27/02/2013
		pt.agentcode,
		substring(	case 
						when charindex(' ', ag.firstnames) = 0 
						then ag.firstnames 
						else rtrim(substring(ag.firstnames, 1, charindex(' ', ag.firstnames))) 
					end + ' ' + ag.Name,1,50),
		coalesce(ah.detailagentcode,ag.Firm),--1,	--SR211450: MPC 27/02/2013 
		case when ST.Count > 0 then 2 else 1 end,	--SR211450: MPC 27/02/2013
		pt.CreateDateTime,
		cd2.Description,	--NULL,	--SR211450: MPC 27/02/2013
		pt.ID,
		pt.IssuedTranID,
		pt.policyID,
		po.policyref,
		po.cont_num,
		pt.CreateDateTime,
		datediff(dd,pt.CreateDateTime,@RunDate),
		NULL,
		NULL,
		NULL,
		NULL,
		pt.WrittenDate,
		pt.IssuedDate,
		coalesce(pt.commcompanycode,po.comp_code),
		case pt.commtype 
			when 'F' then 'Accrual' 
			when 'L' then 'Level' 
			when 'T' then 'IT' 
		end as Basis,
		po.Client_Num,
		case
			when cl.client_typ = 2 then substring(cl.name,1,50) -- PR 27/05/2010 For Corp Clients use Name as Firstname is always empty as causes the Name to be = Null
			else substring(case 
								when charindex(' ', cl.firstnames) = 0 then cl.firstnames 
								else rtrim(substring(cl.firstnames, 1, charindex(' ', cl.firstnames))) 
							end + ' ' + cl.Name,1,50) 
		end,
		--substring(case when charindex(' ', cl.firstnames) = 0 then cl.firstnames 
		--else rtrim(substring(cl.firstnames, 1, charindex(' ', cl.firstnames))) end + ' ' + cl.Name,1,50),
		NULL,
		NULL,
		NULL,
		NULL,
		NULL,
		NULL,
		po.SuspendCommission,
		po.SuspendCommissionLastUpdated,--NULL,NULL,	--SR211450: MPC 27/02/2013
		ST.Count,
		St.Amount,		--SR211450: MPC 27/02/2013
		coalesce(pt.commproductcode,po.productcode),
		coalesce(pt.productgroupcode,po.productgroupcode),
		NULL
from	mstt_policytransactions pt
		inner join mstt_policies po on po.pol_num = pt.policyid
		left outer join mstt_commissions co on co.transactionid = pt.id and co.commissiontype = 1
		inner join mstt_agents ag on ag.code = pt.agentcode
		inner join mstt_clients cl on cl.client_num = po.client_num
		left outer join msit_agenthierarchyhistory ah 
							on ah.agentcode = pt.agentcode 
							and ah.defaultvalue = 1 
							and ah.participanttype in (6,7,8,9)
							and CAST(CONVERT(NVARCHAR, pt.createdatetime, 112) AS DATETIME) between ah.startdate and ah.enddate
		left outer join mstt_agents a2 on a2.code = coalesce(ah.detailagentcode,ag.Firm)
		left join #SuspenseTotals ST on ST.Policy = po.cont_num --SR211450: MPC 27/02/2013
		left join msit_MiWarehouseCodesandDescriptions cd1 on cd1.ColumnName = 'OA_Pipeline_TypeDesc' and cd1.Code = '1'	--SR211450: MPC 27/02/2013
		left join msit_MiWarehouseCodesandDescriptions cd2 on cd2.ColumnName = 'OA_Pipeline_StatusDesc' and cd2.Code = case when ST.Count > 0 then 2 else 1 end	--SR211450: MPC 27/02/2013
where	pt.Transtype = 39			-- Proposal
AND		(							-- No matching Issued Transaction found
			pt.IssuedTranID is null 		
OR 
		(pt.IssuedTranID is not null and pt.IssuedTranID not in (select distinct transactionid from mstt_Expectation))
		)
AND		convert(date,pt.createdatetime) > @DropDate		-- ignore transactions prior to Drop Date			AG 14/08/2018 (2)
AND		convert(date,pt.createdatetime) > @OffDate		-- ignore transactions after assumed Off period		AG 14/08/2018 (2)
AND		co.id is NULL									-- no Initial Commission splits
AND		ag.agenttype in (2,46,49,3,4,5,43,45,51)		-- Businesses and Sellers only
AND		a2.agenttype in (2,46,49)						-- Businesses only

UNION

--- Insert Proposals with Splits into owoa_Pipeline Table

select	DISTINCT
		1,
		cd1.Description,  --NULL,	--SR211450: MPC 27/02/2013
		co.agent_code,
		substring(	case when charindex(' ', ag.firstnames) = 0 
						then ag.firstnames 
						else rtrim(substring(ag.firstnames, 1, charindex(' ', ag.firstnames))) 
					end + ' ' + ag.Name,1,50),
		co.Firm,--1,	--SR211450: MPC 27/02/2013 
		case when ST.Count > 0 then 2 else 1 end,	--SR211450: MPC 27/02/2013
		pt.CreateDateTime,
		cd2.Description,	--NULL,	--SR211450: MPC 27/02/2013
		pt.ID,
		pt.IssuedTranID,
		pt.policyID,
		po.policyref,
		po.cont_num,
		pt.CreateDateTime,
		datediff(dd,pt.CreateDateTime,@RunDate),
		NULL,
		NULL,
		NULL,
		--NULL,				-- AG 08/12/2014
		co.CommissionType,	-- AG 08/12/2014
		pt.WrittenDate,
		pt.IssuedDate,
		coalesce(pt.commcompanycode,po.comp_code),
		case pt.commtype 
			when 'F' then 'Accrual' 
			when 'L' then 'Level' 
			when 'T' then 'IT' 
		end as Basis,
		po.Client_Num,
		case
			when cl.client_typ = 2 
				then substring(cl.name,1,50) -- PR 27/05/2010 For Corp Clients use Name as Firstname is always empty as causes the Name to be = Null
				else substring(
								case 
									when charindex(' ', cl.firstnames) = 0 
										then cl.firstnames 
										else rtrim(substring(cl.firstnames, 1, charindex(' ', cl.firstnames))) 
								end + ' ' + cl.Name,1,50) 
		end,
		--substring(case when charindex(' ', cl.firstnames) = 0 then cl.firstnames 
		--else rtrim(substring(cl.firstnames, 1, charindex(' ', cl.firstnames))) end + ' ' + cl.Name,1,50),
		case 
			when pt.commtype = 'T' or pt.frequency = 6 or pt.comminitialperiod <= 1 then co.FixedAmount 
			when pt.frequency = 2 and pt.comminitialperiod > 1 then co.FixedAmount/pt.comminitialperiod
			when pt.frequency = 5 and pt.comminitialperiod > 1 then 12 * (co.FixedAmount/pt.comminitialperiod)
			else co.FixedAmount 
		end as Amount,
		case when pt.commtype = 'T' or pt.frequency = 6 or pt.comminitialperiod <= 1 then co.BaseAmount 
			when pt.frequency = 2 and pt.comminitialperiod > 1 then co.BaseAmount/pt.comminitialperiod
			when pt.frequency = 5 and pt.comminitialperiod > 1 then 12 * (co.BaseAmount/pt.comminitialperiod)
			else co.BaseAmount 
		end as BaseAmount,
		co.FranchiseUpliftPercent,
		--co.agent_perc,										   AG 08/12/2014

		--AG 14/08/2018 Start
		case when ag.Manager2Code = @OwlManager2Code then		-- AG 08/12/2014
			case when AdviserSplit.AdviserSplitPerc >= 0.01
				then round(((co.Agent_Perc / AdviserSplit.AdviserSplitPerc) * 100.0) * 4.0, 0) / 4.0					--Rounds to nearest 0.25.
				else co.Agent_Perc
			end
		else
			co.Agent_Perc
        end as Agent_Perc, 
		--AG 14/08/2018 End
		
		co.FixedAmount,
		co.Turnover,
		po.SuspendCommission,
		po.SuspendCommissionLastUpdated,--NULL,NULL,	--SR211450: MPC 27/02/2013
		ST.Count,
		St.Amount,		--SR211450: MPC 27/02/2013
		coalesce(pt.commproductcode,po.productcode),
		coalesce(pt.productgroupcode,po.productgroupcode),
		NULL
from	mstt_policytransactions pt
		inner join mstt_policies po on po.pol_num = pt.policyid
		--AG 14/08/2018 Start
		inner join	(select TransactionID, MAX(Agent_Perc) As AdviserSplitPerc
 					 from	mstt_Commissions
					 where	CommissionType = 1
					 and	AGENT_CODE <> '10002'
					 group	by TransactionID
					) AdviserSplit on AdviserSplit.TransactionID = pt.ID		
		--AG 14/08/2018 End
		inner join mstt_commissions co 
					on co.transactionid = pt.id 
					and co.commissiontype = 1 
					and co.agent_code <> '10002'	-- AG 11/11/2014
		inner join mstt_agents ag on ag.code = co.agent_code
		inner join mstt_clients cl on cl.client_num = po.client_num
		left outer join mstt_agents a2 on a2.code = co.Firm
		left join #SuspenseTotals ST on ST.Policy = po.cont_num --SR211450: MPC 27/02/2013
		left join msit_MiWarehouseCodesandDescriptions cd1 on cd1.ColumnName = 'OA_Pipeline_TypeDesc' and cd1.Code = '1'	--SR211450: MPC 27/02/2013
		left join msit_MiWarehouseCodesandDescriptions cd2 on cd2.ColumnName = 'OA_Pipeline_StatusDesc' and cd2.Code = case when ST.Count > 0 then 2 else 1 end	--SR211450: MPC 27/02/2013
where	pt.Transtype = 39			-- Proposal
AND		(							-- No matching Issued Transaction found
			pt.IssuedTranID is null 		
OR 
		(pt.IssuedTranID is not null and pt.IssuedTranID not in (select distinct transactionid from mstt_Expectation))
		)
AND		convert(date,pt.createdatetime) > @DropDate		-- ignore transactions prior to Drop Date			AG 14/08/2018 (2)
AND		convert(date,pt.CreateDateTime) > @OffDate		-- ignore transactions after assumed Off period		AG 14/08/2018 (2)
AND		ag.agenttype in (2,46,49,3,4,5,43,45,51)		-- Businesses and Sellers only
AND		a2.agenttype in (2,46,49)						-- Businesses only



--- Insert Matched Payments not yet on Unpaid List into owoa_Pipeline Table
--- Exclude Payments created prior to @SuspenseDate   --SR211450: MPC 27/02/2013
--- PipeLineTypeDesc='Payment'; StatusDesc='Payment Agreed'

insert into AG_TEST_owoa_Pipeline
(PipelineType,PipelineTypeDesc,SellerCode,SellerName,BusinessCode,StatusCode,StatusDate,StatusDesc,
PropTranID,IssuedTranID,PolicyID,CaseID,PolicyNumber,PipelineStartDate,PipelineDays,ExpectationID,
UnpaidListID,PaidListID,CommType,WrittenDate,IssuedDate,ProviderCode,Basis,ClientID,ClientName,Amount,
BaseAmount,UpliftRate,SellerSplit,NBI,APE,PolicySuspend,PolicySuspendDate,SuspenseCount,SuspenseAmount,
ProductCode,ProdGroupCode,FirstReceipt)
select	DISTINCT
		2 as PipelineType,
		cd1.Description as PipelineTypeDesc,  --NULL,	--SR211450: MPC 27/02/2013
		co.agent_code as SellerCode,
		substring(	case 
						when charindex(' ', ag.firstnames) = 0 then ag.firstnames 
						else rtrim(substring(ag.firstnames, 1, charindex(' ', ag.firstnames))) 
					end + ' ' + ag.Name,1,50) as SellerName,
		co.Firm as BusinessCode,
		case when po.SuspendCommission = 1 
			then 4 
			else 3 
		end as StatusCode,
		ex.date_recv as StatusDate,
		cd2.Description as StatusDesc,  --NULL,	--SR211450: MPC 27/02/2013
		NULL as PropTranID,
		ex.transactionid as IssuedTranID,
		pt.policyid as PolicyID,
		po.policyref as CaseID,
		po.cont_num as PolicyNumber,
		ex.date_recv as PipelineStartDate,
		datediff(dd,ex.Date_Recv,@RunDate) as PipelineDays,
		ex.ID as ExpectationID,
		NULL as UnpaidListID,
		NULL as PaidListID,
		ex.Type as CommType,
		NULL as WrittenDate,
		pt.IssuedDate as IssuedDate,
		coalesce(pt.commcompanycode,po.comp_code) as ProviderCode,
		case pt.commtype 
			when 'F' then 'Accrual' 
			when 'L' then 'Level' 
			when 'T' then 'IT' 
		end as Basis,
		po.Client_Num as ClientID,
		case
			when cl.client_typ = 2 then substring(cl.name,1,50) -- PR 27/05/2010 For Corp Clients use Name as Firstname is always empty as causes the Name to be = Null
			else substring(	case 
								when charindex(' ', cl.firstnames) = 0 then cl.firstnames 
								else rtrim(substring(cl.firstnames, 1, charindex(' ', cl.firstnames))) 
							end + ' ' + cl.Name,1,50) 
		end as ClientName,
		--substring(case when charindex(' ', cl.firstnames) = 0 then cl.firstnames 
		--else rtrim(substring(cl.firstnames, 1, charindex(' ', cl.firstnames))) end + ' ' + cl.Name,1,50),

		round(									-- AG 11/11/2014 Rounding needed in case it is split trail or renewal
		case when ex.type in (2,15,16,17,18,19) 
			then -1 
			else 1 
		end *		--SR211450: MPC 27/02/2013
		case when co.DistributionAllowance is null				-- AG 11/11/2014
				then 1											-- AG 11/11/2014
			 when co.DistributionAllowance > 0 
				then co.FixedAmount/co.DistributionAllowance 
			 else 0 
		end *
		case when ex.Type in (10,16,19,4,15,18) -- AG 11/11/2014 Trail and renewals require split proportion.
			then co.agent_perc/100				-- AG 11/11/2014 Split proportion already on expectation for initial comm.
			else 1								-- AG 11/11/2014
		end *									-- AG 11/11/2014
		case when ex.amount_rec = 0 
			then abs(ex.amount_due) 
			else abs(ex.amount_rec) 		
		end,2) as Amount,						-- AG 11/11/2014 Rounding needed in case it is split trail or renewal
		
		round(									-- AG 11/11/2014 Rounding needed in case it is split trail or renewal
		case when ex.type in (2,15,16,17,18,19) 
				then -1 
				else 1 
		end *		--SR211450: MPC 27/02/2013
		case when co.DistributionAllowance is null				-- AG 11/11/2014
				then 1											-- AG 11/11/2014
			 when co.DistributionAllowance > 0 
				then co.FixedAmount/co.DistributionAllowance 
			 else 0 
		end *
--		case when co.FixedAmount > 0							-- AG 11/11/2014
		case when isnull(co.BaseAmount,0) > 0 and isnull(co.FixedAmount,0) > 0	-- AG 11/11/2014
			then co.BaseAmount/co.FixedAmount 
			else 1 
		end *
		case when ex.Type in (10,16,19,4,15,18) -- AG 11/11/2014 Trail and renewals require split proportion.
			then co.agent_perc/100				-- AG 11/11/2014 Split proportion already on expectation for initial comm.
			else 1								-- AG 11/11/2014
		end *									-- AG 11/11/2014
		case when ex.amount_rec = 0 
			then abs(ex.amount_due) 
			else abs(ex.amount_rec) 
		end,2) as BaseAmount,					-- AG 11/11/2014 Rounding needed in case it is split trail or renewal

		isnull(co.FranchiseUpliftPercent,100) as FranchiseUpliftPercent,	-- AG 11/11/2014. Default to 100
		-- co.agent_perc,										   AG 11/11/2014

		--AG 14/08/2018 Start
		case when ag.Manager2Code = @OwlManager2Code then		-- AG 08/12/2014
				case when AdviserSplit.AdviserSplitPerc >= 0.01
					then round(((co.Agent_Perc / AdviserSplit.AdviserSplitPerc) * 100.0) * 4.0, 0) / 4.0					--Rounds to nearest 0.25.
					else co.Agent_Perc
				end
		--AG 14/08/2018 End
			 when (co.Agent_Perc between 1 and 99) and ex.Type in (10,16,19,4,15,18) and ex.DATE_DUE >= @OpenworkMarginScriptDate then	-- AG 11/11/2014 
			   round(
			   isnull((co.Agent_Perc/(100-
				   isnull((select case when sum(Agent_Perc) = 100 then 0 else sum(Agent_Perc) end from mstt_Commissions 
							where (agent_code = @OpenworkMarginPotCode 
									or agent_code = @OpenworkBSCPotCode) 
							and TransactionID = ex.TransactionID
							and CommissionType = case									
													when ex.Type in (1,2,17) then 1
													when ex.Type in (4,15,18) then 4
													when ex.Type in (10,16,19) then 10
													else 99
												 end),0))),0) 
				* 100,2)
			else
				co.Agent_Perc
        end as Agent_Perc, 

		case	when ex.Type in  (10,16,19,4,15,18)		-- AG 11/11/2014. Trail and renewals do not generate NBI.
					then 0
				--when ex.Type in (2,15,16,17,18,19)	-- AG 11/11/2014
				when ex.Type in (2,17)					-- AG 11/11/2014. Negate initial cklawback and adjustment
					then -1 
				when ex.amount_rec = 0 and ex.amount_due < 0 
					then -1		--SR211450: MPC 27/02/2013
				when ex.amount_rec < 0 
					then -1 
				else 1 
		end * isnull(co.FixedAmount,0) as NBI,			-- AG 11/11/2014

		case	when ex.Type in  (10,16,19,4,15,18)		-- AG 11/11/2014. Trail and renewals do not generate NBI.
					then 0
				--when ex.Type in (2,15,16,17,18,19)	-- AG 11/11/2014
				when ex.Type in (2,17)					-- AG 11/11/2014. Negate initial cklawback and adjustment
					then -1 
				when ex.amount_rec = 0 and ex.amount_due < 0 
					then -1		--SR211450: MPC 27/02/2013
				when ex.amount_rec < 0 
					then -1 
				else 1 
		end * isnull(co.Turnover,0) as APE,				-- AG 11/11/2014

		po.SuspendCommission as PolicySuspend,
		po.SuspendCommissionLastUpdated as PolicySuspendDate,
		NULL as SuspenseCount,
		NULL as SuspenseAmount,
		coalesce(pt.commproductcode,po.productcode) as ProductCode,
		coalesce(pt.productgroupcode,po.productgroupcode) as ProdGroupCode,
		Case	when FM.TranId is not NULL 
					then 'Y' 
		end	as FirstReceipt		--NULL		--SR211450: MPC 27/02/2013
from	mstt_expectation ex
		inner join mstt_policytransactions pt on pt.id = ex.transactionid
		inner join mstt_policies po on po.pol_num = pt.policyid
		inner join mstt_clients cl on cl.client_num = po.client_num
		--AG 14/08/2018 Start
		inner join	(select TransactionID, MAX(Agent_Perc) As AdviserSplitPerc
 					 from	mstt_Commissions
					 where	CommissionType = 1
					 and	AGENT_CODE <> '10002'
					 group	by TransactionID
					) AdviserSplit on AdviserSplit.TransactionID = ex.transactionid		
		--AG 14/08/2018 End
		inner join mstt_commissions co 
					on co.transactionid = ex.transactionid 
					and co.commissiontype = case									-- AG 11/11/2014
												when ex.Type in (1,2,17) then 1
												when ex.Type in (4,15,18) then 4
												when ex.Type in (10,16,19) then 10
												else 99
											end
		inner join mstt_agents ag on ag.code = co.agent_code
		inner join sa_swift_S_STMTCT st on st.statement = ex.statement and st.deleted = 0	-- AG 17/05/2013 Exclude matched payments on deleted statements
		left outer join mstt_agents a2 on a2.code = co.firm
		left outer join mstt_PaymentsPending pp on pp.pacc_id = ex.id
		left join msit_MiWarehouseCodesandDescriptions cd1 on cd1.ColumnName = 'OA_Pipeline_TypeDesc' and cd1.Code = '2'	--SR211450: MPC 27/02/2013
		left join msit_MiWarehouseCodesandDescriptions cd2 on cd2.ColumnName = 'OA_Pipeline_StatusDesc' and cd2.Code = case when po.SuspendCommission = 1 then 4 else 3 end	--SR211450: MPC 27/02/2013
		left join ( select transactionid as TranID,min(ID) as FirstExpID			--SR211450: MPC 27/02/2013
					from mstt_expectation											--SR211450: MPC 27/02/2013
					where Type not in (5,6) and Status in (2,3)						--SR211450: MPC 27/02/2013
					group by transactionid) FM on FM.TranId = ex.transactionid and FM.FirstExpID = ex.ID	--SR211450: MPC 27/02/2013
where	ex.Type in (1,2,17,4,15,18,10,16,19)		-- ALL Payments --SR211450: MPC 27/02/2013
AND		ex.Status = 2								-- Matched (but not on Unpaid List)
AND		ex.Adjust in (0,1)							-- Exclude Adjustments (which never move forward)	--MPC: 18/04/2008		--SR218842: MPC 04/04/2013
AND		pp.ID is NULL								-- Not on Unpaid List
AND		ag.agenttype in (2,46,49,3,4,5,43,45,51)	-- Businesses and Sellers only
AND		a2.agenttype in (2,46,49)					-- Businesses only
AND		coalesce(convert(date,ex.CreateDate),ex.DATE_RECV) > @SuspenseDate		--SR211450: MPC 27/02/2013

--- Insert Pending Payments into owoa_Pipeline Table (only if Policy Suspended)		--SR211450: MPC 27/02/2013
--- Exclude Suspended Payments created earlier than the @SuspendPaymentDate
--- PipeLineTypeDesc='Payment'; StatusDesc='Payment Suspended'

UNION

select	DISTINCT
		2,
		cd1.Description,  --NULL,	--SR211450: MPC 27/02/2013
		cs.agentcode,
		substring(	case 
						when charindex(' ', ag.firstnames) = 0 
						then ag.firstnames 
						else rtrim(substring(ag.firstnames, 1, charindex(' ', ag.firstnames))) 
					end + ' ' + ag.Name,1,50),
		cs.BusinessCode,
		case 
			when cs.SuspendComm = 'Y' 
				then 4 
				else 5 
		end as StatusCode,
		cs.CreateDate,
		cd2.Description,  --NULL,	--SR211450: MPC 27/02/2013
		NULL,
		cs.TransactionId,
		cs.PolicyID,
		cs.CaseID,
		cs.ExtPolicyNumber,
		ex.Date_Recv,
		datediff(dd,ex.Date_Recv,@RunDate),
		cs.ExpectationID,
		cs.PendingPaymentID,
		cs.AgentPaymentsID,
		cs.CommissionType,
		NULL,
		ex.IncomeRecognitionDate,
		cs.ProviderCode,
		case cs.PayBasisCode 
			when 'F' then 'Accrual' 
			when 'L' then 'Level' 
			when 'T' then 'IT' 
		end as Basis,
		cs.ClientID,
		case
			when cl.client_typ = 2 then substring(cl.name,1,50) -- PR 27/05/2010 For Corp Clients use Name as Firstname is always empty as causes the Name to be = Null
			else substring(	case 
								when charindex(' ', cl.firstnames) = 0 then cl.firstnames 
								else rtrim(substring(cl.firstnames, 1, charindex(' ', cl.firstnames))) 
							end + ' ' + cl.Name,1,50) 
		end,
		--substring(case when charindex(' ', cl.firstnames) = 0 then cl.firstnames 
		--else rtrim(substring(cl.firstnames, 1, charindex(' ', cl.firstnames))) end + ' ' + cl.Name,1,50),
		cs.Amount,
		cs.BaseAmount,
		cs.FranchiseUpliftRate,
		--cs.AgentSplit,											  08/12/2014
		
		--AG 14/08/2018 Start	
		case 
		 when ag.Manager2Code = @OwlManager2Code then
				case when AdviserSplit.AdviserSplitPerc >= 0.01
					then round(((cs.AgentSplit / AdviserSplit.AdviserSplitPerc) * 100.0) * 4.0, 0) / 4.0					--Rounds to nearest 0.25.
					else cs.AgentSplit
				end
		--AG 14/08/2018 End	
		 when (cs.AgentSplit between 1 and 99) and cs.CommissionType in (10,16,19) and DueDate >= @OpenworkMarginScriptDate then		
		   isnull((cs.AgentSplit/(100-
		   isnull(CASE																									
					WHEN cs.Amount > 0 then																				
					(select sum(Agent_Perc) from mstt_PaymentsPending where (agent_code = @OpenworkMarginPotCode or agent_code = @OpenworkBSCPotCode) and	
					 pacc_ID=cs.expectationid and isnull(Agent_Perc,0) > 0 and Amount > 0)					
					WHEN cs.Amount < 0 then																				
					(select sum(Agent_Perc) from mstt_PaymentsPending where (agent_code = @OpenworkMarginPotCode or agent_code = @OpenworkBSCPotCode) and	
					 pacc_ID=cs.expectationid and isnull(Agent_Perc,0) > 0 and Amount < 0)					
					ELSE 0																								
					END ,0)	) ) * 100 , cs.AgentSplit)																	
		 else
		  cs.AgentSplit
		end,
		
		cs.INIssued,
		cs.APE,
		po.SuspendCommission,
		po.SuspendCommissionLastUpdated,
		NULL,
		NULL,
		po.productcode,
		po.productgroupcode,
		Case when FM.TranId is not NULL 
			then 'Y' 
		end	--NULL		--SR211450: MPC 27/02/2013
from	msit_CommissionStatement cs
		inner join mstt_Agents ag on ag.code = cs.agentcode
		left outer join mstt_policies po on po.pol_num = cs.policyid
		left outer join mstt_Clients cl on cl.client_num = cs.ClientID
		left outer join mstt_Expectation ex on ex.id = cs.expectationid
		left join msit_MiWarehouseCodesandDescriptions cd1 on cd1.ColumnName = 'OA_Pipeline_TypeDesc' and cd1.Code = '2'	--SR211450: MPC 27/02/2013
		left join msit_MiWarehouseCodesandDescriptions cd2 on cd2.ColumnName = 'OA_Pipeline_StatusDesc' and cd2.Code = case when po.SuspendCommission = 1 then 4 else 3 end	--SR211450: MPC 27/02/2013
		left join ( select transactionid as TranID,min(ID) as FirstExpID			--SR211450: MPC 27/02/2013
					from mstt_expectation											--SR211450: MPC 27/02/2013
					where Type not in (5,6) and Status in (2,3)						--SR211450: MPC 27/02/2013
					group by transactionid) FM on FM.TranId = ex.transactionid and FM.FirstExpID = ex.ID	--SR211450: MPC 27/02/2013
		--AG 14/08/2018 Start
		left join (select	PACC_ID, CONVERT(date,CreateDateTime) as PaymentMatchedDate, MAX(isnull(Agent_Perc,0)) as AdviserSplitPerc
					from	mstt_PaymentsPending
					where	agent_code <> '10002'
					group	by PACC_ID, CONVERT(date,CreateDateTime)
				 ) as AdviserSplit  on  AdviserSplit.PACC_ID = cs.ExpectationID 
									and AdviserSplit.PaymentMatchedDate = cs.CreateDate	-- PaymentDate included to handle backdated agent change (BAC) which does NOT create new expectation records
		--AG 14/08/2018 End
where	cs.reportingclasscode <> 4		-- Exclude Payments to Bank
AND		cs.BACSDate = '1 Jan 1901'	-- Date denotes Pending Payment
--AND cs.OAStatus = 'Valid'		-- Denotes Valid Business Owner Found		--MPC: SR9 - 07/05/2008
--AND cs.OAStatus in ('Suspended','Valid')	-- Denotes Valid Business Owner Found + Suspense PR: 16/03/2009
AND		cs.OAStatus in ('Suspended')		--SR211450: MPC 27/02/2013
AND		cs.CreateDate > @SuspendPaymentDate		--SR211450: MPC 27/02/2013
--AND (ex.Type is null 			-- Standing Order or Manual Payments			--SR211450: MPC 27/02/2013
--or ex.Type in (1,2,17))			-- IC, IC Clawback and IC Adjustments only	--SR211450: MPC 27/02/2013


drop table #SuspenseTotals		--SR211450: MPC 27/02/2013

GO
/****** Object:  StoredProcedure [dbo].[owoa_pipelineList]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************************
Author:			Mark Cameron's DEV Team
Date:			07/12/2007
Description:	This stored proc is used for selecting all the Pipeline Proposals and payments for display
				by the web browser. It displays the first Pipeline screen (not when "Details" is pressed).
				
Amendment History
=================
Date		Author		Description
----		------		-----------
16/03/2009	P Robathan	Cater for structured products
05/11/2014	A Groves	Removed the exclusion of GI products. The only GI product going through Swift at the
						current time is the Owl product "A&H OWL" which needs to be displayed on the Pipeline.
12/03/2015	A Groves	SR368073. Display ProviderName instead of ProviderCode. This is required for the 
						re-branding of PruProtect to Vitality Life where the ProviderCode has not changed.
						This is also consistent with the Commission Listing.
***********************************************************************************************************/
CREATE      procedure [dbo].[owoa_pipelineList]
@Franchise  varchar(7)
,@clientName  varchar(60)
,@provider  varchar(60)
,@seller        varchar(60)
,@status        varchar(60)
,@incNPW  char(5) = 'N'
,@productGroup  char(2) = '0'
as
BEGIN


set nocount on


declare @sellerCode varChar(10)


-- sort out the sellers
if @seller <> '%' begin
  -- get the code of the seller were looking for
  select @sellerCode = sellerCode
  from owoa_sellerXref  
  where sellerName = @seller
    and franchise = @Franchise
end
else begin
  select @sellerCode = '%'
end


if @incNPW = 'TRUE' begin
  -- AG 12/03/2015 Start
  --  select p.*
  select  
  p.PipelineID,
  p.PipelineType,
  p.PipelineTypeDesc,
  p.SellerCode,
  p.SellerName,
  p.BusinessCode,
  p.StatusCode,
  p.StatusDate,
  p.StatusDesc,
  p.PropTranID,
  p.IssuedTranID,
  p.PolicyID,
  p.CaseID,
  p.PolicyNumber,
  p.PipelineStartDate,
  p.PipelineDays,
  p.ExpectationID,
  p.UnpaidListID,
  p.PaidListID,
  p.CommType,
  p.WrittenDate,
  p.IssuedDate,
  --p.ProviderCode,
  isnull(pp.ProductProviderName,'N/A') as ProviderCode,
  p.Basis,
  p.ClientID,
  p.ClientName,
  p.Amount,
  p.BaseAmount,
  p.UpliftRate,
  p.SellerSplit,
  p.NBI,
  p.APE,
  p.PolicySuspend,
  p.PolicySuspendDate,
  p.SuspenseCount,
  p.SuspenseAmount,
  p.ProductCode,
  p.ProdGroupCode,
  p.FirstReceipt
  -- AG 12/03/2015 End
  ,case when structuredproduct = 'Y' then ' Structured' else COALESCE(productgroupname,'Unknown') end as productGrp
  ,case   when npw.PropTranID is NULL then 'off'
    else 'on'
  end as NPW
  from owoa_pipeline p
  left outer join head_office_systems.dbo.owoa_pipelineNPW npw on p.proptranid = npw.proptranid
  left outer join mstt_producthierarchy cpg on p.ProductCode = cpg.productcode
  left outer join mstt_ProductProviders pp on pp.ProductProviderCode = p.ProviderCode	-- AG 12/03/2015 
  where   businessCode =  @Franchise
    and   (sellerCode = @sellerCode or @sellerCode = '%')
    and   clientName like '%' + @clientName + '%'
    and   (providerCode = @provider or @provider = '%')
    and (statusDesc = @status or @status = '%')
    and ( cpg.productgroupcode = @productGroup and cpg.StructuredProduct <> 'Y'
      or (@productGroup = '8' and cpg.StructuredProduct = 'Y')
    or  (@productGroup = '-1' and cpg.productgroupcode is null)
    or  @productGroup = '0'
    )
          --and cpg.productgroupcode <> 1 -- exclude GI!	AG 05/11/2014
  ;
end
else begin
  -- AG 12/03/2015 Start
  --  select p.*
  select  
  p.PipelineID,
  p.PipelineType,
  p.PipelineTypeDesc,
  p.SellerCode,
  p.SellerName,
  p.BusinessCode,
  p.StatusCode,
  p.StatusDate,
  p.StatusDesc,
  p.PropTranID,
  p.IssuedTranID,
  p.PolicyID,
  p.CaseID,
  p.PolicyNumber,
  p.PipelineStartDate,
  p.PipelineDays,
  p.ExpectationID,
  p.UnpaidListID,
  p.PaidListID,
  p.CommType,
  p.WrittenDate,
  p.IssuedDate,
  --p.ProviderCode,
  isnull(pp.ProductProviderName,'N/A') as ProviderCode,
  p.Basis,
  p.ClientID,
  p.ClientName,
  p.Amount,
  p.BaseAmount,
  p.UpliftRate,
  p.SellerSplit,
  p.NBI,
  p.APE,
  p.PolicySuspend,
  p.PolicySuspendDate,
  p.SuspenseCount,
  p.SuspenseAmount,
  p.ProductCode,
  p.ProdGroupCode,
  p.FirstReceipt
  -- AG 12/03/2015 End
  ,case when structuredproduct = 'Y' then 'Structured' else COALESCE(productgroupname,'Unknown') end as productGrp
  ,'off' as NPW
  from owoa_pipeline p
  left outer join head_office_systems.dbo.owoa_pipelineNPW npw on p.proptranid = npw.proptranid
  left outer join mstt_producthierarchy cpg on p.ProductCode = cpg.productcode
  left outer join mstt_ProductProviders pp on pp.ProductProviderCode = p.ProviderCode	-- AG 12/03/2015 
  where   businessCode =  @Franchise
    and   (sellerCode = @sellerCode or @sellerCode = '%')
    and   clientName like '%' + @clientName + '%'
    and   (providerCode = @provider or @provider = '%')
    and (statusDesc = @status or @status = '%')
          and   npw.proptranID is null
    and ( cpg.productgroupcode = @productGroup and cpg.StructuredProduct <> 'Y'
      or (@productGroup = '8' and cpg.StructuredProduct = 'Y')
    or  (@productGroup = '-1' and cpg.productgroupcode is null)
    or  @productGroup = '0'
    )
          --and cpg.productgroupcode <> 1 -- exclude GI!	AG 05/11/2014
  ;

end

END




GO
/****** Object:  StoredProcedure [dbo].[owoa_pipelineNPWman]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[owoa_pipelineNPWman]
	@key [varchar](10),
	@userID	[varchar](50), --changed from [varchar](10), SR109539 refers
	@action [varchar](3) = 'off',
	@Franchise [varchar](10)
WITH EXECUTE AS CALLER
AS
BEGIN
set nocount on

-- check the key sent in is for our franchise
select @franchise = businessCode 
  from owoa_pipeline
 where businessCode =  @Franchise
   and proptranid = @key

if @@rowcount =0 begin
  raiserror('Proposition not at franchise %s / %s',16,1,@key,@Franchise)
  return
end

delete from Head_Office_Systems.dbo.owoa_pipelineNPW
 where proptranid = @key

if @action='on' begin
  insert into Head_Office_Systems.dbo.owoa_pipelineNPW
    (propTranID
    ,userid
    )
  values
    (@key
    ,@userID
    )

END

END




GRANT  EXECUTE  ON [dbo].[owoa_pipelineNPWman]  TO [oaSQLUser]

