/****** Object:  StoredProcedure [dbo].[owoa_populateZurichListingsPortal]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

/****************************************************************************
     Program:   owoa_populateZurichListingsPortal 
    Author: S Walker
Date created: 25/11/2009              
                      
 Description: This program makes the Zurich Listing data available to the portal
        .NET screens.  It should be run in the nightly batch while OpenAccess
        is disabled to users.

        This proc would be called as follows:

          exec owoa_populateZurichListingsPortal
  
  Amendment History               
  -----------------               
                      
  Date    Who     Description       
  ----    ---     -----------     
  22/12/09  A Groves  Amendment to ensure only the latest two of the three
              data sources are made available to the OpenAccess screens.
***************************************************************************/ 
CREATE PROCEDURE [dbo].[owoa_populateZurichListingsPortal]
  -- Add the parameters for the stored procedure here
    
AS
BEGIN

declare @DateToBeKeptFrom datetime


-- Find the second from latest (penultimate) load date

select @DateToBeKeptFrom = min(DerivedTable.created)
from
(
select top 2 dateadd(dd,0,datediff(dd,0,created)) as created
from owoa_openworkunderpaid
group by dateadd(dd,0,datediff(dd,0,created))
order by created desc
) DerivedTable

-- Transfer data from the two most recent dates

truncate table owoa_OpenworkUnderpaidPortal

INSERT INTO owoa_OpenworkUnderpaidPortal
( 
  [Advisor code], 
  Title, 
  Forename, 
  Surname, 
  [Policy No], 
  [Premium Amount], 
  [Premium Freq], 
  [Date Last Paid], 
  [Amount underpaid], 
  [No of months underpaid], 
  Reason,
  [Business Quality Manager ID],
  [Area Director id],
  [Swift Business id],
  [Business Name],
  [Swift Adviser id],
  [Adviser Name], 
  created
) 
SELECT  [Advisor code], 
    Title, 
    Forename, 
    Surname, 
    [Policy No], 
    [Premium Amount], 
    [Premium Freq], 
    [Date Last Paid], 
    [Amount underpaid], 
    [No of months underpaid], 
    Reason,
    [Business Quality Manager ID],
    [Area Director id],
    [Swift Business id],
    [Business Name],
    [Swift Adviser id],
    [Adviser Name], 
    created 
FROM  owoa_OpenworkUnderpaid 
where dateadd(dd,0,datediff(dd,0,created)) >= @DateToBeKeptFrom


/***************************************************************************/ 


-- Find the second from latest (penultimate) load date


select @DateToBeKeptFrom = min(DerivedTable.created)
from
(
select top 2 dateadd(dd,0,datediff(dd,0,created)) as created
from owoa_OpenworkZurichNPW
group by dateadd(dd,0,datediff(dd,0,created))
order by created desc
) DerivedTable

truncate table owoa_OpenworkZurichNPWPortal

INSERT INTO owoa_OpenworkZurichNPWPortal
( 
  [Advisor code], 
  Title, 
  Forename, 
  Surname, 
  [Policy No], 
  [Premium Amount],
  [Premiun Freq],
  [Business Quality Manager ID],
  [Area Director id],
  [Swift Business id],
  [Business Name],
  [Swift Adviser id],
  [Adviser Name], 
  [Npw Reason], 
  created
) 
SELECT  [Advisor code], 
    Title, 
    Forename, 
    Surname, 
    [Policy No], 
    [Premium Amount],
    [Premiun Freq],
    [Business Quality Manager ID],
    [Area Director id],
    [Swift Business id],
    [Business Name],
    [Swift Adviser id],
    [Adviser Name], 
    [Npw Reason], 
    created 
FROM  owoa_OpenworkZurichNPW
where dateadd(dd,0,datediff(dd,0,created)) >= @DateToBeKeptFrom


/***************************************************************************/ 


-- Find the second from latest (penultimate) load date


select @DateToBeKeptFrom = min(DerivedTable.created)
from
(
select top 2 dateadd(dd,0,datediff(dd,0,created)) as created
from owoa_OpenworkZurichLapsed
group by dateadd(dd,0,datediff(dd,0,created))
order by created desc
) DerivedTable

truncate table owoa_OpenworkZurichLapsedPortal

INSERT INTO owoa_OpenworkZurichLapsedPortal 
( 
  [Advisor code], 
  Title, 
  Forename, 
  Surname, 
  [Policy No], 
  [Premium Amount],
  [Premiun Freq], 
  [Date Last Paid], 
  [Effective Date of Lapse], 
  [Payment Status],
  [Business Quality Manager ID],
  [Area Director id],
  [Swift Business id],
  [Business Name],
  [Swift Adviser id],
  [Adviser Name], 
  created, 
  [DD Cancelled Date]
) 
SELECT  [Advisor code], 
    Title, 
    Forename, 
    Surname, 
    [Policy No], 
    [Premium Amount],
    [Premiun Freq], 
    [Date Last Paid], 
    [Effective Date of Lapse], 
    [Payment Status],
    [Business Quality Manager ID],
    [Area Director id],
    [Swift Business id],
    [Business Name],
    [Swift Adviser id],
    [Adviser Name], 
    created, 
    [DD Cancelled Date] 
FROM  owoa_OpenworkZurichLapsed
where dateadd(dd,0,datediff(dd,0,created)) >= @DateToBeKeptFrom


END




