/****** Object:  StoredProcedure [dbo].[owoa_quarterly]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE  PROCEDURE [dbo].[owoa_quarterly]

@OpenworkInd   nvarchar(5) = NULL,
@FranchiseCode nvarchar(15) = NULL,
@Period smalldatetime,
@Adviser nvarchar(15)
AS
--########################################################################
--
-- Object  : procedure
-- Name    : owoa_quarterly
-- Owner   : ???
-- Created : ???????
-- Amended : PR 27/08/2009 Amend Index hint to use SQL 2005 method
--########################################################################

IF @Adviser = 'All'
BEGIN
SELECT @Adviser = NULL
END

SELECT      msit_FeesNonSWIFTRenewalListing.SellerName AS Seller,
      msit_FeesNonSWIFTRenewalListing.Client AS Client,
      msit_FeesNonSWIFTRenewalListing.Policy AS Policy,
      msit_FeesNonSWIFTRenewalListing.StartDate AS StartDate,
      msit_FeesNonSWIFTRenewalListing.Frequency AS Frequency,
      msit_FeesNonSWIFTRenewalListing.Premium AS Premium,
      msit_FeesNonSWIFTRenewalListing.CommRateStd AS RFRate,
      (msit_FeesNonSWIFTRenewalListing.Value1*ISNULL(dbo.msit_AgentInfo.RC_RIGHTS_M1,1)) AS AccruedMth1,
      (msit_FeesNonSWIFTRenewalListing.Value2*ISNULL(dbo.msit_AgentInfo.RC_RIGHTS_M2,1)) AS AccruedMth2,
      (msit_FeesNonSWIFTRenewalListing.Value3*ISNULL(dbo.msit_AgentInfo.RC_RIGHTS_M3,1)) AS AccruedMth3,
      msit_FeesNonSWIFTRenewalListing.Month AS [Month],
      msit_FeesNonSWIFTRenewalListing.RemarksString AS Remarks,
      CASE WHEN dbo.msit_AgentInfo.RC_RIGHTS_M1 = 2 THEN 'Double' ELSE 'Single' END AS RFRateMth1,
      CASE WHEN dbo.msit_AgentInfo.RC_RIGHTS_M2 = 2 THEN 'Double' ELSE 'Single' END AS RFRateMth2,
      CASE WHEN dbo.msit_AgentInfo.RC_RIGHTS_M3 = 2 THEN 'Double' ELSE 'Single' END AS RFRateMth3,
      CASE WHEN dbo.msit_AgentInfo.RC_RIGHTS_M1 = 2 THEN 2 ELSE 1 END AS RFRateMth1Value,
      CASE WHEN dbo.msit_AgentInfo.RC_RIGHTS_M2 = 2 THEN 2 ELSE 1 END AS RFRateMth2Value,
      CASE WHEN dbo.msit_AgentInfo.RC_RIGHTS_M3 = 2 THEN 2 ELSE 1 END AS RFRateMth3Value

--FROM         dbo.msit_FeesNonSWIFTRenewalListing (index=IX_msit_FeesNonSwiftRenewalListing_SwiftFranchise)  
FROM         dbo.msit_FeesNonSWIFTRenewalListing with (index(IX_msit_FeesNonSwiftRenewalListing_SwiftFranchise))  -- PR 27 Aug 2009 - use SQL 2005 method for index hint
        LEFT OUTER JOIN dbo.msit_AgentInfo 
                       ON dbo.msit_AgentInfo.MAIN_SERIAL = dbo.msit_FeesNonSWIFTRenewalListing.FranchiseSerial  
WHERE
--   (msit_FeesNonSWIFTRenewalListing.SWIFTFranchise = ISNULL(@FranchiseCode, SWIFTFranchise)) AND (ISNULL(@OpenworkInd,'N') = ISNULL(OpenworkInd,'N'))
   (msit_FeesNonSWIFTRenewalListing.SWIFTFranchise = @FranchiseCode) AND (ISNULL(@OpenworkInd,'N') = ISNULL(OpenworkInd,'N'))
  AND msit_FeesNonSWIFTRenewalListing.[Month] = @Period   AND SellerID = ISNULL(@Adviser,SellerID)
order by seller
  ,client
  ,policy
  ,startdate





GO
/****** Object:  StoredProcedure [dbo].[owoa_reportAPE]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[owoa_reportAPE]
@Franchise	varchar(7)
,@sMonth	datetime
,@eMonth	datetime
,@seller        varchar(60)
,@eReportType   varchar(2) 

as
BEGIN

/*************************************************************************
 
 Object  : procedure

 Name    : dbo.owoa_reportAPE.sql

The complete @eReportType range is shown below but only 3,4,5,9,10,11 are passed into this proc:
-----------------------------------------------------------------------------------------------
0	Enterprise Written Commission
1	Enterprise Paid Commission
2	Enterprise NBI Totals
3	Enterprise APE Totals
4	Enterprise VNB Totals
5	Enterprise Elite Totals
6	Financial Adviser Written Commission
7	Financial Adviser Paid Commission
8	Financial Adviser NBI Totals
9	Financial Adviser APE Totals
10	Financial Adviser VNB Totals
11	Financial Adviser Elite Totals
--------------------------------------------------------------------------- 

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
16/03/2009	PR			Cater for Structured Products
22/11/2010	VH			Allow for Seller UID to be passed in
24/04/2013	M Cawood	SR207107. Add Elite_Points derivations as this 
						will now be displayed in place of ABC. 
10/05/2018	A Groves	1) Enterprise and adviser VNB reports added in 
							(@eReportType 4 and 10).
						2) Code refactored to use a case statement for
							APE, Elite and VNB rather than having separate
							SQL statements for each.
							
*************************************************************************/

set nocount on

create table #ReportPeriods(
	RptMonth	datetime,
	MonthName	varchar(20),
	PeriodStartDate	datetime,
	PeriodEndDate	datetime,
	OscarStartDate	datetime,
	OscarEndDate	datetime
	)

create table #ReportValues(
	RptMonth	datetime,
	ValueType	varchar(10),
	Value		float)

create table #Products(
	productcode			varchar(20) collate Latin1_General_CI_AS,
	productgroupname	varchar(30)
	)
insert #Products(
	productcode,
	productgroupname)
select	productcode,
		case 
			when structuredproduct = 'Y' then 'Structured' 
			else productgroupname
		end
from mstt_producthierarchy

create table #sellers(
	sellerName varchar(60) collate Latin1_General_CI_AS
)

declare @sellerCode varChar(10)

-- sort out the sellers
if @seller <> '%' begin

	-- vh amend 22/11/2010
	if ISNUMERIC(@seller) = 1 AND LEN(@seller) = 7
		-- get the code of the seller were looking for
		set @sellerCode = @seller
	else
		-- get the code of the seller were looking for
		select @sellerCode = sellerCode
		from owoa_sellerXref	
		where sellerName = @seller
		  and franchise = @Franchise

	-- check if we got a code back
	if @sellerCode in ('NC','',NULL) begin
		-- if not then just put the seller name we received in the file
		insert into #sellers (sellerName )
		values( @seller);
	end
	else begin
		-- if we did then put all then names associated with that code in the file
		insert into #sellers (sellerName )
		select sellerName 
		  from owoa_sellerXref
		 where sellerCode = @sellerCode
		   and franchise = @Franchise
	end
end



-- sort out the reporting periods
insert #ReportPeriods
(
	RptMonth,
	MonthName,
	PeriodStartDate,
	PeriodEndDate,
	OscarStartDate,
	OscarEndDate
)
select	[Month],
		MonthName,
		PeriodStartDate,
		PeriodEndDate,
		OscarStartDate,
		OscarEndDate
from	msit_Commissionstatementperiods csp
where	(csp.month >= @sMonth and csp.month <= @eMonth) 
		or 
		csp.month >= dateAdd(yyyy,-1,getdate())


--- Get ABC Value (superseded)		--SR207107:MPC 24/04/2013
--	Get Elite Points value			--SR207107:MPC 24/04/2013
--	Refactored for VNB points		--AG 10/05/2018

-- 2006
insert #ReportValues
(
	RptMonth,
	ValueType,
	Value
)
select	csp.RptMonth,
		isNull(ph.productgroupname,'Other'),
		sum(case 
				when @eReportType in ('3','9') then oal.APE
				when @eReportType in ('4','10') then oal.VNB_Points
				when @eReportType in ('5','11') then oal.Elite_Points
				else 0.0
			end) 
from 	msit_openworkAdviserListing oal
		inner join #ReportPeriods csp on csp.RptMonth = oal.month
		left outer join msit_commissionStatement cs on cs.businesscode = @Franchise and cs.ID = oal.sourceID
		left outer join #Products ph on ph.productcode = cs.productcode
where 	oal.businessCode =  @Franchise
  and   oal.source='Openwork 2006'
  and   (oal.sellerName in (select sellerName from #sellers)  or @seller = '%')
group	by csp.RptMonth,ph.productgroupname

-- 2005
insert #ReportValues
(
	RptMonth,
	ValueType,
	Value
)
select 	csp.RptMonth,
		case 
			when oal.provider='General Insurance' then 'GI' 
			when oal.provider='SIML' then 'Investment'
			when oal.provider='Sterling' then 'Investment'
			when oal.provider='Scottish Equitable' then 'Pensions'
			else isNull(ph.productgroupname,'Other') 
		end,		
		sum(case 
				when @eReportType in ('3','9') then oal.APE
				when @eReportType in ('4','10') then oal.VNB_Points
				when @eReportType in ('5','11') then oal.Elite_Points
				else 0.0
			end) 
from 	msit_openworkAdviserListing oal
		inner join #ReportPeriods csp on csp.RptMonth = oal.month
		left outer join msit_feesNonSwiftFeeListing fnsfl on fnsfl.ID = oal.sourceID
		left outer join #Products ph on 'NBI_'+fnsfl.productCode = ph.productCode
where 	oal.businessCode =  @Franchise
  and   oal.source='Openwork 2005'
  and   (oal.sellerName in (select sellerName from #sellers)  or @seller = '%')
group	by csp.RptMonth,ph.productgroupname,oal.provider

-- Paymentshield
insert #ReportValues
(
	RptMonth,
	ValueType,
	Value
)
select 	csp.RptMonth,
		'GI',
		sum(case 
				when @eReportType in ('3','9') then oal.APE
				when @eReportType in ('4','10') then oal.VNB_Points
				when @eReportType in ('5','11') then oal.Elite_Points
				else 0.0
			end) 
from 	msit_openworkAdviserListing oal
		inner join #ReportPeriods csp on csp.RptMonth = oal.month
--		left outer join msit_commissionStatement cs on cs.businesscode = @Franchise and cs.ID = oal.sourceID
--		left outer join mstt_producthierarchy ph on ph.productcode = cs.productcode
where 	oal.businessCode =  @Franchise
  and   oal.source='Payshield'
  and   (oal.sellerName in (select sellerName from #sellers)  or @seller = '%')
group	by csp.RptMonth--,ph.productgroupname

-- OMS
insert #ReportValues
(
	RptMonth,
	ValueType,
	Value
)
select 	csp.RptMonth,
		isNull(ph.productgroupname,'Other'),
		sum(case 
				when @eReportType in ('3','9') then oal.APE
				when @eReportType in ('4','10') then oal.VNB_Points
				when @eReportType in ('5','11') then oal.Elite_Points
				else 0.0
			end) 
from 	msit_openworkAdviserListing oal
		inner join #ReportPeriods csp on csp.RptMonth = oal.month
		left outer join omst_OMSCommissionpayments cs on cs.businesscode = @Franchise and cs.ID = oal.sourceID
		left outer join #Products ph on ph.productcode = cs.HierarchyProduct
where 	oal.businessCode =  @Franchise
  and   oal.source='OMS'
  and   (oal.sellerName in (select sellerName from #sellers)  or @seller = '%')
group	by csp.RptMonth,ph.productgroupname


-- output monthly

select	MonthName,
		convert(decimal(10,2),coalesce(sum(case when ValueType='Protection' then Value else 0 end),0)) Protection,
		convert(decimal(10,2),coalesce(sum(case when ValueType='Investment' then Value else 0 end),0)) Investments,
		convert(decimal(10,2),coalesce(sum(case when ValueType='Pensions' then Value else 0 end),0)) Pensions,
		convert(decimal(10,2),coalesce(sum(case when ValueType='Mortgage' then Value else 0 end),0)) Mortgages,
		convert(decimal(10,2),coalesce(sum(case when ValueType='GI' then Value else 0 end),0)) GI,
		convert(decimal(10,2),coalesce(sum(case when ValueType='Structured' then Value else 0 end),0)) Structured,
		convert(decimal(10,2),coalesce(sum(case when ValueType not in ('Protection','Investment','Pensions','Mortgage','GI','Structured') then Value else 0 end),0)) Other,
		convert(decimal(10,2),coalesce(sum(Value),0)) Total
from	#ReportValues
		full outer join #ReportPeriods on #ReportValues.RptMonth = #ReportPeriods.RptMonth
where   #ReportPeriods.RptMonth >= @sMonth
and		#ReportPeriods.RptMonth <= @eMonth
group	by #ReportPeriods.RptMonth, #ReportPeriods.MonthName
order	by #ReportPeriods.RptMonth

-- get the YTD
select	convert(decimal(10,2),coalesce(sum(case when ValueType='Protection' then Value else 0 end),0)) Protection,
		convert(decimal(10,2),coalesce(sum(case when ValueType='Investment' then Value else 0 end),0)) Investments,
		convert(decimal(10,2),coalesce(sum(case when ValueType='Pensions' then Value else 0 end),0)) Pensions,
		convert(decimal(10,2),coalesce(sum(case when ValueType='Mortgage' then Value else 0 end),0)) Mortgages,
		convert(decimal(10,2),coalesce(sum(case when ValueType='GI' then Value else 0 end),0)) GI,
		convert(decimal(10,2),coalesce(sum(case when ValueType='Structured' then Value else 0 end),0)) Structured,
		convert(decimal(10,2),coalesce(sum(case when ValueType not in ('Protection','Investment','Pensions','Mortgage','GI','Structured') then Value else 0 end),0)) Other,
		convert(decimal(10,2),coalesce(sum(Value),0)) Total
from	#ReportValues
		left join #ReportPeriods on #ReportValues.RptMonth = #ReportPeriods.RptMonth
where	right(monthName,4) = datename(YYYY,getdate())

-- get the rolling 12 month
declare @curmonth datetime

select	@curmonth = max([Month])
from	msit_Commissionstatementperiods csp
where	csp.PeriodendDate <= getdate()

select	convert(decimal(10,2),coalesce(sum(case when ValueType='Protection' then Value else 0 end),0)) Protection,
		convert(decimal(10,2),coalesce(sum(case when ValueType='Investment' then Value else 0 end),0)) Investments,
		convert(decimal(10,2),coalesce(sum(case when ValueType='Pensions' then Value else 0 end),0)) Pensions,
		convert(decimal(10,2),coalesce(sum(case when ValueType='Mortgage' then Value else 0 end),0)) Mortgages,
		convert(decimal(10,2),coalesce(sum(case when ValueType='GI' then Value else 0 end),0)) GI,
		convert(decimal(10,2),coalesce(sum(case when ValueType='Structured' then Value else 0 end),0)) Structured,
		convert(decimal(10,2),coalesce(sum(case when ValueType not in ('Protection','Investment','Pensions','Mortgage','GI','Structured') then Value else 0 end),0)) Other,
		convert(decimal(10,2),coalesce(sum(Value),0)) Total
from	#ReportValues
		left join #ReportPeriods on #ReportValues.RptMonth = #ReportPeriods.RptMonth
--where #ReportPeriods.RptMonth >= dateAdd(yyyy,-1,getdate())
where	#ReportPeriods.RptMonth >= dateAdd(yyyy,-1,@curmonth)
and		#ReportPeriods.periodEnddate < getdate()


-- get the page totals
select	convert(decimal(10,2),coalesce(sum(case when ValueType='Protection' then Value else 0 end),0)) Protection,
		convert(decimal(10,2),coalesce(sum(case when ValueType='Investment' then Value else 0 end),0)) Investments,
		convert(decimal(10,2),coalesce(sum(case when ValueType='Pensions' then Value else 0 end),0)) Pensions,
		convert(decimal(10,2),coalesce(sum(case when ValueType='Mortgage' then Value else 0 end),0)) Mortgages,
		convert(decimal(10,2),coalesce(sum(case when ValueType='GI' then Value else 0 end),0)) GI,
		convert(decimal(10,2),coalesce(sum(case when ValueType='Structured' then Value else 0 end),0)) Structured,
		convert(decimal(10,2),coalesce(sum(case when ValueType not in ('Protection','Investment','Pensions','Mortgage','GI','Structured') then Value else 0 end),0)) Other,
		convert(decimal(10,2),coalesce(sum(Value),0)) Total
from	#ReportValues
		left join #ReportPeriods on #ReportValues.RptMonth = #ReportPeriods.RptMonth
where   #ReportPeriods.RptMonth >= @sMonth
and		#ReportPeriods.RptMonth <= @eMonth


drop table #ReportValues
drop table #ReportPeriods
drop table #sellers
drop table #Products

END
GO
/****** Object:  StoredProcedure [dbo].[owoa_reportAPE_Backup20180727AG]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[owoa_reportAPE_Backup20180727AG]
@Franchise	varchar(7)
,@sMonth	datetime
,@eMonth	datetime
,@seller        varchar(60)
,@eReportType   varchar(2) 

as
BEGIN

/*************************************************************************
 
 Object  : procedure

 Name    : dbo.owoa_reportAPE.sql

---------------------------------------------------------------------------

 Amended PR - 16 Mar 2009 - Cater for Structured Products
 Amended VH - 22 Nov 2010 - Allow for Seller UID to be passed in

 Mike Cawood - 24 April 2013 - SR207107
 Add Elite_Points derivations as this will now be displayed in place of ABC. 

*************************************************************************/

set nocount on

create table #ReportPeriods(
	RptMonth	datetime,
	MonthName	varchar(20),
	PeriodStartDate	datetime,
	PeriodEndDate	datetime,
	OscarStartDate	datetime,
	OscarEndDate	datetime
	)

create table #ReportValues(
	RptMonth	datetime,
	ValueType	varchar(10),
	Value		float)

create table #Products(
	productcode			varchar(20) collate Latin1_General_CI_AS,
	productgroupname	varchar(30)
	)
insert #Products(
	productcode,
	productgroupname)
select	productcode,
		case 
			when structuredproduct = 'Y' then 'Structured' 
			else productgroupname
		end
from mstt_producthierarchy

create table #sellers(
	sellerName varchar(60) collate Latin1_General_CI_AS
)

declare @sellerCode varChar(10)

-- sort out the sellers
if @seller <> '%' begin

	-- vh amend 22/11/2010
	if ISNUMERIC(@seller) = 1 AND LEN(@seller) = 7
		-- get the code of the seller were looking for
		set @sellerCode = @seller
	else
		-- get the code of the seller were looking for
		select @sellerCode = sellerCode
		from owoa_sellerXref	
		where sellerName = @seller
		  and franchise = @Franchise

	-- check if we got a code back
	if @sellerCode in ('NC','',NULL) begin
		-- if not then just put the seller name we received in the file
		insert into #sellers (sellerName )
		values( @seller);
	end
	else begin
		-- if we did then put all then names associated with that code in the file
		insert into #sellers (sellerName )
		select sellerName 
		  from owoa_sellerXref
		 where sellerCode = @sellerCode
		   and franchise = @Franchise
	end
end



-- sort out the reporitng periods
insert #ReportPeriods(
	RptMonth,
	MonthName,
	PeriodStartDate,
	PeriodEndDate,
	OscarStartDate,
	OscarEndDate)
select	[Month],
	MonthName,
	PeriodStartDate,
	PeriodEndDate,
	OscarStartDate,
	OscarEndDate
from	msit_Commissionstatementperiods csp
where	(csp.month >= @sMonth
	and csp.month <= @eMonth
	) or 
	csp.month >= dateAdd(yyyy,-1,getdate())


--- Get ABC Value (superseded)		--SR207107:MPC 24/04/2013
--	Get Elite Points value			--SR207107:MPC 24/04/2013
-- 2006
if @eReportType = 4 or @eReportType = 9 begin

insert	#ReportValues(
	RptMonth,
	ValueType,
	Value
	)
select 	csp.RptMonth,
	isNull(ph.productgroupname,'Other'),
	--sum(oal.ABCValue)			--SR207107:MPC 24/04/2013
	sum(oal.Elite_Points)		--SR207107:MPC 24/04/2013
from 	msit_openworkAdviserListing oal
	inner join #ReportPeriods csp on csp.RptMonth = oal.month
	left outer join msit_commissionStatement cs on cs.businesscode = @Franchise and cs.ID = oal.sourceID
	left outer join #Products ph on ph.productcode = cs.productcode
where 	oal.businessCode =  @Franchise
  and   oal.source='Openwork 2006'
  and   (oal.sellerName in (select sellerName from #sellers)  or @seller = '%')
group by csp.RptMonth,ph.productgroupname

-- 2005
insert	#ReportValues(
	RptMonth,
	ValueType,
	Value
	)
select 	csp.RptMonth,
	case 
		when oal.provider='General Insurance' then 'GI' 
		when oal.provider='SIML' then 'Investment'
		when oal.provider='Sterling' then 'Investment'
		when oal.provider='Scottish Equitable' then 'Pensions'
		else isNull(ph.productgroupname,'Other') 
	end,		--sum(oal.ABCValue)			--SR207107:MPC 24/04/2013
	sum(oal.Elite_Points)		--SR207107:MPC 24/04/2013
from 	msit_openworkAdviserListing oal
	inner join #ReportPeriods csp on csp.RptMonth = oal.month
	left outer join msit_feesNonSwiftFeeListing fnsfl on fnsfl.ID = oal.sourceID
	left outer join #Products ph on 'NBI_'+fnsfl.productCode = ph.productCode
where 	oal.businessCode =  @Franchise
  and   oal.source='Openwork 2005'
  and   (oal.sellerName in (select sellerName from #sellers)  or @seller = '%')
group by csp.RptMonth,ph.productgroupname,oal.provider

-- paymentshield
insert	#ReportValues(
	RptMonth,
	ValueType,
	Value
	)
select 	csp.RptMonth,
	--csp.month,
	'GI',
	--sum(oal.ABCValue)			--SR207107:MPC 24/04/2013
	sum(oal.Elite_Points)		--SR207107:MPC 24/04/2013
from 	msit_openworkAdviserListing oal
	inner join #ReportPeriods csp on csp.RptMonth = oal.month
--	left outer join msit_commissionStatement cs on cs.businesscode = @Franchise and cs.ID = oal.sourceID
--	left outer join mstt_producthierarchy ph on ph.productcode = cs.productcode
where 	oal.businessCode =  @Franchise
  and   oal.source='Payshield'
  and   (oal.sellerName in (select sellerName from #sellers)  or @seller = '%')
group by csp.RptMonth--,ph.productgroupname

-- OMS
insert	#ReportValues(
	RptMonth,
	ValueType,
	Value
	)
select 	csp.RptMonth,
	--csp.month,
	isNull(ph.productgroupname,'Other'),
	--sum(oal.ABCValue)			--SR207107:MPC 24/04/2013
	sum(oal.Elite_Points)		--SR207107:MPC 24/04/2013
from 	msit_openworkAdviserListing oal
	inner join #ReportPeriods csp on csp.RptMonth = oal.month
	left outer join omst_OMSCommissionpayments cs on cs.businesscode = @Franchise and cs.ID = oal.sourceID
	left outer join #Products ph on ph.productcode = cs.HierarchyProduct
where 	oal.businessCode =  @Franchise
  and   oal.source='OMS'
  and   (oal.sellerName in (select sellerName from #sellers)  or @seller = '%')
group by csp.RptMonth,ph.productgroupname

-- Get APE value
end
	else begin

	insert	#ReportValues(
	RptMonth,
	ValueType,
	Value
	)
select 	csp.RptMonth,
	--csp.month,
	isNull(ph.productgroupname,'Other'),
	sum(oal.APE)
from 	msit_openworkAdviserListing oal
	inner join #ReportPeriods csp on csp.RptMonth = oal.month
	left outer join msit_commissionStatement cs on cs.businesscode = @Franchise and cs.ID = oal.sourceID
	left outer join #Products ph on ph.productcode = cs.productcode
where 	oal.businessCode =  @Franchise
  and   oal.source='Openwork 2006'
  and   (oal.sellerName in (select sellerName from #sellers)  or @seller = '%')
group by csp.RptMonth,ph.productgroupname

-- 2005
insert	#ReportValues(
	RptMonth,
	ValueType,
	Value
	)
select 	csp.RptMonth,
	case 
		when oal.provider='General Insurance' then 'GI' 
		when oal.provider='SIML' then 'Investment'
		when oal.provider='Sterling' then 'Investment'
		when oal.provider='Scottish Equitable' then 'Pensions'
		else isNull(ph.productgroupname,'Other') 
	end,	sum(oal.APE)
from 	msit_openworkAdviserListing oal
	inner join #ReportPeriods csp on csp.RptMonth = oal.month
	left outer join msit_feesNonSwiftFeeListing fnsfl on fnsfl.ID = oal.sourceID
	left outer join #Products ph on 'NBI_'+fnsfl.productCode = ph.productCode
where 	oal.businessCode =  @Franchise
  and   oal.source='Openwork 2005'
  and   (oal.sellerName in (select sellerName from #sellers)  or @seller = '%')
group by csp.RptMonth,ph.productgroupname,oal.provider

-- paymentshield
insert	#ReportValues(
	RptMonth,
	ValueType,
	Value
	)
select 	csp.RptMonth,
	--csp.month,
	'GI',
	sum(oal.APE)
from 	msit_openworkAdviserListing oal
	inner join #ReportPeriods csp on csp.RptMonth = oal.month
--	left outer join msit_commissionStatement cs on cs.businesscode = @Franchise and cs.ID = oal.sourceID
--	left outer join mstt_producthierarchy ph on ph.productcode = cs.productcode
where 	oal.businessCode =  @Franchise
  and   oal.source='Payshield'
  and   (oal.sellerName in (select sellerName from #sellers)  or @seller = '%')
group by csp.RptMonth--,ph.productgroupname

-- OMS
insert	#ReportValues(
	RptMonth,
	ValueType,
	Value
	)
select 	csp.RptMonth,
	--csp.month,
	isNull(ph.productgroupname,'Other'),
	sum(oal.APE)
from 	msit_openworkAdviserListing oal
	inner join #ReportPeriods csp on csp.RptMonth = oal.month
	left outer join omst_OMSCommissionpayments cs on cs.businesscode = @Franchise and cs.ID = oal.sourceID
	left outer join #Products ph on ph.productcode = cs.HierarchyProduct
where 	oal.businessCode =  @Franchise
  and   oal.source='OMS'
  and   (oal.sellerName in (select sellerName from #sellers)  or @seller = '%')
group by csp.RptMonth,ph.productgroupname

	end -- end else


-- output monthly

select	MonthName,
	convert(decimal(10,2),coalesce(sum(case when ValueType='Protection' then Value else 0 end),0)) Protection,
	convert(decimal(10,2),coalesce(sum(case when ValueType='Investment' then Value else 0 end),0)) Investments,
	convert(decimal(10,2),coalesce(sum(case when ValueType='Pensions' then Value else 0 end),0)) Pensions,
	convert(decimal(10,2),coalesce(sum(case when ValueType='Mortgage' then Value else 0 end),0)) Mortgages,
	convert(decimal(10,2),coalesce(sum(case when ValueType='GI' then Value else 0 end),0)) GI,
	convert(decimal(10,2),coalesce(sum(case when ValueType='Structured' then Value else 0 end),0)) Structured,
	convert(decimal(10,2),coalesce(sum(case when ValueType not in ('Protection','Investment','Pensions','Mortgage','GI','Structured') then Value else 0 end),0)) Other,
	convert(decimal(10,2),coalesce(sum(Value),0)) Total
from	#ReportValues
	full outer join #ReportPeriods on #ReportValues.RptMonth = #ReportPeriods.RptMonth
where   #ReportPeriods.RptMonth >= @sMonth
	and #ReportPeriods.RptMonth <= @eMonth
group by #ReportPeriods.RptMonth,
	#ReportPeriods.MonthName
order by #ReportPeriods.RptMonth

-- get the YTD
select		convert(decimal(10,2),coalesce(sum(case when ValueType='Protection' then Value else 0 end),0)) Protection,
	convert(decimal(10,2),coalesce(sum(case when ValueType='Investment' then Value else 0 end),0)) Investments,
	convert(decimal(10,2),coalesce(sum(case when ValueType='Pensions' then Value else 0 end),0)) Pensions,
	convert(decimal(10,2),coalesce(sum(case when ValueType='Mortgage' then Value else 0 end),0)) Mortgages,
	convert(decimal(10,2),coalesce(sum(case when ValueType='GI' then Value else 0 end),0)) GI,
	convert(decimal(10,2),coalesce(sum(case when ValueType='Structured' then Value else 0 end),0)) Structured,
	convert(decimal(10,2),coalesce(sum(case when ValueType not in ('Protection','Investment','Pensions','Mortgage','GI','Structured') then Value else 0 end),0)) Other,
	convert(decimal(10,2),coalesce(sum(Value),0)) Total
from	#ReportValues
	left join #ReportPeriods on #ReportValues.RptMonth = #ReportPeriods.RptMonth
where right(monthName,4) = datename(YYYY,getdate())

-- get the rolling 12 month
declare @curmonth datetime

select	@curmonth = max([Month])
from	msit_Commissionstatementperiods csp
where	csp.PeriodendDate <= getdate()

select		convert(decimal(10,2),coalesce(sum(case when ValueType='Protection' then Value else 0 end),0)) Protection,
	convert(decimal(10,2),coalesce(sum(case when ValueType='Investment' then Value else 0 end),0)) Investments,
	convert(decimal(10,2),coalesce(sum(case when ValueType='Pensions' then Value else 0 end),0)) Pensions,
	convert(decimal(10,2),coalesce(sum(case when ValueType='Mortgage' then Value else 0 end),0)) Mortgages,
	convert(decimal(10,2),coalesce(sum(case when ValueType='GI' then Value else 0 end),0)) GI,
	convert(decimal(10,2),coalesce(sum(case when ValueType='Structured' then Value else 0 end),0)) Structured,
	convert(decimal(10,2),coalesce(sum(case when ValueType not in ('Protection','Investment','Pensions','Mortgage','GI','Structured') then Value else 0 end),0)) Other,
	convert(decimal(10,2),coalesce(sum(Value),0)) Total
from	#ReportValues
	left join #ReportPeriods on #ReportValues.RptMonth = #ReportPeriods.RptMonth
--where #ReportPeriods.RptMonth >= dateAdd(yyyy,-1,getdate())
where #ReportPeriods.RptMonth >= dateAdd(yyyy,-1,@curmonth)
  and #ReportPeriods.periodEnddate < getdate()


-- get the page totals
select	convert(decimal(10,2),coalesce(sum(case when ValueType='Protection' then Value else 0 end),0)) Protection,
	convert(decimal(10,2),coalesce(sum(case when ValueType='Investment' then Value else 0 end),0)) Investments,
	convert(decimal(10,2),coalesce(sum(case when ValueType='Pensions' then Value else 0 end),0)) Pensions,
	convert(decimal(10,2),coalesce(sum(case when ValueType='Mortgage' then Value else 0 end),0)) Mortgages,
	convert(decimal(10,2),coalesce(sum(case when ValueType='GI' then Value else 0 end),0)) GI,
	convert(decimal(10,2),coalesce(sum(case when ValueType='Structured' then Value else 0 end),0)) Structured,
	convert(decimal(10,2),coalesce(sum(case when ValueType not in ('Protection','Investment','Pensions','Mortgage','GI','Structured') then Value else 0 end),0)) Other,
	convert(decimal(10,2),coalesce(sum(Value),0)) Total
from	#ReportValues
	left join #ReportPeriods on #ReportValues.RptMonth = #ReportPeriods.RptMonth
where   #ReportPeriods.RptMonth >= @sMonth
	and #ReportPeriods.RptMonth <= @eMonth


drop table #ReportValues
drop table #ReportPeriods
drop table #sellers
drop table #Products

END
GO
/****** Object:  StoredProcedure [dbo].[owoa_reportNBI]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO






CREATE    procedure [dbo].[owoa_reportNBI]
@Franchise  varchar(7)
,@sMonth  datetime
,@eMonth  datetime
,@seller        varchar(60)
as

-- Amended PR - 16 Mar 2009 - Cater for Structured Products

BEGIN
set nocount on

create table #ReportPeriods(
  RptMonth  datetime,
  MonthName varchar(20),
  PeriodStartDate datetime,
  PeriodEndDate datetime,
  OscarStartDate  datetime,
  OscarEndDate  datetime
  )


create table #ReportValues(
  RptMonth  datetime,
  ValueType varchar(10),
  Value   float)

create table #Products(
  productcode     varchar(20) collate Latin1_General_CI_AS,
  productgroupname  varchar(30)
  )
insert #Products(
  productcode,
  productgroupname)
select  productcode,
    case 
      when structuredproduct = 'Y' then 'Structured' 
      else productgroupname
    end
from mstt_producthierarchy

create table #sellers(
  sellerName varchar(60) collate Latin1_General_CI_AS
)

declare @sellerCode varChar(10)


-- sort out the sellers
if @seller <> '%' begin
  -- get the code of the seller were looking for
  select @sellerCode = sellerCode
  from owoa_sellerXref  
  where sellerName = @seller
    and franchise = @Franchise
  -- check if we got a code back
  if @sellerCode in ('NC','',NULL) begin
    -- if not then just put the seller name we received in the file
    insert into #sellers (sellerName )
    values( @seller);
  end
  else begin
    -- if we did then put all then names associated with that code in the file
    insert into #sellers (sellerName )
    select sellerName 
      from owoa_sellerXref
     where sellerCode = @sellerCode
       and franchise = @Franchise
  end
end



-- sort out the reporitng periods


insert #ReportPeriods(
  RptMonth,
  MonthName,
  PeriodStartDate,
  PeriodEndDate,
  OscarStartDate,
  OscarEndDate)
select  [Month],
  MonthName,
  PeriodStartDate,
  PeriodEndDate,
  OscarStartDate,
  OscarEndDate
from  msit_Commissionstatementperiods csp
where (csp.month >= @sMonth
  and csp.month <= @eMonth
  ) or 
  csp.month >= dateAdd(yyyy,-1,getdate())




-- 2006
insert  #ReportValues(
  RptMonth,
  ValueType,
  Value
  )
select  csp.RptMonth,
  --csp.month,
  isNull(ph.productgroupname,'Other'),
  sum(totDue_enhd)
from  msit_openworkAdviserListing oal
  inner join #ReportPeriods csp on csp.RptMonth = oal.month
  left outer join msit_commissionStatement cs on cs.businesscode = @Franchise and cs.ID = oal.sourceID
  left outer join #Products ph on ph.productcode = cs.productcode
where   oal.businessCode =  @Franchise
  and   oal.source='Openwork 2006'
  and   (oal.sellerName in (select sellerName from #sellers) or @seller = '%')
group by csp.RptMonth,ph.productgroupname

-- 2005
insert  #ReportValues(
  RptMonth,
  ValueType,
  Value
  )
select  csp.RptMonth,
  case 
    when oal.provider='General Insurance' then 'GI' 
    when oal.provider='SIML' then 'Investment'
    when oal.provider='Sterling' then 'Investment'
    when oal.provider='Scottish Equitable' then 'Pensions'
    else isNull(ph.productgroupname,'Other') 
  end,
  sum(totDue_enhd)
from  msit_openworkAdviserListing oal
  inner join #ReportPeriods csp on csp.RptMonth = oal.month
  left outer join msit_feesNonSwiftFeeListing fnsfl on fnsfl.ID = oal.sourceID
  left outer join #Products ph on 'NBI_'+fnsfl.productCode = ph.productCode
where   oal.businessCode =  @Franchise
  and   oal.source='Openwork 2005'
  and   (oal.sellerName in (select sellerName from #sellers)  or @seller = '%')
group by csp.RptMonth,ph.productgroupname,oal.provider


-- paymentshield
insert  #ReportValues(
  RptMonth,
  ValueType,
  Value
  )
select  csp.RptMonth,
  'GI',
  sum(oal.totDue_enhd)
from  msit_openworkAdviserListing oal
  inner join #ReportPeriods csp on csp.RptMonth = oal.month
--  left outer join msit_commissionStatement cs on cs.businesscode = @Franchise and cs.ID = oal.sourceID
--  left outer join mstt_producthierarchy ph on ph.productcode = cs.productcode
where   oal.businessCode =  @Franchise
  and   oal.source='Payshield'
  and   (oal.sellerName in (select sellerName from #sellers)  or @seller = '%')
group by csp.RptMonth--,ph.productgroupname

-- OMS
insert  #ReportValues(
  RptMonth,
  ValueType,
  Value
  )
select  csp.RptMonth,
  --csp.month,
  isNull(ph.productgroupname,'Other'),
  sum(oal.totDue_enhd)
from  msit_openworkAdviserListing oal
  inner join #ReportPeriods csp on csp.RptMonth = oal.month
  left outer join omst_OMSCommissionpayments cs on cs.businesscode = @Franchise and cs.ID = oal.sourceID
  left outer join #Products ph on ph.productcode = cs.HierarchyProduct
where   oal.businessCode =  @Franchise
  and   oal.source='OMS'
  and   (oal.sellerName in (select sellerName from #sellers)  or @seller = '%')
group by csp.RptMonth,ph.productgroupname




-- output monthly

select  MonthName,
  convert(decimal(10,2),coalesce(sum(case when ValueType='Protection' then Value else 0 end),0)) Protection,
  convert(decimal(10,2),coalesce(sum(case when ValueType='Investment' then Value else 0 end),0)) Investments,
  convert(decimal(10,2),coalesce(sum(case when ValueType='Pensions' then Value else 0 end),0)) Pensions,
  convert(decimal(10,2),coalesce(sum(case when ValueType='Mortgage' then Value else 0 end),0)) Mortgages,
  convert(decimal(10,2),coalesce(sum(case when ValueType='GI' then Value else 0 end),0)) GI,
  convert(decimal(10,2),coalesce(sum(case when ValueType='Structured' then Value else 0 end),0)) Structured,
  convert(decimal(10,2),coalesce(sum(case when ValueType not in ('Protection','Investment','Pensions','Mortgage','GI','Structured') then Value else 0 end),0)) Other,
  convert(decimal(10,2),coalesce(sum(Value),0)) Total
from  #ReportValues
  full outer join #ReportPeriods on #ReportValues.RptMonth = #ReportPeriods.RptMonth
where   #ReportPeriods.RptMonth >= @sMonth
  and #ReportPeriods.RptMonth <= @eMonth
group by #ReportPeriods.RptMonth,
  #ReportPeriods.MonthName
order by #ReportPeriods.RptMonth

-- get the YTD
select    convert(decimal(10,2),coalesce(sum(case when ValueType='Protection' then Value else 0 end),0)) Protection,
  convert(decimal(10,2),coalesce(sum(case when ValueType='Investment' then Value else 0 end),0)) Investments,
  convert(decimal(10,2),coalesce(sum(case when ValueType='Pensions' then Value else 0 end),0)) Pensions,
  convert(decimal(10,2),coalesce(sum(case when ValueType='Mortgage' then Value else 0 end),0)) Mortgages,
  convert(decimal(10,2),coalesce(sum(case when ValueType='GI' then Value else 0 end),0)) GI,
  convert(decimal(10,2),coalesce(sum(case when ValueType='Structured' then Value else 0 end),0)) Structured,
  convert(decimal(10,2),coalesce(sum(case when ValueType not in ('Protection','Investment','Pensions','Mortgage','GI','Structured') then Value else 0 end),0)) Other,
  convert(decimal(10,2),coalesce(sum(Value),0)) Total
from  #ReportValues
  left join #ReportPeriods on #ReportValues.RptMonth = #ReportPeriods.RptMonth
where right(monthName,4) = datename(YYYY,getdate())

-- get the rolling 12 month
declare @curmonth datetime

select  @curmonth = max([Month])
from  msit_Commissionstatementperiods csp
where csp.PeriodendDate <= getdate()

select    convert(decimal(10,2),coalesce(sum(case when ValueType='Protection' then Value else 0 end),0)) Protection,
  convert(decimal(10,2),coalesce(sum(case when ValueType='Investment' then Value else 0 end),0)) Investments,
  convert(decimal(10,2),coalesce(sum(case when ValueType='Pensions' then Value else 0 end),0)) Pensions,
  convert(decimal(10,2),coalesce(sum(case when ValueType='Mortgage' then Value else 0 end),0)) Mortgages,
  convert(decimal(10,2),coalesce(sum(case when ValueType='GI' then Value else 0 end),0)) GI,
  convert(decimal(10,2),coalesce(sum(case when ValueType='Structured' then Value else 0 end),0)) Structured,
  convert(decimal(10,2),coalesce(sum(case when ValueType not in ('Protection','Investment','Pensions','Mortgage','GI','Structured') then Value else 0 end),0)) Other,
  convert(decimal(10,2),coalesce(sum(Value),0)) Total
from  #ReportValues
  left join #ReportPeriods on #ReportValues.RptMonth = #ReportPeriods.RptMonth
--where #ReportPeriods.RptMonth >= dateAdd(yyyy,-1,getdate())
where #ReportPeriods.RptMonth >= dateAdd(yyyy,-1,@curmonth)
  and #ReportPeriods.periodEnddate < getdate()


-- get the page totals
select  convert(decimal(10,2),coalesce(sum(case when ValueType='Protection' then Value else 0 end),0)) Protection,
  convert(decimal(10,2),coalesce(sum(case when ValueType='Investment' then Value else 0 end),0)) Investments,
  convert(decimal(10,2),coalesce(sum(case when ValueType='Pensions' then Value else 0 end),0)) Pensions,
  convert(decimal(10,2),coalesce(sum(case when ValueType='Mortgage' then Value else 0 end),0)) Mortgages,
  convert(decimal(10,2),coalesce(sum(case when ValueType='GI' then Value else 0 end),0)) GI,
  convert(decimal(10,2),coalesce(sum(case when ValueType='Structured' then Value else 0 end),0)) Structured,
  convert(decimal(10,2),coalesce(sum(case when ValueType not in ('Protection','Investment','Pensions','Mortgage','GI','Structured') then Value else 0 end),0)) Other,
  convert(decimal(10,2),coalesce(sum(Value),0)) Total
from  #ReportValues
  left join #ReportPeriods on #ReportValues.RptMonth = #ReportPeriods.RptMonth
where   #ReportPeriods.RptMonth >= @sMonth
  and #ReportPeriods.RptMonth <= @eMonth

drop table #ReportValues
drop table #ReportPeriods
drop table #sellers
drop table #Products
END






