  convert(decimal(10,2),coalesce(sum(case when ValueType='GI' then Value else 0 end),0)) GI,
  convert(decimal(10,2),coalesce(sum(case when ValueType='Structured' then Value else 0 end),0)) Structured,
  convert(decimal(10,2),coalesce(sum(case when ValueType not in ('Protection','Investment','Pensions','Mortgage','GI','Structured') then Value else 0 end),0)) Other,
  convert(decimal(10,2),coalesce(sum(Value),0)) Total
from  #ReportValues
  full outer join #ReportPeriods on #ReportValues.RptMonth = #ReportPeriods.RptMonth
where   #ReportPeriods.RptMonth >= @sMonth
  and #ReportPeriods.RptMonth <= @eMonth
group by #ReportPeriods.RptMonth,
  #ReportPeriods.MonthName
order by #ReportPeriods.RptMonth

-- get the YTD
select    convert(decimal(10,2),coalesce(sum(case when ValueType='Protection' then Value else 0 end),0)) Protection,
