/****** Object:  StoredProcedure [dbo].[owoa_ServicesDownload]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*********************************************************************************************************
Program:		dbo.owoa_ServicesDownload						
Author:			Alan Groves
Date created:	15/08/2019
											
Description
===========
This procedure has been added to the OpenAccess "Adhoc Downloads" to enable advisers 
to view their services and enable them to reconcile their services to their standing
orders on their OpenAccess Account Statement.

The OpenAccess "Adhoc Download request" report drop down list box will show this item as 
"Openwork Services".

It is called as follows:
	exec dbo.owoa_ServicesDownload '1010729', '2019-06-01', '2019-07-01'
									
Amendment History								
=================								

Date		Amended By	Change Details
----------	----------	--------------

*************************************************************************************************************/
CREATE PROCEDURE [dbo].[owoa_ServicesDownload]
		@EnterpriseUID	nvarchar(20),
		@StartMonth		datetime,
		@EndMonth		datetime
AS

SET NOCOUNT ON;

BEGIN TRY

	/****************************************************************************

		Variables
																			
	****************************************************************************/

	declare @Client					varchar(50),
			@Module					varchar(50),
			@PhaseStart				varchar(50),
			@PhaseEnd				varchar(50),
			@PhaseLog				varchar(50),
			@PhaseError				varchar(50),
			@Process				varchar(100),
			@ProcessMessage			varchar(100),
			@RowCount				int,
			@ErrMsg					nvarchar(4000),
			@ErrMsgBrief			nvarchar(100),
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@ErrState				int,
			@EndMonthOriginal		datetime
			
	/****************************************************************************

		Set initial parameters																
																			
	****************************************************************************/		

	set @Client			= 'Openwork'
	set @Module			= 'OpenAccess'
	set @PhaseStart		= 'START'
	set @PhaseEnd   	= 'END'
	set @PhaseLog		= 'LOG'
	set @PhaseError		= 'ERROR'
	set @Process		= object_name(@@procid)

	/****************************************************************************

		Log start
																			
	****************************************************************************/

	exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

	set @EndMonthOriginal = @EndMonth	--Store original parameter value
	
	-- This needs to be changed from first day of the month to last day of the month
	select @EndMonth = dateadd(mm,1,@EndMonth)-1	

	set @ProcessMessage = '@EnterpriseUID=' + @EnterpriseUID + 
							'; @StartMonth=' + convert(varchar(10),@StartMonth,103) +
							'; @EndMonthOriginal=' + convert(varchar(10),@EndMonthOriginal,103) +
							'; @EndMonth=' + convert(varchar(10),@EndMonth,103)
	
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client
						
	/****************************************************************************

		Get the data
																			
	****************************************************************************/		

	select	s.AdviserName,
			s.AdviserUID, 
			s.Source as Provider,
			s.SourceType as ServiceType,
			s.SourceReference as Reference, 
			s.TransactionDateTime, 
			s.ClientFirstname, 
			s.ClientLastname, 
			s.Service1, 
			s.Service2, 
			s.ServiceErrorFlag as ServiceError,
			case s.FeeType				--This may change in the future if contras are introduced
				when 40 then 'Fee'
				else 'Fee'
			end as TransactionType,
			s.NetAmount,
			s.VATAmount,
			s.GrossAmount,
			case when s.PaymentCollectedDate is null 
					then 'Not Yet Collected'
					else convert(varchar(10),s.PaymentCollectedDate,103)
			end as PaymentCollectedDate,
			case when s.PaymentCollectedDate is null
					then 'Not Yet Collected'
					else  s.StandingOrderDescription
			end as StandingOrderDescription
	from	dbo.owoa_Services s
	where	s.EnterpriseUID = @EnterpriseUID
	and		s.Month between @StartMonth and @EndMonth
	order	by s.AdviserName, s.Source, s.SourceType, s.TransactionDateTime, s.ClientLastname, s.ClientFirstname		
				
	select @RowCount = @@rowcount

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
   
	-- Error message line 1
	set @ErrMsgBrief = left(@ErrMsg,100)
	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	
	-- Error message line 2 - if any text exists
	set @ErrMsgBrief = substring(@ErrMsg,101,100)
