CREATE procedure [dbo].[owoa_YTDBankAccountSummary]
 @FranchiseCode nvarchar(20),
 @YearStart     datetime,
 @YearEnd   datetime,
 @UserId    NVARCHAR(20)
as

BEGIN

-- Select Openwork 2005 (Pre-Swift) entries
select
 BusinessCode   = BusinessCode,
 BusinessName   = BusinessName,
 BusinessECode  = BusinessECode,
 [Month]        = [a].[Month],
 Source         = 'Openwork',
 Amount         = sum(Amount),
 OpeningBalance = case when TotalType = 0 then sum(Amount)
                       else 0.0
                  end,
 Debit          = case when TotalType = 1 then sum(Amount)
                       else 0.0
                  end,
 Credit         = case when TotalType = 2 then sum(Amount)
                       else 0.0
                  end,
 Payment        = case when TotalType = 3 then sum(Amount)
                       else 0.0
                  end,
 ClosingBalance = case when TotalType = 9 then sum(Amount)
                       else 0.0
                  end,
 TotalType      = TotalType,
 MonthName      = MonthName,
 PaidDate   = PeriodEndDate,
 Paid     = case  when PeriodEndDate < getdate() then 'Paid'
            else 'Awaiting'
          end 
from
 msit_OpenworkBankDetails a,
 msit_CommissionStatementPeriods b
where
 BusinessCode = @FranchiseCode  and
 source like 'Openwork%'  and
 [b].[Month] >= @yearStart  and
 [b].[Month] <= @yearEnd  and
 [a].[Month] = [b].[Month]
group by
 BusinessCode,
 BusinessName,
 BusinessECode,
 [a].[Month],
 MonthName,
 Source,
 PeriodEndDate,
 TotalType

union all

-- select ZAN entries
select
 BusinessCode   = BusinessCode,
 BusinessName   = BusinessName,
 BusinessECode  = BusinessECode,
 [Month]        = [a].[Month],
 Source         = Source,
 Amount         = sum(Amount),
 OpeningBalance = case when TotalType = 0 then sum(Amount)
                       else 0.0
                  end,
 Debit          = case when TotalType = 1 then sum(Amount)
                       else 0.0
                  end,
 Credit         = case when TotalType = 2 then sum(Amount)
                       else 0.0
                  end,
 Payment        = case when TotalType = 3 then sum(Amount)
                       else 0.0
                  end,
 ClosingBalance = case when TotalType = 9 then sum(Amount)
                       else 0.0
                  end,
 TotalType      = TotalType,
 MonthName      = MonthName,
 PaidDate   = PeriodEndDate,
 Paid     = case  when PeriodEndDate < getdate() then 'Paid'
            else 'Awaiting'
          end 
from
 msit_ZANBankDetails a,
 msit_CommissionStatementPeriods b

where
 BusinessCode = @FranchiseCode and
 [b].[Month] >= @yearStart              and
 [b].[Month] <= @yearEnd          and
 [a].[Month] = [b].[month]
group by
 BusinessCode,
 BusinessName,
 BusinessECode,
 [a].[Month],
 MonthName,
 Source,
 PeriodEndDate,
 TotalType,MonthName



order by [month] ,Source,TotalType 

END


GO
