CREATE  procedure [dbo].[owoa_ZANAdviserDetail]
 @FranchiseCode nvarchar(20),
 @AdviserCode   nvarchar(255),
 @Month         datetime,
 @UserId NVARCHAR(20) = NULL,
 @Policy        nvarchar(255)
with recompile
as
begin
declare
 @sourceID    int,
 @polStartDate  datetime,
 @polID   varchar(25),
 @splitP  float,    -- split details for zan / openwork 2005
 @splitName varchar(30),    -- split details for zan / openwork 2005
 @StartDate     datetime


select top 1  
  @sourceID =sourceID  -- this is the ID to use
  ,@splitP  =agentsplit     -- split details for ZAN & openwork 2005
  ,@splitName =sellerSurname  -- split details for ZAN & openwork 2005
  ,@polID   =policy    -- policy id for next few queries
  ,@polStartDate  =startDate -- this is the start date for NBI
from
 msit_ZANAdviserListing
where
 BusinessCode = @FranchiseCode                      and
 month = @month and
 (SellerName  = @AdviserCode or @AdviserCode = '%') and
-- ([Month]      between @StartDate and @EndDate) and
 @Policy =  alID




select
 PaidDate             = case when BACSDate = '1901-01-01' or BACSDate >= getdate() then NULL
                             else substring(convert(nvarchar(11), BACSDate, 103), 1, 2) + '-' + upper(substring(convert(nvarchar(11), BACSDate), 1, 3)) + '-' + substring(convert(nvarchar(11), BACSDate), 10, 2)
                        end,
 BusinessCode         = BusinessECode,
 SellerCode           = SellerECode,                           --AdviserCode
 SellerForename       = SellerForename,                        --AdviserForename
 SellerSurname        = SellerSurname,                         --AdviserSurname
 SellerName           = SellerName,
 Provider             = Provider,
 ClientSurname        = ClientSurname,
 ClientForename       = ClientForename,
 ClientName           = Client,
 PolicyNumber         = Policy,
 ProdType             = ProdType,
 StartDate            = upper(substring(convert(nvarchar(11), StartDate), 1, 3)) + '-' + substring(convert(nvarchar(11), StartDate), 10, 2),
 Freq                 = Frequency,
 Premium              = case when Premium = 0 then NULL        --Premium/Inv/MortLoanAmt
                             else Premium
                        end,                               
 CommRate             = case when CommRate = 0 then NULL       --FeeRate%
                             else CommRate
                        end,                              
 InitialPeriod        = case when InitialPeriod = 0  then NULL
                             else InitialPeriod
                        end,
 TotalCommDue         = isnull(TotDue_Base,0),                 --TotalFeeDue
 Accrued_Base         = isnull(Accrued_Base,0),                --AccruedThisPeriod
 StillToAccr_Base     = case when StillToAccr_Base < 0 then 0  --StillToAccrue
                             else isnull(StillToAccr_Base,0)
                        end,
 ITAdvanced_Base      = isnull(ITAdvanced_Base,0),             --ITAdvancedThisPeriod
 EnhancementRate      = isnull(EnhancementRate,0),             --EnhdRate
 TotDue_Enhd          = isnull(TotDue_Enhd,0),                 --TotalFeeDue
 Accrued_Enhd         = isnull(Accrued_Enhd,0),                --AccruedThisPeriod
 StillToAccr_Enhd     = case when StillToAccr_Enhd < 0 then 0  --StillToAccrue
                             else isnull(StillToAccr_Enhd,0)
                        end,
 ITAdvance_Enhd       = isnull(ITAdvanced_Enhd,0),             --ITAdvancedThisPeriod
 TotalPayment         = isnull(TotalPayment,0),
 PayBasis             = PayBasis,
 TotalCommSacrifice   = case when Sacrifice = 0 then NULL      --TotalFeeSacrifice£
                             else Sacrifice
                        end,                             
 Split                = case when AgentSplit = 0 then NULL     --Split%
                             else AgentSplit
                        end,                            
 CommType             = FeeType,                               --FeeType
 APE                  = case when APE = 0 then NULL
                           else APE
                        end,
 Remarks              = Remarks,
 ITAccruedThisPeriod  = ITAccrued_Enhd,
 OutstandingLiability = ITOutLiability_Enhd
from
 msit_ZANAdviserListing
where
 BusinessCode = @FranchiseCode                      and
 (SellerName  = @AdviserCode or @AdviserCode = '%') and
  Month = @month and
 @Policy  = alID
 and policy = @polID
order by
 SellerName,
 Provider,
 ClientSurname,
 Client,
 Policy,
 BACSDate,
 PaymentDate


--additional details
select floor(initialPeriod/12) as termYears,initialperiod - (12 * FLOOR(initialPeriod / 12) )  as termMonths
  ,ph.productsubgroupname
  ,'N/A'  as address1,NULL as address2,NULL as address3,NULL as address4,NULL as address5,NULL as postcode,'N/A' as Tel,'N/A' as mobile,'N/A' as birthdate
from msit_feesNonSwiftFeeListing a
  left outer join mstt_producthierarchy ph on 'NBI_'+a.productCode = ph.productCode
where a.ID = @SourceID


--splits
  select @splitP as split,@splitName as sellerSurname

END


GO
/****** Object:  StoredProcedure [dbo].[owoa_ZANAdviserListingRange]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO







CREATE  procedure [dbo].[owoa_ZANAdviserListingRange]
 @FranchiseCode nvarchar(20),
 @AdviserCode   nvarchar(100),
 @sMonth         datetime,
 @eMonth         datetime
with recompile
as
BEGIN
-- Amended PR - 16 Mar 2009 - Do not show recs with zero comm values

declare
 @StartDate     datetime,
 @EndDate       datetime

create table #tmpTbl(
 bcode varchar(7) collate Latin1_General_CI_AS 
,bmonth datetime
)
;

insert into #tmpTbl
select @FranchiseCode,month 
  from msit_CommissionStatementPeriods
 where [Month] >= @sMonth
   and [Month] <= @eMonth
;


select
 PaidDate             = case when BACSDate = '1901-01-01' or BACSDate >= getdate() then NULL
                             else substring(convert(nvarchar(11), BACSDate, 103), 1, 2) + '-' + upper(substring(convert(nvarchar(11), BACSDate), 1, 3)) + '-' + substring(convert(nvarchar(11), BACSDate), 10, 2)
                        end,
 BusinessCode         = BusinessECode,
 SellerCode           = SellerECode,                           --AdviserCode
 SellerForename       = SellerForename,                        --AdviserForename
 SellerSurname        = SellerSurname,                         --AdviserSurname
 SellerName           = SellerName,
 Provider             = Provider,
 ClientSurname        = ClientSurname,
 ClientForename       = ClientForename,
 ClientName           = Client,
 PolicyNumber         = Policy,
 ProdType             = ProdType,
 StartDate            = upper(substring(convert(nvarchar(11), StartDate), 1, 3)) + '-' + substring(convert(nvarchar(11), StartDate), 10, 2),
 Freq                 = Frequency,
 Selpremium           = Premium,
 Premium              = case when Premium = 0 then NULL        --Premium/Inv/MortLoanAmt
                             else Premium
                        end,                               
 CommRate             = case when CommRate = 0 then NULL       --FeeRate%
                             else CommRate
                        end,                              
 InitialPeriod        = case when InitialPeriod = 0  then NULL
                             else InitialPeriod
                        end,
 TotalCommDue         = isnull(TotDue_Base,0),                 --TotalFeeDue
 Accrued_Base         = isnull(Accrued_Base,0),                --AccruedThisPeriod
 StillToAccr_Base     = case when StillToAccr_Base < 0 then 0  --StillToAccrue
                             else isnull(StillToAccr_Base,0)
                        end,
 ITAdvanced_Base      = isnull(ITAdvanced_Base,0),             --ITAdvancedThisPeriod
 EnhancementRate      = isnull(EnhancementRate,0),             --EnhdRate
 TotDue_Enhd          = isnull(TotDue_Enhd,0),                 --TotalFeeDue
 Accrued_Enhd         = isnull(Accrued_Enhd,0),                --AccruedThisPeriod
 StillToAccr_Enhd     = case when StillToAccr_Enhd < 0 then 0  --StillToAccrue
                             else isnull(StillToAccr_Enhd,0)
                        end,
 ITAdvance_Enhd       = isnull(ITAdvanced_Enhd,0),             --ITAdvancedThisPeriod
 TotalPayment         = isnull(TotalPayment,0),
 PayBasis             = PayBasis,
 TotalCommSacrifice   = case when Sacrifice = 0 then NULL      --TotalFeeSacrifice£
                             else Sacrifice
                        end,                             
 Split                = case when AgentSplit = 0 then NULL     --Split%
                             else AgentSplit
                        end,                            
 CommType             = FeeType,                               --FeeType
 APE                  = case when APE = 0 then NULL
                           else APE
                        end,
 Remarks              = Remarks,
 ITAccruedThisPeriod  = ITAccrued_Enhd,
 OutstandingLiability = ITOutLiability_Enhd,
 month =  [Month],
 source = '',
 CaseId = '',
 comKey     = alID
from
 msit_ZANAdviserListing a
 join #tmpTbl b on a.businessCode = b.bcode and a.month = b.bmonth
where
 BusinessCode = @FranchiseCode                      and
 (SellerName  = @AdviserCode or @AdviserCode = '%') and
 (isnull(TotDue_Base,0.00) <> 0 or          -- PR 16/3/2009 do select records if contain zero values
  isnull(Accrued_Base,0.00)  <> 0 or
  isnull(StillToAccr_Base,0.00)  <> 0 or
  isnull(ITAdvanced_Base,0.00)  <> 0 or
  isnull(TotDue_Enhd,0.00)  <> 0 or
  isnull(Accrued_Enhd,0.00)  <> 0 or
  isnull(StillToAccr_Enhd,0.00)  <> 0 or
  isnull(ITAdvanced_Enhd,0.00)  <> 0 or
  isnull(TotalPayment, 0.0)  <> 0 or
  isnull(ITAccrued_Enhd, 0.0)  <> 0 or
  isnull(ITOutLiability_Enhd, 0.0)  <> 0 or
  isnull(APE,0.00)  <> 0 ) 

order by
 SellerName,
 Provider,
 ClientSurname,
 Client,
 Policy,
 BACSDate,
 PaymentDate


drop table #tmpTbl;

END









GO
