create procedure [dbo].[owoa_ZANBankAccountStatementRange]
 @FranchiseCode nvarchar(20),
 @sMonth         datetime,
 @eMonth         datetime,
 @UserId NVARCHAR(20)
as

select
 BusinessCode    = BusinessCode,
 BusinessName    = BusinessName,
 BusinessECode   = BusinessECode,
 [Month]         = [Month],
 Source          = Source,
 Debits          = case when Amount < 0 then Amount
                        else 0
                   end,
 Credits         = case when Amount > 0 then Amount
                        else 0
                   end,
 TotalAmount     = Amount,
 TransactionDate = TransactionDate,
 PaymentType     = PaymentType,
 TransactionType = TransactionType,
 Description     = Description,
 Notes           = Notes,
 Sequence        = Sequence,
 TotalType       = TotalType,
 SortCode        = SortCode
from
 msit_ZANBankDetails
where
 BusinessCode = @FranchiseCode and
 [Month] <= @eMonth              and
 [Month] >= @sMonth              
order by
 TransactionDate,
 SortCode,
 PaymentType,
 Sequence



GO

